    private bool SackAddClip(int epValue)
    {
        SackItemType type = epValue >= 100 ? SackItemType.LargeClip : epValue >= 50 ? SackItemType.MediumClip : SackItemType.SmallClip;
        // Try to stack into existing cell of same type
        for (int i = 0; i < _sackItems.Count; i++)
        {
            if (_sackItems[i].Type == type && _sackItems[i].Count < _sackItems[i].MaxStack)
            {
                var s = _sackItems[i];
                s.Count++;
                _sackItems[i] = s;
                return true;
            }
        }
        // Find empty cell
        var occupied = new HashSet<(int, int)>();
        foreach (var s in _sackItems)
            for (int dy = 0; dy < Math.Max(1, s.Height); dy++)
                for (int dx = 0; dx < Math.Max(1, s.Width); dx++)
                    occupied.Add((s.GridX + dx, s.GridY + dy));
        for (int y = 0; y < SackGridSize; y++)
            for (int x = 0; x < SackGridSize; x++)
                if (!occupied.Contains((x, y)))
                {
                    _sackItems.Add(new SackItem { Type = type, Count = 1, MaxStack = 3, GridX = x, GridY = y, Width = 1, Height = 1 });
                    return true;
                }
        // Sack full — can't add
        return false;
    }
    
    private bool SackRemoveClip(out int epValue)
    {
        // Remove smallest clip first (most efficient reload)
        epValue = 0;
        int bestIdx = -1;
        int bestEp = int.MaxValue;
        for (int i = 0; i < _sackItems.Count; i++)
        {
            int ep = _sackItems[i].Type == SackItemType.SmallClip ? 25 : _sackItems[i].Type == SackItemType.MediumClip ? 50 : 100;
            if (ep < bestEp) { bestEp = ep; bestIdx = i; }
        }
        if (bestIdx < 0) return false;
        epValue = bestEp;
        var item = _sackItems[bestIdx];
        item.Count--;
        if (item.Count <= 0)
            _sackItems.RemoveAt(bestIdx);
        else
            _sackItems[bestIdx] = item;
        return true;
    }
    
    private int SackClipCount()
    {
        int total = 0;
        foreach (var s in _sackItems) total += s.Count;
        return total;
    }
    
