    protected override void LoadContent()
    {
        _spriteBatch = new SpriteBatch(GraphicsDevice);
        _pixel = new Texture2D(GraphicsDevice, 1, 1);
        _pixel.SetData(new[] { Color.White });

        try { _font = Content.Load<SpriteFont>("DefaultFont"); }
        catch { _font = null; }
        try { _titleFont = Content.Load<SpriteFont>("SotNFont"); }
        catch { _titleFont = null; }
        try { _jacquardFont = Content.Load<SpriteFont>("TitleFont"); }
        catch { _jacquardFont = null; }
        
        // Pre-cache only small/immediate songs; large ambient tracks load lazily on first use
        LoadSong("Music/Victory"); LoadSong("Music/Death"); LoadSong("Music/Complete"); LoadSong("Music/Strange");
        
        // Music loaded lazily via LoadSong()
        MediaPlayer.IsRepeating = true;
        MediaPlayer.Volume = 0.4f;
        
        // Generate procedural SFX
        _sfxPickup = GenerateSfx(new[] { 440f, 660f, 880f }, 0.12f, 0.3f);
        _sfxEssence = GenerateSfx(new[] { 330f, 440f, 550f, 660f }, 0.08f, 0.25f);
        _sfxDoorOpen = GenerateSfx(new[] { 200f, 250f, 300f }, 0.15f, 0.2f);
        _sfxHit = GenerateSfx(new[] { 120f, 80f }, 0.06f, 0.4f);
        _sfxDash = GenerateSfx(new[] { 180f, 100f }, 0.03f, 0.12f);

        // Post-processing render targets
        _sceneRT = new RenderTarget2D(GraphicsDevice, 1280, 720, false, SurfaceFormat.Color, DepthFormat.None, 0, RenderTargetUsage.PreserveContents);
        _bloomRT1 = new RenderTarget2D(GraphicsDevice, 320, 180);  // quarter-res
        _bloomRT2 = new RenderTarget2D(GraphicsDevice, 160, 90);   // eighth-res
        _bloomExtractRT = new RenderTarget2D(GraphicsDevice, 640, 360); // half-res extract

        // Try loading compiled shader (precompiled .mgfx file)
        try
        {
            string mgfxPath = System.IO.Path.Combine(Content.RootDirectory, "Effects", "PostProcess.mgfx");
            if (System.IO.File.Exists(mgfxPath))
            {
                byte[] bytecode = System.IO.File.ReadAllBytes(mgfxPath);
                _postProcessEffect = new Effect(GraphicsDevice, bytecode);
                _shadersAvailable = true;
                System.Console.WriteLine("PostProcess shader loaded successfully!");
            }
            else
            {
                // Try content pipeline path
                _postProcessEffect = Content.Load<Effect>("Effects/PostProcess");
                _shadersAvailable = true;
                System.Console.WriteLine("PostProcess shader loaded via content pipeline!");
            }
        }
        catch (Exception)
        {
            _shadersAvailable = false;
            System.Console.WriteLine("PostProcess shader not found — using CPU fallback.");
        }

        // Generate vignette texture (radial gradient, used by both paths)
        _vignetteTexture = GenerateVignetteTexture(1280, 720);

        // === Lighting system init ===
        _lightRT = new RenderTarget2D(GraphicsDevice, 1280, 720);
        
        // Load light mask shader
        try
        {
            string lightPath = System.IO.Path.Combine(Content.RootDirectory, "Effects", "LightMask.mgfx");
            if (System.IO.File.Exists(lightPath))
            {
                byte[] bytecode = System.IO.File.ReadAllBytes(lightPath);
                _lightMaskEffect = new Effect(GraphicsDevice, bytecode);
                System.Console.WriteLine("LightMask shader loaded!");
            }
        }
        catch (Exception)
        {
            System.Console.WriteLine("LightMask shader not found — lighting disabled.");
        }
        
        // Generate 256×256 radial gradient texture for point lights
        {
            int gradSize = 1024; // large enough that upscaling never shows banding
            Color[] gradData = new Color[gradSize * gradSize];
            float center = gradSize / 2f;
            for (int y = 0; y < gradSize; y++)
            for (int x = 0; x < gradSize; x++)
            {
                float dx = x - center, dy = y - center;
                float dist = MathF.Sqrt(dx * dx + dy * dy) / center;
                // Very soft Gaussian — barely any light at 60% radius, zero at edge
                float intensity = MathF.Exp(-dist * dist * 6f);
                if (dist > 0.92f) intensity = 0f;
                // IGN dithering to break any remaining 8-bit banding
                float dither = ((52.9829189f * ((0.06711056f * x + 0.00583715f * y) % 1f)) % 1f - 0.5f) / 128f;
                intensity = MathHelper.Clamp(intensity + dither, 0f, 1f);
                gradData[y * gradSize + x] = new Color(intensity, intensity, intensity, intensity);
            }
            _lightGradient = new Texture2D(GraphicsDevice, gradSize, gradSize);
            _lightGradient.SetData(gradData);
        }
        
        // Generate tileable noise texture for water
        _noiseTexture = GenerateNoiseTexture(NoiseSizeX, NoiseSizeY, seed: 42);
        _noiseTexture2 = GenerateNoiseTexture(NoiseSizeX, NoiseSizeY, seed: 137);
        
        // Water distortion shader
        try
        {
            string waterFxPath = System.IO.Path.Combine(Content.RootDirectory, "Effects", "WaterDistort.mgfx");
            if (System.IO.File.Exists(waterFxPath))
            {
                byte[] bytecode = System.IO.File.ReadAllBytes(waterFxPath);
                _waterDistortEffect = new Effect(GraphicsDevice, bytecode);
                System.Console.WriteLine("Water distortion shader loaded!");
            }
        }
        catch (Exception ex)
        {
            System.Console.WriteLine($"Water shader failed to load: {ex.Message}");
            _waterDistortEffect = null;
        }
        _waterRT = new RenderTarget2D(GraphicsDevice, 1280, 720);

        // Load title screen textures
        try
        {
            string contentDir = Content.RootDirectory;
            string portraitPath = Path.Combine(contentDir, "morien_portrait Background Removed.png");
            if (File.Exists(portraitPath))
                using (var stream = File.OpenRead(portraitPath))
                    _titlePortrait = Texture2D.FromStream(GraphicsDevice, stream);
            
            string wandPath = Path.Combine(contentDir, "wand_gun Background Removed.png");
            if (File.Exists(wandPath))
                using (var stream = File.OpenRead(wandPath))
                    _titleWand = Texture2D.FromStream(GraphicsDevice, stream);
        }
        catch { /* images optional */ }

        // Load tileset
        string tilesetPath = System.IO.Path.Combine(Content.RootDirectory, "urizen_onebit_tileset__v2d0.png");
        if (System.IO.File.Exists(tilesetPath))
        {
            using var stream = System.IO.File.OpenRead(tilesetPath);
            _tileset = Texture2D.FromStream(GraphicsDevice, stream);
            System.Console.WriteLine($"Tileset loaded: {_tileset.Width}x{_tileset.Height}");
            InitTileMaps();
        }
        
        // Load sword sprite sheet
        string swordPath = System.IO.Path.Combine(Content.RootDirectory, "Exotic Swords.png");
        if (System.IO.File.Exists(swordPath))
        {
            using var swordStream = System.IO.File.OpenRead(swordPath);
            _swordTex = Texture2D.FromStream(GraphicsDevice, swordStream);
            System.Console.WriteLine($"Sword sheet loaded: {_swordTex.Width}x{_swordTex.Height}");
        }
        else
        {
            System.Console.WriteLine("Sword sheet not found.");
        }
        
        // Load knight sprite sheet
        string knightPath = System.IO.Path.Combine(Content.RootDirectory, "knights_1x.png");
        if (System.IO.File.Exists(knightPath))
        {
            using var knightStream = System.IO.File.OpenRead(knightPath);
            _playerTex = Texture2D.FromStream(GraphicsDevice, knightStream);
            System.Console.WriteLine($"Knight sheet loaded: {_playerTex.Width}x{_playerTex.Height}");
        }

        // Load tilesets
        _tsSheets = new Texture2D[_tsNames.Length];
        for (int i = 0; i < _tsNames.Length; i++)
        {
            string tsPath = System.IO.Path.Combine(Content.RootDirectory, _tsPaths[i] + ".png");
            if (System.IO.File.Exists(tsPath))
            {
                using var tsStream = System.IO.File.OpenRead(tsPath);
                var tex = Texture2D.FromStream(GraphicsDevice, tsStream);
                _tsSheets[i] = tex;
                // Mask out transparency key color (255,103,139) used by these RPG Maker tilesets
                var pixels = new Color[tex.Width * tex.Height];
                tex.GetData(pixels);
                for (int p = 0; p < pixels.Length; p++)
                {
                    if (pixels[p].R == 255 && pixels[p].G == 103 && pixels[p].B == 139)
                        pixels[p] = Color.Transparent;
                    else
                        pixels[p] = new Color(
                            (int)(pixels[p].R * pixels[p].A / 255f),
                            (int)(pixels[p].G * pixels[p].A / 255f),
                            (int)(pixels[p].B * pixels[p].A / 255f),
                            pixels[p].A);
                }
                tex.SetData(pixels);
                System.Console.WriteLine($"OpenRPG tileset '{_tsNames[i]}' loaded: {tex.Width}x{tex.Height}");
            }
        }
        _tsDungeon = _tsSheets[0]; _tsExterior = _tsSheets[1]; _tsInterior = _tsSheets[2];
        _tsShip = _tsSheets[3]; _tsWorld = _tsSheets[4];
        LoadRoomTiles();

        _playerPos = new Vector2(_arena.Center.X, _arena.Center.Y);
        _undinePos = _playerPos + new Vector2(20, -10);
        _wandPickupPos = _playerPos + new Vector2(60, 0);
        _shieldPickupPos = _playerPos + new Vector2(-60, 0);
    }

    private void InitTileMaps()
    {
        var r7 = new int[TileRows, TileCols];
        for (int row = 0; row < TileRows; row++)
            for (int col = 0; col < TileCols; col++)
                r7[row, col] = 1;
        for (int row = 5; row < 12; row++)
            for (int col = 10; col < 22; col++)
                r7[row, col] = 2;
        for (int row = 1; row < 4; row++)
            for (int col = 13; col < 19; col++)
                r7[row, col] = 3;
        _roomTileMaps[7] = r7;

        _parallaxTileMap = new int[TileRows, TileCols];
        for (int row = 5; row < 12; row++)
            for (int col = 10; col < 22; col++)
                _parallaxTileMap[row, col] = 4;

        for (int room = 1; room <= 9; room++)
        {
            if (_roomTileMaps.ContainsKey(room)) continue;
            var tm = new int[TileRows, TileCols];
            for (int row = 0; row < TileRows; row++)
                for (int col = 0; col < TileCols; col++)
                    tm[row, col] = 1;
            _roomTileMaps[room] = tm;
        }
    }

    private void DrawTileMap()
    {
        if (_tileset == null) return;
        if (!_roomTileMaps.TryGetValue(_currentScreen, out var tileMap)) return;

        int ox = _arena.Left, oy = _arena.Top;

        for (int row = 0; row < TileRows; row++)
        {
            for (int col = 0; col < TileCols; col++)
            {
                int id = tileMap[row, col];
                if (id == 0) continue;

                Rectangle src = GetTileSource(id);
                Rectangle dst = new Rectangle(ox + col * TileDst, oy + row * TileDst, TileDst, TileDst);

                Color tint = id switch
                {
                    2 => new Color(40, 80, 120),
                    3 => new Color(60, 55, 50),
                    4 => new Color(30, 50, 70),
                    _ => new Color(35, 33, 40),
                };

                _spriteBatch.Draw(_tileset, dst, src, tint);
            }
        }
    }

    private Rectangle GetTileSource(int tileType)
    {
        return tileType switch
        {
            1 => new Rectangle(12, 12 * 5, TileSrc, TileSrc),
            2 => new Rectangle(12 * 3, 12 * 8, TileSrc, TileSrc),
            3 => new Rectangle(12 * 2, 12 * 5, TileSrc, TileSrc),
            4 => new Rectangle(12 * 5, 12 * 6, TileSrc, TileSrc),
            _ => new Rectangle(0, 0, TileSrc, TileSrc),
        };
    }

    private void DrawParallaxLayer()
    {
        if (_tileset == null || _parallaxTileMap == null) return;
        if (_currentScreen != 7) return;

        int ox = _arena.Left, oy = _arena.Top;

        float px = (_playerPos.X - ScreenW / 2f) * _parallaxFactor;
        float py = (_playerPos.Y - ScreenH / 2f) * _parallaxFactor;

        for (int row = 0; row < TileRows; row++)
        {
            for (int col = 0; col < TileCols; col++)
            {
                int id = _parallaxTileMap[row, col];
                if (id == 0) continue;

                Rectangle src = GetTileSource(id);
                int dx = ox + col * TileDst - (int)px;
                int dy = oy + row * TileDst - (int)py;
                Rectangle dst = new Rectangle(dx, dy, TileDst, TileDst);

                float waterWave = MathF.Sin(_totalTime * 1.5f + col * 0.5f + row * 0.3f) * 0.1f + 0.9f;
                Color tint = new Color((int)(25 * waterWave), (int)(45 * waterWave), (int)(65 * waterWave), 180);

                _spriteBatch.Draw(_tileset, dst, src, tint);
            }
        }
    }

    protected override void Update(GameTime gameTime)
    {
        float dt = (float)gameTime.ElapsedGameTime.TotalSeconds;
        UpdateMusicFade(dt);
        var kb = Keyboard.GetState();
        var mouse = Mouse.GetState();
        IsMouseVisible = false; // always use custom cursor

        _titleTimer += dt;

        switch (_state)
        {
            case GameState.Intro:
                _introTimer += dt;
                _introScroll += dt * 22f; // scroll speed: 22 px/s
                // Play prologue music
                if (_introTimer < dt * 2f) PlayMusic(LoadSong("Music/NightAmbient2"), "intro");
                // Skip on any key/click after 1s
                if (_introTimer > 1f && (kb.GetPressedKeyCount() > 0 || mouse.LeftButton == ButtonState.Pressed))
                {
                    _state = GameState.TitleScreen;
                    _titleTimer = 0f;
                    _titleWeather = _rng.Next(3);
                    _titleLightningTimer = 2f + (float)_rng.NextDouble() * 3f;
                    _titleLightningFlash = 0f;
                }
                // Auto-advance when scroll is done
                float totalCrawlHeight = IntroCrawl.Length * 26f + ScreenH;
                if (_introScroll > totalCrawlHeight)
                {
                    _state = GameState.TitleScreen;
                    _titleTimer = 0f;
                    _titleWeather = _rng.Next(3);
                    _titleLightningTimer = 2f + (float)_rng.NextDouble() * 3f;
                    _titleLightningFlash = 0f;
                }
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
            case GameState.TitleScreen:
                UpdateTitleScreen(kb);
                UpdateMusic();
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
            case GameState.ModeSelect:
                UpdateModeSelect(kb, dt);
                UpdateMusic();
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
            case GameState.DemoComplete:
            {
                var dkb = Keyboard.GetState();
                _demoCompleteScroll += (float)gameTime.ElapsedGameTime.TotalSeconds * 40f;
                if ((dkb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter)) || _demoCompleteScroll > ScreenH + 200)
                {
                    _state = GameState.Playing;
                    _demoCompleteScroll = 0;
                }
                _prevKb = dkb;
                base.Update(gameTime);
                return;
            }
            case GameState.GameOver:
                UpdateGameOver(kb, dt);
                UpdateMusic();
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
            case GameState.Paused:
                if ((kb.IsKeyDown(Keys.Up) && !_prevKb.IsKeyDown(Keys.Up)) ||
                    (kb.IsKeyDown(Keys.W) && !_prevKb.IsKeyDown(Keys.W)))
                    _pauseSelection = (_pauseSelection - 1 + 3) % 3;
                if ((kb.IsKeyDown(Keys.Down) && !_prevKb.IsKeyDown(Keys.Down)) ||
                    (kb.IsKeyDown(Keys.S) && !_prevKb.IsKeyDown(Keys.S)))
                    _pauseSelection = (_pauseSelection + 1) % 3;
                    
                if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
                    _state = GameState.Playing;
                if (kb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter))
                {
                    switch (_pauseSelection)
                    {
                        case 0: _state = GameState.Playing; break;
                        case 1: _state = GameState.ModeSelect; _menuSelection = 0; break;
                        case 2: _state = GameState.TitleScreen; _menuSelection = 0; break;
                    }
                }
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
        }
        
        // ═══════════════ GAMEPLAY UPDATE (state == Playing) ═══════════════
        
        // Tile Renderer mode — separate update loop
        if (_gameMode == GameMode.TileRenderer)
        {
            UpdateTileRenderer(kb, mouse, dt);
            _prevKb = kb;
            _prevMouse = mouse;
            base.Update(gameTime);
            return;
        }
        
        // Text box blocks all other input
        if (_textBoxMessage != null)
        {
            UpdateTextBox();
            _prevKb = kb;
            _prevMouse = mouse;
            base.Update(gameTime);
            return;
        }
        
        // Pickups (Awakening mode)
        if (_gameMode == GameMode.Awakening)
        {
            UpdatePickups(dt);
            UpdateEtherDrops(dt);
            UpdateTripwires(dt);
            CheckAwakeningRoom2Completion();
            UpdateRoom4(dt);
            UpdateRoom6(dt);
            UpdateRoom3(dt);
            UpdateRoom7(dt);
            UpdateRoom8(dt);
            UpdateRoom1(dt);
            UpdateRoom9(dt);
            
            // Activate Sir Pellinore after boss is dead
            if (!_pellinoreActive && !_pellinoreDefeated && _bossDead && _currentScreen != 9)
            {
                _pellinoreActive = true;
                int[] candidates = { 1, 2, 3, 4, 6, 7, 8 };
                _pellinoreScreen = candidates[_rng.Next(candidates.Length)];
                while (_pellinoreScreen == _currentScreen)
                    _pellinoreScreen = candidates[_rng.Next(candidates.Length)];
                _pellinorePos = new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2);
                _pellinoreWanderTimer = 15f;
                _pellinoreHp = PellinoreMaxHp;
            }
            if (_pellinoreActive && !_pellinoreDefeated)
                UpdatePellinore(dt);
            
            // Demo complete transition after boss text dismissed
            if (_currentScreen == 9 && _bossDead && _textBoxMessage == null && _pickups.Count == 0 && _demoCompleteTimer == 0 && !_creditsPlayed)
                _demoCompleteTimer = 0.01f;
            if (_demoCompleteTimer > 0)
            {
                _demoCompleteTimer += dt;
                if (_demoCompleteTimer > 2f)
                {
                    _state = GameState.DemoComplete;
                    _demoCompleteTimer = 0;
                    _demoCompleteScroll = 0;
                    _creditsPlayed = true;
                }
            }
            
            UpdateMusic();
        }
        
        // TAB inventory toggle
        if (kb.IsKeyDown(Keys.Tab) && !_prevKb.IsKeyDown(Keys.Tab))
        {
            _inventoryOpen = !_inventoryOpen;
            if (!_inventoryOpen) DropOverflowToGround();
        }
        if (_testMode && kb.IsKeyDown(Keys.H) && !_prevKb.IsKeyDown(Keys.H))
            _showHitboxes = !_showHitboxes;
        
        // Always track mouse for inventory hover
        _mouseWorld = new Vector2(mouse.X + _cameraOffset.X, mouse.Y + _cameraOffset.Y);
        float slideTarget = _inventoryOpen ? 1f : 0f;
        _inventorySlide += (slideTarget - _inventorySlide) * InventorySlideSpeed * dt;
        if (MathF.Abs(_inventorySlide - slideTarget) < 0.01f) _inventorySlide = slideTarget;
        
        // Accordion slide animation (runs every frame while inventory is open)
        if (_inventoryOpen)
        {
            float slideSpeed = 6f; // ~0.17s full transition
            _relicsSlide += (_relicsExpanded ? 1f : -1f) * slideSpeed * dt;
            _relicsSlide = MathHelper.Clamp(_relicsSlide, 0f, 1f);
            _statsSlide += (_statsExpanded ? 1f : -1f) * slideSpeed * dt;
            _statsSlide = MathHelper.Clamp(_statsSlide, 0f, 1f);
        }
        
        // Pause gameplay when inventory is open
        if (_inventoryOpen && _inventorySlide > 0.9f)
        {
            // ESC closes inventory
            if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
            {
                _inventoryOpen = false;
                _prevKb = kb;
                _prevMouse = mouse;
                base.Update(gameTime);
                return;
            }
            
            // ═══ Sack grid interaction ═══
            int _sgX = ScreenW / 2 - (SackGridSize * SackCellSize) / 2;
            int _sgY = InvPanelY + 620 - SackGridSize * SackCellSize - 50; // match draw position
            int gridW_ = SackGridSize * SackCellSize;
            int gridH_ = SackGridSize * SackCellSize;
            int smxG = ((int)_mouseWorld.X - _sgX) / SackCellSize;
            int smyG = ((int)_mouseWorld.Y - _sgY) / SackCellSize;
            
            // Armor slot bounds (matches draw position)
            int armorSlotW_ = 60, armorSlotH_ = 60;
            int armorSlotX_ = _sgX - armorSlotW_ - 50;
            int armorSlotY_ = _sgY + (gridH_ - armorSlotH_) / 2;
            bool inArmorSlot = _mouseWorld.X >= armorSlotX_ && _mouseWorld.X < armorSlotX_ + armorSlotW_
                && _mouseWorld.Y >= armorSlotY_ && _mouseWorld.Y < armorSlotY_ + armorSlotH_;
            bool inSackGrid = smxG >= 0 && smxG < SackGridSize && smyG >= 0 && smyG < SackGridSize
                && _mouseWorld.X >= _sgX && _mouseWorld.Y >= _sgY;
            
            // Rotate animation decay
            if (_sackRotateAnim > 0) _sackRotateAnim -= dt * 4f;
            
            // Left-click: start drag (from sack, overflow, or armor slot)
            if (mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released)
            {
                _sackDragFromArmor = false;
                if (inArmorSlot && _equippedArmor != ArmorType.None)
                {
                    // Pick up equipped armor
                    _sackDragIdx = 0; // dummy index
                    _sackDragFromArmor = true;
                    _sackDragFromOverflow = false;
                    _sackDragOffset = _mouseWorld - new Vector2(armorSlotX_, armorSlotY_);
                }
                else if (inSackGrid)
                {
                    for (int si = 0; si < _sackItems.Count; si++)
                    {
                        var s = _sackItems[si];
                        int sw = Math.Max(1, s.Width), sh = Math.Max(1, s.Height);
                        if (smxG >= s.GridX && smxG < s.GridX + sw && smyG >= s.GridY && smyG < s.GridY + sh)
                        {
                            _sackDragIdx = si;
                            _sackDragFromOverflow = false;
                            _sackDragOffset = _mouseWorld - new Vector2(_sgX + s.GridX * SackCellSize, _sgY + s.GridY * SackCellSize);
                            break;
                        }
                    }
                }
                else if (_sackOverflow.Count > 0)
                {
                    // Check if clicking on a floating item
                    for (int oi = 0; oi < _sackOverflow.Count && oi < _sackOverflowPos.Count; oi++)
                    {
                        int ocx = (int)_sackOverflowPos[oi].X;
                        int ocy = (int)_sackOverflowPos[oi].Y;
                        int iw = Math.Max(1, _sackOverflow[oi].Width) * SackCellSize;
                        int ih = Math.Max(1, _sackOverflow[oi].Height) * SackCellSize;
                        if (mouse.X >= ocx && mouse.X < ocx + iw && mouse.Y >= ocy && mouse.Y < ocy + ih)
                        {
                            _sackDragIdx = oi;
                            _sackDragFromOverflow = true;
                            _sackDragOffset = new Vector2(mouse.X - ocx, mouse.Y - ocy);
                            break;
                        }
                    }
                }
            }
            
            // Left-click release: drop item
            if (mouse.LeftButton == ButtonState.Released && _sackDragIdx >= 0)
            {
                if (_sackDragFromArmor)
                {
                    // Dragging FROM armor slot
                    if (inSackGrid)
                    {
                        // Armor → Sack: find 2×2 space starting at hovered cell
                        // For now just put it in the hovered cell (simplified — 2×2 collision later)
                        var occupied2 = new HashSet<(int, int)>();
                        foreach (var s in _sackItems) 
                            for (int dy2 = 0; dy2 < Math.Max(1, s.Height); dy2++)
                                for (int dx2 = 0; dx2 < Math.Max(1, s.Width); dx2++)
                                    occupied2.Add((s.GridX + dx2, s.GridY + dy2));
                        // Check if 2×2 fits at smxG, smyG
                        bool fits = smxG >= 0 && smyG >= 0 && smxG + 2 <= SackGridSize && smyG + 2 <= SackGridSize;
                        if (fits)
                        {
                            for (int dy2 = 0; dy2 < 2 && fits; dy2++)
                                for (int dx2 = 0; dx2 < 2 && fits; dx2++)
                                    if (occupied2.Contains((smxG + dx2, smyG + dy2))) fits = false;
                        }
                        if (fits)
                        {
                            _sackItems.Add(new SackItem { Type = SackItemType.Armor, Armor = _equippedArmor, Count = 1, MaxStack = 1, GridX = smxG, GridY = smyG, Width = 2, Height = 2 });
                            _equippedArmor = ArmorType.None;
                        }
                        // else: doesn't fit, armor stays equipped
                    }
                    else if (!inArmorSlot)
                    {
                        // Dropped outside everything — armor floats at mouse position
                        _sackOverflow.Add(new SackItem { Type = SackItemType.Armor, Armor = _equippedArmor, Count = 1, MaxStack = 1, Width = 2, Height = 2 });
                        _sackOverflowPos.Add(new Vector2(mouse.X - _sackDragOffset.X, mouse.Y - _sackDragOffset.Y));
                        _equippedArmor = ArmorType.None;
                    }
                }
                else if (inArmorSlot && !_sackDragFromOverflow && !_sackDragFromArmor && _sackDragIdx < _sackItems.Count && _sackItems[_sackDragIdx].Type == SackItemType.Armor)
                {
                    // Sack armor → Armor slot: equip (swap if already wearing)
                    var draggedArmor = _sackItems[_sackDragIdx];
                    ArmorType oldArmor = _equippedArmor;
                    _equippedArmor = draggedArmor.Armor;
                    _sackItems.RemoveAt(_sackDragIdx);
                    if (oldArmor != ArmorType.None)
                    {
                        // Put old armor back in sack at the cell where dragged armor was
                        _sackItems.Add(new SackItem { Type = SackItemType.Armor, Armor = oldArmor, Count = 1, MaxStack = 1, GridX = draggedArmor.GridX, GridY = draggedArmor.GridY, Width = 2, Height = 2 });
                    }
                }
                else if (inSackGrid && _sackDragFromOverflow)
                {
                    // Overflow → Sack: place with proper multi-cell handling
                    var ovItem = _sackOverflow[_sackDragIdx];
                    int ow = Math.Max(1, ovItem.Width), oh = Math.Max(1, ovItem.Height);
                    
                    // Calculate origin cell from drag offset
                    int originX = (int)(_mouseWorld.X - _sackDragOffset.X - _sgX + SackCellSize / 2) / SackCellSize;
                    int originY = (int)(_mouseWorld.Y - _sackDragOffset.Y - _sgY + SackCellSize / 2) / SackCellSize;
                    originX = Math.Clamp(originX, 0, SackGridSize - ow);
                    originY = Math.Clamp(originY, 0, SackGridSize - oh);
                    
                    // Check for overlap with existing items
                    int targetIdx = -1;
                    for (int si = 0; si < _sackItems.Count; si++)
                    {
                        var other = _sackItems[si];
                        int otherW = Math.Max(1, other.Width), otherH = Math.Max(1, other.Height);
                        if (originX < other.GridX + otherW && originX + ow > other.GridX &&
                            originY < other.GridY + otherH && originY + oh > other.GridY)
                        { targetIdx = si; break; }
                    }
                    
                    if (targetIdx < 0)
                    {
                        // Empty space — place from overflow into sack
                        ovItem.GridX = originX; ovItem.GridY = originY;
                        _sackItems.Add(ovItem);
                        _sackOverflow.RemoveAt(_sackDragIdx);
                        _sackOverflowPos.RemoveAt(_sackDragIdx);
                    }
                    else if (_sackItems[targetIdx].Type == ovItem.Type && ovItem.Type != SackItemType.Armor && _sackItems[targetIdx].Count < _sackItems[targetIdx].MaxStack)
                    {
                        // Same type clips: stack
                        var dst = _sackItems[targetIdx];
                        int space = dst.MaxStack - dst.Count;
                        int transfer = Math.Min(ovItem.Count, space);
                        dst.Count += transfer;
                        ovItem.Count -= transfer;
                        _sackItems[targetIdx] = dst;
                        if (ovItem.Count <= 0) { _sackOverflow.RemoveAt(_sackDragIdx); _sackOverflowPos.RemoveAt(_sackDragIdx); }
                        else _sackOverflow[_sackDragIdx] = ovItem;
                    }
                    else if (ow == Math.Max(1, _sackItems[targetIdx].Width) && oh == Math.Max(1, _sackItems[targetIdx].Height))
                    {
                        // Same size: swap — overflow item goes into grid, grid item becomes float
                        var gridItem = _sackItems[targetIdx];
                        ovItem.GridX = originX; ovItem.GridY = originY;
                        _sackItems[targetIdx] = ovItem;
                        _sackOverflow[_sackDragIdx] = gridItem;
                        // Keep overflow pos where it was
                    }
                    // else: can't place — stays floating
                }
                else if (inSackGrid && !_sackDragFromOverflow)
                {
                    // Sack → Sack: move/stack/swap
                    var dragged = _sackItems[_sackDragIdx];
                    int dw = Math.Max(1, dragged.Width), dh = Math.Max(1, dragged.Height);
                    
                    // Calculate where the origin cell should land based on drag offset
                    // _sackDragOffset is relative to the item's origin cell top-left
                    int originDropX = (int)(_mouseWorld.X - _sackDragOffset.X - _sgX + SackCellSize / 2) / SackCellSize;
                    int originDropY = (int)(_mouseWorld.Y - _sackDragOffset.Y - _sgY + SackCellSize / 2) / SackCellSize;
                    originDropX = Math.Clamp(originDropX, 0, SackGridSize - dw);
                    originDropY = Math.Clamp(originDropY, 0, SackGridSize - dh);
                    
                    // Find if there's an item at the target
                    int targetIdx = -1;
                    for (int si = 0; si < _sackItems.Count; si++)
                    {
                        if (si == _sackDragIdx) continue;
                        var other = _sackItems[si];
                        int ow = Math.Max(1, other.Width), oh = Math.Max(1, other.Height);
                        // Check overlap with where we'd place the dragged item
                        if (originDropX < other.GridX + ow && originDropX + dw > other.GridX && originDropY < other.GridY + oh && originDropY + dh > other.GridY)
                        { targetIdx = si; break; }
                    }
                    
                    if (targetIdx < 0)
                    {
                        // Empty space — move there
                        var moved = dragged;
                        moved.GridX = originDropX; moved.GridY = originDropY;
                        _sackItems[_sackDragIdx] = moved;
                    }
                    else if (_sackItems[targetIdx].Type == dragged.Type && dragged.Type != SackItemType.Armor)
                    {
                        // Same type (clips): stack
                        var src = dragged;
                        var dst = _sackItems[targetIdx];
                        int space = dst.MaxStack - dst.Count;
                        int transfer = Math.Min(src.Count, space);
                        if (transfer > 0)
                        {
                            dst.Count += transfer;
                            src.Count -= transfer;
                            _sackItems[targetIdx] = dst;
                            if (src.Count <= 0) _sackItems.RemoveAt(_sackDragIdx);
                            else _sackItems[_sackDragIdx] = src;
                        }
                    }
                    else if (dw == Math.Max(1, _sackItems[targetIdx].Width) && dh == Math.Max(1, _sackItems[targetIdx].Height))
                    {
                        // Same size: swap positions
                        var src = dragged;
                        var dst = _sackItems[targetIdx];
                        int tmpX = src.GridX, tmpY = src.GridY;
                        src.GridX = dst.GridX; src.GridY = dst.GridY;
                        dst.GridX = tmpX; dst.GridY = tmpY;
                        _sackItems[_sackDragIdx] = src;
                        _sackItems[targetIdx] = dst;
                    }
                    // else: different sizes overlap — snap back (do nothing)
                }
                else if (!inSackGrid && !inArmorSlot)
                {
                    // Dropped outside grid/slots — item floats at mouse position
                    SackItem floatItem;
                    if (_sackDragFromOverflow && _sackDragIdx < _sackOverflow.Count)
                    {
                        floatItem = _sackOverflow[_sackDragIdx];
                        _sackOverflow.RemoveAt(_sackDragIdx);
                        _sackOverflowPos.RemoveAt(_sackDragIdx);
                    }
                    else if (_sackDragFromArmor)
                    {
                        floatItem = new SackItem { Type = SackItemType.Armor, Armor = _equippedArmor, Count = 1, MaxStack = 1, Width = 2, Height = 2 };
                        _equippedArmor = ArmorType.None;
                    }
                    else if (_sackDragIdx >= 0 && _sackDragIdx < _sackItems.Count)
                    {
                        floatItem = _sackItems[_sackDragIdx];
                        _sackItems.RemoveAt(_sackDragIdx);
                    }
                    else { floatItem = default; goto skipFloat; }
                    _sackOverflow.Add(floatItem);
                    int fw = Math.Max(1, floatItem.Width) * SackCellSize;
                    int fh = Math.Max(1, floatItem.Height) * SackCellSize;
                    _sackOverflowPos.Add(new Vector2(mouse.X - _sackDragOffset.X, mouse.Y - _sackDragOffset.Y));
                    skipFloat:;
                }
                _sackDragIdx = -1;
                _sackDragFromOverflow = false;
            }
            
            // Right-click: rotate item shape (swaps Width/Height for multi-cell items)
            if (mouse.RightButton == ButtonState.Pressed && _prevMouse.RightButton == ButtonState.Released && inSackGrid)
            {
                for (int si = 0; si < _sackItems.Count; si++)
                {
                    var s = _sackItems[si];
                    int sw = Math.Max(1, s.Width), sh = Math.Max(1, s.Height);
                    if (smxG >= s.GridX && smxG < s.GridX + sw && smyG >= s.GridY && smyG < s.GridY + sh)
                    {
                        if (sw != sh && (sw > 1 || sh > 1))
                        {
                            // Swap dimensions — check if rotated version fits
                            int newW = sh, newH = sw;
                            bool fits = s.GridX + newW <= SackGridSize && s.GridY + newH <= SackGridSize;
                            if (fits)
                            {
                                // Check collision with other items
                                for (int si2 = 0; si2 < _sackItems.Count && fits; si2++)
                                {
                                    if (si2 == si) continue;
                                    var other = _sackItems[si2];
                                    int ow = Math.Max(1, other.Width), oh = Math.Max(1, other.Height);
                                    if (s.GridX < other.GridX + ow && s.GridX + newW > other.GridX && s.GridY < other.GridY + oh && s.GridY + newH > other.GridY)
                                        fits = false;
                                }
                            }
                            if (fits)
                            {
                                s.Width = newW; s.Height = newH;
                                _sackItems[si] = s;
                            }
                        }
                        _sackRotateAnim = 1f;
                        break;
                    }
                }
            }
            
            // Handle clicks on inventory items
            if (mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released)
            {
                int mx = mouse.X, my = mouse.Y;
                bool changed = false;
                
                // Form options row
                int fx = InvPanelX + InvItemIndent;
                foreach (var f in _unlockedForms)
                {
                    if (f == Form.None) continue;
                    string fn = f.ToString();
                    int w = MeasureText(fn);
                    if (mx >= fx && mx <= fx + w && my >= InvFormItemsY - 2 && my <= InvFormItemsY + 18)
                    {
                        _loadout.Form = (f == _loadout.Form) ? Form.None : f;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                
                // Behavior options row
                fx = InvPanelX + InvItemIndent;
                foreach (var b in _unlockedBehaviors)
                {
                    if (b == Behavior.None) continue;
                    string bn = b.ToString();
                    int w = MeasureText(bn);
                    if (mx >= fx && mx <= fx + w && my >= InvBehItemsY - 2 && my <= InvBehItemsY + 18)
                    {
                        _loadout.Behavior = (b == _loadout.Behavior) ? Behavior.None : b;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                
                // Essence options row
                fx = InvPanelX + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int w = MeasureText(en);
                    if (mx >= fx && mx <= fx + w && my >= InvEssItemsY - 2 && my <= InvEssItemsY + 18)
                    {
                        _loadout.Essence = (e == _loadout.Essence) ? Essence.None : e;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                
                // Secondary loadout — Form options
                fx = InvPanelX + InvItemIndent;
                foreach (var f in _unlockedForms)
                {
                    if (f == Form.None) continue;
                    string fn = f.ToString();
                    int w = MeasureText(fn);
                    if (mx >= fx && mx <= fx + w && my >= InvSecFormY - 2 && my <= InvSecFormY + 18)
                    {
                        _loadoutSecondary.Form = (f == _loadoutSecondary.Form) ? Form.None : f;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                // Secondary — Behavior options
                fx = InvPanelX + InvItemIndent;
                foreach (var b in _unlockedBehaviors)
                {
                    if (b == Behavior.None) continue;
                    string bn = b.ToString();
                    int w = MeasureText(bn);
                    if (mx >= fx && mx <= fx + w && my >= InvSecBehY - 2 && my <= InvSecBehY + 18)
                    {
                        _loadoutSecondary.Behavior = (b == _loadoutSecondary.Behavior) ? Behavior.None : b;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                // Secondary — Essence options
                fx = InvPanelX + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int w = MeasureText(en);
                    if (mx >= fx && mx <= fx + w && my >= InvSecEssY - 2 && my <= InvSecEssY + 18)
                    {
                        _loadoutSecondary.Essence = (e == _loadoutSecondary.Essence) ? Essence.None : e;
                        changed = true;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                
                // Utility essence options
                fx = InvPanelX + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int w = MeasureText(en);
                    if (mx >= fx && mx <= fx + w && my >= InvUtilItemsY - 2 && my <= InvUtilItemsY + 18)
                    {
                        _utilityEssence = (e == _utilityEssence) ? Essence.None : e;
                        break;
                    }
                    fx += w + InvItemGap;
                }
                
                if (changed) RefreshCombo();
                
                // Right column dropdown click handling
                int rx = ScreenW - 295;
                int ry = _arena.Top - 2 + 20; // panelY + top padding
                bool clickConsumed = false;
                
                // RELICS header button
                if (mx >= rx && mx <= rx + 120 && my >= ry && my <= ry + 24)
                {
                    _relicsExpanded = !_relicsExpanded;
                    if (_relicsExpanded) _statsExpanded = false; // accordion
                    clickConsumed = true;
                }
                
                if (_relicsExpanded)
                {
                    ry += 30; // past header
                    // Relic toggling
                    bool[] relicOwned = { _ownsCaliburn, _ownsNimueTear, _ownsWandOfMerlin, _ownsTomeOfBinding, _ownsHasteBand, _ownsPhylactery, _ownsGrimoire, _ownsDragonDance, _ownsEtherSight, _ownsDamageNumbers, _ownsLambentAura, _ownsEtherRegen, _ownsQuickswap };
                    if (!clickConsumed)
                    {
                        for (int ri = 0; ri < relicOwned.Length; ri++)
                        {
                            if (relicOwned[ri] && mx >= rx && mx <= rx + 300 && my >= ry - 4 && my <= ry + 22)
                            {
                                if (ri == 0) _hasCaliburn = !_hasCaliburn;
                                else if (ri == 1) _hasNimueTear = !_hasNimueTear;
                                else if (ri == 2) _hasWandOfMerlin = !_hasWandOfMerlin;
                                else if (ri == 3) _hasTomeOfBinding = !_hasTomeOfBinding;
                                else if (ri == 4) _hasHasteBand = !_hasHasteBand;
                                else if (ri == 5) _hasPhylactery = !_hasPhylactery;
                                else if (ri == 6) { _hasGrimoire = !_hasGrimoire; RefreshCombo(); }
                                else if (ri == 7) _hasDragonDance = !_hasDragonDance;
                                else if (ri == 8) _hasEtherSight = !_hasEtherSight;
                                else if (ri == 9) _hasDamageNumbers = !_hasDamageNumbers;
                                else if (ri == 10) _hasLambentAura = !_hasLambentAura;
                                else if (ri == 11) { _hasEtherRegenRelic = !_hasEtherRegenRelic; _hasEtherRegen = _hasEtherRegenRelic; }
                                else if (ri == 12) _hasQuickswap = !_hasQuickswap;
                                clickConsumed = true;
                                break;
                            }
                            ry += 24;
                        }
                    }
                    else
                    {
                        for (int ri = 0; ri < relicOwned.Length; ri++) ry += 24;
                    }
                    ry += 10; // gap after relics
                }
                else
                {
                    ry += 30; // past collapsed header
                }
                
                // STATS header button
                if (!clickConsumed && mx >= rx && mx <= rx + 120 && my >= ry && my <= ry + 24)
                {
                    _statsExpanded = !_statsExpanded;
                    if (_statsExpanded) _relicsExpanded = false; // accordion
                }
            }
            
            _prevKb = kb;
            _prevMouse = mouse;
            base.Update(gameTime);
            return;
        }

        // Hitstop: freeze game briefly on heavy hits
        if (_hitstopTimer > 0)
        {
            _hitstopTimer -= dt;
            _prevKb = kb;
            base.Update(gameTime);
            return; // freeze all game logic
        }
        
        // BREAK Finisher: freeze gameplay, only update finisher + particles
        if (_finisherActive)
        {
            UpdateFinisher(dt);
            // Update particles so death effect plays out
            for (int i = _particles.Count - 1; i >= 0; i--)
            {
                var pt = _particles[i];
                pt.Position += pt.Velocity * dt;
                pt.Life -= dt;
                _particles[i] = pt;
                if (pt.Life <= 0) _particles.RemoveAt(i);
            }
            _prevKb = kb;
            _prevMouse = mouse;
            base.Update(gameTime);
            return;
        }
        
        if (_iFrameTimer > 0) _iFrameTimer -= dt;
        if (_cocoonTimer > 0) { _cocoonTimer -= dt; if (_cocoonTimer <= 0) _cocoonHits = 0; }
        if (_reloadTimer > 0) _reloadTimer -= dt;
        if (_damageFlashTimer > 0) _damageFlashTimer -= dt;
        if (_questionMarkTimer > 0) _questionMarkTimer -= dt;
        
        // Mana regen (paused during Shadow Stitch channel or active Prominence)
        bool prominenceActive = false;
        for (int i = 0; i < _projectiles.Count; i++)
        {
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Prominence") { prominenceActive = true; break; }
        }
        if (!_shadowStitch.Active && !prominenceActive && _playerEther < EffectiveMaxEther && _hasEtherRegen)
            _playerEther = MathF.Min(_playerEther + EtherRegenRate * dt, EffectiveMaxEther);
        // Smooth mana display
        // Floor clamp — never go negative
        if (_playerEther < 0) _playerEther = 0;
        _etherDisplay += (_playerEther - _etherDisplay) * 8f * dt;
        if (MathF.Abs(_etherDisplay - _playerEther) < 0.5f) _etherDisplay = _playerEther;
        if (_etherFlashTimer > 0) _etherFlashTimer -= dt;
        _totalTime += dt;
        
        // Behavior ability cooldown
        if (_behaviorAbilityCooldown > 0) _behaviorAbilityCooldown -= dt;
        
        // Ward zone update
        if (_wardZoneActive)
        {
            var wz = _wardZone;
            wz.Life -= dt;
            if (wz.Life <= 0)
            {
                _wardZoneActive = false;
            }
            else
            {
                _wardZone = wz;
                // Regen if player inside ward
                if (Vector2.Distance(_playerPos, wz.Position) < wz.Radius)
                {
                    _playerHp = MathF.Min(_playerHp + 2f * dt, PlayerMaxHp);
                    // Healing sparkle particles
                    if (_rng.NextDouble() < 0.3)
                    {
                        _particles.Add(new Particle
                        {
                            Position = wz.Position + new Vector2((float)_rng.NextDouble() * wz.Radius * 2 - wz.Radius, (float)_rng.NextDouble() * wz.Radius * 2 - wz.Radius),
                            Velocity = new Vector2(0, -15f),
                            Life = 0.6f, MaxLife = 0.6f,
                            Color = new Color(150, 255, 180),
                            Size = 1.5f
                        });
                    }
                }
            }
        }
        
        // Aegis burst timer
        if (_aegisBurstTimer > 0) _aegisBurstTimer -= dt;
        
        // Elemental armor update
        if (_elementalArmorTimer > 0)
        {
            _elementalArmorTimer -= dt;
            if (_elementalArmorTimer <= 0)
            {
                _elementalArmor = ElementalArmorType.None;
                _exoskeletonShieldActive = false;
            }
            else
            {
                // Cinder aura damage to nearby enemies
                if (_elementalArmor == ElementalArmorType.Cinder)
                {
                    for (int ei = 0; ei < _enemies.Count; ei++)
                    {
                        if (!_enemies[ei].Alive) continue;
                        if (Vector2.Distance(_playerPos, _enemies[ei].Position) < 30f)
                        {
                            _enemies[ei].Hp -= 3f * dt;
                            if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                        }
                    }
                    // Ember particles
                    if (_rng.NextDouble() < 0.4)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = _playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 12f,
                            Velocity = new Vector2(MathF.Cos(a + 1.5f), MathF.Sin(a + 1.5f)) * 20f + new Vector2(0, -10f),
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(255, _rng.Next(80, 180), _rng.Next(20, 60)),
                            Size = 1.5f
                        });
                    }
                }
                // Pulse: spark particles
                else if (_elementalArmor == ElementalArmorType.Pulse)
                {
                    if (_rng.NextDouble() < 0.3)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = _playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 10f,
                            Velocity = new Vector2((float)_rng.NextDouble() * 40f - 20f, (float)_rng.NextDouble() * 40f - 20f),
                            Life = 0.15f, MaxLife = 0.15f,
                            Color = new Color(100 + _rng.Next(100), 120 + _rng.Next(80), 255),
                            Size = 1f
                        });
                    }
                }
            }
        }

        if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
        {
            if (_inventoryOpen)
                _inventoryOpen = false;
            else
            {
                _state = GameState.Paused;
                _pauseSelection = 0;
            }
        }

        // Post-processing shader hotkeys (disabled during Playing to avoid RT crash)
        if (_state != GameState.Playing && _state != GameState.Paused && kb.IsKeyDown(Keys.P) && !_prevKb.IsKeyDown(Keys.P))
            _postProcessEnabled = !_postProcessEnabled;
        if (kb.IsKeyDown(Keys.Y) && !_prevKb.IsKeyDown(Keys.Y))
            _bloomIntensity = MathHelper.Clamp(_bloomIntensity - 0.05f, 0f, 1f);
        if (kb.IsKeyDown(Keys.U) && !_prevKb.IsKeyDown(Keys.U))
            _bloomIntensity = MathHelper.Clamp(_bloomIntensity + 0.05f, 0f, 1f);
        if (kb.IsKeyDown(Keys.I) && !_prevKb.IsKeyDown(Keys.I))
            _vignetteStrength = MathHelper.Clamp(_vignetteStrength - 0.05f, 0f, 1f);
        if (kb.IsKeyDown(Keys.O) && !_prevKb.IsKeyDown(Keys.O))
            _vignetteStrength = MathHelper.Clamp(_vignetteStrength + 0.05f, 0f, 1f);
        if (kb.IsKeyDown(Keys.N) && !_prevKb.IsKeyDown(Keys.N))
            _dayNightEnabled = !_dayNightEnabled;
        
        // Day/night cycle
        if (_dayNightEnabled)
        {
            _dayTimeMinutes += dt / 60f; // real seconds → cycle minutes
            if (_dayTimeMinutes >= DayNightCycleMinutes) _dayTimeMinutes -= DayNightCycleMinutes;
            // Day/night: bright plateau during day, rapid dusk/dawn, short dark night
            // Use smoothstep-like power curve: raise sine to flatten the top
            float dayPhase = MathF.Sin(_dayTimeMinutes / DayNightCycleMinutes * MathF.PI * 2f - MathF.PI / 2f);
            float normalized = (dayPhase + 1f) / 2f; // 0..1 raw sine
            // Power curve: sqrt pushes values toward 1 (bright plateau), then square the dark end
            // Result: ~90-100% for most of daytime, rapid drop through 30-0% at night
            _ambientLight = normalized < 0.5f 
                ? MathF.Pow(normalized * 2f, 2.5f) * 0.5f   // night→dawn: slow rise from dark
                : 1f - MathF.Pow((1f - normalized) * 2f, 2.5f) * 0.5f; // day→dusk: holds bright, rapid drop
        }

        // Toggle test mode
        if (kb.IsKeyDown(Keys.T) && !_prevKb.IsKeyDown(Keys.T))
        {
            _testMode = !_testMode;
            if (_testMode)
            {
                foreach (Form f in Enum.GetValues<Form>()) _unlockedForms.Add(f);
                foreach (Behavior b in Enum.GetValues<Behavior>()) _unlockedBehaviors.Add(b);
                foreach (Essence e in Enum.GetValues<Essence>()) _unlockedEssences.Add(e);
                _hasWand = true;
                _hasShield = true;
                _hasCaliburn = true;
                _hasNimueTear = true;
                _hasWandOfMerlin = true;
                _hasHasteBand = true;
                _hasPhylactery = true; _hasGrimoire = true;
                _ownsCaliburn = true; _ownsNimueTear = true; _ownsWandOfMerlin = true;
                _ownsHasteBand = true; _ownsPhylactery = true; _ownsGrimoire = true;
                _hasDragonDance = true;
                _ownsDragonDance = true;
                _hasDamageNumbers = true;
                _hasLambentAura = true;
                _ownsEtherSight = true;
                _ownsDamageNumbers = true;
                _ownsLambentAura = true;
                _enemies.Clear(); _enemyById.Clear();
            }
        }

        // Dash
        _dashCooldown -= dt;
        if (_isDashing)
        {
            _dashTimer -= dt;
            if (_dashTimer <= 0) _isDashing = false;
        }

        if (_hasShield && kb.IsKeyDown(Keys.Space) && !_prevKb.IsKeyDown(Keys.Space) && _dashCooldown <= 0 && !_isDashing)
        {
            Vector2 move = Vector2.Zero;
            if (kb.IsKeyDown(Keys.W)) move.Y -= 1;
            if (kb.IsKeyDown(Keys.S)) move.Y += 1;
            if (kb.IsKeyDown(Keys.A)) move.X -= 1;
            if (kb.IsKeyDown(Keys.D)) move.X += 1;
            _mouseWorld = new Vector2(mouse.X + _cameraOffset.X, mouse.Y + _cameraOffset.Y);
            if (move.LengthSquared() < 0.01f)
            {
                move = _mouseWorld - _playerPos;
            }
            if (move.LengthSquared() > 0)
            {
                move.Normalize();
                _dashDir = move;
                _isDashing = true;
                PlaySfx(_sfxDash);
                _dashTimer = DashDuration;
                _dashCooldown = DashCooldownTime;
            }
        }

        // Loadout swap — Q key (requires Quickswap relic)
        if (_hasQuickswap && kb.IsKeyDown(Keys.Q) && !_prevKb.IsKeyDown(Keys.Q))
        {
            (_loadout, _loadoutSecondary) = (_loadoutSecondary, _loadout);
            _loadoutIsPrimary = !_loadoutIsPrimary;
            _loadoutSwapTimer = LoadoutSwapDuration;
        }
        if (_loadoutSwapTimer > 0) _loadoutSwapTimer -= dt;

        // Sword swing — Shift key
        _swordCooldown -= dt;
        if (_swordTimer > 0) _swordTimer -= dt;
        if (_hasSword && kb.IsKeyDown(Keys.LeftShift) && !_prevKb.IsKeyDown(Keys.LeftShift) 
            && _swordCooldown <= 0 && _swordTimer <= 0 && !_isDashing && !_finisherActive)
        {
            _mouseWorld = new Vector2(mouse.X + _cameraOffset.X, mouse.Y + _cameraOffset.Y);
            _swordDir = Vector2.Normalize(_mouseWorld - _playerPos);
            if (float.IsNaN(_swordDir.X)) _swordDir = new Vector2(1, 0);
            _swordTimer = SwordSwingTime;
            _swordCooldown = SwordCooldownTime;
            _swordHitEnemies.Clear();
            PlaySfx(_sfxHit);
        }
        // Sword hit detection during swing
        if (_swordTimer > 0)
        {
            float swingAngle = MathF.Atan2(_swordDir.Y, _swordDir.X);
            for (int i = 0; i < _enemies.Count; i++)
            {
                if (_swordHitEnemies.Contains(i)) continue;
                var e = _enemies[i];
                if (!e.Alive || e.Spawning) continue;
                float dist = Vector2.Distance(_playerPos, e.Position);
                if (dist > SwordRange + e.Size) continue;
                // Check if enemy is within the arc
                float angleToEnemy = MathF.Atan2(e.Position.Y - _playerPos.Y, e.Position.X - _playerPos.X);
                float angleDiff = MathF.Abs(MathHelper.WrapAngle(angleToEnemy - swingAngle));
                if (angleDiff > SwordArc / 2f) continue;
                // Hit!
                _swordHitEnemies.Add(i);
                e.Hp -= SwordDamage;
                e.HitFlash = 0.15f;
                e.HitCooldown = 0.1f;
                // Kill check
                if (e.Hp <= 0)
                {
                    e.Alive = false;
                    SpawnEtherDrops(e.Position, false);
                }
                // Stagger
                if (e.Stagger < e.MaxStagger)
                    e.Stagger += SwordStagger;
                // Knockback
                if (dist > 1f)
                {
                    Vector2 kb2 = Vector2.Normalize(e.Position - _playerPos) * SwordKnockback;
                    e.Velocity += kb2;
                }
                _enemies[i] = e;
            }
        }

        // Melee BREAK finisher — E key when near a broken low-HP enemy
        if (kb.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E) && !_finisherActive)
        {
            for (int i = 0; i < _enemies.Count; i++)
            {
                var e = _enemies[i];
                if (!e.Alive || !e.IsBroken) continue;
                if (e.Hp > 255f) continue; // finisher available when broken and HP <= 255
                if (Vector2.Distance(_playerPos, e.Position) > 60f) continue;

                _finisherActive = true;
                _finisherTimer = FinisherDuration;
                _finisherTarget = e.Position;
                _finisherEnemyIndex = i;
                _finisherEssence = _loadout.Essence;
                _finisherIsRanged = false;
                _finisherZoom = 1f;
                _finisherKillProcessed = false;
                break;
            }
        }

        // Utility essence — E key when no finisher/NPC interaction triggered
        if (_utilityCooldown > 0) _utilityCooldown -= dt;
        if (_utilityFlashTimer > 0) _utilityFlashTimer -= dt;
        if (kb.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E) && !_finisherActive 
            && _utilityEssence != Essence.None && _utilityCooldown <= 0)
        {
            // Check if near an NPC first — if so, NPC code handles it downstream
            bool nearNpc = false;
            foreach (var npc in _npcs)
                if (Vector2.Distance(_playerPos, npc.Position) < npc.InteractRadius) { nearNpc = true; break; }
            
            if (!nearNpc)
            {
                _utilityCooldown = UtilityCooldownTime;
                _utilityFlashTimer = 0.4f;
                // Burst particles in essence color
                Color utilCol = GetEssenceColor(_utilityEssence);
                for (int up = 0; up < 16; up++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 60f + (float)_rng.NextDouble() * 80f;
                    _particles.Add(new Particle {
                        Position = _playerPos,
                        Velocity = new Vector2(MathF.Cos(a) * spd, MathF.Sin(a) * spd),
                        Life = 0.5f, MaxLife = 0.5f,
                        Color = utilCol, Size = 3f
                    });
                }
                // TODO: Step 4 — check nearby interactables for matching essence
            }
        }

        // Active Reload — requires clips. R starts bar sweep, R again to time it.
        if (kb.IsKeyDown(Keys.R) && !_prevKb.IsKeyDown(Keys.R))
        {
            if (!_reloadActive && _reloadTimer <= 0 && SackClipCount() > 0 && _playerEther < EffectiveMaxEther)
            {
                // Start reload sweep
                _reloadActive = true;
                _reloadCursor = 0f;
                _reloadInputLocked = false;
                PlaySfx(_sfxHit, 0.2f);
            }
            else if (_reloadActive && !_reloadInputLocked)
            {
                // Second press — consume clip and check timing
                _reloadInputLocked = true;
                _reloadActive = false;
                _reloadTimer = ReloadCooldown;
                
                // Visual position: 0→1→0 (right then left)
                float visualPos = _reloadCursor <= 1f ? _reloadCursor : 2f - _reloadCursor;
                
                // Use smallest clip first
                SackRemoveClip(out int clipValue);
                _playerEther = MathF.Min(_playerEther + clipValue, EffectiveMaxEther);
                
                if (visualPos >= ReloadSweetSpotStart && visualPos <= ReloadSweetSpotEnd)
                {
                    // ACTIVE RELOAD — 10% damage bonus on next 8 hits
                    _reloadDmgBonus = 1.10f;
                    _reloadDmgBonusShots = 8;
                    _trauma = MathF.Min(_trauma + 0.05f, 0.3f);
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = _playerPos + new Vector2(-24, -28),
                        Text = $"ACTIVE! +{clipValue}EP",
                        Color = new Color(80, 255, 160),
                        Life = 1f, MaxLife = 1f,
                    });
                    for (int rp = 0; rp < 16; rp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float r = 25f + (float)_rng.NextDouble() * 15f;
                        _particles.Add(new Particle
                        {
                            Position = _playerPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                            Velocity = -new Vector2(MathF.Cos(a), MathF.Sin(a)) * 60f,
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(80, 255, 160) * 0.8f,
                            Size = 2.5f,
                        });
                    }
                }
                else
                {
                    // FAILED — still reloads, secret: next hit does +50%
                    _reloadDmgBonus = 1.5f;
                    _reloadDmgBonusShots = 1;
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = _playerPos + new Vector2(-18, -25),
                        Text = $"+{clipValue}EP",
                        Color = new Color(100, 180, 255),
                        Life = 0.8f, MaxLife = 0.8f,
                    });
                    for (int rp = 0; rp < 8; rp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float r = 30f + (float)_rng.NextDouble() * 20f;
                        _particles.Add(new Particle
                        {
                            Position = _playerPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                            Velocity = -new Vector2(MathF.Cos(a), MathF.Sin(a)) * 50f,
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(80, 160, 255) * 0.8f,
                            Size = 2.5f,
                        });
                    }
                }
            }
        }
        
        // Update reload bar sweep
        if (_reloadActive)
        {
            _reloadCursor += dt / (ReloadDuration * 0.5f); // 0→2 in ReloadDuration seconds
            if (_reloadCursor >= 2f)
            {
                // Ran out of time — consume clip, normal reload, no bonus
                _reloadActive = false;
                _reloadTimer = ReloadCooldown;
                SackRemoveClip(out int clipValue);
                _playerEther = MathF.Min(_playerEther + clipValue, EffectiveMaxEther);
                _floatingTexts.Add(new FloatingText
                {
                    Position = _playerPos + new Vector2(-18, -25),
                    Text = $"+{clipValue}EP",
                    Color = new Color(100, 180, 255),
                    Life = 0.8f, MaxLife = 0.8f,
                });
            }
        }

        // Synthesize clips — only available at Room 5 merchant (removed Tab shortcut)

        // Movement
        if (_isDashing)
        {
            _playerPos += _dashDir * DashSpeed * dt;
            
            // Shield-dash opens ShieldDash doors on contact
            if (_gameMode == GameMode.Awakening)
            {
                var dashRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
                int dax = _arena.Left, day = _arena.Top, daw = _arena.Width, dah = _arena.Height;
                for (int di = 0; di < _doors.Count; di++)
                {
                    var d = _doors[di];
                    if (d.FromScreen != _currentScreen || d.State != DoorState.Locked || d.KeyType != DoorKeyType.ShieldDash) continue;
                    Rectangle doorRect = d.Side switch
                    {
                        "N" => new Rectangle(dax + daw / 2 - 50, day, 100, 20),
                        "S" => new Rectangle(dax + daw / 2 - 50, day + dah - 20, 100, 20),
                        "W" => new Rectangle(dax, day + dah / 2 - 50, 20, 100),
                        "E" => new Rectangle(dax + daw - 20, day + dah / 2 - 50, 20, 100),
                        _ => Rectangle.Empty
                    };
                    if (!dashRect.Intersects(doorRect)) continue;
                    d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                    _doors[di] = d;
                    PlaySfx(_sfxDoorOpen);
                    for (int ri = 0; ri < _doors.Count; ri++)
                    {
                        var rd = _doors[ri];
                        if (rd.FromScreen == d.ToScreen && rd.ToScreen == d.FromScreen && rd.State == DoorState.Locked)
                        {
                            rd.State = DoorState.Opening; rd.OpenTimer = 0.5f;
                            _doors[ri] = rd;
                        }
                    }
                    // Stone shatter effect
                    var dc = new Vector2(doorRect.Center.X, doorRect.Center.Y);
                    for (int dp = 0; dp < 16; dp++)
                    {
                        float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float speed = 40f + (float)_rng.NextDouble() * 60f;
                        float life = 0.4f + (float)_rng.NextDouble() * 0.3f;
                        _particles.Add(new Particle
                        {
                            Position = dc,
                            Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                            Life = life, MaxLife = life,
                            Color = new Color(95, 85, 78),
                            Size = 3f
                        });
                    }
                }
            }
        }
        else
        {
            Vector2 move = Vector2.Zero;
            if (!_ledgeHopping)
            {
            if (kb.IsKeyDown(Keys.W)) move.Y -= 1;
            if (kb.IsKeyDown(Keys.S)) move.Y += 1;
            if (kb.IsKeyDown(Keys.A)) move.X -= 1;
            if (kb.IsKeyDown(Keys.D)) move.X += 1;
            }
            // Wail debuff timer (always ticks, even when not moving)
            if (_wailDebuffTimer > 0) _wailDebuffTimer -= dt;
            if (_webSlowTimer > 0) _webSlowTimer -= dt;
            
            // Spider web tethers: slow player
            for (int wi = _spiderWebs.Count - 1; wi >= 0; wi--)
            {
                var w = _spiderWebs[wi];
                w.Life -= dt;
                if (w.Life <= 0) { _spiderWebs.RemoveAt(wi); continue; }
                _spiderWebs[wi] = w;
                if (Vector2.Distance(_playerPos, w.Position) < w.Radius)
                    _webSlowTimer = 0.3f;
            }

            // Door opening animation timer
            for (int di = 0; di < _doors.Count; di++)
            {
                var d = _doors[di];
                if (d.State == DoorState.Opening)
                {
                    d.OpenTimer -= dt;
                    if (d.OpenTimer <= 0) { d.State = DoorState.Open; d.OpenTimer = 0; }
                    _doors[di] = d;
                }
            }

            if (move.LengthSquared() > 0)
            {
                move.Normalize();
                if (_wailDebuffTimer > 0) move = -move; // inverted movement
                var preMovePos = _playerPos;
                _preMovePos = _playerPos;
                _playerPos += move * PlayerSpeed * (_webSlowTimer > 0 ? 0.4f : 1f) * dt;
                
                // Walk animation + facing direction (ping-pong: 0-1-2-1-0-1-2...)
                _walkAnimTimer += dt * 6f;
                if (_walkAnimTimer >= 4f) _walkAnimTimer -= 4f;
                int raw = (int)_walkAnimTimer;
                _walkFrame = raw < 3 ? raw : 4 - raw; // 0,1,2,1
                // Determine facing from movement direction
                if (MathF.Abs(move.X) > MathF.Abs(move.Y))
                    _facingDir = move.X < 0 ? 1 : 2; // left or right
                else
                    _facingDir = move.Y < 0 ? 3 : 0; // up or down
            }
            else
            {
                _walkFrame = 1; // idle = middle frame (standing)
                _pushTimer = 0f;
            }
            // Override walk anim when pushing against a wall
            if (_pushingWall && move.LengthSquared() > 0)
            {
                _pushTimer += dt;
                _walkFrame = 1; // freeze on standing frame (push pose)
                _wallPushTime += dt;
                _angerPulse += dt;
            }
            else
            {
                _pushTimer = 0f;
                _wallPushTime = 0f;
                _angerPulse = 0f;
            }
        }
        
        // Clamp to screen edges (tiles cover full screen)
        _playerPos.X = MathHelper.Clamp(_playerPos.X, PlayerSize, ScreenW - PlayerSize);
        _playerPos.Y = MathHelper.Clamp(_playerPos.Y, PlayerSize + TSDst, ScreenH - PlayerSize);
        
        // Scrolling camera — smooth follow for rooms larger than screen
        if (_arena.Height > ScreenH - 60) // room taller than screen
        {
            // Target: center camera on player Y, clamped so we never see outside arena
            float targetY = _playerPos.Y - ScreenH / 2f;
            float maxScroll = _arena.Bottom + 80 - ScreenH; // 80 = _arena.Top margin
            targetY = MathHelper.Clamp(targetY, 0f, maxScroll);
            // Asymptotic averaging (Squirrel Eiserloh smooth follow)
            float followSpeed = 5f; // higher = snappier
            _cameraOffset.Y += (targetY - _cameraOffset.Y) * (1f - MathF.Exp(-followSpeed * dt));
            _cameraOffset.Y = MathHelper.Clamp(_cameraOffset.Y, 0f, maxScroll);
        }
        else
        {
            _cameraOffset = Vector2.Zero;
        }
        
        // Cosmetic jump (Space when not dashing — shield dash takes priority when movement keys held)
        bool spacePressed = kb.IsKeyDown(Keys.Space) && !_prevKb.IsKeyDown(Keys.Space);
        bool movementHeld = kb.IsKeyDown(Keys.W) || kb.IsKeyDown(Keys.S) || kb.IsKeyDown(Keys.A) || kb.IsKeyDown(Keys.D);
        if (!_isJumping && !_isDashing && spacePressed && (!_hasShield || !movementHeld))
        {
            _isJumping = true;
            _jumpVelocity = JumpStrength;
        }
        if (_isJumping)
        {
            _jumpHeight += _jumpVelocity * dt;
            _jumpVelocity -= JumpGravity * dt;
            if (_jumpHeight <= 0f)
            {
                _jumpHeight = 0f;
                _isJumping = false;
                _jumpVelocity = 0f;
                // Landing dust puff
                for (int d = 0; d < 10; d++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI; // semicircle upward
                    float spd = 40f + (float)_rng.NextDouble() * 60f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 12f, PlayerSize / 2),
                        Velocity = new Vector2(MathF.Cos(a + MathF.PI) * spd, -15f - (float)_rng.NextDouble() * 25f),
                        Life = 0.5f, MaxLife = 0.5f,
                        Color = new Color(170, 155, 130),
                        Size = 3f + (float)_rng.NextDouble() * 2f
                    });
                }
            }
        }
        
        // Ledge hop update (ALttP style)
        if (_ledgeHopping)
        {
            _ledgeHopTimer += dt;
            float t2 = MathHelper.Clamp(_ledgeHopTimer / LedgeHopDuration, 0f, 1f);
            // Smooth movement
            float smoothT = t2 * t2 * (3f - 2f * t2); // smoothstep
            _playerPos = Vector2.Lerp(_ledgeHopStart, _ledgeHopTarget, smoothT);
            // Visual jump arc (shadow stays, player hops up then down)
            _jumpHeight = MathF.Sin(t2 * MathF.PI) * 45f; // 45px peak arc
            _isJumping = true; // suppress normal jump
            // Rapid walk cycle during hop (ALttP style)
            _walkAnimTimer += dt * 16f; // ~4x normal speed
            if (_walkAnimTimer >= 4f) _walkAnimTimer -= 4f;
            int hopRaw = (int)_walkAnimTimer;
            _walkFrame = hopRaw < 3 ? hopRaw : 4 - hopRaw;
            if (t2 >= 1f)
            {
                _ledgeHopping = false;
                _jumpHeight = 0f;
                _isJumping = false;
                // Landing dust
                for (int d2 = 0; d2 < 6; d2++)
                {
                    float a2 = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd2 = 30f + (float)_rng.NextDouble() * 40f;
                    _particles.Add(new Particle {
                        Position = _playerPos, Velocity = new Vector2(MathF.Cos(a2) * spd2, MathF.Sin(a2) * spd2),
                        Life = 0.4f, MaxLife = 0.4f, Color = new Color(170, 155, 130), Size = 2f
                    });
                }
            }
        }
        
        // Wall collision (push player out of walls) — skip when inside cave or ledge hopping
        _pushingWall = false;
        if (!_inCave && !_ledgeHopping && _screenWalls.TryGetValue(_currentScreen, out var walls))
        {
            var playerRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            _screenWallOneWay.TryGetValue(_currentScreen, out var owList);
            for (int wi = 0; wi < walls.Count; wi++)
            {
                var wall = walls[wi];
                if (!playerRect.Intersects(wall)) continue;
                int ow = (owList != null && wi < owList.Count) ? owList[wi] : 0;
                
                // Find minimum push-out direction
                float pushLeft = playerRect.Right - wall.Left;
                float pushRight = wall.Right - playerRect.Left;
                float pushUp = playerRect.Bottom - wall.Top;
                float pushDown = wall.Bottom - playerRect.Top;
                float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                
                // One-way: skip push if player is passing from the allowed direction
                // ow=1: can pass from north (player above, moving down) → skip pushUp
                // ow=2: can pass from south → skip pushDown
                // ow=3: can pass from west → skip pushLeft  
                // ow=4: can pass from east → skip pushRight
                // One-way walls (ALttP ledge style):
                // ow direction = direction player CAN hop THROUGH
                // ow=1: hop up, ow=2: hop down, ow=3: hop left, ow=4: hop right
                // Ledge lines: zero-thickness edges, only block perpendicular movement
                if (ow >= 1 && ow <= 4 && !_ledgeHopping)
                {
                    bool isHorizontal = (ow <= 2); // 1=hop up, 2=hop down → horizontal line
                    float linePos, playerMin, playerMax, playerCenter, halfSize;
                    bool overlapsLine;
                    float penetration;
                    bool playerOnHopSide;
                    
                    if (isHorizontal)
                    {
                        // Horizontal ledge: check if player X overlaps wall X range
                        // Half-tile ledge (≤24px tall): line at bottom/top edge
                        // Full-tile+ ledge (>24px): line at center between the two halves
                        bool isHalfTile = wall.Height <= 24;
                        if (isHalfTile)
                            linePos = (ow == 1) ? wall.Top : wall.Bottom;
                        else
                            linePos = wall.Top + wall.Height / 2f;
                        overlapsLine = playerRect.Right > wall.Left && playerRect.Left < wall.Right;
                        halfSize = PlayerHitboxH / 2f;
                        playerCenter = _playerPos.Y + PlayerHitboxOffsetY;
                        // ow=1 (hop up): player is below line, pushing up
                        // ow=2 (hop down): player is above line, pushing down
                        playerOnHopSide = (ow == 1) ? (playerCenter > linePos) : (playerCenter < linePos);
                        float pTop = _playerPos.Y + PlayerHitboxOffsetY - PlayerHitboxH / 2f;
                        float pBot = _playerPos.Y + PlayerHitboxOffsetY + PlayerHitboxH / 2f;
                        penetration = (ow == 1) ? (linePos - pTop) : (pBot - linePos);
                    }
                    else
                    {
                        // Vertical ledge: check if player Y overlaps wall Y range
                        bool isHalfTileV = wall.Width <= 24;
                        if (isHalfTileV)
                            linePos = (ow == 3) ? wall.Left : wall.Right;
                        else
                            linePos = wall.Left + wall.Width / 2f;
                        overlapsLine = playerRect.Bottom > wall.Top && playerRect.Top < wall.Bottom;
                        halfSize = PlayerSize / 2f;
                        playerCenter = _playerPos.X;
                        playerOnHopSide = (ow == 3) ? (playerCenter > linePos) : (playerCenter < linePos);
                        float pLeft = _playerPos.X - PlayerSize / 2f;
                        float pRight = _playerPos.X + PlayerSize / 2f;
                        penetration = (ow == 3) ? (linePos - pLeft) : (pRight - linePos);
                    }
                    
                    if (!overlapsLine || penetration <= 0) continue; // not touching line
                    
                    // Check if player is pushing in the hop direction
                    bool pushing = false;
                    if (ow == 1 && kb.IsKeyDown(Keys.W) && playerOnHopSide) pushing = true;
                    if (ow == 2 && kb.IsKeyDown(Keys.S) && playerOnHopSide) pushing = true;
                    if (ow == 3 && kb.IsKeyDown(Keys.A) && playerOnHopSide) pushing = true;
                    if (ow == 4 && kb.IsKeyDown(Keys.D) && playerOnHopSide) pushing = true;
                    
                    if (pushing && _ledgeHoldDir == ow)
                    {
                        _ledgeHoldTimer += dt;
                        if (_ledgeHoldTimer >= LedgeHopHoldTime)
                        {
                            _ledgeHopping = true;
                            _ledgeHopTimer = 0f;
                            _ledgeHopStart = _playerPos;
                            float hopDist = TSDst + PlayerSize;
                            _ledgeHopTarget = _playerPos;
                            if (ow == 1) _ledgeHopTarget.Y -= hopDist;
                            if (ow == 2) _ledgeHopTarget.Y += hopDist;
                            if (ow == 3) _ledgeHopTarget.X -= hopDist;
                            if (ow == 4) _ledgeHopTarget.X += hopDist;
                            _ledgeHoldTimer = 0f;
                            _ledgeHoldDir = 0;
                            break; // stop checking walls this frame — hop is starting
                        }
                    }
                    else if (pushing)
                    {
                        _ledgeHoldTimer = 0f;
                        _ledgeHoldDir = ow;
                    }
                    else
                    {
                        _ledgeHoldTimer = 0f;
                        _ledgeHoldDir = 0;
                    }
                    
                    // Push out only along the perpendicular axis (float-precise)
                    _pushingWall = true;
                    if (isHorizontal)
                    {
                        float pTop = _playerPos.Y + PlayerHitboxOffsetY - PlayerHitboxH / 2f;
                        float pBot = _playerPos.Y + PlayerHitboxOffsetY + PlayerHitboxH / 2f;
                        if (_playerPos.Y + PlayerHitboxOffsetY > linePos)
                        {
                            float fix = linePos - pTop;
                            if (fix > 0) _playerPos.Y += fix;
                        }
                        else
                        {
                            float fix = pBot - linePos;
                            if (fix > 0) _playerPos.Y -= fix;
                        }
                    }
                    else
                    {
                        float pLeft = _playerPos.X - PlayerSize / 2f;
                        float pRight = _playerPos.X + PlayerSize / 2f;
                        if (_playerPos.X > linePos)
                        {
                            float fix = linePos - pLeft;
                            if (fix > 0) _playerPos.X += fix;
                        }
                        else
                        {
                            float fix = pRight - linePos;
                            if (fix > 0) _playerPos.X -= fix;
                        }
                    }
                    playerRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
                    continue;
                }
                
                // Solid wall or player-only wall: push out using float-precise hitbox
                float fLeft = _playerPos.X - PlayerSize / 2f;
                float fRight = _playerPos.X + PlayerSize / 2f;
                float fTop = _playerPos.Y + PlayerHitboxOffsetY - PlayerHitboxH / 2f;
                float fBot = _playerPos.Y + PlayerHitboxOffsetY + PlayerHitboxH / 2f;
                float fpLeft = fRight - wall.Left;
                float fpRight = wall.Right - fLeft;
                float fpUp = fBot - wall.Top;
                float fpDown = wall.Bottom - fTop;
                float fMinPush = MathF.Min(MathF.Min(fpLeft, fpRight), MathF.Min(fpUp, fpDown));
                
                _pushingWall = true;
                if (fMinPush == fpLeft) _playerPos.X -= fpLeft;
                else if (fMinPush == fpRight) _playerPos.X += fpRight;
                else if (fMinPush == fpUp) _playerPos.Y -= fpUp;
                else _playerPos.Y += fpDown;
                playerRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            }
        }
        
        // Pedestal collision (pickups have solid pedestals)
        if (_gameMode == GameMode.Awakening)
        {
            var playerRect2 = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            foreach (var p in _pickups)
            {
                // Only collide if in correct context (cave for wand/wandofmerlin)
                if ((p.Type == "wand" || p.Type == "wandofmerlin") && !_inCave) continue;
                var pedestal = new Rectangle((int)p.Position.X - 18, (int)p.Position.Y + 8, 36, 18);
                if (!playerRect2.Intersects(pedestal)) continue;
                float pushLeft = playerRect2.Right - pedestal.Left;
                float pushRight = pedestal.Right - playerRect2.Left;
                float pushUp = playerRect2.Bottom - pedestal.Top;
                float pushDown = pedestal.Bottom - playerRect2.Top;
                float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                if (minPush == pushLeft) _playerPos.X -= pushLeft;
                else if (minPush == pushRight) _playerPos.X += pushRight;
                else if (minPush == pushUp) _playerPos.Y -= pushUp;
                else _playerPos.Y += pushDown;
                playerRect2 = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            }
            
            // Locked door collision
            foreach (var d in _doors)
            {
                if (d.FromScreen != _currentScreen || (d.State != DoorState.Locked && d.State != DoorState.Opening)) continue;
                int dax = _arena.Left, day = _arena.Top, daw = _arena.Width, dah = _arena.Height;
                Rectangle doorRect = d.Side switch
                {
                    "N" => new Rectangle(dax + daw / 2 - 50, day, 100, 20),
                    "S" => new Rectangle(dax + daw / 2 - 50, day + dah - 20, 100, 20),
                    "W" => new Rectangle(dax, day + dah / 2 - 50, 20, 100),
                    "E" => new Rectangle(dax + daw - 20, day + dah / 2 - 50, 20, 100),
                    _ => Rectangle.Empty
                };
                if (!playerRect2.Intersects(doorRect)) continue;
                float pL = playerRect2.Right - doorRect.Left;
                float pR = doorRect.Right - playerRect2.Left;
                float pU = playerRect2.Bottom - doorRect.Top;
                float pD = doorRect.Bottom - playerRect2.Top;
                float mp = MathF.Min(MathF.Min(pL, pR), MathF.Min(pU, pD));
                if (mp == pL) _playerPos.X -= pL;
                else if (mp == pR) _playerPos.X += pR;
                else if (mp == pU) _playerPos.Y -= pU;
                else _playerPos.Y += pD;
                playerRect2 = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            }
        }
        
        // Player hedge collision (solid, no buff)
        {
            var pRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            foreach (var hedge in _hedgeWalls)
            {
                if (hedge.GrowTimer > 0) continue;
                if (!pRect.Intersects(hedge.Rect)) continue;
                float pushLeft = pRect.Right - hedge.Rect.Left;
                float pushRight = hedge.Rect.Right - pRect.Left;
                float pushUp = pRect.Bottom - hedge.Rect.Top;
                float pushDown = hedge.Rect.Bottom - pRect.Top;
                float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                if (minPush == pushLeft) _playerPos.X -= pushLeft;
                else if (minPush == pushRight) _playerPos.X += pushRight;
                else if (minPush == pushUp) _playerPos.Y -= pushUp;
                else _playerPos.Y += pushDown;
                pRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            }
        }
        
        // Screen transitions
        if (!_inTransition && !_inCave)
        {
            int col = (_currentScreen - 1) % 3; // 0,1,2
            int row = (_currentScreen - 1) / 3; // 0,1,2
            bool transitioned = false;
            float edge = PlayerSize; // transition triggers at arena edge
            int prevScreen = _currentScreen;
            
            // Use screen edges for transitions (tiles cover full screen)
            float transL = PlayerSize;           // left screen edge + margin
            float transR = ScreenW - PlayerSize; // right screen edge - margin
            float transT = PlayerSize + TSDst;    // top: 1 tile down from screen edge (avoid HUD)
            float transB = ScreenH - PlayerSize; // bottom screen edge - margin
            
            // Block screen transitions while inside Room 3 portal
            if (_inPortal || _portalTransitioning || _challengeActive) transitioned = true; // skip transition checks

            // Door-centered transition zones (doors are 100px wide, centered on wall)
            int doorZone = 50; // half door width
            int doorCXLocal = _arena.Left + _arena.Width / 2;
            int doorCYLocal = _arena.Top + _arena.Height / 2;
            bool hasDoorW = _gameMode != GameMode.Awakening || HasDoorOnSide(_currentScreen, "W");
            bool hasDoorE = _gameMode != GameMode.Awakening || HasDoorOnSide(_currentScreen, "E");
            bool hasDoorN = _gameMode != GameMode.Awakening || HasDoorOnSide(_currentScreen, "N");
            bool hasDoorS = _gameMode != GameMode.Awakening || HasDoorOnSide(_currentScreen, "S");
            bool inDoorY = _playerPos.Y >= doorCYLocal - doorZone && _playerPos.Y <= doorCYLocal + doorZone;
            bool inDoorX = _playerPos.X >= doorCXLocal - doorZone && _playerPos.X <= doorCXLocal + doorZone;

            if (!transitioned && _playerPos.X <= transL && col > 0)
            {
                if (!hasDoorW || !inDoorY || (_gameMode == GameMode.Awakening && IsAwakeningDoorLocked(_currentScreen, "W"))) { _playerPos.X = transL + 1; }
                else {
                _currentScreen--;
                _playerPos.X = transR - edge;
                _transitionDir = new Vector2(-ScreenW, 0);
                transitioned = true;
                }
            }
            else if (!transitioned && _playerPos.X >= transR && col < 2)
            {
                if (!hasDoorE || !inDoorY || (_gameMode == GameMode.Awakening && IsAwakeningDoorLocked(_currentScreen, "E"))) { _playerPos.X = transR - 1; }
                else {
                _currentScreen++;
                _playerPos.X = transL + edge;
                _transitionDir = new Vector2(ScreenW, 0);
                transitioned = true;
                }
            }
            else if (!transitioned && _playerPos.Y <= transT && row > 0)
            {
                if (!hasDoorN || !inDoorX || (_gameMode == GameMode.Awakening && IsAwakeningDoorLocked(_currentScreen, "N"))) { _playerPos.Y = transT + 1; }
                else {
                _currentScreen -= 3;
                _playerPos.Y = transB - edge;
                _transitionDir = new Vector2(0, -ScreenH);
                transitioned = true;
                }
            }
            else if (!transitioned && _playerPos.Y >= transB && row < 3)
            {
                if (!hasDoorS || !inDoorX || (_gameMode == GameMode.Awakening && IsAwakeningDoorLocked(_currentScreen, "S"))) { _playerPos.Y = transB - 1; }
                else {
                _currentScreen += 3;
                _playerPos.Y = transT + edge;
                _transitionDir = new Vector2(0, ScreenH);
                transitioned = true;
                }
            }

            if (transitioned && prevScreen != _currentScreen)
                UnlockDoorPair(prevScreen, _currentScreen);

            if (transitioned && prevScreen != _currentScreen)
            {
                _inTransition = true;
                _screenTransitionTimer = ScreenTransitionDuration;
                // Keep planted seeds, clear everything else
                for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
                {
                    if (_projectiles[pi].Params.IsStationary && _projectiles[pi].ArcLanded)
                        continue; // keep planted seeds
                    _projectiles.RemoveAt(pi);
                }
                _lingerZones.Clear();
                // Save hedges for the screen we're leaving, load hedges for destination
                {
                    int oldScreen = _currentScreen;
                    if (_transitionDir.X < 0) oldScreen = _currentScreen + 1;
                    else if (_transitionDir.X > 0) oldScreen = _currentScreen - 1;
                    else if (_transitionDir.Y < 0) oldScreen = _currentScreen + 3;
                    else if (_transitionDir.Y > 0) oldScreen = _currentScreen - 3;
                    // Save current hedges
                    if (_hedgeWalls.Count > 0)
                        _screenHedges[oldScreen] = new List<HedgeWall>(_hedgeWalls);
                    else
                        _screenHedges.Remove(oldScreen);
                    if (_revealedMazeCells.Count > 0)
                        _screenRevealedCells[oldScreen] = new HashSet<(int,int)>(_revealedMazeCells);
                    else
                        _screenRevealedCells.Remove(oldScreen);
                    // Load destination hedges
                    if (_screenHedges.TryGetValue(_currentScreen, out var destHedges))
                        _hedgeWalls = new List<HedgeWall>(destHedges);
                    else
                        _hedgeWalls.Clear();
                    if (_screenRevealedCells.TryGetValue(_currentScreen, out var destCells))
                        _revealedMazeCells = new HashSet<(int,int)>(destCells);
                    else
                        _revealedMazeCells.Clear();
                }
                _particles.Clear();
                _burningTrees.Clear();
                _enemyProjectiles.Clear();
                _spiderWebs.Clear();
                
                // Snap companions to player on room transition
                if (_angelActive)
                {
                    var ca = _angel;
                    ca.ActualPos = _playerPos + new Vector2(MathF.Cos(ca.OrbitAngle), MathF.Sin(ca.OrbitAngle)) * 60f;
                    ca.Velocity = Vector2.Zero;
                    ca.Returning = false;
                    ca.SwoopTimer = 0f;
                    _angel = ca;
                }
                if (_knightActive)
                {
                    var ck = _knight;
                    ck.ActualPos = _playerPos + new Vector2(MathF.Cos(ck.OrbitAngle), MathF.Sin(ck.OrbitAngle)) * 70f;
                    ck.Velocity = Vector2.Zero;
                    ck.Returning = false;
                    ck.SwingTimer = 0f;
                    ck.WindupTimer = 0f;
                    _knight = ck;
                }
                
                // Campaign: save current enemies back, load new screen's enemies
                if (_gameMode == GameMode.Campaign)
                {
                    // Save enemies from the screen we just LEFT (oldScreen)
                    int oldScreen = _currentScreen;
                    // Calculate old screen from transition direction
                    if (_transitionDir.X < 0) oldScreen = _currentScreen + 1;
                    else if (_transitionDir.X > 0) oldScreen = _currentScreen - 1;
                    else if (_transitionDir.Y < 0) oldScreen = _currentScreen + 3;
                    else if (_transitionDir.Y > 0) oldScreen = _currentScreen - 3;
                    
                    // Check if old screen is cleared (all enemies dead)
                    bool allDead = true;
                    foreach (var e in _enemies)
                        if (e.Alive) { allDead = false; break; }
                    if (allDead && _enemies.Count > 0)
                        _clearedScreens.Add(oldScreen);
                    
                    // Save remaining alive enemies
                    if (!_clearedScreens.Contains(oldScreen))
                        _screenEnemies[oldScreen] = new List<Enemy>(_enemies.Where(e => e.Alive));
                    
                    // Load new screen's enemies (or empty if cleared)
                    _enemies.Clear();
                    _enemyById.Clear();
                    _immolants.Clear();
                    if (!_clearedScreens.Contains(_currentScreen) && _screenEnemies.TryGetValue(_currentScreen, out var savedEnemies))
                    {
                        foreach (var e in savedEnemies)
                        {
                            _enemies.Add(e);
                            _enemyById[e.Id] = e;
                        }
                    }
                }
                
                // Awakening mode: update room name, init room content
                if (_gameMode == GameMode.Awakening)
                {
                    _roomNameDisplay = AwakeningRoomNames[_currentScreen];
                    _roomNameTimer = 3f;
                    _enemies.Clear();
                    _enemyById.Clear();
                    _pickups.Clear();
                    _tripwires.Clear();
                    
                    // Save any clip/armor drops on the floor as room items before clearing
                    {
                        int oldScr = _currentScreen;
                        if (_transitionDir.X < 0) oldScr = _currentScreen + 1;
                        else if (_transitionDir.X > 0) oldScr = _currentScreen - 1;
                        else if (_transitionDir.Y < 0) oldScr = _currentScreen + 3;
                        else if (_transitionDir.Y > 0) oldScr = _currentScreen - 3;
                        var groundItems = new List<SackItem>();
                        foreach (var ed in _etherDrops)
                        {
                            if (ed.IsClip)
                            {
                                SackItemType ctype = ed.ClipEP >= 100 ? SackItemType.LargeClip : ed.ClipEP >= 50 ? SackItemType.MediumClip : SackItemType.SmallClip;
                                groundItems.Add(new SackItem { Type = ctype, Count = 1, MaxStack = 3, Width = 1, Height = 1 });
                            }
                            else if (ed.IsArmor)
                            {
                                groundItems.Add(new SackItem { Type = SackItemType.Armor, Armor = ed.ArmorDrop, Count = 1, MaxStack = 1, Width = 2, Height = 2 });
                            }
                        }
                        if (groundItems.Count > 0)
                        {
                            _roomDroppedItems[oldScr] = groundItems;
                            // Track average position of dropped ether items for thief spawn
                            Vector2 avgDropPos = Vector2.Zero; int dropCount = 0;
                            foreach (var ed in _etherDrops)
                            {
                                if (ed.IsClip || ed.IsArmor) { avgDropPos += ed.Position; dropCount++; }
                            }
                            _roomDropPos[oldScr] = dropCount > 0 ? avgDropPos / dropCount : _playerPos;
                        }
                        else
                        {
                            _roomDroppedItems.Remove(oldScr);
                            _roomDropPos.Remove(oldScr);
                        }
                    }
                    
                    _etherDrops.Clear();
                    _webTethers.Clear();
                    _pickupFlashTimer = 0;
                    _pickupTextTimer = 0;
                    _pickupText = null;
                    _pickupParticles.Clear();
                    _lavaRects.Clear();
                    _boneHusks.Clear();
                            if (!_portalTransitioning && !_inPortal)
                    {
                        _inPortal = false;
                        _challengeActive = false;
                    }
                    // Set arena size — Room 11 is tall (scrolling room)
                    if (_currentScreen == 11)
                        _arena = new Rectangle(60, 80, 1160, 1300); // 1280×1440 minus margins
                    else
                        _arena = new Rectangle(60, 80, 1160, 580);
                    _cameraOffset = Vector2.Zero;
                    InitAwakeningRoomContent(_currentScreen);
                    _visitedRooms.Add(_currentScreen);
                    
                    // Thief: if items were left in this room, spawn a thief
                    if (_roomDroppedItems.TryGetValue(_currentScreen, out var droppedItems) && droppedItems.Count > 0 && !_roomsWithThief.Contains(_currentScreen))
                    {
                        _roomsWithThief.Add(_currentScreen);
                        // Spawn thief where items were dropped
                        Vector2 spawnPos = _roomDropPos.TryGetValue(_currentScreen, out var dp) ? dp 
                            : new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2);
                        // Clamp to arena
                        spawnPos.X = MathHelper.Clamp(spawnPos.X, _arena.Left + 30, _arena.Right - 30);
                        spawnPos.Y = MathHelper.Clamp(spawnPos.Y, _arena.Top + 30, _arena.Bottom - 30);
                        var thief = new Enemy(spawnPos, 180f);
                        thief.Type = EnemyType.Thief;
                        thief.MaxStagger = 100f;
                        thief.AiPhase = 0; // rummaging (unaware)
                        thief.AiStateTimer = 0f;
                        _thiefStolenLoot[thief.Id] = new List<SackItem>(droppedItems);
                        _enemies.Add(thief);
                        _enemyById[thief.Id] = thief;
                        _roomDroppedItems.Remove(_currentScreen);
                        _roomDropPos.Remove(_currentScreen);
                    }
                    if (_visitedRooms.Count(r => r != 5) >= 4)
                        _merchantActive = true;
                    // Pellinore warning
                    if (_pellinoreActive && !_pellinoreDefeated && _pellinoreScreen == _currentScreen)
                    {
                        _pellinorePos = new Vector2(
                            _arena.Left + 60 + (float)_rng.NextDouble() * (_arena.Width - 120),
                            _arena.Top + 60 + (float)_rng.NextDouble() * (_arena.Height - 120));
                        _pendingTextBox = "A cold presence lingers...";
                    }
                }
            }
        }

        if (_inTransition)
        {
            _screenTransitionTimer -= dt;
            float t = MathHelper.Clamp(_screenTransitionTimer / ScreenTransitionDuration, 0f, 1f);
            // SmoothStop for nice deceleration (Squirrel Eiserloh style)
            float smooth = 1f - (1f - (1f - t)) * (1f - (1f - t)); // = 1 - t²
            _transitionOffset = _transitionDir * t;
            if (_screenTransitionTimer <= 0)
            {
                _inTransition = false;
                _screenTransitionTimer = 0;
                _transitionOffset = Vector2.Zero;
                
                // Show pending text box after transition completes
                if (_pendingTextBox != null)
                {
                    _textBoxMessage = _pendingTextBox;
                    _textBoxWaiting = true;
                    _pendingTextBox = null;
                }
            }
        }



        _playerPos.X = MathHelper.Clamp(_playerPos.X, PlayerSize / 2, ScreenW - PlayerSize / 2);
        _playerPos.Y = MathHelper.Clamp(_playerPos.Y, PlayerSize / 2 + TSDst, ScreenH - PlayerSize / 2);

        // Undine familiar update
        UpdateUndine(dt);

        // Pickup collision (Campaign/Gauntlet only — Awakening uses pickup system)
        if (_gameMode != GameMode.Awakening)
        {
            if (!_hasWand && Vector2.Distance(_playerPos, _wandPickupPos) < (PlayerSize + PickupSize) / 2f)
                _hasWand = true;
            if (!_hasShield && Vector2.Distance(_playerPos, _shieldPickupPos) < (PlayerSize + PickupSize) / 2f)
                _hasShield = true;
        }

        // Fire rate from loadout
        var resolvedParams = ProjectileParams.Resolve(_loadout);

        // Haste Band relic: fire rate boost proportional to base fire rate
        // Slow forms get a bigger absolute boost, fast forms get less
        if (_hasHasteBand)
            resolvedParams.FireRate *= 0.65f; // 35% faster across the board

        _fireTimer -= dt;
        
        // Dragon Dance: decay stacks over time
        if (_dragonDanceStacks > 0)
        {
            _dragonDanceStacks -= 0.03f * dt; // slow decay (~3.3s to lose one stack)
            if (_dragonDanceStacks < 0) _dragonDanceStacks = 0;
        }

        // No wand yet — show question mark on click
        if (!_hasWand && mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released && _fireTimer <= 0)
        {
            _questionMarkTimer = 0.8f;
            _fireTimer = 0.3f;
        }

        // Seed Recall: RMB detonates all planted seeds
        if (_hasWand && _loadout.Form == Form.Seed 
            && mouse.RightButton == ButtonState.Pressed && _prevMouse.RightButton == ButtonState.Released)
        {
            for (int i = 0; i < _projectiles.Count; i++)
            {
                var s = _projectiles[i];
                if (s.Alive && s.Params.IsStationary && _loadout.Form == Form.Seed)
                {
                    s.Age = s.Lifetime; // force expiry → triggers detonation in death code
                    _projectiles[i] = s;
                }
            }
        }
        // Charge shot (hold right mouse button with Wand of Merlin relic) — not Seed form
        else if (_hasWandOfMerlin && _hasWand && _loadout.Form != Form.Seed && mouse.RightButton == ButtonState.Pressed)
        {
            _isCharging = true;
            _chargeTimer = MathF.Min(_chargeTimer + dt, ChargeTime);
        }
        else if (_isCharging && mouse.RightButton == ButtonState.Released)
        {
            // Release charged shot
            if (_chargeTimer >= ChargeTime * 0.3f) // minimum 30% charge to fire
            {
                float chargePct = _chargeTimer / ChargeTime;
                float chargeEther = 40f * chargePct; // charged shots cost up to 40 mana
                if (_playerEther >= chargeEther)
                {
                    _playerEther -= chargeEther;
                    _etherFlashTimer = 0.15f;
                    FireWeapon(_mouseWorld, chargePct);
                    _fireTimer = resolvedParams.FireRate * 1.5f;
                    // Charged attack juice: hitstop + trauma + zoom
                    float chargeJuice = chargePct * chargePct; // quadratic scaling
                    _hitstopTimer = MathF.Max(_hitstopTimer, 0.02f + chargeJuice * 0.04f); // up to 0.06s
                    _trauma = MathF.Min(_trauma + 0.08f + chargeJuice * 0.15f, 1f);
                }
            }
            _isCharging = false;
            _chargeTimer = 0f;
        }

        // Tiamat's Garden: hold LMB to continuously grow maze outward
        if (_hasWand && _currentFusion == "Tiamat's Garden" && mouse.LeftButton == ButtonState.Pressed)
        {
            _tiamatGrowTimer -= dt;
            if (_tiamatGrowTimer <= 0)
            {
                _tiamatGrowTimer = 0.25f; // pulse every 0.25s
                _tiamatGrowRadius += 20f; // expand 30px per pulse
                float epCost = 8f; // 5 EP per grow pulse
                if (_playerEther >= epCost)
                {
                    _playerEther -= epCost;
                    _etherFlashTimer = 0.08f;
                    Vector2 center = _mouseWorld;
                    center.X = MathHelper.Clamp(center.X, _arena.Left + 20, _arena.Right - 20);
                    center.Y = MathHelper.Clamp(center.Y, _arena.Top + 20, _arena.Bottom - 20);
                    RevealMazeNear(center, _tiamatGrowRadius);
                    // Growth ripple particles at the expanding edge
                    for (int p = 0; p < 8; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = center + new Vector2(MathF.Cos(a), MathF.Sin(a)) * _tiamatGrowRadius,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 20f + new Vector2(0, -15f),
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = _rng.NextDouble() > 0.5 ? new Color(50, 140, 35) : new Color(200, 40, 60),
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                }
            }
        }
        else
        {
            _tiamatGrowTimer = 0;
            _tiamatGrowRadius = 60f; // reset to base radius
        }
        
        // === Behavior-only abilities (Form==None, Essence==None, Behavior!=None) ===
        if (_hasWand && !_isCharging && mouse.LeftButton == ButtonState.Pressed && _fireTimer <= 0
            && _loadout.Form == Form.None && _loadout.Essence == Essence.None && _loadout.Behavior != Behavior.None
            && _behaviorAbilityCooldown <= 0)
        {
            bool triggered = false;
            if (_loadout.Behavior == Behavior.Shatter && _playerEther >= 18f)
            {
                // Quake Stomp
                _playerEther -= 18f;
                _behaviorAbilityCooldown = 1.5f;
                _trauma = MathF.Min(_trauma + 0.3f, 1f);
                float baseDmg = 15f * 0.5f; // 50% of single-slot base damage
                for (int ei = 0; ei < _enemies.Count; ei++)
                {
                    if (!_enemies[ei].Alive) continue;
                    float dist = Vector2.Distance(_playerPos, _enemies[ei].Position);
                    if (dist < 60f)
                    {
                        _enemies[ei].Hp -= baseDmg;
                        _enemies[ei].Stagger += 15f;
                        if (_enemies[ei].Stagger >= _enemies[ei].MaxStagger)
                        {
                            _enemies[ei].Stagger = 0;
                            _enemies[ei].StaggerTimer = 0.5f;
                        }
                        Vector2 pushDir = _enemies[ei].Position - _playerPos;
                        if (pushDir.LengthSquared() > 0.01f) pushDir.Normalize(); else pushDir = Vector2.UnitY;
                        _enemies[ei].KnockbackVel = pushDir * 80f;
                        if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                    }
                }
                // Cracked wall — Quake Stomp breaks it too
                if (!_crackedWallBroken && _inCave)
                {
                    var ca = _caveArea;
                    Vector2 crackCenter = new Vector2(ca.Right - 6, ca.Y + ca.Height / 3 + 25);
                    if (Vector2.Distance(_playerPos, crackCenter) < 80f)
                    {
                        _crackedWallBroken = true;
                        _crackedWallShakeTimer = 0.4f;
                        for (int d = 0; d < 25; d++)
                        {
                            float a2 = MathF.PI + (float)_rng.NextDouble() * MathF.PI;
                            float sp = 40f + (float)_rng.NextDouble() * 120f;
                            float li = 0.6f + (float)_rng.NextDouble() * 0.5f;
                            _particles.Add(new Particle
                            {
                                Position = crackCenter,
                                Velocity = new Vector2(MathF.Cos(a2), MathF.Sin(a2)) * sp,
                                Life = li, MaxLife = li,
                                Color = new Color(60 + _rng.Next(30), 50 + _rng.Next(25), 45 + _rng.Next(20)),
                                Size = 2f + (float)_rng.NextDouble() * 3f
                            });
                        }
                        _pickups.Add(new PickupItem
                        {
                            Position = new Vector2(ca.Right + 30, ca.Y + ca.Height / 3 + 25),
                            Name = "Wand of Merlin",
                            DisplayText = "Wand of Merlin — Hold to charge a devastating blast",
                            Type = "wandofmerlin",
                            Collected = false,
                            BobTimer = 0f,
                            GlowColor = new Color(100, 80, 200)
                        });
                    }
                }
                // Dust/rock particles
                for (int p = 0; p < 18; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 40f + (float)_rng.NextDouble() * 60f;
                    float life = 0.4f + (float)_rng.NextDouble() * 0.3f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * spd,
                        Life = life, MaxLife = life,
                        Color = new Color(120 + _rng.Next(40), 100 + _rng.Next(30), 80 + _rng.Next(20)),
                        Size = 2f + (float)_rng.NextDouble() * 2f
                    });
                }
                triggered = true;
            }
            else if (_loadout.Behavior == Behavior.Linger && _playerEther >= 20f)
            {
                // Ward
                _playerEther -= 20f;
                _behaviorAbilityCooldown = 2f;
                _wardZone = (_playerPos, 6f, 6f, 50f);
                _wardZoneActive = true;
                triggered = true;
            }
            else if (_loadout.Behavior == Behavior.Bloom && _playerEther >= 15f)
            {
                // Aegis Burst
                _playerEther -= 15f;
                _behaviorAbilityCooldown = 2f;
                _aegisBurstTimer = 0.2f;
                _aegisBurstPos = _playerPos;
                // Reflect enemy projectiles within 70px
                for (int ep = 0; ep < _enemyProjectiles.Count; ep++)
                {
                    var eproj = _enemyProjectiles[ep];
                    if (Vector2.Distance(eproj.Position, _playerPos) < 70f)
                    {
                        eproj.Velocity = -eproj.Velocity;
                        _enemyProjectiles[ep] = eproj;
                    }
                }
                // Knockback enemies within 70px
                for (int ei = 0; ei < _enemies.Count; ei++)
                {
                    if (!_enemies[ei].Alive) continue;
                    if (Vector2.Distance(_playerPos, _enemies[ei].Position) < 70f)
                    {
                        Vector2 pushDir = _enemies[ei].Position - _playerPos;
                        if (pushDir.LengthSquared() > 0.01f) pushDir.Normalize(); else pushDir = Vector2.UnitY;
                        _enemies[ei].KnockbackVel = pushDir * 40f;
                    }
                }
                // Sparkle particles
                for (int p = 0; p < 12; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 30f,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 50f,
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(255, 240, 180),
                        Size = 2f
                    });
                }
                triggered = true;
            }
            if (triggered)
            {
                _etherFlashTimer = 0.15f;
                _fireTimer = 0.3f;
            }
        }
        // === Essence-only abilities (Form==None, Behavior==None, Essence!=None) ===
        else if (_hasWand && !_isCharging && mouse.LeftButton == ButtonState.Pressed && _fireTimer <= 0
            && _loadout.Form == Form.None && _loadout.Behavior == Behavior.None && _loadout.Essence != Essence.None
            && _playerEther >= 25f)
        {
            _playerEther -= 25f;
            _etherFlashTimer = 0.15f;
            _fireTimer = 1f;
            _elementalArmorTimer = 25f;
            _exoskeletonShieldActive = false;
            if (_loadout.Essence == Essence.Cinder)
            {
                _elementalArmor = ElementalArmorType.Cinder;
            }
            else if (_loadout.Essence == Essence.Pulse)
            {
                _elementalArmor = ElementalArmorType.Pulse;
            }
            else if (_loadout.Essence == Essence.Bone)
            {
                _elementalArmor = ElementalArmorType.Bone;
                _exoskeletonShieldActive = true;
            }
            else
            {
                _elementalArmorTimer = 0f; // unsupported essence, refund timer
            }
        }
        else if (_hasWand && !_isCharging && mouse.LeftButton == ButtonState.Pressed && _fireTimer <= 0)
        {
            // All slots empty — show question mark
            if (_loadout.Form == Form.None && _loadout.Behavior == Behavior.None && _loadout.Essence == Essence.None)
            {
                _questionMarkTimer = 0.8f;
                _fireTimer = 0.3f;
            }
            else
            {
            // Grimoire gate: 3 slots filled but no grimoire = fizzle
            int slots = _loadout.FilledSlots;
            
            // Autonomous companions — intercept click before EP cost
            if (_currentFusion == "Caoilfhionn" || _currentFusion == "Scathach")
            {
                if (_currentFusion == "Caoilfhionn")
                {
                    if (!_angelActive)
                    {
                        // First click = summon
                        _angelActive = true;
                        var ca = _angel;
                        ca.ActualPos = _playerPos + new Vector2(60f, 0f);
                        ca.Velocity = Vector2.Zero;
                        ca.SwoopsLeft = 5;
                        ca.DepartTimer = 0f;
                        ca.SwoopCooldown = 0.5f;
                        _angel = ca;
                    }
                    else if (_angel.DepartTimer <= 0)
                    {
                        var ca = _angel;
                        Vector2 toM = _mouseWorld - _playerPos;
                        if (toM.Length() > 200f) toM = Vector2.Normalize(toM) * 200f;
                        ca.SwoopStart = ca.ActualPos;
                        ca.SwoopTarget = _playerPos + toM;
                        ca.SwoopTimer = 0.3f;
                        ca.SwoopCooldown = 0.8f;
                        ca.Returning = false;
                        _angel = ca;
                    }
                }
                else if (_currentFusion == "Scathach")
                {
                    if (!_knightActive)
                    {
                        // First click = summon
                        _knightActive = true;
                        var ck = _knight;
                        ck.ActualPos = _playerPos + new Vector2(-70f, 0f);
                        ck.Velocity = Vector2.Zero;
                        ck.SwingsLeft = 4;
                        ck.DepartTimer = 0f;
                        ck.SwingCooldown = 0.8f;
                        ck.WindupTimer = 0f;
                        ck.SwingTimer = 0f;
                        _knight = ck;
                    }
                    else if (_knight.DepartTimer <= 0 
                        && _knight.WindupTimer <= 0 && _knight.SwingTimer <= 0)
                    {
                        var ck = _knight;
                        Vector2 toM = _mouseWorld - _playerPos;
                        if (toM.Length() > 200f) toM = Vector2.Normalize(toM) * 200f;
                        ck.SwingStart = ck.ActualPos;
                        ck.SwingTarget = _playerPos + toM;
                        ck.SwingAngle = MathF.Atan2(toM.Y, toM.X);
                        ck.WindupTimer = 0.25f;
                        ck.SwingCooldown = 1.5f;
                        ck.Returning = false;
                        _knight = ck;
                    }
                }
                _fireTimer = 0.3f; // short cooldown to prevent spam
                return;
            }
            
            if (slots == 3 && !_hasGrimoire)
            {
                // Fizzle: wand crackles but nothing happens
                _floatingTexts.Add(new FloatingText
                {
                    Position = _playerPos + new Vector2(-8, -28),
                    Text = "!",
                    Color = new Color(255, 220, 100),
                    Life = 1.2f, MaxLife = 1.2f,
                });
                // Crackling particles from wand tip
                for (int sp = 0; sp < 8; sp++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + Vector2.Normalize(_mouseWorld - _playerPos) * 12f,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (20f + (float)_rng.NextDouble() * 30f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(180, 160, 255) * 0.6f,
                        Size = 1.5f,
                    });
                }
                _fireTimer = 0.5f; // cooldown so it doesn't spam
                // Show textbox on first fizzle only
                if (!_hasShownGrimoireFizzle)
                {
                    _hasShownGrimoireFizzle = true;
                    _textBoxMessage = "The wand crackles with energy... but the power dissipates. You need a Grimoire to channel triple fusions.";
                    _textBoxWaiting = true;
                }
                return;
            }
            // Mana cost: base by slot count, fusion overrides
            float etherCost = 0f; // 0-1 slot: FREE (basic tools always available)
            if (slots == 2) etherCost = 8f; // dual combo
            if (slots == 3) etherCost = _hasGrimoire && _currentFusion != null ? 20f : 12f; // 3 slots
            // Seed discount: setup weapon needs cheaper shots
            if (_loadout.Form == Form.Seed) etherCost *= 0.7f;
            // Per-fusion overrides
            if (_currentFusion == "Senbonzakura") etherCost = 14f; // lighter than typical L3
            else if (_currentFusion == "Pillars of Muspelheim") etherCost = 22f; // each bolt spawns a lingering pillar
            else if (_currentFusion == "Sacred Fist") etherCost = 25f; // 3-5 shots from full
            else if (_currentFusion == "Shadow Stitch") etherCost = 50f; // 2 shots max
            else if (_currentFusion == "Hiten Mitsurugi") etherCost = 35f; // high commit
            else if (_currentFusion == "Dragon Slayer") etherCost = 40f; // colossal swing
            else if (_currentFusion == "Marrow Bloom") etherCost = 25f;
            else if (_currentFusion == "Earthquake") etherCost = 40f; // huge area spell
            else if (_currentFusion == "Unicorn Diana") etherCost = 35f;
            else if (_currentFusion == "Thunderbird Mars") etherCost = 30f;
            else if (_currentFusion == "Dark Gate") etherCost = 28f;
            else if (_currentFusion == "Serpent Mercury") etherCost = 25f;
            else if (_currentFusion == "Gae Bolg") etherCost = 20f;
            else if (_currentFusion == "Grave Call") etherCost = 18f;
            else if (_currentFusion == "Tiamat's Garden") etherCost = 50f;
            else if (_currentFusion == "Fire-flaught Hasp") etherCost = 20f;
            else if (_currentFusion == "Graveyard") etherCost = 22f;
            else if (_currentFusion == "Ifrit's Fury") etherCost = 25f;
            else if (_currentFusion == "Raijin's Drum") etherCost = 22f;
            else if (_currentFusion == "Prominence") etherCost = 50f;
            else if (_currentFusion == "Raiju") etherCost = 24f;
            else if (_currentFusion == "Fossil") etherCost = 20f;
            else if (_currentFusion == "Bifrost") etherCost = 24f;
            else if (_currentFusion == "Spine of the World") etherCost = 22f;
            else if (_currentFusion == "Fenrir's Jaw") etherCost = 26f;
            else if (_currentFusion == "Hammer of God") etherCost = 35f;
            else if (_currentFusion == "Caoilfhionn") etherCost = 30f;
            else if (_currentFusion == "Scathach") etherCost = 30f;
            else if (_currentFusion == "Amaterasu") etherCost = 30f;
            else if (_currentFusion == "Hydra") etherCost = 26f;
            else if (_currentFusion == "Za Hando") etherCost = 35f;
            else if (_currentFusion == "Mollificare") etherCost = 20f;
            else if (_currentFusion == "Abhiseka") etherCost = 30f;
            else if (_currentFusion == "Sambhogakaya") etherCost = 35f;
            
            if (_playerEther >= etherCost)
            {
                _playerEther -= etherCost;
                _etherFlashTimer = 0.15f;
                FireWeapon(_mouseWorld);
                _fireTimer = resolvedParams.FireRate;
                // Hiten Mitsurugi: brutal recovery — miss and you're dead
                if (_currentFusion == "Hiten Mitsurugi") _fireTimer = 2.5f;
                else if (_currentFusion == "Dragon Slayer") _fireTimer = 2.0f;
                if (_currentFusion == "Marrow Bloom") _fireTimer = 0.8f;
                if (_currentFusion == "Earthquake") _fireTimer = 1.5f; // slow between casts
                if (_currentFusion == "Hammer of God") _fireTimer = 2.0f; // divine judgment takes time
                if (_currentFusion == "Za Hando") _fireTimer = 2.5f; // erasing space takes commitment
                if (_currentFusion == "Sambhogakaya") _fireTimer = 3.0f; // transcendence has a long cooldown
                // Immolant bone attack tracking
                if (_loadout.Essence == Essence.Bone && (_currentScreen == 8 || _currentScreen == 9))
                {
                    if (_currentScreen == 8) _boneAttackCount8++;
                    else _boneAttackCount9++;
                }
            }
            } // end else (non-empty slots)
        }
        // Quick-fire: fresh click bypasses fire timer at 1.5× EP cost (only for EP-costing attacks)
        else if (_hasWand && !_isCharging && mouse.LeftButton == ButtonState.Pressed 
                 && _prevMouse.LeftButton == ButtonState.Released && _fireTimer > 0)
        {
            // Autonomous companions — redirect click, no EP cost
            if (_currentFusion == "Caoilfhionn" || _currentFusion == "Scathach")
            {
                if (_currentFusion == "Caoilfhionn" && _angelActive && _angel.DepartTimer <= 0)
                {
                    var ca = _angel;
                    Vector2 toM = _mouseWorld - _playerPos;
                    if (toM.Length() > 200f) toM = Vector2.Normalize(toM) * 200f;
                    ca.SwoopStart = ca.ActualPos;
                    ca.SwoopTarget = _playerPos + toM;
                    ca.SwoopTimer = 0.3f;
                    ca.SwoopCooldown = 0.8f;
                    ca.Returning = false;
                    _angel = ca;
                }
                else if (_currentFusion == "Scathach" && _knightActive && _knight.DepartTimer <= 0 
                    && _knight.WindupTimer <= 0 && _knight.SwingTimer <= 0)
                {
                    var ck = _knight;
                    Vector2 toM = _mouseWorld - _playerPos;
                    if (toM.Length() > 200f) toM = Vector2.Normalize(toM) * 200f;
                    ck.SwingStart = ck.ActualPos;
                    ck.SwingTarget = _playerPos + toM;
                    ck.SwingAngle = MathF.Atan2(toM.Y, toM.X);
                    ck.WindupTimer = 0.25f;
                    ck.SwingCooldown = 1.5f;
                    ck.Returning = false;
                    _knight = ck;
                }
                // Don't summon from quick-fire — only normal fire summons
            }
            else
            {
            float etherCost = 0f; // 0-1 slot: FREE
            int slots = _loadout.FilledSlots;
            if (slots == 2) etherCost = 8f;
            if (slots == 3) etherCost = 20f;
            if (_loadout.Form == Form.Seed) etherCost *= 0.7f;
            if (_currentFusion == "Senbonzakura") etherCost = 14f;
            else if (_currentFusion == "Sacred Fist") etherCost = 25f;
            else if (_currentFusion == "Shadow Stitch") etherCost = 50f;
            else if (_currentFusion == "Hiten Mitsurugi") etherCost = 35f;
            else if (_currentFusion == "Earthquake") etherCost = 40f;
            else if (_currentFusion == "Unicorn Diana") etherCost = 35f;
            else if (_currentFusion == "Thunderbird Mars") etherCost = 30f;
            else if (_currentFusion == "Dark Gate") etherCost = 28f;
            else if (_currentFusion == "Serpent Mercury") etherCost = 25f;
            else if (_currentFusion == "Gae Bolg") etherCost = 20f;
            else if (_currentFusion == "Grave Call") etherCost = 18f;
            else if (_currentFusion == "Tiamat's Garden") etherCost = 50f;
            else if (_currentFusion == "Marrow Bloom") etherCost = 25f;
            else if (_currentFusion == "Hammer of God") etherCost = 35f;
            else if (_currentFusion == "Caoilfhionn") etherCost = 30f;
            else if (_currentFusion == "Za Hando") etherCost = 35f;
            else if (_currentFusion == "Mollificare") etherCost = 20f;
            else if (_currentFusion == "Abhiseka") etherCost = 30f;
            else if (_currentFusion == "Sambhogakaya") etherCost = 35f;
            etherCost *= 1.5f; // quick-fire penalty
            
            // Quick-fire only works for attacks that cost EP — free attacks must respect fire timer
            if (etherCost <= 0f) { /* do nothing — hold-fire at normal rate instead */ }
            else if (_playerEther >= etherCost)
            {
                _playerEther -= etherCost;
                _etherFlashTimer = 0.15f;
                FireWeapon(_mouseWorld);
                _fireTimer = resolvedParams.FireRate * 0.5f; // shorter cooldown after quick-fire
                if (_currentFusion == "Hiten Mitsurugi") _fireTimer = 2.5f; // no bypass for Hiten
                else if (_currentFusion == "Dragon Slayer") _fireTimer = 2.0f; // no bypass
                if (_currentFusion == "Marrow Bloom") _fireTimer = 0.8f;
                if (_currentFusion == "Hammer of God") _fireTimer = 2.0f;
                if (_currentFusion == "Za Hando") _fireTimer = 2.5f;
                if (_currentFusion == "Sambhogakaya") _fireTimer = 3.0f;
            }
            } // end else (non-companion quick-fire)
        }

        // Shadow Stitch: release LMB → deal damage to all chained, end channel
        if (_shadowStitch.Active && mouse.LeftButton == ButtonState.Released)
        {
            int chainCount = _shadowStitch.ChainedIds.Count;
            float dmgPerEnemy = (8f + chainCount * 12f); // scales with chain length
            
            for (int c = 0; c < chainCount; c++)
            {
                if (_enemyById.TryGetValue(_shadowStitch.ChainedIds[c], out var ce) && ce.Alive)
                {
                        ce.Hp -= dmgPerEnemy;
                        ce.Possessed = false;
                        ce.StaggerTimer = 0;
                        ce.HitFlash = 0.15f;
                        ce.KnockbackVel = Vector2.Zero;
                        ce.SquashTimer = 0.1f;
                        
                        // Dark explosion per enemy on release
                        SpawnExplosion(ce.Position, new Color(100, 30, 150), 12, 0.35f, 8f);
                        
                        if (ce.Hp <= 0)
                        {
                            ce.Alive = false;
                            _killCount++;
                            SpawnExplosion(ce.Position, ce.BaseColor, 10, 0.3f, 6f);
                        }
                }
            }
            
            // Big release burst at player
            _hitstopTimer = 0.08f + chainCount * 0.03f;
            _trauma = MathF.Min(_trauma + 0.15f + chainCount * 0.05f, 1f);
            SpawnExplosion(_shadowStitch.AnchorPos, new Color(60, 20, 90), 15, 0.4f, 10f);
            
            _shadowStitch.Active = false;
            _shadowStitch.ChainedIds = null;
            _fireTimer = 0.5f; // cooldown after release
        }

        if (kb.IsKeyDown(Keys.D1) && !_prevKb.IsKeyDown(Keys.D1))
            _loadout.Form = CycleEnum(_loadout.Form, _unlockedForms);
        if (kb.IsKeyDown(Keys.D2) && !_prevKb.IsKeyDown(Keys.D2))
            _loadout.Behavior = CycleEnum(_loadout.Behavior, _unlockedBehaviors);
        if (kb.IsKeyDown(Keys.D3) && !_prevKb.IsKeyDown(Keys.D3))
            _loadout.Essence = CycleEnum(_loadout.Essence, _unlockedEssences);

        // Check spell fusion
        if (kb.IsKeyDown(Keys.D1) && !_prevKb.IsKeyDown(Keys.D1) ||
            kb.IsKeyDown(Keys.D2) && !_prevKb.IsKeyDown(Keys.D2) ||
            kb.IsKeyDown(Keys.D3) && !_prevKb.IsKeyDown(Keys.D3))
        {
            RefreshCombo();
        }

        for (int i = _projectiles.Count - 1; i >= 0; i--)
        {
            bool wasArcing = _projectiles[i].ArcDuration > 0 && !_projectiles[i].ArcLanded;
            _projectiles[i].Update(dt, _playerPos, _arena);
            
            // Spiral Lance: keep beam alive while mouse held, drain EP
            if (_currentDualCombo == "Spiral Lance" && _projectiles[i].Alive && _projectiles[i].BeamLen > 0 && Mouse.GetState().LeftButton == ButtonState.Pressed && _playerEther > 0)
            {
                _projectiles[i].Age = MathF.Min(_projectiles[i].Age, _projectiles[i].Params.Lifetime * 0.5f);
                _playerEther -= 30f * dt;
            }
            
            // Cave wall collision — kill projectiles that exit cave bounds (except into alcove)
            if (_inCave && _projectiles[i].Alive)
            {
                // Cracked wall check — must run BEFORE cave bullet wall kills projectiles
                if (!_crackedWallBroken && _currentScreen == 5)
                {
                    var ca2 = _caveArea;
                    Rectangle crackHitbox = new Rectangle(ca2.Right - 12, ca2.Y + ca2.Height / 3, 24, 50);
                    if (crackHitbox.Contains((int)_projectiles[i].Position.X, (int)_projectiles[i].Position.Y) && _loadout.Behavior == Behavior.Shatter)
                    {
                        _crackedWallBroken = true;
                        _crackedWallShakeTimer = 0.4f;
                        _trauma = MathF.Min(_trauma + 0.5f, 1f);
                        _projectiles[i].Alive = false;
                        PlaySfx(_sfxHit);
                        for (int d = 0; d < 25; d++)
                        {
                            float angle = MathF.PI + (float)_rng.NextDouble() * MathF.PI;
                            float speed = 40f + (float)_rng.NextDouble() * 120f;
                            float life = 0.6f + (float)_rng.NextDouble() * 0.5f;
                            _particles.Add(new Particle
                            {
                                Position = new Vector2(ca2.Right - 6, ca2.Y + ca2.Height / 3 + 25),
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = new Color(60 + _rng.Next(30), 50 + _rng.Next(25), 45 + _rng.Next(20)),
                                Size = 2f + (float)_rng.NextDouble() * 3f
                            });
                        }
                        _pickups.Add(new PickupItem
                        {
                            Position = new Vector2(ca2.Right + 30, ca2.Y + ca2.Height / 3 + 25),
                            Name = "Wand of Merlin",
                            DisplayText = "Wand of Merlin obtained — Hold to charge a devastating blast",
                            Type = "wandofmerlin",
                            GlowColor = new Color(100, 80, 200)
                        });
                    }
                }
                
                var p = _projectiles[i];
                var ca = _caveArea;
                bool outsideCave = p.Position.X < ca.Left || p.Position.Y < ca.Top || p.Position.Y > ca.Bottom;
                bool outsideRight = p.Position.X > ca.Right;
                if (_crackedWallBroken && outsideRight)
                {
                    int alcoveTop = ca.Y + ca.Height / 3 - 5;
                    int alcoveBot = alcoveTop + 60;
                    outsideRight = p.Position.Y < alcoveTop || p.Position.Y > alcoveBot || p.Position.X > ca.Right + 70;
                }
                if (outsideCave || outsideRight)
                {
                    _projectiles[i].Alive = false;
                }
            }
            
            // Wall-type-based projectile bouncing (for non-internally-bouncing projectiles)
            if (_gameMode == GameMode.Awakening && !_projectiles[i].Params.Bounces && !_inPortal)
            {
                // Water ripple when projectile exits over water wall
                var proj = _projectiles[i];
                if (!proj.Alive && _gameMode == GameMode.Awakening)
                {
                    WallType wt = WallType.None;
                    if (proj.Position.X < _arena.Left) wt = GetRoomWall(_currentScreen, "W");
                    else if (proj.Position.X > _arena.Right) wt = GetRoomWall(_currentScreen, "E");
                    else if (proj.Position.Y < _arena.Top) wt = GetRoomWall(_currentScreen, "N");
                    else if (proj.Position.Y > _arena.Bottom) wt = GetRoomWall(_currentScreen, "S");
                    
                    if (wt == WallType.Water)
                    {
                        Vector2 ripplePos = new Vector2(
                            MathHelper.Clamp(proj.Position.X, _arena.Left, _arena.Right),
                            MathHelper.Clamp(proj.Position.Y, _arena.Top, _arena.Bottom));
                        // Expanding ring particles
                        for (int r = 0; r < 8; r++)
                        {
                            float a = r * MathF.PI * 2f / 8f;
                            float spd = 15f + (float)_rng.NextDouble() * 10f;
                            _particles.Add(new Particle
                            {
                                Position = ripplePos,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = new Color(100, 170, 220),
                                Size = 1.5f
                            });
                        }
                        // Central splash
                        _particles.Add(new Particle
                        {
                            Position = ripplePos,
                            Velocity = Vector2.Zero,
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(180, 220, 255),
                            Size = 3f
                        });
                    }
                    else if (wt == WallType.Stone || wt == WallType.None)
                    {
                        // Stone/default wall impact — dust + sparks
                        Vector2 hitPos = new Vector2(
                            MathHelper.Clamp(proj.Position.X, _arena.Left, _arena.Right),
                            MathHelper.Clamp(proj.Position.Y, _arena.Top, _arena.Bottom));
                        for (int sp = 0; sp < 8; sp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 30f + (float)_rng.NextDouble() * 60f;
                            _particles.Add(new Particle
                            {
                                Position = hitPos,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                                MaxLife = 0.7f,
                                Color = new Color(140 + _rng.Next(50), 130 + _rng.Next(40), 100 + _rng.Next(30)),
                                Size = 2f + (float)_rng.NextDouble() * 2f
                            });
                        }
                    }
                    else if (wt == WallType.Tree)
                    {
                        // Tree wall impact — leaf burst
                        Vector2 hitPos = new Vector2(
                            MathHelper.Clamp(proj.Position.X, _arena.Left, _arena.Right),
                            MathHelper.Clamp(proj.Position.Y, _arena.Top, _arena.Bottom));
                        for (int sp = 0; sp < 4; sp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = hitPos,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 25f,
                                Life = 0.5f, MaxLife = 0.5f,
                                Color = new Color(50 + _rng.Next(40), 100 + _rng.Next(40), 30 + _rng.Next(20)),
                                Size = 1.5f
                            });
                        }
                        // Cinder projectiles set trees on fire
                        if (proj.Params.EssenceType == Essence.Cinder)
                        {
                            _burningTrees.Add((hitPos, 5f));
                        }
                    }
                }
            }
            
            // Seed landing impact
            if (wasArcing && _projectiles[i].ArcLanded)
            {
                var landColor = new Color(_projectiles[i].Params.Color.R, _projectiles[i].Params.Color.G, _projectiles[i].Params.Color.B);
                // Impact burst
                SpawnExplosion(_projectiles[i].Position, landColor, 8, 0.25f, 8f);
                // Dust cloud (ground debris)
                for (int d = 0; d < 5; d++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, 2f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 50f, -10f - (float)_rng.NextDouble() * 20f),
                        Life = 0.35f, MaxLife = 0.35f,
                        Color = new Color(140, 130, 110) * 0.5f,
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
            }
            
            // Seed proximity detonation: armed seeds pop when enemy gets close
            if (_projectiles[i].Alive && _projectiles[i].Params.IsStationary 
                && _loadout.Form == Form.Seed && _projectiles[i].Age > 0.5f) // 0.5s arm time
            {
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    if (Vector2.Distance(_projectiles[i].Position, _enemies[j].Position) < 25f)
                    {
                        var s2 = _projectiles[i];
                        s2.Age = s2.Lifetime; // trigger detonation
                        _projectiles[i] = s2;
                        // Proximity trigger flash
                        SpawnExplosion(_projectiles[i].Position, Color.White, 6, 0.15f, 10f);
                        _trauma = MathF.Min(_trauma + 0.03f, 1f);
                        break;
                    }
                }
            }
            
            // Projectile-wall collision
            if (_projectiles[i].Alive && !_projectiles[i].Params.IsStationary 
                && _projectiles[i].BeamLen <= 0 // beams handled separately
                && _screenWalls.TryGetValue(_currentScreen, out var pWalls))
            {
                var pRect = _projectiles[i].HitBox;
                _screenWallOneWay.TryGetValue(_currentScreen, out var pOwList);
                for (int pwi = 0; pwi < pWalls.Count; pwi++)
                {
                    var wall = pWalls[pwi];
                    if (!pRect.Intersects(wall)) continue;
                    // Projectiles pass through ledge walls only in the hop direction
                    int pow = (pOwList != null && pwi < pOwList.Count) ? pOwList[pwi] : 0;
                    if (pow == 5) continue; // player-only wall, bullets pass through
                    if (pow > 0 && pow <= 4)
                    {
                        var vel = _projectiles[i].Velocity;
                        bool passThrough = false;
                        if (pow == 1 && vel.Y < 0) passThrough = true; // hop up, bullet going up
                        if (pow == 2 && vel.Y > 0) passThrough = true; // hop down, bullet going down
                        if (pow == 3 && vel.X < 0) passThrough = true; // hop left
                        if (pow == 4 && vel.X > 0) passThrough = true; // hop right
                        if (passThrough) continue;
                    }
                    if (_projectiles[i].Params.Bounces && _projectiles[i].Params.MaxBounces > 0)
                    {
                        // Bounce off wall
                        float pushLeft = pRect.Right - wall.Left;
                        float pushRight = wall.Right - pRect.Left;
                        float pushUp = pRect.Bottom - wall.Top;
                        float pushDown = wall.Bottom - pRect.Top;
                        float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                        if (minPush == pushLeft || minPush == pushRight)
                            _projectiles[i].Velocity.X = -_projectiles[i].Velocity.X;
                        else
                            _projectiles[i].Velocity.Y = -_projectiles[i].Velocity.Y;
                        _projectiles[i].Params.MaxBounces--;
                        
                        // Silk Snare: trail silk thread from last bounce to this bounce
                        if (_projectiles[i].FusionName == "SilkSnare")
                        {
                            Vector2 fromPos = _projectiles[i].ArcStart.LengthSquared() > 0 ? _projectiles[i].ArcStart : _playerPos;
                            float hue = (_projectiles[i].Params.MaxBounces * 50f + _totalTime * 40f) % 360f;
                            _tripwires.Add(new Tripwire
                            {
                                Start = fromPos,
                                End = _projectiles[i].Position,
                                Life = 5f, MaxLife = 5f,
                                WireColor = HueToColor(hue),
                                HitsLeft = 3,
                                Damage = _projectiles[i].Params.BaseDamage * 0.25f,
                                HitEnemies = new HashSet<int>(),
                            });
                            _projectiles[i].ArcStart = _projectiles[i].Position;
                        }
                        _particles.Add(new Particle
                        {
                            Position = _projectiles[i].Position,
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                            Life = 0.15f, MaxLife = 0.15f,
                            Color = new Color(_projectiles[i].Params.Color.R, _projectiles[i].Params.Color.G, _projectiles[i].Params.Color.B),
                            Size = 2f,
                        });
                    }
                    else
                    {
                        var p = _projectiles[i];
                        var wallHitPos = p.Position;
                        var pColor = new Color(p.Params.Color.R, p.Params.Color.G, p.Params.Color.B);
                        
                        // Shatter on wall hit — spawn fragments
                        if (p.Params.ShatterCount > 0)
                        {
                            int frags = p.Params.ShatterCount;
                            for (int s = 0; s < frags; s++)
                            {
                                float angle = ((float)s / frags) * MathF.PI * 2f + (float)_rng.NextDouble() * 0.3f;
                                var fragVel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * (p.Params.Speed * 0.6f);
                                var fragParms = p.Params;
                                fragParms.ShatterCount = 0; // no recursive shatter
                                fragParms.BaseDamage *= 0.4f;
                                fragParms.Lifetime = 0.3f;
                                fragParms.Size = MathF.Max(p.Params.Size * 0.5f, 2f);
                                _projectiles.Add(new Projectile(wallHitPos, fragVel, fragParms));
                            }
                            SpawnExplosion(wallHitPos, pColor, 6, 0.2f, 5f);
                        }
                        
                        // Linger on wall hit — spawn zone at impact
                        if (p.Params.LingerDuration > 0)
                        {
                            float lr = p.Params.LingerRadius > 0 ? p.Params.LingerRadius : 15f;
                            _lingerZones.Add(new LingerZone
                            {
                                Position = wallHitPos,
                                Radius = lr,
                                Life = p.Params.LingerDuration,
                                MaxLife = p.Params.LingerDuration,
                                Damage = p.Params.BaseDamage * 0.15f,
                                TickTimer = 0f,
                                Color = pColor,
                                EssenceType = p.Params.EssenceType,
                                FusionTag = p.Params.EssenceType == Essence.Cinder ? "EmberPool" : p.Params.EssenceType == Essence.Pulse ? "SparkPool" : null,
                            });
                        }
                        
                        // Web Trap: spawn large web zone on wall/obstacle hit
                        if (p.FusionName == "WebTrap")
                        {
                            _lingerZones.Add(new LingerZone
                            {
                                Position = wallHitPos,
                                Radius = 55f,
                                Life = 6f, MaxLife = 6f,
                                Damage = p.Params.BaseDamage * 0.1f,
                                TickTimer = 0f,
                                Color = new Color(200, 180, 220),
                                EssenceType = Essence.Silk,
                                FusionTag = "WebTrap",
                                SlowFactor = 0.3f,
                            });
                            // Web deployment particles
                            for (int wp = 0; wp < 15; wp++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float r = (float)_rng.NextDouble() * 50f;
                                _particles.Add(new Particle
                                {
                                    Position = wallHitPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                                    Velocity = new Vector2(MathF.Cos(a) * 15f, MathF.Sin(a) * 15f),
                                    Life = 0.4f, MaxLife = 0.4f,
                                    Color = new Color(200, 180, 220) * 0.6f,
                                    Size = 1.5f,
                                });
                            }
                        }
                        
                        // Bloom: burst of particles on wall (visual pop)
                        if (p.Params.BloomGrowRate > 0)
                        {
                            SpawnExplosion(wallHitPos, pColor, 10, 0.3f, 8f);
                        }
                        
                        // Nova: shockwave doesn't stop at walls (by design — it's a shockwave)
                        // Chain: handled separately (dies on wall)
                        
                        // Cinder: flame burst on wall impact
                        if (p.Params.EssenceType == Essence.Cinder)
                        {
                            for (int fi = 0; fi < 12; fi++)
                            {
                                float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float spd = 20f + (float)_rng.NextDouble() * 80f;
                                float life = 0.2f + (float)_rng.NextDouble() * 0.4f;
                                double cr = _rng.NextDouble();
                                Color fc = cr < 0.15 ? new Color(255, 255, 220) :
                                           cr < 0.35 ? new Color(255, 220, 60) :
                                           cr < 0.65 ? new Color(255, 140, 30) :
                                           cr < 0.85 ? new Color(255, 80, 15) :
                                                        new Color(200, 40, 10);
                                _particles.Add(new Particle
                                {
                                    Position = wallHitPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                                    Velocity = new Vector2(MathF.Cos(angle) * spd, MathF.Sin(angle) * spd - 40f),
                                    Life = life, MaxLife = life,
                                    Color = fc,
                                    Size = 2f + (float)_rng.NextDouble() * 4f,
                                });
                            }
                        }

                        // Default wall hit spark
                        if (p.Params.ShatterCount <= 0 && p.Params.LingerDuration <= 0 && p.Params.BloomGrowRate <= 0)
                        {
                            SpawnExplosion(wallHitPos, pColor, 3, 0.15f, 4f);
                        }
                        
                        // Silk Shot: create rainbow tripwire from player to wall
                        if (_currentDualCombo == "Rainbow Thread" || p.FusionName == "SilkShot")
                        {
                            float hue = (float)(_rng.NextDouble() * 360.0);
                            Color wireColor = HueToColor(hue);
                            _tripwires.Add(new Tripwire
                            {
                                Start = _playerPos,
                                End = wallHitPos,
                                Life = 6f,
                                MaxLife = 6f,
                                WireColor = wireColor,
                                HitsLeft = 4,
                                Damage = p.Params.BaseDamage * 0.5f,
                                HitEnemies = new HashSet<int>(),
                            });
                            // Rainbow shimmer particles along wire
                            Vector2 wireDir = wallHitPos - _playerPos;
                            float wireLen = wireDir.Length();
                            if (wireLen > 0)
                            {
                                wireDir /= wireLen;
                                for (int tw = 0; tw < 6; tw++)
                                {
                                    float t2 = (float)tw / 5f;
                                    _particles.Add(new Particle
                                    {
                                        Position = Vector2.Lerp(_playerPos, wallHitPos, t2),
                                        Velocity = new Vector2(0, -15f),
                                        Life = 0.4f, MaxLife = 0.4f,
                                        Color = wireColor * 0.8f,
                                        Size = 2f
                                    });
                                }
                            }
                        }
                        
                        _projectiles[i].Alive = false;
                    }
                    break;
                }
            }
            
            // SilkShot: create tripwire when hitting arena border (room edges)
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "SilkShot")
            {
                var sp = _projectiles[i].Position;
                bool hitBorder = sp.X <= _arena.Left || sp.X >= _arena.Right || sp.Y <= _arena.Top || sp.Y >= _arena.Bottom;
                if (hitBorder)
                {
                    Vector2 clampedPos = new Vector2(
                        MathHelper.Clamp(sp.X, _arena.Left, _arena.Right),
                        MathHelper.Clamp(sp.Y, _arena.Top, _arena.Bottom));
                    float hue = (float)(_rng.NextDouble() * 360.0);
                    Color wireColor = HueToColor(hue);
                    _tripwires.Add(new Tripwire
                    {
                        Start = _playerPos,
                        End = clampedPos,
                        Life = 6f,
                        MaxLife = 6f,
                        WireColor = wireColor,
                        HitsLeft = 4,
                        Damage = _projectiles[i].Params.BaseDamage * 0.5f,
                        HitEnemies = new HashSet<int>(),
                    });
                    Vector2 wireDir2 = clampedPos - _playerPos;
                    float wireLen2 = wireDir2.Length();
                    if (wireLen2 > 0)
                    {
                        wireDir2 /= wireLen2;
                        for (int tw = 0; tw < 6; tw++)
                        {
                            float t2 = (float)tw / 5f;
                            _particles.Add(new Particle
                            {
                                Position = Vector2.Lerp(_playerPos, clampedPos, t2),
                                Velocity = new Vector2(0, -15f),
                                Life = 0.4f, MaxLife = 0.4f,
                                Color = wireColor * 0.8f,
                                Size = 2f
                            });
                        }
                    }
                    _projectiles[i].Alive = false;
                }
            }
            
            // Projectile-door collision: shoot locked doors to open (Super Metroid style)
            if (_projectiles[i].Alive && _gameMode == GameMode.Awakening)
            {
                var pRect = _projectiles[i].HitBox;
                int dax = _arena.Left, day = _arena.Top, daw = _arena.Width, dah = _arena.Height;
                for (int di = 0; di < _doors.Count; di++)
                {
                    var d = _doors[di];
                    if (d.FromScreen != _currentScreen || d.State != DoorState.Locked) continue;
                    Rectangle doorRect = d.Side switch
                    {
                        "N" => new Rectangle(dax + daw / 2 - 50, day, 100, 20),
                        "S" => new Rectangle(dax + daw / 2 - 50, day + dah - 20, 100, 20),
                        "W" => new Rectangle(dax, day + dah / 2 - 50, 20, 100),
                        "E" => new Rectangle(dax + daw - 20, day + dah / 2 - 50, 20, 100),
                        _ => Rectangle.Empty
                    };
                    if (!pRect.Intersects(doorRect)) continue;
                    
                    var proj = _projectiles[i];
                    bool canOpen = d.KeyType switch
                    {
                        DoorKeyType.Lance => proj.Params.FormType == Form.Lance,
                        DoorKeyType.Flame => proj.Params.EssenceType == Essence.Cinder,
                        DoorKeyType.Wave => _loadout.Behavior != Behavior.None, // need any behavior equipped
                        DoorKeyType.Grimoire => _hasGrimoire && _loadout.FilledSlots == 3,
                        DoorKeyType.ShieldDash => false,
                        _ => false
                    };
                    
                    if (canOpen)
                    {
                        d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                        _doors[di] = d;
                        // Also open the reverse door
                        for (int ri = 0; ri < _doors.Count; ri++)
                        {
                            var rd = _doors[ri];
                            if (rd.FromScreen == d.ToScreen && rd.ToScreen == d.FromScreen && rd.State == DoorState.Locked)
                            {
                                rd.State = DoorState.Opening; rd.OpenTimer = 0.5f;
                                _doors[ri] = rd;
                            }
                        }
                        _projectiles[i].Alive = false;
                        // Door open particles
                        var doorCenter = new Vector2(doorRect.Center.X, doorRect.Center.Y);
                        for (int dp = 0; dp < 12; dp++)
                        {
                            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float speed = 30f + (float)_rng.NextDouble() * 50f;
                            float life = 0.4f + (float)_rng.NextDouble() * 0.3f;
                            _particles.Add(new Particle
                            {
                                Position = doorCenter,
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = d.KeyType == DoorKeyType.Flame ? new Color(180, 220, 255) :
                                        d.KeyType == DoorKeyType.Grimoire ? new Color(200, 120, 255) :
                                        new Color(200, 180, 140),
                                Size = 3f
                            });
                        }
                    }
                    else
                    {
                        // Wrong item — projectile bounces off, small spark
                        SpawnExplosion(_projectiles[i].Position, Color.Gray, 3, 0.1f, 3f);
                        // Don't kill the projectile — let it continue
                    }
                    break;
                }
            }
            
            // Chain homing: gently steer toward target enemy
            if (_projectiles[i].Alive && _projectiles[i].HomingTargetId >= 0)
            {
                Enemy target = null;
                if (_enemyById.TryGetValue(_projectiles[i].HomingTargetId, out var ht) && ht.Alive)
                    target = ht;
                if (target != null)
                {
                    Vector2 toTarget = target.Position - _projectiles[i].Position;
                    if (toTarget.LengthSquared() > 1f)
                    {
                        toTarget.Normalize();
                        Vector2 currentDir = _projectiles[i].Velocity;
                        float speed = currentDir.Length();
                        if (speed > 0)
                        {
                            currentDir /= speed;
                            // Slerp-like: blend current direction toward target
                            Vector2 newDir = Vector2.Lerp(currentDir, toTarget, _projectiles[i].HomingStrength * dt);
                            if (newDir.LengthSquared() > 0) newDir.Normalize();
                            _projectiles[i].Velocity = newDir * speed;
                        }
                    }
                }
            }
            
            // Marrow Bloom homing handled by Bloom+Lance beam rotation
            
            // Muspelheim fireball trail — thick fire particles
            if (_projectiles[i].Alive && _currentFusion == "Pillars of Muspelheim" && _projectiles[i].Velocity.LengthSquared() > 1f)
            {
                int trailCount = 2 + (_rng.NextDouble() < 0.4 ? 1 : 0);
                for (int tc = 0; tc < trailCount; tc++)
                {
                    float life = 0.2f + (float)_rng.NextDouble() * 0.3f;
                    double cr = _rng.NextDouble();
                    Color fc = cr < 0.15 ? new Color(255, 255, 220) :
                               cr < 0.35 ? new Color(255, 220, 60) :
                               cr < 0.65 ? new Color(255, 140, 30) :
                               cr < 0.85 ? new Color(255, 80, 15) :
                                            new Color(200, 40, 10);
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -40f - (float)_rng.NextDouble() * 50f),
                        Life = life, MaxLife = life,
                        Color = fc,
                        Size = 2f + (float)_rng.NextDouble() * 3.5f,
                    });
                }
            }
            if (_projectiles[i].Alive && _projectiles[i].Params.LingerDuration > 0 
                && !_projectiles[i].Params.IsStationary && _projectiles[i].Velocity.LengthSquared() > 1f
                && (_currentFusion == "Pillars of Muspelheim" || _currentFusion == "Dragonbreath" || _currentFusion == "Vesuvius"))
            {
                _projectiles[i].LingerTrailTimer -= dt;
                if (_projectiles[i].LingerTrailTimer <= 0)
                {
                    _projectiles[i].LingerTrailTimer = 0.15f;
                    bool isPillar = _currentFusion == "Pillars of Muspelheim";
                    bool isDragon = _currentFusion == "Dragonbreath";
                    bool isVesu = _currentFusion == "Vesuvius";
                    float zoneRadius = isVesu ? 20f : isDragon ? 12f : (_projectiles[i].Params.LingerRadius > 0 ? _projectiles[i].Params.LingerRadius * 0.7f : 18f);
                    float zoneLife = isVesu ? 2.5f : isDragon ? 1.5f : (isPillar ? _projectiles[i].Params.LingerDuration * 1.5f : _projectiles[i].Params.LingerDuration);
                    _lingerZones.Add(new LingerZone
                    {
                        Position = _projectiles[i].Position,
                        Radius = zoneRadius,
                        Life = zoneLife,
                        MaxLife = zoneLife,
                        Damage = _projectiles[i].Params.BaseDamage * (isDragon ? 0.1f : isVesu ? 0.12f : 0.15f),
                        TickTimer = 0f,
                        Color = new Color(_projectiles[i].Params.Color.R, _projectiles[i].Params.Color.G, _projectiles[i].Params.Color.B),
                        EssenceType = _projectiles[i].Params.EssenceType,
                        IsPillar = isPillar,
                        PillarTimer = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        FusionTag = isDragon ? "Dragonbreath" : isVesu ? "Vesuvius" : isPillar ? null : _projectiles[i].Params.EssenceType == Essence.Cinder ? "EmberPool" : _projectiles[i].Params.EssenceType == Essence.Pulse ? "SparkPool" : null,
                    });
                }
            }
            
            // Dragonbreath: fire particles trailing each pellet
            if (_projectiles[i].Alive && _currentFusion == "Dragonbreath" && _rng.NextDouble() < 0.4)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -20f - (float)_rng.NextDouble() * 40f),
                    Life = 0.15f + (float)_rng.NextDouble() * 0.2f,
                    MaxLife = 0.35f,
                    Color = _rng.NextDouble() > 0.3 ? new Color(255, 120, 20) : new Color(255, 200, 50),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f,
                });
            }

            // Surtr's Crown: fire trail from orbiting fireballs
            if (_projectiles[i].Alive && _currentFusion == "Surtr's Crown" && _rng.NextDouble() < 0.5)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position,
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                    Life = 0.2f + (float)_rng.NextDouble() * 0.3f,
                    MaxLife = 0.5f,
                    Color = _rng.NextDouble() > 0.4 ? new Color(255, 120, 20) : new Color(255, 200, 50),
                    Size = 2f + (float)_rng.NextDouble() * 3f,
                });
            }

            // Fimbulwinter: frost particle trail on ring projectiles
            if (_projectiles[i].Alive && _currentFusion == "Fimbulwinter" && _rng.NextDouble() < 0.3)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, ((float)_rng.NextDouble() - 0.5f) * 15f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.4f,
                    MaxLife = 0.7f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(180, 220, 255) : new Color(230, 240, 255),
                    Size = 1.5f + (float)_rng.NextDouble() * 2.5f,
                });
            }

            // Vesuvius: rising fire/smoke trail on ring projectiles
            if (_projectiles[i].Alive && _currentFusion == "Vesuvius" && _rng.NextDouble() < 0.4)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position,
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -40f - (float)_rng.NextDouble() * 60f), // rise upward
                    Life = 0.3f + (float)_rng.NextDouble() * 0.4f,
                    MaxLife = 0.7f,
                    Color = _rng.NextDouble() > 0.6 ? new Color(255, 100, 20) : (_rng.NextDouble() > 0.5 ? new Color(255, 200, 50) : new Color(80, 60, 60)),
                    Size = 2f + (float)_rng.NextDouble() * 3f,
                });
            }

            // Gebel's Swarm: dark bat trail + mild homing toward nearest enemy
            if (_projectiles[i].Alive && _currentFusion == "Gebel's Swarm" && _rng.NextDouble() < 0.25)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position,
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                    Life = 0.15f + (float)_rng.NextDouble() * 0.15f,
                    MaxLife = 0.3f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(100, 30, 130) : new Color(50, 15, 60),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f,
                });
            }
            // Gebel bat homing: gentle steer toward nearest enemy
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Gebel's Swarm" && _projectiles[i].Velocity.LengthSquared() > 1f)
            {
                Enemy nearestE = null;
                float nearD = float.MaxValue;
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                    float d = Vector2.Distance(_projectiles[i].Position, _enemies[e].Position);
                    if (d < 200f && d < nearD) { nearD = d; nearestE = _enemies[e]; }
                }
                if (nearestE != null)
                {
                    Vector2 desired = nearestE.Position - _projectiles[i].Position;
                    if (desired.LengthSquared() > 1f)
                    {
                        desired.Normalize();
                        desired *= _projectiles[i].Velocity.Length();
                        _projectiles[i].Velocity = Vector2.Lerp(_projectiles[i].Velocity, desired, 2f * dt);
                    }
                }
            }

            // Fire Bolt: animated flame trail — multi-particle, color lifecycle
            if (_projectiles[i].Alive && _currentDualCombo == "Fire Bolt")
            {
                // 2-3 flame particles per frame for a thick fire trail
                int flameCount = 2 + (_rng.NextDouble() < 0.4 ? 1 : 0);
                for (int fc = 0; fc < flameCount; fc++)
                {
                    float spread = 4f + (float)_rng.NextDouble() * 4f;
                    float lifespan = 0.25f + (float)_rng.NextDouble() * 0.35f;
                    // Pick color along fire gradient: white-hot core → yellow → orange → red
                    double colorRoll = _rng.NextDouble();
                    Color flameColor;
                    if (colorRoll < 0.15) flameColor = new Color(255, 255, 220); // white-hot
                    else if (colorRoll < 0.35) flameColor = new Color(255, 220, 60); // bright yellow
                    else if (colorRoll < 0.65) flameColor = new Color(255, 140, 30); // orange
                    else if (colorRoll < 0.85) flameColor = new Color(255, 80, 15); // deep orange
                    else flameColor = new Color(200, 40, 10); // red ember
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(
                            ((float)_rng.NextDouble() - 0.5f) * spread,
                            ((float)_rng.NextDouble() - 0.5f) * spread),
                        Velocity = new Vector2(
                            ((float)_rng.NextDouble() - 0.5f) * 40f,
                            -30f - (float)_rng.NextDouble() * 60f), // strong upward drift
                        Life = lifespan,
                        MaxLife = lifespan,
                        Color = flameColor,
                        Size = 2f + (float)_rng.NextDouble() * 3.5f, // big start, particle system shrinks
                    });
                }
            }

            // ═══ SHOCK BOLT: lightning crackle trail ═══
            if (_projectiles[i].Alive && _currentDualCombo == "Shock Bolt")
            {
                // 2-3 lightning particles per frame — branching electric trail
                int boltCount = 2 + (_rng.NextDouble() < 0.5 ? 1 : 0);
                for (int bc = 0; bc < boltCount; bc++)
                {
                    float spread = 6f + (float)_rng.NextDouble() * 6f;
                    float lifespan = 0.15f + (float)_rng.NextDouble() * 0.2f;
                    double colorRoll = _rng.NextDouble();
                    Color boltColor;
                    if (colorRoll < 0.2) boltColor = new Color(255, 255, 255);
                    else if (colorRoll < 0.45) boltColor = new Color(180, 200, 255);
                    else if (colorRoll < 0.7) boltColor = new Color(100, 140, 255);
                    else if (colorRoll < 0.85) boltColor = new Color(140, 100, 255);
                    else boltColor = new Color(60, 80, 200);
                    
                    float jitterAngle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float jitterSpeed = 60f + (float)_rng.NextDouble() * 80f;
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(
                            ((float)_rng.NextDouble() - 0.5f) * spread,
                            ((float)_rng.NextDouble() - 0.5f) * spread),
                        Velocity = new Vector2(MathF.Cos(jitterAngle), MathF.Sin(jitterAngle)) * jitterSpeed,
                        Life = lifespan,
                        MaxLife = lifespan,
                        Color = boltColor,
                        Size = 1.5f + (float)_rng.NextDouble() * 2.5f
                    });
                }
                
                if (_rng.NextDouble() < 0.15)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 30f, (float)(_rng.NextDouble() - 0.5) * 30f),
                        Life = 0.08f,
                        MaxLife = 0.08f,
                        Color = new Color(220, 230, 255),
                        Size = 5f + (float)_rng.NextDouble() * 4f
                    });
                }
            }

            // Morrigan's Court: shadow wisp trail from orbiting phantoms
            if (_projectiles[i].Alive && _currentFusion == "Morrigan's Court" && _rng.NextDouble() < 0.35)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -10f - (float)_rng.NextDouble() * 20f), // wisps rise
                    Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                    MaxLife = 0.6f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(80, 30, 100) : new Color(50, 20, 70),
                    Size = 2f + (float)_rng.NextDouble() * 2f,
                });
            }

            // Yggdrasil vine whip trail

            // Shadow Stitch: extending hand projectile — just visual trail, no linger
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "ShadowStitch")
            {
                // Grow slightly as it extends
                float growProgress = MathF.Min(_projectiles[i].Age / 1.2f, 1f);
                _projectiles[i].Params.Size = 14f + growProgress * 6f;

                // Shadow trail along arm from player
                if (_rng.NextDouble() < 0.7)
                {
                    float prog = (float)_rng.NextDouble();
                    Vector2 armPos = Vector2.Lerp(_playerPos, _projectiles[i].Position, prog);
                    _particles.Add(new Particle
                    {
                        Position = armPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                        Velocity = Vector2.Zero,
                        Life = 0.12f, MaxLife = 0.12f,
                        Color = new Color(25, 8, 40),
                        Size = 6f + prog * 6f,
                    });
                }
            }
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Yggdrasil" && _rng.NextDouble() < 0.5)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position,
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                    Life = 0.2f + (float)_rng.NextDouble() * 0.2f,
                    MaxLife = 0.4f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(60, 200, 60) : new Color(100, 220, 40),
                    Size = 2f + (float)_rng.NextDouble() * 2f,
                });
            }

            // Shango's Shale: bolts return to player after 2+ bounces
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Shango's Shale" && _projectiles[i].Params.MaxBounces <= 4)
            {
                Vector2 toPlayer = _playerPos - _projectiles[i].Position;
                if (toPlayer.LengthSquared() > 1f)
                {
                    toPlayer.Normalize();
                    float speed = _projectiles[i].Velocity.Length();
                    Vector2 desired = toPlayer * speed;
                    _projectiles[i].Velocity = Vector2.Lerp(_projectiles[i].Velocity, desired, 5f * dt);
                }
                // Kill bolt when it reaches player (within 15f)
                if (Vector2.Distance(_projectiles[i].Position, _playerPos) < 15f)
                {
                    _projectiles[i].Alive = false;
                    // Return flash
                    SpawnExplosion(_playerPos, new Color(255, 240, 60), 6, 0.15f, 8f);
                }
            }

            // Heaven Bolt: homing toward nearest enemy
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "HeavenBolt")
            {
                Enemy nearest = null;
                float bestD = 200f;
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                    float d = Vector2.Distance(_projectiles[i].Position, _enemies[j].Position);
                    if (d < bestD) { bestD = d; nearest = _enemies[j]; }
                }
                if (nearest != null)
                {
                    Vector2 toE = nearest.Position - _projectiles[i].Position;
                    if (toE.LengthSquared() > 1f)
                    {
                        toE.Normalize();
                        float spd = _projectiles[i].Velocity.Length();
                        _projectiles[i].Velocity = Vector2.Lerp(_projectiles[i].Velocity, toE * spd, 3f * dt);
                    }
                }
                // Holy trail
                if (_rng.NextDouble() < 0.4)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, ((float)_rng.NextDouble() - 0.5f) * 15f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = new Color(240, 245, 255),
                        Size = 1.5f + (float)_rng.NextDouble() * 1.5f,
                    });
                }
            }

            // Bouncing Betty: proximity mine — explodes when enemy comes near
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "BouncingBetty")
            {
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                    if (Vector2.Distance(_projectiles[i].Position, _enemies[j].Position) < 40f)
                    {
                        // POP UP AND EXPLODE — launch upward briefly then shatter
                        _projectiles[i].Alive = false;
                        // AoE damage to all enemies in blast radius
                        for (int k = 0; k < _enemies.Count; k++)
                        {
                            if (!_enemies[k].Alive) continue;
                            if (Vector2.Distance(_projectiles[i].Position, _enemies[k].Position) < 60f)
                            {
                                _enemies[k].TakeDamage(ApplyElementCounter(_enemies[k], _projectiles[i].Params.BaseDamage * 1.5f, _projectiles[i].Params.EssenceType));
                                _damageNumbers.Add(new DamageNumber
                                {
                                    Position = _enemies[k].Position + new Vector2(0, -_enemies[k].Size / 2),
                                    Amount = _projectiles[i].Params.BaseDamage * 1.5f,
                                    Timer = 0.6f,
                                    Color = new Color(220, 220, 210),
