                            }
                        }
                        // Bone shrapnel burst — 8 fragments in all directions
                        for (int f = 0; f < 8; f++)
                        {
                            float angle = (MathF.PI * 2f / 8) * f + ((float)_rng.NextDouble() - 0.5f) * 0.3f;
