            }

            // ═══ DUAL COMBO UNIQUE BEHAVIORS ═══

            // Tesla Ball: on final bounce (MaxBounces == 0), latch onto nearest enemy and tick damage
            if (_projectiles[i].Alive && _currentDualCombo == "Tesla Ball" && _projectiles[i].Params.MaxBounces <= 0 && _projectiles[i].FusionName != "TeslaLatch")
            {
