                        {
                            Position = closest.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 50f, ((float)_rng.NextDouble() - 0.5f) * 50f),
                            Life = 0.15f, MaxLife = 0.15f,
