                if (beamDir.LengthSquared() > 0)
                {
                    beamDir.Normalize();
                    float len = _projectiles[i].BeamLen;
                    float interval = 0.15f;
                    float prevAge = _projectiles[i].Age - dt;
                    if ((int)(prevAge / interval) != (int)(_projectiles[i].Age / interval))
                    {
                        int patches = (int)(len / 30f);
                        for (int p = 0; p < patches; p++)
                        {
                            float t = (p + 0.5f) / patches;
                            Vector2 patchPos = _projectiles[i].Position + beamDir * len * t;
                            patchPos += new Vector2((float)_rng.NextDouble() * 10 - 5, (float)_rng.NextDouble() * 10 - 5);
                            _lingerZones.Add(new LingerZone
                            {
                                Position = patchPos,
                                Radius = 18f,
                                Life = 4f, MaxLife = 4f,
                                Damage = 0.8f,
                                TickTimer = 0.4f,
                                Color = new Color(90, 70, 50),
                                EssenceType = Essence.None,
                                SlowFactor = 0.4f,
                                FusionTag = "ScorchedEarth"
                            });
                        }
                    }
                    for (int dp = 0; dp < 6; dp++)
                    {
                        float t = (float)_rng.NextDouble();
                        Vector2 debrisPos = _projectiles[i].Position + beamDir * len * t;
                        debrisPos += new Vector2((float)_rng.NextDouble() * 12 - 6, (float)_rng.NextDouble() * 12 - 6);
                        float upAngle = -MathF.PI/2f + (float)(_rng.NextDouble() - 0.5) * 0.8f;
                        float spd = 30f + (float)_rng.NextDouble() * 50f;
                        _particles.Add(new Particle
                        {
                            Position = debrisPos,
                            Velocity = new Vector2(MathF.Cos(upAngle), MathF.Sin(upAngle)) * spd,
                            Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                            MaxLife = 0.6f,
                            Color = new Color(110 + _rng.Next(40), 90 + _rng.Next(30), 60 + _rng.Next(20)),
                            Size = 2f + (float)_rng.NextDouble() * 2.5f
                        });
                    }
                    if (_rng.NextDouble() < 0.5)
                    {
                        float t = (float)_rng.NextDouble();
                        Vector2 dustPos = _projectiles[i].Position + beamDir * len * t;
                        _particles.Add(new Particle
                        {
                            Position = dustPos,
                            Velocity = new Vector2((float)_rng.NextDouble() * 20 - 10, -5f - (float)_rng.NextDouble() * 15f),
                            Life = 0.5f + (float)_rng.NextDouble() * 0.5f,
                            MaxLife = 1f,
                            Color = new Color(140, 120, 90, 100),
                            Size = 4f + (float)_rng.NextDouble() * 4f
                        });
                    }
                    _trauma = MathF.Min(_trauma + 0.02f * dt * 60f, 0.3f);
                    for (int ei = _enemies.Count - 1; ei >= 0; ei--)
                    {
                        if (!_enemies[ei].Alive) continue;
                        Vector2 toEnemy = _enemies[ei].Position - _projectiles[i].Position;
                        float proj2 = Vector2.Dot(toEnemy, beamDir);
                        if (proj2 < 0 || proj2 > len) continue;
                        Vector2 closest = _projectiles[i].Position + beamDir * proj2;
                        if (Vector2.Distance(closest, _enemies[ei].Position) < _enemies[ei].Size + 10)
                        {
                            if (_enemies[ei].HitCooldown <= 0)
                            {
                                float dmg = _projectiles[i].Params.BaseDamage;
                                _enemies[ei].Hp -= dmg;
                                _enemies[ei].HitCooldown = 0.15f;
                                _enemies[ei].HitFlash = 0.05f;
                                if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                                for (int ed = 0; ed < 5; ed++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    _particles.Add(new Particle
                                    {
                                        Position = _enemies[ei].Position,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 40f),
                                        Life = 0.25f, MaxLife = 0.25f,
                                        Color = new Color(200, 160, 100),
                                        Size = 2f
                                    });
                                }
                            }
                        }
                    }
                }
            }
            
            // ═══ NYOIBŌ: extending magic pole — grows longer while held ═══

            // ═══ SUN LANCE: giant flaming beam with tons of fire particles ═══
            if (_projectiles[i].Alive && (_projectiles[i].FusionName == "SunLance" || (_currentDualCombo == "Sun Lance" && _projectiles[i].BeamLen > 0)))
            {
                Vector2 beamDir = _projectiles[i].BeamDirection;
                if (beamDir.LengthSquared() > 0)
                {
                    beamDir.Normalize();
                    float len = _projectiles[i].BeamLen;
                    
                    for (int fp = 0; fp < 9; fp++)
                    {
                        float t = (float)_rng.NextDouble();
                        Vector2 flamePos = _projectiles[i].Position + beamDir * len * t;
                        float perpAngle = MathF.Atan2(beamDir.Y, beamDir.X) + MathF.PI / 2f;
                        float spread = (float)(_rng.NextDouble() - 0.5) * _projectiles[i].Size * 1.5f;
                        flamePos += new Vector2(MathF.Cos(perpAngle), MathF.Sin(perpAngle)) * spread;
                        
                        float lifespan = 0.2f + (float)_rng.NextDouble() * 0.3f;
                        double colorRoll = _rng.NextDouble();
                        Color flameColor;
                        if (colorRoll < 0.15) flameColor = new Color(255, 255, 220);
                        else if (colorRoll < 0.35) flameColor = new Color(255, 220, 60);
                        else if (colorRoll < 0.6) flameColor = new Color(255, 160, 30);
                        else if (colorRoll < 0.8) flameColor = new Color(255, 80, 15);
                        else flameColor = new Color(200, 40, 10);
                        
                        _particles.Add(new Particle
                        {
                            Position = flamePos,
                            Velocity = new Vector2(MathF.Cos(perpAngle), MathF.Sin(perpAngle)) * ((float)_rng.NextDouble() - 0.5f) * 60f
                                + new Vector2(0, -20f),
                            Life = lifespan,
                            MaxLife = lifespan,
                            Color = flameColor,
                            Size = 2.5f + (float)_rng.NextDouble() * 3.5f
                        });
                    }
                    
                    Vector2 tipPos = _projectiles[i].Position + beamDir * len;
                    for (int tb = 0; tb < 3; tb++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = tipPos,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (30f + (float)_rng.NextDouble() * 40f),
                            Life = 0.15f + (float)_rng.NextDouble() * 0.15f,
                            MaxLife = 0.3f,
                            Color = new Color(255, 200 + _rng.Next(55), 50 + _rng.Next(80)),
                            Size = 2f + (float)_rng.NextDouble() * 3f
                        });
                    }
                    
                    _trauma = MathF.Min(_trauma + 0.015f, 0.2f);
                }
            }

            // ═══ BONE SPEAR: rapid thrust animation + bone fragments ═══
            if (_projectiles[i].Alive && (_projectiles[i].FusionName == "BoneSpear" || (_currentDualCombo == "Bone Spear" && _projectiles[i].BeamLen > 0)))
            {
                _projectiles[i].Position = _playerPos;
                Vector2 beamDir = _projectiles[i].BeamDirection;
                if (beamDir.LengthSquared() > 0)
                {
                    beamDir.Normalize();
                    float age = _projectiles[i].Age;
                    float maxLen = _projectiles[i].Params.BeamLength > 0 ? _projectiles[i].Params.BeamLength : 160f;
                    
                    float thrustTime = 0.08f;
                    float lifetime = _projectiles[i].Lifetime;
                    float retractStart = lifetime - 0.08f;
                    float lenFrac;
                    if (age < thrustTime)
                        lenFrac = age / thrustTime;
                    else if (age > retractStart)
                        lenFrac = (lifetime - age) / 0.08f;
                    else
                        lenFrac = 1f;
                    lenFrac = MathHelper.Clamp(lenFrac, 0f, 1f);
                    lenFrac = 1f - (1f - lenFrac) * (1f - lenFrac);
                    _projectiles[i].BeamLen = maxLen * lenFrac;
                    
                    float len = _projectiles[i].BeamLen;
                    Vector2 tipPos = _projectiles[i].Position + beamDir * len;
                    
                    if (age < 0.12f)
                    {
                        for (int bp = 0; bp < 4; bp++)
                        {
                            float perpAngle = MathF.Atan2(beamDir.Y, beamDir.X) + MathF.PI / 2f;
                            float spread = (float)(_rng.NextDouble() - 0.5) * 2f;
                            _particles.Add(new Particle
                            {
                                Position = tipPos + new Vector2(
                                    ((float)_rng.NextDouble() - 0.5f) * 8f,
                                    ((float)_rng.NextDouble() - 0.5f) * 8f),
                                Velocity = new Vector2(
                                    MathF.Cos(perpAngle + spread) * (40f + (float)_rng.NextDouble() * 30f),
                                    MathF.Sin(perpAngle + spread) * (40f + (float)_rng.NextDouble() * 30f)),
                                Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                                MaxLife = 0.5f,
                                Color = new Color(200 + _rng.Next(40), 185 + _rng.Next(40), 140 + _rng.Next(30)),
                                Size = 1.5f + (float)_rng.NextDouble() * 2f
                            });
                        }
                    }
                    
                    if (_rng.NextDouble() < 0.4 && len > 10)
                    {
                        float t = (float)_rng.NextDouble();
                        Vector2 dustPos = _projectiles[i].Position + beamDir * len * t;
                        _particles.Add(new Particle
                        {
                            Position = dustPos,
                            Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 15f, -10f - (float)_rng.NextDouble() * 15f),
                            Life = 0.2f + (float)_rng.NextDouble() * 0.15f,
                            MaxLife = 0.35f,
                            Color = new Color(180 + _rng.Next(30), 165 + _rng.Next(30), 130 + _rng.Next(20)),
                            Size = 1f + (float)_rng.NextDouble() * 1.5f
                        });
                    }
                    
                    if (age < dt * 2f)
                        _trauma = MathF.Min(_trauma + 0.12f, 0.4f);
                    
                    for (int ei = _enemies.Count - 1; ei >= 0; ei--)
                    {
                        if (!_enemies[ei].Alive) continue;
                        Vector2 toEnemy = _enemies[ei].Position - _projectiles[i].Position;
                        float proj2 = Vector2.Dot(toEnemy, beamDir);
                        if (proj2 < 0 || proj2 > len) continue;
                        Vector2 closest = _projectiles[i].Position + beamDir * proj2;
                        if (Vector2.Distance(closest, _enemies[ei].Position) < _enemies[ei].Size + 8)
                        {
                            if (_enemies[ei].HitCooldown <= 0)
                            {
                                float dmg = _projectiles[i].Params.BaseDamage;
                                _enemies[ei].Hp -= dmg;
                                _enemies[ei].HitCooldown = 0.1f;
                                _enemies[ei].HitFlash = 0.05f;
                                // Knockback toward cursor — you're PLACING enemies with the thrust
                                Vector2 knockDir = _mouseWorld - _enemies[ei].Position;
                                if (knockDir.LengthSquared() > 1f) knockDir.Normalize();
                                else knockDir = beamDir;
                                _enemies[ei].KnockbackVel = knockDir * 200f;
                                if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                                for (int bc = 0; bc < 5; bc++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    _particles.Add(new Particle
                                    {
                                        Position = _enemies[ei].Position,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (50f + (float)_rng.NextDouble() * 40f),
                                        Life = 0.2f, MaxLife = 0.2f,
                                        Color = new Color(220, 200, 160),
                                        Size = 2f
                                    });
                                }
                            }
                        }
                    }
                }
            }

            // ═══ NYOIBŌ: extending magic pole — grows longer while held ═══
            if (_projectiles[i].Alive && _currentDualCombo == "Nyoibo" && _projectiles[i].BeamLen > 0)
            {
                _projectiles[i].Position = _playerPos;
                Vector2 beamDir = _projectiles[i].BeamDirection;
                if (beamDir.LengthSquared() > 0)
                {
                    beamDir.Normalize();
                    float age = _projectiles[i].Age;
                    float baseLen = 120f;
                    float growRate = 200f;
                    float maxLen = 800f;
                    float targetLen = MathF.Min(baseLen + age * growRate, maxLen);
                    _projectiles[i].BeamLen = targetLen;
                    float baseWidth = 4f;
                    float maxWidth = 14f;
                    float widthFrac = (targetLen - baseLen) / (maxLen - baseLen);
                    _projectiles[i].Size = baseWidth + widthFrac * (maxWidth - baseWidth);
                    float len = _projectiles[i].BeamLen;
                    Vector2 tipPos = _projectiles[i].Position + beamDir * len;
                    for (int gp = 0; gp < 4; gp++)
                    {
                        float t = (float)_rng.NextDouble();
                        Vector2 polePos = _projectiles[i].Position + beamDir * len * t;
                        float perpAngle = MathF.Atan2(beamDir.Y, beamDir.X) + MathF.PI / 2f;
                        float spread = (float)(_rng.NextDouble() - 0.5) * _projectiles[i].Size;
                        polePos += new Vector2(MathF.Cos(perpAngle), MathF.Sin(perpAngle)) * spread;
                        _particles.Add(new Particle
                        {
                            Position = polePos,
                            Velocity = beamDir * (30f + (float)_rng.NextDouble() * 40f),
                            Life = 0.2f + (float)_rng.NextDouble() * 0.2f,
                            MaxLife = 0.4f,
                            Color = new Color(255, 200 + _rng.Next(55), 50 + _rng.Next(100)),
                            Size = 1.5f + (float)_rng.NextDouble() * 1.5f
                        });
                    }
                    for (int tp = 0; tp < 3; tp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = tipPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 5f,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (20f + (float)_rng.NextDouble() * 30f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(255, 220, 100),
                            Size = 2f + (float)_rng.NextDouble() * 2f
                        });
                    }
                    float pulseInterval = 0.3f;
                    float prevAge2 = age - dt;
                    if ((int)(prevAge2 / pulseInterval) != (int)(age / pulseInterval) && age > 0.3f)
                    {
                        for (int pp = 0; pp < 8; pp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = tipPos,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (50f + (float)_rng.NextDouble() * 40f),
                                Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                                MaxLife = 0.5f,
                                Color = new Color(255, 180 + _rng.Next(75), _rng.Next(80)),
                                Size = 2.5f + (float)_rng.NextDouble() * 2f
                            });
                        }
                    }
                    _trauma = MathF.Min(_trauma + widthFrac * 0.01f, 0.2f);
                    for (int ei = _enemies.Count - 1; ei >= 0; ei--)
                    {
                        if (!_enemies[ei].Alive) continue;
                        Vector2 toEnemy = _enemies[ei].Position - _projectiles[i].Position;
                        float proj2 = Vector2.Dot(toEnemy, beamDir);
                        if (proj2 < 0 || proj2 > len) continue;
                        Vector2 closest = _projectiles[i].Position + beamDir * proj2;
                        if (Vector2.Distance(closest, _enemies[ei].Position) < _enemies[ei].Size + _projectiles[i].Size)
                        {
                            if (_enemies[ei].HitCooldown <= 0)
                            {
                                float dmg = _projectiles[i].Params.BaseDamage;
                                _enemies[ei].Hp -= dmg;
                                _enemies[ei].HitCooldown = 0.12f;
                                _enemies[ei].HitFlash = 0.05f;
                                _enemies[ei].KnockbackVel = beamDir * 150f;
                                if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                                for (int gs = 0; gs < 6; gs++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    _particles.Add(new Particle
                                    {
                                        Position = _enemies[ei].Position,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (60f + (float)_rng.NextDouble() * 50f),
                                        Life = 0.2f, MaxLife = 0.2f,
                                        Color = new Color(255, 200, 80),
                                        Size = 2f
                                    });
                                }
                            }
                        }
                    }
                }
            }
            
            // ═══ BLOOM + LANCE: mild homing toward nearest enemy ═══
            if (_projectiles[i].Alive && _loadout.Form == Form.Lance && _loadout.Behavior == Behavior.Bloom
                && _projectiles[i].BeamLen > 0 && (_projectiles[i].FusionName == null || _projectiles[i].FusionName == "MarrowBloom"))
            {
                _projectiles[i].Position = _playerPos; // follow player
                // Find nearest enemy and rotate beam toward it
                float bestDist = float.MaxValue;
                Vector2 bestDir = Vector2.Zero;
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    float d = Vector2.Distance(_playerPos, _enemies[j].Position);
                    if (d < bestDist) { bestDist = d; bestDir = _enemies[j].Position - _playerPos; }
                }
                if (bestDir.LengthSquared() > 1f)
                {
                    bestDir = Vector2.Normalize(bestDir);
                    Vector2 curDir = _projectiles[i].BeamDirection;
                    if (curDir.LengthSquared() > 0)
                    {
                        curDir = Vector2.Normalize(curDir);
                        // Lerp angle toward target at ~3 rad/s
                        float curAngle = MathF.Atan2(curDir.Y, curDir.X);
                        float tgtAngle = MathF.Atan2(bestDir.Y, bestDir.X);
                        float diff = tgtAngle - curAngle;
                        while (diff > MathF.PI) diff -= MathF.PI * 2f;
                        while (diff < -MathF.PI) diff += MathF.PI * 2f;
                        float rotSpeed = 3f * dt;
                        float newAngle = curAngle + MathHelper.Clamp(diff, -rotSpeed, rotSpeed);
                        var p = _projectiles[i];
                        p.BeamDirection = new Vector2(MathF.Cos(newAngle), MathF.Sin(newAngle));
                        _projectiles[i] = p;
                    }
                }
            }

            // ═══ MARROW SHOT: spinning bone visual ═══
            if (_projectiles[i].Alive && _currentDualCombo == "Marrow Shot" && _projectiles[i].BeamLen <= 0)
            {
                // Bone fragment trail
                if (_rng.NextDouble() < 0.3)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 20f, (float)(_rng.NextDouble() - 0.5) * 20f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(190, 175, 140),
                        Size = 1.5f
                    });
                }
            }
            
            // ═══ SILK SHOT: tripwire creation on wall hit ═══
            // (Handled in hit/death code below — on wall contact, creates tripwire from player to impact point)

            // ═══ END DUAL COMBO BEHAVIORS ═══

            // Katyusha rocket trail (smoke + sparks)
            if (_projectiles[i].Alive && (_projectiles[i].FusionName == "Katyusha" || _projectiles[i].FusionName == "KatyushaMed"))
            {
                // Smoke trail
                if (_rng.NextDouble() < 0.6)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = -_projectiles[i].Velocity * 0.1f + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(160, 150, 140) : new Color(100, 90, 80),
                        Size = _projectiles[i].FusionName == "Katyusha" ? 4f + (float)_rng.NextDouble() * 3f : 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                // Spark trail
                if (_rng.NextDouble() < 0.3)
                {
                    Color[] sparks = { new Color(255, 200, 40), new Color(255, 100, 20), new Color(255, 255, 200) };
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                        Life = 0.1f + (float)_rng.NextDouble() * 0.1f,
                        MaxLife = 0.2f,
                        Color = sparks[_rng.Next(sparks.Length)],
                        Size = 1f + (float)_rng.NextDouble() * 1.5f,
                    });
                }
            }

            // Death's Scythe: bone trail particles from saw
            if (_projectiles[i].Alive && _currentFusion == "Death's Scythe" && _rng.NextDouble() < 0.35)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -30f - (float)_rng.NextDouble() * 30f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                    MaxLife = 0.5f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(220, 220, 210) : new Color(180, 170, 150),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f,
                });
            }

            // Indra's Arrow: persistent sparking trail on chain projectiles
            if (_projectiles[i].Alive && _currentFusion == "Indra's Arrow" && _rng.NextDouble() < 0.5)
            {
                _particles.Add(new Particle
                {
                    Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                    Life = 0.1f + (float)_rng.NextDouble() * 0.15f,
                    MaxLife = 0.25f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(255, 240, 60) : new Color(200, 200, 255),
                    Size = 1f + (float)_rng.NextDouble() * 2f,
                });
            }

            // Event Horizon: pull enemies to orbit edge + force field at orbit radius
            if (_projectiles[i].Alive && _currentFusion == "Event Horizon" && _projectiles[i].Params.OrbitSpeed > 0)
            {
                float orbitR = _projectiles[i].Params.OrbitRadius;
                float pullRange = orbitR * 4f; // pull from 4× orbit radius
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive) continue;
                    if (_enemies[e].Speed > 100f) continue; // fast enemies resist the pull
                    Vector2 toPlayer = _playerPos - _enemies[e].Position;
                    float dist = toPlayer.Length();
                    
                    if (dist < orbitR) 
                    {
                        // INSIDE orbit — forcefully push OUT to orbit edge
                        if (dist > 1f)
                        {
                            Vector2 pushDir = _enemies[e].Position - _playerPos;
                            pushDir.Normalize();
                            _enemies[e].Position = _playerPos + pushDir * (orbitR + 5f);
                        }
                        else
                        {
                            // Exactly on player — push in random direction
                            float ra = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _enemies[e].Position = _playerPos + new Vector2(MathF.Cos(ra), MathF.Sin(ra)) * (orbitR + 5f);
                        }
                    }
                    else if (dist < pullRange && dist > orbitR + 2f)
                    {
                        // Outside orbit — pull toward orbit edge (not center)
                        toPlayer.Normalize();
                        float targetDist = orbitR + 3f;
                        float pullStrength = 80f * (1f - (dist - targetDist) / (pullRange - targetDist));
                        float maxMove = (dist - targetDist) * 0.3f;
                        float move = MathF.Min(pullStrength * dt, MathF.Max(maxMove, 0f));
                        _enemies[e].Position += toPlayer * move;
                    }
                }
                // Black hole visual: dark swirling particles
                if (_rng.NextDouble() < 0.4)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float r = 20f + (float)_rng.NextDouble() * 50f;
                    Vector2 orbPos = _playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * r;
                    // Particles spiral inward
                    Vector2 tangent = new Vector2(-MathF.Sin(a), MathF.Cos(a));
                    _particles.Add(new Particle
                    {
                        Position = orbPos,
                        Velocity = tangent * 40f + (_playerPos - orbPos) * 0.5f,
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.6 ? new Color(60, 20, 80) : (_rng.NextDouble() > 0.5 ? new Color(100, 50, 140) : new Color(40, 10, 60)),
                        Size = 1.5f + (float)_rng.NextDouble() * 2.5f,
                    });
                }
            }

            // ═══ NEW TRIPLE COMBO PROJECTILE BEHAVIORS ═══

            // Ifrit's Fury: thick flame trail
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "IfritsFury")
            {
                for (int ft = 0; ft < 6; ft++)
                {
                    double cr = _rng.NextDouble();
                    Color fc = cr < 0.15 ? Color.White :
                               cr < 0.3 ? new Color(255, 255, 180) :
                               cr < 0.5 ? new Color(255, 220, 60) :
                               cr < 0.7 ? new Color(255, 140, 30) :
                               cr < 0.85 ? new Color(255, 80, 15) :
                                            new Color(200, 40, 10);
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -30f - (float)_rng.NextDouble() * 40f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.6f,
                        Color = fc,
                        Size = 3f + (float)_rng.NextDouble() * 4f,
                    });
                }
            }

            // Ifrit fragment gravity
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "IfritFrag")
            {
                _projectiles[i].Velocity = new Vector2(_projectiles[i].Velocity.X, _projectiles[i].Velocity.Y + 400f * dt);
                // Check ground hit
                if (_projectiles[i].Position.Y > _arena.Bottom - 20)
                {
                    _projectiles[i].Alive = false;
                    SpawnExplosion(_projectiles[i].Position, new Color(255, 120, 30), 8, 0.3f, 12f);
                    _lingerZones.Add(new LingerZone
                    {
                        Position = _projectiles[i].Position,
                        Radius = 15f,
                        Life = 2f,
                        MaxLife = 2f,
                        Damage = _projectiles[i].Params.BaseDamage * 0.3f,
                        TickTimer = 0f,
                        Color = new Color(255, 100, 20),
                        EssenceType = Essence.Cinder,
                        FusionTag = "IfritFrag",
                    });
                }
            }

            // Prominence: track cursor
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Prominence")
            {
                _projectiles[i].Position = _mouseWorld;
                float scale = _projectiles[i].CurrentScale;
                float maxScale = _projectiles[i].Params.BloomMaxScale;
                // Fire particles radiating outward
                int pCount = 2 + (int)(scale * 2f);
                for (int fp = 0; fp < pCount; fp++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 20f + scale * 20f;
                    double cr = _rng.NextDouble();
                    Color pc = scale < 1.5f ? new Color(255, 140, 30) :
                               scale < 2.2f ? new Color(255, 220, 60) :
                                               new Color(255, 255, 220);
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * _projectiles[i].Size * scale * 0.5f,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = pc,
                        Size = 2f + scale,
                    });
                }
                // Screen shake at high power
                if (scale > maxScale * 0.8f) _trauma = MathF.Min(_trauma + 0.02f, 1f);
            }

            // Raiju: erratic velocity perturbation + lightning arcs
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Raiju")
            {
                float age = _projectiles[i].Age;
                float perturbMag = 50f + age * 200f;
                _projectiles[i].Velocity += new Vector2(
                    ((float)_rng.NextDouble() - 0.5f) * perturbMag * dt,
                    ((float)_rng.NextDouble() - 0.5f) * perturbMag * dt);
                // Electric particle trail
                if (_rng.NextDouble() < 0.6)
                {
                    double cr = _rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                        Life = 0.15f, MaxLife = 0.15f,
                        Color = cr < 0.33 ? new Color(100, 120, 255) : cr < 0.66 ? new Color(180, 140, 255) : Color.White,
                        Size = 1.5f + (float)_rng.NextDouble() * 2f,
                    });
                }
                // Lightning arc to nearest enemy
                float arcRange = 40f + _projectiles[i].Size * _projectiles[i].CurrentScale * 3f;
                float arcInterval = MathF.Max(0.25f, 0.8f - age * 0.5f);
                _projectiles[i].LingerTrailTimer -= dt;
                if (_projectiles[i].LingerTrailTimer <= 0)
                {
                    _projectiles[i].LingerTrailTimer = arcInterval;
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive) continue;
                        float d = Vector2.Distance(_projectiles[i].Position, _enemies[e].Position);
                        if (d < arcRange)
                        {
                            _enemies[e].TakeDamage(ApplyElementCounter(_enemies[e], _projectiles[i].Params.BaseDamage * 0.3f, _projectiles[i].Params.EssenceType, showBark: false));
                            // Spark particles at enemy
                            for (int sp = 0; sp < 4; sp++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = _enemies[e].Position,
                                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                                    Life = 0.1f, MaxLife = 0.1f,
                                    Color = Color.White,
                                    Size = 2f,
                                });
                            }
                            break; // arc to nearest only
                        }
                    }
                }
            }

            // Fossil: grow size over time + bone particle orbit
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Fossil")
            {
                _projectiles[i].Size += dt * 8f;
                _projectiles[i].OrbitAngle += dt * 6f;
                // Orbiting bone fragments as particles
                float orbitR = _projectiles[i].Size * 0.8f;
                for (int f = 0; f < 4; f++)
                {
                    float a = _projectiles[i].OrbitAngle + (MathF.PI * 2f / 4f) * f;
                    Vector2 orbPos = _projectiles[i].Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * orbitR;
                    _particles.Add(new Particle
                    {
                        Position = orbPos,
                        Velocity = Vector2.Zero,
                        Life = 0.08f, MaxLife = 0.08f,
                        Color = new Color(220, 210, 180),
                        Size = 2f + _projectiles[i].Size * 0.1f,
                    });
                }
                // Bone dust trail
                if (_rng.NextDouble() < 0.4)
                {
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -10f - (float)_rng.NextDouble() * 15f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(200, 190, 160),
                        Size = 1.5f,
                    });
                }
            }

            // Amaterasu: spreading fire from beam
            if (_projectiles[i].Alive && _projectiles[i].FusionName == "Amaterasu" && _projectiles[i].BeamLen > 0)
            {
                float age = _projectiles[i].Age;
                Vector2 bDir = _projectiles[i].BeamDirection;
                float bLen = _projectiles[i].BeamLen;
                Vector2 perp = new Vector2(-bDir.Y, bDir.X);
                // Fire particles along beam
                if (_rng.NextDouble() < 0.7)
                {
                    float t = (float)_rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _projectiles[i].Position + bDir * bLen * t + perp * ((float)_rng.NextDouble() - 0.5f) * (10f + age * 80f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -40f - (float)_rng.NextDouble() * 60f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 120, 30) : new Color(255, 200, 50),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                // Spread linger zones perpendicular at timed intervals
                float perpDist = age < 0.15f ? 0f : age < 0.3f ? 20f : age < 0.5f ? 40f : 50f;
                if (perpDist > 0 && _rng.NextDouble() < 0.15)
                {
                    float t = (float)_rng.NextDouble();
                    float side = _rng.NextDouble() > 0.5 ? 1f : -1f;
                    _lingerZones.Add(new LingerZone
                    {
                        Position = _projectiles[i].Position + bDir * bLen * t + perp * side * perpDist,
                        Radius = 10f,
                        Life = 2f,
                        MaxLife = 2f,
                        Damage = _projectiles[i].Params.BaseDamage * 0.15f,
                        TickTimer = 0f,
                        Color = new Color(255, 100, 20),
                        EssenceType = Essence.Cinder,
                        FusionTag = "Amaterasu",
                    });
                }
                _trauma = MathF.Min(_trauma + age * 0.01f, 1f);
            }

            if (!_projectiles[i].Alive)
            {
                var dying = _projectiles[i];

                // Fire-flaught Hasp: thunderstorm zone on death
                if (dying.FusionName == "FireflaughtHasp")
                {
                    _lingerZones.Add(new LingerZone
                    {
                        Position = dying.Position,
                        Radius = 45f,
                        Life = 6f,
                        MaxLife = 6f,
                        Damage = dying.Params.BaseDamage * 0.2f,
                        TickTimer = 0f,
                        Color = new Color(80, 90, 110),
                        EssenceType = Essence.Pulse,
                        FusionTag = "ThunderStorm",
                        PillarTimer = 0.5f,
                    });
                }

                // Graveyard: bone altar zone on death
                if (dying.FusionName == "Graveyard")
                {
                    _lingerZones.Add(new LingerZone
                    {
                        Position = dying.Position,
                        Radius = 40f,
                        Life = 7f,
                        MaxLife = 7f,
                        Damage = dying.Params.BaseDamage * 0.2f,
                        TickTimer = 0f,
                        Color = new Color(200, 190, 160),
                        EssenceType = Essence.Bone,
                        FusionTag = "Graveyard",
                        SlowFactor = 0.5f,
                    });
                }

                // Ifrit's Fury: fragments arc upward on death
                if (dying.FusionName == "IfritsFury")
                {
                    SpawnExplosion(dying.Position, new Color(255, 120, 30), 15, 0.4f, 15f);
                    for (int f = 0; f < 6; f++)
                    {
                        float xSpread = ((float)_rng.NextDouble() - 0.5f) * 200f;
                        float yVel = -200f - (float)_rng.NextDouble() * 100f;
                        var fragParms = dying.Params;
                        fragParms.Lifetime = 1.5f;
                        fragParms.Size = 4f;
                        fragParms.Piercing = false;
                        fragParms.ShatterCount = 0;
                        fragParms.BloomGrowRate = 0;
                        fragParms.IsStationary = false;
                        var frag = new Projectile(dying.Position, new Vector2(xSpread, yVel), fragParms);
                        frag.Size = 4f;
                        frag.FusionName = "IfritFrag";
                        _projectiles.Add(frag);
                    }
                }

                // Raijin's Drum: shockwave ring on death
                if (dying.FusionName == "RaijinsDrum")
                {
                    for (int r = 0; r < 12; r++)
                    {
                        float a = (MathF.PI * 2f / 12f) * r;
                        Vector2 rv = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 300f;
                        var waveParms = dying.Params;
                        waveParms.Lifetime = 0.3f;
                        waveParms.Size = 2f;
                        waveParms.Piercing = true;
                        waveParms.ShatterCount = 0;
                        waveParms.BloomGrowRate = 0;
                        waveParms.IsStationary = false;
                        var wave = new Projectile(dying.Position, rv, waveParms);
                        wave.Size = 2f;
                        wave.FusionName = "RaijinWave";
                        _projectiles.Add(wave);
                    }
                    // Lightning strikes at cardinal points
                    Vector2[] cardinals = { new(0, -40), new(0, 40), new(-40, 0), new(40, 0) };
                    foreach (var c in cardinals)
                    {
                        Vector2 strikePos = dying.Position + c;
                        for (int sp = 0; sp < 4; sp++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = strikePos,
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 80f, ((float)_rng.NextDouble() - 0.5f) * 80f),
                                Life = 0.15f, MaxLife = 0.15f,
                                Color = Color.White,
                                Size = 2.5f,
                            });
                        }
                    }
                    _trauma = MathF.Min(_trauma + 0.15f, 1f);
                }

                // RaijinWave: stagger on hit handled by normal damage; apply extra stagger in hit section

                // Prominence: fire linger zone on death
                if (dying.FusionName == "Prominence")
                {
                    float finalSize = dying.Size * dying.CurrentScale;
                    _lingerZones.Add(new LingerZone
                    {
                        Position = dying.Position,
                        Radius = finalSize * 1.5f,
                        Life = 2f,
                        MaxLife = 2f,
                        Damage = dying.Params.BaseDamage * 0.4f,
                        TickTimer = 0f,
                        Color = new Color(255, 140, 30),
                        EssenceType = Essence.Cinder,
                        FusionTag = "Prominence",
                    });
                    SpawnExplosion(dying.Position, new Color(255, 200, 50), 15, 0.5f, finalSize);
                }

                // Raiju: static discharge zones on death
                if (dying.FusionName == "Raiju")
                {
                    for (int z = 0; z < 6; z++)
                    {
                        Vector2 offset = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f);
                        _lingerZones.Add(new LingerZone
                        {
                            Position = dying.Position + offset,
                            Radius = 8f,
                            Life = 0.5f,
                            MaxLife = 0.5f,
                            Damage = dying.Params.BaseDamage * 0.15f,
                            TickTimer = 0f,
                            Color = new Color(120, 160, 255),
                            EssenceType = Essence.Pulse,
                            FusionTag = "Raiju",
                        });
                    }
                    SpawnExplosion(dying.Position, new Color(150, 180, 255), 10, 0.3f, 12f);
                }

                // Fossil: shatter into bone fragments on death
                if (dying.FusionName == "Fossil")
                {
                    int fragCount = 3 + (int)(dying.Size / 4f);
                    SpawnExplosion(dying.Position, new Color(220, 210, 180), fragCount * 2, 0.4f, dying.Size);
                    for (int f = 0; f < fragCount; f++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 150f + (float)_rng.NextDouble() * 100f;
                        var fragParms = dying.Params;
                        fragParms.Lifetime = 0.5f;
                        fragParms.Size = 3f;
                        fragParms.Piercing = false;
                        fragParms.ShatterCount = 0;
                        fragParms.BloomGrowRate = 0;
                        fragParms.IsStationary = false;
                        var frag = new Projectile(dying.Position, new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd, fragParms);
                        frag.Size = 3f;
                        frag.FusionName = "FossilFrag";
                        _projectiles.Add(frag);
                    }
                }

                // Silk Snare: final thread from last bounce to death point
                if (dying.FusionName == "SilkSnare" && dying.ArcStart.LengthSquared() > 0)
                {
                    float hue = (_totalTime * 40f) % 360f;
                    _tripwires.Add(new Tripwire
                    {
                        Start = dying.ArcStart, End = dying.Position,
                        Life = 5f, MaxLife = 5f, WireColor = HueToColor(hue),
                        HitsLeft = 3, Damage = dying.Params.BaseDamage * 0.25f, HitEnemies = new HashSet<int>(),
                    });
                }

                // Web Trap: spawn web zone on expiry/ground hit
                if (dying.FusionName == "WebTrap" && dying.Age >= dying.Lifetime)
                {
                    _lingerZones.Add(new LingerZone
                    {
                        Position = dying.Position, Radius = 55f,
                        Life = 6f, MaxLife = 6f,
                        Damage = dying.Params.BaseDamage * 0.1f,
                        TickTimer = 0f, Color = new Color(200, 180, 220),
                        EssenceType = Essence.Silk, FusionTag = "WebTrap", SlowFactor = 0.3f,
                    });
                    for (int wp = 0; wp < 15; wp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float r = (float)_rng.NextDouble() * 50f;
                        _particles.Add(new Particle
                        {
                            Position = dying.Position + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                            Velocity = new Vector2(MathF.Cos(a) * 15f, MathF.Sin(a) * 15f),
                            Life = 0.4f, MaxLife = 0.4f, Color = new Color(200, 180, 220) * 0.6f, Size = 1.5f,
                        });
                    }
                }

                // Linger zone on natural death (timeout)
                if (dying.Params.LingerDuration > 0 && dying.Age >= dying.Lifetime)
                {
                    bool isPillar = _currentFusion == "Pillars of Muspelheim";
                    bool isMoss = _currentDualCombo == "Creeping Moss";
                    bool isQuake = dying.FusionName == "Earthquake";
                    _lingerZones.Add(new LingerZone
                    {
                        Position = dying.Position,
                        Radius = dying.Params.LingerRadius > 0 ? dying.Params.LingerRadius : 25f,
                        Life = isPillar ? dying.Params.LingerDuration * 1.5f : dying.Params.LingerDuration,
                        MaxLife = isPillar ? dying.Params.LingerDuration * 1.5f : dying.Params.LingerDuration,
                        Damage = dying.Params.BaseDamage * 0.3f,
                        TickTimer = 0f,
                        Color = isMoss ? new Color(40, 120, 30) : isQuake ? new Color(200, 190, 150) : new Color(dying.Params.Color.R, dying.Params.Color.G, dying.Params.Color.B),
                        EssenceType = dying.Params.EssenceType,
                        IsPillar = isPillar,
                        PillarTimer = 0.2f,
                        FusionTag = isMoss ? "CreepingMoss" : isQuake ? "Earthquake" : null,
                        GrowRate = isMoss ? 8f : 0f,       // grows 8px/s
                        MaxRadius = isMoss ? 80f : 0f,
                        SlowFactor = isMoss ? 1f : isQuake ? 1f : 0f,
                    });
                }
                // Bloom AoE on natural death
                if (dying.Params.BloomGrowRate > 0 && dying.Age >= dying.Lifetime)
                {
                    float finalRadius = dying.Size * dying.CurrentScale;
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive) continue;
                        if (Vector2.Distance(dying.Position, _enemies[j].Position) < finalRadius + _enemies[j].Size)
                        {
                            _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], dying.Params.BaseDamage * 0.5f, dying.Params.EssenceType));
                        }
                    }
                    SpawnExplosion(dying.Position, new Color(dying.Params.Color.R, dying.Params.Color.G, dying.Params.Color.B), 10, 0.4f, finalRadius * 0.5f);
                }
                
                // Seed detonation juice + chain reaction
                if (dying.Params.IsStationary && dying.ArcDuration > 0)
                {
                    var detColor = new Color(dying.Params.Color.R, dying.Params.Color.G, dying.Params.Color.B);
                    // Big detonation burst
                    SpawnExplosion(dying.Position, detColor, 15, 0.45f, 18f);
                    // White flash at center
                    SpawnExplosion(dying.Position, Color.White, 5, 0.15f, 6f);
                    // Dust ring expanding outward
                    for (int dr = 0; dr < 10; dr++)
                    {
                        float a = (MathF.PI * 2f / 10) * dr + (float)_rng.NextDouble() * 0.3f;
                        _particles.Add(new Particle
                        {
                            Position = dying.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (100f + (float)_rng.NextDouble() * 40f),
                            Life = 0.35f, MaxLife = 0.35f,
                            Color = detColor * 0.7f,
                            Size = 3f + (float)_rng.NextDouble() * 3f,
                        });
                    }
                    // Ground debris
                    for (int dr = 0; dr < 4; dr++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = dying.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 12f, 0),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, -40f - (float)_rng.NextDouble() * 60f),
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(100, 90, 70),
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                    _trauma = MathF.Min(_trauma + 0.12f, 1f);
                    _hitstopTimer = MathF.Max(_hitstopTimer, 0.03f);
                    
                    // AoE damage on detonation
                    float blastRadius = 30f;
                    for (int ej = 0; ej < _enemies.Count; ej++)
                    {
                        if (!_enemies[ej].Alive) continue;
                        if (_enemies[ej].Possessed) continue;
                        if (Vector2.Distance(dying.Position, _enemies[ej].Position) < blastRadius + _enemies[ej].Size / 2f)
                        {
                            float dmg = ApplyElementCounter(_enemies[ej], dying.Params.BaseDamage * 1.5f, dying.Params.EssenceType);
                            bool killed = _enemies[ej].TakeDamage(dmg);
                            _damageNumbers.Add(new DamageNumber
                            {
                                Position = _enemies[ej].Position + new Vector2(_rng.Next(-8, 8), -_enemies[ej].Size / 2),
                                Amount = dmg,
                                Timer = 0.8f,
                                Color = new Color(255, 200, 60),
                            });
                            // Knockback from blast center
                            Vector2 blastKb = _enemies[ej].Position - dying.Position;
                            if (blastKb.LengthSquared() > 0) blastKb.Normalize();
                            _enemies[ej].KnockbackVel = blastKb * 200f;
                        }
                    }
                    
                    // Chain reaction: detonate nearby seeds
                    for (int ci = _projectiles.Count - 1; ci >= 0; ci--)
                    {
                        if (ci == i) continue;
                        var other = _projectiles[ci];
                        if (!other.Alive || !other.Params.IsStationary) continue;
                        if (other.ArcDuration > 0 && !other.ArcLanded) continue; // skip seeds still in flight
                        if (Vector2.Distance(dying.Position, other.Position) < 60f)
                        {
                            other.Alive = false; // will be processed on its own iteration
                        }
                    }
                }
                
                _projectiles.RemoveAt(i);
            }
        }

        // ═══════════════ SHADOW STITCH UPDATE ═══════════════
        if (_shadowStitch.Active)
        {
            // Keep Morien anchored
            _playerPos = _shadowStitch.AnchorPos;
            
            // Keep all chained enemies frozen
            for (int c = 0; c < _shadowStitch.ChainedIds.Count; c++)
            {
                if (_enemyById.TryGetValue(_shadowStitch.ChainedIds[c], out var fe) && fe.Alive)
                {
                    fe.StaggerTimer = 0.2f;
                    fe.Possessed = true;
                    fe.PossessTimer = 0.2f;
                }
            }
            
            // Seeking tendril extending toward next target
            if (_shadowStitch.Seeking)
            {
                Enemy seekTarget = null;
                if (_enemyById.TryGetValue(_shadowStitch.SeekTargetId, out var st) && st.Alive) seekTarget = st;
                
                if (seekTarget == null)
                {
                    _shadowStitch.Seeking = false;
                }
                else
                {
                    Vector2 toTarget = seekTarget.Position - _shadowStitch.SeekingTip;
                    float dist = toTarget.Length();
                    if (dist < seekTarget.Size + 5f)
                    {
                        _shadowStitch.ChainedIds.Add(seekTarget.Id);
                        seekTarget.StaggerTimer = 10f;
                        seekTarget.Possessed = true;
                        seekTarget.PossessTimer = 10f;
                        _shadowStitch.Seeking = false;
                        SpawnExplosion(seekTarget.Position, new Color(80, 30, 120), 12, 0.3f, 10f);
                        _hitstopTimer = 0.06f;
                        _trauma = MathF.Min(_trauma + 0.12f, 1f);
                    }
                    else
                    {
                        toTarget /= dist;
                        _shadowStitch.SeekingTip += toTarget * _shadowStitch.SeekSpeed * dt;
                        Vector2 lastNode = _shadowStitch.ChainedIds.Count > 0 ? GetEnemyPos(_shadowStitch.ChainedIds[^1]) : _playerPos;
                        if (Vector2.Distance(_shadowStitch.SeekingTip, lastNode) > _shadowStitch.MaxRange)
                            _shadowStitch.Seeking = false;
                    }
                }
            }
            
            // Find next target if not already seeking
            if (!_shadowStitch.Seeking && _shadowStitch.ChainedIds.Count > 0)
            {
                Vector2 lastPos = GetEnemyPos(_shadowStitch.ChainedIds[^1]);
                Enemy nearest = null;
                float nearDist = float.MaxValue;
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive || _shadowStitch.ChainedIds.Contains(_enemies[e].Id)) continue;
                    float d = Vector2.Distance(lastPos, _enemies[e].Position);
                    if (d < _shadowStitch.MaxRange && d < nearDist)
                    {
                        nearDist = d;
                        nearest = _enemies[e];
                    }
                }
                if (nearest != null)
                {
                    _shadowStitch.Seeking = true;
                    _shadowStitch.SeekTargetId = nearest.Id;
                    _shadowStitch.SeekingTip = lastPos;
                }
            }
            
            // Shadow particles along chain
            if (_rng.NextDouble() < 0.6)
            {
                Vector2 prev = _playerPos;
                for (int c = 0; c < _shadowStitch.ChainedIds.Count; c++)
                {
                    Vector2 epos = GetEnemyPos(_shadowStitch.ChainedIds[c]);
                    float prog = (float)_rng.NextDouble();
                    Vector2 ppos = Vector2.Lerp(prev, epos, prog);
                    _particles.Add(new Particle
                    {
                        Position = ppos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                        Velocity = Vector2.Zero,
                        Life = 0.1f, MaxLife = 0.1f,
                        Color = new Color(30, 8, 45),
                        Size = 6f + (float)_rng.NextDouble() * 5f,
                    });
                    prev = epos;
                }
            }
        }

        for (int i = _enemies.Count - 1; i >= 0; i--)
        {
            _enemies[i].Update(dt, _playerPos, _arena);
            
            // Maw special: ether drain aura + bite contact damage
            if (_enemies[i].Alive && _enemies[i].Type == EnemyType.Maw)
            {
                float mawDist = Vector2.Distance(_enemies[i].Position, _playerPos);
                // Ether drain aura — drains EP when within 120px
                if (mawDist < 120f && _playerEther > 0)
                {
                    float drainRate = 8f * (1f - mawDist / 120f); // stronger when closer
                    _playerEther = MathF.Max(0f, _playerEther - drainRate * dt);
                    _etherFlashTimer = 0.05f; // subtle EP flash
                }
                // Bite snap damage (AiPhase 2)
                if (_enemies[i].AiPhase == 2 && mawDist < 35f && _iFrameTimer <= 0)
                {
                    DamagePlayer(20f, _enemies[i].Position);
                    _trauma = MathF.Min(_trauma + 0.3f, 1f);
                }
            }
            // Charger lunge contact damage
            if (_enemies[i].Alive && _enemies[i].Type == EnemyType.Charger && _enemies[i].AiPhase == 2)
            {
                float chargeDist = Vector2.Distance(_enemies[i].Position, _playerPos);
                if (chargeDist < _enemies[i].Size + 10f && _iFrameTimer <= 0)
                {
                    DamagePlayer(15f, _enemies[i].Position);
                    _trauma = MathF.Min(_trauma + 0.25f, 1f);
                }
            }
            // Wraith slash contact damage
            if (_enemies[i].Alive && _enemies[i].Type == EnemyType.Wraith && _enemies[i].AiPhase == 2)
            {
                float wraithDist = Vector2.Distance(_enemies[i].Position, _playerPos);
                if (wraithDist < _enemies[i].Size + 15f && _iFrameTimer <= 0)
                {
                    DamagePlayer(12f, _enemies[i].Position);
                    _trauma = MathF.Min(_trauma + 0.2f, 1f);
                }
            }
            // Enemy-wall collision
            if (_enemies[i].Alive && _screenWalls.TryGetValue(_currentScreen, out var eWalls))
            {
                float es = _enemies[i].Size;
                var eRect = new Rectangle((int)(_enemies[i].Position.X - es/2), (int)(_enemies[i].Position.Y - es/2), (int)es, (int)es);
                foreach (var wall in eWalls)
                {
                    if (!eRect.Intersects(wall)) continue;
                    float pushLeft = eRect.Right - wall.Left;
                    float pushRight = wall.Right - eRect.Left;
                    float pushUp = eRect.Bottom - wall.Top;
                    float pushDown = wall.Bottom - eRect.Top;
                    float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                    if (minPush == pushLeft) { _enemies[i].Position.X -= pushLeft; _enemies[i].WallSlideDir = Vector2.UnitY; }
                    else if (minPush == pushRight) { _enemies[i].Position.X += pushRight; _enemies[i].WallSlideDir = Vector2.UnitY; }
                    else if (minPush == pushUp) { _enemies[i].Position.Y -= pushUp; _enemies[i].WallSlideDir = Vector2.UnitX; }
                    else { _enemies[i].Position.Y += pushDown; _enemies[i].WallSlideDir = Vector2.UnitX; }
                    // Dust puff on first wall hit
                    if (!_enemies[i].WallSlideStarted)
                    {
                        for (int d = 0; d < 4; d++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = _enemies[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(180, 170, 150),
                                Size = 2f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                    }
                    _enemies[i].WallSlideTimer = 0.4f; // slide for 0.4s then try direct path again
                    eRect = new Rectangle((int)(_enemies[i].Position.X - es/2), (int)(_enemies[i].Position.Y - es/2), (int)es, (int)es);
                }
            }
            
            // Arena border collision — enemies can't be knocked past screen edges
            if (_enemies[i].Alive)
            {
                float es = _enemies[i].Size * 0.5f;
                Vector2 oldPos = _enemies[i].Position;
                _enemies[i].Position.X = MathHelper.Clamp(_enemies[i].Position.X, _arena.Left + es, _arena.Right - es);
                _enemies[i].Position.Y = MathHelper.Clamp(_enemies[i].Position.Y, _arena.Top + es, _arena.Bottom - es);
                // Wall slam particles if clamped while moving fast
                if (_enemies[i].Position != oldPos && _enemies[i].KnockbackVel.LengthSquared() > 2000f)
                {
                    _enemies[i].KnockbackVel *= -0.3f; // slight bounce
                    _trauma = MathF.Min(_trauma + 0.08f, 0.4f);
                    for (int d = 0; d < 6; d++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = _enemies[i].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(200, 190, 170),
                            Size = 2.5f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                }
            }

            // Hedge wall collision (Tiamat's Garden)
            if (_enemies[i].Alive && !_enemies[i].Possessed)
            {
                float es2 = _enemies[i].Size;
                var eRect2 = new Rectangle((int)(_enemies[i].Position.X - es2/2), (int)(_enemies[i].Position.Y - es2/2), (int)es2, (int)es2);
                for (int h = 0; h < _hedgeWalls.Count; h++)
                {
                    var hedge = _hedgeWalls[h];
                    if (hedge.GrowTimer > 0) continue; // not yet solid
                    if (!eRect2.Intersects(hedge.Rect)) continue;
                    // Push out
                    float pushLeft = eRect2.Right - hedge.Rect.Left;
                    float pushRight = hedge.Rect.Right - eRect2.Left;
                    float pushUp = eRect2.Bottom - hedge.Rect.Top;
                    float pushDown = hedge.Rect.Bottom - eRect2.Top;
                    float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                    if (minPush == pushLeft) _enemies[i].Position.X -= pushLeft;
                    else if (minPush == pushRight) _enemies[i].Position.X += pushRight;
                    else if (minPush == pushUp) _enemies[i].Position.Y -= pushUp;
                    else _enemies[i].Position.Y += pushDown;
                    eRect2 = new Rectangle((int)(_enemies[i].Position.X - es2/2), (int)(_enemies[i].Position.Y - es2/2), (int)es2, (int)es2);
                    // Thorn damage + slow on contact (charged = 1.5× damage)
                    float thornDps = hedge.Charged ? 22f : 15f;
                    _enemies[i].TakeDamage(ApplyElementCounter(_enemies[i], thornDps * dt, _loadout.Essence, showBark: false));
                    _enemies[i].SlowTimer = MathF.Max(_enemies[i].SlowTimer, 0.5f);
                    // Hedge blocks path → set wall slide direction
                    if (minPush == pushLeft || minPush == pushRight)
                        _enemies[i].WallSlideDir = Vector2.UnitY;
                    else
                        _enemies[i].WallSlideDir = Vector2.UnitX;
                    _enemies[i].WallSlideTimer = 0.4f;
                    // Enemy damages the hedge
                    hedge.Hp -= 3f * dt;
                    _hedgeWalls[h] = hedge;
                }
            }
            
            // Spawn enemy projectiles from pending shots
            if (_enemies[i].PendingShots.Count > 0)
            {
                foreach (var shot in _enemies[i].PendingShots)
                {
                    if (shot.Speed < 0)
                    {
                        // Thief escape: smoke bomb particles + smiley decal
                        Vector2 escPos = _enemies[i].Position;
                        for (int p = 0; p < 30; p++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 20f + (float)_rng.NextDouble() * 80f;
                            _particles.Add(new Particle
                            {
                                Position = escPos,
                                Velocity = new Vector2(MathF.Cos(a) * spd, MathF.Sin(a) * spd),
                                Life = 0.8f + (float)_rng.NextDouble() * 0.5f,
                                MaxLife = 1.3f,
                                Color = new Color(80, 80, 80) * 0.8f,
                                Size = 4f + (float)_rng.NextDouble() * 6f,
                            });
                        }
                        // Smiley face as a persistent decal (abuse floating text with long life)
                        _floatingTexts.Add(new FloatingText { Position = escPos + new Vector2(-6, 0), Text = ":)", Color = new Color(255, 220, 80) * 0.6f, Life = 8f, MaxLife = 8f });
                        _trauma = MathF.Min(_trauma + 0.15f, 0.5f);
                        continue;
                    }
                    _enemyProjectiles.Add(new EnemyProjectile
                    {
                        Position = _enemies[i].Position,
                        Velocity = shot.Direction * shot.Speed,
                        Damage = shot.Damage,
                        Size = shot.Size,
                        Life = shot.Lifetime,
                        Seeking = shot.Seeking,
                        Color = Color.Lerp(_enemies[i].BaseColor, Color.White, 0.3f),
                    });
                }
                _enemies[i].PendingShots.Clear();
            }
            
            // Spider web vs player projectiles
            if (_spiderWebs.Count > 0)
            {
                for (int wi = _spiderWebs.Count - 1; wi >= 0; wi--)
                {
                    var w = _spiderWebs[wi];
                    for (int pi2 = _projectiles.Count - 1; pi2 >= 0; pi2--)
                    {
                        if (!_projectiles[pi2].Alive) continue;
                        if (Vector2.Distance(_projectiles[pi2].Position, w.Position) < 20f)
                        {
                            // Cinder/fire destroys instantly
                            if (_projectiles[pi2].Params.EssenceType == Essence.Cinder)
                                w.HitsLeft = 0;
                            else
                                w.HitsLeft--;
                            if (w.HitsLeft <= 0)
                            {
                                for (int pp = 0; pp < 5; pp++)
                                    _particles.Add(new Particle { Position = w.Position, Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f), Life = 0.4f, MaxLife = 0.4f, Color = new Color(160, 160, 170), Size = 2f });
                                _spiderWebs.RemoveAt(wi);
                                break;
                            }
                            _spiderWebs[wi] = w;
                            break;
                        }
                    }
                }
            }
            
            // Gae Bolg Shrieker: pulse electricity to nearby enemies
            if (_enemies[i].ShriekerTimer > 0 && _enemies[i].ShriekerPulseTimer <= 0)
            {
                _enemies[i].ShriekerPulseTimer = 0.5f; // pulse every 0.5s
                float pulseRadius = 80f;
                float pulseDmg = 12f;
                // Damage nearby enemies
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (i == j || !_enemies[j].Alive || _enemies[j].ShriekerTimer > 0) continue;
                    float d = Vector2.Distance(_enemies[i].Position, _enemies[j].Position);
                    if (d < pulseRadius)
                    {
                        _enemies[j].TakeDamage(pulseDmg);
                        _enemies[j].StasisTimer = MathF.Max(_enemies[j].StasisTimer, 0.3f);
                        // Lightning arc particles to hit enemy
                        Vector2 arcStep = (_enemies[j].Position - _enemies[i].Position) / 6f;
                        for (int p = 0; p < 6; p++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = _enemies[i].Position + arcStep * p + new Vector2(((float)_rng.NextDouble() - 0.5f) * 12f, ((float)_rng.NextDouble() - 0.5f) * 12f),
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(180, 220, 255),
                                Size = 2f,
                            });
                        }
                    }
                }
                // Shrieker scream visual: ring of electric particles expanding outward
                for (int p = 0; p < 12; p++)
                {
                    float a = (MathF.PI * 2f / 12f) * p;
                    _particles.Add(new Particle
                    {
                        Position = _enemies[i].Position,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (60f + (float)_rng.NextDouble() * 40f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(100, 180, 255) : new Color(200, 230, 255),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.05f, 1f);
            }
            
            // Possessed enemies: steer toward and damage other enemies
            if (_enemies[i].Alive && _enemies[i].Possessed)
            {
                Enemy target = null;
                float tDist = float.MaxValue;
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (i == j || !_enemies[j].Alive || _enemies[j].Possessed) continue;
                    float d = Vector2.Distance(_enemies[i].Position, _enemies[j].Position);
                    if (d < tDist) { tDist = d; target = _enemies[j]; }
                }
                if (target != null)
                {
                    // Steer toward target
                    Vector2 toTarget = target.Position - _enemies[i].Position;
                    if (toTarget.LengthSquared() > 1f)
                    {
                        toTarget.Normalize();
                        float spd = _enemies[i].Speed * 1.3f; // possessed are aggressive
                        _enemies[i].Position += toTarget * spd * dt;
                    }
                    // Contact damage
                    if (tDist < 15f)
                    {
                        // Saibaman: self-destruct on contact!
                        if (_enemies[i].FusionTag == "Saibaman")
                        {
                            // Explode — AoE damage to all nearby enemies
                            for (int k = 0; k < _enemies.Count; k++)
                            {
                                if (k == i || !_enemies[k].Alive || _enemies[k].Possessed) continue;
                                if (Vector2.Distance(_enemies[i].Position, _enemies[k].Position) < 50f)
                                {
                                    _enemies[k].TakeDamage(_enemies[i].Hp * 2f); // big self-destruct damage
                                }
                            }
                            _enemies[i].Hp = 0;
                            _enemies[i].Alive = false;
                            SpawnExplosion(_enemies[i].Position, new Color(120, 40, 160), 15, 0.4f, 18f);
                            SpawnExplosion(_enemies[i].Position, new Color(60, 200, 30), 10, 0.3f, 12f);
                            _trauma = MathF.Min(_trauma + 0.15f, 1f);
                        }
                        else
                        {
                            bool killed = target.TakeDamage(_enemies[i].Hp * 0.3f);
                            if (killed) { SpawnExplosion(target.Position, new Color(255, 215, 0), 8, 0.3f, 6f); }
                        }
                    }
                }
            }
            if (!_enemies[i].Alive)
            {
                // Thief escape (Phase 3): skip normal death — already handled via PendingShots signal
                if (_enemies[i].Type == EnemyType.Thief && _enemies[i].AiPhase == 3)
                {
                    _thiefStolenLoot.Remove(_enemies[i].Id);
                    _enemyById.Remove(_enemies[i].Id);
                    _enemies.RemoveAt(i);
                    continue;
                }
                
                // Fusion-specific possessed enemy death effects
                if (_enemies[i].Possessed)
                {
                    if (_currentFusion == "Gebel's Swarm")
                    {
                        // Possessed enemy explodes into bat projectiles
                        var parms = ProjectileParams.Resolve(_loadout);
                        parms.BaseDamage *= 0.4f;
                        for (int b = 0; b < 6; b++)
                        {
                            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                            var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 200f;
                            var bat = new Projectile(_enemies[i].Position, vel, parms);
                            bat.Lifetime = 0.5f;
                            bat.Size = 4f;
                            bat.FusionName = "Gebel's Swarm";
                            _projectiles.Add(bat);
                        }
                        SpawnExplosion(_enemies[i].Position, new Color(120, 40, 160), 10, 0.3f, 8f);
                        _trauma = MathF.Min(_trauma + 0.1f, 1f);
                    }
                    else if (_currentFusion == "Morrigan's Court")
                    {
                        // Dead possessed enemy spawns an additional orbiting phantom
                        var parms = ProjectileParams.Resolve(_loadout);
                        parms.BaseDamage *= 0.5f;
                        float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                        Vector2 offset = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * parms.OrbitRadius;
                        var phantom = new Projectile(_playerPos + offset, Vector2.Zero, parms);
                        phantom.OrbitAngle = angle;
                        phantom.Size = 7f;
                        phantom.Lifetime = 4f;
                        phantom.FusionName = "Morrigan's Court";
                        _projectiles.Add(phantom);
                        SpawnExplosion(_enemies[i].Position, new Color(80, 30, 100), 8, 0.4f, 6f);
                    }
                }
                
                // ═══════════════ UNIVERSAL DEATH EFFECTS ═══════════════
                var deadEnemy = _enemies[i];

                // Bonfire growth: enemy died, check if inside a bonfire zone
                for (int bz = 0; bz < _lingerZones.Count; bz++)
                {
                    var zone = _lingerZones[bz];
                    if (zone.FusionTag != "Bonfire") continue;
                    if (Vector2.Distance(zone.Position, deadEnemy.Position) < zone.Radius + deadEnemy.Size / 2f)
                    {
                        float origRadius = 25f;
                        zone.Radius = MathF.Min(zone.Radius * 1.3f, origRadius * 3f);
                        zone.Life = MathF.Min(zone.Life + 3f, zone.MaxLife + 6f);
                        _lingerZones[bz] = zone;
                        // Growth flash
                        SpawnExplosion(zone.Position, new Color(255, 200, 60), 15, 0.3f, 10f);
                        _trauma = MathF.Min(_trauma + 0.08f, 1f);
                        break;
                    }
                }
                
                // Base death burst: particles in enemy color
                int burstCount = 10 + (int)(deadEnemy.Size * 0.5f);
                for (int dp = 0; dp < burstCount; dp++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 60f + (float)_rng.NextDouble() * 120f;
                    _particles.Add(new Particle
                    {
                        Position = deadEnemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size, ((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size),
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.25f + (float)_rng.NextDouble() * 0.2f,
                        MaxLife = 0.45f,
                        Color = Color.Lerp(deadEnemy.BaseColor, Color.White, (float)_rng.NextDouble() * 0.4f),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                // White flash center burst
                for (int dp = 0; dp < 4; dp++)
                {
                    _particles.Add(new Particle
                    {
                        Position = deadEnemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 4f, ((float)_rng.NextDouble() - 0.5f) * 4f),
                        Velocity = Vector2.Zero,
                        Life = 0.08f,
                        MaxLife = 0.08f,
                        Color = Color.White,
                        Size = deadEnemy.Size * (0.6f + (float)_rng.NextDouble() * 0.4f),
                    });
                }
                // Trauma scales with enemy size
                _trauma = MathF.Min(_trauma + 0.08f + deadEnemy.Size * 0.002f, 1f);
                
                // ═══════════════ BOSS KILL SPECTACLE ═══════════════
                if (deadEnemy.Id == _bossId)
                {
                    _hitstopTimer = 0.3f; // freeze frame
                    _trauma = 1f; // max shake
                    
                    // Massive explosion ring
                    for (int bp = 0; bp < 40; bp++)
                    {
                        float a = bp * MathF.PI * 2f / 40f;
                        float spd = 150f + (float)_rng.NextDouble() * 200f;
                        _particles.Add(new Particle
                        {
                            Position = deadEnemy.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                            Life = 0.5f + (float)_rng.NextDouble() * 0.4f, MaxLife = 0.9f,
                            Color = Color.Lerp(deadEnemy.BaseColor, Color.White, (float)_rng.NextDouble() * 0.5f),
                            Size = 4f + (float)_rng.NextDouble() * 5f,
                        });
                    }
                    // White core flash
                    for (int bp = 0; bp < 8; bp++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = deadEnemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                            Velocity = Vector2.Zero,
                            Life = 0.12f, MaxLife = 0.12f,
                            Color = Color.White,
                            Size = deadEnemy.Size * (1f + (float)_rng.NextDouble() * 0.5f),
                        });
                    }
                    // Shard rain — extra shards everywhere
                    for (int bp = 0; bp < 15; bp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 60f + (float)_rng.NextDouble() * 100f;
                        int val = _rng.NextDouble() < 0.2 ? 25 : _rng.NextDouble() < 0.5 ? 5 : 1;
                        _shards.Add(new EtherShard
                        {
                            Position = deadEnemy.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                            Life = 10f,
                            Value = val,
                            MagnetTimer = 0.6f + (float)_rng.NextDouble() * 0.4f,
                        });
                    }
                }
                
                // Kill streak tracking (skip possessed minions — they're ours)
                if (!deadEnemy.Possessed)
                {
                    _streakCount++;
                    _streakTimer = 2f;
                }
                
                // Ether shard drops
                {
                    // Bigger enemies drop more; small chance of high-value shards
                    int shardCount = 1 + (int)(deadEnemy.Size / 10f) + (_rng.NextDouble() < 0.3 ? 1 : 0);
                    for (int sd = 0; sd < shardCount; sd++)
                    {
                        int val = 1;
                        double roll = _rng.NextDouble();
                        if (roll < 0.03) val = 25;       // 3% gold
                        else if (roll < 0.15) val = 5;   // 12% blue
                        
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 80f + (float)_rng.NextDouble() * 60f;
                        _shards.Add(new EtherShard
                        {
                            Position = deadEnemy.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                            Life = 8f, // despawn after 8s
                            Value = val,
                            MagnetTimer = 0.3f + (float)_rng.NextDouble() * 0.2f, // scatter first, then pull
                        });
                    }
                }
                
                // Marrow Bloom: dead enemy becomes a Bone Husk obstacle
                if (deadEnemy.KilledByFusion == "MarrowBloom")
                {
                    _boneHusks.Add(new BoneHusk
                    {
                        Position = deadEnemy.Position,
                        Size = MathF.Max(deadEnemy.Size * 0.8f, 20f),
                        Hp = 1f,
                        GrowTimer = 1.5f,
                        PulseTimer = 0f,
                        EnemySize = deadEnemy.Size,
                        EnemyColor = deadEnemy.BaseColor,
                        SpikeCount = 0
                    });
                }
                
                // Thief: drop stolen loot on ANY kill path
                if (deadEnemy.Type == EnemyType.Thief && _thiefStolenLoot.TryGetValue(deadEnemy.Id, out var loot))
                {
                    foreach (var item in loot) DropSackItemToGround(item);
                    _thiefStolenLoot.Remove(deadEnemy.Id);
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = deadEnemy.Position + new Vector2(-30, -30),
                        Text = "RECOVERED LOOT!",
                        Color = new Color(255, 200, 50),
                        Life = 1.5f, MaxLife = 1.5f,
                    });
                }
                
                TryDropComponent(deadEnemy);
                _enemyById.Remove(deadEnemy.Id);
                _enemies.RemoveAt(i);
                _killCount++;
                _playerEther = MathF.Min(_playerEther + 2f, EffectiveMaxEther); // flat 2 EP per kill
                if (_hasDragonDance) _dragonDanceStacks += 0.1f; // +10% per kill
                continue;
            }

            // Shield bash damage
            if (_isDashing)
            {
                float dist = Vector2.Distance(_enemies[i].Position, _playerPos);
                if (dist < (_enemies[i].Size + PlayerSize) / 2f + 5f)
                {
                    _enemies[i].TakeDamage(ApplyElementCounter(_enemies[i], 15f, _loadout.Essence));
                    Vector2 kb2 = _enemies[i].Position - _playerPos;
                    if (kb2.LengthSquared() > 0) kb2.Normalize();
                    _enemies[i].Position += kb2 * 60f;
                    _trauma = MathF.Min(_trauma + 0.1f, 1f);
                }
            }

            // Contact damage (skip if dashing = invulnerable)
            if (!_isDashing && !_testMode && !_enemies[i].Spawning)
            {
                float dist = Vector2.Distance(_enemies[i].Position, _playerPos);
                if (dist < (_enemies[i].Size + PlayerSize) / 2f)
                {
                    DamagePlayer(10f, _enemies[i].Position);
                    _trauma = MathF.Min(_trauma + 0.05f * dt, 1f);
                }
            }
        }

        // Bone Husk updates
        for (int i = _boneHusks.Count - 1; i >= 0; i--)
        {
            var husk = _boneHusks[i];
            
            // Grow animation
            if (husk.GrowTimer > 0)
            {
                float prev = husk.GrowTimer;
                husk.GrowTimer -= dt;
                float phase = 1f - (husk.GrowTimer / 1.5f); // 0→1 over 1.5s
                
                // Phase 1 (0-0.2): Seizure — vibrate, leak bone particles
                if (phase < 0.2f)
                {
                    // Leak bone crack particles
                    if (_rng.NextDouble() < 0.3)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = husk.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * husk.EnemySize * 0.3f,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 15f,
                            Life = 0.5f, MaxLife = 0.5f,
                            Color = new Color(220, 200, 170),
                            Size = 1f
                        });
                    }
                }
                // Phase 2 (0.2-0.47): Eruption — spikes burst out one at a time
                else if (phase < 0.47f)
                {
                    int targetSpikes = (int)((phase - 0.2f) / 0.27f * 8f);
                    if (targetSpikes > husk.SpikeCount)
                    {
                        husk.SpikeCount = targetSpikes;
                        _trauma = MathF.Min(_trauma + 0.03f, 1f); // micro-shake per spike
                        // Spike burst particles
                        float spikeAngle = (husk.SpikeCount - 1) * MathF.PI * 2f / 8f;
                        for (int p = 0; p < 4; p++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = husk.Position + new Vector2(MathF.Cos(spikeAngle), MathF.Sin(spikeAngle)) * husk.EnemySize * 0.5f,
                                Velocity = new Vector2(MathF.Cos(spikeAngle) + (float)(_rng.NextDouble() - 0.5) * 0.5f,
                                                       MathF.Sin(spikeAngle) + (float)(_rng.NextDouble() - 0.5) * 0.5f) * (40f + (float)_rng.NextDouble() * 30f),
                                Life = 0.4f, MaxLife = 0.4f,
                                Color = new Color(200, 60, 40), // blood/gore
                                Size = 1.5f
                            });
                        }
                    }
                }
                // Phase 3 (0.47-0.8): Bloom — body swells and hardens
                else if (phase < 0.8f)
                {
                    husk.SpikeCount = 8; // all spikes out
                }
                // Phase 4 (0.8-1.0): Solidify — final crunch
                else
                {
                    husk.SpikeCount = 8;
                    if (prev > 0 && husk.GrowTimer <= 0)
                    {
                        // Final solidify crunch
                        _trauma = MathF.Min(_trauma + 0.12f, 1f);
                        for (int p = 0; p < 8; p++)
                        {
                            float a = p * MathF.PI * 2f / 8f;
                            _particles.Add(new Particle
                            {
                                Position = husk.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 25f,
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = new Color(255, 240, 200),
                                Size = 2.5f
                            });
                        }
                    }
                }
                
                _boneHusks[i] = husk;
                continue; // don't collide while growing
            }
            
            husk.PulseTimer += dt;
            float currentSize = husk.Size;
            
            // Damage enemies on contact
            for (int ei = 0; ei < _enemies.Count; ei++)
            {
                if (!_enemies[ei].Alive) continue;
                float dist = Vector2.Distance(husk.Position, _enemies[ei].Position);
                if (dist < currentSize + _enemies[ei].Size / 2f)
                {
                    _enemies[ei].TakeDamage(ApplyElementCounter(_enemies[ei], 15f * dt, _loadout.Essence, showBark: false));
                    // Push enemy away
                    Vector2 push = _enemies[ei].Position - husk.Position;
                    if (push.LengthSquared() > 0) push.Normalize();
                    _enemies[ei].Position += push * 40f * dt;
                }
            }
            
            // Damage player on contact
            if (!_isDashing)
            {
                float playerDist = Vector2.Distance(husk.Position, _playerPos);
                if (playerDist < currentSize + PlayerSize / 2f)
                {
                    DamagePlayer(5f * dt, husk.Position);
                }
            }
            
            // Block player movement (push out)
            float pDist = Vector2.Distance(husk.Position, _playerPos);
            if (pDist < currentSize + PlayerSize / 2f - 2f)
            {
                Vector2 pushDir = _playerPos - husk.Position;
                if (pushDir.LengthSquared() > 0) pushDir.Normalize();
                _playerPos = husk.Position + pushDir * (currentSize + PlayerSize / 2f);
            }
            
            // Destroyed by any projectile hit (player projectiles only)
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                if (!proj.Alive) continue;
                if (Vector2.Distance(proj.Position, husk.Position) < currentSize + 5f)
                {
                    // Shatter into bone particles
                    for (int p = 0; p < 12; p++)
                    {
                        float a = p * MathF.PI * 2f / 12f + (float)_rng.NextDouble() * 0.3f;
                        float spd = 60f + (float)_rng.NextDouble() * 80f;
                        _particles.Add(new Particle
                        {
                            Position = husk.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                            Life = 0.8f, MaxLife = 0.8f,
                            Color = new Color(220, 200, 170),
                            Size = 2f + (float)_rng.NextDouble() * 2f
                        });
                    }
                    _trauma = MathF.Min(_trauma + 0.08f, 1f);
                    husk.Hp = 0;
                    _projectiles[pi].Alive = false;
                    break;
                }
            }
            
            _boneHusks[i] = husk;
            if (husk.Hp <= 0)
                _boneHusks.RemoveAt(i);
        }

        // Collect shatter spawns to add AFTER iteration
        List<Projectile> deferred = null;

        // Seed + Bounce proximity detection: explode into bouncing fragments
        for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
        {
            var proj = _projectiles[pi];
            if (!proj.Alive || !proj.Params.IsStationary || !proj.Params.Bounces) continue;
            bool triggered = false;
            for (int ei = 0; ei < _enemies.Count; ei++)
            {
                if (!_enemies[ei].Alive) continue;
                if (Vector2.Distance(proj.Position, _enemies[ei].Position) < 30f)
                {
                    triggered = true;
                    break;
                }
            }
            if (triggered)
            {
                proj.Alive = false;
                deferred ??= new();
                int fragCount = 4 + _rng.Next(3); // 4-6
                for (int f = 0; f < fragCount; f++)
                {
                    float angle = f * (MathF.PI * 2f / fragCount) + (float)_rng.NextDouble() * 0.3f;
                    var fragParms = proj.Params;
                    fragParms.IsStationary = false;
                    fragParms.Speed = 250f;
                    fragParms.Lifetime = 2f;
                    fragParms.BaseDamage *= 0.5f;
                    var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 250f;
                    var frag = new Projectile(proj.Position, vel, fragParms) { Size = proj.Size * 0.6f };
                    deferred.Add(frag);
                }
                SpawnExplosion(proj.Position, new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B), 8, 0.3f, 15f);
            }
        }

        for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
        {
            var proj = _projectiles[pi];
            if (!proj.Alive) continue;
            // Seeds in arc flight don't collide yet
            if (proj.ArcDuration > 0 && !proj.ArcLanded) continue;
            // Grace period (comet in flight, etc.)
            if (proj.GracePeriod > 0) continue;
            for (int i = _enemies.Count - 1; i >= 0; i--)
            {
                if (!_enemies[i].Alive) continue;
                // Swinging blade collision: check if enemy is within the blade's current sweep
                bool hit = false;
                if (proj.BladeLength > 0)
                {
                    float swingT = MathHelper.Clamp(proj.Age / proj.Lifetime, 0f, 1f);
                    // Match easing to the draw: Dragon Slayer = ease-in, others = ease-out
                    float easedT = (proj.FusionName == "DragonSlayer" || proj.FusionName == "DragonSlayerAfter")
                        ? swingT * swingT
                        : 1f - (1f - swingT) * (1f - swingT);
                    float currentAngle = MathHelper.Lerp(proj.SwingStartAngle, proj.SwingEndAngle, easedT);
                    Vector2 toEnemy = _enemies[i].Position - proj.Position;
                    float dist = toEnemy.Length();
                    if (dist < proj.BladeLength + _enemies[i].Size / 2f && dist > 6f)
                    {
                        float enemyAngle = MathF.Atan2(toEnemy.Y, toEnemy.X);
                        float angleDiff = enemyAngle - currentAngle;
                        while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
                        while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
                        if (MathF.Abs(angleDiff) < 0.4f) // ~23° grace on each side of blade
                            hit = true;
                    }
                }
                else if (proj.SlashRadius > 0)
                {
                    Vector2 toEnemy = _enemies[i].Position - proj.Position;
                    float dist = toEnemy.Length();
                    if (dist < proj.SlashRadius + _enemies[i].Size / 2f && dist > proj.SlashRadius * 0.3f)
                    {
                        float enemyAngle = MathF.Atan2(toEnemy.Y, toEnemy.X);
                        float angleDiff = enemyAngle - proj.SlashBaseAngle;
                        // Normalize to [-PI, PI]
                        while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
                        while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
                        if (MathF.Abs(angleDiff) < proj.SlashSweep / 2f + 0.2f) // small angular grace
                            hit = true;
                    }
                }
                else
                {
                    hit = proj.HitBox.Intersects(_enemies[i].HitBox);
                }
                if (hit)
                {
                    // Skip enemies already hit by piercing projectiles
                    if (proj.Params.Piercing && proj.HitEnemies.Contains(_enemies[i].Id))
                        continue;
                    
                    var enemy = _enemies[i];

                    // Sap leech heal
                    if (enemy.LeechStack > 0)
                        _playerHp = MathF.Min(_playerHp + enemy.LeechStack * 0.5f, PlayerMaxHp);

                    float dmg = proj.Params.BaseDamage;
                    // Active reload damage bonus (consumed on actual hits)
                    if (_reloadDmgBonusShots > 0)
                    {
                        dmg *= _reloadDmgBonus;
                        _reloadDmgBonusShots--;
                        if (_reloadDmgBonusShots <= 0) _reloadDmgBonus = 1f;
                    }
                    // Bloom: damage scales with current growth
                    if (proj.Params.BloomGrowRate > 0)
                        dmg *= proj.CurrentScale;
                    
                    // Gauntlet resistance: 25% damage from non-matching behavior
                    if (enemy.FusionTag != null && enemy.FusionTag.StartsWith("weak_"))
                    {
                        string weakness = enemy.FusionTag.Substring(5); // "linger", "shatter", "bloom"
                        Behavior projBehavior = proj.Params.BehaviorType;
                        bool matches = (weakness == "linger" && projBehavior == Behavior.Linger) ||
                                       (weakness == "shatter" && projBehavior == Behavior.Shatter) ||
                                       (weakness == "bloom" && projBehavior == Behavior.Bloom);
                        if (!matches) dmg *= 0.25f;
                        // Spawn WEAKNESS or RESIST bark (requires Ether Sight)
                        if (_hasEtherSight)
                            _floatingTexts.Add(new FloatingText
                            {
                                Position = enemy.Position + new Vector2(-20, -enemy.Size / 2 - 15),
                                Text = matches ? "WEAKNESS!" : "RESIST",
                                Color = matches ? new Color(255, 200, 50) : new Color(120, 120, 120),
                                Life = matches ? 1.0f : 0.6f,
                                MaxLife = matches ? 1.0f : 0.6f
                            });
                    }
                    
                    // Element counter: damage modifier
                    dmg = ApplyElementCounter(enemy, dmg, proj.Params.EssenceType);
                    
                    bool killed = enemy.TakeDamage(dmg, proj.Velocity);
                    if (killed && proj.FusionName != null)
                        enemy.KilledByFusion = proj.FusionName;
                    
                    // Stagger/Break system
                    if (!killed)
                    {
                        if (!enemy.IsBroken)
                        {
                            float staggerAmount = dmg * 0.8f;
                            staggerAmount = MathF.Max(staggerAmount, 5f); // minimum stagger per hit
                            if (_currentDualCombo != null) staggerAmount *= 1.5f;
                            staggerAmount = ApplyElementCounterStagger(enemy, staggerAmount, proj.Params.EssenceType);
                            if (enemy.FractureStacks > 0) { staggerAmount *= 1.5f; enemy.FractureStacks--; }
                            enemy.Stagger += staggerAmount;
                            if (enemy.Stagger >= enemy.MaxStagger)
                            {
                                enemy.Stagger = 0;
                                enemy.BreakTimer = 2.5f;
                                enemy.StaggerTimer = 0.5f;
                                _trauma = MathF.Min(_trauma + 0.2f, 0.8f);
                            }
                        }
                        else
                        {
                            enemy.Hp -= dmg * 2f; // extra 2x on top of 1x already dealt = 3x total
                            _playerEther = MathF.Min(_playerEther + 3f, EffectiveMaxEther);
                            if (enemy.Hp <= 0)
                            {
                                // Ranged finisher: triple fusion kill on broken enemy
                                if (_currentFusion != null && !_finisherActive)
                                {
                                    enemy.Hp = 1f;
                                    enemy.Alive = true;
                                    _finisherActive = true;
                                    _finisherTimer = FinisherDuration;
                                    _finisherTarget = enemy.Position;
                                    _finisherEnemyIndex = i;
                                    _finisherEssence = proj.Params.EssenceType;
                                    _finisherIsRanged = true;
                                    _finisherZoom = 1f;
                                    _finisherKillProcessed = false;
                                    killed = false;
                                }
                                else
                                {
                                    enemy.Alive = false; killed = true;
                                    SpawnEtherDrops(enemy.Position, false);
                                }
                            }
                        }
                    }
                    
                    // Thief hit barks
                    if (enemy.Type == EnemyType.Thief && !killed && enemy.BarkTimer <= 0)
                    {
                        string[] hitBarks = { "Ow!", "Hey!", "Quit it!", "Not the face!", "I bruise easily!" };
                        enemy.Bark = hitBarks[_rng.Next(hitBarks.Length)]; enemy.BarkTimer = 0.8f;
                    }
                    
                    // Death barks for unique enemies (as floating text since enemy gets removed)
                    if (killed)
                    {
                        bool hollowKill = proj.Params.EssenceType == Essence.Hollow;
                        string deathBark = enemy.Type switch
                        {
                            EnemyType.Thief => "Was just... trying to survive...",
                            EnemyType.ShieldMaiden => "I held... the line...",
                            // Hollow essence: fae energy reveals their inner thoughts
                            EnemyType.Webspinner when hollowKill => "I was... building a home... for my children...",
                            EnemyType.HollowPlate when hollowKill => "I remember... sunlight... a name I've forgotten...",
                            EnemyType.GuardGargoyle when hollowKill => "I dreamed... of flying... not falling...",
                            EnemyType.HedgeSniper when hollowKill => "I only wanted... to be left alone...",
                            EnemyType.TowerGuard when hollowKill => "I was told... someone would come... to relieve me...",
                            EnemyType.Maw when hollowKill => "...finally... shape...",
                            EnemyType.Maw => "...",
                            EnemyType.Charger when hollowKill => "Couldn't stop... running... from what I was...",
                            EnemyType.Gremlin when hollowKill => "Hehe... wasn't even... funny...",
                            EnemyType.Wraith when hollowKill => "I forgot... what I looked like... before...",
                            _ => null,
                        };
                        if (deathBark != null)
                        {
                            Color deathCol = hollowKill ? new Color(140, 180, 220) * 0.8f : new Color(200, 200, 200) * 0.7f;
                            _floatingTexts.Add(new FloatingText
                            {
                                Position = enemy.Position + new Vector2(-deathBark.Length * 2.5f, -enemy.Size / 2 - 30),
                                Text = deathBark,
                                Color = deathCol,
                                Life = 2.5f, MaxLife = 2.5f,
                            });
                        }
                    }
                    
                    PlaySfx(_sfxHit, killed ? 0.5f : 0.25f);
                    _trauma = MathF.Min(_trauma + (killed ? 0.15f : 0.05f), 1f);
                    
                    // Knockback: push enemy away from projectile direction
                    if (!killed)
                    {
                        Vector2 kbDir = proj.Velocity;
                        if (kbDir.LengthSquared() < 1f) kbDir = enemy.Position - _playerPos; // fallback
                        if (kbDir.LengthSquared() > 0) kbDir.Normalize();
                        float kbForce = 120f + dmg * 3f; // scales with damage
                        enemy.KnockbackVel = kbDir * kbForce;
                    }
                    
                    // Muddy Water: extra knockback + slow
                    if (_currentDualCombo == "Muddy Water")
                    {
                        Vector2 pushDir = proj.Velocity;
                        if (pushDir.LengthSquared() > 0) pushDir.Normalize();
                        enemy.KnockbackVel += pushDir * 200f;
                        enemy.SlowTimer = MathF.Max(enemy.SlowTimer, 1.5f);
                    }
                    
                    // Thunder Wave: guaranteed stasis
                    if (_currentDualCombo == "Thunder Wave")
                    {
                        enemy.StasisTimer = MathF.Max(enemy.StasisTimer, 1.2f);
                    }
                    
                    // Ice Shard: brief freeze on hit
                    if (_currentDualCombo == "Ice Shard")
                    {
                        enemy.StasisTimer = MathF.Max(enemy.StasisTimer, 0.6f);
                    }
                    
                    // Summon Spirit: fear + slow (ghostly dread)
                    if (_currentDualCombo == "Summon Spirit")
                    {
                        enemy.FearTimer = MathF.Max(enemy.FearTimer, 1.0f);
                        enemy.SlowTimer = MathF.Max(enemy.SlowTimer, 0.8f);
                    }
                    
                    // Gae Bolg: turn enemy into a Shrieker (DOS2 style)
                    if (proj.FusionName == "GaeBolg" && enemy.ShriekerTimer <= 0 && enemy.Alive)
                    {
                        enemy.ShriekerTimer = 5f; // 5 second shrieker
                        enemy.ShriekerPulseTimer = 0f; // pulse immediately
                        enemy.StasisTimer = 5f;
                        enemy.KnockbackVel = Vector2.Zero;
                        // Impalement particles: barbs sprouting
                        for (int bp = 0; bp < 15; bp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float len = 8f + (float)_rng.NextDouble() * 15f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * len * 3f,
                                Life = 0.4f, MaxLife = 0.4f,
                                Color = _rng.NextDouble() > 0.3 ? new Color(100, 180, 255) : new Color(255, 255, 200),
                                Size = 2f + (float)_rng.NextDouble() * 3f,
                            });
                        }
                        _hitstopTimer = 0.15f;
                        _trauma = MathF.Min(_trauma + 0.2f, 1f);
                    }
                    
                    // Raijin Wave: extra stagger
                    if (proj.FusionName == "RaijinWave" && !killed)
                    {
                        enemy.Stagger += 15f;
                    }

                    // Fossil Fragment: apply fracture
                    if (proj.FusionName == "FossilFrag" && !killed)
                    {
                        enemy.FractureStacks = MathHelper.Min(enemy.FractureStacks + 1, 5);
                    }

                    // Senbonzakura: blood jet spray on hit
                    if (proj.FusionName == "Senbonzakura")
                    {
                        Vector2 sprayDir = proj.Velocity;
                        if (sprayDir.LengthSquared() > 0) sprayDir.Normalize();
                        for (int bp = 0; bp < 8; bp++)
                        {
                            float spread = ((float)_rng.NextDouble() - 0.5f) * 0.4f;
                            float sprayAngle = MathF.Atan2(sprayDir.Y, sprayDir.X) + spread;
                            float spraySpd = 120f + (float)_rng.NextDouble() * 160f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position + sprayDir * (enemy.Size * 0.4f),
                                Velocity = new Vector2(MathF.Cos(sprayAngle), MathF.Sin(sprayAngle)) * spraySpd,
                                Life = 0.3f + (float)_rng.NextDouble() * 0.35f,
                                MaxLife = 0.65f,
                                Color = new Color(180 + _rng.Next(60), 0, 0),
                                Size = 2.5f + (float)_rng.NextDouble() * 3f,
                            });
                        }
                    }

                    // Sacred Fist: bone impact explosion + hitstop
                    if (proj.FusionName == "SacredFist")
                    {
                        _hitstopTimer = MathF.Max(_hitstopTimer, 0.12f);
                        _trauma = MathF.Min(_trauma + 0.25f, 1f);
                        // Bone shrapnel burst
                        Vector2 punchDir = proj.Velocity;
                        if (punchDir.LengthSquared() > 0) punchDir.Normalize();
                        for (int bp = 0; bp < 16; bp++)
                        {
                            float a = MathF.Atan2(punchDir.Y, punchDir.X) + ((float)_rng.NextDouble() - 0.5f) * 1.6f;
                            float spd = 150f + (float)_rng.NextDouble() * 250f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                Life = 0.25f + (float)_rng.NextDouble() * 0.25f,
                                MaxLife = 0.5f,
                                Color = _rng.NextDouble() > 0.6 ? new Color(240, 225, 195) : new Color(200, 180, 150),
                                Size = 2f + (float)_rng.NextDouble() * 4f,
                            });
                        }
                        // Impact shockwave ring
                        for (int bp = 0; bp < 12; bp++)
                        {
                            float a = bp / 12f * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 180f,
                                Life = 0.15f, MaxLife = 0.15f,
                                Color = new Color(255, 240, 200),
                                Size = 3f,
                            });
                        }
                        enemy.KnockbackVel = punchDir * 400f; // massive knockback
                    }

                    // ═══════════════ ESSENCE HIT EFFECTS ═══════════════
                    Vector2 hitDir = proj.Velocity;
                    if (hitDir.LengthSquared() > 0) hitDir.Normalize();
                    Essence hitEssence = _loadout.Essence;
                    
                    // Tier: 0=single slot (skip), 1=dual combo, 2=spell fusion
                    int comboTier = _currentFusion != null ? 2 : (_currentDualCombo != null ? 1 : 0);
                    if (comboTier > 0 && hitEssence != Essence.None)
                    {
                    float cMul = comboTier == 2 ? 2.5f : 1f; // particle count multiplier
                    float sMul = comboTier == 2 ? 1.6f : 1f; // size multiplier
                    float lMul = comboTier == 2 ? 1.4f : 1f; // lifetime multiplier
                    float vMul = comboTier == 2 ? 1.3f : 1f; // velocity multiplier
                    
                    switch (hitEssence)
                    {
                        case Essence.Cinder:
                            for (int ep = 0; ep < (int)(6 * cMul); ep++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * enemy.Size, ((float)_rng.NextDouble() - 0.5f) * enemy.Size),
                                    Velocity = new Vector2(MathF.Cos(a) * 30f * vMul, (-40f - (float)_rng.NextDouble() * 60f) * vMul),
                                    Life = (0.3f + (float)_rng.NextDouble() * 0.3f) * lMul, MaxLife = 0.6f * lMul,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(255, 160, 30) : new Color(255, 80, 10),
                                    Size = (3f + (float)_rng.NextDouble() * 3f) * sMul,
                                });
                            }
                            for (int ep = 0; ep < (int)(3 * cMul); ep++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, 0),
                                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f * vMul, (-20f - (float)_rng.NextDouble() * 15f) * vMul),
                                    Life = (0.5f + (float)_rng.NextDouble() * 0.4f) * lMul, MaxLife = 0.9f * lMul,
                                    Color = new Color(255, 220, 80),
                                    Size = (1.5f + (float)_rng.NextDouble()) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Dark:
                            for (int ep = 0; ep < (int)(5 * cMul); ep++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float spd = (30f + (float)_rng.NextDouble() * 50f) * vMul;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position,
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                    Life = (0.4f + (float)_rng.NextDouble() * 0.3f) * lMul, MaxLife = 0.7f * lMul,
                                    Color = _rng.NextDouble() > 0.4 ? new Color(80, 20, 120) : new Color(40, 0, 60),
                                    Size = (3f + (float)_rng.NextDouble() * 4f) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Bone:
                            for (int ep = 0; ep < (int)(5 * cMul); ep++)
                            {
                                float a = MathF.Atan2(hitDir.Y, hitDir.X) + ((float)_rng.NextDouble() - 0.5f) * 1.5f;
                                float spd = (80f + (float)_rng.NextDouble() * 100f) * vMul;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position,
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd + new Vector2(0, 30f),
                                    Life = (0.3f + (float)_rng.NextDouble() * 0.2f) * lMul, MaxLife = 0.5f * lMul,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(230, 220, 200) : new Color(200, 190, 170),
                                    Size = (2f + (float)_rng.NextDouble() * 2f) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Silk:
                            for (int ep = 0; ep < (int)(4 * cMul); ep++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position,
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (20f + (float)_rng.NextDouble() * 30f) * vMul,
                                    Life = (0.5f + (float)_rng.NextDouble() * 0.4f) * lMul, MaxLife = 0.9f * lMul,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(220, 200, 240) : new Color(255, 255, 255),
                                    Size = (1.5f + (float)_rng.NextDouble() * 2f) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Pulse:
                            for (int ep = 0; ep < (int)(6 * cMul); ep++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float spd = (100f + (float)_rng.NextDouble() * 120f) * vMul;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                    Life = (0.1f + (float)_rng.NextDouble() * 0.15f) * lMul, MaxLife = 0.25f * lMul,
                                    Color = _rng.NextDouble() > 0.3 ? new Color(255, 255, 100) : Color.White,
                                    Size = (1.5f + (float)_rng.NextDouble() * 1.5f) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Hollow:
                            for (int ep = 0; ep < (int)(5 * cMul); ep++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float dist = (15f + (float)_rng.NextDouble() * 20f) * sMul;
                                Vector2 start = enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist;
                                _particles.Add(new Particle
                                {
                                    Position = start,
                                    Velocity = (enemy.Position - start) * 3f * vMul,
                                    Life = (0.2f + (float)_rng.NextDouble() * 0.15f) * lMul, MaxLife = 0.35f * lMul,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(60, 20, 100) : new Color(30, 10, 60),
                                    Size = (2.5f + (float)_rng.NextDouble() * 3f) * sMul,
                                });
                            }
                            break;
                            
                        case Essence.Sap:
                            for (int ep = 0; ep < (int)(4 * cMul); ep++)
                            {
                                Vector2 toPlayer = _playerPos - enemy.Position;
                                if (toPlayer.LengthSquared() > 0) toPlayer.Normalize();
                                float spread = ((float)_rng.NextDouble() - 0.5f) * 0.8f;
                                float sa = MathF.Atan2(toPlayer.Y, toPlayer.X) + spread;
                                _particles.Add(new Particle
                                {
                                    Position = enemy.Position,
                                    Velocity = new Vector2(MathF.Cos(sa), MathF.Sin(sa)) * (60f + (float)_rng.NextDouble() * 40f) * vMul,
                                    Life = (0.4f + (float)_rng.NextDouble() * 0.3f) * lMul, MaxLife = 0.7f * lMul,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(80, 220, 50) : new Color(40, 180, 30),
                                    Size = (2f + (float)_rng.NextDouble() * 2f) * sMul,
                                });
                            }
                            break;
                    }
                    } // end comboTier > 0

                    // Hiten Mitsurugi: HEAVY hitstop + impact spectacle
                    if (proj.FusionName == "HitenSlash")
                    {
                        _hitstopTimer = 0.15f; // long freeze — sells the cut
                        // Big impact burst — white flash + lavender silk wisps
                        for (int sp = 0; sp < 16; sp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (120f + (float)_rng.NextDouble() * 100f),
                                Life = 0.15f + (float)_rng.NextDouble() * 0.1f,
                                MaxLife = 0.25f,
                                Color = _rng.NextDouble() > 0.3 ? Color.White : new Color(180, 140, 220),
                                Size = 2.5f + (float)_rng.NextDouble() * 3f,
                            });
                        }
                        _trauma = MathF.Min(_trauma + 0.25f, 1f); // extra shake on hit
                    }

                    // Nimue's Tear relic: siphon 8% of damage as HP
                    if (_hasNimueTear)
                        _playerHp = MathF.Min(_playerHp + dmg * 0.08f, PlayerMaxHp);

                    // Cinder explosion particles
                    if (proj.Params.EssenceType == Essence.Cinder)
                        SpawnExplosion(enemy.Position, new Color(255, 100, 30), 8);
                    // Pulse lightning flash
                    if (proj.Params.EssenceType == Essence.Pulse)
                        SpawnExplosion(enemy.Position, new Color(255, 240, 60), 4, 0.15f, 5f);
                    // Dark shadow burst
                    if (proj.Params.EssenceType == Essence.Dark)
                        SpawnExplosion(enemy.Position, new Color(120, 40, 160), 6, 0.25f, 4f);

                    // Damage number
                    _damageNumbers.Add(new DamageNumber
                    {
                        Position = enemy.Position + new Vector2(0, -enemy.Size / 2),
                        Amount = dmg,
                        Timer = 0.8f,
                        Color = new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B)
                    });

                    // Status effects
                    if (proj.Params.StatusChance > 0 && _rng.NextDouble() < proj.Params.StatusChance)
                    {
                        switch (proj.Params.EssenceType)
                        {
                            case Essence.Cinder: enemy.IgniteTimer = MathF.Max(enemy.IgniteTimer, proj.Params.StatusDuration); break;
                            case Essence.Silk: enemy.SlowTimer = MathF.Max(enemy.SlowTimer, proj.Params.StatusDuration); break;
                            case Essence.Pulse: enemy.StaggerTimer = MathF.Max(enemy.StaggerTimer, 0.5f); if (!enemy.IsBroken) enemy.Stagger += 15f; break;
                            case Essence.Dark: enemy.FearTimer = MathF.Max(enemy.FearTimer, proj.Params.StatusDuration); break;
                            case Essence.Hollow: enemy.SilenceTimer = MathF.Max(enemy.SilenceTimer, proj.Params.StatusDuration); break;
                            case Essence.Sap: enemy.LeechStack += 1f; break;
                            case Essence.Bone: enemy.TakeDamage(ApplyElementCounter(enemy, proj.Params.BaseDamage * 0.3f, Essence.Bone, showBark: false)); enemy.FractureStacks = 3; break;
                        }
                    }

                    // Stasis on hit: freeze enemies in radius
                    if (proj.Params.StasisRadius > 0)
                    {
                        for (int j = 0; j < _enemies.Count; j++)
                        {
                            if (!_enemies[j].Alive) continue;
                            if (Vector2.Distance(proj.Position, _enemies[j].Position) < proj.Params.StasisRadius)
                            {
                                _enemies[j].StasisTimer = MathF.Max(_enemies[j].StasisTimer, proj.Params.StasisDuration);
                            }
                        }
                        SpawnExplosion(proj.Position, new Color(200, 230, 255), 8, 0.3f, proj.Params.StasisRadius * 0.3f);
                    }

                    // Binding Lance: pin enemy with silk threads radiating outward
                    if (proj.FusionName == "BindingLance")
                    {
                        enemy.SlowTimer = MathF.Max(enemy.SlowTimer, 2.5f);
                        enemy.StaggerTimer = MathF.Max(enemy.StaggerTimer, 2.5f);
                        // Spawn silk thread tripwires radiating from enemy
                        int threadCount = 6;
                        for (int th = 0; th < threadCount; th++)
                        {
                            float angle = (MathF.PI * 2f / threadCount) * th + (float)_rng.NextDouble() * 0.3f;
                            float threadLen = 60f + (float)_rng.NextDouble() * 40f;
                            Vector2 threadEnd = enemy.Position + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * threadLen;
                            // Clamp to arena
                            threadEnd.X = MathHelper.Clamp(threadEnd.X, _arena.Left, _arena.Right);
                            threadEnd.Y = MathHelper.Clamp(threadEnd.Y, _arena.Top, _arena.Bottom);
                            float hue = (th * 60f + _totalTime * 30f) % 360f;
                            _tripwires.Add(new Tripwire
                            {
                                Start = enemy.Position,
                                End = threadEnd,
                                Life = 3f, MaxLife = 3f,
                                WireColor = HueToColor(hue),
                                HitsLeft = 2,
                                Damage = proj.Params.BaseDamage * 0.3f,
                                HitEnemies = new HashSet<int> { enemy.Id },
                            });
                        }
                        // Silk burst particles
                        for (int sp = 0; sp < 12; sp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 60f),
                                Life = 0.5f, MaxLife = 0.5f,
                                Color = new Color(200, 180, 220) * 0.8f,
                                Size = 2f + (float)_rng.NextDouble(),
                            });
                        }
                        _floatingTexts.Add(new FloatingText
                        {
                            Position = enemy.Position + new Vector2(-15, -20),
                            Text = "BOUND",
                            Color = new Color(200, 180, 220),
                            Life = 1f, MaxLife = 1f,
                        });
                    }

                    // Crystal Spiderweb: shatter into radial tripwires on hit
                    if (proj.FusionName == "CrystalSpiderweb")
                    {
                        int webStrands = 8;
                        for (int ws = 0; ws < webStrands; ws++)
                        {
                            float angle = (MathF.PI * 2f / webStrands) * ws;
                            float strandLen = 80f + (float)_rng.NextDouble() * 50f;
                            Vector2 strandEnd = proj.Position + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * strandLen;
                            strandEnd.X = MathHelper.Clamp(strandEnd.X, _arena.Left, _arena.Right);
                            strandEnd.Y = MathHelper.Clamp(strandEnd.Y, _arena.Top, _arena.Bottom);
                            float hue = (ws * 45f) % 360f;
                            _tripwires.Add(new Tripwire
                            {
                                Start = proj.Position,
                                End = strandEnd,
                                Life = 5f, MaxLife = 5f,
                                WireColor = HueToColor(hue),
                                HitsLeft = 3,
                                Damage = proj.Params.BaseDamage * 0.3f,
                                HitEnemies = new HashSet<int>(),
                            });
                        }
                        // Concentric ring tripwires connecting the radials
                        for (int ring = 1; ring <= 2; ring++)
                        {
                            float ringR = 35f * ring;
                            for (int ws = 0; ws < webStrands; ws++)
                            {
                                float a1 = (MathF.PI * 2f / webStrands) * ws;
                                float a2 = (MathF.PI * 2f / webStrands) * ((ws + 1) % webStrands);
                                Vector2 p1 = proj.Position + new Vector2(MathF.Cos(a1), MathF.Sin(a1)) * ringR;
                                Vector2 p2 = proj.Position + new Vector2(MathF.Cos(a2), MathF.Sin(a2)) * ringR;
                                float hue = ((ws + ring * 4) * 45f) % 360f;
                                _tripwires.Add(new Tripwire
                                {
                                    Start = p1, End = p2,
                                    Life = 5f, MaxLife = 5f,
                                    WireColor = HueToColor(hue),
                                    HitsLeft = 2,
                                    Damage = proj.Params.BaseDamage * 0.2f,
                                    HitEnemies = new HashSet<int>(),
                                });
                            }
                        }
                        // Crystal shatter particles
                        for (int sp = 0; sp < 20; sp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 60f + (float)_rng.NextDouble() * 100f;
                            _particles.Add(new Particle
                            {
                                Position = proj.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = _rng.NextDouble() > 0.5 ? new Color(220, 200, 240) : new Color(180, 160, 200),
                                Size = 2f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                        _trauma = MathF.Min(_trauma + 0.15f, 0.4f);
                    }

                    // Possess on kill
                    if (killed && proj.Params.Possesses)
                    {
                        Enemy nearest = null;
                        float nearDist = float.MaxValue;
                        for (int j = 0; j < _enemies.Count; j++)
                        {
                            if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                            float d = Vector2.Distance(enemy.Position, _enemies[j].Position);
                            if (d < nearDist) { nearDist = d; nearest = _enemies[j]; }
                        }
                        if (nearest != null)
                        {
                            nearest.Possessed = true;
                            nearest.PossessTimer = 3f;
                        }
                    }

                    // Samael's Embrace: possess on HIT, not just kill (dark nova mass-conversion)
                    if (!killed && proj.FusionName == "Samael's Embrace" && !enemy.Possessed)
                    {
                        enemy.Possessed = true;
                        enemy.PossessTimer = 2.5f; // shorter than normal since it's on-hit
                        SpawnExplosion(enemy.Position, new Color(120, 40, 160), 6, 0.2f, 5f);
                    }

                    // Mollificare: permanently pacify on hit — enemy stops attacking, can't die
                    if (proj.FusionName == "Mollificare" && !enemy.Pacified)
                    {
                        enemy.Pacified = true;
                        enemy.Hp = MathF.Max(enemy.Hp, 1f); // can't die from this hit
                        // Ripple burst on pacification
                        for (int ri = 0; ri < 20; ri++)
                        {
                            float angle2 = (MathF.PI * 2f / 20) * ri;
                            float speed2 = 40f + (float)_rng.NextDouble() * 30f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(angle2), MathF.Sin(angle2)) * speed2,
                                Life = 0.4f + (float)_rng.NextDouble() * 0.2f,
                                MaxLife = 0.6f,
                                Color = new Color(240, 235, 220),
                                Size = 2f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                        _floatingTexts.Add(new FloatingText
                        {
                            Position = enemy.Position + new Vector2(0, -20),
                            Text = "PACIFIED",
                            Color = new Color(240, 235, 220),
                            Life = 1.5f,
                            MaxLife = 1.5f,
                        });
                    }
                    // Un-pacify if hit by anything else
                    if (enemy.Pacified && proj.FusionName != "Mollificare")
                    {
                        enemy.Pacified = false;
                    }

                    // Hiten Mitsurugi: clean diagonal split kill
                    if (killed && proj.FusionName == "HitenSlash")
                    {
                        _hitstopTimer = MathF.Max(_hitstopTimer, 0.08f);
                        _trauma = MathF.Min(_trauma + 0.2f, 1f);
                        float slashAngle = (proj.SwingStartAngle + proj.SwingEndAngle) / 2f;
                        float perpAngle = slashAngle + MathF.PI / 2f;
                        Vector2 splitDir1 = new Vector2(MathF.Cos(perpAngle), MathF.Sin(perpAngle));
                        Vector2 splitDir2 = -splitDir1;
                        float halfSize = enemy.Size * 0.5f;
                        Vector2 slashDir = new Vector2(MathF.Cos(slashAngle), MathF.Sin(slashAngle));
                        // 3 chunks per half — clean geometric split
                        for (int h = 0; h < 3; h++)
                        {
                            float offset = (h - 1) * halfSize * 0.4f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position + slashDir * offset + splitDir1 * 2f,
                                Velocity = splitDir1 * (60f + h * 20f),
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = enemy.BaseColor,
                                Size = halfSize * 0.8f,
                            });
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position + slashDir * offset + splitDir2 * 2f,
                                Velocity = splitDir2 * (60f + h * 20f),
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = enemy.BaseColor,
                                Size = halfSize * 0.8f,
                            });
                        }
                        // Thin silk slash line
                        _particles.Add(new Particle
                        {
                            Position = enemy.Position - slashDir * enemy.Size,
                            Velocity = slashDir * 40f,
                            Life = 0.2f, MaxLife = 0.2f,
                            Color = new Color(220, 200, 255),
                            Size = 2f,
                        });
                    }

                    // Shadow Stitch: on first hit, start the chain-possess channel
                    if (proj.FusionName == "ShadowStitch" && !_shadowStitch.Active && enemy.Alive)
                    {
                        _shadowStitch = new ShadowStitchState
                        {
                            Active = true,
                            AnchorPos = _playerPos,
                            ChainedIds = new List<int> { enemy.Id },
                            SeekingTip = enemy.Position,
                            SeekSpeed = 200f,
                            Seeking = false,
                            SeekTargetId = -1,
                            MaxRange = 150f,
                        };
                        enemy.StaggerTimer = 10f;
                        enemy.Possessed = true;
                        enemy.PossessTimer = 10f;
                        
                        // Big connection burst
                        SpawnExplosion(enemy.Position, new Color(80, 30, 120), 15, 0.4f, 10f);
                        _hitstopTimer = 0.1f;
                        _trauma = MathF.Min(_trauma + 0.2f, 1f);
                    }

                    // Determine if projectile should die
                    bool shouldDie = !proj.Params.Piercing;
                    
                    // Track hit for piercing projectiles
                    if (proj.Params.Piercing)
                        proj.HitEnemies.Add(enemy.Id);

                    // Caliburn relic: pierce one enemy
                    if (shouldDie && proj.Params.PierceOne && proj.Params.PierceCount < 1)
                    {
                        proj.Params.PierceCount++;
                        shouldDie = false;
                    }

                    if (shouldDie)
                    {
                        proj.Alive = false;

                        // Katyusha: big rocket splits into 5 medium fireworks on hit
                        if (proj.FusionName == "Katyusha" && proj.Size > 6f)
                        {
                            deferred ??= new();
                            Color[] fireworkColors = { new Color(255, 60, 60), new Color(60, 200, 255), new Color(60, 255, 60), new Color(255, 220, 40), new Color(255, 120, 255) };
                            // Fire forward in a cone (binary tree — same general direction)
                            float parentAngle = MathF.Atan2(proj.Velocity.Y, proj.Velocity.X);
                            for (int f = 0; f < 5; f++)
                            {
                                float spread = MathHelper.ToRadians(50f); // 50° total cone
                                float angle = parentAngle + (f - 2) * spread / 4f + ((float)_rng.NextDouble() - 0.5f) * 0.2f;
                                var fragParms = proj.Params;
                                fragParms.Speed = 180f;
                                fragParms.Lifetime = 0.5f;
                                fragParms.BaseDamage *= 0.4f;
                                fragParms.Size = 4f;
                                fragParms.ShatterCount = 4;
                                var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 180f;
                                var frag = new Projectile(proj.Position, vel, fragParms) { Size = 4f, FusionName = "KatyushaMed" };
                                deferred.Add(frag);
                            }
                            // Big firework explosion — multi-color spark burst
                            _trauma = MathF.Min(_trauma + 0.2f, 1f);
                            for (int sp = 0; sp < 20; sp++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float spd = 60f + (float)_rng.NextDouble() * 120f;
                                _particles.Add(new Particle
                                {
                                    Position = proj.Position,
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                    Life = 0.3f + (float)_rng.NextDouble() * 0.4f,
                                    MaxLife = 0.7f,
                                    Color = fireworkColors[_rng.Next(fireworkColors.Length)],
                                    Size = 2f + (float)_rng.NextDouble() * 3f,
                                });
                            }
                        }
                        // Katyusha medium rockets: smaller firework burst on death (cascade stage 2)
                        else if (proj.FusionName == "KatyushaMed")
                        {
                            // Shatter handles the final small fragments
                            // Just add sparkle burst
                            Color[] fireworkColors = { new Color(255, 60, 60), new Color(60, 200, 255), new Color(60, 255, 60), new Color(255, 220, 40), new Color(255, 120, 255) };
                            for (int sp = 0; sp < 10; sp++)
                            {
                                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                float spd = 40f + (float)_rng.NextDouble() * 80f;
                                _particles.Add(new Particle
                                {
                                    Position = proj.Position,
                                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                                    Life = 0.2f + (float)_rng.NextDouble() * 0.3f,
                                    MaxLife = 0.5f,
                                    Color = fireworkColors[_rng.Next(fireworkColors.Length)],
                                    Size = 1.5f + (float)_rng.NextDouble() * 2f,
                                });
                            }
                        }

                        // Orbit + Bounce: detach from orbit and ricochet
                        if (proj.Params.OrbitSpeed > 0 && proj.Params.Bounces && proj.Params.MaxBounces > 0)
                        {
                            proj.Alive = true;
                            proj.Params.OrbitSpeed = 0;
                            proj.Params.OrbitRadius = 0;
                            Vector2 awayDir = proj.Position - enemy.Position;
                            if (awayDir.LengthSquared() > 0) awayDir.Normalize();
                            else awayDir = new Vector2(1, 0);
                            proj.Velocity = awayDir * 300f;
                            proj.Params.MaxBounces--;
                            proj.Params.IsStationary = false;
                            break;
                        }

                        // Bounce → ricochet to nearest other enemy
                        if (proj.Params.Bounces && proj.Params.MaxBounces > 0)
                        {
                            Enemy nearestEnemy = null;
                            float nearDist = 400f;
                            for (int j = 0; j < _enemies.Count; j++)
                            {
                                if (j == i || !_enemies[j].Alive) continue;
                                float d = Vector2.Distance(proj.Position, _enemies[j].Position);
                                if (d < nearDist) { nearDist = d; nearestEnemy = _enemies[j]; }
                            }
                            if (nearestEnemy != null)
                            {
                                var ricParms = proj.Params;
                                ricParms.MaxBounces--;
                                ricParms.BaseDamage *= 0.7f;
                                Vector2 ricDir = nearestEnemy.Position - proj.Position;
                                if (ricDir.LengthSquared() > 0) ricDir.Normalize();
                                deferred ??= new();
                                deferred.Add(new Projectile(proj.Position, ricDir * proj.Params.Speed * 0.8f, ricParms)
                                {
                                    Size = proj.Size * 0.8f
                                });
                                // Death's Scythe: bone shrapnel on bounce (actual damaging projectiles)
                                if (_currentFusion == "Death's Scythe")
                                {
                                    SpawnExplosion(proj.Position, new Color(220, 220, 210), 6, 0.3f, 6f);
                                    _trauma = MathF.Min(_trauma + 0.08f, 1f);
                                    // Spawn bone fragment projectiles
                                    deferred ??= new();
                                    var fragParms = proj.Params;
                                    fragParms.Returns = false;
                                    fragParms.MaxBounces = 0;
                                    fragParms.BaseDamage *= 0.3f;
                                    for (int b = 0; b < 5; b++)
                                    {
                                        float bAngle = (float)_rng.NextDouble() * MathF.PI * 2f;
                                        var bVel = new Vector2(MathF.Cos(bAngle), MathF.Sin(bAngle)) * 180f;
                                        var bone = new Projectile(proj.Position, bVel, fragParms);
                                        bone.Lifetime = 0.4f;
                                        bone.Size = 3f;
                                        deferred.Add(bone);
                                    }
                                }
                            }
                        }

                        // Chain → jump to nearest unhit enemy
                        if (proj.Params.MaxChainTargets > 0)
                        {
                            Enemy chainTarget = null;
                            float chainDist = 400f;
                            for (int j = 0; j < _enemies.Count; j++)
                            {
                                if (!_enemies[j].Alive) continue;
                                if (proj.HitEnemies != null && proj.HitEnemies.Contains(_enemies[j].Id)) continue;
                                float d = Vector2.Distance(proj.Position, _enemies[j].Position);
                                if (d < chainDist && HasLineOfSight(proj.Position, _enemies[j].Position))
                                { chainDist = d; chainTarget = _enemies[j]; }
                            }
                            if (chainTarget != null)
                            {
                                var chainParms = proj.Params;
                                chainParms.MaxChainTargets--;
                                chainParms.BaseDamage *= 0.85f;
                                Vector2 chainDir = chainTarget.Position - proj.Position;
                                if (chainDir.LengthSquared() > 0) chainDir.Normalize();
                                deferred ??= new();
                                var chainProj = new Projectile(proj.Position, chainDir * proj.Params.Speed, chainParms)
                                {
                                    Size = proj.Size,
                                    HomingTargetId = chainTarget.Id,
                                    HomingStrength = 4f, // gentle curve, not perfect tracking
                                };
                                // Carry over hit list so it doesn't re-hit same enemies
                                if (proj.HitEnemies != null)
                                    foreach (var id in proj.HitEnemies) chainProj.HitEnemies.Add(id);
                                if (proj.FusionName == "SerpentMercury")
                                {
                                    chainProj.FusionName = "SerpentMercury";
                                    // Poison linger at each chain point
                                    _lingerZones.Add(new LingerZone
                                    {
                                        Position = proj.Position,
                                        Radius = 20f,
                                        Life = 4f, MaxLife = 4f,
                                        Damage = proj.Params.BaseDamage * 0.3f,
                                        TickTimer = 0.3f,
                                        Color = new Color(50, 160, 50),
                                        EssenceType = Essence.Sap,
                                        FusionTag = "SerpentMercury",
                                        SlowFactor = 0.6f,
                                    });
                                }
                                chainProj.HitEnemies.Add(enemy.Id);
                                if (proj.FusionName != null && proj.FusionName != "SerpentMercury")
                                    chainProj.FusionName = proj.FusionName;
                                deferred.Add(chainProj);
                                // Visual: lightning arc line (particles between positions)
                                bool isIndra = _currentFusion == "Indra's Arrow";
                                bool isChronos = _currentFusion == "Chronos' Chain";
                                bool isZeusChain = _currentFusion == "Zeus in Chains";
                                int arcCount = isIndra ? 10 : (isChronos ? 8 : isZeusChain ? 12 : 4);
                                float arcLife = isIndra ? 0.5f : (isChronos ? 0.4f : isZeusChain ? 1.5f : 0.2f);
                                Vector2 step = (chainTarget.Position - proj.Position) / arcCount;
                                if (isZeusChain)
                                {
                                    // Zeus: chain-link tether — alternating horizontal/vertical oval chain links
                                    for (int p = 0; p < arcCount; p++)
                                    {
                                        float jitter = MathF.Sin(p * 2.3f) * 4f;
                                        Vector2 perpDir = new Vector2(-step.Y, step.X);
                                        if (perpDir.LengthSquared() > 0) perpDir.Normalize();
                                        _particles.Add(new Particle
                                        {
                                            Position = proj.Position + step * (p + 0.5f) + perpDir * jitter,
                                            Velocity = perpDir * (MathF.Sin(p * 1.7f) * 8f), // slight sway
                                            Life = arcLife,
                                            MaxLife = arcLife,
                                            Color = p % 2 == 0 ? new Color(180, 200, 240) : new Color(140, 180, 255),
                                            Size = p % 2 == 0 ? 4f : 3f, // alternating link sizes
                                        });
                                    }
                                    // Bright electric sparks along the chain
                                    for (int sp = 0; sp < 6; sp++)
                                    {
                                        float t = (float)_rng.NextDouble();
                                        _particles.Add(new Particle
                                        {
                                            Position = proj.Position + (chainTarget.Position - proj.Position) * t,
                                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                                            Life = 0.3f, MaxLife = 0.3f,
                                            Color = Color.White,
                                            Size = 1.5f,
                                        });
                                    }
                                }
                                else
                                {
                                    for (int p = 0; p < arcCount; p++)
                                    {
                                        float jitter = isIndra ? 15f : 10f;
                                        _particles.Add(new Particle
                                        {
                                            Position = proj.Position + step * p + new Vector2(((float)_rng.NextDouble() - 0.5f) * jitter, ((float)_rng.NextDouble() - 0.5f) * jitter),
                                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                                            Life = arcLife,
                                            MaxLife = arcLife,
                                            Color = isIndra ? new Color(255, 240, 60) : (isChronos ? new Color(160, 200, 230) : new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B)),
                                            Size = isIndra ? 3f : (isChronos ? 2.5f : 2f),
                                        });
                                    }
                                }
                                // Indra: bright flash at chain point
                                if (isIndra)
                                {
                                    SpawnExplosion(proj.Position, new Color(255, 240, 100), 6, 0.2f, 8f);
                                }
                                // Chronos: time-freeze flash at each chain point
                                if (isChronos)
                                {
                                    SpawnExplosion(proj.Position, new Color(160, 200, 230), 8, 0.3f, 10f);
                                }
                                // Zeus in Chains: electric cage linger + tether to previous chain target
                                if (isZeusChain)
                                {
                                    SpawnExplosion(proj.Position, new Color(140, 180, 255), 10, 0.3f, 12f);
                                    // Chain-link tether from player to first hit (only on first chain jump)
                                    if (proj.HitEnemies.Count <= 1)
                                    {
                                        Vector2 playerToHit = proj.Position - _playerPos;
                                        int linkCount = (int)(playerToHit.Length() / 8f);
                                        if (linkCount > 0)
                                        {
                                            Vector2 linkStep = playerToHit / linkCount;
                                            Vector2 linkPerp = new Vector2(-linkStep.Y, linkStep.X);
                                            if (linkPerp.LengthSquared() > 0) linkPerp.Normalize();
                                            for (int lk = 0; lk < linkCount; lk++)
                                            {
                                                float sway = MathF.Sin(lk * 2.3f) * 3f;
                                                _particles.Add(new Particle
                                                {
                                                    Position = _playerPos + linkStep * (lk + 0.5f) + linkPerp * sway,
                                                    Velocity = linkPerp * (MathF.Sin(lk * 1.7f) * 5f),
                                                    Life = 1.2f, MaxLife = 1.2f,
                                                    Color = lk % 2 == 0 ? new Color(180, 200, 240) : new Color(140, 180, 255),
                                                    Size = lk % 2 == 0 ? 4f : 3f,
                                                });
                                            }
                                        }
                                    }
                                    // Cage linger zone on the hit enemy
                                    _lingerZones.Add(new LingerZone
                                    {
                                        Position = chainTarget.Position,
                                        Radius = 22f,
                                        Life = 2.5f, MaxLife = 2.5f,
                                        Damage = proj.Params.BaseDamage * 0.2f,
                                        TickTimer = 0f,
                                        Color = new Color(140, 180, 255),
                                        EssenceType = Essence.Pulse,
                                        FusionTag = "ZeusCage",
                                    });
                                    // Tether to previous enemy in chain (the one we jumped FROM)
                                    // proj.Position is where we jumped from, find the enemy there
                                    int prevEnemyId = -1;
                                    float closestDist = 30f;
                                    for (int eidx = 0; eidx < _enemies.Count; eidx++)
                                    {
                                        if (!_enemies[eidx].Alive || _enemies[eidx].Id == enemy.Id) continue;
                                        float d = Vector2.Distance(_enemies[eidx].Position, proj.Position);
                                        if (d < closestDist) { closestDist = d; prevEnemyId = _enemies[eidx].Id; }
                                    }
                                    if (prevEnemyId >= 0)
                                    {
                                        _zeusTethers.Add(new ZeusTether
                                        {
                                            EnemyIdA = prevEnemyId,
                                            EnemyIdB = enemy.Id,
                                            Life = 2.5f, MaxLife = 2.5f,
                                            DamagePerTick = proj.Params.BaseDamage * 0.15f,
                                            TickTimer = 0f,
                                            ArcPhase = (float)_rng.NextDouble() * 100f,
                                        });
                                    }
                                }
                                // Arc Lightning dual combo: leave persistent damaging arc between chain points
                                if (_currentDualCombo == "Arc Lightning")
                                {
                                    // Spawn a line of tiny stationary damaging projectiles along the arc
                                    int arcSegs = 4;
                                    Vector2 arcStep = (chainTarget.Position - proj.Position) / arcSegs;
                                    for (int seg = 0; seg < arcSegs; seg++)
                                    {
                                        var arcParms = proj.Params;
                                        arcParms.IsStationary = true;
                                        arcParms.Speed = 0;
                                        arcParms.Lifetime = 0.5f;
                                        arcParms.BaseDamage *= 0.15f;
                                        arcParms.OrbitSpeed = 0;
                                        arcParms.OrbitRadius = 0;
                                        arcParms.Piercing = true;
                                        Vector2 segPos = proj.Position + arcStep * (seg + 0.5f) + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f);
                                        var arcProj = new Projectile(segPos, Vector2.Zero, arcParms);
                                        arcProj.Size = 2f;
                                        arcProj.FusionName = "ArcSegment";
                                        deferred.Add(arcProj);
                                    }
                                }
                            }
                        }

                        // Linger → spawn damage zone at impact
                        if (proj.Params.LingerDuration > 0)
                        {
                            bool isPillar = _currentFusion == "Pillars of Muspelheim";
                            _lingerZones.Add(new LingerZone
                            {
                                Position = proj.Position,
                                Radius = proj.Params.LingerRadius > 0 ? proj.Params.LingerRadius : 25f,
                                Life = isPillar ? proj.Params.LingerDuration * 1.5f : proj.Params.LingerDuration,
                                MaxLife = isPillar ? proj.Params.LingerDuration * 1.5f : proj.Params.LingerDuration,
                                Damage = proj.Params.BaseDamage * 0.3f,
                                TickTimer = 0f,
                                Color = new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B),
                                EssenceType = proj.Params.EssenceType,
                                IsPillar = isPillar,
                                PillarTimer = 0.2f,
                                FusionTag = isPillar ? null : proj.Params.EssenceType == Essence.Cinder ? "EmberPool" : proj.Params.EssenceType == Essence.Pulse ? "SparkPool" : null,
                            });
                        }

                        // Bloom → AoE explosion
                        if (proj.Params.BloomGrowRate > 0)
                        {
                            float finalRadius = proj.Size * proj.CurrentScale;
                            for (int j = 0; j < _enemies.Count; j++)
                            {
                                if (!_enemies[j].Alive || j == i) continue;
                                if (Vector2.Distance(proj.Position, _enemies[j].Position) < finalRadius + _enemies[j].Size)
                                {
                                    _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], proj.Params.BaseDamage * 0.5f, proj.Params.EssenceType));
                                    _damageNumbers.Add(new DamageNumber
                                    {
                                        Position = _enemies[j].Position + new Vector2(0, -_enemies[j].Size / 2),
                                        Amount = proj.Params.BaseDamage * 0.5f,
                                        Timer = 0.6f,
                                        Color = new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B)
                                    });
                                }
                            }
                            SpawnExplosion(proj.Position, new Color(proj.Params.Color.R, proj.Params.Color.G, proj.Params.Color.B), 10, 0.4f, finalRadius * 0.5f);
                        }

                        if (proj.Params.ShatterCount > 0)
                        {
                            deferred ??= new();
                            SpawnShatterDeferred(proj, deferred);
                        }
                        break;
                    }
                }
            }
        }
        if (deferred != null) _projectiles.AddRange(deferred);

        // Spawn enemies (not in test mode, only after picking up wand)
        if (!_testMode && _hasWand && _gameMode != GameMode.Awakening)
        {
            _waveBannerTimer -= dt;
            
            if (!_bossAlive)
            {
                _spawnTimer -= dt;
                if (_spawnTimer <= 0 && _enemies.Count < 20)
                {
                    SpawnEnemy();
                    _spawnTimer = MathF.Max(0.3f, _spawnInterval - _wave * 0.1f);
                }

                if (_killCount >= _waveKillTarget)
                {
                    // Spawn boss!
                    SpawnBoss();
                }
            }
            else
            {
                // Boss is alive — check if it died
                bool found = _enemyById.TryGetValue(_bossId, out var br) && br.Alive;
                if (!found)
                {
                    _bossAlive = false;
                    _bossId = -1;
                    _wave++;
                    _killCount = 0;
                    _waveKillTarget = 5 + _wave * 2;
                    _spawnInterval = MathF.Max(0.5f, _spawnInterval - 0.15f);
                    _waveBannerTimer = 2f;
                }
            }
        }

        // ═══ Firework Embers update ═══
        for (int i = _fireworkEmbers.Count - 1; i >= 0; i--)
        {
            var fe = _fireworkEmbers[i];
            fe.Timer -= dt;
            fe.Velocity.Y += 600f * dt; // gravity slows upward, then pulls down
            fe.Position += fe.Velocity * dt;
            // White-hot trail
            _particles.Add(new Particle
            {
                Position = fe.Position,
                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, 10f + (float)_rng.NextDouble() * 10f),
                Life = 0.15f, MaxLife = 0.15f,
                Color = Color.White,
                Size = 2f,
            });
            if (fe.Timer <= 0)
            {
                // EXPLODE into 8 fiery fragments
                for (int f = 0; f < 8; f++)
                {
                    float angle = f * MathF.PI * 2f / 8f + (float)_rng.NextDouble() * 0.3f;
                    float spd = 100f + (float)_rng.NextDouble() * 80f;
                    var parms = ProjectileParams.Resolve(_loadout);
                    parms.Speed = spd;
                    parms.BaseDamage = fe.Damage * 0.3f;
                    parms.Lifetime = 0.6f;
                    parms.Size = 3f;
                    parms.Gravity = 300f;
                    parms.Color = new EssenceColor(255, 140, 30);
                    parms.LingerDuration = 1.5f;
                    parms.LingerRadius = 12f;
                    parms.ShatterCount = 0;
                    var frag = new Projectile(fe.Position, new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * spd, parms);
                    frag.FusionName = "FireworkFrag";
                    frag.Size = 3f;
                    _projectiles.Add(frag);
                }
                // Big burst particles
                for (int p = 0; p < 20; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 60f + (float)_rng.NextDouble() * 120f;
                    Color c = _rng.NextDouble() < 0.3 ? new Color(255, 255, 200) : _rng.NextDouble() < 0.6 ? new Color(255, 200, 50) : new Color(255, 80, 10);
                    _particles.Add(new Particle
                    {
                        Position = fe.Position,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.6f,
                        Color = c,
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.1f, 1f);
                fe.Alive = false;
            }
            _fireworkEmbers[i] = fe;
            if (!fe.Alive) _fireworkEmbers.RemoveAt(i);
        }

        // ═══ Bone Stakes update ═══
        for (int i = _boneStakes.Count - 1; i >= 0; i--)
        {
            var stake = _boneStakes[i];
            stake.Life -= dt;
            if (stake.Life <= 0) { stake.Alive = false; }
            if (stake.Alive)
            {
                // Check enemy collision
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    if (Vector2.Distance(stake.Position, _enemies[j].Position) < 20f)
                    {
                        // Shatter the stake
                        stake.Alive = false;
                        // Apply 2 fracture stacks
                        var enemy = _enemies[j];
                        enemy.FractureStacks = Math.Min(enemy.FractureStacks + 2, 10);
                        _enemies[j] = enemy;
                        // Spray 5 bone fragments
                        for (int f = 0; f < 5; f++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 120f + (float)_rng.NextDouble() * 80f;
                            var parms = ProjectileParams.Resolve(_loadout);
                            parms.Speed = spd;
                            parms.BaseDamage = stake.Damage * 0.4f;
                            parms.Lifetime = 0.4f;
                            parms.Size = 3f;
                            parms.Color = new EssenceColor(220, 210, 190);
                            var frag = new Projectile(stake.Position, new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd, parms);
                            frag.Size = 3f;
                            _projectiles.Add(frag);
                        }
                        SpawnExplosion(stake.Position, new Color(220, 210, 190), 8, 0.3f, 8f);
                        _trauma = MathF.Min(_trauma + 0.05f, 1f);
                        break;
                    }
                }
                // Boss tail collision for bone stakes
                if (stake.Alive && _bossActive && _bossDeathTimer == 0 && _bossSegments != null)
                {
                    Vector2 tailPos = _bossSegments[_bossSegmentCount - 1];
                    if (Vector2.Distance(stake.Position, tailPos) < 20f)
                    {
                        stake.Alive = false;
                        _bossHp -= stake.Damage;
                        _bossHitFlash = 0.15f;
                        for (int f = 0; f < 5; f++)
                        {
                            float ba = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float bspd = 120f + (float)_rng.NextDouble() * 80f;
                            var bparms = ProjectileParams.Resolve(_loadout);
                            bparms.Speed = bspd;
                            bparms.BaseDamage = stake.Damage * 0.4f;
                            bparms.Lifetime = 0.4f;
                            bparms.Size = 3f;
                            bparms.Color = new EssenceColor(220, 210, 190);
                            var frag = new Projectile(stake.Position, new Vector2(MathF.Cos(ba), MathF.Sin(ba)) * bspd, bparms);
                            frag.Size = 3f;
                            _projectiles.Add(frag);
                        }
                        SpawnExplosion(stake.Position, new Color(220, 210, 190), 8, 0.3f, 8f);
                        _trauma = MathF.Min(_trauma + 0.05f, 1f);
                    }
                }
            }
            _boneStakes[i] = stake;
            if (!stake.Alive) _boneStakes.RemoveAt(i);
        }

        // Particles update
        const int MaxParticles = 2000;
        while (_particles.Count > MaxParticles)
            _particles.RemoveAt(0); // remove oldest
        for (int i = _particles.Count - 1; i >= 0; i--)
        {
            var pt = _particles[i];
            pt.Position += pt.Velocity * dt;
            pt.Life -= dt;
            _particles[i] = pt;
            if (pt.Life <= 0) _particles.RemoveAt(i);
        }

        // Burning trees — tick timers, spawn flame particles
        for (int i = _burningTrees.Count - 1; i >= 0; i--)
        {
            var bt = _burningTrees[i];
            bt.Timer -= dt;
            _burningTrees[i] = bt;
            if (bt.Timer <= 0) { _burningTrees.RemoveAt(i); continue; }
            // Flame particles
            if (_rng.NextDouble() < 0.5)
            {
                _particles.Add(new Particle
                {
                    Position = bt.Pos + new Vector2((float)(_rng.NextDouble() - 0.5) * 16f, (float)(_rng.NextDouble() - 0.5) * 8f),
                    Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 10f, -20f - (float)_rng.NextDouble() * 30f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                    MaxLife = 0.6f,
                    Color = Color.Lerp(new Color(255, 200, 40), new Color(255, 60, 10), (float)_rng.NextDouble()),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f
                });
            }
        }

        // Zeus tethers update
        for (int i = _zeusTethers.Count - 1; i >= 0; i--)
        {
            var t = _zeusTethers[i];
            t.Life -= dt;
            if (t.Life <= 0) { _zeusTethers.RemoveAt(i); continue; }
            t.TickTimer -= dt;
            if (t.TickTimer <= 0)
            {
                t.TickTimer = 0.4f; // damage tick rate
                // Damage both linked enemies
                for (int ei = 0; ei < _enemies.Count; ei++)
                {
                    if (_enemies[ei].Alive && (_enemies[ei].Id == t.EnemyIdA || _enemies[ei].Id == t.EnemyIdB))
                    {
                        var e = _enemies[ei];
                        e.Hp -= t.DamagePerTick;
                        e.HitFlash = 0.1f;
                        _enemies[ei] = e;
                    }
                }
            }
            _zeusTethers[i] = t;
        }

        // Conductor mechanic: when a tethered enemy takes damage, arc to all linked enemies
        // (handled via the tether tick above — continuous damage while bound)

        // Linger zones update
        for (int i = _lingerZones.Count - 1; i >= 0; i--)
        {
            var z = _lingerZones[i];
            z.Life -= dt;
            
            // Growing zones (Creeping Moss)
            if (z.GrowRate > 0 && z.Radius < z.MaxRadius)
                z.Radius = MathF.Min(z.Radius + z.GrowRate * dt, z.MaxRadius);
            
            z.TickTimer -= dt;
            if (z.TickTimer <= 0)
            {
                z.TickTimer = 0.3f;
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    if (_enemies[j].Possessed) continue; // don't hurt our own minions
                    if (Vector2.Distance(z.Position, _enemies[j].Position) < z.Radius + _enemies[j].Size / 2f)
                    {
                        float zDmg = ApplyElementCounter(_enemies[j], z.Damage, z.EssenceType, showBark: false);
                        _enemies[j].TakeDamage(zDmg);
                        _damageNumbers.Add(new DamageNumber
                        {
                            Position = _enemies[j].Position + new Vector2((_rng.Next(-8, 8)), -_enemies[j].Size / 2),
                            Amount = z.Damage,
                            Timer = 0.5f,
                            Color = z.Color
                        });
                        // Slow enemies in zones with SlowFactor
                        if (z.SlowFactor > 0)
                            _enemies[j].SlowTimer = MathF.Max(_enemies[j].SlowTimer, 0.5f);
                    }
                }
            }
            _lingerZones[i] = z;
            if (z.Life <= 0) _lingerZones.RemoveAt(i);
        }

        // Pillar eruptions for Pillars of Muspelheim
        for (int i = 0; i < _lingerZones.Count; i++)
        {
            var z = _lingerZones[i];
            if (!z.IsPillar) continue;
            z.PillarTimer -= dt;
            if (z.PillarTimer <= 0)
            {
                z.PillarTimer = 0.8f + (float)_rng.NextDouble() * 0.4f; // erupt every 0.8-1.2s
                // Tall fire eruption — layered particles for flame column look
                // Core column: fast, bright, narrow
                for (int p = 0; p < 10; p++)
                {
                    float xSpread = ((float)_rng.NextDouble() - 0.5f) * z.Radius * 0.6f;
                    float life = 0.3f + (float)_rng.NextDouble() * 0.3f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(xSpread, 0),
                        Velocity = new Vector2(
                            ((float)_rng.NextDouble() - 0.5f) * 20f,
                            -(350f + (float)_rng.NextDouble() * 200f)),
                        Life = life, MaxLife = life,
                        Color = _rng.NextDouble() < 0.3 ? new Color(255, 255, 220) : new Color(255, 220, 60),
                        Size = 3f + (float)_rng.NextDouble() * 3f,
                    });
                }
                // Mid flames: wider, orange
                for (int p = 0; p < 10; p++)
                {
                    float xSpread = ((float)_rng.NextDouble() - 0.5f) * z.Radius * 1.5f;
                    float life = 0.4f + (float)_rng.NextDouble() * 0.4f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(xSpread, 0),
                        Velocity = new Vector2(
                            ((float)_rng.NextDouble() - 0.5f) * 50f,
                            -(200f + (float)_rng.NextDouble() * 200f)),
                        Life = life, MaxLife = life,
                        Color = _rng.NextDouble() < 0.5 ? new Color(255, 140, 30) : new Color(255, 80, 15),
                        Size = 4f + (float)_rng.NextDouble() * 4f,
                    });
                }
                // Outer embers: slow, red, scattered wide
                for (int p = 0; p < 8; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 40f + (float)_rng.NextDouble() * 80f;
                    float life = 0.5f + (float)_rng.NextDouble() * 0.5f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * z.Radius, 0),
                        Velocity = new Vector2(MathF.Cos(angle) * spd, -80f - (float)_rng.NextDouble() * 120f),
                        Life = life, MaxLife = life,
                        Color = _rng.NextDouble() < 0.5 ? new Color(200, 40, 10) : new Color(150, 30, 5),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                // Ground glow ring at base
                for (int p = 0; p < 6; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * z.Radius,
                        Velocity = new Vector2(MathF.Cos(angle) * 15f, MathF.Sin(angle) * 15f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(255, 150, 30),
                        Size = 4f,
                    });
                }
                // AoE damage at eruption point
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    if (Vector2.Distance(z.Position, _enemies[j].Position) < z.Radius * 1.5f)
                    {
                        float eDmg = ApplyElementCounter(_enemies[j], z.Damage * 2f, z.EssenceType);
                        _enemies[j].TakeDamage(eDmg);
                        _enemies[j].IgniteTimer = MathF.Max(_enemies[j].IgniteTimer, 2f);
                        _damageNumbers.Add(new DamageNumber
                        {
                            Position = _enemies[j].Position + new Vector2(_rng.Next(-8, 8), -_enemies[j].Size),
                            Amount = z.Damage * 2f,
                            Timer = 0.8f,
                            Color = new Color(255, 200, 50)
                        });
                    }
                }
                _trauma = MathF.Min(_trauma + 0.15f, 1f); // bigger shake per eruption
            }
            // Ambient smolder between eruptions
            if (_rng.NextDouble() < 0.3)
            {
                float life = 0.2f + (float)_rng.NextDouble() * 0.3f;
                _particles.Add(new Particle
                {
                    Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * z.Radius, 0),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -30f - (float)_rng.NextDouble() * 40f),
                    Life = life, MaxLife = life,
                    Color = _rng.NextDouble() < 0.5 ? new Color(255, 100, 20) : new Color(200, 50, 10),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f,
                });
            }
            _lingerZones[i] = z;
        }

        // Fusion flash timer
        if (_fusionFlashTimer > 0) _fusionFlashTimer -= dt;
        if (_comboDiscoveryTimer > 0) _comboDiscoveryTimer -= dt;

        // Yggdrasil's Root: vine whip attacks + healing aura
        // + Tesla Coil, Hell/Heaven Portals, Medusa's Garden
        for (int i = 0; i < _lingerZones.Count; i++)
        {
            var z = _lingerZones[i];
            if (z.FusionTag == null) continue; // only process tagged zones

            // ═══ Abhiseka: hallowed ground — damages enemies on tick + heals player ═══
            if (z.FusionTag == "Abhiseka")
            {
                z.TickTimer -= dt;
                if (z.TickTimer <= 0)
                {
                    z.TickTimer = 0.5f;
                    for (int ei = 0; ei < _enemies.Count; ei++)
                    {
                        var e = _enemies[ei];
                        if (e.Hp <= 0) continue;
                        float dist = Vector2.Distance(e.Position, z.Position);
                        if (dist < z.Radius)
                        {
                            e.Hp -= z.Damage;
                            ApplyElementCounter(e, z.Damage, Essence.Hollow, true);
                            _enemies[ei] = e;
                        }
                    }
                    // Heal player inside zone
                    if (Vector2.Distance(_playerPos, z.Position) < z.Radius)
                    {
                        _playerHp = MathF.Min(_playerHp + 2f, PlayerMaxHp);
                    }
                }
                // White fire ascending particles
                if (_rng.NextDouble() < 0.4)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float d = (float)_rng.NextDouble() * z.Radius * 0.8f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * d,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -40f - (float)_rng.NextDouble() * 30f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 255, 240) : new Color(255, 220, 150),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                _lingerZones[i] = z;
                continue;
            }

            // ═══ Sambhogakaya: silence enemies inside + tick damage ═══
            if (z.FusionTag == "Sambhogakaya")
            {
                // Zone follows player every frame
                z.Position = _playerPos;
                z.TickTimer -= dt;
                if (z.TickTimer <= 0)
                {
                    z.TickTimer = 0.4f;
                    for (int ei = 0; ei < _enemies.Count; ei++)
                    {
                        var e = _enemies[ei];
                        if (e.Hp <= 0) continue;
                        float dist = Vector2.Distance(e.Position, z.Position);
                        if (dist < z.Radius)
                        {
                            e.Hp -= z.Damage;
                            e.SilenceTimer = MathF.Max(e.SilenceTimer, 1f);
                            ApplyElementCounter(e, z.Damage, Essence.Hollow, true);
                            _enemies[ei] = e;
                        }
                    }
                }
                _lingerZones[i] = z;
                continue;
            }

            // ═══ Bonfire: heavy flame particles ═══
            if (z.FusionTag == "Bonfire")
            {
                int particleCount = 4 + _rng.Next(3);
                for (int p = 0; p < particleCount; p++)
                {
                    float ox = ((float)_rng.NextDouble() - 0.5f) * z.Radius * 2f;
                    float oy = ((float)_rng.NextDouble() - 0.5f) * z.Radius;
                    double roll = _rng.NextDouble();
                    if (roll < 0.4)
                    {
                        // Ground embers
                        _particles.Add(new Particle { Position = z.Position + new Vector2(ox, oy), Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -5f), Life = 0.2f, MaxLife = 0.2f, Color = _rng.NextDouble() > 0.5 ? new Color(255, 100, 20) : new Color(255, 60, 10), Size = 1.5f });
                    }
                    else if (roll < 0.75)
                    {
                        // Mid flames
                        _particles.Add(new Particle { Position = z.Position + new Vector2(ox * 0.5f, 0), Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -40f - (float)_rng.NextDouble() * 40f), Life = 0.3f, MaxLife = 0.3f, Color = _rng.NextDouble() > 0.5 ? new Color(255, 200, 50) : new Color(255, 160, 30), Size = 2f + (float)_rng.NextDouble() });
                    }
                    else
                    {
                        // Rising sparks
                        _particles.Add(new Particle { Position = z.Position + new Vector2(ox * 0.3f, 0), Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, -100f - (float)_rng.NextDouble() * 50f), Life = 0.5f, MaxLife = 0.5f, Color = _rng.NextDouble() > 0.5 ? Color.White : new Color(255, 255, 150), Size = 1f });
                    }
                }
                _lingerZones[i] = z;
                continue;
            }

            // ═══ Storm Giant's Ward: zap enemies ═══
            if (z.FusionTag == "StormWard")
            {
                z.PillarTimer -= dt;
                if (z.PillarTimer <= 0)
                {
                    z.PillarTimer = 0.4f;
                    // Find nearest enemy within radius
                    Enemy zapTarget = null;
                    float bestD = z.Radius;
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive) continue;
                        float d = Vector2.Distance(z.Position, _enemies[e].Position);
                        if (d < bestD) { bestD = d; zapTarget = _enemies[e]; }
                    }
                    if (zapTarget != null)
                    {
                        float zapDmg = ApplyElementCounter(zapTarget, 3f, z.EssenceType);
                        zapTarget.TakeDamage(zapDmg);
                        var zt = zapTarget;
                        zt.Stagger += 8f;
                        // Find enemy index to write back stagger
                        for (int e = 0; e < _enemies.Count; e++)
                        {
                            if (_enemies[e].Id == zapTarget.Id) { _enemies[e] = zt; break; }
                        }
                        _damageNumbers.Add(new DamageNumber { Position = zapTarget.Position + new Vector2(0, -zapTarget.Size / 2), Amount = zapDmg, Timer = 0.5f, Color = new Color(100, 180, 255) });
                        SpawnExplosion(z.Position + new Vector2(0, -12f), new Color(150, 200, 255), 4, 0.15f, 3f);
                        SpawnExplosion(zapTarget.Position, new Color(150, 200, 255), 4, 0.15f, 3f);

                        // Chain to 1 additional enemy within 60px
                        Enemy chainTarget = null;
                        float chainD = 60f;
                        for (int e = 0; e < _enemies.Count; e++)
                        {
                            if (!_enemies[e].Alive || _enemies[e].Id == zapTarget.Id) continue;
                            float d = Vector2.Distance(zapTarget.Position, _enemies[e].Position);
                            if (d < chainD) { chainD = d; chainTarget = _enemies[e]; }
                        }
                        if (chainTarget != null)
                        {
                            chainTarget.TakeDamage(ApplyElementCounter(chainTarget, zapDmg * 0.5f, z.EssenceType, showBark: false));
                            SpawnExplosion(chainTarget.Position, new Color(150, 200, 255), 3, 0.1f, 2f);
                        }
                    }
                }
                _lingerZones[i] = z;
                continue;
            }

            // ═══ Bone Pit: spawn bone spikes ═══
            if (z.FusionTag == "BonePit")
            {
                z.PillarTimer -= dt;
                if (z.PillarTimer <= 0)
                {
                    z.PillarTimer = 0.6f;
                    float spikeAngle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spikeDist = (float)_rng.NextDouble() * z.Radius;
                    Vector2 spikePos = z.Position + new Vector2(MathF.Cos(spikeAngle), MathF.Sin(spikeAngle)) * spikeDist;
                    _boneStakes.Add(new BoneStake
                    {
                        Position = spikePos,
                        Angle = ((float)_rng.NextDouble() - 0.5f) * 0.5f,
                        Life = z.Life, // persists for zone's remaining life
                        MaxLife = z.Life,
                        Damage = z.Damage * 2f,
                        Alive = true,
                    });
                    _trauma = MathF.Min(_trauma + 0.02f, 0.3f);
                    // Bone dust particles
                    for (int p = 0; p < 4; p++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = spikePos,
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -20f - (float)_rng.NextDouble() * 20f),
                            Life = 0.2f, MaxLife = 0.2f,
                            Color = new Color(200, 190, 160),
                            Size = 1.5f,
                        });
                    }
                }
                _lingerZones[i] = z;
                continue;
            }

            if (z.FusionTag == "Yggdrasil")
            {
            z.VineTimer -= dt;
            if (z.VineTimer <= 0)
            {
                z.VineTimer = 0.6f; // vine lash every 0.6s
                // Fire 4 vine whip projectiles outward toward nearest enemies
                var parms = ProjectileParams.Resolve(_loadout);
                parms.BaseDamage = z.Damage * 1.5f;
                parms.Piercing = true;
                parms.Lifetime = 0.4f;
                int vineCount = 4;
                for (int v = 0; v < vineCount; v++)
                {
                    // Find nearest enemy or fire in spread pattern
                    float angle;
                    Enemy target = null;
                    float bestD = 200f;
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                        float d = Vector2.Distance(z.Position, _enemies[j].Position);
                        if (d < bestD) { bestD = d; target = _enemies[j]; }
                    }
                    if (target != null)
                    {
                        Vector2 toE = target.Position - z.Position;
                        angle = MathF.Atan2(toE.Y, toE.X) + (v - 1.5f) * 0.4f;
                    }
                    else
                    {
                        angle = (MathF.PI * 2f / vineCount) * v + z.Life * 2f; // spinning pattern
                    }
                    var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 180f;
                    var vine = new Projectile(z.Position, vel, parms);
                    vine.Size = 7f;
                    vine.Lifetime = 0.6f;
                    vine.FusionName = "Yggdrasil";
                    _projectiles.Add(vine);
                }
                // Vine lash particles
                for (int p = 0; p < 8; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 60f),
                        Life = 0.2f + (float)_rng.NextDouble() * 0.2f,
                        MaxLife = 0.4f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(60, 180, 60) : new Color(120, 200, 40),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            // Healing aura: heal player if within range
            if (Vector2.Distance(z.Position, _playerPos) < z.Radius * 3f)
            {
                _playerHp = MathF.Min(_playerHp + 2f * dt, PlayerMaxHp);
            }
            }
            else if (z.FusionTag == "Tesla")
            {
                // Nikola's Coil: periodic chain lightning to nearest enemy
                z.VineTimer -= dt;
                if (z.VineTimer <= 0)
                {
                    z.VineTimer = 0.5f; // zap every 0.5s
                    Enemy nearest = null;
                    float bestD = 180f; // zap range
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                        float d = Vector2.Distance(z.Position, _enemies[j].Position);
                        if (d < bestD) { bestD = d; nearest = _enemies[j]; }
                    }
                    if (nearest != null)
                    {
                        // Damage + stasis
                        nearest.TakeDamage(ApplyElementCounter(nearest, z.Damage, z.EssenceType));
                        nearest.StasisTimer = MathF.Max(nearest.StasisTimer, 0.3f);
                        // Lightning arc particles between coil and target
                        Vector2 step = (nearest.Position - z.Position) / 6f;
                        for (int p = 0; p < 6; p++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = z.Position + step * p + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                                Life = 0.15f, MaxLife = 0.15f,
                                Color = _rng.NextDouble() > 0.5 ? new Color(255, 240, 60) : new Color(200, 200, 255),
                                Size = 2f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                        SpawnExplosion(nearest.Position, new Color(255, 240, 60), 4, 0.1f, 5f);
                    }
                    // Coil ambient spark
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -8f - (float)_rng.NextDouble() * 12f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -20f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = new Color(255, 240, 60),
                        Size = 1f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            else if (z.FusionTag == "HellPortal")
            {
                // Fire portal: ambient fire particles rising from portal
                z.VineTimer -= dt;
                if (z.VineTimer <= 0)
                {
                    z.VineTimer = 0.3f;
                    for (int p = 0; p < 3; p++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * z.Radius * 2f, ((float)_rng.NextDouble() - 0.5f) * z.Radius),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -40f - (float)_rng.NextDouble() * 40f),
                            Life = 0.3f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.6f,
                            Color = _rng.NextDouble() > 0.5 ? new Color(255, 80, 20) : new Color(255, 40, 10),
                            Size = 2f + (float)_rng.NextDouble() * 3f,
                        });
                    }
                }
            }
            else if (z.FusionTag == "HeavenPortal")
            {
                // Holy portal: periodically fire homing bolts at enemies
                z.VineTimer -= dt;
                if (z.VineTimer <= 0)
                {
                    z.VineTimer = 0.8f; // cherub fires every 0.8s
                    Enemy nearest = null;
                    float bestD = 250f;
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                        float d = Vector2.Distance(z.Position, _enemies[j].Position);
                        if (d < bestD) { bestD = d; nearest = _enemies[j]; }
                    }
                    if (nearest != null)
                    {
                        var lp = ProjectileParams.Resolve(_loadout);
                        lp.BaseDamage = z.Damage * 2f;
                        lp.Speed = 200f;
                        lp.Lifetime = 1.2f;
                        lp.Piercing = true;
                        Vector2 toE = nearest.Position - z.Position;
                        if (toE.LengthSquared() > 0) toE.Normalize();
                        var bolt = new Projectile(z.Position + new Vector2(0, -10f), toE * 200f, lp);
                        bolt.Size = 4f;
                        bolt.FusionName = "HeavenBolt";
                        _projectiles.Add(bolt);
                    }
                    // Holy glow
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(0, -8f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -30f),
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(240, 245, 255),
                        Size = 3f,
                    });
                }
            }
            else if (z.FusionTag == "Medusa")
            {
                // Petrification zone: enemies inside get long stasis
                z.VineTimer -= dt;
                if (z.VineTimer <= 0)
                {
                    z.VineTimer = 0.5f;
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                        if (Vector2.Distance(z.Position, _enemies[j].Position) < z.Radius + _enemies[j].Size / 2f)
                        {
                            _enemies[j].StasisTimer = MathF.Max(_enemies[j].StasisTimer, 2.5f); // long petrification
                            // Stone particles on enemy
                            _particles.Add(new Particle
                            {
                                Position = _enemies[j].Position,
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -15f),
                                Life = 0.3f, MaxLife = 0.3f,
                                Color = new Color(160, 170, 150),
                                Size = 2f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                    }
                }
                // When zone expires, deal burst bone damage to petrified enemies
                if (z.Life <= dt && z.Life > 0)
                {
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive) continue;
                        if (Vector2.Distance(z.Position, _enemies[j].Position) < z.Radius * 1.5f)
                        {
                            _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], z.Damage * 3f, z.EssenceType)); // stone shatter burst
                            SpawnExplosion(_enemies[j].Position, new Color(180, 180, 170), 6, 0.3f, 8f);
                        }
                    }
                    SpawnExplosion(z.Position, new Color(160, 170, 150), 12, 0.4f, z.Radius * 0.5f);
                    _trauma = MathF.Min(_trauma + 0.12f, 1f);
                }
            }
            else if (z.FusionTag == "CreepingMoss")
            {
                // Ambient moss spore particles — rate increases with radius
                float sporeChance = 0.3f + (z.Radius / z.MaxRadius) * 0.5f;
                if (_rng.NextDouble() < sporeChance)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float dist = (float)_rng.NextDouble() * z.Radius;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(MathF.Cos(angle) * dist, MathF.Sin(angle) * dist),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -8f - (float)_rng.NextDouble() * 12f),
                        Life = 0.6f + (float)_rng.NextDouble() * 0.6f,
                        MaxLife = 1.2f,
                        Color = _rng.NextDouble() > 0.4 ? new Color(40, 130, 35) : new Color(70, 160, 50),
                        Size = 1.5f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            else if (z.FusionTag == "Earthquake")
            {
                // Cage: enemies touching the spike get pushed back toward cage center + take damage
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    float d = Vector2.Distance(z.Position, _enemies[j].Position);
                    if (d < z.Radius + _enemies[j].Size / 2f)
                    {
                        // Push toward center of the cage (player position when cast)
                        // Spike zones form a ring — push inward keeps enemies trapped
                        Vector2 pushDir = z.Position - _enemies[j].Position;
                        if (pushDir.LengthSquared() > 0) pushDir.Normalize();
                        _enemies[j].KnockbackVel = -pushDir * 150f; // push AWAY from spike
                        _enemies[j].StaggerTimer = MathF.Max(_enemies[j].StaggerTimer, 0.2f);
                        // Bone impact particles
                        for (int p = 0; p < 3; p++)
                        {
                            _particles.Add(new Particle
                            {
                                Position = _enemies[j].Position,
                                Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(200, 190, 150),
                                Size = 2f,
                            });
                        }
                    }
                }
            }
            else if (z.FusionTag == "GraveCall")
            {
                // Skeletal hands erupt when enemies get near
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive || _enemies[j].ShriekerTimer > 0) continue;
                    float d = Vector2.Distance(z.Position, _enemies[j].Position);
                    if (d < z.Radius + _enemies[j].Size / 2f)
                    {
                        // Grab: root enemy in place + damage
                        _enemies[j].StasisTimer = MathF.Max(_enemies[j].StasisTimer, 0.8f);
                        _enemies[j].StaggerTimer = MathF.Max(_enemies[j].StaggerTimer, 0.3f);
                        // Hand particles erupting from ground
                        if (_rng.NextDouble() < 0.3)
                        {
                            for (int p = 0; p < 4; p++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = _enemies[j].Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, 5f),
                                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -30f - (float)_rng.NextDouble() * 20f),
                                    Life = 0.3f, MaxLife = 0.3f,
                                    Color = new Color(200, 190, 160),
                                    Size = 2f + (float)_rng.NextDouble() * 2f,
                                });
                            }
                        }
                        // Check if this kills the enemy → spawn skeleton
                        if (_enemies[j].Hp <= z.Damage && _enemies[j].Alive)
                        {
                            Vector2 skelePos = _enemies[j].Position;
                            // Spawn skeleton minion (possessed enemy that fights for you)
                            var skeleton = new Enemy(skelePos, 30f);
                            skeleton.Size = 10f;
                            skeleton.Speed = 60f;
                            skeleton.BaseColor = new Color(200, 190, 160);
                            skeleton.Possessed = true;
                            skeleton.PossessTimer = 6f; // fights for 6 seconds
                            skeleton.FusionTag = "Skeleton";
                            skeleton.SpawnTimer = 0.5f;
                            skeleton.SpawnDuration = 0.5f;
                            _enemies.Add(skeleton);
                            _enemyById[skeleton.Id] = skeleton;
                            // Crawl-out particles
                            for (int p = 0; p < 10; p++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = skelePos,
                                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -20f - (float)_rng.NextDouble() * 30f),
                                    Life = 0.5f, MaxLife = 0.5f,
                                    Color = _rng.NextDouble() > 0.5 ? new Color(180, 170, 140) : new Color(100, 80, 50),
                                    Size = 2f + (float)_rng.NextDouble() * 3f,
                                });
                            }
                            _trauma = MathF.Min(_trauma + 0.15f, 1f);
                        }
                    }
                }
                // Ambient grave particles — wisps of bone dust rising
                if (_rng.NextDouble() < 0.2)
                {
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * z.Radius, ((float)_rng.NextDouble() - 0.5f) * z.Radius),
                        Velocity = new Vector2(0, -10f - (float)_rng.NextDouble() * 10f),
                        Life = 0.8f, MaxLife = 0.8f,
                        Color = new Color(160, 140, 110) * 0.5f,
                        Size = 1.5f,
                    });
                }
            }
            else if (z.FusionTag == "ThunderStorm")
            {
                z.PillarTimer -= dt;
                if (z.PillarTimer <= 0)
                {
                    z.PillarTimer = 0.5f;
                    // Lightning strike at random position in zone
                    float strikeX = z.Position.X + ((float)_rng.NextDouble() - 0.5f) * z.Radius * 2f;
                    Vector2 strikePos = new Vector2(strikeX, z.Position.Y);
                    // Flash line particles (vertical lightning bolt)
                    for (int lp = 0; lp < 6; lp++)
                    {
                        float yOff = -30f + lp * 8f;
                        _particles.Add(new Particle
                        {
                            Position = new Vector2(strikeX + ((float)_rng.NextDouble() - 0.5f) * 3f, z.Position.Y + yOff),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, 0),
                            Life = 0.12f, MaxLife = 0.12f,
                            Color = _rng.NextDouble() > 0.3 ? Color.White : new Color(255, 255, 150),
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                    // Spark burst at impact
                    for (int sp = 0; sp < 5; sp++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = strikePos,
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                            Life = 0.2f, MaxLife = 0.2f,
                            Color = new Color(255, 255, 180),
                            Size = 1.5f,
                        });
                    }
                    // Damage enemies near strike
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive) continue;
                        if (Vector2.Distance(strikePos, _enemies[j].Position) < 15f + _enemies[j].Size / 2f)
                        {
                            _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], z.Damage * 2f, z.EssenceType));
                            _enemies[j].Stagger += 10f;
                        }
                    }
                }
                _lingerZones[i] = z;
            }
            else if (z.FusionTag == "Graveyard")
            {
                // Pull enemies toward center
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive) continue;
                    float d = Vector2.Distance(z.Position, _enemies[j].Position);
                    if (d < z.Radius + _enemies[j].Size / 2f)
                    {
                        Vector2 toCenter = z.Position - _enemies[j].Position;
                        if (toCenter.LengthSquared() > 1f)
                        {
                            toCenter.Normalize();
                            _enemies[j].Position += toCenter * 30f * dt;
                        }
                        // Enemies near center take 3× damage + stun
                        if (d < 10f)
                        {
                            _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], z.Damage * 3f, z.EssenceType));
                            _enemies[j].StasisTimer = MathF.Max(_enemies[j].StasisTimer, 1f);
                        }
                    }
                }
                // Bone dust particles
                if (_rng.NextDouble() < 0.3)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * z.Radius * (float)_rng.NextDouble(),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -10f - (float)_rng.NextDouble() * 15f),
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = new Color(200, 190, 160),
                        Size = 1.5f,
                    });
                }
            }
            else if (z.FusionTag == "Bifrost")
            {
                // Push enemies along stored beam direction
                Vector2 beamDir2 = new Vector2(z.VineTimer, z.GrowRate);
                if (beamDir2.LengthSquared() > 0.01f)
                {
                    beamDir2.Normalize();
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive) continue;
                        float d = Vector2.Distance(z.Position, _enemies[j].Position);
                        if (d < z.Radius + _enemies[j].Size / 2f)
                        {
                            _enemies[j].KnockbackVel += beamDir2 * 60f * dt;
                        }
                    }
                }
                // Rainbow crackle particles
                if (_rng.NextDouble() < 0.3)
                {
                    float hue = (_totalTime * 3f) % 1f;
                    int r2 = (int)(MathF.Sin(hue * MathF.PI * 2f) * 127 + 128);
                    int g2 = (int)(MathF.Sin((hue + 0.33f) * MathF.PI * 2f) * 127 + 128);
                    int b2 = (int)(MathF.Sin((hue + 0.66f) * MathF.PI * 2f) * 127 + 128);
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * z.Radius * 2f, ((float)_rng.NextDouble() - 0.5f) * z.Radius * 2f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = new Color(r2, g2, b2),
                        Size = 1.5f,
                    });
                }
            }
            else if (z.FusionTag == "DarkGate" || z.FusionTag == "SerpentMercury")
            {

                if (z.FusionTag == "DarkGate")
                {
                    for (int j = 0; j < _enemies.Count; j++)
                    {
                        if (!_enemies[j].Alive) continue;
                        float d = Vector2.Distance(z.Position, _enemies[j].Position);
                        if (d < z.Radius * 2f && d > 5f)
                        {
                            Vector2 pull = z.Position - _enemies[j].Position;
                            pull.Normalize();
                            _enemies[j].Position += pull * 40f * dt;
                        }
                    }
                }
                if (_rng.NextDouble() < 0.4)
                {
                    float a3 = (float)_rng.NextDouble() * MathF.PI * 2f;
                    Color zoneColor = z.FusionTag == "DarkGate" ? new Color(80, 20, 120) : new Color(50, 160, 50);
                    _particles.Add(new Particle
                    {
                        Position = z.Position + new Vector2(MathF.Cos(a3), MathF.Sin(a3)) * z.Radius,
                        Velocity = new Vector2(-MathF.Sin(a3), MathF.Cos(a3)) * 25f,
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = zoneColor * 0.7f,
                        Size = 2f,
                    });
                }
            }
            _lingerZones[i] = z;
        }

        // Hedge walls update (Tiamat's Garden)
        for (int i = _hedgeWalls.Count - 1; i >= 0; i--)
        {
            var h = _hedgeWalls[i];
            h.Life -= dt;
            // Grow animation
            if (h.GrowTimer > 0)
            {
                float oldGrow = h.GrowTimer;
                h.GrowTimer -= dt;
                // Bloom burst when growth completes!
                if (h.GrowTimer <= 0 && oldGrow > 0)
                {
                    Color[] bloomColors = { new Color(200, 40, 60), new Color(220, 180, 40), new Color(140, 50, 180), new Color(40, 120, 200), new Color(240, 120, 60), new Color(255, 150, 200) };
                    for (int p = 0; p < 10; p++)
                    {
                        float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 30f + (float)_rng.NextDouble() * 50f;
                        _particles.Add(new Particle
                        {
                            Position = new Vector2(h.Rect.Center.X, h.Rect.Center.Y),
                            Velocity = new Vector2(MathF.Cos(angle) * spd, MathF.Sin(angle) * spd - 20f),
                            Life = 0.5f, MaxLife = 0.5f,
                            Color = bloomColors[_rng.Next(bloomColors.Length)],
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                }
            }
            
            if (h.Life <= 0 || h.Hp <= 0)
            {
                // Death particles — autumn leaves scattering (tan, brown, faded gold)
                Color[] autumnLeaves = { new Color(180, 140, 50), new Color(140, 95, 40), new Color(110, 70, 30), new Color(160, 120, 45), new Color(100, 75, 35) };
                for (int p = 0; p < 12; p++)
                {
                    _particles.Add(new Particle
                    {
                        Position = new Vector2(h.Rect.Center.X + ((float)_rng.NextDouble() - 0.5f) * h.Rect.Width, h.Rect.Center.Y + ((float)_rng.NextDouble() - 0.5f) * h.Rect.Height),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 50f, -10f + ((float)_rng.NextDouble() - 0.5f) * 40f),
                        Life = 0.8f, MaxLife = 0.8f,
                        Color = autumnLeaves[_rng.Next(autumnLeaves.Length)],
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _revealedMazeCells.Remove((h.MazeCellX, h.MazeCellY));
                _hedgeWalls.RemoveAt(i);
                continue;
            }
            // Contact damage + thorn slow (only after fully grown)
            if (h.GrowTimer <= 0)
            {
                for (int j = 0; j < _enemies.Count; j++)
                {
                    if (!_enemies[j].Alive || _enemies[j].Possessed) continue;
                    var eRect = new Rectangle((int)(_enemies[j].Position.X - _enemies[j].Size/2), (int)(_enemies[j].Position.Y - _enemies[j].Size/2), (int)_enemies[j].Size, (int)_enemies[j].Size);
                    if (h.Rect.Intersects(eRect))
                    {
                        // Push enemy out
                        Vector2 pushDir = _enemies[j].Position - new Vector2(h.Rect.Center.X, h.Rect.Center.Y);
                        if (pushDir.LengthSquared() > 0) pushDir.Normalize();
                        _enemies[j].Position += pushDir * 150f * dt;
                        // Thorn damage — meaningful
                        _enemies[j].TakeDamage(ApplyElementCounter(_enemies[j], 15f * dt, Essence.Sap, showBark: false));
                        _enemies[j].SlowTimer = MathF.Max(_enemies[j].SlowTimer, 0.5f);
                        // Thorn hit particles
                        if (_rng.NextDouble() < 0.3)
                        {
                            _particles.Add(new Particle
                            {
                                Position = _enemies[j].Position,
                                Velocity = pushDir * 30f + new Vector2(0, -10f),
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(40, 120, 30),
                                Size = 2f,
                            });
                        }
                        // Enemy presence damages the hedge
                        h.Hp -= 3f * dt;
                    }
                }
            }
            _hedgeWalls[i] = h;
        }
        
        // Off-screen hedge decay (timers still tick while player is away)
        foreach (var kvp in _screenHedges)
        {
            if (kvp.Key == _currentScreen) continue; // current screen updated above
            var list = kvp.Value;
            for (int i = list.Count - 1; i >= 0; i--)
            {
                var h = list[i];
                h.Life -= dt;
                if (h.Life <= 0) { list.RemoveAt(i); continue; }
                list[i] = h;
            }
        }
        
        // Damage numbers update
        for (int i = _damageNumbers.Count - 1; i >= 0; i--)
        {
            var dn = _damageNumbers[i];
            dn.Position.Y -= 40f * dt;
            dn.Timer -= dt;
            _damageNumbers[i] = dn;
            if (dn.Timer <= 0) _damageNumbers.RemoveAt(i);
        }

        // Floating combat text update
        for (int i = _floatingTexts.Count - 1; i >= 0; i--)
        {
            var ft = _floatingTexts[i];
            ft.Life -= dt;
            ft.Position += new Vector2(0, -30f * dt);
            if (ft.Life <= 0) { _floatingTexts.RemoveAt(i); continue; }
            _floatingTexts[i] = ft;
        }
        for (int i = _screenCracks.Count - 1; i >= 0; i--)
        {
            var sc = _screenCracks[i];
            sc.Timer -= dt;
            if (sc.Timer <= 0) { _screenCracks.RemoveAt(i); continue; }
            _screenCracks[i] = sc;
        }

        // Pickup notifications update
        for (int i = _pickupNotifs.Count - 1; i >= 0; i--)
        {
            var pn = _pickupNotifs[i];
            pn.Timer -= dt;
            _pickupNotifs[i] = pn;
            if (pn.Timer <= 0) _pickupNotifs.RemoveAt(i);
        }

        if (_trauma > 0)
        {
            _trauma = MathF.Max(_trauma - 1.2f * dt, 0);
            float shake = _trauma * _trauma;
            _shakeX = MathF.Sin(100f + _noiseTime * 25f) * shake * 8f;
            _shakeY = MathF.Sin(200f + _noiseTime * 30f) * shake * 8f;
        }
        else { _shakeX = 0; _shakeY = 0; }
        _noiseTime += dt;
        _gorgonTime += dt;
        
        // Kill streak timer
        if (_streakTimer > 0)
        {
            _streakTimer -= dt;
            if (_streakTimer <= 0)
            {
                if (_streakCount > _bestStreak) _bestStreak = _streakCount;
                _streakCount = 0;
            }
        }
        
        // Ether shard update
        float magnetRadius = 80f;
        float magnetSpeed = 350f;
        float collectRadius = 12f;
        for (int i = _shards.Count - 1; i >= 0; i--)
        {
            var s = _shards[i];
            s.Life -= dt;
            s.MagnetTimer -= dt;
            
            if (s.MagnetTimer <= 0)
            {
                // Pull toward player
                Vector2 toPlayer = _playerPos - s.Position;
                float dist = toPlayer.Length();
                if (dist < magnetRadius && dist > 1f)
                {
                    Vector2 pullDir = toPlayer / dist;
                    float pullStrength = magnetSpeed * (1f - dist / magnetRadius); // stronger when closer
                    s.Velocity = s.Velocity * 0.9f + pullDir * pullStrength * dt * 60f;
                }
                else
                {
                    s.Velocity *= MathF.Pow(0.05f, dt); // friction when outside magnet range
                }
                
                // Collect
                if (dist < collectRadius)
                {
                    _hardEther += s.Value;
                    // Tiny sparkle on collect
                    for (int sp = 0; sp < 3; sp++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        Color sparkColor = s.Value >= 25 ? new Color(255, 215, 0) : s.Value >= 5 ? new Color(80, 160, 255) : new Color(180, 240, 255);
                        _particles.Add(new Particle
                        {
                            Position = s.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 40f,
                            Life = 0.15f, MaxLife = 0.15f,
                            Color = sparkColor,
                            Size = 2f,
                        });
                    }
                    _shards.RemoveAt(i);
                    continue;
                }
            }
            else
            {
                s.Velocity *= MathF.Pow(0.01f, dt); // fast decel during scatter phase
            }
            
            s.Position += s.Velocity * dt;
            
            if (s.Life <= 0) { _shards.RemoveAt(i); continue; }
            _shards[i] = s;
        }
        
        // Enemy projectile update
        for (int i = _enemyProjectiles.Count - 1; i >= 0; i--)
        {
            var ep = _enemyProjectiles[i];
            ep.Life -= dt;
            if (ep.Life <= 0)
            {
                // Web projectile (Size==6): spawn spider web on expiry
                if (ep.Size == 6f)
                    _spiderWebs.Add(new SpiderWeb { Position = ep.Position, Radius = 40f, Life = 8f, MaxLife = 8f, HitsLeft = 2 });
                _enemyProjectiles.RemoveAt(i); continue;
            }
            
            // Seeking: gently home toward player
            if (ep.Seeking)
            {
                Vector2 toP = _playerPos - ep.Position;
                if (toP.LengthSquared() > 1f)
                {
                    toP.Normalize();
                    ep.Velocity = Vector2.Lerp(ep.Velocity, toP * ep.Velocity.Length(), 2f * dt);
                }
            }
            
            ep.Position += ep.Velocity * dt;
            
            // Check collision with player
            float playerRadius = 8f;
            if (Vector2.Distance(ep.Position, _playerPos) < playerRadius + ep.Size / 2f)
            {
                DamagePlayer(ep.Damage, ep.Position);
                SpawnExplosion(ep.Position, ep.Color, 6, 0.2f, 8f);
                _enemyProjectiles.RemoveAt(i);
                continue;
            }
            
            // Hedge wall blocks enemy projectiles
            bool hedgeBlocked = false;
            for (int h = _hedgeWalls.Count - 1; h >= 0; h--)
            {
                var hedge = _hedgeWalls[h];
                if (hedge.GrowTimer > 0) continue; // not fully grown yet
                if (hedge.Rect.Contains((int)ep.Position.X, (int)ep.Position.Y))
                {
                    // Bullet absorbed — damage the hedge
                    hedge.Hp -= 5f;
                    _hedgeWalls[h] = hedge;
                    // Leaf burst on impact
                    for (int p = 0; p < 4; p++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = ep.Position,
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = _rng.NextDouble() > 0.5 ? new Color(50, 130, 30) : new Color(100, 80, 40),
                            Size = 2f,
                        });
                    }
                    hedgeBlocked = true;
                    break;
                }
            }
            if (hedgeBlocked) { _enemyProjectiles.RemoveAt(i); continue; }
            
            // Out of arena
            if (ep.Position.X < _arena.Left - 20 || ep.Position.X > _arena.Right + 20 ||
                ep.Position.Y < _arena.Top - 20 || ep.Position.Y > _arena.Bottom + 20)
            {
                if (ep.Size == 6f)
                    _spiderWebs.Add(new SpiderWeb { Position = ep.Position, Radius = 40f, Life = 8f, MaxLife = 8f, HitsLeft = 2 });
                _enemyProjectiles.RemoveAt(i);
                continue;
            }
            
            _enemyProjectiles[i] = ep;
        }
        
        // ═══════════════ ENEMY SPAWN EFFECTS ═══════════════
        foreach (var enemy in _enemies)
        {
            if (!enemy.Spawning || !enemy.Alive) continue;
            float t = 1f - enemy.SpawnTimer / enemy.SpawnDuration; // 0→1 progress
            
            switch (enemy.Type)
            {
                case EnemyType.GuardGargoyle:
                    // Shadow on ground growing, then slam particles at end
                    if (t < 0.8f)
                    {
                        // Warning shadow particles
                        if (_rng.NextDouble() < 0.3)
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f * t, ((float)_rng.NextDouble() - 0.5f) * 20f * t),
                                Velocity = Vector2.Zero,
                                Life = 0.15f, MaxLife = 0.15f,
                                Color = new Color(30, 20, 40),
                                Size = 3f + t * 8f,
                            });
                    }
                    else if (enemy.SpawnTimer < 0.05f)
                    {
                        // Landing slam
                        for (int sp = 0; sp < 8; sp++)
                        {
                            float a = sp * MathF.PI * 2f / 8f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 80f,
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(160, 140, 180),
                                Size = 3f,
                            });
                        }
                        _trauma = MathF.Min(_trauma + 0.08f, 1f);
                    }
                    break;
                    
                case EnemyType.HollowPlate:
                    // Stone fragments rising from ground, assembling
                    if (_rng.NextDouble() < 0.5)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float dist = 15f + (float)_rng.NextDouble() * 15f;
                        Vector2 start = enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist * (1f - t);
                        _particles.Add(new Particle
                        {
                            Position = start + new Vector2(0, 10f * (1f - t)),
                            Velocity = (enemy.Position - start) * 2f + new Vector2(0, -30f * t),
                            Life = 0.2f + (float)_rng.NextDouble() * 0.1f, MaxLife = 0.3f,
                            Color = new Color(60 + _rng.Next(30), 60 + _rng.Next(30), 80 + _rng.Next(30)),
                            Size = 2f + (float)_rng.NextDouble() * 3f,
                        });
                    }
                    break;
                    
                case EnemyType.HedgeSniper:
                    // Vine/leaf particles growing upward from ground
                    if (_rng.NextDouble() < 0.4)
                    {
                        _particles.Add(new Particle
                        {
                            Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 12f, enemy.Size * 0.5f * (1f - t)),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, -15f - (float)_rng.NextDouble() * 20f),
                            Life = 0.3f + (float)_rng.NextDouble() * 0.2f, MaxLife = 0.5f,
                            Color = _rng.NextDouble() > 0.5 ? new Color(40, 120, 30) : new Color(80, 160, 50),
                            Size = 1.5f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                    break;
                    
                case EnemyType.TowerGuard:
                    // Heavy shadow like gargoyle but bigger, longer
                    if (t < 0.7f)
                    {
                        if (_rng.NextDouble() < 0.4)
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position + new Vector2(((float)_rng.NextDouble() - 0.5f) * 25f * t, ((float)_rng.NextDouble() - 0.5f) * 25f * t),
                                Velocity = Vector2.Zero,
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(20, 20, 30),
                                Size = 4f + t * 12f,
                            });
                    }
                    else if (enemy.SpawnTimer < 0.05f)
                    {
                        // Heavy slam — more particles, bigger shake
                        for (int sp = 0; sp < 12; sp++)
                        {
                            float a = sp * MathF.PI * 2f / 12f;
                            _particles.Add(new Particle
                            {
                                Position = enemy.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 100f + new Vector2(0, 20f),
                                Life = 0.25f, MaxLife = 0.25f,
                                Color = new Color(140, 140, 160),
                                Size = 3f + (float)_rng.NextDouble() * 2f,
                            });
                        }
                        _trauma = MathF.Min(_trauma + 0.15f, 1f);
                    }
                    break;
                    
                case EnemyType.Squire:
                case EnemyType.ShieldMaiden:
                    // Simple portal/warp-in: ring of sparkles closing inward
                    if (_rng.NextDouble() < 0.3)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float dist = 20f * (1f - t);
                        _particles.Add(new Particle
                        {
                            Position = enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist,
                            Velocity = (enemy.Position - (enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist)) * 1.5f,
                            Life = 0.15f + (float)_rng.NextDouble() * 0.1f, MaxLife = 0.25f,
                            Color = enemy.Type == EnemyType.ShieldMaiden ? new Color(200, 170, 120) : new Color(180, 180, 170),
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                    break;
            }
        }
        
        // Senbonzakura: ambient petal aura around Morien
        if (_currentFusion == "Senbonzakura")
        {
            for (int i = 0; i < 2; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                float r = 10f + (float)_rng.NextDouble() * 25f;
                float orbSpd = 40f + (float)_rng.NextDouble() * 30f;
                // Tangential velocity for swirling effect
                Vector2 tangent = new Vector2(-MathF.Sin(a), MathF.Cos(a));
                _particles.Add(new Particle
                {
                    Position = _playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * r,
                    Velocity = tangent * orbSpd + new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -10f - (float)_rng.NextDouble() * 15f),
                    Life = 0.5f + (float)_rng.NextDouble() * 0.4f,
                    MaxLife = 0.9f,
                    Color = new Color(230 + _rng.Next(25), 150 + _rng.Next(60), 170 + _rng.Next(40)),
                    Size = 1.5f + (float)_rng.NextDouble() * 1.5f,
                });
            }
        }
        
        // Gorgon's Grasp: autonomous snake attacks
        if (_currentFusion == "Gorgon's Grasp" && _gorgonSnakes.Count > 0)
        {
            Vector2 gDir = Vector2.Zero;
            var gMs = Mouse.GetState();
            Vector2 gMPos = new Vector2(gMs.X, gMs.Y);
            if (Vector2.DistanceSquared(gMPos, _playerPos) > 1f)
            { gDir = gMPos - _playerPos; gDir.Normalize(); }
            
            for (int si = 0; si < _gorgonSnakes.Count; si++)
            {
                var snake = _gorgonSnakes[si];
                
                // Tick down strike animation
                if (snake.StrikeTimer > 0) snake.StrikeTimer -= dt;
                
                // Tick attack cooldown
                snake.AttackTimer -= dt;
                if (snake.AttackTimer <= 0)
                {
                    // Compute snake head position (same as draw code)
                    float behindAngle = MathF.Atan2(-gDir.Y, -gDir.X) + snake.AngleOffset;
                    Vector2 snakeBase = _playerPos + new Vector2(MathF.Cos(behindAngle), MathF.Sin(behindAngle)) * 12f;
                    // Walk segments to find head
                    Vector2 prev = snakeBase;
                    Vector2 headDir = gDir;
                    for (int seg = 0; seg < 10; seg++)
                    {
                        float t = (float)(seg + 1) / 10f;
                        Vector2 baseD = new Vector2(MathF.Cos(behindAngle), MathF.Sin(behindAngle));
                        Vector2 segD = Vector2.Lerp(baseD, gDir, t * t);
                        if (segD.LengthSquared() > 0) segD.Normalize();
                        Vector2 perp = new Vector2(-segD.Y, segD.X);
                        float slither = MathF.Sin(_gorgonTime * 8f + snake.Phase + t * 6f) * 4f * (1f - t * 0.5f);
                        prev = prev + segD * 5f + perp * slither;
                        if (seg == 9) headDir = segD;
                    }
                    Vector2 snakeHead = prev;
                    
                    // Find nearest enemy
                    int bestIdx = -1;
                    float bestDist = 250f;
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                        float d = Vector2.Distance(snakeHead, _enemies[e].Position);
                        if (d < bestDist) { bestDist = d; bestIdx = e; }
                    }
                    
                    if (bestIdx >= 0)
                    {
                        var enemy = _enemies[bestIdx];
                        Vector2 toEnemy = enemy.Position - snakeHead;
                        if (toEnemy.LengthSquared() > 0) toEnemy.Normalize();
                        
                        // Build projectile params from current loadout
                        var aParms = BuildProjectileParams();
                        
                        if (bestDist < 55f)
                        {
                            // BITE: snake lunges forward, short range high damage
                            snake.StrikeTimer = 0.15f; // lunge animation
                            snake.TargetId = enemy.Id;
                            aParms.BaseDamage *= 2.5f;
                            aParms.Speed = 400f;
                            aParms.Lifetime = 0.08f;
                            aParms.Piercing = true;
                            aParms.StasisDuration = 1.5f;
                            aParms.StasisRadius = 20f;
                            var bite = new Projectile(snakeHead, toEnemy * 400f, aParms);
                            bite.FusionName = "GorgonBite";
                            bite.Size = 8f;
                            _projectiles.Add(bite);
                            snake.AttackTimer = 0.6f; // fast bite cooldown
                        }
                        else
                        {
                            // SPIT: poison glob from mouth toward enemy
                            aParms.Speed = 200f;
                            aParms.Lifetime = 1.0f;
                            aParms.StasisDuration = 0.8f;
                            aParms.StasisRadius = 15f;
                            float jitter = ((float)_rng.NextDouble() - 0.5f) * 0.12f;
                            float angle = MathF.Atan2(toEnemy.Y, toEnemy.X) + jitter;
                            var spitDir = new Vector2(MathF.Cos(angle), MathF.Sin(angle));
                            var spit = new Projectile(snakeHead, spitDir * 200f, aParms);
                            spit.FusionName = "GorgonSpit";
                            spit.Size = 5f;
                            _projectiles.Add(spit);
                            snake.AttackTimer = 0.9f; // slower spit cooldown
                        }
                    }
                    else
                    {
                        snake.AttackTimer = 0.3f; // check again soon
                    }
                }
                
                _gorgonSnakes[si] = snake;
            }
        }

        // Caoilfhionn: guardian angel — orbits player, swoops at nearby enemies
        if (_angelActive && _currentFusion == "Caoilfhionn")
        {
            _angelTime += dt;
            var a = _angel;
            a.IdleTime += dt;
            
            // Departure — ascending and fading out
            if (a.DepartTimer > 0)
            {
                a.DepartTimer -= dt;
                if (a.DepartTimer <= 0)
                {
                    _angelActive = false;
                    _angel = a;
                }
                else
                {
                    // Shed feather particles while departing
                    if (_rng.NextDouble() < 0.3)
                    {
                        Vector2 dPos = _playerPos + new Vector2(MathF.Cos(a.OrbitAngle), MathF.Sin(a.OrbitAngle)) * 60f;
                        _particles.Add(new Particle
                        {
                            Position = dPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 16f, 0),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, 10f + (float)_rng.NextDouble() * 20f),
                            Life = 0.8f, MaxLife = 0.8f,
                            Color = new Color(180, 40, 40) * 0.7f,
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                    _angel = a;
                }
            }
            else if (a.SwoopTimer > 0)
            {
                // Currently swooping toward target
                a.SwoopTimer -= dt;
                if (a.SwoopTimer <= 0)
                {
                    // Impact — direct damage to enemies near swoop target
                    var aParms = BuildProjectileParams();
                    float swoopDmg = aParms.BaseDamage * 3f;
                    float swoopRadius = 35f;
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                        float eDist = Vector2.Distance(a.SwoopTarget, _enemies[e].Position);
                        if (eDist < swoopRadius + _enemies[e].Size / 2f)
                        {
                            _enemies[e].TakeDamage(ApplyElementCounter(_enemies[e], swoopDmg, Essence.Hollow));
                            _enemies[e].Stagger += 15f;
                            _enemies[e].HitFlash = 0.15f;
                            Vector2 akb = _enemies[e].Position - a.SwoopTarget;
                            if (akb.LengthSquared() > 0.01f) akb = Vector2.Normalize(akb);
                            _enemies[e].KnockbackVel = akb * 120f;
                        }
                    }
                    
                    // Impact particles — white/violet burst
                    SpawnExplosion(a.SwoopTarget, new Color(220, 200, 255), 10, 0.3f, 15f);
                    SpawnExplosion(a.SwoopTarget, Color.White, 5, 0.15f, 8f);
                    _trauma = MathF.Min(_trauma + 0.08f, 0.5f);
                    
                    // Decrement swoop budget
                    a.SwoopsLeft--;
                    
                    if (a.SwoopsLeft <= 0)
                    {
                        // Final swoop — begin departure
                        a.DepartTimer = 1.5f;
                        a.Returning = false;
                        a.SwoopCooldown = 999f; // no more swoops
                    }
                    else
                    {
                        // Begin return
                        a.Returning = true;
                        a.ReturnTimer = 0.3f;
                        a.SwoopCooldown = 1.2f;
                    }
                }
            }
            else if (a.Returning)
            {
                // Flying back to orbit position
                a.ReturnTimer -= dt;
                if (a.ReturnTimer <= 0)
                {
                    a.Returning = false;
                }
            }
            else
            {
                // Orbiting — advance angle with slight speed variation
                float speedWobble = 1f + 0.2f * MathF.Sin(a.IdleTime * 0.7f);
                a.OrbitAngle += a.OrbitSpeed * speedWobble * dt;
                if (a.OrbitAngle > MathF.PI * 2f) a.OrbitAngle -= MathF.PI * 2f;
                
                // Target orbit position with figure-8 wobble
                float fig8X = MathF.Sin(a.IdleTime * 1.3f) * 8f;
                float fig8Y = MathF.Sin(a.IdleTime * 2.1f) * 6f;
                float vertBob = MathF.Sin(a.IdleTime * 2.5f) * 4f;
                Vector2 orbitTarget = _playerPos + new Vector2(
                    MathF.Cos(a.OrbitAngle) * 60f + fig8X,
                    MathF.Sin(a.OrbitAngle) * 60f + fig8Y + vertBob);
                
                // Spring-follow: accelerate toward target, dampen velocity
                Vector2 toTarget = orbitTarget - a.ActualPos;
                float springK = 6f;  // spring stiffness
                float damping = 4f;  // velocity damping
                a.Velocity += toTarget * springK * dt;
                a.Velocity *= MathF.Max(0f, 1f - damping * dt);
                a.ActualPos += a.Velocity * dt;
                
                // Check for swoop cooldown
                a.SwoopCooldown -= dt;
                if (a.SwoopCooldown <= 0)
                {
                    // Find nearest enemy within detection range
                    Vector2 angelPos = a.ActualPos;
                    int bestIdx = -1;
                    float bestDist = 200f; // detection range
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                        float d = Vector2.Distance(angelPos, _enemies[e].Position);
                        if (d < bestDist) { bestDist = d; bestIdx = e; }
                    }
                    
                    if (bestIdx >= 0)
                    {
                        a.SwoopTarget = _enemies[bestIdx].Position;
                        a.SwoopStart = angelPos;
                        a.TargetId = _enemies[bestIdx].Id;
                        a.SwoopTimer = 0.25f; // swoop duration
                    }
                }
            }
            
            _angel = a;
        }

        // Scáthach: shadow knight — orbits player, arc-sweeps at nearby enemies
        if (_knightActive && _currentFusion == "Scathach")
        {
            _knightTime += dt;
            var k = _knight;
            k.IdleTime += dt;
            
            // Departure
            if (k.DepartTimer > 0)
            {
                k.DepartTimer -= dt;
                if (k.DepartTimer <= 0)
                {
                    _knightActive = false;
                    _knight = k;
                }
                else
                {
                    // Shadow particles dissolving
                    if (_rng.NextDouble() < 0.4)
                    {
                        _particles.Add(new Particle
                        {
                            Position = k.ActualPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -20f - (float)_rng.NextDouble() * 30f),
                            Life = 0.6f, MaxLife = 0.6f,
                            Color = new Color(60, 20, 80) * 0.8f,
                            Size = 3f + (float)_rng.NextDouble() * 3f,
                        });
                    }
                    _knight = k;
                }
            }
            else if (k.WindupTimer > 0)
            {
                // Wind-up — knight travels to target before swinging
                k.WindupTimer -= dt;
                if (k.WindupTimer <= 0)
                {
                    // Arrived — start the swing
                    k.SwingTimer = 0.3f; // arc sweep duration
                    k.ActualPos = k.SwingTarget;
                }
                else
                {
                    // Travel to target
                    float wt = 1f - (k.WindupTimer / 0.25f);
                    wt = wt * wt; // ease-in
                    k.ActualPos = Vector2.Lerp(k.SwingStart, k.SwingTarget, wt);
                }
                _knight = k;
            }
            else if (k.SwingTimer > 0)
            {
                // Swinging — arc damage dealt at the start
                float prevTimer = k.SwingTimer;
                k.SwingTimer -= dt;
                
                // Deal damage once at start of swing
                if (prevTimer >= 0.28f && k.SwingTimer < 0.28f)
                {
                    float swingDmg = BuildProjectileParams().BaseDamage * 4f;
                    float arcRadius = 100f; // bigger reach to match bigger sword
                    float halfArc = MathF.PI / 3f; // 120 degree arc = ±60 degrees
                    
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                        Vector2 toE = _enemies[e].Position - k.ActualPos;
                        float eDist = toE.Length();
                        if (eDist < arcRadius + _enemies[e].Size / 2f)
                        {
                            // Very close enemies always hit (they're at the blade origin)
                            bool inArc = eDist < 30f;
                            if (!inArc)
                            {
                                // Check if within arc angle
                                float eAngle = MathF.Atan2(toE.Y, toE.X);
                                float angleDiff = eAngle - k.SwingAngle;
                                // Normalize to [-PI, PI]
                                while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
                                while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
                                inArc = MathF.Abs(angleDiff) < halfArc;
                            }
                            
                            if (inArc)
                            {
                                _enemies[e].TakeDamage(ApplyElementCounter(_enemies[e], swingDmg, Essence.Dark));
                                _enemies[e].Stagger += 25f;
                                _enemies[e].HitFlash = 0.2f;
                                Vector2 ekb = toE.LengthSquared() > 0.01f ? Vector2.Normalize(toE) : Vector2.UnitX;
                                _enemies[e].KnockbackVel = ekb * 180f;
                            }
                        }
                    }
                    
                    // Swing slash particles — arc of dark energy
                    for (int p = 0; p < 12; p++)
                    {
                        float pAngle = k.SwingAngle - halfArc + (halfArc * 2f * p / 11f);
                        Vector2 pDir = new Vector2(MathF.Cos(pAngle), MathF.Sin(pAngle));
                        float pDist = 30f + (float)_rng.NextDouble() * 50f;
                        _particles.Add(new Particle
                        {
                            Position = k.ActualPos + pDir * pDist,
                            Velocity = pDir * (60f + (float)_rng.NextDouble() * 40f),
                            Life = 0.4f, MaxLife = 0.4f,
                            Color = new Color(100, 40, 140),
                            Size = 3f + (float)_rng.NextDouble() * 3f,
                        });
                    }
                    _trauma = MathF.Min(_trauma + 0.12f, 0.5f);
                }
                
                if (k.SwingTimer <= 0)
                {
                    k.SwingsLeft--;
                    if (k.SwingsLeft <= 0)
                    {
                        k.DepartTimer = 2.0f; // slower departure — dissolves into shadow
                        k.SwingCooldown = 999f;
                    }
                    else
                    {
                        k.Returning = true;
                        k.ReturnTimer = 0.4f;
                        k.SwingCooldown = 2.0f;
                    }
                }
                _knight = k;
            }
            else if (k.Returning)
            {
                k.ReturnTimer -= dt;
                if (k.ReturnTimer <= 0)
                {
                    k.Returning = false;
                }
                _knight = k;
            }
            else
            {
                // Orbiting — slower, heavier than Caoilfhionn
                float speedWobble = 1f + 0.15f * MathF.Sin(k.IdleTime * 0.5f);
                k.OrbitAngle += k.OrbitSpeed * speedWobble * dt;
                if (k.OrbitAngle > MathF.PI * 2f) k.OrbitAngle -= MathF.PI * 2f;
                
                // Wider orbit, less wobble — heavy and deliberate
                float fig8X = MathF.Sin(k.IdleTime * 0.8f) * 5f;
                float vertBob = MathF.Sin(k.IdleTime * 1.5f) * 3f;
                Vector2 orbitTarget = _playerPos + new Vector2(
                    MathF.Cos(k.OrbitAngle) * 70f + fig8X,
                    MathF.Sin(k.OrbitAngle) * 70f + vertBob);
                
                // Spring-follow — stiffer but more damped (heavier)
                Vector2 toTarget = orbitTarget - k.ActualPos;
                float springK = 4f;
                float damping = 5f;
                k.Velocity += toTarget * springK * dt;
                k.Velocity *= MathF.Max(0f, 1f - damping * dt);
                k.ActualPos += k.Velocity * dt;
                
                // Auto-attack
                k.SwingCooldown -= dt;
                if (k.SwingCooldown <= 0)
                {
                    int bestIdx = -1;
                    float bestDist = 180f;
                    for (int e = 0; e < _enemies.Count; e++)
                    {
                        if (!_enemies[e].Alive || _enemies[e].Possessed) continue;
                        float d = Vector2.Distance(k.ActualPos, _enemies[e].Position);
                        if (d < bestDist) { bestDist = d; bestIdx = e; }
                    }
                    
                    if (bestIdx >= 0)
                    {
                        k.SwingStart = k.ActualPos;
                        k.SwingTarget = _enemies[bestIdx].Position;
                        k.SwingAngle = MathF.Atan2(
                            _enemies[bestIdx].Position.Y - k.ActualPos.Y,
                            _enemies[bestIdx].Position.X - k.ActualPos.X);
                        k.WindupTimer = 0.25f;
                    }
                }
                _knight = k;
            }
        }

        if (!_testMode && _playerHp <= 0)
        {
            _state = GameState.GameOver;
            _timesFallen++;
            _gameOverTimer = 0f;
            _gameOverSelection = 0;
        }

        // Relic toggling by clicking (test mode)
        if (_testMode && mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released)
        {
            int relicX = 1010; // matches hpBarX in DrawHUD
            int relicY = 8 + 14 + 32; // hpBarY(8) + etherOffset(14) + relicOffset(32) = 54
            for (int i = 0; i < 7; i++)
            {
                var box = new Rectangle(relicX + i * 28, relicY, 24, 24);
                if (box.Contains(mouse.X, mouse.Y))
                {
                    if (i == 0) _hasCaliburn = !_hasCaliburn;
                    else if (i == 1) _hasNimueTear = !_hasNimueTear;
                    else if (i == 2) _hasWandOfMerlin = !_hasWandOfMerlin;
                    else if (i == 3) _hasHasteBand = !_hasHasteBand;
                    else if (i == 4) _hasPhylactery = !_hasPhylactery;
                    else if (i == 5) _hasDragonDance = !_hasDragonDance;
                    else if (i == 6) { _hasGrimoire = !_hasGrimoire; RefreshCombo(); }
                }
            }
        }

        _prevMouse = mouse;
        _prevKb = kb;
        base.Update(gameTime);
    }

    private ProjectileParams BuildProjectileParams()
    {
        return ProjectileParams.Resolve(_loadout);
    }

    // ═══════════════ BREAK FINISHER ═══════════════

    private void UpdateFinisher(float dt)
    {
        if (!_finisherActive) return;

        _finisherTimer -= dt;

        // Phase 1 (1.2 → 0.8): Zoom in + freeze
        if (_finisherTimer > 0.8f)
        {
            float t = 1f - (_finisherTimer - 0.8f) / 0.4f; // 0→1
            _finisherZoom = 1f + t * 0.25f; // 1x → 1.25x
        }
        // Phase 2 (0.8 → 0.3): Smash Bros jitter (handled in draw)
        // Phase 3 (0.3 → 0.0): Element-specific death + zoom out
        else if (_finisherTimer <= 0.3f && _finisherTimer > 0f)
        {
            // Zoom back out
            float t = _finisherTimer / 0.3f; // 1→0
            _finisherZoom = 1f + t * 0.25f;

            // Spawn death particles + kill enemy on first frame of phase 3
            if (!_finisherKillProcessed)
            {
                _finisherKillProcessed = true;
                Vector2 pos = _finisherTarget;
                _trauma = MathF.Min(_trauma + 0.7f, 1f);
                
                // BREAK finisher bonus: extra ether drops
                SpawnEtherDrops(pos, false);
                SpawnEtherDrops(pos, false); // double drops for finisher kills

                // Main burst — lots of particles
                int particleCount = 120;
                for (int p = 0; p < particleCount; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 30f + (float)_rng.NextDouble() * 200f;
                    float life = 0.5f + (float)_rng.NextDouble() * 1.0f;
                    Color col;
                    float size;
                    switch (_finisherEssence)
                    {
                        case Essence.Cinder:
                            col = Color.Lerp(new Color(255, 200, 40), new Color(255, 40, 10), (float)_rng.NextDouble());
                            size = 2f + (float)_rng.NextDouble() * 6f;
                            break;
                        case Essence.Pulse:
                            col = _rng.NextDouble() > 0.3 ? new Color(80, 180, 255) : Color.White;
                            size = 1f + (float)_rng.NextDouble() * 4f;
                            break;
                        case Essence.Bone:
                            col = Color.Lerp(new Color(230, 220, 200), new Color(140, 120, 90), (float)_rng.NextDouble());
                            size = 3f + (float)_rng.NextDouble() * 6f;
                            spd *= 0.5f;
                            break;
                        default:
                            col = Color.Lerp(new Color(200, 200, 210), Color.White, (float)_rng.NextDouble());
                            size = 2f + (float)_rng.NextDouble() * 4f;
                            break;
                    }
                    _particles.Add(new Particle
                    {
                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = life, MaxLife = life,
                        Color = col,
                        Size = size
                    });
                }
                
                // Bright white flash ring (expanding circle of particles)
                for (int r = 0; r < 24; r++)
                {
                    float a = r * MathF.PI * 2f / 24f;
                    _particles.Add(new Particle
                    {
                        Position = pos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 180f,
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = Color.White,
                        Size = 4f
                    });
                }
                
                // Secondary ring (element colored, slower)
                Color ringCol = _finisherEssence switch
                {
                    Essence.Cinder => new Color(255, 120, 30),
                    Essence.Pulse => new Color(100, 200, 255),
                    Essence.Bone => new Color(220, 200, 170),
                    _ => new Color(180, 180, 190)
                };
                for (int r = 0; r < 16; r++)
                {
                    float a = r * MathF.PI * 2f / 16f + 0.2f;
                    _particles.Add(new Particle
                    {
                        Position = pos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 100f,
                        Life = 0.6f, MaxLife = 0.6f,
                        Color = ringCol,
                        Size = 5f
                    });
                }
                
                // Lingering embers/sparks (slow drifters)
                for (int e = 0; e < 20; e++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                        Velocity = new Vector2(MathF.Cos(a) * 15f, -10f - (float)_rng.NextDouble() * 20f),
                        Life = 1.2f + (float)_rng.NextDouble() * 0.8f,
                        MaxLife = 2f,
                        Color = ringCol * 0.8f,
                        Size = 1f + (float)_rng.NextDouble() * 2f
                    });
                }

                // Kill the enemy and spawn ether shard drops
                if (_finisherEnemyIndex >= 0 && _finisherEnemyIndex < _enemies.Count)
                {
                    var deadEnemy = _enemies[_finisherEnemyIndex];
                    deadEnemy.Alive = false;
                    _enemies[_finisherEnemyIndex] = deadEnemy;

                    // ═══ WEAKNESS-ELEMENT DEATH BURST ═══
                    // If the finisher essence matches the enemy's weakness, play a unique death visual
                    bool weaknessFinisher = _finisherEssence != Essence.None && 
                        (_finisherEssence == deadEnemy.Weakness || _finisherEssence == deadEnemy.Weakness2);
                    
                    if (weaknessFinisher)
                    {
                        // Extra trauma + hitstop for the special kill
                        _trauma = MathF.Min(_trauma + 0.3f, 1f);
                        
                        switch (_finisherEssence)
                        {
                            case Essence.Cinder:
                            {
                                // Ash disintegration — burns from extremities inward
                                for (int p = 0; p < 60; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float dist = deadEnemy.Size * 0.3f + (float)_rng.NextDouble() * deadEnemy.Size * 0.5f;
                                    Vector2 origin = pos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist;
                                    _particles.Add(new Particle
                                    {
                                        Position = origin,
                                        Velocity = new Vector2(MathF.Cos(a) * 10f, -20f - (float)_rng.NextDouble() * 40f), // ash rises
                                        Life = 1.5f + (float)_rng.NextDouble() * 1.5f,
                                        MaxLife = 3f,
                                        Color = Color.Lerp(new Color(80, 60, 50), new Color(40, 30, 25), (float)_rng.NextDouble()),
                                        Size = 2f + (float)_rng.NextDouble() * 4f
                                    });
                                }
                                // Inner ember glow that fades
                                for (int p = 0; p < 20; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                                        Velocity = new Vector2(MathF.Cos(a) * 5f, -15f - (float)_rng.NextDouble() * 10f),
                                        Life = 0.8f + (float)_rng.NextDouble() * 0.5f,
                                        MaxLife = 1.3f,
                                        Color = Color.Lerp(new Color(255, 160, 30), new Color(255, 60, 10), (float)_rng.NextDouble()),
                                        Size = 1f + (float)_rng.NextDouble() * 2f
                                    });
                                }
                                break;
                            }
                            case Essence.Pulse:
                            {
                                // Spark burst — shatters into electric fragments with arcs
                                for (int p = 0; p < 40; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 100f + (float)_rng.NextDouble() * 250f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd2,
                                        Life = 0.3f + (float)_rng.NextDouble() * 0.5f,
                                        MaxLife = 0.8f,
                                        Color = _rng.NextDouble() > 0.4 ? new Color(120, 200, 255) : Color.White,
                                        Size = 1f + (float)_rng.NextDouble() * 3f
                                    });
                                }
                                // Lightning arc lines (fast long particles)
                                for (int p = 0; p < 12; p++)
                                {
                                    float a = p * MathF.PI * 2f / 12f + (float)_rng.NextDouble() * 0.3f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 350f,
                                        Life = 0.15f + (float)_rng.NextDouble() * 0.1f,
                                        MaxLife = 0.25f,
                                        Color = Color.White,
                                        Size = 1f
                                    });
                                }
                                break;
                            }
                            case Essence.Bone:
                            {
                                // Fracture cascade — cracks like stone, pieces fall
                                for (int p = 0; p < 30; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 40f + (float)_rng.NextDouble() * 80f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size, ((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size),
                                        Velocity = new Vector2(MathF.Cos(a) * spd2, -30f + MathF.Sin(a) * spd2 * 0.5f), // biased upward then falls
                                        Life = 1.0f + (float)_rng.NextDouble() * 1.5f,
                                        MaxLife = 2.5f,
                                        Color = Color.Lerp(new Color(200, 190, 170), new Color(120, 110, 90), (float)_rng.NextDouble()),
                                        Size = 4f + (float)_rng.NextDouble() * 8f // chunky stone pieces
                                    });
                                }
                                // Dust cloud
                                for (int p = 0; p < 25; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                                        Velocity = new Vector2(MathF.Cos(a) * 20f, MathF.Sin(a) * 20f),
                                        Life = 1.0f + (float)_rng.NextDouble() * 0.8f,
                                        MaxLife = 1.8f,
                                        Color = new Color(160, 150, 130) * 0.4f,
                                        Size = 6f + (float)_rng.NextDouble() * 6f
                                    });
                                }
                                break;
                            }
                            case Essence.Silk:
                            {
                                // Cocoon collapse — threads wrap inward, then crumble
                                // Converging threads (inward spiral)
                                for (int p = 0; p < 30; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float dist = 40f + (float)_rng.NextDouble() * 60f;
                                    Vector2 startPos = pos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist;
                                    // Move inward
                                    _particles.Add(new Particle
                                    {
                                        Position = startPos,
                                        Velocity = (pos - startPos) * 1.5f, // converge on center
                                        Life = 0.5f + (float)_rng.NextDouble() * 0.3f,
                                        MaxLife = 0.8f,
                                        Color = Color.Lerp(new Color(180, 220, 180), new Color(120, 200, 120), (float)_rng.NextDouble()),
                                        Size = 1f + (float)_rng.NextDouble() * 2f
                                    });
                                }
                                // Then outward dust burst (delayed by shorter life on converge)
                                for (int p = 0; p < 25; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 30f + (float)_rng.NextDouble() * 50f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd2,
                                        Life = 1.2f + (float)_rng.NextDouble() * 0.8f,
                                        MaxLife = 2.0f,
                                        Color = new Color(160, 180, 140) * 0.5f,
                                        Size = 3f + (float)_rng.NextDouble() * 4f
                                    });
                                }
                                break;
                            }
                            case Essence.Dark:
                            {
                                // Shadow dissolution — shadow pulls them into the floor
                                // Downward-streaming dark particles
                                for (int p = 0; p < 40; p++)
                                {
                                    float xSpread = ((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size * 1.5f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(xSpread, ((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size),
                                        Velocity = new Vector2(xSpread * -0.5f, 40f + (float)_rng.NextDouble() * 80f), // pulled DOWN
                                        Life = 0.8f + (float)_rng.NextDouble() * 0.6f,
                                        MaxLife = 1.4f,
                                        Color = Color.Lerp(new Color(60, 20, 80), new Color(30, 10, 40), (float)_rng.NextDouble()),
                                        Size = 2f + (float)_rng.NextDouble() * 5f
                                    });
                                }
                                // Shadow pool spreading outward along ground
                                for (int p = 0; p < 16; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 20f + (float)_rng.NextDouble() * 40f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(0, deadEnemy.Size * 0.3f),
                                        Velocity = new Vector2(MathF.Cos(a) * spd2, MathF.Abs(MathF.Sin(a)) * spd2 * 0.3f), // mostly horizontal
                                        Life = 1.5f + (float)_rng.NextDouble() * 1.0f,
                                        MaxLife = 2.5f,
                                        Color = new Color(20, 5, 30) * 0.6f,
                                        Size = 5f + (float)_rng.NextDouble() * 6f
                                    });
                                }
                                break;
                            }
                            case Essence.Hollow:
                            {
                                // Light reveal — enemy becomes translucent light, gently fades
                                // Soft expanding glow particles (slow, bright)
                                for (int p = 0; p < 35; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 10f + (float)_rng.NextDouble() * 30f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size * 0.5f, ((float)_rng.NextDouble() - 0.5f) * deadEnemy.Size * 0.5f),
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd2,
                                        Life = 1.5f + (float)_rng.NextDouble() * 1.5f,
                                        MaxLife = 3f,
                                        Color = Color.Lerp(new Color(200, 220, 255), Color.White, (float)_rng.NextDouble()),
                                        Size = 3f + (float)_rng.NextDouble() * 5f
                                    });
                                }
                                // Central bright flash (longer lasting than normal)
                                for (int p = 0; p < 8; p++)
                                {
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 6f, ((float)_rng.NextDouble() - 0.5f) * 6f),
                                        Velocity = new Vector2(0, -5f - (float)_rng.NextDouble() * 10f), // gentle rise
                                        Life = 2f + (float)_rng.NextDouble() * 1f,
                                        MaxLife = 3f,
                                        Color = new Color(240, 245, 255),
                                        Size = 6f + (float)_rng.NextDouble() * 4f
                                    });
                                }
                                break;
                            }
                            case Essence.Sap:
                            {
                                // Overgrowth — roots/vines erupt, flowers bloom, then wilt
                                // Vine tendrils shooting outward
                                for (int p = 0; p < 20; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float spd2 = 60f + (float)_rng.NextDouble() * 80f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos,
                                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd2,
                                        Life = 1.0f + (float)_rng.NextDouble() * 1.0f,
                                        MaxLife = 2f,
                                        Color = Color.Lerp(new Color(50, 120, 30), new Color(80, 160, 50), (float)_rng.NextDouble()),
                                        Size = 2f + (float)_rng.NextDouble() * 3f
                                    });
                                }
                                // Flower blooms (bright colored pops)
                                for (int p = 0; p < 15; p++)
                                {
                                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                                    float dist = 10f + (float)_rng.NextDouble() * 30f;
                                    Color flowerCol = _rng.NextDouble() > 0.5 
                                        ? Color.Lerp(new Color(255, 180, 200), new Color(255, 100, 150), (float)_rng.NextDouble())
                                        : Color.Lerp(new Color(255, 230, 100), new Color(255, 180, 50), (float)_rng.NextDouble());
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * dist,
                                        Velocity = new Vector2(0, -8f - (float)_rng.NextDouble() * 12f), // petals drift up
                                        Life = 1.5f + (float)_rng.NextDouble() * 1.0f,
                                        MaxLife = 2.5f,
                                        Color = flowerCol,
                                        Size = 3f + (float)_rng.NextDouble() * 4f
                                    });
                                }
                                // Wilting leaves (falling)
                                for (int p = 0; p < 12; p++)
                                {
                                    float xDrift = ((float)_rng.NextDouble() - 0.5f) * 40f;
                                    _particles.Add(new Particle
                                    {
                                        Position = pos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -10f),
                                        Velocity = new Vector2(xDrift, 20f + (float)_rng.NextDouble() * 30f), // falls down
                                        Life = 2f + (float)_rng.NextDouble() * 1f,
                                        MaxLife = 3f,
                                        Color = Color.Lerp(new Color(120, 100, 40), new Color(80, 60, 20), (float)_rng.NextDouble()),
                                        Size = 2f + (float)_rng.NextDouble() * 3f
                                    });
                                }
                                break;
                            }
                        }
                        
                        // Weakness finisher floating text (gated behind Ether Sight)
                        if (_hasEtherSight)
                        {
                            _floatingTexts.Add(new FloatingText
                            {
                                Position = pos + new Vector2(-40, -deadEnemy.Size - 20),
                                Text = "MASTERY!",
                                Color = new Color(255, 230, 140),
                                Life = 2f, MaxLife = 2f,
                            });
                        }
                    }

                    // Ether shard drops (simplified from universal death effects)
                    int shardCount = 1 + (int)(deadEnemy.Size / 10f) + (_rng.NextDouble() < 0.3 ? 1 : 0);
                    for (int sd = 0; sd < shardCount; sd++)
                    {
                        int val = 1;
                        double roll = _rng.NextDouble();
                        if (roll < 0.03) val = 25;
                        else if (roll < 0.15) val = 5;
                        float sa = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float sspd = 80f + (float)_rng.NextDouble() * 60f;
                        _shards.Add(new EtherShard
                        {
                            Position = deadEnemy.Position,
                            Velocity = new Vector2(MathF.Cos(sa), MathF.Sin(sa)) * sspd,
                            Life = 8f,
                            Value = val,
                            MagnetTimer = 0.3f + (float)_rng.NextDouble() * 0.2f,
                        });
                    }

                    // Kill streak
                    if (!deadEnemy.Possessed)
                    {
                        _streakCount++;
                        _streakTimer = 2f;
                    }
                }
            }
        }

        // End finisher
        if (_finisherTimer <= 0)
        {
            _finisherActive = false;
            _finisherZoom = 1f;
            _finisherEnemyIndex = -1;
        }
    }

    // ═══════════════ MENU STATE METHODS ═══════════════
    
    private void UpdateTitleScreen(KeyboardState kb)
    {
        if ((kb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter)) ||
            (kb.IsKeyDown(Keys.Space) && !_prevKb.IsKeyDown(Keys.Space)))
        {
            _state = GameState.ModeSelect;
            _menuSelection = 0;
        }
        if (kb.IsKeyDown(Keys.Escape)) _state = GameState.TitleScreen;
    }
    
    private void UpdateModeSelect(KeyboardState kb, float dt)
    {
        if (_menuTransitioning)
        {
            _menuFlashTimer -= dt;
            if (_menuFlashTimer <= 0.4f && _menuFadeTimer == 0f)
                _menuFadeTimer = 0.8f;
            if (_menuFadeTimer > 0)
                _menuFadeTimer -= dt;
            if (_menuFlashTimer <= 0 && _menuFadeTimer <= 0)
            {
                _menuTransitioning = false;
                _menuFlashTimer = 0;
                _menuFadeTimer = 0;
                switch (_menuFlashSelection)
                {
                    case 0:
                        _gameMode = GameMode.Awakening;
                        ResetGame();
                        _unlockedForms.Remove(Form.Bolt);
                        _loadout.Form = Form.None;
                        if (!_awakeningIntroDone)
                        {
                            _textBoxMessage = "This is the demo. Enjoy!";
                            _textBoxWaiting = true;
                            _awakeningIntroDone = true;
                        }
                        else
                        {
                            _textBoxMessage = "Unlock the Grimoire and find your true power.";
                            _textBoxWaiting = true;
                        }
                        InitAwakeningRoom5();
                        InitAwakeningDoors();
                        _hasLambentAura = true; _ownsLambentAura = true; // player glows from the start
                        _hasEtherRegen = true; _hasEtherRegenRelic = true; _ownsEtherRegen = true; // passive EP regen
                        _hasSword = true;
                        _state = GameState.Playing;
                        break;
                    case 1:
                        _gameMode = GameMode.Campaign;
                        ResetGame();
                        _state = GameState.Playing;
                        break;
                    case 2:
                        _gameMode = GameMode.Gauntlet;
                        ResetGame();
                        _hasWand = true;
                        _hasShield = true;
                        _hasSword = true;
                        _hasCaliburn = true; _hasNimueTear = true; _hasWandOfMerlin = true; _hasTomeOfBinding = true; _ownsTomeOfBinding = true;
                        _hasHasteBand = true; _hasPhylactery = true; _hasGrimoire = true;
                        _hasLambentAura = true; _ownsLambentAura = true;
                        _ownsCaliburn = true; _ownsNimueTear = true; _ownsWandOfMerlin = true;
                        _ownsHasteBand = true; _ownsPhylactery = true; _ownsGrimoire = true;
                        foreach (Form f in Enum.GetValues<Form>()) _unlockedForms.Add(f);
                        foreach (Behavior b in Enum.GetValues<Behavior>()) _unlockedBehaviors.Add(b);
                        foreach (Essence e in Enum.GetValues<Essence>()) _unlockedEssences.Add(e);
                        _state = GameState.Playing;
                        break;
                    case 3:
                        _gameMode = GameMode.TileRenderer;
                        _trSheetIdx = 0;
                        _trCameraPos = Vector2.Zero;
                        _trScale = 3;
                        _state = GameState.Playing;
                        break;
                    case 4:
                        Exit();
                        break;
                }
                _menuFlashSelection = -1;
            }
            return;
        }

        if ((kb.IsKeyDown(Keys.Up) && !_prevKb.IsKeyDown(Keys.Up)) ||
            (kb.IsKeyDown(Keys.W) && !_prevKb.IsKeyDown(Keys.W)))
            _menuSelection = (_menuSelection - 1 + 5) % 5;
        if ((kb.IsKeyDown(Keys.Down) && !_prevKb.IsKeyDown(Keys.Down)) ||
            (kb.IsKeyDown(Keys.S) && !_prevKb.IsKeyDown(Keys.S)))
            _menuSelection = (_menuSelection + 1) % 5;
            
        if (kb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter))
        {
            if (_menuSelection == 4) { Exit(); return; }
            _menuFlashTimer = 0.8f;
            _menuFlashSelection = _menuSelection;
            _menuTransitioning = true;
            if (_sfxHit != null) _sfxHit.Play(0.5f, 0.2f, 0f);
        }
        
        if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
            _state = GameState.TitleScreen;
    }
    
