    private void TriggerRoomCleared(string roomName = null)
    {
        _roomClearedTimer = 3f;
        _roomClearedText = roomName != null ? $"{roomName} Complete!" : "Room Cleared!";
        _trauma = MathF.Min(_trauma + 0.15f, 1f);
        // Big celebration particles
        for (int p = 0; p < 50; p++)
        {
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float speed = 40f + (float)_rng.NextDouble() * 100f;
            _particles.Add(new Particle
            {
                Position = new Vector2(ScreenW / 2, ScreenH / 2),
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                Life = 1.5f + (float)_rng.NextDouble() * 1f,
                MaxLife = 2.5f,
                Color = Color.Lerp(new Color(255, 215, 0), new Color(255, 140, 40), (float)_rng.NextDouble()),
                Size = 2f + (float)_rng.NextDouble() * 3f,
            });
        }
    }
    
