    private void InitAwakeningRoomContent(int screen)
    {
        // Don't re-init rooms that are already cleared
        _npcs.Clear();
        
        // ═══ Torches — always set up (persist across clears) ═══
        _torches.Clear();
        int ax = _arena.Left, ay = _arena.Top, aw = _arena.Width, ah = _arena.Height;
        switch (screen)
        {
            case 1:
                _torches.Add(new Vector2(ax + 60, ay + 60));
                _torches.Add(new Vector2(ax + aw - 60, ay + 60));
                _torches.Add(new Vector2(ax + 60, ay + ah - 60));
                _torches.Add(new Vector2(ax + aw - 60, ay + ah - 60));
                break;
            case 2: // Armory — torches along walls
                _torches.Add(new Vector2(ax + 100, ay + 80));
                _torches.Add(new Vector2(ax + aw - 100, ay + 80));
                _torches.Add(new Vector2(ax + aw / 2, ay + ah - 60));
                break;
            case 3: // Proving Grounds — scattered
                _torches.Add(new Vector2(ax + 80, ay + ah / 2));
                _torches.Add(new Vector2(ax + aw - 80, ay + ah / 2));
                break;
            // Room 4 torches are set in InitAwakeningRoom4()
            case 5: // Awakening hub — warm and well-lit
                _torches.Add(new Vector2(ax + 120, ay + 80));
                _torches.Add(new Vector2(ax + aw - 120, ay + 80));
                _torches.Add(new Vector2(ax + aw / 2, ay + 60));
                _torches.Add(new Vector2(ax + 120, ay + ah - 60));
                _torches.Add(new Vector2(ax + aw - 120, ay + ah - 60));
                break;
            case 6: // Wellspring — essence crystals provide most light, just corners
                _torches.Add(new Vector2(ax + 50, ay + 50));
                _torches.Add(new Vector2(ax + aw - 50, ay + 50));
                break;
            case 7: // Lady's Shrine — ceremonial
                _torches.Add(new Vector2(ax + 100, ay + 100));
                _torches.Add(new Vector2(ax + aw - 100, ay + 100));
                _torches.Add(new Vector2(ax + aw / 2, ay + 60));
                break;
            case 8: // Lava Sanctum — lava provides light, minimal torches
                _torches.Add(new Vector2(ax + 60, ay + 60));
                _torches.Add(new Vector2(ax + aw - 60, ay + 60));
                break;
            case 9: // Bone Wyrm — ominous, few torches
                _torches.Add(new Vector2(ax + 80, ay + 80));
                _torches.Add(new Vector2(ax + aw - 80, ay + 80));
                break;
            case 11: // The Depths — tall scrolling room, torches down both sides
                for (int ti = 0; ti < 6; ti++)
                {
                    float ty = ay + 100 + ti * (ah - 200) / 5f;
                    _torches.Add(new Vector2(ax + 60, ty));
                    _torches.Add(new Vector2(ax + aw - 60, ty));
                }
                break;
        }
        
        // Auto-populate torches from painted tile data (overrides hardcoded if room has tile data)
        AddTorchesFromTiles(screen);
        
        // Early return for cleared rooms (torches already set up above)
        if (_clearedScreens.Contains(screen))
        {
            if (screen == 4) InitAwakeningRoom4Npcs();
            if (screen == 8) InitRoom8Lava();
            return;
        }
        _sigils.Clear();
        _sigilParticles.Clear();
        _essenceCrystals.Clear();
        
        switch (screen)
        {
            case 1: InitAwakeningRoom1(); break;
            case 3: InitAwakeningRoom3(); break;
            case 4: InitAwakeningRoom4(); break;
            case 6: InitAwakeningRoom6(); break;
            case 7: InitAwakeningRoom7(); break;
            case 8: InitAwakeningRoom8(); break;
            case 9: InitAwakeningRoom9(); break;
            case 11: InitAwakeningRoom11(); break;
            case 5: InitAwakeningRoom5Content(); break;
        }
    }
    
