        _sigils.Add(new Sigil { Position = new Vector2(ax + 610, ay + 470), GlowColor = new Color(80, 255, 120), GlowTimer = 0f }); // low near mid obstacle
        _sigils.Add(new Sigil { Position = new Vector2(ax + 900, ay + 180), GlowColor = new Color(255, 160, 80), GlowTimer = 0f }); // far right, behind nothing but distance
