    private void UpdateRoom4(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 4) return;
        // Update sigil glow/shatter (always, even after cleared, so effects finish)
        for (int i = 0; i < _sigils.Count; i++)
        {
            var s = _sigils[i];
            s.GlowTimer += dt;
            if (s.ShatterTimer > 0) s.ShatterTimer -= dt;
            _sigils[i] = s;
        }
        
        // Update sigil particles
        for (int i = _sigilParticles.Count - 1; i >= 0; i--)
        {
            var p = _sigilParticles[i];
            p.Pos += p.Vel * dt;
            p.Life -= dt;
            if (p.Life <= 0) _sigilParticles.RemoveAt(i);
            else _sigilParticles[i] = p;
        }
        
        // NPC hit flash timer
        for (int i = 0; i < _npcs.Count; i++)
        {
            var n = _npcs[i];
            if (n.HitFlashTimer > 0) { n.HitFlashTimer -= dt; _npcs[i] = n; }
        }
        
        // Projectile hits on NPCs (damage but no death yet)
        for (int ni = 0; ni < _npcs.Count; ni++)
        {
            var npc = _npcs[ni];
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                if (Vector2.Distance(proj.Position, npc.Position) < 18f)
                {
                    var parms = ProjectileParams.Resolve(_loadout);
                    npc.Hp = MathF.Max(0, npc.Hp - parms.BaseDamage);
                    npc.HitFlashTimer = 0.15f;
                    _npcs[ni] = npc;
                    _projectiles.RemoveAt(pi);
                    
                    // NPC death
                    if (npc.Hp <= 0)
                    {
                        // Death particles
                        for (int dp = 0; dp < 15; dp++)
                        {
                            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float speed = 30f + (float)_rng.NextDouble() * 60f;
                            _particles.Add(new Particle
                            {
                                Position = npc.Position,
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = 0.6f, MaxLife = 0.6f,
                                Color = npc.BodyColor,
                                Size = 2f
                            });
                        }
                        _npcs.RemoveAt(ni);
                        _npcKilled.Add(_currentScreen);
                        break;
                    }
                }
            }
        }
        
        if (_clearedScreens.Contains(4))
        {
            // Post-quest: knight has idle dialogue (only after leaving and returning)
            if (_npcs.Count > 0 && !_knightDialogueStarted && _knightDialogueStep >= 10)
            {
                var npc = _npcs[0];
                float dist = Vector2.Distance(_playerPos, npc.Position);
                var kbk = Keyboard.GetState();
                if (dist < npc.InteractRadius && kbk.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E))
                {
                    _knightDialogueStarted = true;
                    _textBoxMessage = "I need to do something with my life...";
                    _textBoxWaiting = true;
                }
            }
            if (_knightDialogueStarted && _textBoxMessage == null)
            {
                _knightDialogueStarted = false;
            }
            return;
        }
        
        // NPC proximity check
        if (_knightDialogueStep == 0 && _npcs.Count > 0)
        {
            var knight = _npcs[0];
            var kbk = Keyboard.GetState();
            if (Vector2.Distance(_playerPos, knight.Position) < knight.InteractRadius && kbk.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E))
            {
                if (!_hasWand)
                {
                    _textBoxMessage = "Come back with a weapon.";
                    _textBoxWaiting = true;
                }
                else
                {
                    _knightDialogueStep = 1;
                    _textBoxMessage = "You carry the wand. Good. But a mage without a shield is a dead mage.";
                    _textBoxWaiting = true;
                }
            }
        }
        
        // Advance dialogue when text box dismissed
        if (_knightDialogueStep == 1 && _textBoxMessage == null)
        {
            _knightDialogueStep = 2;
            _textBoxMessage = "Strike the three sigils on my walls. Prove your discipline.";
            _textBoxWaiting = true;
        }
        else if (_knightDialogueStep == 2 && _textBoxMessage == null)
        {
            _knightDialogueStep = 3;
            SpawnRoom4Sigils();
        }
        
        // Check projectile hits on sigils
        if (_knightDialogueStep == 3)
        {
            for (int si = 0; si < _sigils.Count; si++)
            {
                var s = _sigils[si];
                if (s.Destroyed) continue;
                
                for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
                {
                    var proj = _projectiles[pi];
                    if (Vector2.Distance(proj.Position, s.Position) < 20f)
                    {
                        s.Destroyed = true;
                        s.ShatterTimer = 0.5f;
                        _sigils[si] = s;
                        _projectiles.RemoveAt(pi);
                        
                        // Spawn shatter particles
                        var rng = new Random();
                        for (int p = 0; p < 12; p++)
                        {
                            float angle = (float)(rng.NextDouble() * MathF.PI * 2);
                            float speed = 60f + (float)rng.NextDouble() * 100f;
                            _sigilParticles.Add((s.Position, new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed, 0.6f + (float)rng.NextDouble() * 0.4f, s.GlowColor));
                        }
                        break;
                    }
                }
            }
            
            // All sigils destroyed?
            if (_sigils.Count > 0 && _sigils.All(s => s.Destroyed))
            {
                _knightDialogueStep = 4;
                _textBoxMessage = "Well done. This shield served me through many battles. It's yours now.";
                _textBoxWaiting = true;
                _clearedScreens.Add(4);
                TriggerRoomCleared("Knight's Hall");
                
                // Spawn shield pickup near knight
                var knight = _npcs[0];
                _pickups.Add(new PickupItem
                {
                    Position = knight.Position + new Vector2(40, 0),
                    Name = "Shield",
                    DisplayText = "Shield Obtained — SPACE to dash",
                    Type = "shield",
                    Collected = false,
                    BobTimer = 0f,
                    GlowColor = new Color(80, 120, 200)
                });
                
                // Shield-dash doors now opened by dashing into them
            }
        }
    }
    
    private void DrawNPCs()
    {
        // Draw torches
        for (int ti = 0; ti < _torches.Count; ti++)
        {
            var torch = _torches[ti];
            int tx = (int)torch.X, ty = (int)torch.Y;
            float time = _totalTime + ti * 2.37f; // stagger flicker per torch
            
            // Torch pole
            DrawRect(tx - 1, ty, 3, 14, new Color(80, 60, 40));
            DrawRect(tx - 2, ty + 12, 5, 3, new Color(60, 45, 30)); // base
            
            // Flame — smooth flickering using sin combinations
            float f1 = (MathF.Sin(time * 7.3f + 1.2f) + MathF.Sin(time * 11.7f + 3.4f)) * 0.25f + 0.5f;
            float f2 = (MathF.Sin(time * 9.1f + 2.7f) + MathF.Sin(time * 13.3f + 0.8f)) * 0.25f + 0.5f;
            float sway = (MathF.Sin(time * 3.1f) + MathF.Sin(time * 4.7f + 1f)) * 1.2f;
            
            // Outer flame (orange)
            DrawRect(tx - 3 + (int)sway, ty - 10, 7, 8, new Color(255, 140, 40) * (f1 * 0.7f));
            // Inner flame (yellow) 
            DrawRect(tx - 2 + (int)sway, ty - 8, 5, 5, new Color(255, 220, 80) * (f2 * 0.8f));
            // Hot core (white-yellow)
            DrawRect(tx - 1 + (int)(sway * 0.5f), ty - 5, 3, 3, new Color(255, 250, 200) * (f1 * 0.9f));
            // Flame tip
            float tipSway = (MathF.Sin(time * 15f) + MathF.Sin(time * 21f + 2f)) * 1.5f;
            DrawRect(tx + (int)tipSway, ty - 13, 1, 3, new Color(255, 180, 60) * (f2 * 0.5f));
            
            // Additive scene glow — draws the gradient texture for smooth bloom-compatible light
            float glowPulse = 0.5f + 0.15f * (MathF.Sin(time * 3.7f) + MathF.Sin(time * 5.3f + 1f));
            if (_lightGradient != null)
            {
                int glowRad = 100;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    tx - glowRad, (ty - 4) - glowRad,
                    glowRad * 2, glowRad * 2), new Color(255, 180, 80) * glowPulse * 0.6f);
            }
        }
        
        foreach (var npc in _npcs)
        {
            int x = (int)npc.Position.X;
            int y = (int)npc.Position.Y;
            
            Color bodyCol = npc.HitFlashTimer > 0 ? Color.White : npc.BodyColor;
            Color accentCol = npc.HitFlashTimer > 0 ? Color.White : npc.AccentColor;
            
            // Sprite-based NPC knight (1st knight from sheet, columns 0-2)
            if (_playerTex != null)
            {
                int npcCol = 0; // 1st knight
                int npcFrame = 1; // standing frame (middle)
                int npcFacing = 0; // facing down (toward player)
                // Face player
                var toPlayer = _playerPos - npc.Position;
                if (MathF.Abs(toPlayer.X) > MathF.Abs(toPlayer.Y))
                    npcFacing = toPlayer.X < 0 ? 1 : 2;
                else
                    npcFacing = toPlayer.Y < 0 ? 3 : 0;
                int srcX = (npcCol + npcFrame) * KF_W;
                int srcY = npcFacing * KF_H;
                var srcRect = new Rectangle(srcX, srcY, KF_W, KF_H);
                float scale = 2.5f;
                var origin = new Vector2(KF_W / 2f, KF_H - 4f);
                Color spriteTint = npc.HitFlashTimer > 0 ? Color.White : Color.White;
                _spriteBatch.Draw(_playerTex, new Vector2(x, y + 14f), srcRect, spriteTint,
                    0f, origin, scale, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
            }
            else
            {
                // Fallback rect knight
                // Feet / boots
                DrawRect(x - 6, y + 8, 5, 6, new Color(60, 50, 40));
                DrawRect(x + 1, y + 8, 5, 6, new Color(60, 50, 40));
                // Body / armor
                DrawRect(x - 8, y - 10, 16, 20, bodyCol);
                DrawRect(x - 6, y - 8, 12, 3, bodyCol * 1.2f);
                // Pauldrons
                DrawRect(x - 10, y - 10, 4, 6, accentCol);
                DrawRect(x + 6, y - 10, 4, 6, accentCol);
                // Head / helm
                DrawRect(x - 5, y - 18, 10, 9, bodyCol);
                DrawRect(x - 3, y - 14, 6, 2, new Color(30, 30, 40));
                DrawRect(x - 1, y - 21, 2, 4, accentCol);
                // Belt
                DrawRect(x - 7, y, 14, 2, accentCol);
            }
            
            // Health bar (only show if damaged)
            if (npc.Hp < npc.MaxHp)
            {
                int barW = 30;
                int barH = 3;
                int barX = x - barW / 2;
                int barY = y - 26;
                float hpPct = npc.Hp / npc.MaxHp;
                DrawRect(barX - 1, barY - 1, barW + 2, barH + 2, Color.Black);
                DrawRect(barX, barY, barW, barH, new Color(40, 10, 10));
                DrawRect(barX, barY, (int)(barW * hpPct), barH, new Color(200, 60, 60));
            }
            
            // [E] Talk prompt for Room 4 knight
            if (_currentScreen == 4 && Vector2.Distance(_playerPos, npc.Position) < npc.InteractRadius)
            {
                string ePrompt = "[E] Talk";
                int epw = MeasureText(ePrompt, 0.8f);
                DrawTextFallback((int)npc.Position.X - epw / 2, (int)npc.Position.Y - 45, ePrompt, new Color(200, 180, 100), 0.8f);
            }
        }
    }
    
    private void DrawSigils()
    {
        foreach (var s in _sigils)
        {
            if (s.Destroyed && s.ShatterTimer <= 0) continue;
            
            int x = (int)s.Position.X;
            int y = (int)s.Position.Y;
            float glow = (MathF.Sin(s.GlowTimer * 4f) + 1f) / 2f;
            
            if (!s.Destroyed)
            {
                // Outer glow
                DrawRect(x - 14, y - 14, 28, 28, s.GlowColor * 0.1f * (0.5f + glow * 0.5f));
                // Sigil circle (square approximation)
                DrawRect(x - 10, y - 10, 20, 20, s.GlowColor * 0.3f);
                DrawRect(x - 8, y - 8, 16, 16, s.GlowColor * (0.5f + glow * 0.3f));
                // Inner symbol — cross pattern
                DrawRect(x - 1, y - 7, 2, 14, s.GlowColor * 0.9f);
                DrawRect(x - 7, y - 1, 14, 2, s.GlowColor * 0.9f);
                // Corner dots
                DrawRect(x - 5, y - 5, 2, 2, Color.White * (0.6f + glow * 0.4f));
                DrawRect(x + 3, y - 5, 2, 2, Color.White * (0.6f + glow * 0.4f));
                DrawRect(x - 5, y + 3, 2, 2, Color.White * (0.6f + glow * 0.4f));
                DrawRect(x + 3, y + 3, 2, 2, Color.White * (0.6f + glow * 0.4f));
            }
            else
            {
                // Shatter remnant — fading outline
                float a = s.ShatterTimer / 0.5f;
                DrawRect(x - 8, y - 8, 16, 16, s.GlowColor * 0.2f * a);
            }
        }
        
        // Sigil shatter particles
        foreach (var p in _sigilParticles)
        {
            float a = MathHelper.Clamp(p.Life, 0, 1);
            DrawRect((int)p.Pos.X - 1, (int)p.Pos.Y - 1, 3, 3, p.Col * a);
        }
    }
    
    private void InitAwakeningRoom6()
    {
        // "The Wellspring" — crystal cave with essence pickups
        int ax = _arena.Left;
        int ay = _arena.Top;
        
        _essenceCrystals.Clear();
        if (!_room6IntroShown)
        {
            _pendingTextBox = "A magical shrine... its waters look like they linger...";
            _room6IntroShown = true;
        }
        _room6BoneCageHp = 3;
        _room6BoneCageBroken = _unlockedEssences.Contains(Essence.Pulse);
        _room6ElectricFieldActive = !_unlockedEssences.Contains(Essence.Cinder);
        _room6ElectricFieldDissipating = 0f;
        
        // Three main crystals above pools, plus hidden Bone
        _essenceCrystals.Add(new EssenceCrystal
        {
            Position = new Vector2(ax + 280, ay + 180),
            EssenceType = Essence.Cinder,
            CrystalColor = new Color(255, 100, 30),
            PoolColor = new Color(255, 60, 20),
            BobTimer = 0f,
            Hidden = false
        });
        _essenceCrystals.Add(new EssenceCrystal
        {
            Position = new Vector2(ax + 700, ay + 180),
            EssenceType = Essence.Pulse,
            CrystalColor = new Color(200, 140, 255),
            PoolColor = new Color(160, 100, 220),
            BobTimer = 1f,
            Hidden = false
        });
        // Bone crystal — hidden inside cracked rock, must shoot to break
        if (!_unlockedEssences.Contains(Essence.Bone))
        {
        _essenceCrystals.Add(new EssenceCrystal
        {
            Position = new Vector2(ax + 560, ay + 290),
            EssenceType = Essence.Bone,
            CrystalColor = new Color(200, 190, 170),
            PoolColor = new Color(60, 50, 45),
            BobTimer = 0.5f,
            Hidden = true,
            RockHp = 3f,
            RockMaxHp = 3f,
            CrackStage = 0
        });
        }
        
        if (!_awakeningIntroShown.Contains(6))
        {
            _pendingTextBox = "The Wellspring. Essences imbue your magic with elemental power.";
            _awakeningIntroShown.Add(6);
        }
    }
    
    private void UpdateRoom6(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 6) return;
        
        // Update crystal bob and collect effects
        for (int i = 0; i < _essenceCrystals.Count; i++)
        {
            var c = _essenceCrystals[i];
            c.BobTimer += dt;
            if (c.CollectEffectTimer > 0) c.CollectEffectTimer -= dt;
            _essenceCrystals[i] = c;
        }
        
        // ═══ Room 6 Puzzle: Bone Cage around Pulse crystal ═══
        if (!_room6BoneCageBroken)
        {
            // Cage position = Pulse crystal position (ax+700, ay+180)
            Vector2 cagePos = new Vector2(_arena.Left + 700, _arena.Top + 180);
            
            // Hint text when player approaches without Bone
            if (Vector2.Distance(_playerPos, cagePos) < 50f && !_unlockedEssences.Contains(Essence.Bone))
            {
                _pickupText = "It's guarded by a bone cage... maybe bones themselves can disrupt it?"; _pickupTextTimer = 0.5f; _pickupEffectPos = cagePos;
            }
            
            // Check projectile hits on cage
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                if (!proj.Alive) continue;
                bool hit = Vector2.Distance(proj.Position, cagePos) < 22f;
                if (proj.BeamLen > 0)
                {
                    Vector2 bd = proj.BeamDirection.LengthSquared() > 0.1f ? Vector2.Normalize(proj.BeamDirection) : Vector2.UnitX;
                    Vector2 toC = cagePos - proj.Position;
                    float along = Vector2.Dot(toC, bd);
                    if (along > 0 && along < proj.BeamLen && Vector2.Distance(proj.Position + bd * along, cagePos) < 22f) hit = true;
                }
                if (!hit) continue;
                
                if (_loadout.Essence == Essence.Bone) // Bone essence projectile
                {
                    _room6BoneCageHp--;
                    if (proj.BeamLen <= 0) { proj.Alive = false; _projectiles[pi] = proj; }
                    // Crack particles
                    for (int p = 0; p < 8; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 25f + (float)_rng.NextDouble() * 40f;
                        float l = 0.3f + (float)_rng.NextDouble() * 0.2f;
                        _particles.Add(new Particle { Position = cagePos, Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd, Life = l, MaxLife = l, Color = new Color(200, 190, 170), Size = 2f });
                    }
                    _trauma = MathF.Min(_trauma + 0.08f, 1f);
                    
                    if (_room6BoneCageHp <= 0)
                    {
                        _room6BoneCageBroken = true;
                        _pickupText = "The bone cage shatters!"; _pickupTextTimer = 2f; _pickupEffectPos = cagePos;
                        // Big shatter burst
                        for (int p = 0; p < 15; p++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 50f + (float)_rng.NextDouble() * 70f;
                            float l = 0.5f + (float)_rng.NextDouble() * 0.3f;
                            _particles.Add(new Particle { Position = cagePos, Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd, Life = l, MaxLife = l, Color = new Color(220, 210, 190), Size = 3f });
                        }
                        _trauma = MathF.Min(_trauma + 0.2f, 1f);
                        SpawnExplosion(cagePos, new Color(200, 190, 170), 10, 0.4f, 12f);
                    }
                }
                else
                {
                    // Wrong element — red flash spark
                    if (proj.BeamLen <= 0) { proj.Alive = false; _projectiles[pi] = proj; }
                    _particles.Add(new Particle { Position = cagePos, Velocity = Vector2.Zero, Life = 0.15f, MaxLife = 0.15f, Color = new Color(255, 60, 60), Size = 4f });
                }
            }
        }
        
        // ═══ Room 6 Puzzle: Electric Field around Cinder crystal ═══
        if (_room6ElectricFieldActive)
        {
            Vector2 fieldPos = new Vector2(_arena.Left + 280, _arena.Top + 180);
            
            // Dissipation animation
            if (_room6ElectricFieldDissipating > 0)
            {
                _room6ElectricFieldDissipating -= dt;
                if (_room6ElectricFieldDissipating <= 0)
                {
                    _room6ElectricFieldActive = false;
                    _pickupText = "The electric field fizzles out..."; _pickupTextTimer = 2f; _pickupEffectPos = fieldPos;
                }
                // Fizzle spark particles during dissipation
                if (_rng.NextDouble() < 0.5)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle { Position = fieldPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 20f, Velocity = new Vector2(0, -30f), Life = 0.3f, MaxLife = 0.3f, Color = new Color(100, 150, 255), Size = 2f });
                }
            }
            else
            {
                // Hint text
                if (Vector2.Distance(_playerPos, fieldPos) < 50f && !_unlockedEssences.Contains(Essence.Pulse))
                {
                    _pickupText = "Electric energy crackles... it needs to be neutralized"; _pickupTextTimer = 0.5f; _pickupEffectPos = fieldPos;
                }
                
                // Ambient electric particles
                if (_rng.NextDouble() < 0.3)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float r = (float)_rng.NextDouble() * 25f;
                    _particles.Add(new Particle { Position = fieldPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r), Velocity = new Vector2((float)_rng.NextDouble() * 30f - 15f, -20f), Life = 0.2f, MaxLife = 0.2f, Color = new Color(120, 160, 255), Size = 1.5f });
                }
                
                // Check projectile hits
                for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
                {
                    var proj = _projectiles[pi];
                    if (!proj.Alive) continue;
                    bool hit = Vector2.Distance(proj.Position, fieldPos) < 25f;
                    if (proj.BeamLen > 0)
                    {
                        Vector2 bd = proj.BeamDirection.LengthSquared() > 0.1f ? Vector2.Normalize(proj.BeamDirection) : Vector2.UnitX;
                        Vector2 toC = fieldPos - proj.Position;
                        float along = Vector2.Dot(toC, bd);
                        if (along > 0 && along < proj.BeamLen && Vector2.Distance(proj.Position + bd * along, fieldPos) < 25f) hit = true;
                    }
                    if (!hit) continue;
                    
                    if (_loadout.Essence == Essence.Pulse)
                    {
                        // Pulse neutralizes the field
                        _room6ElectricFieldDissipating = 0.5f;
                        if (proj.BeamLen <= 0) { proj.Alive = false; _projectiles[pi] = proj; }
                        // Big spark burst
                        for (int p = 0; p < 12; p++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 40f + (float)_rng.NextDouble() * 60f;
                            float l = 0.3f + (float)_rng.NextDouble() * 0.2f;
                            _particles.Add(new Particle { Position = fieldPos, Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd, Life = l, MaxLife = l, Color = new Color(150, 200, 255), Size = 2.5f });
                        }
                        _trauma = MathF.Min(_trauma + 0.1f, 1f);
                        break;
                    }
                    else
                    {
                        // Wrong element — absorbed with spark
                        if (proj.BeamLen <= 0) { proj.Alive = false; _projectiles[pi] = proj; }
                        _particles.Add(new Particle { Position = fieldPos, Velocity = Vector2.Zero, Life = 0.15f, MaxLife = 0.15f, Color = new Color(255, 60, 60), Size = 4f });
                    }
                }
                
                // Block player from walking through field
                if (Vector2.Distance(_playerPos, fieldPos) < 28f)
                {
                    Vector2 push = _playerPos - fieldPos;
                    if (push.LengthSquared() < 0.01f) push = Vector2.UnitY;
                    push.Normalize();
                    _playerPos = fieldPos + push * 28f;
                }
            }
        }
        
        // Check player proximity to uncollected crystals
        for (int i = 0; i < _essenceCrystals.Count; i++)
        {
            var c = _essenceCrystals[i];
            if (c.Collected) continue;
            if (_unlockedEssences.Contains(c.EssenceType)) { c.Collected = true; _essenceCrystals[i] = c; continue; }
            
            // Bone: must be shot to break, multi-stage destruction
            if (c.Hidden)
            {
                if (c.CrackStage >= 3)
                {
                    // Rock destroyed — check if player walks to dropped essence
                    if (!c.Collected && Vector2.Distance(_playerPos, c.Position) < 24f)
                    {
                        c.Collected = true;
                        c.CollectEffectTimer = 1.0f;
                        _essenceCrystals[i] = c;
                        _unlockedEssences.Add(c.EssenceType);
                        if (_loadout.Essence == Essence.None)
                            _loadout = _loadout with { Essence = c.EssenceType };
                        _pickupFlashTimer = 0.15f;
                        _pickupText = "...Bone Essence?";
                        _pickupTextTimer = 1.5f;
                        _pickupEffectPos = c.Position;
                        PlaySfx(_sfxEssence, 0.5f);
                        RefreshCombo();
                    }
                    continue;
                }
                
                // Check projectile hits on the rock (including beams)
                for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
                {
                    var proj = _projectiles[pi];
                    if (!proj.Alive) continue;
                    
                    bool hit = false;
                    if (proj.BeamLen > 0)
                    {
                        // Beam: check if line from proj.Position along proj.Velocity direction passes near rock
                        Vector2 beamDir = proj.Velocity.LengthSquared() > 0 ? Vector2.Normalize(proj.Velocity) : (proj.BeamDirection.LengthSquared() > 0 ? Vector2.Normalize(proj.BeamDirection) : Vector2.UnitX);
                        Vector2 toRock = c.Position - proj.Position;
                        float along = Vector2.Dot(toRock, beamDir);
                        if (along > 0 && along < proj.BeamLen)
                        {
                            Vector2 closest = proj.Position + beamDir * along;
                            if (Vector2.Distance(closest, c.Position) < 20f)
                                hit = true;
                        }
                    }
                    else
                    {
                        hit = Vector2.Distance(proj.Position, c.Position) < 18f;
                    }
                    
                    if (hit)
                    {
                        if (proj.BeamLen <= 0) _projectiles.RemoveAt(pi); // don't remove beams
                        c.RockHp -= 1f;
                        c.CrackStage = (int)(c.RockMaxHp - c.RockHp);
                        
                        // Rock chip particles each hit
                        var rng2 = new Random();
                        for (int p = 0; p < 8; p++)
                        {
                            float angle = (float)(rng2.NextDouble() * MathF.PI * 2);
                            float speed = 20f + (float)rng2.NextDouble() * 40f;
                            float life = 0.3f + (float)rng2.NextDouble() * 0.2f;
                            _pickupParticles.Add(new Particle
                            {
                                Position = c.Position,
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = new Color(85, 75, 68), Size = 2f
                            });
                        }
                        
                        if (c.RockHp <= 0)
                        {
                            c.CrackStage = 3;
                            // Big shatter burst
                            for (int p = 0; p < 15; p++)
                            {
                                float angle = (float)(rng2.NextDouble() * MathF.PI * 2);
                                float speed = 40f + (float)rng2.NextDouble() * 70f;
                                float life = 0.5f + (float)rng2.NextDouble() * 0.3f;
                                _pickupParticles.Add(new Particle
                                {
                                    Position = c.Position,
                                    Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                    Life = life, MaxLife = life,
                                    Color = new Color(70, 60, 55), Size = 3f
                                });
                            }
                        }
                        
                        _essenceCrystals[i] = c;
                        break;
                    }
                }
                
                // Bone rock has collision — push player out
                if (c.CrackStage < 3)
                {
                    Rectangle rockRect = new((int)c.Position.X - 14, (int)c.Position.Y - 6, 28, 18);
                    Rectangle playerRect = new((int)_playerPos.X - 6, (int)_playerPos.Y - 6, 12, 12);
                    if (rockRect.Intersects(playerRect))
                    {
                        Vector2 push = _playerPos - c.Position;
                        if (push.LengthSquared() < 0.01f) push = Vector2.UnitY;
                        push.Normalize();
                        _playerPos += push * 2f;
                    }
                }
                continue;
            }
            
            // Block collection while barriers are active
            if (c.EssenceType == Essence.Pulse && !_room6BoneCageBroken) continue;
            if (c.EssenceType == Essence.Cinder && _room6ElectricFieldActive) continue;
            
            if (Vector2.Distance(_playerPos, c.Position) < 24f)
            {
                c.Collected = true;
                c.CollectEffectTimer = 1.0f;
                _essenceCrystals[i] = c;
                
                _unlockedEssences.Add(c.EssenceType);
                
                // Auto-equip if no essence equipped
                if (_loadout.Essence == Essence.None)
                    _loadout = _loadout with { Essence = c.EssenceType };
                
                // Flame doors now opened by shooting with Cinder
                
                // Display text (bone is subtle)
                if (!c.Hidden)
                {
                    _pickupFlashTimer = 0.2f;
                    _pickupRingRadius = 0f;
                    _pickupText = $"{c.EssenceType} Essence Obtained";
                    _pickupTextTimer = 2f;
                    _pickupEffectPos = c.Position;
                    PlaySfx(_sfxEssence);
                    
                    // Spawn burst particles in element color
                    var rng = new Random();
                    for (int p = 0; p < 20; p++)
                    {
                        float angle = (float)(rng.NextDouble() * MathF.PI * 2);
                        float speed = 40f + (float)rng.NextDouble() * 80f;
                        float life = 0.8f + (float)rng.NextDouble() * 0.4f;
                        _pickupParticles.Add(new Particle
                        {
                            Position = c.Position,
                            Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                            Life = life, MaxLife = life,
                            Color = c.CrystalColor, Size = 2f
                        });
                    }
                }
                else
                {
                    // Bone: subtler effect
                    _pickupText = "...Bone Essence?";
                    _pickupTextTimer = 1.5f;
                    _pickupEffectPos = c.Position;
                }
                
                RefreshCombo();
            }
        }
        
        // The Maw — spawns after all Room 6 essences are collected
        if (_currentScreen == 6 && !_mawSpawned 
            && _unlockedEssences.Contains(Essence.Cinder) 
            && _unlockedEssences.Contains(Essence.Pulse) 
            && _unlockedEssences.Contains(Essence.Bone))
        {
            _mawSpawned = true;
            // Spawn The Maw at center of room
            var mawPos = new Vector2(_arena.Center.X, _arena.Center.Y - 40);
            var maw = new Enemy(mawPos, 200f);
            maw.Type = EnemyType.Maw;
            maw.MaxStagger = 9999f; // unstaggerable
            maw.Size = 60f;
            maw.Speed = 20f; // slow drift
            maw.ElementType = Essence.Hollow; // void entity
            maw.Weakness = Essence.Sap; // life opposes void
            maw.AiPhase = 0;
            maw.AiStateTimer = 3f;
            maw.FacingAngle = 0f;
            _enemies.Add(maw);
            _enemyById[maw.Id] = maw;
            
            // Dramatic entrance — lights dim, screen shake
            _trauma = MathF.Min(_trauma + 0.4f, 1f);
            _hitstopTimer = 0.3f;
            _floatingTexts.Add(new FloatingText
            {
                Position = maw.Position + new Vector2(-20, -50),
                Text = "Something stirs in the dark...",
                Color = new Color(180, 40, 50),
                Life = 3f, MaxLife = 3f,
            });
        }
    }
    
    private void DrawEssenceCrystals()
    {
        if (_currentScreen != 6 || _gameMode != GameMode.Awakening) return;
        
        // Ambient mystic background effects for the whole room
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        
        // Floating motes of light
        for (int m = 0; m < 15; m++)
        {
            float mx = ax + 50 + (m * 71 + MathF.Sin(time * 0.4f + m * 1.3f) * 40f) % (_arena.Width - 100);
            float my = ay + 30 + (m * 53 + MathF.Cos(time * 0.3f + m * 0.9f) * 30f) % (_arena.Height - 60);
            float ma = (MathF.Sin(time * 1.5f + m * 2.1f) + 1f) / 2f * 0.4f;
            Color moteCol = m % 3 == 0 ? new Color(255, 150, 50) : m % 3 == 1 ? new Color(100, 200, 255) : new Color(200, 140, 255);
            DrawRect((int)mx, (int)my, 2, 2, moteCol * ma);
            DrawRect((int)mx - 1, (int)my, 4, 1, moteCol * ma * 0.3f);
            DrawRect((int)mx, (int)my - 1, 1, 4, moteCol * ma * 0.3f);
        }
        
        // ═══ Bone Cage around Pulse crystal ═══
        if (!_room6BoneCageBroken)
        {
            int cx = ax + 700, cy = ay + 180;
            float cageAlpha = 0.8f;
            Color boneCol = new Color(200, 190, 170);
            // Vertical bars around crystal — remove 2 bars per hit
            int barsRemaining = _room6BoneCageHp * 2; // 3 HP = 6 bars, 2 HP = 4 bars, 1 HP = 2 bars
            for (int b = 0; b < barsRemaining; b++)
            {
                float angle = b * MathF.PI * 2f / barsRemaining + time * 0.2f;
                int bx = cx + (int)(MathF.Cos(angle) * 18f);
                int by = cy + (int)(MathF.Sin(angle) * 12f);
                // Vertical bone bar
                DrawRect(bx - 1, by - 14, 3, 28, boneCol * cageAlpha);
                DrawRect(bx, by - 16, 1, 2, boneCol * (cageAlpha * 0.6f)); // top nub
                DrawRect(bx, by + 14, 1, 2, boneCol * (cageAlpha * 0.6f)); // bottom nub
                // Crack lines based on damage taken
                // Crack lines on remaining bars when damaged
                if (_room6BoneCageHp < 3)
                {
                    DrawRect(bx - 2, by + (b % 3) * 4 - 4, 5, 1, Color.DarkGray * 0.5f);
                }
            }
            // Top and bottom ring
            DrawRect(cx - 18, cy - 14, 36, 1, boneCol * (cageAlpha * 0.5f));
            DrawRect(cx - 18, cy + 14, 36, 1, boneCol * (cageAlpha * 0.5f));
        }
        
        // ═══ Electric Field around Cinder crystal ═══
        if (_room6ElectricFieldActive)
        {
            int fx = ax + 280, fy = ay + 180;
            float fieldAlpha = _room6ElectricFieldDissipating > 0 ? _room6ElectricFieldDissipating / 0.5f : 1f;
            Color elecCol = new Color(100, 160, 255);
            // Outer crackling border
            for (int b = 0; b < 8; b++)
            {
                float angle = b * MathF.PI * 2f / 8f;
                float wobble = MathF.Sin(time * 8f + b * 2.3f) * 4f;
                int ex = fx + (int)((22f + wobble) * MathF.Cos(angle));
                int ey = fy + (int)((16f + wobble * 0.7f) * MathF.Sin(angle));
                DrawRect(ex - 1, ey - 1, 3, 3, elecCol * (fieldAlpha * 0.7f));
            }
            // Lightning arcs between border points
            for (int a = 0; a < 3; a++)
            {
                float a1 = (time * 3f + a * 2.1f) % (MathF.PI * 2f);
                float a2 = a1 + 0.8f + MathF.Sin(time * 5f + a) * 0.3f;
                int x1 = fx + (int)(20f * MathF.Cos(a1)), y1 = fy + (int)(14f * MathF.Sin(a1));
                int x2 = fx + (int)(20f * MathF.Cos(a2)), y2 = fy + (int)(14f * MathF.Sin(a2));
                // Simple 2-segment arc via small rects
                int mx2 = (x1 + x2) / 2 + (int)(MathF.Sin(time * 12f + a * 4f) * 6f);
                int my2 = (y1 + y2) / 2 + (int)(MathF.Cos(time * 10f + a * 3f) * 4f);
                DrawRect(mx2 - 1, my2 - 1, 2, 2, elecCol * (fieldAlpha * 0.6f));
                DrawRect((x1 + mx2) / 2, (y1 + my2) / 2, 2, 1, elecCol * (fieldAlpha * 0.4f));
                DrawRect((mx2 + x2) / 2, (my2 + y2) / 2, 2, 1, elecCol * (fieldAlpha * 0.4f));
            }
            // Core glow
            DrawRect(fx - 16, fy - 10, 32, 20, elecCol * (fieldAlpha * 0.08f));
            DrawRect(fx - 10, fy - 6, 20, 12, elecCol * (fieldAlpha * 0.12f));
        }
        
        foreach (var c in _essenceCrystals)
        {
            int x = (int)c.Position.X;
            int y = (int)c.Position.Y;
            float bob = MathF.Sin(c.BobTimer * 2.5f) * 3f;
            float glow = (MathF.Sin(c.BobTimer * 2f) + 1f) / 2f;
            
            if (!c.Hidden)
            {
                // Large glowing pool
                DrawRect(x - 30, y + 10, 60, 16, c.PoolColor * 0.12f);
                DrawRect(x - 24, y + 12, 48, 12, c.PoolColor * 0.2f);
                DrawRect(x - 18, y + 14, 36, 8, c.PoolColor * (0.3f + glow * 0.15f));
                DrawRect(x - 12, y + 16, 24, 4, c.PoolColor * (0.4f + glow * 0.1f));
                // Pool surface shimmer
                float shimX = MathF.Sin(c.BobTimer * 3f) * 10f;
                DrawRect(x - 6 + (int)shimX, y + 15, 8, 1, Color.White * (0.15f + glow * 0.1f));
                DrawRect(x + 4 - (int)shimX, y + 17, 6, 1, Color.White * (0.1f + glow * 0.08f));
                // Rising particle column
                for (int p = 0; p < 4; p++)
                {
                    float py = y + 8 - p * 12 - (c.BobTimer * 20f + p * 15f) % 50f;
                    float px = x + MathF.Sin(c.BobTimer * 2f + p * 1.5f) * 4f;
                    float pa = 0.3f * (1f - ((c.BobTimer * 20f + p * 15f) % 50f) / 50f);
                    DrawRect((int)px, (int)py, 2, 2, c.CrystalColor * pa);
                }
            }
            else
            {
                // Bone: cracked rock with progressive destruction
                if (c.CrackStage < 3)
                {
                    // Rock body — bigger at stage 0, chunks missing at higher stages
                    if (c.CrackStage == 0)
                    {
                        DrawRect(x - 14, y - 8, 28, 22, new Color(70, 60, 55));
                        DrawRect(x - 12, y - 6, 24, 18, new Color(85, 75, 68));
                        DrawRect(x - 16, y + 2, 32, 10, new Color(65, 55, 50));
                        // Subtle crack hints
                        DrawRect(x - 2, y - 6, 1, 8, new Color(50, 42, 38));
                        DrawRect(x + 6, y - 4, 1, 6, new Color(50, 42, 38));
                    }
                    else if (c.CrackStage == 1)
                    {
                        DrawRect(x - 14, y - 8, 28, 22, new Color(70, 60, 55));
                        DrawRect(x - 12, y - 6, 24, 18, new Color(85, 75, 68));
                        DrawRect(x - 16, y + 2, 32, 10, new Color(65, 55, 50));
                        // Visible cracks
                        DrawRect(x - 4, y - 8, 1, 14, new Color(40, 32, 28));
                        DrawRect(x + 5, y - 6, 1, 12, new Color(40, 32, 28));
                        DrawRect(x - 8, y + 1, 8, 1, new Color(40, 32, 28));
                        DrawRect(x + 2, y + 4, 7, 1, new Color(40, 32, 28));
                        // Glow through cracks
                        DrawRect(x - 3, y - 2, 1, 6, c.CrystalColor * 0.2f);
                        DrawRect(x + 5, y, 1, 4, c.CrystalColor * 0.15f);
                    }
                    else // CrackStage == 2
                    {
                        // Chunks missing, rock fragmenting
                        DrawRect(x - 12, y - 6, 10, 16, new Color(70, 60, 55));
                        DrawRect(x + 2, y - 4, 10, 14, new Color(70, 60, 55));
                        DrawRect(x - 14, y + 4, 28, 8, new Color(65, 55, 50));
                        // Big cracks with bright glow
                        DrawRect(x - 2, y - 6, 4, 16, c.CrystalColor * 0.25f);
                        DrawRect(x - 6, y + 1, 12, 2, c.CrystalColor * 0.2f);
                        // Bone glow visible through gaps
                        float boneGlow = (MathF.Sin(c.BobTimer * 3f) + 1f) / 2f;
                        DrawRect(x - 1, y - 2, 2, 6, c.CrystalColor * (0.3f + boneGlow * 0.2f));
                    }
                }
                else
                {
                    // Rock destroyed — rubble + revealed bone crystal floating above
                    DrawRect(x - 14, y + 6, 8, 4, new Color(60, 50, 45));
                    DrawRect(x + 6, y + 8, 6, 3, new Color(55, 45, 40));
                    DrawRect(x - 4, y + 10, 5, 2, new Color(50, 42, 38));
                    
                    if (!c.Collected)
                    {
                        // Revealed bone crystal bobbing above rubble
                        int dy2 = (int)(MathF.Sin(c.BobTimer * 2.5f) * 3f);
                        float bGlow = (MathF.Sin(c.BobTimer * 2f) + 1f) / 2f;
                        // Glow
                        DrawRect(x - 8, y - 14 + dy2, 16, 16, c.CrystalColor * 0.08f * (0.5f + bGlow * 0.5f));
                        // Crystal
                        DrawRect(x - 3, y - 12 + dy2, 6, 2, c.CrystalColor * 0.6f);
                        DrawRect(x - 4, y - 10 + dy2, 8, 4, c.CrystalColor * 0.8f);
                        DrawRect(x - 5, y - 6 + dy2, 10, 4, c.CrystalColor);
                        DrawRect(x - 4, y - 2 + dy2, 8, 4, c.CrystalColor * 0.8f);
                        DrawRect(x - 3, y + 2 + dy2, 6, 2, c.CrystalColor * 0.6f);
                        // Crack texture
                        DrawRect(x - 1, y - 8 + dy2, 1, 6, new Color(100, 90, 80) * 0.3f);
                    }
                }
            }
            
            if (c.Collected && c.CollectEffectTimer > 0)
            {
                float t = c.CollectEffectTimer;
                float radius = (1f - t) * 40f;
                
                if (c.EssenceType == Essence.Cinder)
                {
                    for (int ff = 0; ff < 8; ff++)
                    {
                        float angle = ff * MathF.PI / 4f + c.BobTimer;
                        int fx2 = x + (int)(MathF.Cos(angle) * radius);
                        int fy2 = y + (int)(MathF.Sin(angle) * radius * 0.6f);
                        DrawRect(fx2 - 2, fy2 - 5, 4, 10, c.CrystalColor * t);
                        DrawRect(fx2 - 1, fy2 - 7, 2, 5, new Color(255, 200, 50) * t);
                    }
                }
                else if (c.EssenceType == Essence.Silk)
                {
                    float iceW = (1f - t) * 80f;
                    DrawRect(x - (int)(iceW / 2), y + 6, (int)iceW, 8, new Color(180, 220, 255) * t * 0.5f);
                    DrawRect(x - (int)(iceW / 3), y + 8, (int)(iceW * 0.6f), 4, new Color(220, 240, 255) * t * 0.7f);
                    for (int ic = 0; ic < 5; ic++)
                    {
                        float ix = x - iceW / 2 + ic * (iceW / 4);
                        DrawRect((int)ix, y + 2, 2, 6, new Color(200, 230, 255) * t * 0.6f);
                    }
                }
                else if (c.EssenceType == Essence.Pulse)
                {
                    var rng = new Random((int)(c.BobTimer * 100));
                    for (int a = 0; a < 5; a++)
                    {
                        int ax2 = x + rng.Next(-40, 40);
                        int ay2 = y + rng.Next(-30, 30);
                        DrawRect(MathHelper.Min(x, ax2), MathHelper.Min(y, ay2), Math.Abs(ax2 - x) + 1, 1, c.CrystalColor * t * 0.8f);
                        DrawRect(ax2 - 1, ay2 - 1, 3, 3, Color.White * t * 0.6f);
                    }
                }
                else if (c.EssenceType == Essence.Bone)
                {
                    float rise = (1f - t) * 20f;
                    DrawRect(x - 2, y + 10 - (int)rise, 4, (int)rise, new Color(200, 190, 170) * t);
                    DrawRect(x - 5, y + 10 - (int)rise, 2, 4, new Color(180, 170, 150) * t);
                    DrawRect(x + 3, y + 10 - (int)rise, 2, 4, new Color(180, 170, 150) * t);
                    DrawRect(x - 1, y + 10 - (int)rise - 2, 2, 2, new Color(160, 150, 140) * t);
                }
                continue;
            }
            
            if (c.Collected) continue;
            if (c.Hidden) continue;
            
            int dy = (int)bob;
            
            // Ambient glow aura
            DrawRect(x - 16, y - 18 + dy, 32, 32, c.CrystalColor * 0.06f * (0.5f + glow * 0.5f));
            DrawRect(x - 12, y - 14 + dy, 24, 24, c.CrystalColor * 0.1f * (0.6f + glow * 0.4f));
            
            // Crystal body
            DrawRect(x - 3, y - 16 + dy, 6, 2, c.CrystalColor * 0.7f);
            DrawRect(x - 5, y - 14 + dy, 10, 4, c.CrystalColor * 0.9f);
            DrawRect(x - 6, y - 10 + dy, 12, 6, c.CrystalColor);
            DrawRect(x - 5, y - 4 + dy, 10, 4, c.CrystalColor * 0.9f);
            DrawRect(x - 3, y + dy, 6, 2, c.CrystalColor * 0.7f);
            
            DrawRect(x - 2, y - 10 + dy, 4, 4, Color.White * (0.3f + glow * 0.2f));
            DrawRect(x - 4, y - 8 + dy, 1, 6, Color.White * 0.15f);
            DrawRect(x + 3, y - 8 + dy, 1, 6, Color.White * 0.15f);
            
            DrawRect(x, y - 40 + dy, 1, 24, c.CrystalColor * 0.2f);
            DrawRect(x - 1, y - 35 + dy, 3, 14, c.CrystalColor * 0.1f);
        }
    }

    private void InitAwakeningRoom3()
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        
        _portalPos = new Vector2(ax + 520, ay + 260);
        _redoSigilPos = new Vector2(ax + 520, ay + 260);
        
        // If returning from portal, restore portal state
        if (!_inPortal)
        {
            _challengeWave = 0;
            _challengeActive = false;
            _challengeWaveDelay = 0;
            _challengeComplete = false;
        }
        
        if (!_awakeningIntroShown.Contains(3))
        {
            _pendingTextBox = "The Proving Grounds. Step through the portal... if you dare.";
            _awakeningIntroShown.Add(3);
        }
        
        // Webspinner spiders — lurk on ceiling
        for (int si = 0; si < 3; si++)
        {
            var spider = new Enemy(new Vector2(ax + 200 + si * 200, ay + 60), 35f);
            spider.Type = EnemyType.Webspinner;
            spider.BaseColor = new Color(60, 50, 70);
            spider.Size = 12f;
            spider.Speed = 65f;
            spider.AiPhase = 0;
            spider.AiStateTimer = 1.5f + si * 0.8f;
            spider.DropEssence = Essence.Silk;
            spider.ElementType = Essence.Silk;
            spider.Weakness = Essence.Cinder;
            spider.SpawnTimer = 0;
            _enemies.Add(spider);
            _enemyById[spider.Id] = spider;
        }
    }
    
    private void UpdateRoom3(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 3)
        {
            if (_inPortal) { _inPortal = false; _portalTransitioning = false; _challengeActive = false; }
            return;
        }
        
        // Portal transition
        if (_portalTransitioning)
        {
            _portalTransitionTimer -= dt;
            if (_portalTransitionTimer <= 0)
            {
                _portalTransitioning = false;
                if (_portalEntering)
                {
                    _inPortal = true;
                    _playerPos = new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height - 60);
                    _enemies.Clear();
                    _enemyById.Clear();
                    _lingerZones.Clear();
                    _projectiles.Clear();
                    _boneStakes.Clear();
                    _challengeWave = 0;
                    _challengeActive = true;
                    _challengeWaveDelay = 1.5f; // brief pause before wave 1
                    _challengeWaveMax = 3;
                    _textBoxMessage = "Survive the trial.";
                    _textBoxWaiting = true;
                }
                else
                {
                    _inPortal = false;
                    _playerPos = _portalPos + new Vector2(0, 30);
                }
            }
            return; // block gameplay during transition
        }
        
        // Lightning in portal arena
        if (_inPortal)
        {
            _lightningTimer -= dt;
            if (_lightningTimer <= 0)
            {
                _lightningTimer = 2f + (float)_rng.NextDouble() * 2.5f;
                _lightningFlash = 0.15f;
                _lightningStrikePos = new Vector2(_arena.Left + 60 + _rng.Next(_arena.Width - 120), _arena.Top + 60 + _rng.Next(_arena.Height - 120));
                _lightningStrikeTimer = 1.5f; // longer linger
            }
            if (_lightningFlash > 0) _lightningFlash -= dt;
            
            // Lightning strike hazard
            if (_lightningStrikeTimer > 0)
            {
                _lightningStrikeTimer -= dt;
                // Multi-flicker: flash the screen white several times in first 0.5s
                if (_lightningStrikeTimer > 1.0f)
                {
                    float flickerPhase = (_lightningStrikeTimer - 1.0f) * 16f;
                    if (((int)flickerPhase) % 3 == 0) _lightningFlash = 0.05f;
                }
                // Spawn electric particles — more during active bolt, fewer during linger
                int particleCount = _lightningStrikeTimer > 1.0f ? 5 : 2;
                for (int ep = 0; ep < particleCount; ep++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float speed = 15f + (float)_rng.NextDouble() * 50f;
                    float life = 0.3f + (float)_rng.NextDouble() * 0.4f;
                    _particles.Add(new Particle
                    {
                        Position = _lightningStrikePos + new Vector2((float)(_rng.NextDouble() - 0.5) * 30f, (float)(_rng.NextDouble() - 0.5) * 30f),
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                        Life = life, MaxLife = life,
                        Color = _rng.NextDouble() < 0.4 ? Color.White : new Color(150, 180, 255),
                        Size = 1f + (float)_rng.NextDouble() * 2f
                    });
                }
                // Deal damage in first 0.3s
                if (_lightningStrikeTimer > 1.2f && _iFrameTimer <= 0)
                {
                    float dist = Vector2.Distance(_playerPos, _lightningStrikePos);
                    if (dist < 45f)
                    {
                        _playerHp -= 15;
                        _iFrameTimer = 0.8f;
                        _trauma = MathF.Min(_trauma + 0.6f, 1f);
                        if (_sfxHit != null) _sfxHit.Play(0.7f, 0f, 0f);
                    }
                }
            }
            
            // Clamp player to floating island platform
            int platY = _arena.Top + _arena.Height - 80;
            int platX = _arena.Left + 60;
            int platW = _arena.Width - 120;
            _playerPos.X = MathHelper.Clamp(_playerPos.X, _arena.Left + PlayerSize, _arena.Right - PlayerSize);
            _playerPos.Y = MathHelper.Clamp(_playerPos.Y, _arena.Top + PlayerSize, _arena.Bottom - PlayerSize);
        }
        
        // Portal entry (not in portal, walk near portal, must press E)
        if (!_inPortal && !_portalTransitioning && !_challengeComplete && Vector2.Distance(_playerPos, _portalPos) < 45f)
        {
            var kb2 = Keyboard.GetState();
            bool eDown = kb2.IsKeyDown(Keys.E);
            bool ePrev = _prevKb.IsKeyDown(Keys.E);
            if (eDown && !ePrev)
            {
                _portalTransitioning = true;
                _portalTransitionTimer = 0.6f;
                _portalEntering = true;
                _inTransition = false;
                _transitionOffset = Vector2.Zero;
                _screenTransitionTimer = 0;
            }
        }
        
        // Redo sigil interaction
        if (!_inPortal && _challengeComplete && Vector2.Distance(_playerPos, _redoSigilPos) < 28f)
        {
            var kb = Keyboard.GetState();
            if (kb.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E))
            {
                _challengeRedoCount++;
                _challengeComplete = false;
                _caliburnDropped = false; // only drops first time, but keep flag
                _portalTransitioning = true;
                _portalTransitionTimer = 0.6f;
                _portalEntering = true;
                _inTransition = false;
                _transitionOffset = Vector2.Zero;
                _screenTransitionTimer = 0;
            }
        }
        
        // Wave combat inside portal
        if (_inPortal && _challengeActive)
        {
            // Wave delay
            if (_challengeWaveDelay > 0)
            {
                _challengeWaveDelay -= dt;
                if (_challengeWaveDelay <= 0)
                {
                    _challengeWave++;
                    SpawnChallengeWave(_challengeWave, _challengeRedoCount);
                }
                return;
            }
            
            // Check if all enemies dead
            bool allDead = true;
            foreach (var e in _enemies)
                if (e.Alive) { allDead = false; break; }
            
            if (allDead && _challengeWave > 0 && _challengeWaveDelay <= 0)
            {
                // Ether shard burst from center
                int shardCount = 5 + _challengeWave * 3 + _challengeRedoCount * 2;
                for (int s = 0; s < shardCount; s++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float speed = 60f + (float)_rng.NextDouble() * 100f;
                    float life = 0.8f + (float)_rng.NextDouble() * 0.5f;
                    _particles.Add(new Particle
                    {
                        Position = new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2),
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                        Life = life, MaxLife = life,
                        Color = new Color(100, 200, 255),
                        Size = 3f
                    });
                }
                
                if (_challengeWave >= _challengeWaveMax)
                {
                    // Challenge complete
                    _challengeActive = false;
                    
                    if (!_clearedScreens.Contains(3))
                    {
                        _clearedScreens.Add(3);
                        TriggerRoomCleared("Proving Grounds");
                        // Drop Caliburn Shard
                        _caliburnDropped = true;
                        _pickups.Add(new PickupItem
                        {
                            Position = new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height - 100),
                            Name = "Caliburn Shard",
                            DisplayText = "Caliburn Shard Obtained — Projectiles pierce enemies",
                            Type = "caliburn",
                            GlowColor = new Color(200, 170, 100)
                        });
                    }
                    else
                    {
                        // Redo completion — exit portal after delay
                        _challengeWaveDelay = 1.5f; // brief pause
                        // Will handle exit below
                    }
                }
                else
                {
                    _challengeWaveDelay = 1.5f; // delay before next wave
                }
            }
            
            // After redo completion, exit portal
            if (!_challengeActive && _clearedScreens.Contains(3) && _caliburnDropped == false && _challengeWaveDelay > 0)
            {
                _challengeWaveDelay -= dt;
                if (_challengeWaveDelay <= 0)
                {
                    _portalTransitioning = true;
                    _portalTransitionTimer = 0.6f;
                    _portalEntering = false;
                    _challengeComplete = true;
                }
            }
        }
        
        // After picking up Caliburn, exit portal
        if (_inPortal && !_challengeActive && !_portalTransitioning && _clearedScreens.Contains(3) && _hasCaliburn)
        {
            if (!_portalTransitioning)
            {
                _portalTransitioning = true;
                _portalTransitionTimer = 0.6f;
                _portalEntering = false;
                _challengeComplete = true;
            }
        }
    }
    
    private void SpawnChallengeWave(int wave, int redoCount)
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        float hpMult = 1f + redoCount * 0.5f;
        float spdMult = 1f + redoCount * 0.2f;
        
        int baseCount = wave + 1; // wave 1=2, wave 2=3, wave 3=4
        int count = baseCount + redoCount;
        
        for (int e = 0; e < count; e++)
        {
            float ex = ax + 100 + (float)_rng.NextDouble() * (aw - 200);
            float ey = ay + 60 + (float)_rng.NextDouble() * (ah / 2f);
            
            // Mix enemy types based on wave
            float hp = (wave == 1 ? 50f : wave == 2 ? 88f : 125f) * hpMult;
            float spd = (wave == 1 ? 60f : wave == 2 ? 45f : 80f) * spdMult;
            
            var enemy = new Enemy(new Vector2(ex, ey), hp);
            enemy.Speed = spd;
            enemy.Size = wave == 1 ? 10f : wave == 2 ? 14f : 8f;
            enemy.BaseColor = wave == 1 ? new Color(200, 60, 60) : wave == 2 ? new Color(60, 160, 60) : new Color(180, 80, 200);
            enemy.SpawnTimer = 0.5f;
            enemy.SpawnDuration = 0.5f;
            enemy.Type = wave == 1 ? EnemyType.Squire : wave == 2 ? EnemyType.GuardGargoyle : EnemyType.HollowPlate;
            
            _enemies.Add(enemy);
            _enemyById[enemy.Id] = enemy;
        }
        
        // Webspinners in wave 2+
        if (wave >= 2)
        {
            int spiderCount = wave == 2 ? 1 : 2;
            for (int si = 0; si < spiderCount; si++)
            {
                float sx = ax + 150 + (float)_rng.NextDouble() * (aw - 300);
                float sy = ay + 50 + (float)_rng.NextDouble() * 40f;
                var spider = new Enemy(new Vector2(sx, sy), (60f + wave * 10f) * hpMult);
                spider.Type = EnemyType.Webspinner;
                spider.BaseColor = new Color(60, 50, 70);
                spider.Size = 12f;
                spider.Speed = 65f * spdMult;
                spider.AiPhase = 0;
                spider.AiStateTimer = 1f + si * 0.5f;
                spider.DropEssence = Essence.Silk;
                spider.ElementType = Essence.Silk;
                spider.Weakness = Essence.Cinder;
                spider.SpawnTimer = 0.5f;
                spider.SpawnDuration = 0.5f;
                _enemies.Add(spider);
                _enemyById[spider.Id] = spider;
            }
        }
    }
    
    private void DrawRoom3Portal()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 3) return;
        
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        if (_inPortal)
        {
            // Desert floor — sandy tan with varying horizontal bands (top-down)
            for (int row = 0; row < ah; row += 8)
            {
                float sandVar = MathF.Sin(row * 0.15f + 3.7f) * 0.08f;
                int r = (int)(194 + sandVar * 40 + (row % 16 < 8 ? 0 : -8));
                int g = (int)(160 + sandVar * 30 + (row % 24 < 12 ? 0 : -6));
                int b2 = (int)(110 + sandVar * 20 + (row % 20 < 10 ? 0 : -5));
                DrawRect(ax, ay + row, aw, 8, new Color(r, g, b2));
            }
            // Subtle sand texture dots
            for (int d = 0; d < 30; d++)
            {
                int dx = ax + (d * 137 + 23) % aw;
                int dy = ay + (d * 89 + 47) % ah;
                DrawRect(dx, dy, 2, 2, new Color(180, 150, 100) * 0.15f);
            }
            
            // Cacti (top-down: green rectangles with arm stubs, 4 scattered)
            int[][] cacti = { new[]{ax+150, ay+120}, new[]{ax+400, ay+400}, new[]{ax+800, ay+150}, new[]{ax+950, ay+350} };
            foreach (var cact in cacti)
            {
                int cx2 = cact[0], cy2 = cact[1];
                // Main trunk
                DrawRect(cx2 - 4, cy2 - 16, 8, 32, new Color(50, 120, 50));
                DrawRect(cx2 - 3, cy2 - 14, 6, 28, new Color(60, 140, 55));
                // Left arm
                DrawRect(cx2 - 14, cy2 - 8, 10, 6, new Color(50, 120, 50));
                DrawRect(cx2 - 14, cy2 - 14, 6, 8, new Color(55, 130, 52));
                // Right arm
                DrawRect(cx2 + 4, cy2 + 2, 10, 6, new Color(50, 120, 50));
                DrawRect(cx2 + 8, cy2 - 4, 6, 8, new Color(55, 130, 52));
                // Shadow (top-down)
                DrawRect(cx2 + 3, cy2 + 14, 12, 4, new Color(0, 0, 0) * 0.12f);
            }
            
            // Desert walls — adobe/sandstone border
            Color wallCol = new Color(160, 130, 90);
            Color wallDark = new Color(120, 95, 65);
            int wallThick = 14;
            // Top wall
            DrawRect(ax, ay, aw, wallThick, wallCol);
            DrawRect(ax, ay + wallThick, aw, 2, wallDark);
            // Bottom wall
            DrawRect(ax, ay + ah - wallThick, aw, wallThick, wallCol);
            DrawRect(ax, ay + ah - wallThick - 2, aw, 2, wallDark);
            // Left wall
            DrawRect(ax, ay, wallThick, ah, wallCol);
            DrawRect(ax + wallThick, ay, 2, ah, wallDark);
            // Right wall
            DrawRect(ax + aw - wallThick, ay, wallThick, ah, wallCol);
            DrawRect(ax + aw - wallThick - 2, ay, 2, ah, wallDark);

            // Rain streaks (diagonal, reusing title screen weather pattern)
            for (int r2 = 0; r2 < 40; r2++)
            {
                float rx = ax + ((r2 * 73 + time * 180f) % (aw + 60)) - 30;
                float ry = ay + ((r2 * 47 + time * 320f) % (ah + 40)) - 20;
                DrawRect((int)rx, (int)ry, 1, 6, new Color(180, 180, 220) * 0.2f);
            }
            
            // Purple lightning flashes (periodic)
            float flashCycle = time % 4f;
            if (flashCycle < 0.12f)
            {
                float flashAlpha = (0.12f - flashCycle) / 0.12f;
                DrawRect(ax, ay, aw, ah, new Color(120, 60, 200) * (flashAlpha * 0.18f));
                // Purple lightning bolt
                int lx = ax + 100 + (int)((time * 137) % (aw - 200));
                int ly = ay;
                for (int seg = 0; seg < 6; seg++)
                {
                    int nlx = lx + ((seg * 17 + (int)(time * 100)) % 31) - 15;
                    int nly = ly + ah / 8;
                    DrawRect(Math.Min(lx, nlx), ly, Math.Abs(nlx - lx) + 2, nly - ly, new Color(180, 100, 255) * (flashAlpha * 0.6f));
                    lx = nlx; ly = nly;
                }
            }
            
            // Wave indicator
            if (_challengeActive && _challengeWave > 0)
            {
                string waveText = $"Wave {_challengeWave}/{_challengeWaveMax}";
                int ww = MeasureText(waveText, 1f);
                DrawTextOutlined(ax + aw / 2 - ww / 2, ay + 20, waveText, new Color(200, 170, 100), Color.Black, 1f);
            }
        }
        else
        {
            // Regular room with portal and overgrown details
            
            // Vine/overgrown details on walls
            for (int v = 0; v < 8; v++)
            {
                float vx = ax + 20 + v * (aw / 8f);
                float vy = ay + MathF.Sin(time * 0.5f + v * 1.2f) * 3f;
                DrawRect((int)vx, (int)vy, 3, 20 + v % 3 * 8, new Color(40, 80, 35) * 0.4f);
                DrawRect((int)vx + 1, (int)(vy + 8), 1, 12, new Color(60, 100, 50) * 0.3f);
            }
            
            // Crumbled stone scattered
            DrawRect(ax + 80, ay + 380, 16, 8, new Color(80, 75, 70));
            DrawRect(ax + 750, ay + 120, 12, 10, new Color(75, 70, 65));
            DrawRect(ax + 400, ay + 450, 10, 6, new Color(70, 65, 60));
            
            // Portal (shimmering oval)
            if (!_challengeComplete)
            {
                int px = (int)_portalPos.X;
                int py = (int)_portalPos.Y;
                float shimmer = (MathF.Sin(time * 3f) + 1f) / 2f;
                
                // Outer glow
                DrawRect(px - 24, py - 36, 48, 72, new Color(80, 60, 180) * 0.08f * (0.5f + shimmer * 0.5f));
                DrawRect(px - 20, py - 32, 40, 64, new Color(100, 80, 200) * 0.12f * (0.5f + shimmer * 0.5f));
                
                // Portal body (vertical oval via stacked rects)
                DrawRect(px - 8, py - 30, 16, 4, new Color(120, 100, 220) * 0.6f);
                DrawRect(px - 12, py - 26, 24, 8, new Color(140, 120, 240) * 0.7f);
                DrawRect(px - 14, py - 18, 28, 12, new Color(160, 140, 255) * (0.7f + shimmer * 0.2f));
                DrawRect(px - 16, py - 6, 32, 12, new Color(170, 150, 255) * (0.8f + shimmer * 0.15f));
                DrawRect(px - 14, py + 6, 28, 12, new Color(160, 140, 255) * (0.7f + shimmer * 0.2f));
                DrawRect(px - 12, py + 18, 24, 8, new Color(140, 120, 240) * 0.7f);
                DrawRect(px - 8, py + 26, 16, 4, new Color(120, 100, 220) * 0.6f);
                
                // Inner highlight
                DrawRect(px - 6, py - 12, 12, 24, Color.White * (0.15f + shimmer * 0.1f));
                
                // Sparkles around portal
                for (int s = 0; s < 6; s++)
                {
                    float sa = time * 2f + s * MathF.PI / 3f;
                    float sx = px + MathF.Cos(sa) * 22f;
                    float sy = py + MathF.Sin(sa) * 34f;
                    DrawRect((int)sx, (int)sy, 2, 2, new Color(200, 180, 255) * (0.3f + shimmer * 0.3f));
                }
                
                // "Press E" prompt when nearby
                if (Vector2.Distance(_playerPos, _portalPos) < 70f)
                {
                    string prompt = "[E] Enter";
                    int pw = MeasureText(prompt, 1f);
                    DrawTextOutlined(px - pw / 2, py - 48, prompt, new Color(200, 180, 255) * (0.6f + shimmer * 0.3f), Color.Black * 0.5f, 1f);
                }
                // Debug removed — now in Update
            }
            else
            {
                // Redo sigil (glowing floor symbol)
                int sx = (int)_redoSigilPos.X;
                int sy = (int)_redoSigilPos.Y;
                float pulse = (MathF.Sin(time * 2f) + 1f) / 2f;
                
                // Circle approximation
                DrawRect(sx - 16, sy - 4, 32, 8, new Color(200, 170, 100) * (0.15f + pulse * 0.1f));
                DrawRect(sx - 12, sy - 8, 24, 16, new Color(200, 170, 100) * (0.1f + pulse * 0.08f));
                DrawRect(sx - 4, sy - 12, 8, 24, new Color(200, 170, 100) * (0.1f + pulse * 0.08f));
                
                // Inner cross
                DrawRect(sx - 1, sy - 8, 2, 16, new Color(255, 220, 130) * (0.3f + pulse * 0.2f));
                DrawRect(sx - 8, sy - 1, 16, 2, new Color(255, 220, 130) * (0.3f + pulse * 0.2f));
                
                // "Press E" prompt
                if (Vector2.Distance(_playerPos, _redoSigilPos) < 50f)
                {
                    string prompt = "[E] Re-enter the Trial";
                    int pw = MeasureText(prompt, 1f);
                    DrawTextOutlined(sx - pw / 2, sy - 26, prompt, new Color(200, 170, 100), Color.Black, 1f);
                }
            }
            
            // Lightning strike visual — jagged bolt from sky + ground scorch
            if (_lightningStrikeTimer > 0)
            {
                int lx = (int)_lightningStrikePos.X;
                int ly = (int)_lightningStrikePos.Y;
                float intensity = MathHelper.Clamp(_lightningStrikeTimer / 1.5f, 0f, 1f);
                bool flickerOn = _lightningStrikeTimer > 1.0f ? (((int)(_lightningStrikeTimer * 16f)) % 3 != 2) : true;
                
                if (flickerOn && _lightningStrikeTimer > 0.5f)
                {
                    // Jagged bolt from top of screen to strike point
                    float boltAlpha = MathHelper.Clamp((_lightningStrikeTimer - 0.5f) / 1.0f, 0f, 1f);
                    Color boltCol = Color.White * boltAlpha;
                    Color boltGlow = new Color(150, 180, 255) * (boltAlpha * 0.5f);
                    int bx = lx;
                    int by = ay;
                    int segments = 8;
                    int segH = (ly - ay) / segments;
                    // Use strike pos as seed for consistent jag pattern
                    int jagSeed = (int)(_lightningStrikePos.X * 7 + _lightningStrikePos.Y * 13);
                    for (int seg = 0; seg < segments; seg++)
                    {
                        int nextX = lx + ((jagSeed + seg * 37) % 41 - 20);
                        if (seg == segments - 1) nextX = lx;
                        int nextY = by + segH;
                        // Thick bolt (3px wide glow + 1px bright core)
                        DrawRect(MathHelper.Min(bx, nextX) - 2, by, Math.Abs(nextX - bx) + 4, segH, boltGlow);
                        DrawRect(MathHelper.Min(bx, nextX), by, Math.Abs(nextX - bx) + 1, segH, boltCol);
                        bx = nextX;
                        by = nextY;
                    }
                    // Branch bolt (shorter, dimmer)
                    int branchSeg = segments / 2;
                    int branchX = lx + ((jagSeed + branchSeg * 37) % 41 - 20);
                    int branchY = ay + segH * branchSeg;
                    int branchEndX = branchX + ((jagSeed * 3) % 61 - 30);
                    int branchEndY = branchY + segH * 2;
                    DrawRect(MathHelper.Min(branchX, branchEndX), branchY, Math.Abs(branchEndX - branchX) + 1, branchEndY - branchY, boltGlow * 0.5f);
                }
                
                // Ground scorch mark (persists through full duration)
                float scorchAlpha = intensity * 0.6f;
                DrawRect(lx - 15, ly - 15, 30, 30, new Color(100, 120, 255) * (scorchAlpha * 0.15f));
                DrawRect(lx - 8, ly - 8, 16, 16, new Color(180, 200, 255) * (scorchAlpha * 0.25f));
                // Center flash (brighter when fresh)
                float centerAlpha = _lightningStrikeTimer > 1.0f ? intensity : intensity * 0.4f;
                DrawRect(lx - 4, ly - 4, 8, 8, Color.White * centerAlpha);
                DrawRect(lx - 2, ly - 2, 4, 4, new Color(200, 220, 255) * centerAlpha);
                // Electric arcs around impact
                float arcTime = _totalTime * 12f;
                for (int arc = 0; arc < 4; arc++)
                {
                    float a = arc * MathF.PI / 2f + arcTime;
                    int ax2 = lx + (int)(MathF.Cos(a) * 12f);
                    int ay2 = ly + (int)(MathF.Sin(a) * 12f);
                    DrawRect(ax2, ay2, 2, 2, new Color(150, 180, 255) * (intensity * 0.5f));
                }
            }
        }
    }
    
    private void DrawRoom3Overlay()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 3) return;
        if (!_portalTransitioning) return;
        
        // Screen warp transition effect
        float t = _portalTransitionTimer / 0.6f; // 1 → 0
        float alpha;
        if (_portalEntering)
            alpha = 1f - t; // fade to black
        else
            alpha = t; // fade from black
        
        DrawRect(0, 0, ScreenW, ScreenH, new Color(20, 15, 40) * alpha);
        
        // Warp lines
        float warpIntensity = MathF.Sin((1f - t) * MathF.PI);
        for (int w = 0; w < 8; w++)
        {
            int wy = (int)(ScreenH * (w + 0.5f) / 8f);
            int ww = (int)(warpIntensity * 200f);
            DrawRect(ScreenW / 2 - ww / 2, wy, ww, 1, new Color(160, 140, 255) * warpIntensity * 0.4f);
        }
    }
    
    private void InitAwakeningRoom7()
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        
        _shrinePos = new Vector2(ax + 520, ay + 240);
        _shrineTargetPos = new Vector2(ax + 520, ay + 380);
        
        if (!_awakeningIntroShown.Contains(7))
        {
            _pendingTextBox = "The Shrine of the Lady. The waters here remember everything.";
            _awakeningIntroShown.Add(7);
        }
    }
    
    private void UpdateRoom7(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 7) return;
        if (_clearedScreens.Contains(7))
        {
            // Secret: Linger zone in the water summons Undine
            if (!_hasUndine && !_ownsUndine)
            {
                int waterY = _arena.Top + _arena.Height - 100;
                foreach (var zone in _lingerZones)
                {
                    if (zone.Position.Y > waterY && zone.Position.X > _arena.Left + 20 && zone.Position.X < _arena.Right - 20)
                    {
                        _hasUndine = true;
                        _ownsUndine = true;
                        _undinePos = new Vector2(zone.Position.X, waterY - 20);
                        
                        for (int p = 0; p < 40; p++)
                        {
                            float angle = -MathF.PI / 2f + ((float)_rng.NextDouble() - 0.5f) * MathF.PI * 0.8f;
                            float speed = 60f + (float)_rng.NextDouble() * 120f;
                            float life = 0.8f + (float)_rng.NextDouble() * 0.6f;
                            _particles.Add(new Particle
                            {
                                Position = _undinePos,
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = new Color(80 + _rng.Next(40), 160 + _rng.Next(40), 220),
                                Size = 2f + (float)_rng.NextDouble() * 2f
                            });
                        }
                        
                        _textBoxMessage = "Something stirs beneath the surface...\nA fragment of the Lady's power bonds to you.\n\nUndine acquired — Nimue's Wisp";
                        _textBoxWaiting = true;
                        _trauma = MathF.Min(_trauma + 0.3f, 1f);
                        break;
                    }
                }
            }
            
            // Respawn Nimue's Tear if room cleared but not collected
            if (!_hasNimueTear && !_pickups.Any(p => p.Type == "nimue"))
            {
                _pickups.Add(new PickupItem
                {
                    Position = _shrinePos + new Vector2(0, -20),
                    Name = "Nimue's Tear",
                    DisplayText = "Nimue's Tear Obtained — Drain HP on hit",
                    Type = "nimue",
                    GlowColor = new Color(80, 160, 220)
                });
            }
            return;
        }
        
        // Proximity dialogue
        if (!_room7DialogueStarted && Vector2.Distance(_playerPos, _shrinePos) < 60f)
        {
            _room7DialogueStarted = true;
            _room7DialogueStep = 1;
            _textBoxMessage = "The Lady speaks: \"Two forces joined become more than their sum. Show me a Dual Combo to prove your understanding.\"";
            _textBoxWaiting = true;
        }
        
        // After first dialogue, activate quest
        if (_room7DialogueStep == 1 && _textBoxMessage == null)
        {
            _room7DialogueStep = 2;
            _room7QuestActive = true;
        }
        
        // Check projectile hits on target while quest active
        if (_room7QuestActive)
        {
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                bool shrineHit = false;
                if (proj.BeamLen > 0)
                {
                    Vector2 beamDir2 = proj.Velocity != Vector2.Zero ? Vector2.Normalize(proj.Velocity) : 
                                       (proj.BeamDirection != Vector2.Zero ? Vector2.Normalize(proj.BeamDirection) : Vector2.Zero);
                    if (beamDir2 != Vector2.Zero)
                    {
                        Vector2 toTarget = _shrineTargetPos - proj.Position;
                        float along = Vector2.Dot(toTarget, beamDir2);
                        if (along > 0 && along < proj.BeamLen)
                        {
                            Vector2 closest = proj.Position + beamDir2 * along;
                            shrineHit = Vector2.Distance(closest, _shrineTargetPos) < 40f;
                        }
                    }
                }
                else
                {
                    shrineHit = Vector2.Distance(proj.Position, _shrineTargetPos) < 40f;
                }
                if (shrineHit)
                {
                    // Check if player has 2 slots filled (dual combo potential) OR lance form
                    if (_loadout.FilledSlots >= 2 || _loadout.Form == Form.Lance)
                    {
                        _projectiles.RemoveAt(pi);
                        _room7QuestActive = false;
                        _room7DialogueStep = 3;
                        _clearedScreens.Add(7);
                        TriggerRoomCleared("Shrine of the Lady");
                        
                        // Water glow burst
                        for (int p = 0; p < 25; p++)
                        {
                            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float speed = 20f + (float)_rng.NextDouble() * 50f;
                            float life = 1f + (float)_rng.NextDouble() * 0.5f;
                            _pickupParticles.Add(new Particle
                            {
                                Position = _shrinePos,
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = new Color(80, 160, 220),
                                Size = 2f
                            });
                        }
                        
                        // Spawn Nimue's Tear
                        _pickups.Add(new PickupItem
                        {
                            Position = _shrinePos + new Vector2(0, -20),
                            Name = "Nimue's Tear",
                            DisplayText = "Nimue's Tear Obtained — Drain HP on hit",
                            Type = "nimue",
                            GlowColor = new Color(80, 160, 220)
                        });
                        
                        _textBoxMessage = "The waters accept your offering. The Lady's blessing is yours.";
                        _textBoxWaiting = true;
                        break;
                    }
                    else
                    {
                        // Wrong — not a dual combo
                        _projectiles.RemoveAt(pi);
                        // Small rejection spark
                        SpawnExplosion(proj.Position, new Color(100, 100, 120), 4, 0.15f, 3f);
                        break;
                    }
                }
            }
        }
    }
    
    private void DrawRoom7Shrine()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 7) return;
        
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        int sx = (int)_shrinePos.X;
        int sy = (int)_shrinePos.Y;
        
        // Water pool — defined rectangular pool with stone borders
        int poolX = ax + 80, poolY = ay + ah - 140, poolW = aw - 160, poolH = 120;
        
        // Stone border
        DrawRect(poolX - 6, poolY - 6, poolW + 12, poolH + 12, new Color(90, 85, 95));
        DrawRect(poolX - 4, poolY - 4, poolW + 8, poolH + 8, new Color(75, 70, 80));
        DrawRect(poolX - 2, poolY - 2, poolW + 4, poolH + 4, new Color(65, 60, 70));
        
        // Water body — scrolling noise texture
        DrawScrollingNoiseWater(poolX, poolY, poolW, poolH, time);
        
        // Sparkle/shimmer particles on surface
        for (int m = 0; m < 16; m++)
        {
            float mx = poolX + 10 + (m * 73 + MathF.Sin(time * 0.6f + m * 2.1f) * 15f) % (poolW - 20);
            float my = poolY + 8 + (m * 41) % (poolH - 16);
            float sparkle = (MathF.Sin(time * 3f + m * 1.7f) + 1f) / 2f;
            if (sparkle > 0.7f) // only show bright sparkles
            {
                float sa = (sparkle - 0.7f) / 0.3f * 0.6f;
                DrawRect((int)mx, (int)my, 2, 2, Color.White * sa);
                DrawRect((int)mx - 1, (int)my, 4, 1, new Color(180, 220, 255) * (sa * 0.5f));
                DrawRect((int)mx, (int)my - 1, 1, 4, new Color(180, 220, 255) * (sa * 0.5f));
            }
        }
        
        // Ripple circles expanding and fading
        for (int r = 0; r < 3; r++)
        {
            float rippleTime = (time * 0.4f + r * 1.3f) % 3f;
            float rippleRadius = rippleTime * 20f;
            float rippleAlpha = MathF.Max(0, 1f - rippleTime / 3f) * 0.25f;
            float rcx = poolX + poolW * (0.25f + r * 0.25f);
            float rcy = poolY + poolH * 0.5f + MathF.Sin(r * 2.1f) * 15f;
            int rr = (int)rippleRadius;
            // Draw as horizontal and vertical lines forming a diamond/circle approx
            DrawRect((int)(rcx - rr), (int)rcy, rr * 2, 1, new Color(120, 190, 240) * rippleAlpha);
            DrawRect((int)rcx, (int)(rcy - rr), 1, rr * 2, new Color(120, 190, 240) * rippleAlpha);
            DrawRect((int)(rcx - rr / 2), (int)(rcy - rr / 2), 1, rr, new Color(120, 190, 240) * (rippleAlpha * 0.5f));
            DrawRect((int)(rcx + rr / 2), (int)(rcy - rr / 2), 1, rr, new Color(120, 190, 240) * (rippleAlpha * 0.5f));
        }
        
        // Shrine base (stone altar)
        DrawRect(sx - 30, sy + 10, 60, 16, new Color(70, 65, 75));
        DrawRect(sx - 26, sy + 6, 52, 6, new Color(80, 75, 85));
        DrawRect(sx - 22, sy + 2, 44, 6, new Color(85, 80, 90));
        // Decorative edge
        DrawRect(sx - 28, sy + 24, 56, 3, new Color(60, 55, 65));
        
        // Chalice
        DrawRect(sx - 4, sy - 8, 8, 4, new Color(160, 140, 100)); // rim
        DrawRect(sx - 6, sy - 4, 12, 8, new Color(140, 120, 80)); // bowl
        DrawRect(sx - 3, sy + 4, 6, 6, new Color(120, 100, 70));  // stem
        DrawRect(sx - 5, sy + 10, 10, 3, new Color(140, 120, 80)); // base
        
        // Water glow in chalice
        float chaliceGlow = (MathF.Sin(time * 2f) + 1f) / 2f;
        DrawRect(sx - 4, sy - 6, 8, 4, new Color(80, 160, 220) * (0.3f + chaliceGlow * 0.2f));
        
        // Shrine glow aura
        DrawRect(sx - 40, sy - 20, 80, 60, new Color(80, 160, 220) * 0.04f * (0.5f + chaliceGlow * 0.5f));
        
        // If quest complete, Nimue's Tear is handled by pickup system
        // If quest not started, chalice has a soft beam
        if (!_clearedScreens.Contains(7))
        {
            DrawRect(sx, sy - 30, 1, 22, new Color(80, 160, 220) * 0.15f);
            DrawRect(sx - 1, sy - 25, 3, 14, new Color(80, 160, 220) * 0.08f);
        }
        
        // Quest target (glowing circle on the water)
        if (_room7QuestActive)
        {
            int tx = (int)_shrineTargetPos.X;
            int ty = (int)_shrineTargetPos.Y;
            float tPulse = (MathF.Sin(time * 3f) + 1f) / 2f;
            
            // Outer ring
            DrawRect(tx - 18, ty - 4, 36, 2, new Color(200, 170, 100) * (0.3f + tPulse * 0.2f));
            DrawRect(tx - 18, ty + 2, 36, 2, new Color(200, 170, 100) * (0.3f + tPulse * 0.2f));
            DrawRect(tx - 4, ty - 18, 2, 36, new Color(200, 170, 100) * (0.3f + tPulse * 0.2f));
            DrawRect(tx + 2, ty - 18, 2, 36, new Color(200, 170, 100) * (0.3f + tPulse * 0.2f));
            
            // Inner dot
            DrawRect(tx - 2, ty - 2, 4, 4, new Color(255, 220, 130) * (0.5f + tPulse * 0.3f));
            
            // "Fire a Dual Combo here" hint
            string hint = "Dual Combo Target";
            int hw = MeasureText(hint, 1f);
            DrawTextOutlined(tx - hw / 2, ty - 30, hint, new Color(200, 170, 100) * 0.7f, Color.Black * 0.5f, 1f);
        }
        
        // Grotto rock formations on sides
        DrawRect(ax + 10, ay + 60, 40, 80, new Color(55, 50, 60));
        DrawRect(ax + 30, ay + 50, 25, 30, new Color(50, 45, 55));
        DrawRect(ax + aw - 50, ay + 60, 40, 80, new Color(55, 50, 60));
        DrawRect(ax + aw - 35, ay + 50, 25, 30, new Color(50, 45, 55));
        
        // Stalactites from ceiling
        for (int st = 0; st < 6; st++)
        {
            int stx = ax + 100 + st * (aw - 200) / 5;
            int stLen = 15 + (st * 7) % 20;
            DrawRect(stx, ay, 4, stLen, new Color(65, 60, 70));
            DrawRect(stx + 1, ay, 2, stLen + 4, new Color(55, 50, 60));
        }
    }
    
    private void InitAwakeningRoom1()
    {
        _gauntletWave = _clearedScreens.Contains(1) ? 4 : 0;
        _gauntletWaveDelay = 0;
        _gauntletStarted = _clearedScreens.Contains(1);
        _gauntletPractice = false;
        // Intro text is now shown when player walks toward center (UpdateRoom1)
    }
    
    private void SpawnGauntletWave(int wave)
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        _enemies.Clear();
        _enemyById.Clear();
        _floatingTexts.Clear();
        
        if (wave == 1)
        {
            // Swarm — 6 tiny fast enemies, weak to Linger (zone damage)
            _gauntletMatchBehavior = Behavior.Linger;
            for (int i = 0; i < 6; i++)
            {
                float ex = ax + 100 + (float)_rng.NextDouble() * (aw - 200);
                float ey = ay + 80 + (float)_rng.NextDouble() * (ah - 160);
                var e = new Enemy(new Vector2(ex, ey), 30f);
                e.Speed = 80f;
                e.Size = 6f;
                e.BaseColor = new Color(255, 100, 100);
                e.Type = EnemyType.Squire;
                e.SpawnTimer = 0.4f;
                e.SpawnDuration = 0.4f;
                e.FusionTag = "weak_linger";
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
        else if (wave == 2)
        {
            // Armored heavy — 3 slow tough enemies, weak to Shatter (fragments bypass armor)
            _gauntletMatchBehavior = Behavior.Shatter;
            for (int i = 0; i < 3; i++)
            {
                float ex = ax + 200 + i * 300;
                float ey = ay + ah / 2;
                var e = new Enemy(new Vector2(ex, ey), 200f);
                e.Speed = 30f;
                e.Size = 18f;
                e.BaseColor = new Color(140, 140, 160);
                e.Type = EnemyType.TowerGuard;
                e.SpawnTimer = 0.5f;
                e.SpawnDuration = 0.5f;
                e.FusionTag = "weak_shatter";
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
        else if (wave == 3)
        {
            // Evasive teleporters — 4 enemies that blink around, weak to Bloom (homing)
            _gauntletMatchBehavior = Behavior.Bloom;
            for (int i = 0; i < 4; i++)
            {
                float ex = ax + 150 + (float)_rng.NextDouble() * (aw - 300);
                float ey = ay + 100 + (float)_rng.NextDouble() * (ah - 200);
                var e = new Enemy(new Vector2(ex, ey), 63f);
                e.Speed = 90f;
                e.Size = 10f;
                e.BaseColor = new Color(160, 80, 255);
                e.Type = EnemyType.HedgeSniper; // pops up, fires, relocates
                e.SpawnTimer = 0.4f;
                e.SpawnDuration = 0.4f;
                e.FusionTag = "weak_bloom";
                e.AiStateTimer = 1f + (float)_rng.NextDouble() * 2f; // teleport timer
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
        else if (wave == 4)
        {
            // Charger rush — 3 chargers that telegraph and lunge
            _gauntletMatchBehavior = Behavior.Linger; // zone damage punishes predictable paths
            for (int i = 0; i < 3; i++)
            {
                float ex = ax + 150 + i * (aw - 300) / 2;
                float ey = ay + 80 + (float)_rng.NextDouble() * (ah - 160);
                var e = new Enemy(new Vector2(ex, ey), 120f);
                e.Speed = 70f;
                e.Size = 14f;
                e.BaseColor = new Color(180, 120, 60);
                e.Type = EnemyType.Charger;
                e.SpawnTimer = 0.5f;
                e.SpawnDuration = 0.5f;
                e.AiStateTimer = 1f + i * 0.8f; // stagger first charges
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
        else if (wave == 5)
        {
            // Gremlin swarm — 8 tiny bouncing chaos
            _gauntletMatchBehavior = Behavior.Bloom; // homing catches erratic movement
            for (int i = 0; i < 8; i++)
            {
                float ex = ax + 80 + (float)_rng.NextDouble() * (aw - 160);
                float ey = ay + 60 + (float)_rng.NextDouble() * (ah - 120);
                var e = new Enemy(new Vector2(ex, ey), 25f);
                e.Speed = 120f;
                e.Size = 6f;
                e.BaseColor = new Color(80, 200, 80);
                e.Type = EnemyType.Gremlin;
                e.SpawnTimer = 0.3f;
                e.SpawnDuration = 0.3f;
                e.AiStateTimer = 0.1f + (float)_rng.NextDouble() * 0.4f;
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
        else if (wave == 6)
        {
            // Wraith ambush — 3 wraiths + 2 squires (wraiths vanish, squires distract)
            _gauntletMatchBehavior = Behavior.Shatter; // burst when they materialize
            for (int i = 0; i < 3; i++)
            {
                float ex = ax + 200 + (float)_rng.NextDouble() * (aw - 400);
                float ey = ay + 100 + (float)_rng.NextDouble() * (ah - 200);
                var e = new Enemy(new Vector2(ex, ey), 80f);
                e.Speed = 60f;
                e.Size = 12f;
                e.BaseColor = new Color(120, 60, 180);
                e.Type = EnemyType.Wraith;
                e.SpawnTimer = 0.6f;
                e.SpawnDuration = 0.6f;
                e.AiStateTimer = 0.5f + i * 0.7f; // stagger materializations
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
            for (int i = 0; i < 2; i++)
            {
                float ex = ax + 100 + (float)_rng.NextDouble() * (aw - 200);
                float ey = ay + 80 + (float)_rng.NextDouble() * (ah - 160);
                var e = new Enemy(new Vector2(ex, ey), 30f);
                e.Speed = 50f;
                e.Size = 8f;
                e.BaseColor = new Color(200, 200, 200);
                e.Type = EnemyType.Squire;
                e.SpawnTimer = 0.4f;
                e.SpawnDuration = 0.4f;
                _enemies.Add(e);
                _enemyById[e.Id] = e;
            }
        }
    }
    
    private void UpdateRoom1(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 1) return;
        if (_clearedScreens.Contains(1)) return;
        
        // Start on proximity to center (only after transition completes)
        if (!_gauntletStarted && !_inTransition && _screenTransitionTimer <= 0 && Vector2.Distance(_playerPos, new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2)) < 200f)
        {
            _gauntletStarted = true;
            _gauntletWave = 1;
            _gauntletWaveDelay = 0;
            _unlockedBehaviors.Add(Behavior.Linger);
            RefreshCombo();
            _loadout = _loadout with { Behavior = Behavior.Linger };
            RefreshCombo();
            _gauntletPractice = true;
            _enemies.Add(new Enemy(new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2 - 50), 15f) { Size = 14f, Speed = 0f, BaseColor = new Color(139, 119, 101) });
            if (!_awakeningIntroShown.Contains(1))
            {
                _textBoxMessage = "The Gauntlet. The right tool for the right foe.\nTry out your new ability on this target.";
                _awakeningIntroShown.Add(1);
            }
            else
            {
                _textBoxMessage = "Try out your new ability on this target.";
            }
            _textBoxWaiting = true;
        }
        
        // Practice dummy completion check
        if (_gauntletPractice && _enemies.Count > 0 && _enemies.All(e => !e.Alive))
        {
            _gauntletPractice = false;
            _enemies.Clear();
            _enemyById.Clear();
            _gauntletWaveDelay = 1.5f;
            string waveMsg = _gauntletWave == 1 ? "Good. Now face the Swarm." :
                             _gauntletWave == 2 ? "Good. Now face the Armored." :
                             "Good. Now face the Evasive.";
            _textBoxMessage = waveMsg;
            _textBoxWaiting = true;
        }
        
        // Wave delay countdown
        if (_gauntletWaveDelay > 0)
        {
            _gauntletWaveDelay -= dt;
            if (_gauntletWaveDelay <= 0 && _gauntletWave >= 1 && _gauntletWave <= 3)
            {
                // For waves 2/3, spawn practice dummy first if behavior not yet given
                bool needsPractice = (_gauntletWave == 2 && !_unlockedBehaviors.Contains(Behavior.Shatter))
                                  || (_gauntletWave == 3 && !_unlockedBehaviors.Contains(Behavior.Bloom));
                if (needsPractice)
                {
                    if (_gauntletWave == 2)
                    {
                        _unlockedBehaviors.Add(Behavior.Shatter);
                        RefreshCombo();
                        _loadout = _loadout with { Behavior = Behavior.Shatter };
                        RefreshCombo();
                    }
                    else
                    {
                        _unlockedBehaviors.Add(Behavior.Bloom);
                        RefreshCombo();
                        _loadout = _loadout with { Behavior = Behavior.Bloom };
                        RefreshCombo();
                    }
                    _gauntletPractice = true;
                    _enemies.Add(new Enemy(new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2 - 50), 15f) { Size = 14f, Speed = 0f, BaseColor = new Color(139, 119, 101) });
                    _textBoxMessage = "Try out your new ability on this target.";
                    _textBoxWaiting = true;
                }
                else
                {
                    SpawnGauntletWave(_gauntletWave);
                }
            }
            return;
        }
        
        // Safety: if wave is active but no enemies exist and no delay, respawn
        if (_gauntletWave >= 1 && _gauntletWave <= 3 && _enemies.Count == 0 && _gauntletWaveDelay <= 0)
        {
            _gauntletPractice = false;
            SpawnGauntletWave(_gauntletWave);
        }
        
        // Check wave completion
        if (_gauntletWave >= 1 && _gauntletWave <= 3)
        {
            bool allDead = true;
            for (int i = 0; i < _enemies.Count; i++)
            {
                if (_enemies[i].Alive) { allDead = false; break; }
            }
            
            if (allDead && _enemies.Count > 0)
            {
                // Ether burst
                for (int p = 0; p < 15; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float speed = 30f + (float)_rng.NextDouble() * 60f;
                    _particles.Add(new Particle
                    {
                        Position = new Vector2(_arena.Left + _arena.Width / 2, _arena.Top + _arena.Height / 2),
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                        Life = 1f, MaxLife = 1f,
                        Color = _gauntletWave == 1 ? new Color(255, 100, 100) : _gauntletWave == 2 ? new Color(140, 140, 160) : new Color(160, 80, 255),
                        Size = 2f
                    });
                }
                
                _enemies.Clear();
                _enemyById.Clear();
                _gauntletWave++;
                _gauntletWaveDelay = 2.0f; // pause before next phase
                
                if (_gauntletWave == 4)
                {
                    // All waves complete — strip gauntlet behaviors; player must pick them up from crystals
                    _unlockedBehaviors.Remove(Behavior.Linger);
                    _unlockedBehaviors.Remove(Behavior.Shatter);
                    _unlockedBehaviors.Remove(Behavior.Bloom);
                    _loadout = _loadout with { Behavior = Behavior.None };
                    RefreshCombo();
                    
                    // Spawn behavior crystals
                    _clearedScreens.Add(1);
                    TriggerRoomCleared("The Gauntlet");
                    _textBoxMessage = "The Gauntlet is cleared. Claim your rewards.";
                    _textBoxWaiting = true;
                    
                    int cx = _arena.Left + _arena.Width / 2;
                    int cy = _arena.Top + _arena.Height / 2;
                    _pickups.Add(new PickupItem
                    {
                        Position = new Vector2(cx - 80, cy),
                        Name = "Linger",
                        DisplayText = "Linger Behavior Obtained — Creates persistent damage zones",
                        Type = "behavior_linger",
                        GlowColor = new Color(255, 100, 100)
                    });
                    _pickups.Add(new PickupItem
                    {
                        Position = new Vector2(cx, cy),
                        Name = "Shatter",
                        DisplayText = "Shatter Behavior Obtained — Projectiles fragment on impact",
                        Type = "behavior_shatter",
                        GlowColor = new Color(140, 140, 180)
                    });
                    _pickups.Add(new PickupItem
                    {
                        Position = new Vector2(cx + 80, cy),
                        Name = "Bloom",
                        DisplayText = "Bloom Behavior Obtained — Projectiles grow and home in",
                        Type = "behavior_bloom",
                        GlowColor = new Color(160, 80, 255)
                    });
                }
            }
        }
        
        // Evasive enemies teleport periodically
        for (int i = 0; i < _enemies.Count; i++)
        {
            var e = _enemies[i];
            if (!e.Alive || e.FusionTag != "weak_bloom") continue;
            if (e.StaggerTimer > 0) { _enemies[i] = e; continue; } // don't teleport while staggered
            e.AiStateTimer -= dt;
            if (e.AiStateTimer <= 0)
            {
                // Save old position for afterimage
                Vector2 oldPos = e.Position;
                // Teleport to random position
                e.Position = new Vector2(
                    _arena.Left + 100 + (float)_rng.NextDouble() * (_arena.Width - 200),
                    _arena.Top + 80 + (float)_rng.NextDouble() * (_arena.Height - 160));
                e.AiStateTimer = 1.5f + (float)_rng.NextDouble() * 2f;
                
                // Teleport afterimage particles at OLD position
                for (int p = 0; p < 8; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = oldPos,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 40f,
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = new Color(160, 80, 255) * 0.6f,
                        Size = 2f
                    });
                }
                // Brief flash at NEW position
                for (int p = 0; p < 4; p++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = e.Position,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 20f,
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(200, 120, 255) * 0.4f,
                        Size = 1.5f
                    });
                }
            }
            _enemies[i] = e;
        }
    }
    
    private void DrawRoom1Gauntlet()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 1) return;
        
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        // Dark floor tint
        DrawRect(ax, ay, aw, ah, new Color(15, 10, 10) * 0.3f);
        
        // Torches on pillars (4 corners + center)
        int[][] torchPositions = {
            new[] { ax + 150, ay + 100 },
            new[] { ax + 850, ay + 100 },
            new[] { ax + 150, ay + 410 },
            new[] { ax + 850, ay + 410 },
        };
        
        foreach (var tp in torchPositions)
        {
            int tx = tp[0] + 15;
            int ty = tp[1] - 20;
            
            // Torch bracket
            DrawRect(tx - 2, ty + 10, 4, 10, new Color(100, 80, 50));
            
            // Flame
            float flicker = MathF.Sin(time * 8f + tx * 0.1f) * 2f;
            DrawRect(tx - 3, ty + (int)flicker, 6, 8, new Color(255, 180, 40) * 0.8f);
            DrawRect(tx - 2, ty - 2 + (int)flicker, 4, 5, new Color(255, 220, 80) * 0.6f);
            DrawRect(tx - 1, ty - 4 + (int)flicker, 2, 3, new Color(255, 255, 200) * 0.4f);
            
            // Light pool on ground
            float lightPulse = (MathF.Sin(time * 3f + tx) + 1f) / 2f;
            DrawRect(tx - 20, ty + 20, 40, 20, new Color(255, 150, 40) * (0.03f + lightPulse * 0.02f));
        }
        
        // Pillar stone detail
        foreach (var wall in _screenWalls[1])
        {
            DrawRect(wall.X + 2, wall.Y + 2, wall.Width - 4, 2, new Color(80, 75, 85)); // highlight
            DrawRect(wall.X + 2, wall.Y + wall.Height - 3, wall.Width - 4, 2, new Color(40, 35, 45)); // shadow
        }
        
        // Wave indicator text (during combat)
        if (_gauntletStarted && _gauntletWave >= 1 && _gauntletWave <= 3 && _gauntletWaveDelay <= 0)
        {
            string hint = _gauntletWave == 1 ? "Equip LINGER to counter the swarm" :
                          _gauntletWave == 2 ? "Equip SHATTER to break their armor" :
                                               "Equip BLOOM \u2014 your attacks will seek out foes";
            int hw = MeasureText(hint, 1f);
            float hintAlpha = (MathF.Sin(time * 2f) + 1f) / 2f * 0.4f + 0.3f;
            DrawTextOutlined(ax + aw / 2 - hw / 2, ay + 20, hint, new Color(200, 170, 100) * hintAlpha, Color.Black * hintAlpha * 0.5f, 1f);
        }
        
        // Floating embers
        for (int e = 0; e < 8; e++)
        {
            float ex = ax + 50 + (e * 131) % (aw - 100);
            float ey = ay + ah - 10 - ((time * 25 + e * 53) % (ah + 20));
            float ea = (MathF.Sin(time * 1.8f + e * 2.3f) + 1f) / 2f * 0.4f;
            DrawRect((int)ex, (int)ey, 2, 2, new Color(255, 140, 40) * ea);
        }
    }
    
    private void InitRoom8Lava()
    {
        int ax = _arena.X, ay = _arena.Y;
        _lavaRects.Clear();
        int moatL = ax + 180, moatT = ay + 120, moatW = 660, moatH = 340;
        int islandL = ax + 400, islandT = ay + 230, islandW = 220, islandH = 120;
        _lavaRects.Add(new Rectangle(moatL, moatT, moatW, islandT - moatT));
        _lavaRects.Add(new Rectangle(moatL, islandT + islandH, moatW, moatT + moatH - islandT - islandH));
        _lavaRects.Add(new Rectangle(moatL, islandT, islandL - moatL, islandH));
        _lavaRects.Add(new Rectangle(islandL + islandW, islandT, moatL + moatW - islandL - islandW, islandH));
    }
    
    private void InitAwakeningRoom8()
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        InitRoom8Lava();
        
        // Lava moat dimensions (needed for island/bridge positioning)
        int moatL = ax + 180, moatT = ay + 120;
        int islandL = ax + 400, islandT = ay + 230, islandW = 220, islandH = 120;
        
        // Lever on outer rim (left side) to spawn bridge
        _room8LeverPos = new Vector2(ax + 80, ay + ah / 2);
        // Don't reset _room8BridgeActive — bridge persists across room transitions
        
        // Grimoire on center island pedestal
        if (!_clearedScreens.Contains(8))
        {
            _pickups.Add(new PickupItem
            {
                Position = new Vector2(islandL + islandW / 2, islandT + islandH / 2 - 10),
                Name = "Grimoire",
                DisplayText = "Grimoire Obtained — The old magic awakens",
                Type = "grimoire_awakening",
                GlowColor = new Color(180, 120, 255)
            });
        }
        
    }
    
    private void UpdateRoom8(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 8) return;
        
        // Lever interaction — press E near lever to spawn bridge
        var kb = Keyboard.GetState();
        if (!_room8BridgeActive && Vector2.Distance(_playerPos, _room8LeverPos) < 30f && kb.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E))
        {
            _room8BridgeActive = true;
            _trauma = MathF.Min(_trauma + 0.2f, 1f);
        }
        
        // Grimoire reveal sequence
        if (_grimoireRevealActive)
        {
            _grimoireRevealTimer -= dt;
            if (_grimoireRevealTimer <= 0)
            {
                _grimoireRevealPhase++;
                switch (_grimoireRevealPhase)
                {
                    case 1: // Slots light up
                        _grimoireRevealTimer = 2.0f;
                        break;
                    case 2: // Fusion name or "fill slots" message
                        _grimoireRevealTimer = 2.5f;
                        // Check if 3 slots filled
                        if (_loadout.FilledSlots == 3 && _hasGrimoire)
                        {
                            RefreshCombo();
                            _grimoireRevealFusion = _currentFusion;
                        }
                        break;
                    case 3: // Explosion + shake
                        _grimoireRevealTimer = 1.5f;
                        _trauma = MathF.Min(_trauma + 0.4f, 1f);
                        // Massive particle burst
                        for (int p = 0; p < 80; p++)
                        {
                            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float speed = 40f + (float)_rng.NextDouble() * 120f;
                            float life = 1f + (float)_rng.NextDouble() * 1.5f;
                            _particles.Add(new Particle
                            {
                                Position = new Vector2(ScreenW / 2, ScreenH / 2),
                                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                                Life = life, MaxLife = life,
                                Color = _rng.NextDouble() < 0.5 ? new Color(255, 215, 0) : new Color(180, 120, 255),
                                Size = 2f + (float)_rng.NextDouble() * 3f
                            });
                        }
                        // Unseal Room 9 door
                        for (int di = 0; di < _doors.Count; di++)
                        {
                            var d = _doors[di];
                            if (d.FromScreen == 8 && d.ToScreen == 9 && d.State == DoorState.Locked)
                            {
                                d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                                _doors[di] = d;
                            }
                            if (d.FromScreen == 9 && d.ToScreen == 8 && d.State == DoorState.Locked)
                            {
                                d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                                _doors[di] = d;
                            }
                        }
                        _trauma = MathF.Min(_trauma + 0.7f, 1f);
                        break;
                    case 4: // Done
                        _grimoireRevealActive = false;
                        _textBoxMessage = "The seal to the east crumbles. Something stirs beyond...";
                        _textBoxWaiting = true;
                        break;
                }
            }
            return; // Block all other updates during reveal
        }
        
        // Lava hurt cooldown
        if (_lavaHurtCooldown > 0) _lavaHurtCooldown -= dt;
        
        // Lava acts as solid wall — push player out. Obsidian platforms are safe zones.
        if (_lavaRects.Count > 0)
        {
            // Expand collision by 6px (coast border visual extends into lava zone)
            const int lavaPad = 6;
            var playerRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            foreach (var lr in _lavaRects)
            {
                var padded = new Rectangle(lr.X - lavaPad, lr.Y - lavaPad, lr.Width + lavaPad * 2, lr.Height + lavaPad * 2);
                if (!playerRect.Intersects(padded)) continue;
                
                // Check if on active bridge — but CLAMP to bridge bounds vertically
                if (_room8BridgeActive)
                {
                    int bIslandT = _arena.Top + 230, bIslandH = 120;
                    int bridgeY = bIslandT + bIslandH / 2 - 12;
                    var bridgeRect = new Rectangle(_arena.Left + 160, bridgeY - 12, 700, 28);
                    if (playerRect.Intersects(bridgeRect))
                    {
                        // On bridge — clamp to bridge vertical bounds
                        float halfP = PlayerSize / 2f;
                        if (_playerPos.Y - halfP < bridgeRect.Top)
                            _playerPos.Y = bridgeRect.Top + halfP;
                        if (_playerPos.Y + halfP > bridgeRect.Bottom)
                            _playerPos.Y = bridgeRect.Bottom - halfP;
                        playerRect = new Rectangle((int)(_playerPos.X - halfP), (int)(_playerPos.Y - halfP), (int)PlayerSize, (int)PlayerSize);
                        continue;
                    }
                }
                
                // Check if on center island
                int islandL = _arena.Left + 400, islandT = _arena.Top + 230, islandW = 220, islandH = 120;
                var islandRect = new Rectangle(islandL, islandT, islandW, islandH);
                if (playerRect.Intersects(islandRect)) continue;
                
                // Standard push-out collision (against padded rect)
                float pushLeft = playerRect.Right - padded.Left;
                float pushRight = padded.Right - playerRect.Left;
                float pushUp = playerRect.Bottom - padded.Top;
                float pushDown = padded.Bottom - playerRect.Top;
                float minPush = MathF.Min(MathF.Min(pushLeft, pushRight), MathF.Min(pushUp, pushDown));
                if (minPush == pushLeft) _playerPos.X -= pushLeft;
                else if (minPush == pushRight) _playerPos.X += pushRight;
                else if (minPush == pushUp) _playerPos.Y -= pushUp;
                else _playerPos.Y += pushDown;
                playerRect = new Rectangle((int)(_playerPos.X - PlayerSize/2), (int)(_playerPos.Y - PlayerHitboxH/2 + PlayerHitboxOffsetY), (int)PlayerSize, (int)PlayerHitboxH);
            }
        }
        
        
        // Check grimoire pickup — override normal pickup to trigger reveal sequence
        for (int i = _pickups.Count - 1; i >= 0; i--)
        {
            var p = _pickups[i];
            if (p.Type == "grimoire_awakening" && !p.Collected && Vector2.Distance(_playerPos, p.Position) < 24f)
            {
                p.Collected = true;
                _pickups[i] = p;
                _pickups.RemoveAt(i);
                _hasGrimoire = true;
                RefreshCombo();
                _clearedScreens.Add(8);
                TriggerRoomCleared("Lava Sanctum");
                
                // SOTN pickup effect
                _pickupFlashTimer = 0.3f;
                _pickupRingRadius = 0f;
                _pickupEffectPos = p.Position;
                _pickupText = p.DisplayText;
                _pickupTextTimer = 2f;
                PlaySfx(_sfxPickup);
                
                // Start reveal sequence
                _grimoireRevealActive = true;
                StopMusic(); // dramatic silence for reveal
                _grimoireRevealTimer = 1.0f; // 1s blackout
                _grimoireRevealPhase = 0;
                _grimoireRevealFusion = null;
                break;
            }
        }
        
        // Immolant spawning — triggered by bone attacks
        _immolantSpawnCooldown -= dt;
        if (_boneAttackCount8 >= 3 && _immolants.Count(im => im.Alive) < MaxImmolants && _immolantSpawnCooldown <= 0)
        {
            _boneAttackCount8 = 0;
            _immolantSpawnCooldown = 5f;
            if (_lavaRects.Count > 0)
            {
                var lava = _lavaRects[_rng.Next(_lavaRects.Count)];
                SpawnImmolant(new Vector2(lava.X + _rng.Next(lava.Width), lava.Y + _rng.Next(lava.Height)));
            }
        }
        UpdateImmolants(dt);
        
        // Lava push-back handled above in the main lava collision loop (with bridge/island checks)
    }
    
    private void DrawRoom8Lava()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 8) return;
        
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        // Volcanic floor (dark stone)
        // Lava moat — ONE continuous noise pass for the whole moat area, island drawn on top
        if (_lavaRects.Count > 0)
        {
            int moatL = ax + 180, moatT = ay + 120, moatW = 660, moatH = 340;
            DrawScrollingNoiseLava(moatL, moatT, moatW, moatH, time);
            
            // === Irregular coastline — ALttP style jagged rocky edges ===
            int iL = ax + 400, iT = ay + 230, iW = 220, iH = 120;
            float glowPulse = 0.5f + 0.2f * MathF.Sin(time * 2.5f);
            const int seg = 8; // segment size for irregular edges
            
            // Coast color layers (innermost to outermost from land)
            Color[] coastColors = {
                new Color(45, 38, 28),   // 0: stone edge
                new Color(60, 42, 22),   // 1: dark stone  
                new Color(90, 50, 18),   // 2: warm brown
                new Color(140, 65, 15),  // 3: orange-brown
                new Color(200, 85, 15),  // 4: bright orange
                new Color(255, 110, 20), // 5: lava contact
            };
            int coastLayers = coastColors.Length;
            int coastMaxPx = coastLayers * 3; // total coast width in pixels
            
            // Draw irregular coast for a rectangular region
            // Each segment along each edge has a seeded jitter
            // The jitter makes each coast layer's edge wavy
            
            // --- ISLAND coast (extends outward into lava) ---
            // Fill island first so coast layers draw ON TOP of lava behind it
            // Draw coast layers from outermost (lava side) to innermost (land side)
            for (int layer = coastLayers - 1; layer >= 0; layer--)
            {
                Color lc = coastColors[layer];
                if (layer == coastLayers - 1) lc = lc * (glowPulse); // outermost pulses
                int baseOff = (coastLayers - layer) * 3; // how far out from island edge
                
                // Top edge
                for (int sx = iL - coastMaxPx; sx < iL + iW + coastMaxPx; sx += seg)
                {
                    int hash = ((sx * 7 + 31 + layer * 53) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2; // -2 to +4
                    int drawY = iT - baseOff + jitter;
                    int drawW = seg;
                    if (sx < iL - baseOff) continue;
                    if (sx + seg > iL + iW + baseOff) continue;
                    DrawRect(sx, drawY, drawW, 3, lc);
                }
                // Bottom edge
                for (int sx = iL - coastMaxPx; sx < iL + iW + coastMaxPx; sx += seg)
                {
                    int hash = ((sx * 11 + 67 + layer * 41) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    int drawY = iT + iH + baseOff - 3 - jitter;
                    if (sx < iL - baseOff) continue;
                    if (sx + seg > iL + iW + baseOff) continue;
                    DrawRect(sx, drawY, seg, 3, lc);
                }
                // Left edge
                for (int sy = iT - coastMaxPx; sy < iT + iH + coastMaxPx; sy += seg)
                {
                    int hash = ((sy * 13 + 43 + layer * 37) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    int drawX = iL - baseOff + jitter;
                    if (sy < iT - baseOff) continue;
                    if (sy + seg > iT + iH + baseOff) continue;
                    DrawRect(drawX, sy, 3, seg, lc);
                }
                // Right edge
                for (int sy = iT - coastMaxPx; sy < iT + iH + coastMaxPx; sy += seg)
                {
                    int hash = ((sy * 17 + 89 + layer * 29) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    int drawX = iL + iW + baseOff - 3 - jitter;
                    if (sy < iT - baseOff) continue;
                    if (sy + seg > iT + iH + baseOff) continue;
                    DrawRect(drawX, sy, 3, seg, lc);
                }
            }
            
            // Island fill (on top of coast layers)
            DrawRect(iL, iT, iW, iH, new Color(25, 22, 18));
            // Top face highlight
            DrawRect(iL + 1, iT + 1, iW - 2, 3, new Color(40, 35, 28));
            // Bottom shadow
            DrawRect(iL, iT + iH - 2, iW, 2, new Color(15, 12, 8));
            // Stone texture
            for (int iy = iT + 4; iy < iT + iH - 4; iy += 10)
                for (int ix = iL + 4; ix < iL + iW - 4; ix += 12)
                {
                    int hash = (ix * 7 + iy * 13) & 0xFF;
                    if (hash < 80)
                        DrawRect(ix + (hash % 5), iy + (hash % 3), 2 + hash % 4, 2, 
                            hash < 40 ? new Color(30, 27, 22) : new Color(20, 18, 14));
                }
            
            // --- OUTER MOAT coast (extends INWARD from arena floor into lava) ---
            // Draw arena floor extensions to cover the coast zone outside moat
            DrawRect(moatL - coastMaxPx - 2, moatT - coastMaxPx - 2, moatW + coastMaxPx * 2 + 4, coastMaxPx + 2, new Color(15, 15, 20)); // top
            DrawRect(moatL - coastMaxPx - 2, moatT + moatH, moatW + coastMaxPx * 2 + 4, coastMaxPx + 2, new Color(15, 15, 20)); // bottom
            DrawRect(moatL - coastMaxPx - 2, moatT, coastMaxPx + 2, moatH, new Color(15, 15, 20)); // left
            DrawRect(moatL + moatW, moatT, coastMaxPx + 2, moatH, new Color(15, 15, 20)); // right
            
            for (int layer = coastLayers - 1; layer >= 0; layer--)
            {
                Color lc = coastColors[layer];
                if (layer == coastLayers - 1) lc = lc * (glowPulse);
                int baseOff = (coastLayers - layer) * 3;
                
                // Top edge (inside top of moat)
                for (int sx = moatL; sx < moatL + moatW; sx += seg)
                {
                    int hash = ((sx * 23 + 101 + layer * 59) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    DrawRect(sx, moatT + baseOff - 3 - jitter, seg, 3, lc);
                }
                // Bottom edge (inside bottom)
                for (int sx = moatL; sx < moatL + moatW; sx += seg)
                {
                    int hash = ((sx * 19 + 113 + layer * 47) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    DrawRect(sx, moatT + moatH - baseOff + jitter, seg, 3, lc);
                }
                // Left edge (inside left)
                for (int sy = moatT; sy < moatT + moatH; sy += seg)
                {
                    int hash = ((sy * 29 + 127 + layer * 43) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    DrawRect(moatL + baseOff - 3 - jitter, sy, 3, seg, lc);
                }
                // Right edge (inside right)
                for (int sy = moatT; sy < moatT + moatH; sy += seg)
                {
                    int hash = ((sy * 31 + 139 + layer * 37) & 0x7FFFFFFF) % 7;
                    int jitter = hash - 2;
                    DrawRect(moatL + moatW - baseOff + jitter, sy, 3, seg, lc);
                }
            }
            
            // === Surface bubbles — MUCH bigger, more visible ===
            for (int b = 0; b < 8; b++)
            {
                float bSeed = b * 47.3f;
                float bCycleTime = 3.0f + (b % 4) * 1.0f; // 3-6s cycles (slower = more visible)
                float bPhase = ((time + bSeed) % bCycleTime) / bCycleTime;
                float bx = moatL + 30 + ((b * 173 + (int)(bSeed * 3)) % (moatW - 60));
                float by = moatT + 20 + ((b * 97 + (int)(bSeed * 7)) % (moatH - 40));
                if (bx > iL - 10 && bx < iL + iW + 10 && by > iT - 10 && by < iT + iH + 10) continue;
                
                if (bPhase < 0.6f)
                {
                    // Growing dome — dark center (cooled crust) with bright rim
                    float grow = bPhase / 0.6f;
                    int bRad = 4 + (int)(grow * 12); // much bigger: up to 16px
                    float bAlpha = 0.4f + grow * 0.4f;
                    // Bright glowing rim
                    DrawRect((int)bx - bRad, (int)by - bRad, bRad * 2, 2, new Color(255, 180, 40) * bAlpha);
                    DrawRect((int)bx - bRad, (int)by + bRad - 2, bRad * 2, 2, new Color(255, 140, 20) * bAlpha);
                    DrawRect((int)bx - bRad, (int)by - bRad, 2, bRad * 2, new Color(255, 160, 30) * bAlpha);
                    DrawRect((int)bx + bRad - 2, (int)by - bRad, 2, bRad * 2, new Color(255, 160, 30) * bAlpha);
                    // Dark dome center (cooled surface)
                    if (bRad > 6)
                        DrawRect((int)bx - bRad + 3, (int)by - bRad + 3, (bRad - 3) * 2, (bRad - 3) * 2, 
                            new Color(80, 30, 10) * (bAlpha * 0.5f));
                    // Highlight on top (light catches the dome)
                    DrawRect((int)bx - 2, (int)by - bRad + 1, 4, 2, new Color(255, 255, 180) * (bAlpha * 0.6f));
                }
                else if (bPhase < 0.75f)
                {
                    // POP — bright burst
                    float pop = (bPhase - 0.6f) / 0.15f;
                    int burstRad = 12 + (int)(pop * 10);
                    float burstAlpha = (1f - pop) * 0.7f;
                    // Bright splash
                    DrawRect((int)bx - burstRad, (int)by - 2, burstRad * 2, 3, new Color(255, 220, 80) * burstAlpha);
                    DrawRect((int)bx - 2, (int)by - burstRad, 3, burstRad * 2, new Color(255, 220, 80) * burstAlpha);
                    // Splatter particles (4 directions)
                    for (int sp = 0; sp < 4; sp++)
                    {
                        float spAngle = sp * MathF.PI / 2f + 0.3f;
                        float spDist = pop * 18f;
                        int spx = (int)(bx + MathF.Cos(spAngle) * spDist);
                        int spy = (int)(by + MathF.Sin(spAngle) * spDist);
                        DrawRect(spx, spy, 3, 3, new Color(255, 160, 30) * burstAlpha);
                    }
                }
                else
                {
                    // Afterglow — fading ring
                    float fade = (bPhase - 0.75f) / 0.25f;
                    float fadeAlpha = (1f - fade) * 0.3f;
                    int fadeRad = 14 + (int)(fade * 6);
                    DrawRect((int)bx - fadeRad, (int)by - 1, fadeRad * 2, 2, new Color(200, 80, 20) * fadeAlpha);
                    DrawRect((int)bx - 1, (int)by - fadeRad, 2, fadeRad * 2, new Color(200, 80, 20) * fadeAlpha);
                }
            }
            
            // === Rising ember sparks ===
            for (int e = 0; e < 25; e++)
            {
                float eSeed = e * 31.7f;
                float eCycleTime = 1.5f + (e % 7) * 0.4f;
                float ePhase = ((time + eSeed) % eCycleTime) / eCycleTime;
                float ex = moatL + 10 + ((e * 211 + (int)(eSeed)) % (moatW - 20));
                float eyBase = moatT + ((e * 131 + (int)(eSeed * 5)) % moatH);
                if (ex > iL - 3 && ex < iL + iW + 3 && eyBase > iT - 3 && eyBase < iT + iH + 3) continue;
                float ey = eyBase - ePhase * 40f;
                float drift = MathF.Sin(time * 4f + eSeed) * 4f;
                float eAlpha = ePhase < 0.15f ? ePhase / 0.15f : (1f - ePhase) / 0.85f;
                int eSize = ePhase < 0.4f ? 3 : (ePhase < 0.7f ? 2 : 1);
                Color eCol = ePhase < 0.2f ? new Color(255, 255, 150) : (ePhase < 0.5f ? new Color(255, 180, 50) : new Color(200, 80, 20));
                DrawRect((int)(ex + drift), (int)ey, eSize, eSize, eCol * (eAlpha * 0.8f));
            }
            
            // Hot spots (bright flickers)
            for (int h = 0; h < 8; h++)
            {
                float hx = moatL + ((h * 137 + (int)(time * 20)) % moatW);
                float hy = moatT + ((h * 89 + (int)(time * 15)) % moatH);
                if (hx > iL && hx < iL + iW && hy > iT && hy < iT + iH) continue;
                float ha = (MathF.Sin(time * 3f + h * 2.1f) + 1f) / 2f * 0.4f;
                DrawRect((int)hx, (int)hy, 6, 4, new Color(255, 255, 150) * ha);
            }
        }
        
        // Solid stone bridge across lava when active
        if (_room8BridgeActive)
        {
            int bIslandT = ay + 230, bIslandH = 120;
            int bridgeY = bIslandT + bIslandH / 2 - 12;
            int bridgeX = ax + 160;
            int bridgeW = 700;
            // Shadow
            DrawRect(bridgeX, bridgeY + 2, bridgeW, 24, new Color(30, 25, 30));
            // Main stone
            DrawRect(bridgeX, bridgeY, bridgeW, 20, new Color(70, 65, 75));
            // Highlight edge
            DrawRect(bridgeX, bridgeY, bridgeW, 3, new Color(90, 85, 95));
            // Stone texture lines
            for (int s = 0; s < bridgeW; s += 40)
                DrawRect(bridgeX + s, bridgeY, 1, 20, new Color(50, 45, 55));
        }

        // Center island (dark stone, slightly elevated look)
        int islandL = ax + 400, islandT = ay + 220, islandW = 220, islandH = 140;
        DrawRect(islandL - 4, islandT - 4, islandW + 8, islandH + 8, new Color(50, 40, 45)); // shadow
        DrawRect(islandL, islandT, islandW, islandH, new Color(60, 55, 65));
        DrawRect(islandL + 4, islandT + 4, islandW - 8, 3, new Color(75, 70, 80)); // highlight edge
        
        // Grimoire pedestal on island (if not collected)
        if (!_clearedScreens.Contains(8))
        {
            int gx = islandL + islandW / 2;
            int gy = islandT + islandH / 2 - 10;
            
            // Heavy glow underneath
            float glowPulse = (MathF.Sin(time * 1.5f) + 1f) / 2f;
            DrawRect(gx - 30, gy - 10, 60, 40, new Color(120, 60, 200) * (0.06f + glowPulse * 0.04f));
            DrawRect(gx - 20, gy - 5, 40, 30, new Color(160, 100, 255) * (0.08f + glowPulse * 0.04f));
            
            // Stone pedestal
            DrawRect(gx - 12, gy + 10, 24, 8, new Color(80, 75, 90));
            DrawRect(gx - 8, gy + 6, 16, 6, new Color(90, 85, 100));
            
            // Floating book
            float bookBob = MathF.Sin(time * 2f) * 3f;
            int by = gy - 6 + (int)bookBob;
            DrawRect(gx - 10, by, 20, 14, new Color(60, 20, 100)); // cover
            DrawRect(gx - 8, by + 2, 16, 10, new Color(180, 160, 120)); // pages
            DrawRect(gx - 10, by + 6, 20, 2, new Color(100, 50, 160)); // spine
            // Glow around book
            DrawRect(gx - 14, by - 4, 28, 22, new Color(180, 120, 255) * (0.1f + glowPulse * 0.08f));
        }
        
        // Rising ember particles (ambient)
        for (int e = 0; e < 15; e++)
        {
            float ex = ax + 180 + (e * 67) % (aw - 360);
            float ey = ay + ah - 20 - ((time * 30 + e * 41) % (ah + 40));
            float ea = (MathF.Sin(time * 1.5f + e * 2.1f) + 1f) / 2f * 0.5f;
            float eSize = 1 + (e % 3);
            Color ec = e % 3 == 0 ? new Color(255, 180, 40) : e % 3 == 1 ? new Color(255, 100, 20) : new Color(255, 60, 10);
            DrawRect((int)ex, (int)ey, (int)eSize, (int)eSize, ec * ea);
        }
        
        // Heat shimmer effect (subtle horizontal line distortions above lava)
        for (int sh = 0; sh < 6; sh++)
        {
            float shx = ax + 200 + MathF.Sin(time * 0.7f + sh * 1.5f) * 10f + sh * 100;
            float shy = ay + 120 + MathF.Sin(time * 1.2f + sh) * 15f;
            DrawRect((int)shx, (int)shy, 30, 1, new Color(255, 200, 100) * 0.04f);
        }
        
        // Draw lever
        if (!_room8BridgeActive)
        {
            int lx = (int)_room8LeverPos.X;
            int ly = (int)_room8LeverPos.Y;
            // Base
            DrawRect(lx - 6, ly + 5, 12, 6, new Color(80, 70, 60));
            // Handle
            DrawRect(lx - 2, ly - 12, 4, 17, new Color(160, 140, 100));
            // Knob
            DrawRect(lx - 3, ly - 14, 6, 4, new Color(200, 180, 100));
            // Prompt
            if (Vector2.Distance(_playerPos, _room8LeverPos) < 40f)
            {
                string prompt = "[E] Pull Lever";
                int pw = MeasureText(prompt);
                DrawTextOutlined(lx - pw / 2, ly - 28, prompt, new Color(255, 220, 120), Color.Black * 0.7f);
            }
        }
        else
        {
            int lx = (int)_room8LeverPos.X;
            int ly = (int)_room8LeverPos.Y;
            DrawRect(lx - 6, ly + 5, 12, 6, new Color(80, 70, 60));
            DrawRect(lx - 8, ly + 2, 16, 4, new Color(140, 120, 80)); // pulled down
        }
    }
    
    private void DrawRoom8Reveal()
    {
        if (!_grimoireRevealActive) return;
        
        float time = _totalTime;
        
        // Full-screen black overlay
        float blackAlpha = _grimoireRevealPhase == 0 ? MathF.Min((1f - _grimoireRevealTimer) * 2f, 1f) : 1f;
        if (_grimoireRevealPhase >= 3) blackAlpha = MathF.Max(_grimoireRevealTimer / 1.5f, 0f); // fade out
        DrawRect(0, 0, ScreenW, ScreenH, Color.Black * blackAlpha);
        
        if (_grimoireRevealPhase >= 1)
        {
            // Show loadout slots lighting up one by one
            float slotProgress = _grimoireRevealPhase == 1 ? (2f - _grimoireRevealTimer) / 2f : 1f;
            int slotY = ScreenH / 2 - 40;
            
            string[] slotLabels = { _loadout.Form.ToString(), _loadout.Behavior.ToString(), _loadout.Essence.ToString() };
            Color[] slotColors = { new Color(100, 200, 255), new Color(200, 100, 255), new Color(255, 160, 60) };
            
            for (int s = 0; s < 3; s++)
            {
                float threshold = (s + 1) / 3f;
                if (slotProgress < threshold) continue;
                
                float slotAlpha = MathF.Min((slotProgress - (s / 3f)) * 3f, 1f);
                string label = slotLabels[s] == "None" ? "---" : slotLabels[s];
                int tw = MeasureText(label, 2f);
                int sx = ScreenW / 2 - tw / 2;
                int sy = slotY + s * 40;
                
                DrawTextOutlined(sx, sy, label, slotColors[s] * slotAlpha, Color.Black * slotAlpha, 2f);
            }
        }
        
        if (_grimoireRevealPhase >= 2)
        {
            // Fusion name or "fill slots" message
            float textAlpha = _grimoireRevealPhase == 2 ? MathF.Min((2.5f - _grimoireRevealTimer) / 0.5f, 1f) : 1f;
            
            if (_grimoireRevealFusion != null)
            {
                // MASSIVE gold fusion name
                int fw = MeasureText(_grimoireRevealFusion, 3f);
                DrawTextOutlined(ScreenW / 2 - fw / 2, ScreenH / 2 + 80, _grimoireRevealFusion,
                    new Color(255, 215, 0) * textAlpha, Color.Black * textAlpha, 3f);
            }
            else if (_loadout.FilledSlots < 3)
            {
                string msg = "Fill all three slots to unleash your true power";
                int mw = MeasureText(msg, 1.5f);
                DrawTextOutlined(ScreenW / 2 - mw / 2, ScreenH / 2 + 80, msg,
                    new Color(200, 170, 100) * textAlpha, Color.Black * textAlpha, 1.5f);
            }
            else
            {
                string msg = "The Grimoire pulses with unfamiliar energy...";
                int mw = MeasureText(msg, 1.5f);
                DrawTextOutlined(ScreenW / 2 - mw / 2, ScreenH / 2 + 80, msg,
                    new Color(180, 120, 255) * textAlpha, Color.Black * textAlpha, 1.5f);
            }
        }
    }
    
    // ========================== ROOM 9 — BONE WYRM ==========================
    
    private void InitAwakeningRoom9()
    {
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        _bossLavaPools.Clear();
        
        if (_clearedScreens.Contains(9))
        {
            _bossActive = false;
            _bossDead = true;
            return;
        }
        
        // Init segments in a coiled position at center
        _bossSegments = new Vector2[_bossSegmentCount];
        _bossSegmentAngles = new float[_bossSegmentCount];
        Vector2 center = new Vector2(ax + aw / 2, ay + ah / 2);
        for (int i = 0; i < _bossSegmentCount; i++)
        {
            float a = i * 0.5f;
            _bossSegments[i] = center + new Vector2(MathF.Cos(a) * i * 5f, MathF.Sin(a) * i * 5f);
            _bossSegmentAngles[i] = a;
        }
        
        _bossHp = 300f;
        _bossMaxHp = 300f;
        _bossPhase = 0;
        _bossSpeed = 0;
        _bossAngle = 0;
        _bossActive = false;
        _bossDead = false; _victoryPlayed = false;
        _bossHitFlash = 0;
        _bossRageTimer = 0;
        _bossIntroTimer = 0;
        _bossIntroDone = false;
        _bossDeathTimer = 0;
        _bossLavaTimer = 0;
        
        if (!_awakeningIntroShown.Contains(9))
        {
            _awakeningIntroShown.Add(9);
        }
    }
    
    private void InitAwakeningRoom11()
    {
        // "The Depths" — tall scrolling test room, 1280×1440
        int ax = _arena.Left, ay = _arena.Top, aw = _arena.Width, ah = _arena.Height;
        float cx = ax + aw / 2f;
        
        void AddEnemy(EnemyType type, Vector2 pos, float hp, float speed, float size, Color col, float stagger = 0f)
        {
            var e = new Enemy(pos, hp);
            e.Type = type;
            e.Speed = speed;
            e.Size = size;
            e.BaseColor = col;
            e.SpawnTimer = 0.5f;
            e.SpawnDuration = 0.5f;
            if (stagger > 0) e.AiStateTimer = stagger;
            _enemies.Add(e);
            _enemyById[e.Id] = e;
        }
        
        // Upper section: squires patrolling
        AddEnemy(EnemyType.Squire, new Vector2(cx - 100, ay + 200), 30f, 80f, 6f, new Color(255, 100, 100));
        AddEnemy(EnemyType.Squire, new Vector2(cx + 100, ay + 250), 30f, 80f, 6f, new Color(255, 100, 100));
        
        // Middle section: chargers
        AddEnemy(EnemyType.Charger, new Vector2(cx - 150, ay + 500), 120f, 70f, 14f, new Color(180, 120, 60), 1f);
        AddEnemy(EnemyType.Charger, new Vector2(cx + 150, ay + 550), 120f, 70f, 14f, new Color(180, 120, 60), 2f);
        AddEnemy(EnemyType.GuardGargoyle, new Vector2(cx, ay + 680), 60f, 50f, 12f, new Color(120, 130, 140));
        
        // Lower section: wraiths + gremlins
        AddEnemy(EnemyType.Wraith, new Vector2(cx - 200, ay + 900), 80f, 60f, 10f, new Color(100, 60, 140));
        AddEnemy(EnemyType.Wraith, new Vector2(cx + 200, ay + 950), 80f, 60f, 10f, new Color(100, 60, 140), 1.5f);
        AddEnemy(EnemyType.Gremlin, new Vector2(cx - 80, ay + 1050), 25f, 100f, 5f, new Color(80, 200, 80));
        AddEnemy(EnemyType.Gremlin, new Vector2(cx + 80, ay + 1100), 25f, 100f, 5f, new Color(80, 200, 80));
        AddEnemy(EnemyType.Gremlin, new Vector2(cx, ay + 1150), 25f, 100f, 5f, new Color(80, 200, 80));
        
        // Intro text
        if (!_awakeningIntroShown.Contains(11))
        {
            _pendingTextBox = "The air grows heavy. The walls stretch downward\ninto darkness...";
            _awakeningIntroShown.Add(11);
        }
    }
    
    private void UpdateRoom9(float dt)
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 9) return;
        if (_clearedScreens.Contains(9)) return;
        if (_bossSegments == null) return;
        if (_inventoryOpen) return;
        
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        _bossHitFlash = MathF.Max(0, _bossHitFlash - dt);
        _bossRageTimer = MathF.Max(0, _bossRageTimer - dt);
        
        // Boss intro sequence
        if (!_bossIntroDone)
        {
            _bossIntroTimer += dt;
            if (_bossIntroTimer < 0.3f)
            {
                _trauma = MathF.Min(_trauma + dt * 0.2f, 0.3f);
                return;
            }
            else if (_bossIntroTimer < 0.6f)
            {
                return;
            }
            else
            {
                _bossIntroDone = true;
                _bossActive = true;
                _bossPhase = 1;
                _bossSpeed = _bossBaseSpeed;
                _bossAngle = MathF.Atan2(_playerPos.Y - _bossSegments[0].Y, _playerPos.X - _bossSegments[0].X);
                _trauma = MathF.Min(_trauma + 0.4f, 1f);
            }
        }
        
        if (!_bossActive) return;
        
        // Immolant spawning during boss fight
        _immolantSpawnCooldown -= dt;
        if (_boneAttackCount9 >= 3 && _immolants.Count(im => im.Alive) < 1 && _immolantSpawnCooldown <= 0)
        {
            _boneAttackCount9 = 0;
            _immolantSpawnCooldown = 8f;
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            SpawnImmolant(new Vector2(_arena.Center.X + MathF.Cos(angle) * (_arena.Width / 2 - 20),
                                      _arena.Center.Y + MathF.Sin(angle) * (_arena.Height / 2 - 20)));
        }
        UpdateImmolants(dt);
        
        // Death sequence
        if (_bossHp <= 0 && _bossDeathTimer == 0)
        {
            _bossDeathTimer = 0.01f;
        }
        
        if (_bossDeathTimer > 0)
        {
            _bossDeathTimer += dt;
            _bossSpeed = MathF.Max(0, _bossSpeed - dt * 200f);
            
            if ((int)(_bossDeathTimer * 8) != (int)((_bossDeathTimer - dt) * 8))
            {
                int segIdx = _rng.Next(_bossSegmentCount);
                for (int p = 0; p < 15; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = _bossSegments[segIdx],
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 80f),
                        Life = 0.8f, MaxLife = 0.8f,
                        Color = new Color(220, 200, 160),
                        Size = 3f
                    });
                }
                _trauma = MathF.Min(_trauma + 0.15f, 0.6f);
            }
            
            // Segments drift apart during death
            // Segments stay frozen at death positions (no drift)
            
            // Final explosion at death
            if (_bossDeathTimer >= 2.8f && _bossDeathTimer - dt < 2.8f)
            {
                _trauma = 1f;
                for (int p = 0; p < 100; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 60f + (float)_rng.NextDouble() * 200f;
                    _particles.Add(new Particle
                    {
                        Position = _bossSegments[0],
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 1.5f + (float)_rng.NextDouble() * 1f,
                        MaxLife = 2.5f,
                        Color = Color.Lerp(new Color(255, 200, 100), new Color(255, 80, 40), (float)_rng.NextDouble()),
                        Size = 3f + (float)_rng.NextDouble() * 4f,
                    });
                }
            }
            
            if (_bossDeathTimer > 3f)
            {
                _bossActive = false;
                _bossDead = true;
                _projectiles.Clear();
                _lavaRects.Clear();
                // Kill all Immolants
                for (int ii = _immolants.Count - 1; ii >= 0; ii--)
                {
                    var im = _immolants[ii];
                    for (int p = 0; p < 20; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float spd = 30f + (float)_rng.NextDouble() * 80f;
                        _particles.Add(new Particle
                        {
                            Position = im.Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                            Life = 0.6f, MaxLife = 0.6f,
                            Color = new Color(255, 120 + _rng.Next(80), 20),
                            Size = 2f + (float)_rng.NextDouble() * 3f
                        });
                    }
                }
                _immolants.Clear();
                _clearedScreens.Add(9);
                TriggerRoomCleared("Victory!");
                if (!_victoryPlayed) { PlayMusic(LoadSong("Music/Victory"), "victory", oneShot: true); _victoryPlayed = true; }
                
                int cx = ax + aw / 2;
                int cy = ay + ah / 2;
                _pickups.Add(new PickupItem
                {
                    Position = new Vector2(cx - 30, cy),
                    Name = "Haste Band",
                    DisplayText = "Haste Band Obtained — Move faster",
                    Type = "haste",
                    GlowColor = new Color(100, 255, 100)
                });
                _pickups.Add(new PickupItem
                {
                    Position = new Vector2(cx + 30, cy),
                    Name = "Phylactery",
                    DisplayText = "Phylactery Obtained — +25% max EP",
                    Type = "phylactery",
                    GlowColor = new Color(200, 100, 255)
                });
                
                _textBoxMessage = "The Wyrm falls. Your power is your own.";
                _textBoxWaiting = true;
                PlaySfx(_sfxPickup);
                for (int lp = 0; lp < _bossLavaPools.Count; lp++)
                {
                    var pool = _bossLavaPools[lp];
                    pool.FadeTimer = 2f;
                    _bossLavaPools[lp] = pool;
                }
                return;
            }
        }
        
        // Phase transitions based on HP
        float hpPct = _bossHp / _bossMaxHp;
        int targetPhase = hpPct > 0.75f ? 1 : hpPct > 0.5f ? 2 : hpPct > 0.25f ? 3 : 4;
        if (targetPhase > _bossPhase)
        {
            _bossPhase = targetPhase;
            _trauma = MathF.Min(_trauma + 0.5f, 1f);
            _bossBaseSpeed += 20f;
            _bossTurnSpeed += 0.3f;
            
            int poolW = 60 + _bossPhase * 15;
            int poolH = 40 + _bossPhase * 10;
            _bossLavaPools.Add(new LavaPool { Rect = new Rectangle(
                (int)_bossSegments[0].X - poolW / 2,
                (int)_bossSegments[0].Y - poolH / 2,
                poolW, poolH), SpawnTimer = 0.5f, FadeTimer = 0 });
        }
        
        // Moldorm AI
        float rageSpeedMult = _bossRageTimer > 0 ? 1.6f : 1f;
        float rageTurnMult = _bossRageTimer > 0 ? 1.4f : 1f;
        _bossSpeed = _bossBaseSpeed * rageSpeedMult;
        
        Vector2 toPlayer = _playerPos - _bossSegments[0];
        float targetAngle = MathF.Atan2(toPlayer.Y, toPlayer.X);
        
        float angleDiff = targetAngle - _bossAngle;
        while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
        while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
        _bossAngle += MathF.Sign(angleDiff) * MathF.Min(MathF.Abs(angleDiff), _bossTurnSpeed * rageTurnMult * dt);
        
        Vector2 headVel = new Vector2(MathF.Cos(_bossAngle), MathF.Sin(_bossAngle)) * _bossSpeed * dt;
        _bossSegments[0] += headVel;
        _bossSegmentAngles[0] = _bossAngle;
        
        // Wall bouncing
        float margin = _bossHeadSize / 2;
        bool bounced = false;
        if (_bossSegments[0].X < ax + margin) { _bossSegments[0] = new Vector2(ax + margin, _bossSegments[0].Y); _bossAngle = MathF.PI - _bossAngle; bounced = true; }
        if (_bossSegments[0].X > ax + aw - margin) { _bossSegments[0] = new Vector2(ax + aw - margin, _bossSegments[0].Y); _bossAngle = MathF.PI - _bossAngle; bounced = true; }
        if (_bossSegments[0].Y < ay + margin) { _bossSegments[0] = new Vector2(_bossSegments[0].X, ay + margin); _bossAngle = -_bossAngle; bounced = true; }
        if (_bossSegments[0].Y > ay + ah - margin) { _bossSegments[0] = new Vector2(_bossSegments[0].X, ay + ah - margin); _bossAngle = -_bossAngle; bounced = true; }
        if (bounced) _trauma = MathF.Min(_trauma + 0.1f, 0.5f);
        
        // Body follows
        for (int i = 1; i < _bossSegmentCount; i++)
        {
            Vector2 diff = _bossSegments[i - 1] - _bossSegments[i];
            float dist = diff.Length();
            if (dist > _bossSegmentSpacing)
            {
                Vector2 dir = diff / dist;
                _bossSegments[i] += dir * (dist - _bossSegmentSpacing);
                _bossSegmentAngles[i] = MathF.Atan2(dir.Y, dir.X);
            }
        }
        
        // Head contact damage
        if (_bossDeathTimer == 0 && _iFrameTimer <= 0 && Vector2.Distance(_bossSegments[0], _playerPos) < _bossHeadSize / 2 + 8)
        {
            _playerHp -= 15f;
            Vector2 kb2 = _playerPos - _bossSegments[0];
            if (kb2.LengthSquared() > 0) kb2.Normalize();
            _playerPos += kb2 * 60f;
            _trauma = MathF.Min(_trauma + 0.3f, 1f);
            _iFrameTimer = 0.5f;
        }
        
        // Body contact damage
        if (_bossDeathTimer == 0 && _iFrameTimer <= 0)
        {
            for (int i = 1; i < _bossSegmentCount - 1; i++)
            {
                float segSize = MathHelper.Lerp(_bossHeadSize, _bossTailSize, (float)i / (_bossSegmentCount - 1));
                if (Vector2.Distance(_bossSegments[i], _playerPos) < segSize / 2 + 6)
                {
                    _playerHp -= 8f;
                    Vector2 kb3 = _playerPos - _bossSegments[i];
                    if (kb3.LengthSquared() > 0) kb3.Normalize();
                    _playerPos += kb3 * 40f;
                    _trauma = MathF.Min(_trauma + 0.15f, 0.5f);
                    _iFrameTimer = 0.3f;
                    break;
                }
            }
        }
        
        // Tail vulnerability
        if (_bossDeathTimer == 0)
        {
            Vector2 tailPos = _bossSegments[_bossSegmentCount - 1];
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                if (!proj.Alive) continue;
                
                // Beam collision: check line segment against tail circle
                bool hitTail = false;
                if (proj.BeamLen > 0)
                {
                    Vector2 bd = proj.BeamDirection.LengthSquared() > 0.1f ? Vector2.Normalize(proj.BeamDirection) : Vector2.UnitX;
                    Vector2 beamEnd = proj.Position + bd * proj.BeamLen;
                    hitTail = LineCircleIntersects(proj.Position, beamEnd, tailPos, _bossTailSize + 8);
                }
                else
                {
                    hitTail = Vector2.Distance(proj.Position, tailPos) < _bossTailSize + 8;
                }
                
                if (hitTail)
                {
                    float dmg = proj.Params.BaseDamage;
                    if (proj.Params.BehaviorType == Behavior.Shatter) dmg *= 1.5f;
                    if (_currentFusion != null) dmg *= 1.3f;
                    
                    _bossHp -= dmg;
                    _bossHitFlash = 0.15f;
                    _bossRageTimer = 2f;
                    _trauma = MathF.Min(_trauma + 0.2f, 0.7f);
                    PlaySfx(_sfxHit, 0.6f);
                    
                    for (int p = 0; p < 10; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = tailPos,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (30f + (float)_rng.NextDouble() * 50f),
                            Life = 0.5f, MaxLife = 0.5f,
                            Color = new Color(220, 200, 160),
                            Size = 2f
                        });
                    }
                    
                    if (proj.BeamLen <= 0) { proj.Alive = false; _projectiles[pi] = proj; }
                    continue;
                }
                
                // Non-tail hits deflect with spark
                for (int si = 0; si < _bossSegmentCount - 1; si++)
                {
                    float segSize = MathHelper.Lerp(_bossHeadSize, _bossTailSize, (float)si / (_bossSegmentCount - 1));
                    bool hitSeg = false;
                    if (proj.BeamLen > 0)
                    {
                        Vector2 bd = proj.BeamDirection.LengthSquared() > 0.1f ? Vector2.Normalize(proj.BeamDirection) : Vector2.UnitX;
                        Vector2 beamEnd = proj.Position + bd * proj.BeamLen;
                        hitSeg = LineCircleIntersects(proj.Position, beamEnd, _bossSegments[si], segSize / 2 + 4);
                    }
                    else
                    {
                        hitSeg = Vector2.Distance(proj.Position, _bossSegments[si]) < segSize / 2 + 4;
                    }
                    if (hitSeg)
                    {
                        if (proj.BeamLen <= 0)
                        {
                            proj.Velocity = -proj.Velocity;
                            _projectiles[pi] = proj;
                        }
                        for (int p = 0; p < 3; p++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = proj.Position,
                                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 40f,
                                Life = 0.2f, MaxLife = 0.2f,
                                Color = new Color(200, 200, 220),
                                Size = 1.5f
                            });
                        }
                        break;
                    }
                }
            }
        }
        
        // Update lava pool timers
        for (int lpi = _bossLavaPools.Count - 1; lpi >= 0; lpi--)
        {
            var lp = _bossLavaPools[lpi];
            if (lp.SpawnTimer > 0) { lp.SpawnTimer -= dt; _bossLavaPools[lpi] = lp; }
            if (lp.FadeTimer > 0) { lp.FadeTimer -= dt; if (lp.FadeTimer <= 0) { _bossLavaPools.RemoveAt(lpi); continue; } _bossLavaPools[lpi] = lp; }
        }
        
        // Lava pool flame particles
        foreach (var pool in _bossLavaPools)
        {
            if (pool.SpawnTimer > 0 || pool.FadeTimer > 0) continue;
            if (_rng.NextDouble() < 0.4) // ~40% chance per frame per pool
            {
                float px = pool.Rect.Left + (float)_rng.NextDouble() * pool.Rect.Width;
                float py = pool.Rect.Top + (float)_rng.NextDouble() * pool.Rect.Height * 0.5f;
                _particles.Add(new Particle
                {
                    Position = new Vector2(px, py),
                    Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 15f, -30f - (float)_rng.NextDouble() * 40f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.4f,
                    MaxLife = 0.7f,
                    Color = Color.Lerp(new Color(255, 200, 60), new Color(255, 80, 20), (float)_rng.NextDouble()),
                    Size = 1.5f + (float)_rng.NextDouble() * 2f
                });
            }
        }
        
        // Lava pools damage player
        if (_iFrameTimer <= 0)
        {
            foreach (var pool in _bossLavaPools)
            {
                if (pool.SpawnTimer > 0) continue;
                if (pool.FadeTimer > 0) continue;
                if (pool.Rect.Contains((int)_playerPos.X, (int)_playerPos.Y))
                {
                    _playerHp -= 5f;
                    _iFrameTimer = 0.3f;
                    _trauma = MathF.Min(_trauma + 0.1f, 0.4f);
                    break;
                }
            }
        }
        
        // Periodic lava drip from body (phases 3+)
        if (_bossPhase >= 3 && _bossDeathTimer == 0)
        {
            _bossLavaTimer += dt;
            if (_bossLavaTimer > 3f)
            {
                _bossLavaTimer = 0;
                int poolIdx = _rng.Next(3, _bossSegmentCount - 2);
                int pw = 40, ph = 30;
                _bossLavaPools.Add(new LavaPool { Rect = new Rectangle(
                    (int)_bossSegments[poolIdx].X - pw / 2,
                    (int)_bossSegments[poolIdx].Y - ph / 2,
                    pw, ph), SpawnTimer = 0.5f, FadeTimer = 0 });
                if (_bossLavaPools.Count > 8) _bossLavaPools.RemoveAt(0);
            }
        }
    }
    
    // ═══════════════ SIR PELLINORE — WANDERING GHOST ═══════════════
    
    private static readonly Dictionary<int, int[]> RoomAdjacency = new()
    {
        {1, new[]{2,4}}, {2, new[]{1,3,5}}, {3, new[]{2,6}},
        {4, new[]{1,5,7}}, {5, new[]{2,4,6,8}}, {6, new[]{3,5,9}},
        {7, new[]{4,8}}, {8, new[]{5,7,9}}, {9, new[]{6,8}}
    };
    
    private void UpdateUndine(float dt)
    {
        if (!_hasUndine) return;
        
        // Orbit around player
        _undineOrbitAngle += dt * 1.8f;
        float orbitRadius = 30f + MathF.Sin(_undineOrbitAngle * 0.3f) * 5f;
        Vector2 targetPos = _playerPos + new Vector2(
            MathF.Cos(_undineOrbitAngle) * orbitRadius,
            MathF.Sin(_undineOrbitAngle) * orbitRadius * 0.6f - 10f);
        _undinePos = Vector2.Lerp(_undinePos, targetPos, dt * 6f);
        
        // Contact damage to enemies (3 DPS)
        for (int i = 0; i < _enemies.Count; i++)
        {
            if (!_enemies[i].Alive) continue;
            if (Vector2.Distance(_undinePos, _enemies[i].Position) < _enemies[i].Size + 6f)
            {
                var e = _enemies[i];
                e.Hp -= 3f * dt;
                if (e.Hp <= 0) e.Alive = false;
                _enemies[i] = e;
            }
        }
        
        // Echo shot: mimic player's last projectile after cooldown
        _undineMimicTimer -= dt;
        if (_undineMimicTimer <= 0 && _projectiles.Count > 0)
        {
            for (int i = _projectiles.Count - 1; i >= 0; i--)
            {
                var p = _projectiles[i];
                if (!p.Alive || p.Age > 0.5f) continue; // recently fired only
                if (p.BeamLen > 0) continue; // don't mimic beams
                if (p.ArcDuration > 0) continue; // don't mimic arcs
                
                var echoParms = p.Params;
                echoParms.BaseDamage *= 0.4f;
                echoParms.Speed *= 0.8f;
                echoParms.Lifetime *= 0.6f;
                
                Vector2 dir = p.Velocity != Vector2.Zero ? Vector2.Normalize(p.Velocity) : new Vector2(1, 0);
                var echo = new Projectile(_undinePos, dir * echoParms.Speed, echoParms);
                echo.FusionName = p.FusionName;
                _projectiles.Add(echo);
                _undineMimicTimer = 2.5f;
                break;
            }
        }
        
        // Trail particles
        _undineTrailTimer -= dt;
        if (_undineTrailTimer <= 0)
        {
            _undineTrailTimer = 0.1f;
            Color trailCol = _loadout.Essence switch
            {
                Essence.Cinder => new Color(255, 120, 40),
                Essence.Pulse => new Color(100, 180, 255),
                Essence.Bone => new Color(200, 200, 180),
                _ => new Color(80, 160, 220)
            };
            _particles.Add(new Particle
            {
                Position = _undinePos + new Vector2(_rng.Next(-3, 3), _rng.Next(-3, 3)),
                Velocity = new Vector2(0, -8f),
                Life = 0.35f, MaxLife = 0.35f,
                Color = trailCol * 0.5f,
                Size = 1.5f
            });
        }
    }
    
    private void DrawUndine()
    {
        if (!_hasUndine) return;
        
        float time = _totalTime;
        float pulse = (MathF.Sin(time * 3f) + 1f) / 2f;
        float alpha = _undineAlpha + pulse * 0.15f;
        
        int ux = (int)_undinePos.X;
        int uy = (int)_undinePos.Y;
        
        Color baseCol = _loadout.Essence switch
        {
            Essence.Cinder => Color.Lerp(new Color(80, 160, 220), new Color(255, 120, 40), 0.4f),
            Essence.Pulse => Color.Lerp(new Color(80, 160, 220), new Color(100, 200, 255), 0.5f),
            Essence.Bone => Color.Lerp(new Color(80, 160, 220), new Color(200, 200, 180), 0.3f),
            _ => new Color(80, 160, 220)
        };
        
        // Outer glow
        DrawRect(ux - 8, uy - 8, 16, 16, baseCol * alpha * 0.15f);
        // Inner glow
        DrawRect(ux - 5, uy - 5, 10, 10, baseCol * alpha * 0.6f);
        // Core
        DrawRect(ux - 3, uy - 3, 6, 6, Color.White * alpha * 0.9f);
        
        // Wispy tendrils (4 orbiting dots)
        for (int t = 0; t < 4; t++)
        {
            float tAngle = time * 2.5f + t * MathF.PI / 2f;
            float tDist = 6f + MathF.Sin(time * 4f + t) * 2f;
            int tx = ux + (int)(MathF.Cos(tAngle) * tDist);
            int ty = uy + (int)(MathF.Sin(tAngle) * tDist * 0.7f);
            DrawRect(tx, ty, 2, 2, baseCol * alpha * 0.7f);
        }
    }
    
    private void SpawnImmolant(Vector2 pos)
    {
        _immolants.Add(new Immolant
        {
            Position = pos, Hp = ImmolantMaxHp, Alive = true,
            SpawnTimer = 1.0f, FlameIntensity = 0.5f, RushCooldown = 2f,
        });
        for (int p = 0; p < 30; p++)
        {
            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
            float spd = 40f + (float)_rng.NextDouble() * 80f;
            _particles.Add(new Particle
            {
                Position = pos,
                Velocity = new Vector2(MathF.Cos(a) * spd * 0.3f, -MathF.Abs(MathF.Sin(a)) * spd),
                Life = 0.8f + (float)_rng.NextDouble() * 0.4f, MaxLife = 1.2f,
                Color = new Color(255, (int)(100 + _rng.NextDouble() * 100), 20),
                Size = 2f + (float)_rng.NextDouble() * 2f
            });
        }
        _trauma = MathF.Min(_trauma + 0.2f, 1f);
        if (_sfxHit != null) _sfxHit.Play(0.4f, -0.3f, 0f);
    }

    private void UpdateImmolants(float dt)
    {
        if (_inventoryOpen) return;
        for (int i = _immolants.Count - 1; i >= 0; i--)
        {
            var im = _immolants[i];
            if (!im.Alive) { _immolants.RemoveAt(i); continue; }

            if (im.SpawnTimer > 0)
            {
                im.SpawnTimer -= dt;
                im.FlameIntensity = MathHelper.Lerp(0.2f, 1f, 1f - im.SpawnTimer);
                _immolants[i] = im; continue;
            }

            im.HitFlashTimer -= dt;
            im.RushCooldown -= dt;
            im.DodgeCooldown -= dt;
            im.WailCooldown -= dt;

            if (im.StaggerTimer > 0)
            {
                im.StaggerTimer -= dt;
                im.FlameIntensity = 0.2f;
                _immolants[i] = im; continue;
            }

            // Wail wind-up
            if (im.WailTimer > 0)
            {
                im.WailTimer += dt;
                im.FlameIntensity = 2.0f;
                if (im.WailTimer >= 0.5f)
                {
                    // Fire the wail
                    im.WailTimer = 0;
                    im.WailCooldown = 6f;
                    _wailEffects.Add(new WailEffect { Position = im.Position, Timer = 0f, MaxTimer = 0.8f });
                    _trauma = MathF.Min(_trauma + 0.4f, 1f);
                    if (Vector2.Distance(im.Position, _playerPos) < 100f && _iFrameTimer <= 0)
                    {
                        _playerHp -= 10f;
                        _iFrameTimer = 0.8f;
                        _wailDebuffTimer = 1.5f;
                    }
                }
                _immolants[i] = im; continue;
            }

            im.FlameIntensity = MathHelper.Lerp(im.FlameIntensity, 1f, dt * 3f);

            float dist = Vector2.Distance(im.Position, _playerPos);

            // Utility AI: check for incoming projectiles to dodge
            bool shouldDodge = false;
            Vector2 dodgeDir = Vector2.Zero;
            if (im.DodgeCooldown <= 0)
            {
                for (int pi = 0; pi < _projectiles.Count; pi++)
                {
                    var proj = _projectiles[pi];
                    if (!proj.Alive) continue;
                    float projDist = Vector2.Distance(proj.Position, im.Position);
                    if (projDist > 80f || projDist < 5f) continue;
                    if (proj.Velocity.LengthSquared() < 1f) continue;
                    Vector2 projDir = Vector2.Normalize(proj.Velocity);
                    float dot = Vector2.Dot(Vector2.Normalize(im.Position - proj.Position), projDir);
                    if (dot > 0.7f)
                    {
                        dodgeDir = new Vector2(-projDir.Y, projDir.X);
                        if ((float)_rng.NextDouble() > 0.5f) dodgeDir = -dodgeDir;
                        shouldDodge = true; break;
                    }
                }
            }

            if (shouldDodge)
            {
                Vector2 oldPos = im.Position;
                float dodgeDist = 40f + (float)_rng.NextDouble() * 20f;
                im.Position += dodgeDir * dodgeDist;
                im.Position = new Vector2(
                    MathHelper.Clamp(im.Position.X, _arena.Left + 10, _arena.Right - 10),
                    MathHelper.Clamp(im.Position.Y, _arena.Top + 10, _arena.Bottom - 10));
                im.DodgeCooldown = 0.4f;
                // Afterimage trail
                for (int ai = 0; ai < 8; ai++)
                {
                    float ait = (float)ai / 8f;
                    _particles.Add(new Particle
                    {
                        Position = Vector2.Lerp(oldPos, im.Position, ait) + new Vector2(((float)_rng.NextDouble() - 0.5f) * 4f, ((float)_rng.NextDouble() - 0.5f) * 4f),
                        Velocity = Vector2.Zero,
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(255, 140, 40) * (1f - ait * 0.5f),
                        Size = 4f * (1f - ait * 0.3f)
                    });
                }
                for (int p = 0; p < 6; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = oldPos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 25f,
                        Life = 0.3f, MaxLife = 0.3f,
                        Color = new Color(200, 100, 40) * 0.6f, Size = 2f
                    });
                }
            }
            else if (im.RushTimer > 0)
            {
                im.RushTimer -= dt;
                im.JitterTimer += dt;
                Vector2 jitterOffset = new Vector2(MathF.Sin(im.JitterTimer * 15f) * 15f, MathF.Cos(im.JitterTimer * 15f) * 15f);
                im.Position += (im.RushDir * 250f + jitterOffset) * dt;
                im.Position = new Vector2(
                    MathHelper.Clamp(im.Position.X, _arena.Left + 5, _arena.Right - 5),
                    MathHelper.Clamp(im.Position.Y, _arena.Top + 5, _arena.Bottom - 5));
                if (Vector2.Distance(im.Position, _playerPos) < 16f && _iFrameTimer <= 0)
                {
                    _playerHp -= 12f; _iFrameTimer = 0.8f;
                    _trauma = MathF.Min(_trauma + 0.3f, 1f);
                    im.RushTimer = 0; im.RushCooldown = 3f;
                    _wailDebuffTimer = 0.3f;
                    for (int p = 0; p < 12; p++)
                    {
                        float a = p * MathF.PI * 2f / 12f;
                        _particles.Add(new Particle
                        {
                            Position = _playerPos,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 60f,
                            Life = 0.5f, MaxLife = 0.5f,
                            Color = new Color(255, 80, 30) * 0.5f, Size = 1.5f
                        });
                    }
                }
            }
            else if (dist < 200f && dist > 5f && im.RushCooldown <= 0)
            {
                im.FlameIntensity = 1.5f;
                im.RushTimer = 0.6f;
                im.RushDir = Vector2.Normalize(_playerPos - im.Position);
                im.JitterTimer = 0f; im.RushCooldown = 3f;
            }
            else
            {
                // Wail trigger: close range, not rushing
                if (im.WailCooldown <= 0 && dist < 150f && dist > 5f)
                {
                    im.WailTimer = 0.001f; // start wind-up
                }
                else if (dist > 20f)
                    im.Position += Vector2.Normalize(_playerPos - im.Position) * 40f * dt;
                if (dist < 14f && dist > 0.1f && _iFrameTimer <= 0)
                {
                    _playerHp -= 8f; _iFrameTimer = 0.6f;
                    _trauma = MathF.Min(_trauma + 0.15f, 1f);
                }
            }

            // Ember trail
            if (_rng.NextDouble() < 0.3)
            {
                _particles.Add(new Particle
                {
                    Position = im.Position + new Vector2((float)(_rng.NextDouble() - 0.5) * 8, (float)(_rng.NextDouble() - 0.5) * 8),
                    Velocity = new Vector2((float)(_rng.NextDouble() - 0.5) * 10, -15f - (float)_rng.NextDouble() * 20f),
                    Life = 0.4f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.7f,
                    Color = new Color(255, (int)(120 + _rng.NextDouble() * 100), 20) * im.FlameIntensity,
                    Size = 1f + (float)_rng.NextDouble()
                });
            }
            _immolants[i] = im;
        }

        // Projectile hits on immolants
        for (int ii = _immolants.Count - 1; ii >= 0; ii--)
        {
            var im = _immolants[ii];
            if (!im.Alive || im.SpawnTimer > 0) continue;
            for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
            {
                var proj = _projectiles[pi];
                if (!proj.Alive) continue;
                bool hit = false;
                if (proj.BeamLen > 0)
                {
                    Vector2 beamDir = proj.Velocity.LengthSquared() > 0.1f ? Vector2.Normalize(proj.Velocity) :
                                      (proj.BeamDirection.LengthSquared() > 0.1f ? Vector2.Normalize(proj.BeamDirection) : Vector2.Zero);
                    if (beamDir != Vector2.Zero)
                    {
                        Vector2 toIm = im.Position - proj.Position;
                        float along = Vector2.Dot(toIm, beamDir);
                        if (along > 0 && along < proj.BeamLen)
                            hit = Vector2.Distance(proj.Position + beamDir * along, im.Position) < 14f;
                    }
                }
                else if (proj.BladeLength > 0 && proj.SwingEndAngle != proj.SwingStartAngle)
                {
                    // Swing arc check (Hiten Mitsurugi, Dragon Slayer, etc.)
                    float swingT = MathHelper.Clamp(proj.Age / MathF.Max(proj.Lifetime, 0.01f), 0f, 1f);
                    float easedT = (proj.FusionName == "DragonSlayer" || proj.FusionName == "DragonSlayerAfter")
                        ? swingT * swingT
                        : 1f - (1f - swingT) * (1f - swingT);
                    float currentAngle = MathHelper.Lerp(proj.SwingStartAngle, proj.SwingEndAngle, easedT);
                    Vector2 toIm = im.Position - proj.Position;
                    float dist = toIm.Length();
                    if (dist < proj.BladeLength + 8f && dist > 6f)
                    {
                        float imAngle = MathF.Atan2(toIm.Y, toIm.X);
                        float angleDiff = imAngle - currentAngle;
                        while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
                        while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
                        if (MathF.Abs(angleDiff) < 0.4f) hit = true;
                    }
                }
                else hit = Vector2.Distance(proj.Position, im.Position) < 14f;

                if (hit)
                {
                    var parms = ProjectileParams.Resolve(_loadout);
                    float dmg = parms.BaseDamage;
                    bool isPulse = _loadout.Essence == Essence.Pulse;
                    bool isBone = _loadout.Essence == Essence.Bone;
                    if (isPulse) dmg *= 2f;
                    if (isBone) dmg *= 0.25f;
                    im.Hp -= dmg;
                    im.HitFlashTimer = 0.12f;
                    if (_hasEtherSight && (isPulse || isBone))
                        _floatingTexts.Add(new FloatingText
                        {
                            Position = im.Position + new Vector2(-20, -15),
                            Text = isPulse ? "WEAKNESS!" : "RESIST",
                            Color = isPulse ? new Color(255, 200, 50) : new Color(120, 120, 120),
                            Life = isPulse ? 1f : 0.6f, MaxLife = isPulse ? 1f : 0.6f
                        });
                    if (dmg >= 20f) im.StaggerTimer = 2f;
                    _damageNumbers.Add(new DamageNumber { Position = im.Position + new Vector2(0, -12), Amount = dmg, Timer = 0.8f, Color = isPulse ? new Color(255, 200, 50) : Color.White });
                    if (im.Hp <= 0)
                    {
                        im.Alive = false;
                        for (int dp = 0; dp < 20; dp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            float spd = 20f + (float)_rng.NextDouble() * 50f;
                            bool isFlame = dp < 10;
                            _particles.Add(new Particle
                            {
                                Position = im.Position + new Vector2((float)(_rng.NextDouble() - 0.5) * 6, (float)(_rng.NextDouble() - 0.5) * 6),
                                Velocity = isFlame ? new Vector2(MathF.Cos(a) * spd * 0.3f, -spd) : new Vector2(MathF.Cos(a) * spd, MathF.Sin(a) * spd),
                                Life = isFlame ? 0.6f : 0.4f, MaxLife = isFlame ? 0.6f : 0.4f,
                                Color = isFlame ? new Color(255, 140, 30) : new Color(180, 170, 140),
                                Size = isFlame ? 2f : 1.5f
                            });
                        }
                        _playerEther = MathF.Min(_playerEther + 8f, EffectiveMaxEther);
                    }
                    _immolants[ii] = im;
                    if (!proj.Params.Piercing) _projectiles.RemoveAt(pi);
                    break;
                }
            }
        }

        // Update wail effects
        for (int wi = _wailEffects.Count - 1; wi >= 0; wi--)
        {
            var we = _wailEffects[wi];
            we.Timer += dt;
            if (we.Timer >= we.MaxTimer) { _wailEffects.RemoveAt(wi); continue; }
            _wailEffects[wi] = we;
        }
    }

    private void DrawImmolants()
    {
        foreach (var im in _immolants)
        {
            if (!im.Alive) continue;
            float spawnAlpha = im.SpawnTimer > 0 ? MathHelper.Clamp(1f - im.SpawnTimer, 0, 1) : 1f;
            float flash = im.HitFlashTimer > 0 ? 1f : 0f;
            float fi = MathHelper.Clamp(im.FlameIntensity, 0, 1.5f);
            int x = (int)im.Position.X;
            int y = (int)im.Position.Y;
            if (im.WailTimer > 0)
            {
                x += (int)(MathF.Sin(_totalTime * 40f) * 3f);
                y += (int)(MathF.Cos(_totalTime * 35f) * 3f);
            }
            if (im.SpawnTimer > 0) y += (int)(im.SpawnTimer * 30f);

            float time = _totalTime;
            for (int layer = 2; layer >= 0; layer--)
            {
                float flicker = MathF.Sin(time * 12f + layer * 2.1f + im.Position.X * 0.1f) * 0.3f + 0.7f;
                int size = 14 + layer * 4 - (int)(im.StaggerTimer > 0 ? layer * 3 : 0);
                float layerAlpha = (0.15f + layer * 0.05f) * fi * flicker * spawnAlpha;
                Color flameCol = layer switch
                {
                    0 => new Color(255, 220, 80),
                    1 => new Color(255, 140, 30),
                    _ => new Color(200, 60, 20)
                };
                if (im.StaggerTimer > 0) flameCol = new Color(80, 60, 50);
                int ox = (int)(MathF.Sin(time * 8f + layer * 3f) * 2f);
                int oy = (int)(MathF.Cos(time * 10f + layer * 2f) * 2f);
                DrawRect(x - size / 2 + ox, y - size / 2 + oy - layer * 3, size, size, flameCol * layerAlpha);
            }

            Color skullCol = flash > 0 ? Color.White : new Color(40, 35, 30) * spawnAlpha;
            DrawRect(x - 5, y - 5, 10, 10, skullCol);
            Color eyeCol = im.StaggerTimer > 0 ? new Color(60, 40, 30) * spawnAlpha : new Color(255, 80, 20) * (fi * spawnAlpha);
            DrawRect(x - 3, y - 3, 2, 2, eyeCol);
            DrawRect(x + 1, y - 3, 2, 2, eyeCol);
            DrawRect(x - 1, y, 1, 2, new Color(30, 25, 20) * spawnAlpha);
            DrawRect(x - 3, y + 2, 6, 2, new Color(180, 170, 140) * spawnAlpha);
            DrawRect(x - 2, y + 2, 1, 2, new Color(30, 25, 20) * spawnAlpha);
            DrawRect(x + 1, y + 2, 1, 2, new Color(30, 25, 20) * spawnAlpha);

            if (im.FlameIntensity > 1.2f)
                DrawRect(x - 10, y - 10, 20, 20, new Color(255, 200, 50) * 0.08f);
            if (im.StaggerTimer > 0 && im.StaggerTimer > 1.5f)
                DrawTextFallback(x - 2, y - 18, "!", new Color(255, 100, 100));

            if (im.Hp < ImmolantMaxHp && im.Hp > 0)
            {
                int barW = 20, barH = 2;
                int barX = x - barW / 2, barY = y + 10;
                DrawRect(barX, barY, barW, barH, new Color(40, 10, 10));
                DrawRect(barX, barY, (int)(barW * MathHelper.Clamp(im.Hp / ImmolantMaxHp, 0, 1)), barH, new Color(255, 100, 30));
            }
        }

        // Draw wail shockwave effects
        foreach (var we in _wailEffects)
        {
            float progress = we.Timer / we.MaxTimer;
            float alpha = 1f - progress;
            Color wailColor = new Color(255, 120, 40) * alpha;
            int cx = (int)we.Position.X;
            int cy = (int)we.Position.Y;
            for (int ring = 0; ring < 4; ring++)
            {
                float ringDelay = ring * 0.08f;
                float ringProgress = MathHelper.Clamp((we.Timer - ringDelay) / (we.MaxTimer - ringDelay), 0, 1);
                if (ringProgress <= 0) continue;
                float radius = ringProgress * 120f * (1f - ring * 0.15f);
                float ringAlpha = (1f - ringProgress) * alpha;
                Color rc = new Color(255, 120, 40) * ringAlpha;
                // Draw ring as 16-segment circle
                for (int seg = 0; seg < 16; seg++)
                {
                    float a1 = seg * MathF.PI * 2f / 16f;
                    int sx = cx + (int)(MathF.Cos(a1) * radius);
                    int sy = cy + (int)(MathF.Sin(a1) * radius);
                    DrawRect(sx, sy, 2, 2, rc);
                }
                // Spikes on outermost ring
                if (ring == 0)
                {
                    for (int sp = 0; sp < 8; sp++)
                    {
                        float sa = sp * MathF.PI * 2f / 8f;
                        int sx1 = cx + (int)(MathF.Cos(sa) * radius);
                        int sy1 = cy + (int)(MathF.Sin(sa) * radius);
                        int sx2 = cx + (int)(MathF.Cos(sa) * (radius + 12f * ringAlpha));
                        int sy2 = cy + (int)(MathF.Sin(sa) * (radius + 12f * ringAlpha));
                        DrawRect((sx1 + sx2) / 2, (sy1 + sy2) / 2, 2, 2, rc);
                    }
                }
            }
        }
    }

    private void UpdatePellinore(float dt)
    {
        if (_pellinoreDeathTimer > 0)
        {
            _pellinoreDeathTimer -= dt;
            // Death particles
            if (_rng.NextDouble() < 0.4)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                float sp = 20f + (float)_rng.NextDouble() * 60f;
                _particles.Add(new Particle
                {
                    Position = _pellinorePos + new Vector2(_rng.Next(-8, 8), _rng.Next(-12, 4)),
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * sp,
                    Life = 0.6f, MaxLife = 0.6f,
                    Color = new Color(200, 200, 255),
                    Size = 2f + (float)_rng.NextDouble() * 2f
                });
            }
            if (_pellinoreDeathTimer <= 0)
            {
                _pellinoreActive = false;
                _pellinoreDefeated = true;
                _pickups.Add(new PickupItem
                {
                    Position = _pellinorePos,
                    Name = "Pellinore's Oath",
                    DisplayText = "Pellinore's Oath — The hunt is over. Your grandfather rests.",
                    Type = "pellinore_oath",
                    Collected = false, BobTimer = 0f,
                    GlowColor = new Color(200, 200, 255)
                });
            }
            return;
        }
        
        _pellinoreHitFlash = MathF.Max(0, _pellinoreHitFlash - dt);
        _pellinoreStaggerTimer = MathF.Max(0, _pellinoreStaggerTimer - dt);
        
        // Off-screen: wander between rooms
        if (_pellinoreScreen != _currentScreen)
        {
            _pellinoreWanderTimer -= dt;
            if (_pellinoreWanderTimer <= 0)
            {
                _pellinoreWanderTimer = 15f + (float)_rng.NextDouble() * 5f;
                var adj = RoomAdjacency[_pellinoreScreen];
                if (_rng.NextDouble() < 0.7)
                {
                    // Move toward player
                    int best = adj[0];
                    int bestDist = RoomDist(adj[0], _currentScreen);
                    for (int i = 1; i < adj.Length; i++)
                    {
                        int d = RoomDist(adj[i], _currentScreen);
                        if (d < bestDist) { bestDist = d; best = adj[i]; }
                    }
                    _pellinoreScreen = best;
                }
                else
                {
                    _pellinoreScreen = adj[_rng.Next(adj.Length)];
                }
                // If entering player's screen, place at edge
                if (_pellinoreScreen == _currentScreen)
                {
                    _pellinorePos = new Vector2(
                        _arena.Left + 60 + (float)_rng.NextDouble() * (_arena.Width - 120),
                        _arena.Top + 60 + (float)_rng.NextDouble() * (_arena.Height - 120));
                    _textBoxMessage = "A cold presence lingers...";
                    _textBoxWaiting = true;
                }
            }
            return;
        }
        
        // On player's screen
        if (_pellinoreStaggerTimer > 0) return;
        
        // If player is in cave, Pellinore waits outside (can't fit through entrance)
        if (_inCave) return;
        
        // Move toward player
        Vector2 toPlayer = _playerPos - _pellinorePos;
        float dist = toPlayer.Length();
        if (dist > 5f)
        {
            Vector2 dir = toPlayer / dist;
            _pellinorePos += dir * _pellinoreSpeed * dt;
            _pellinoreFacing = dir.X >= 0 ? 1 : -1;
        }
        
        // Clamp to arena
        _pellinorePos.X = MathHelper.Clamp(_pellinorePos.X, _arena.Left + 20, _arena.Right - 20);
        _pellinorePos.Y = MathHelper.Clamp(_pellinorePos.Y, _arena.Top + 20, _arena.Bottom - 20);
        
        // Lance thrust attack
        _pellinoreAttackTimer -= dt;
        if (_pellinoreAttackTimer <= 0 && _pellinoreCharging <= 0 && dist < 150f)
        {
            _pellinoreCharging = 0.3f;
            _pellinoreChargeDir = dist > 1f ? toPlayer / dist : new Vector2(_pellinoreFacing, 0);
            _pellinoreAttackTimer = 1.8f;
        }
        if (_pellinoreCharging > 0)
        {
            _pellinoreCharging -= dt;
            _pellinorePos += _pellinoreChargeDir * 400f * dt; // fast thrust
            _pellinorePos.X = MathHelper.Clamp(_pellinorePos.X, _arena.Left + 10, _arena.Right - 10);
            _pellinorePos.Y = MathHelper.Clamp(_pellinorePos.Y, _arena.Top + 10, _arena.Bottom - 10);
            if (Vector2.Distance(_playerPos, _pellinorePos) < 20f && _iFrameTimer <= 0)
            {
                _playerHp -= 15f;
                _iFrameTimer = 0.8f;
                _trauma = MathF.Min(_trauma + 0.25f, 1f);
            }
        }
        
        // Spectral howl
        _pellinoreHowlTimer -= dt;
        if (_pellinoreHowlTimer <= 0)
        {
            _pellinoreHowlTimer = 3.5f;
            for (int i = 0; i < 8; i++)
            {
                float angle = i * MathF.PI * 2f / 8f;
                _enemyProjectiles.Add(new EnemyProjectile
                {
                    Position = _pellinorePos,
                    Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 110f,
                    Damage = 10f,
                    Life = 3f,
                    Color = new Color(160, 170, 220),
                    Size = 4f
                });
            }
            _trauma = MathF.Min(_trauma + 0.1f, 1f);
        }
        
        // Trail particles
        _pellinoreTrailTimer -= dt;
        if (_pellinoreTrailTimer <= 0)
        {
            _pellinoreTrailTimer = 0.08f;
            _particles.Add(new Particle
            {
                Position = _pellinorePos + new Vector2(_rng.Next(-4, 4), _rng.Next(-4, 8)),
                Velocity = new Vector2(0, -10f),
                Life = 0.4f, MaxLife = 0.4f,
                Color = new Color(140, 160, 200) * 0.4f,
                Size = 1.5f + (float)_rng.NextDouble()
            });
        }
        
        // Projectile collision (player projectiles hitting Pellinore)
        for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
        {
            var proj = _projectiles[pi];
            if (!proj.Alive) continue;
            // Beam/lance: line-vs-circle intersection
            float hitDist;
            if (proj.BeamLen > 0 && proj.BeamDirection.LengthSquared() > 0.1f)
            {
                Vector2 beamDir = proj.BeamDirection;
                if (beamDir.LengthSquared() > 0.1f) beamDir.Normalize();
                Vector2 toP = _pellinorePos - proj.Position;
                float along = Vector2.Dot(toP, beamDir);
                along = MathHelper.Clamp(along, 0, proj.BeamLen);
                Vector2 closest = proj.Position + beamDir * along;
                hitDist = Vector2.Distance(closest, _pellinorePos);
            }
            else if (proj.BladeLength > 0 && proj.SwingEndAngle != proj.SwingStartAngle)
            {
                // Swing arc check (Hiten, Dragon Slayer, etc.)
                float swingT = MathHelper.Clamp(proj.Age / MathF.Max(proj.Lifetime, 0.01f), 0f, 1f);
                float easedT = (proj.FusionName == "DragonSlayer" || proj.FusionName == "DragonSlayerAfter")
                    ? swingT * swingT
                    : 1f - (1f - swingT) * (1f - swingT);
                float currentAngle = MathHelper.Lerp(proj.SwingStartAngle, proj.SwingEndAngle, easedT);
                Vector2 toP = _pellinorePos - proj.Position;
                float pDist = toP.Length();
                if (pDist < proj.BladeLength + 12f && pDist > 6f)
                {
                    float pAngle = MathF.Atan2(toP.Y, toP.X);
                    float angleDiff = pAngle - currentAngle;
                    while (angleDiff > MathF.PI) angleDiff -= MathF.PI * 2f;
                    while (angleDiff < -MathF.PI) angleDiff += MathF.PI * 2f;
                    hitDist = MathF.Abs(angleDiff) < 0.4f ? 0f : float.MaxValue;
                }
                else hitDist = float.MaxValue;
            }
            else
            {
                hitDist = Vector2.Distance(proj.Position, _pellinorePos);
            }
            if (hitDist < 18f)
            {
                // Ghost immunity: only Hollow essence can harm Pellinore
                bool isHollow = proj.Params.EssenceType == Essence.Hollow || _loadout.Essence == Essence.Hollow;
                if (!isHollow)
                {
                    // Phase through — ghostly "immune" feedback
                    if (!proj.Params.Piercing)
                        _projectiles.RemoveAt(pi);
                    // Ethereal wisps showing the attack passed through
                    for (int p = 0; p < 3; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = _pellinorePos + new Vector2(MathF.Cos(a) * 6f, MathF.Sin(a) * 6f),
                            Velocity = new Vector2(MathF.Cos(a) * 20f, MathF.Sin(a) * 20f - 15f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(160, 180, 220) * 0.3f,
                            Size = 2f,
                        });
                    }
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = _pellinorePos + new Vector2(-20, -20),
                        Text = "IMMUNE",
                        Color = new Color(160, 180, 220) * 0.6f,
                        Life = 0.8f, MaxLife = 0.8f,
                    });
                    continue;
                }
                float dmg = proj.Params.BaseDamage;
                _pellinoreHp -= dmg;
                _pellinoreHitFlash = 0.1f;
                _pellinoreStagger += dmg;
                if (_pellinoreStagger >= 50f)
                {
                    _pellinoreStagger = 0;
                    _pellinoreStaggerTimer = 1f;
                    _pellinoreCharging = 0;
                }
                if (!proj.Params.Piercing)
                    _projectiles.RemoveAt(pi);
                
                // Hit particles
                for (int p = 0; p < 5; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = _pellinorePos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 50f,
                        Life = 0.25f, MaxLife = 0.25f,
                        Color = Color.White,
                        Size = 1.5f
                    });
                }
                
                if (_pellinoreHp <= 0)
                {
                    _pellinoreDeathTimer = 3f;
                    _pellinoreCharging = 0;
                    // Big death burst
                    for (int p = 0; p < 30; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        float sp = 40f + (float)_rng.NextDouble() * 100f;
                        float li = 0.8f + (float)_rng.NextDouble() * 0.5f;
                        _particles.Add(new Particle
                        {
                            Position = _pellinorePos,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * sp,
                            Life = li, MaxLife = li,
                            Color = new Color(220, 210, 180),
                            Size = 2f + (float)_rng.NextDouble() * 3f
                        });
                    }
                    return;
                }
            }
        }
    }
    
    private static int RoomDist(int a, int b)
    {
        int ax = (a - 1) % 3, ay = (a - 1) / 3;
        int bx = (b - 1) % 3, by = (b - 1) / 3;
        return Math.Abs(ax - bx) + Math.Abs(ay - by);
    }
    
    private void DrawPellinore()
    {
        if (!_pellinoreActive || _pellinoreScreen != _currentScreen) return;
        
        float time = _totalTime;
        float alpha = _pellinoreAlpha + MathF.Sin(time * 3f) * 0.1f;
        if (_pellinoreDeathTimer > 0)
            alpha *= MathHelper.Clamp(_pellinoreDeathTimer / 3f, 0, 1) * (MathF.Sin(time * 20f) > 0 ? 1f : 0.3f);
        
        Color bodyCol = _pellinoreHitFlash > 0 ? Color.White : new Color(140, 160, 200) * alpha;
        Color helmetCol = _pellinoreHitFlash > 0 ? Color.White : new Color(170, 185, 220) * alpha;
        Color lanceCol = _pellinoreHitFlash > 0 ? Color.White : new Color(220, 220, 240) * alpha;
        
        int px = (int)_pellinorePos.X;
        int py = (int)_pellinorePos.Y;
        
        // Body
        DrawRect(px - 6, py - 12, 12, 24, bodyCol);
        // Helmet
        DrawRect(px - 6, py - 20, 12, 8, helmetCol);
        // Visor slit
        DrawRect(px - 3, py - 16, 6, 2, new Color(40, 40, 60) * alpha);
        // Lance
        int lanceDir = _pellinoreFacing;
        DrawRect(px + lanceDir * 6, py - 4, lanceDir * 24, 2, lanceCol);
        DrawRect(px + lanceDir * 28, py - 6, 2, 6, lanceCol); // lance tip
        // Shoulder pauldrons
        DrawRect(px - 8, py - 12, 3, 6, helmetCol);
        DrawRect(px + 5, py - 12, 3, 6, helmetCol);
        // Ghostly cloak trail
        float cloakSway = MathF.Sin(time * 2.5f) * 3f;
        DrawRect(px - 5 + (int)cloakSway, py + 12, 10, 6, bodyCol * 0.5f);
        DrawRect(px - 3 + (int)(cloakSway * 0.7f), py + 18, 6, 4, bodyCol * 0.3f);
        
        // HP bar (only when damaged)
        if (_pellinoreHp < PellinoreMaxHp && _pellinoreDeathTimer <= 0)
        {
            int barW = 40;
            int barX = px - barW / 2;
            int barY = py - 28;
            DrawRect(barX - 1, barY - 1, barW + 2, 5, Color.Black * 0.6f);
            DrawRect(barX, barY, barW, 3, new Color(40, 0, 0));
            int fillW = (int)(barW * MathHelper.Clamp(_pellinoreHp / PellinoreMaxHp, 0, 1));
            DrawRect(barX, barY, fillW, 3, new Color(200, 60, 60));
        }
        
        // Stagger indicator
        if (_pellinoreStaggerTimer > 0)
        {
            float starSpin = time * 5f;
            for (int s = 0; s < 3; s++)
            {
                float sa = starSpin + s * MathF.PI * 2f / 3f;
                int sx = px + (int)(MathF.Cos(sa) * 12f);
                int sy = py - 24 + (int)(MathF.Sin(sa) * 4f);
                DrawRect(sx, sy, 2, 2, new Color(255, 255, 100) * 0.7f);
            }
        }
    }
    
    private void DrawRoom9Boss()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 9) return;
        
        float time = _totalTime;
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        
        // Dark cavern floor with red ambient
        for (int row = 0; row < ah; row += 12)
        {
            float tt = (float)row / ah;
            DrawRect(ax, ay + row, aw, 12, new Color(20, 8, 8) * (0.2f + tt * 0.1f));
        }
        
        // Bone fragments in walls
        for (int b = 0; b < 12; b++)
        {
            int bx = ax + 10 + (b * 97) % (aw - 20);
            int by = ay + (b < 6 ? 5 : ah - 15);
            DrawRect(bx, by, 8 + b % 3 * 4, 6, new Color(180, 170, 140) * 0.3f);
            DrawRect(bx + 2, by + 1, 4, 3, new Color(200, 190, 160) * 0.2f);
        }
        
        // Red ambient pulse
        float pulse = (MathF.Sin(time * 1.5f) + 1f) / 2f;
        DrawRect(ax, ay, aw, ah, new Color(80, 15, 10) * (0.03f + pulse * 0.02f));
        
        // Lava pools
        foreach (var pool in _bossLavaPools)
        {
            float spawnScale = pool.SpawnTimer > 0 ? 1f - pool.SpawnTimer / 0.5f : 1f;
            float fadeAlpha = pool.FadeTimer > 0 ? pool.FadeTimer / 2f : 1f;
            float alpha = spawnScale * fadeAlpha;
            int pw = (int)(pool.Rect.Width * spawnScale);
            int ph = (int)(pool.Rect.Height * spawnScale);
            int px = pool.Rect.Center.X - pw / 2;
            int py = pool.Rect.Center.Y - ph / 2;
            DrawRect(px - 4, py - 4, pw + 8, ph + 8, new Color(200, 80, 20) * 0.15f * alpha);
            float lavaPulse = (MathF.Sin(time * 3f + pool.Rect.X * 0.05f) + 1f) / 2f;
            DrawRect(px, py, pw, ph, new Color(200, 70, 20) * (0.6f + lavaPulse * 0.2f) * alpha);
            DrawRect(px + 4, py + 3, pw - 8, ph - 6, new Color(255, 140, 40) * (0.4f + lavaPulse * 0.3f) * alpha);
            DrawRect(px + 8, py + 6, pw - 16, ph / 3, new Color(255, 200, 80) * (0.3f + lavaPulse * 0.2f) * alpha);
        }
        
        // Corner bone pillars
        foreach (var wall in _screenWalls[9])
        {
            DrawRect(wall.X, wall.Y, wall.Width, wall.Height, new Color(160, 150, 120));
            DrawRect(wall.X + 3, wall.Y + 3, wall.Width - 6, wall.Height - 6, new Color(180, 170, 140));
            DrawRect(wall.X + 6, wall.Y - 4, 12, 8, new Color(190, 180, 150));
            DrawRect(wall.X + 8, wall.Y - 2, 3, 3, new Color(40, 20, 20));
            DrawRect(wall.X + 13, wall.Y - 2, 3, 3, new Color(40, 20, 20));
        }
        
        if (_bossSegments == null) return;
        
        // Boss intro name card
        if (!_bossIntroDone && _bossIntroTimer > 1.5f)
        {
            string bossName = "BONE WYRM";
            int nw = MeasureText(bossName, 2f);
            float cardAlpha = MathF.Min((_bossIntroTimer - 1.5f) * 2f, 1f);
            DrawRect(ax + aw / 2 - nw / 2 - 20, ay + ah / 2 - 20, nw + 40, 40, Color.Black * cardAlpha * 0.7f);
            DrawTextOutlined(ax + aw / 2 - nw / 2, ay + ah / 2 - 10, bossName, new Color(220, 180, 140) * cardAlpha, Color.Black * cardAlpha, 2f);
        }
        
        // Draw segments (tail to head)
        bool flashOn = _bossHitFlash > 0 && ((int)(_bossHitFlash * 20) % 2 == 0);
        // Body stays mostly opaque during death; only eyes/tail fade
        float bodyDeathAlpha = _bossDeathTimer > 0 ? MathF.Max(0.8f, 1f - _bossDeathTimer / 10f) : 1f;
        float eyeDeathFade = _bossDeathTimer > 0 ? MathF.Max(0f, 1f - _bossDeathTimer / 2f) : 1f;
        float tailDeathFade = _bossDeathTimer > 0 ? MathF.Max(0f, 1f - _bossDeathTimer / 1.5f) : 1f;
        
        for (int i = _bossSegmentCount - 1; i >= 0; i--)
        {
            float t2 = (float)i / (_bossSegmentCount - 1);
            float segSize = MathHelper.Lerp(_bossHeadSize, _bossTailSize, t2);
            Vector2 pos = _bossSegments[i];
            float angle = _bossSegmentAngles[i];
            
            if (i == 0)
            {
                // HEAD — triangular Hades style
                Color headColor = flashOn ? Color.White : (_bossRageTimer > 0 ? new Color(220, 100, 80) : new Color(200, 185, 150));
                headColor *= bodyDeathAlpha;
                float cos = MathF.Cos(angle);
                float sin = MathF.Sin(angle);
                
                int hw = (int)(segSize * 0.8f);
                int hh = (int)(segSize * 0.6f);
                DrawRect((int)(pos.X - hw / 2), (int)(pos.Y - hh / 2), hw, hh, headColor);
                
                int sw = (int)(segSize * 0.5f);
                int sh = (int)(segSize * 0.3f);
                DrawRect((int)(pos.X + cos * segSize * 0.4f - sw / 2), (int)(pos.Y + sin * segSize * 0.4f - sh / 2), sw, sh, headColor * 0.9f);
                DrawRect((int)(pos.X + cos * segSize * 0.6f - sw / 3), (int)(pos.Y + sin * segSize * 0.6f - sh / 3), sw / 2, sh / 2, headColor * 0.8f);
                
                // Eyes
                float eyeOff = segSize * 0.15f;
                float perpX = -sin;
                float perpY = cos;
                Color eyeColor = (_bossRageTimer > 0 ? new Color(255, 60, 30) : new Color(200, 40, 40)) * eyeDeathFade;
                // Dim eyes during death
                if (_bossDeathTimer > 0)
                {
                    float dimFactor = MathF.Max(0, 1f - _bossDeathTimer / 2f);
                    eyeColor = new Color((int)(eyeColor.R * dimFactor), (int)(eyeColor.G * dimFactor), (int)(eyeColor.B * dimFactor));
                }
                DrawRect((int)(pos.X + cos * 4 + perpX * eyeOff - 2), (int)(pos.Y + sin * 4 + perpY * eyeOff - 2), 4, 4, eyeColor);
                DrawRect((int)(pos.X + cos * 4 - perpX * eyeOff - 2), (int)(pos.Y + sin * 4 - perpY * eyeOff - 2), 4, 4, eyeColor);
                
                // Jaw
                DrawRect((int)(pos.X + cos * segSize * 0.3f - 3), (int)(pos.Y + sin * segSize * 0.3f + 2), 6, 2, new Color(120, 100, 80));
            }
            else if (i == _bossSegmentCount - 1)
            {
                // TAIL — glowing weak point
                Color tailBase = flashOn ? Color.White : new Color(255, 200, 80);
                float localTailFade = _bossDeathTimer > 0 ? MathF.Max(0f, 1f - _bossDeathTimer / 1.5f) : 1f;
                tailBase *= localTailFade;
                float tailPulse = (MathF.Sin(time * 4f) + 1f) / 2f;
                
                DrawRect((int)(pos.X - segSize - 4), (int)(pos.Y - segSize - 4), (int)(segSize * 2 + 8), (int)(segSize * 2 + 8), 
                    new Color(255, 180, 60) * (0.1f + tailPulse * 0.08f));
                DrawRect((int)(pos.X - segSize / 2), (int)(pos.Y - segSize / 2), (int)segSize, (int)segSize, tailBase * (0.8f + tailPulse * 0.2f));
                DrawRect((int)(pos.X - segSize / 3), (int)(pos.Y - segSize / 3), (int)(segSize * 0.6f), (int)(segSize * 0.6f), Color.White * 0.3f);
            }
            else
            {
                // BODY — bone segments with ribs
                Color bodyColor = flashOn ? Color.White : new Color(190 - (int)(t2 * 30), 175 - (int)(t2 * 25), 140 - (int)(t2 * 20));
                bodyColor *= (i >= _bossSegmentCount - 3) ? tailDeathFade : bodyDeathAlpha;
                DrawRect((int)(pos.X - segSize / 2), (int)(pos.Y - segSize / 2), (int)segSize, (int)segSize, bodyColor);
                if (i % 2 == 0)
                    DrawRect((int)(pos.X - segSize / 2 + 1), (int)(pos.Y - 1), (int)segSize - 2, 2, bodyColor * 0.7f);
                DrawRect((int)(pos.X - 1), (int)(pos.Y - segSize / 2), 2, (int)segSize, new Color(210, 200, 170) * 0.3f);
                // Crack lines during death
                if (_bossDeathTimer > 0)
                {
                    float crackAlpha = MathF.Min(_bossDeathTimer / 1.5f, 1f);
                    Color crackCol = new Color(40, 30, 20) * crackAlpha;
                    int sx = (int)(pos.X - segSize / 2);
                    int sy = (int)(pos.Y - segSize / 2);
                    int ss = (int)segSize;
                    DrawRect(sx + ss / 4, sy, 1, ss / 2, crackCol);
                    DrawRect(sx + ss / 4, sy + ss / 3, ss / 3, 1, crackCol);
                    DrawRect(sx + ss * 2 / 3, sy + ss / 4, 1, ss / 2, crackCol);
                }
            }
        }
        
        // HP bar
        if (_bossActive && _bossIntroDone)
        {
            int barW = 400;
            int barH = 12;
            int barX = ax + aw / 2 - barW / 2;
            int barY = ay + 15;
            float hpPctDraw = MathF.Max(0, _bossHp / _bossMaxHp);
            
            DrawRect(barX - 1, barY - 1, barW + 2, barH + 2, Color.Black * 0.8f);
            Color hpColor = hpPctDraw > 0.5f ? new Color(200, 60, 60) : hpPctDraw > 0.25f ? new Color(220, 120, 40) : new Color(255, 50, 30);
            DrawRect(barX, barY, (int)(barW * hpPctDraw), barH, hpColor);
            DrawRect(barX, barY, (int)(barW * hpPctDraw), 2, Color.White * 0.15f);
            
            string label = "BONE WYRM";
            int lw = MeasureText(label, 1f);
            DrawTextOutlined(ax + aw / 2 - lw / 2, barY + barH + 4, label, new Color(200, 180, 140), Color.Black * 0.6f, 1f);
        }
        
        // Rising embers
        for (int e = 0; e < 6; e++)
        {
            float ex = ax + 40 + (e * 173) % (aw - 80);
            float ey = ay + ah - 5 - ((time * 20 + e * 67) % (ah + 30));
            float ea = (MathF.Sin(time * 2f + e * 1.7f) + 1f) / 2f * 0.3f;
            DrawRect((int)ex, (int)ey, 2, 2, new Color(255, 100, 30) * ea);
        }
    }
    
    private void CheckAwakeningRoom2Completion()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 2) return;
        if (_clearedScreens.Contains(2)) return;
        if (_enemies.Any(e => e.Alive)) return;
        
        // All dummies destroyed — spawn Lance on a pedestal (mark cleared immediately)
        _clearedScreens.Add(2);
        TriggerRoomCleared("Training Grounds");
        
        float cx = _arena.Center.X;
        float cy = _arena.Center.Y;
        
        _pickups.Add(new PickupItem
        {
            Position = new Vector2(cx, cy - 20),
            Name = "Lance",
            DisplayText = "Lance Form Obtained",
            Type = "lance",
            Collected = false,
            BobTimer = 0f,
            GlowColor = new Color(100, 180, 255) // blue
        });
        
        _textBoxMessage = "The Lance. A focused beam of pure energy.";
        _textBoxWaiting = true;
    }
    
    private void UnlockAwakeningDoors(DoorKeyType keyType)
    {
        for (int i = 0; i < _doors.Count; i++)
        {
            var d = _doors[i];
            if (d.KeyType == keyType && d.State == DoorState.Locked)
            {
                d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                _doors[i] = d;
            }
        }
    }
    
