    private void UpdateEtherDrops(float dt)
    {
        for (int i = _etherDrops.Count - 1; i >= 0; i--)
        {
            var d = _etherDrops[i];
            d.Life -= dt;
            if (d.Life <= 0) { _etherDrops.RemoveAt(i); continue; }
            
            if (!d.IsHard && !d.IsClip && !d.IsArmor)
            {
                // Liquid ether: scatter then home toward player
                d.MagnetTimer -= dt;
                if (d.MagnetTimer <= 0)
                {
                    // Home toward player
                    Vector2 toPlayer = _playerPos - d.Position;
                    float dist = toPlayer.Length();
                    if (dist > 1f)
                    {
                        toPlayer /= dist;
                        float magnetSpeed = 200f + (8f - d.Life) * 40f; // accelerates over time
                        d.Velocity = toPlayer * magnetSpeed;
                    }
                }
                else
                {
                    // Decelerate during scatter
                    d.Velocity *= 1f - 5f * dt;
                }
                
                // Collect on proximity
                if (Vector2.Distance(d.Position, _playerPos) < 18f)
                {
                    _playerEther = MathF.Min(_playerEther + d.Amount, EffectiveMaxEther);
                    // Small blue flash
                    _particles.Add(new Particle
                    {
                        Position = d.Position,
                        Velocity = Vector2.Zero,
                        Life = 0.15f, MaxLife = 0.15f,
                        Color = new Color(80, 160, 255) * 0.8f,
                        Size = 4f,
                    });
                    _etherDrops.RemoveAt(i); continue;
                }
            }
            else if (d.IsClip)
            {
                // Clip drop: friction, walk over to pick up
                d.Velocity *= 1f - 4f * dt;
                d.MagnetTimer -= dt;
                if (d.MagnetTimer <= 0 && Vector2.Distance(d.Position, _playerPos) < 16f)
                {
                    if (!SackAddClip(d.ClipEP)) goto skipClipPickup; // sack full — leave on ground
                    Color clipCol = d.ClipEP >= 100 ? new Color(160, 120, 255) :
                                    d.ClipEP >= 50 ? new Color(80, 160, 255) :
                                    new Color(80, 200, 230);
                    for (int p = 0; p < 4; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = d.Position,
                            Velocity = new Vector2(MathF.Cos(a) * 25f, MathF.Sin(a) * 25f),
                            Life = 0.25f, MaxLife = 0.25f,
                            Color = clipCol * 0.8f,
                            Size = 3f,
                        });
                    }
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = d.Position + new Vector2(-8, -15),
                        Text = "+CLIP",
                        Color = clipCol,
                        Life = 0.8f, MaxLife = 0.8f,
                    });
                    _etherDrops.RemoveAt(i); continue;
                }
                skipClipPickup:;
            }
            else if (d.IsArmor)
            {
                // Armor drop: friction, walk over to pick up into sack
                d.Velocity *= 1f - 4f * dt;
                d.MagnetTimer -= dt;
                if (d.MagnetTimer <= 0 && Vector2.Distance(d.Position, _playerPos) < 16f)
                {
                    // Try to add to sack as 2×2
                    bool added = false;
                    var occupied = new HashSet<(int, int)>();
                    foreach (var s in _sackItems)
                        for (int dy = 0; dy < Math.Max(1, s.Height); dy++)
                            for (int dx = 0; dx < Math.Max(1, s.Width); dx++)
                                occupied.Add((s.GridX + dx, s.GridY + dy));
                    for (int gy = 0; gy <= SackGridSize - 2 && !added; gy++)
                        for (int gx = 0; gx <= SackGridSize - 2 && !added; gx++)
                        {
                            bool fits = true;
                            for (int dy = 0; dy < 2 && fits; dy++)
                                for (int dx = 0; dx < 2 && fits; dx++)
                                    if (occupied.Contains((gx + dx, gy + dy))) fits = false;
                            if (fits)
                            {
                                _sackItems.Add(new SackItem { Type = SackItemType.Armor, Armor = d.ArmorDrop, Count = 1, MaxStack = 1, GridX = gx, GridY = gy, Width = 2, Height = 2 });
                                added = true;
                            }
                        }
                    if (!added) goto skipArmorPickup; // sack full — leave on ground
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = d.Position + new Vector2(-20, -15),
                        Text = "+ARMOR",
                        Color = new Color(120, 100, 160),
                        Life = 1f, MaxLife = 1f,
                    });
                    for (int p = 0; p < 6; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = d.Position,
                            Velocity = new Vector2(MathF.Cos(a) * 30f, MathF.Sin(a) * 30f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(120, 100, 160) * 0.8f,
                            Size = 3f,
                        });
                    }
                    _etherDrops.RemoveAt(i); continue;
                }
                skipArmorPickup:;
            }
            else
            {
                // Hard ether: friction, no homing
                d.Velocity *= 1f - 4f * dt;
                
                // Collect on proximity (walk over)
                if (Vector2.Distance(d.Position, _playerPos) < 14f)
                {
                    _hardEther += (int)d.Amount;
                    // Crystal collect flash
                    for (int p = 0; p < 6; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = d.Position,
                            Velocity = new Vector2(MathF.Cos(a) * 30f, MathF.Sin(a) * 30f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(200, 180, 255) * 0.7f,
                            Size = 2f,
                        });
                    }
                    _floatingTexts.Add(new FloatingText
                    {
                        Position = d.Position + new Vector2(-6, -12),
                        Text = "+" + (int)d.Amount,
                        Color = new Color(200, 180, 255),
                        Life = 0.8f, MaxLife = 0.8f,
                    });
                    _etherDrops.RemoveAt(i); continue;
                }
            }
            
            d.Position += d.Velocity * dt;
            // Clamp to arena
            d.Position.X = MathHelper.Clamp(d.Position.X, _arena.Left + 4, _arena.Right - 4);
            d.Position.Y = MathHelper.Clamp(d.Position.Y, _arena.Top + 4, _arena.Bottom - 4);
            _etherDrops[i] = d;
        }
    }
    
    private void UpdateTripwires(float dt)
    {
        // Update tripwire lifetimes and check enemy collisions
        for (int i = _tripwires.Count - 1; i >= 0; i--)
        {
            var tw = _tripwires[i];
            tw.Life -= dt;
            if (tw.Life <= 0) { _tripwires.RemoveAt(i); continue; }
            _tripwires[i] = tw;
            
            // Check enemy intersection with tripwire line
            Vector2 wireDir = tw.End - tw.Start;
            float wireLen = wireDir.Length();
            if (wireLen < 1) continue;
            wireDir /= wireLen;
            
            for (int ei = 0; ei < _enemies.Count; ei++)
            {
                var e = _enemies[ei];
                if (!e.Alive || e.StaggerTimer > 0) continue;
                
                // Point-to-line distance
                Vector2 toEnemy = e.Position - tw.Start;
                float proj2 = Vector2.Dot(toEnemy, wireDir);
                if (proj2 < 0 || proj2 > wireLen) continue;
                Vector2 closest = tw.Start + wireDir * proj2;
                float dist = Vector2.Distance(closest, e.Position);
                
                if (dist < e.Size + 4)
                {
                    // Skip if already hit this enemy on this wire
                    if (tw.HitEnemies != null && tw.HitEnemies.Contains(e.Id)) continue;
                    
                    // Stun + damage the enemy
                    e.StaggerTimer = 1.0f;
                    e.HitFlash = 0.15f;
                    e.KnockbackVel = Vector2.Zero;
                    if (tw.Damage > 0) { e.Hp -= tw.Damage; if (e.Hp <= 0) e.Alive = false; }
                    _enemies[ei] = e;
                    if (tw.HitEnemies != null) tw.HitEnemies.Add(e.Id);
                    tw.HitsLeft--;
                    _tripwires[i] = tw;
                    
                    // Damage number
                    if (tw.Damage > 0)
                        _damageNumbers.Add(new DamageNumber { Position = e.Position + new Vector2(0, -12), Amount = tw.Damage, Timer = 0.8f, Color = tw.WireColor });
                    
                    // Snap particles at hit point
                    for (int p2 = 0; p2 < 5; p2++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = closest + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                            Velocity = new Vector2((float)_rng.NextDouble() * 40f - 20f, -20f - (float)_rng.NextDouble() * 15f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = tw.WireColor,
                            Size = 2f
                        });
                    }
                    _trauma = MathF.Min(_trauma + 0.08f, 0.3f);
                    PlaySfx(_sfxHit, 0.3f);
                    
                    if (tw.HitsLeft <= 0)
                    {
                        // Break the wire with particles
                        for (int p2 = 0; p2 < 8; p2++)
                        {
                            float t2 = (float)p2 / 7f;
                            _particles.Add(new Particle
                            {
                                Position = Vector2.Lerp(tw.Start, tw.End, t2),
                                Velocity = new Vector2((float)_rng.NextDouble() * 40f - 20f, -30f - (float)_rng.NextDouble() * 20f),
                                Life = 0.4f, MaxLife = 0.4f,
                                Color = tw.WireColor,
                                Size = 2f
                            });
                        }
                        _tripwires.RemoveAt(i);
                        break;
                    }
                }
            }
        }
    }
    
    private void UpdatePickups(float dt)
    {
        var kb = Keyboard.GetState();
        
        // Cave transition
        if (_caveTransitionTimer > 0)
        {
            _caveTransitionTimer -= dt;
            if (_caveTransitionTimer <= 0)
            {
                if (_caveTransitionIn)
                {
                    _inCave = true;
                    _torches.Clear(); // hide overworld torches in cave
                    // Add cave interior light (dim, centered)
                    _torches.Add(new Vector2(ScreenW / 2f, ScreenH / 2f));
                    AddTorchesFromTiles(50); // scan cave tile data for lights
                    _playerPos = new Vector2(_caveExit.Center.X, _caveExit.Center.Y - 40);
                }
                else
                {
                    // Already on overworld — just finalize position
                    _playerPos = _caveReturnPos;
                }
            }
            return; // freeze during transition
        }
        
        // Check cave entrance (overworld)
        if (!_inCave && _gameMode == GameMode.Awakening && _currentScreen == 5)
        {
            if (_caveEntrance.Contains((int)_playerPos.X, (int)_playerPos.Y))
            {
                _caveReturnPos = new Vector2(_caveEntrance.Center.X, _caveEntrance.Bottom + 20);
                _caveTransStartPos = _playerPos;
                _caveTransitionIn = true;
                _caveTransitionTimer = CaveTransitionDuration;
                _roomNameDisplay = "The Cave";
                _roomNameTimer = 3f;
            }
            
            // Merchant interaction
            if (_merchantActive)
            {
                _merchantPos = new Vector2(_arena.Left + 700, _arena.Top + 300);
                if (_merchantHitFlash > 0) _merchantHitFlash -= dt;
                
                // First visit tooltip
                if (_merchantFirstVisit && Vector2.Distance(_playerPos, _merchantPos) < 60f)
                {
                    _merchantFirstVisit = false;
                    _textBoxMessage = "Exchange your crystal ether for liquid ether here.";
                    _textBoxWaiting = true;
                }
                // Projectile collision with merchant
                for (int pi = _projectiles.Count - 1; pi >= 0; pi--)
                {
                    if (Vector2.Distance(_projectiles[pi].Position, _merchantPos) < 18f)
                    {
                        _merchantHp = MathF.Max(0, _merchantHp - 5f);
                        _merchantHitFlash = 0.15f;
                        _projectiles.RemoveAt(pi);
                    }
                }
                
                var kb2 = Keyboard.GetState();
                if (Vector2.Distance(_playerPos, _merchantPos) < 40f && kb2.IsKeyDown(Keys.E) && !_prevKb.IsKeyDown(Keys.E))
                {
                    bool allCleared = true;
                    for (int r = 1; r <= 9; r++)
                        if (!_clearedScreens.Contains(r)) { allCleared = false; break; }
                    
                    // Merchant sells large clips only
                    if (_hardEther >= LargeClipCost)
                    {
                        _hardEther -= LargeClipCost;
                        SackAddClip(100);
                        _textBoxMessage = $"\"A full crystal charge — the finest I can offer.\"\n\n+1 Large Clip (100EP) — {SackClipCount()} clips total\nCrystals remaining: {_hardEther}";
                        _textBoxWaiting = true;
                        for (int cp = 0; cp < 12; cp++)
                        {
                            float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                            _particles.Add(new Particle
                            {
                                Position = _merchantPos + new Vector2(MathF.Cos(a) * 25f, MathF.Sin(a) * 25f),
                                Velocity = -new Vector2(MathF.Cos(a), MathF.Sin(a)) * 40f,
                                Life = 0.5f, MaxLife = 0.5f,
                                Color = new Color(160, 120, 255) * 0.8f,
                                Size = 2.5f,
                            });
                        }
                        _floatingTexts.Add(new FloatingText
                        {
                            Position = _merchantPos + new Vector2(-20, -35),
                            Text = "+Large CLIP",
                            Color = new Color(200, 180, 255),
                            Life = 1f, MaxLife = 1f,
                        });
                    }
                    else
                    {
                        _textBoxMessage = $"\"I can crystallize your ether into a full wand charge...\"\n\nLarge Clip (100EP): {LargeClipCost} crystals\n\nYou have {_hardEther} crystals.";
                    }
                    _textBoxWaiting = true;
                }
            }
        }
        
        // Check cave exit (inside cave)
        if (_inCave)
        {
            if (_caveExit.Contains((int)_playerPos.X, (int)_playerPos.Y))
            {
                // Immediately switch to overworld, then play grow animation from cave entrance
                _inCave = false;
                AddTorchesFromTiles(5); // restore overworld torches
                _playerPos = _caveReturnPos;
                _caveTransStartPos = new Vector2(_caveEntrance.Center.X, _caveEntrance.Center.Y);
                _caveTransitionIn = false;
                _caveTransitionTimer = CaveTransitionDuration;
                _roomNameDisplay = AwakeningRoomNames[5];
                _roomNameTimer = 3f;
            }
            
            // Clamp player to cave bounds (alcove extends right wall when broken)
            float rightClamp = _caveArea.Right - 10;
            if (_crackedWallBroken)
            {
                var caa = _caveArea;
                int alcoveTop = caa.Y + caa.Height / 3 - 5;
                int alcoveBot = alcoveTop + 60;
                if (_playerPos.Y >= alcoveTop && _playerPos.Y <= alcoveBot)
                    rightClamp = _caveArea.Right + 55;
            }
            _playerPos.X = MathHelper.Clamp(_playerPos.X, _caveArea.Left + 10, rightClamp);
            _playerPos.Y = MathHelper.Clamp(_playerPos.Y, _caveArea.Top + 10, _caveArea.Bottom - 10);
            
            // Cracked wall — right wall of cave
            if (!_crackedWallBroken)
            {
                var ca = _caveArea;
                
                // Quake Stomp (Shatter-only ability) near the wall
                if (_loadout.Behavior == Behavior.Shatter && _loadout.Form == Form.None && _loadout.Essence == Essence.None)
                {
                    Rectangle stompZone = new Rectangle(ca.Right - 40, ca.Y + ca.Height / 3 - 10, 50, 70);
                    if (_behaviorAbilityCooldown <= 0 && stompZone.Contains((int)_playerPos.X, (int)_playerPos.Y))
                    {
                        // Stomp will be triggered by the ability — check if stomp just fired
                        // (handled by the shatter AoE hitting the wall zone)
                    }
                }
            }
            
            if (_crackedWallShakeTimer > 0) _crackedWallShakeTimer -= dt;
        }
        
        for (int i = 0; i < _pickups.Count; i++)
        {
            var p = _pickups[i];
            if (p.Collected) continue;
            p.BobTimer += dt;
            _pickups[i] = p;
            
            // Check player proximity (wand/wandofmerlin only collectable inside cave)
            if ((p.Type == "wand" || p.Type == "wandofmerlin") && !_inCave) continue;
            float dist = Vector2.Distance(_playerPos, p.Position);
            if (dist < 24f)
            {
                // Collect!
                p.Collected = true;
                _pickups[i] = p;
                
                // Apply item effect
                if (p.Type == "wand") { _hasWand = true; _unlockedForms.Add(Form.Bolt); _loadout.Form = Form.Bolt; RefreshCombo(); }
                else if (p.Type == "shield") { _hasShield = true; }
                else if (p.Type == "caliburn") { _hasCaliburn = true; }
                else if (p.Type == "wandofmerlin") { _hasWandOfMerlin = true; _ownsWandOfMerlin = true; }
                else if (p.Type == "pellinore_oath") { /* trophy relic — no gameplay effect yet */ }
                else if (p.Type == "nimue") { _hasNimueTear = true; }
                else if (p.Type == "tome") { _hasTomeOfBinding = true; _ownsTomeOfBinding = true; RefreshCombo(); }
                else if (p.Type == "behavior_linger") { _unlockedBehaviors.Add(Behavior.Linger); }
                else if (p.Type == "behavior_shatter") { _unlockedBehaviors.Add(Behavior.Shatter); }
                else if (p.Type == "behavior_bloom") { _unlockedBehaviors.Add(Behavior.Bloom); }
                else if (p.Type == "lance")
                {
                    _unlockedForms.Add(Form.Lance);
                    _loadout = _loadout with { Form = Form.Lance };
                }
                else if (p.Type == "haste") { _hasHasteBand = true; _ownsHasteBand = true; }
                else if (p.Type == "phylactery") { _hasPhylactery = true; _ownsPhylactery = true; }
                else if (p.Type == "grimoire_awakening") { _hasGrimoire = true; _ownsGrimoire = true; _clearedScreens.Add(8); TriggerRoomCleared("Lava Sanctum"); }
                
                // Trigger SOTN pickup effect
                _pickupFlashTimer = 0.3f;
                _pickupRingRadius = 0f;
                PlaySfx(_sfxPickup);
                _pickupText = p.DisplayText;
                _pickupTextTimer = 2.5f;
                _pickupEffectPos = p.Position;
                
                // Burst particles
                for (int j = 0; j < 30; j++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float speed = 50f + (float)_rng.NextDouble() * 150f;
                    _pickupParticles.Add(new Particle
                    {
                        Position = p.Position,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                        Life = 0.8f + (float)_rng.NextDouble() * 0.5f,
                        MaxLife = 1.3f,
                        Color = Color.Lerp(p.GlowColor, Color.White, (float)_rng.NextDouble() * 0.5f),
                        Size = 1.5f + (float)_rng.NextDouble() * 2f,
                    });
                }
                // Inward spiral then outward burst
                for (int j = 0; j < 15; j++)
                {
                    float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float dist2 = 60f + (float)_rng.NextDouble() * 40f;
                    _pickupParticles.Add(new Particle
                    {
                        Position = p.Position + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * dist2,
                        Velocity = new Vector2(MathF.Cos(angle + MathF.PI), MathF.Sin(angle + MathF.PI)) * 80f,
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = p.GlowColor,
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
        }
        
        // Update pickup effect
        if (_pickupFlashTimer > 0) _pickupFlashTimer -= dt;
        if (_roomClearedTimer > 0) _roomClearedTimer -= dt;
        if (_pickupTextTimer > 0) _pickupTextTimer -= dt;
        if (_pickupRingRadius < 200f && _pickupTextTimer > 0) _pickupRingRadius += 400f * dt;
        
        // Update pickup particles
        for (int i = _pickupParticles.Count - 1; i >= 0; i--)
        {
            var p = _pickupParticles[i];
            p.Position += p.Velocity * dt;
            p.Velocity *= 0.95f;
            p.Life -= dt;
            if (p.Life <= 0) { _pickupParticles.RemoveAt(i); continue; }
            _pickupParticles[i] = p;
        }
        
        // Room name timer (pause during text box)
        if (_roomNameTimer > 0 && _textBoxMessage == null) _roomNameTimer -= dt;
    }
    
    private void UpdateTextBox()
    {
        if (_textBoxMessage == null) return;
        var kb = Keyboard.GetState();
        if (_textBoxWaiting && (
            (kb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter)) ||
            (kb.IsKeyDown(Keys.Space) && !_prevKb.IsKeyDown(Keys.Space))))
        {
            _textBoxMessage = null;
            _textBoxWaiting = false;
        }
    }
    
    private void DrawCave()
    {
        if (!_inCave) return;
        
        // Black background (covers the arena)
        DrawRect(0, 0, ScreenW, ScreenH, new Color(5, 5, 8));
        
        var ca = _caveArea;
        
        // Painted tiles for cave (room 50) — draw at cave area position
        bool caveTiled = _roomTileData.ContainsKey(50) || _roomTileOverlay.ContainsKey(50);
        if (caveTiled)
        {
            var (caveCols, caveRows) = GetRoomTileSize(50);
            var bg = _roomTileData.TryGetValue(50, out var bgD) ? bgD : null;
            var fg = _roomTileOverlay.TryGetValue(50, out var fgD) ? fgD : null;
            // Offset: cave tiles start at cave area origin
            int ox = ca.X - TSDst; // 1 tile border
            int oy = ca.Y - TSDst;
            for (int r = 0; r < caveRows; r++)
            {
                for (int c = 0; c < caveCols; c++)
                {
                    int dx = ox + c * TSDst;
                    int dy = oy + r * TSDst;
                    // BG
                    bool drewBg = false;
                    if (bg != null && r < bg.GetLength(0) && c < bg.GetLength(1))
                    {
                        var (s, t) = bg[r, c];
                        if (s >= 0 && t >= 0 && _tsSheets[s] != null)
                        {
                            int sc = _tsSheets[s].Width / TS16;
                            _spriteBatch.Draw(_tsSheets[s], new Rectangle(dx, dy, TSDst, TSDst),
                                new Rectangle((t % sc) * TS16, (t / sc) * TS16, TS16, TS16), Color.White);
                            drewBg = true;
                        }
                    }
                    if (!drewBg) DrawRect(dx, dy, TSDst, TSDst, new Color(18, 16, 20));
                    // FG
                    if (fg != null && r < fg.GetLength(0) && c < fg.GetLength(1))
                    {
                        var (s2, t2) = fg[r, c];
                        if (s2 >= 0 && t2 >= 0 && _tsSheets[s2] != null)
                        {
                            int sc2 = _tsSheets[s2].Width / TS16;
                            _spriteBatch.Draw(_tsSheets[s2], new Rectangle(dx, dy, TSDst, TSDst),
                                new Rectangle((t2 % sc2) * TS16, (t2 / sc2) * TS16, TS16, TS16), Color.White);
                        }
                    }
                }
            }
        }
        else
        {
            // Fallback procedural cave
            DrawRect(ca.X, ca.Y, ca.Width, ca.Height, new Color(18, 16, 20)); // floor
        
        // Wall borders — rough stone look
        int wallThick = 12;
        DrawRect(ca.X - wallThick, ca.Y - wallThick, ca.Width + wallThick * 2, wallThick, new Color(45, 40, 38)); // top
        DrawRect(ca.X - wallThick, ca.Y, wallThick, ca.Height, new Color(40, 36, 34)); // left
        DrawRect(ca.Right, ca.Y, wallThick, ca.Height, new Color(40, 36, 34)); // right
        // Bottom wall with gap for exit
        int exitGap = 60;
        int exitX = ca.X + ca.Width / 2 - exitGap / 2;
        DrawRect(ca.X - wallThick, ca.Bottom, exitX - ca.X + wallThick, wallThick, new Color(45, 40, 38));
        DrawRect(exitX + exitGap, ca.Bottom, ca.Right - exitX - exitGap + wallThick, wallThick, new Color(45, 40, 38));
        
        // Wall texture — subtle horizontal lines
        for (int wy = ca.Y; wy < ca.Y + wallThick; wy += 4)
            DrawRect(ca.X, ca.Y - wallThick + (wy - ca.Y), ca.Width, 1, new Color(50, 45, 42) * 0.3f);
        
        // Light rays from exit
        int lightCX = _caveExit.Center.X;
        int lightCY = ca.Bottom;
        for (int r = 0; r < 5; r++)
        {
            float spread = (r - 2) * 18f;
            float rayAlpha = 0.08f - MathF.Abs(r - 2) * 0.015f;
            float rayW = 6f + MathF.Abs(r - 2) * 2f;
            // Rays fan upward from exit
            for (int ry = 0; ry < 80; ry += 2)
            {
                float t = ry / 80f;
                float x = lightCX + spread * t;
                float y = lightCY - ry;
                float a = rayAlpha * (1f - t * 0.7f);
                DrawRect((int)(x - rayW / 2), (int)y, (int)rayW, 2, new Color(255, 240, 200) * a);
            }
        }
        } // end else (non-tiled cave)
        
        // Exit label
        int lightCX2 = _caveExit.Center.X;
        int lightCY2 = ca.Bottom;
        DrawTextOutlined(lightCX2 - MeasureText("EXIT", 0.7f) / 2, lightCY2 + 4, "EXIT", new Color(200, 180, 140) * 0.6f, Color.Black * 0.3f, 0.7f);
        
        // ═══ Cracked Wall / Secret Alcove ═══
        float time = _totalTime;
        {
            int crackX = ca.Right + 6; // center of right wall (wall is 12px thick starting at ca.Right)
            int crackY = ca.Y + ca.Height / 3;
            int crackH = 50;
            
            if (!_crackedWallBroken)
            {
                // Crack lines on the right wall — darker than wall color (40,36,34)
                Color crackCol = new Color(20, 16, 14);
                Color crackGlow = new Color(80, 60, 50);
                // Main crack — a jagged vertical line
                DrawRect(crackX - 2, crackY + 5, 2, 16, crackCol);
                DrawRect(crackX - 1, crackY + 10, 2, 10, crackCol);
                DrawRect(crackX - 3, crackY + 21, 2, 12, crackCol);
                DrawRect(crackX, crackY + 30, 2, 8, crackCol);
                // Branching cracks
                DrawRect(crackX - 5, crackY + 14, 4, 2, crackCol);
                DrawRect(crackX - 6, crackY + 27, 5, 2, crackCol);
                DrawRect(crackX + 1, crackY + 18, 4, 2, crackCol);
                // Faint warm glow through the cracks (hints at something behind)
                float glowPulse = (MathF.Sin(time * 1.5f) + 1f) / 2f;
                DrawRect(crackX - 1, crackY + 12, 1, 8, crackGlow * (0.1f + glowPulse * 0.08f));
                DrawRect(crackX - 2, crackY + 25, 1, 6, crackGlow * (0.08f + glowPulse * 0.06f));
                // Tiny dust drip
                float dustY = (time * 12f) % (crackH + 20f);
                if (dustY < crackH)
                    DrawRect(crackX - 2, crackY + (int)dustY, 1, 2, new Color(70, 60, 55) * 0.4f);
            }
            else
            {
                // Wall broken — opening to alcove
                DrawRect(crackX - 8, crackY - 2, 20, crackH + 4, new Color(12, 10, 14)); // dark opening
                
                // Alcove interior
                int alcoveW = 65;
                DrawRect(ca.Right, crackY - 5, alcoveW, crackH + 10, new Color(14, 12, 16)); // floor
                DrawRect(ca.Right, crackY - 10, alcoveW, 5, new Color(35, 30, 28)); // ceiling
                DrawRect(ca.Right, crackY + crackH + 5, alcoveW, 5, new Color(35, 30, 28)); // floor edge
                DrawRect(ca.Right + alcoveW - 4, crackY - 5, 4, crackH + 10, new Color(38, 33, 30)); // back wall
                
                // Rubble around the opening
                DrawRect(crackX - 10, crackY + crackH, 8, 4, new Color(55, 48, 42));
                DrawRect(crackX - 6, crackY + crackH + 2, 5, 3, new Color(50, 43, 38));
                DrawRect(crackX + 2, crackY - 4, 6, 3, new Color(52, 45, 40));
                DrawRect(crackX - 12, crackY + crackH - 2, 4, 3, new Color(48, 42, 37));
                
                // Faint purple glow from inside (if relic not yet collected)
                if (!_hasWandOfMerlin)
                {
                    float glowPulse = (MathF.Sin(time * 2f) + 1f) / 2f;
                    DrawRect(ca.Right + 10, crackY + 5, 40, crackH - 10, new Color(80, 50, 160) * (0.04f + glowPulse * 0.03f));
                }
            }
        }
        
        // Dark ambient particles (dust motes)
        for (int d = 0; d < 8; d++)
        {
            float dx = ca.X + 30 + (d * 47 + MathF.Sin(time * 0.5f + d * 1.7f) * 20f) % (ca.Width - 60);
            float dy = ca.Y + 20 + (d * 31 + MathF.Cos(time * 0.3f + d * 2.1f) * 15f) % (ca.Height - 40);
            DrawRect((int)dx, (int)dy, 2, 2, new Color(60, 55, 50) * 0.4f);
        }
    }
    
    private void DrawCaveEntrance()
    {
        if (_gameMode != GameMode.Awakening || _currentScreen != 5 || _inCave) return;
        // Skip visual if room has painted tiles (cave entrance tile replaces this)
        if (_roomTileData.ContainsKey(5) || _roomTileOverlay.ContainsKey(5)) return;
        
        var ce = _caveEntrance;
        // Dark opening
        DrawRect(ce.X, ce.Y, ce.Width, ce.Height, new Color(8, 6, 10));
        // Subtle inner shadow at top
        DrawRect(ce.X + 2, ce.Y, ce.Width - 4, 4, new Color(3, 2, 5));
        // Archway hint at top
        DrawRect(ce.X - 2, ce.Y - 2, ce.Width + 4, 3, new Color(65, 58, 55));
    }
    
    private void DrawEtherDrops()
    {
        float time = _totalTime;
        foreach (var d in _etherDrops)
        {
            int x = (int)d.Position.X, y = (int)d.Position.Y;
            float lifeRatio = d.Life / d.MaxLife;
            float alpha = MathHelper.Clamp(lifeRatio * 2f, 0f, 1f); // fade in last 50%
            
            if (d.IsClip)
            {
                // Clip on ground: colored crystal square with bob
                Color clipCol = d.ClipEP >= 100 ? new Color(160, 120, 255) :
                                d.ClipEP >= 50 ? new Color(80, 160, 255) :
                                new Color(80, 200, 230);
                float bob = MathF.Sin(time * 3f + d.Position.X * 0.1f) * 2f;
                int by = y + (int)bob;
                float pulse = 0.6f + 0.4f * MathF.Sin(time * 5f + d.Position.Y * 0.15f);
                DrawRect(x - 5, by - 5, 10, 10, clipCol * (alpha * 0.2f * pulse));
                DrawRect(x - 3, by - 3, 6, 6, clipCol * (alpha * 0.7f * pulse));
                DrawRect(x - 1, by - 1, 2, 2, Color.White * (alpha * 0.5f));
            }
            else if (d.IsArmor)
            {
                // Armor on ground: purple chestplate silhouette with bob + glow
                float bob = MathF.Sin(time * 2.5f + d.Position.X * 0.1f) * 3f;
                int by = y + (int)bob;
                float pulse = 0.5f + 0.5f * MathF.Sin(time * 3f + d.Position.Y * 0.15f);
                Color ac = new Color(120, 100, 160) * pulse;
                Color ad = new Color(80, 65, 120) * pulse;
                Color glow = new Color(100, 80, 140) * (pulse * 0.2f);
                // Outer glow
                DrawRect(x - 14, by - 14, 28, 28, glow);
                DrawRect(x - 12, by - 12, 24, 24, glow);
                // Shoulders
                DrawRect(x - 11, by - 8, 6, 5, ac);
                DrawRect(x + 5, by - 8, 6, 5, ac);
                // Torso
                DrawRect(x - 7, by - 3, 14, 12, ac);
                DrawRect(x - 5, by - 1, 10, 8, ad);
                // Belt
                DrawRect(x - 7, by + 9, 14, 2, ac * 0.8f);
                // Gem
                DrawRect(x - 2, by + 1, 4, 4, new Color(100, 140, 200) * pulse);
                DrawRect(x - 1, by + 2, 2, 2, new Color(140, 180, 240) * pulse);
            }
            else if (!d.IsHard)
            {
                // Liquid ether: small blue orb with glow
                float pulse = 0.6f + 0.4f * MathF.Sin(time * 8f + d.Position.X * 0.1f);
                Color glow = new Color(60, 140, 255) * (alpha * 0.3f * pulse);
                DrawRect(x - 4, y - 4, 8, 8, glow); // soft glow
                Color core = new Color(100, 180, 255) * (alpha * 0.9f);
                DrawRect(x - 2, y - 2, 4, 4, core); // orb body
                DrawRect(x - 1, y - 1, 2, 2, new Color(180, 220, 255) * alpha); // bright center
            }
            else
            {
                // Hard ether: purple-white crystal, faceted look
                float bob = MathF.Sin(time * 3f + d.Position.Y * 0.05f) * 2f;
                int by = y + (int)bob;
                float shimmer = 0.5f + 0.5f * MathF.Sin(time * 6f + d.Position.X * 0.2f);
                Color crystal = new Color(180, 140, 255) * (alpha * 0.8f);
                Color bright = new Color(220, 200, 255) * (alpha * shimmer);
                // Diamond shape: 4 small rects
                DrawRect(x - 1, by - 4, 2, 3, crystal);  // top
                DrawRect(x - 3, by - 1, 3, 2, crystal);  // left
                DrawRect(x + 1, by - 1, 3, 2, crystal);  // right
                DrawRect(x - 1, by + 1, 2, 3, crystal);  // bottom
                DrawRect(x - 1, by - 1, 2, 2, bright);   // center sparkle
                // Ground shadow
                DrawRect(x - 2, y + 5, 4, 1, new Color(40, 30, 60) * (alpha * 0.3f));
            }
        }
    }
    
    private void DrawTripwires()
    {
        float time = _totalTime;
        foreach (var tw in _tripwires)
        {
            float alpha = MathF.Min(tw.Life / tw.MaxLife * 2f, 1f); // fade out in last half
            Vector2 dir = tw.End - tw.Start;
            float len = dir.Length();
            if (len < 1) continue;
            dir /= len;
            
            // Draw wire as series of small rects (no line primitive in SpriteBatch)
            int steps = (int)(len / 3f);
            for (int s = 0; s <= steps; s++)
            {
                float t2 = (float)s / steps;
                Vector2 pos = Vector2.Lerp(tw.Start, tw.End, t2);
                // Rainbow shimmer along length
                float hue = (t2 * 360f + time * 120f) % 360f;
                Color c = HueToColor(hue) * alpha;
                // Slight wave perpendicular to wire
                float perpX = -dir.Y;
                float perpY = dir.X;
                float wave = MathF.Sin(t2 * 12f + time * 8f) * 2f;
                DrawRect((int)(pos.X + perpX * wave), (int)(pos.Y + perpY * wave), 2, 2, c);
            }
        }
    }
    
    private void DrawPickups()
    {
        foreach (var p in _pickups)
        {
            // Only draw wand when in cave
            if ((p.Type == "wand" || p.Type == "wandofmerlin") && !_inCave) continue;
            
            // Stone pedestal (always drawn, even after collection)
            int px = (int)p.Position.X;
            int py = (int)p.Position.Y;
            DrawRect(px - 16, py + 8, 32, 6, new Color(80, 75, 70));   // top slab
            DrawRect(px - 14, py + 14, 28, 8, new Color(60, 56, 52));  // middle
            DrawRect(px - 18, py + 22, 36, 4, new Color(70, 65, 60));  // base
            DrawRect(px - 14, py + 8, 28, 1, new Color(100, 95, 90));  // highlight
            
            if (p.Collected) continue; // item gone, pedestal remains
            
            float bob = MathF.Sin(p.BobTimer * 3f) * 4f;
            float glow = (MathF.Sin(p.BobTimer * 2f) + 1f) / 2f * 0.3f + 0.7f;
            
            Vector2 drawPos = p.Position + new Vector2(0, bob - 12); // float above pedestal
            
            // Glow circle
            DrawRect((int)(drawPos.X - 12), (int)(drawPos.Y - 12), 24, 24, p.GlowColor * 0.12f * glow);
            DrawRect((int)(drawPos.X - 8), (int)(drawPos.Y - 8), 16, 16, p.GlowColor * 0.25f * glow);
            // Item body
            DrawRect((int)(drawPos.X - 5), (int)(drawPos.Y - 8), 10, 16, p.GlowColor * glow);
            DrawRect((int)(drawPos.X - 3), (int)(drawPos.Y - 6), 6, 12, Color.White * glow);
            // Light beam above
            DrawRect((int)(drawPos.X - 1), (int)(drawPos.Y - 60), 2, 52, p.GlowColor * 0.15f);
            DrawRect((int)(drawPos.X), (int)(drawPos.Y - 50), 1, 42, p.GlowColor * 0.25f);
        }
        
        // SOTN flash
        if (_pickupFlashTimer > 0)
        {
            float alpha = _pickupFlashTimer / 0.3f;
            DrawRect(0, 0, ScreenW, ScreenH, Color.White * alpha * 0.6f);
        }
        
        // Expanding ring
        if (_pickupRingRadius > 0 && _pickupRingRadius < 200f)
        {
            float alpha = 1f - _pickupRingRadius / 200f;
            int r = (int)_pickupRingRadius;
            int cx = (int)_pickupEffectPos.X;
            int cy = (int)_pickupEffectPos.Y;
            // Draw ring as 4 arcs (top, bottom, left, right rectangles)
            DrawRect(cx - r, cy - 1, r * 2, 2, new Color(255, 215, 0) * alpha);
            DrawRect(cx - 1, cy - r, 2, r * 2, new Color(255, 215, 0) * alpha);
        }
        
        // Pickup particles
        foreach (var p in _pickupParticles)
        {
            float alpha = p.Life / p.MaxLife;
            int s = (int)(p.Size * alpha);
            if (s < 1) s = 1;
            DrawRect((int)(p.Position.X - s / 2), (int)(p.Position.Y - s / 2), s, s, p.Color * alpha);
        }
        
        // Rising gold text
        if (_pickupText != null && _pickupTextTimer > 0)
        {
            float t = 1f - _pickupTextTimer / 2.5f;
            float rise = t * 40f;
            float alpha = t < 0.1f ? t * 10f : (t > 0.7f ? (1f - t) / 0.3f : 1f);
            float scale = 1.2f + t * 0.3f;
            int tw = MeasureText(_pickupText, scale);
            int tx = (int)_pickupEffectPos.X - tw / 2;
            int ty = (int)_pickupEffectPos.Y - 50 - (int)rise;
            DrawTextOutlined(tx, ty, _pickupText, new Color(255, 215, 0) * alpha, Color.Black * alpha, scale);
        }
        
        // Room cleared celebration
        if (_roomClearedTimer > 0)
        {
            float alpha = MathF.Min(_roomClearedTimer, 1f);
            float scale = 1.5f + (3f - _roomClearedTimer) * 0.3f;
            var tf = _titleFont ?? _font;
            DrawTextCenteredOutlined((int)(ScreenH / 3), _roomClearedText ?? "Room Cleared!", 
                Color.Lerp(new Color(255, 215, 0), Color.White, MathF.Sin(_totalTime * 8f) * 0.3f + 0.3f) * alpha, 
                Color.Black * alpha, scale, tf, 2);
        }
    }
    
    private void DrawTextBox()
    {
        if (_textBoxMessage == null) return;
        
        int boxX = 60;
        int boxW = ScreenW - 120;
        int maxTextW = boxW - 40;
        
        // Word-wrap the message
        var lines = new List<string>();
        string[] words = _textBoxMessage.Split(' ');
        string current = "";
        foreach (var word in words)
        {
            string test = current.Length == 0 ? word : current + " " + word;
            if (MeasureText(test, 1f) > maxTextW && current.Length > 0)
            {
                lines.Add(current);
                current = word;
            }
            else
            {
                current = test;
            }
        }
        if (current.Length > 0) lines.Add(current);
        
        int lineH = 18;
        int textH = lines.Count * lineH;
        int boxH = Math.Max(80, textH + 40);
        int boxY = ScreenH - boxH - 20;
        
        // Dark box with gold border
        DrawRect(boxX, boxY, boxW, boxH, new Color(10, 10, 15, 230));
        DrawRect(boxX, boxY, boxW, 2, new Color(200, 170, 100));
        DrawRect(boxX, boxY + boxH - 2, boxW, 2, new Color(200, 170, 100));
        DrawRect(boxX, boxY, 2, boxH, new Color(200, 170, 100));
        DrawRect(boxX + boxW - 2, boxY, 2, boxH, new Color(200, 170, 100));
        
        // Draw wrapped lines
        for (int i = 0; i < lines.Count; i++)
        {
            DrawTextOutlined(boxX + 20, boxY + 16 + i * lineH, lines[i], Color.White, Color.Black, 1f);
        }
        
        // Advance arrow (bottom right, pulsing)
        float pulse = (MathF.Sin(_totalTime * 4f) + 1f) / 2f;
        DrawTextOutlined(boxX + boxW - 40, boxY + boxH - 24, ">>", new Color(255, 215, 0) * (0.5f + pulse * 0.5f), Color.Black);
    }
    
    private void DrawAwakeningDoors()
    {
        if (_gameMode != GameMode.Awakening) return;
        
        int ax = _arena.Left;
        int ay = _arena.Top;
        int aw = _arena.Width;
        int ah = _arena.Height;
        float time = _totalTime;
        
        foreach (var d in _doors)
        {
            if (d.FromScreen != _currentScreen) continue;
            if (d.State != DoorState.Locked && d.State != DoorState.Opening) continue;
            
            // Scale factor for opening animation
            float openScale = d.State == DoorState.Opening ? d.OpenTimer / 0.5f : 1f;
            
            // Door position based on side — thick visible barriers
            int dx, dy, dw, dh;
            switch (d.Side)
            {
                case "N": dx = ax + aw / 2 - 50; dy = ay - TSDst; dw = 100; dh = 20; break;
                case "S": dx = ax + aw / 2 - 50; dy = ay + ah - 20 + TSDst; dw = 100; dh = 20; break;
                case "W": dx = ax - TSDst; dy = ay + ah / 2 - 50; dw = 20; dh = 100; break;
                case "E": dx = ax + aw - 20 + TSDst; dy = ay + ah / 2 - 50; dw = 20; dh = 100; break;
                default: continue;
            }
            
            // Apply opening animation scale
            if (d.State == DoorState.Opening)
            {
                int cdx = dx + dw / 2, cdy = dy + dh / 2;
                dw = (int)(dw * openScale);
                dh = (int)(dh * openScale);
                dx = cdx - dw / 2;
                dy = cdy - dh / 2;
                if (dw <= 0 || dh <= 0) continue;
            }
            
            switch (d.KeyType)
            {
                case DoorKeyType.Flame:
                    // Frozen gate — ice barrier
                    DrawRect(dx, dy, dw, dh, new Color(120, 180, 220));
                    DrawRect(dx + 2, dy + 2, dw - 4, dh - 4, new Color(160, 210, 240));
                    // Ice crystals
                    if (dw > dh) // horizontal
                    {
                        for (int i = 0; i < 5; i++)
                        {
                            int ix = dx + 8 + i * (dw - 16) / 4;
                            DrawRect(ix, dy - 4, 3, 6, new Color(180, 220, 255) * 0.8f);
                            DrawRect(ix, dy + dh - 2, 3, 4, new Color(180, 220, 255) * 0.6f);
                        }
                    }
                    else // vertical
                    {
                        for (int i = 0; i < 5; i++)
                        {
                            int iy = dy + 8 + i * (dh - 16) / 4;
                            DrawRect(dx - 4, iy, 6, 3, new Color(180, 220, 255) * 0.8f);
                            DrawRect(dx + dw - 2, iy, 4, 3, new Color(180, 220, 255) * 0.6f);
                        }
                    }
                    // Dripping particles
                    float drip = (time * 30f) % 20f;
                    if (dw > dh)
                    {
                        DrawRect(dx + dw / 3, dy + dh + (int)drip, 1, 3, new Color(140, 200, 240) * (1f - drip / 20f));
                        DrawRect(dx + dw * 2 / 3, dy + dh + (int)((drip + 10) % 20), 1, 3, new Color(140, 200, 240) * (1f - ((drip + 10) % 20) / 20f));
                    }
                    // Frost glow
                    DrawRect(dx - 2, dy - 2, dw + 4, dh + 4, new Color(100, 180, 255) * 0.06f);
                    break;
                    
                case DoorKeyType.Grimoire:
                    // Sealed by ancient magic — glowing runes
                    DrawRect(dx, dy, dw, dh, new Color(60, 40, 80));
                    DrawRect(dx + 2, dy + 2, dw - 4, dh - 4, new Color(80, 50, 100));
                    // Pulsing rune glow
                    float runeGlow = (MathF.Sin(time * 2f) + 1f) / 2f;
                    DrawRect(dx, dy, dw, dh, new Color(150, 80, 200) * 0.1f * runeGlow);
                    // Rune symbols
                    if (dw > dh)
                    {
                        for (int r = 0; r < 3; r++)
                        {
                            int rx = dx + 12 + r * (dw - 24) / 2;
                            DrawRect(rx, dy + 2, 4, 4, new Color(200, 120, 255) * (0.3f + runeGlow * 0.3f));
                            DrawRect(rx + 1, dy + 3, 2, 2, Color.White * (0.1f + runeGlow * 0.15f));
                        }
                    }
                    else
                    {
                        for (int r = 0; r < 3; r++)
                        {
                            int ry = dy + 12 + r * (dh - 24) / 2;
                            DrawRect(dx + 2, ry, 4, 4, new Color(200, 120, 255) * (0.3f + runeGlow * 0.3f));
                            DrawRect(dx + 3, ry + 1, 2, 2, Color.White * (0.1f + runeGlow * 0.15f));
                        }
                    }
                    // Seal aura
                    DrawRect(dx - 4, dy - 4, dw + 8, dh + 8, new Color(120, 60, 180) * 0.04f);
                    // Hint text when nearby
                    {
                        int gcx = dx + dw / 2, gcy = dy + dh / 2;
                        if (Vector2.Distance(_playerPos, new Vector2(gcx, gcy)) < 120f)
                        {
                            string grimHint = "Use a triple combo to open";
                            int ghw = MeasureText(grimHint, 0.7f);
                            DrawTextOutlined(gcx - ghw / 2, gcy - (dw > dh ? 25 : 20), grimHint, new Color(200, 120, 255) * 0.8f, Color.Black * 0.5f, 0.7f);
                        }
                    }
                    break;
                    
                case DoorKeyType.ShieldDash:
                    // Cracked stone wall — breakable by shield dash
                    DrawRect(dx, dy, dw, dh, new Color(80, 70, 65));
                    DrawRect(dx + 2, dy + 2, dw - 4, dh - 4, new Color(95, 85, 78));
                    // Prominent cracks
                    float crackPulse = (MathF.Sin(time * 1.5f) + 1f) / 2f;
                    if (dw > dh)
                    {
                        DrawRect(dx + dw / 3 - 1, dy, 2, dh, new Color(40, 32, 28));
                        DrawRect(dx + dw / 3, dy + dh / 3, 1, dh / 3, new Color(180, 140, 60) * (0.2f + crackPulse * 0.15f));
                        DrawRect(dx + dw * 2 / 3, dy + 1, 1, dh - 2, new Color(40, 32, 28));
                        DrawRect(dx + dw / 2, dy + 2, 1, dh - 4, new Color(50, 42, 38));
                    }
                    else
                    {
                        DrawRect(dx, dy + dh / 3 - 1, dw, 2, new Color(40, 32, 28));
                        DrawRect(dx + dw / 3, dy + dh / 3, dw / 3, 1, new Color(180, 140, 60) * (0.2f + crackPulse * 0.15f));
                        DrawRect(dx + 1, dy + dh * 2 / 3, dw - 2, 1, new Color(40, 32, 28));
                        DrawRect(dx + 2, dy + dh / 2, dw - 4, 1, new Color(50, 42, 38));
                    }
                    // Rubble at base
                    if (dw > dh)
                    {
                        DrawRect(dx + dw / 3 - 2, dy + dh, 4, 3, new Color(70, 60, 55));
                        DrawRect(dx + dw * 2 / 3 - 1, dy + dh, 3, 2, new Color(75, 65, 58));
                    }
                    else
                    {
                        DrawRect(dx + dw, dy + dh / 3 - 2, 3, 4, new Color(70, 60, 55));
                        DrawRect(dx + dw, dy + dh * 2 / 3, 2, 3, new Color(75, 65, 58));
                    }
                    // Shield impact symbol — glowing cracks from center
                    int scx = dx + dw / 2, scy = dy + dh / 2;
                    DrawRect(scx - 3, scy - 3, 6, 6, new Color(180, 140, 60) * (0.2f + crackPulse * 0.2f));
                    // Hint when nearby
                    if (Vector2.Distance(_playerPos, new Vector2(scx, scy)) < 120f)
                    {
                        string dashHint = "Shield dash to break";
                        int dhw = MeasureText(dashHint, 0.7f);
                        DrawTextOutlined(scx - dhw / 2, scy - (dw > dh ? 25 : 20), dashHint, new Color(180, 160, 100) * 0.8f, Color.Black * 0.5f, 0.7f);
                    }
                    break;
                    
                case DoorKeyType.Lance:
                    // Castle gate with glowing target — shoot to open
                    DrawRect(dx, dy, dw, dh, new Color(100, 80, 60));
                    DrawRect(dx + 2, dy + 2, dw - 4, dh - 4, new Color(120, 95, 70));
                    // Metal bands
                    if (dw > dh)
                    {
                        DrawRect(dx + dw / 4, dy, 2, dh, new Color(140, 130, 110));
                        DrawRect(dx + dw * 3 / 4, dy, 2, dh, new Color(140, 130, 110));
                    }
                    else
                    {
                        DrawRect(dx, dy + dh / 4, dw, 2, new Color(140, 130, 110));
                        DrawRect(dx, dy + dh * 3 / 4, dw, 2, new Color(140, 130, 110));
                    }
                    // Glowing target bullseye
                    float lancePulse = (MathF.Sin(time * 2.5f) + 1f) / 2f;
                    int tcx = dx + dw / 2, tcy = dy + dh / 2;
                    DrawRect(tcx - 6, tcy - 6, 12, 12, new Color(255, 200, 80) * (0.15f + lancePulse * 0.15f));
                    DrawRect(tcx - 4, tcy - 4, 8, 8, new Color(255, 160, 40) * (0.3f + lancePulse * 0.2f));
                    DrawRect(tcx - 2, tcy - 2, 4, 4, new Color(255, 220, 120) * (0.5f + lancePulse * 0.3f));
                    // "Shoot" text hint when nearby
                    if (Vector2.Distance(_playerPos, new Vector2(tcx, tcy)) < 120f)
                    {
                        string shootHint = "Shoot Lance to open";
                        int shw = MeasureText(shootHint, 0.7f);
                        DrawTextOutlined(tcx - shw / 2, tcy - (dw > dh ? 25 : 20), shootHint, new Color(255, 200, 80) * 0.8f, Color.Black * 0.5f, 0.7f);
                    }
                    break;
                    
                case DoorKeyType.Wave:
                    // Mystical barrier
                    float waveGlow = (MathF.Sin(time * 3f) + 1f) / 2f;
                    DrawRect(dx, dy, dw, dh, new Color(40, 80, 120) * (0.6f + waveGlow * 0.3f));
                    DrawRect(dx + 1, dy + 1, dw - 2, dh - 2, new Color(60, 120, 180) * (0.4f + waveGlow * 0.2f));
                    DrawRect(dx, dy, dw, dh, new Color(100, 180, 255) * 0.08f * waveGlow);
                    break;
            }
        }
    }
    
    private void DrawRoomName()
    {
        if (_gameMode != GameMode.Awakening) return;
        if (_roomNameTimer <= 0) return;
        
        string name = _currentScreen >= 1 && _currentScreen <= 9
            ? AwakeningRoomNames[_currentScreen] : "";
        
        float alpha = _roomNameTimer > 0 ? MathF.Min(_roomNameTimer, 1f) : 0f;
        if (alpha <= 0 || name == "") return;
        
        int tw = MeasureText(name, 1f);
        int nameY = ScreenH - 28;
        DrawTextOutlined(ScreenW - tw - 16, nameY, name, new Color(200, 170, 100) * alpha, Color.Black * alpha, 1f);
    }
    
    private bool HasDoorOnSide(int fromScreen, string side)
    {
        foreach (var d in _doors)
        {
            if (d.FromScreen == fromScreen && d.Side == side)
                return true;
        }
        return false;
    }

    private bool IsAwakeningDoorLocked(int fromScreen, string side)
    {
        // Lock gauntlet exits during active challenge
        if (fromScreen == 1 && _gauntletStarted && !_clearedScreens.Contains(1))
            return true;
        
        foreach (var d in _doors)
        {
            if (d.FromScreen == fromScreen && d.Side == side)
                return d.State == DoorState.Locked || d.State == DoorState.Opening;
        }
        return false;
    }

    private void UnlockDoorPair(int fromScreen, int toScreen)
    {
        // Unlock both directions between these screens
        for (int i = 0; i < _doors.Count; i++)
        {
            var d = _doors[i];
            if ((d.FromScreen == fromScreen && d.ToScreen == toScreen) ||
                (d.FromScreen == toScreen && d.ToScreen == fromScreen))
            {
                if (d.State == DoorState.Locked)
                {
                    d.State = DoorState.Opening; d.OpenTimer = 0.5f;
                    _doors[i] = d;
                }
            }
        }
    }

    private WallType GetRoomWall(int room, string side)
    {
        return room switch
        {
            1 => WallType.Stone,   // Gauntlet — arena walls, bounce projectiles
            2 => WallType.Stone,   // Armory — castle interior
            3 => WallType.Tree,    // Proving Grounds — overgrown ruins
            4 => WallType.Stone,   // Knight's Hall — grand hall
            5 => WallType.Stone,   // Awakening — cave walls
            6 => WallType.Water,   // Wellspring — crystal cave with water
            7 => WallType.Water,   // Shrine — sacred pool
            8 => WallType.Lava,    // Lava Sanctum
            9 => WallType.Void,    // Boss — floating in darkness
            _ => WallType.Stone
        };
    }

    private FloorStyle GetRoomFloor(int room)
    {
        return room switch
        {
            1 => FloorStyle.DarkStone,   // Gauntlet
            2 => FloorStyle.BrownStone,  // Armory
            3 => FloorStyle.Grass,       // Proving Grounds
            4 => FloorStyle.BrownStone,  // Knight's Hall
            5 => FloorStyle.Cave,        // Awakening
            6 => FloorStyle.Cave,        // Wellspring
            7 => FloorStyle.Ice,         // Shrine
            8 => FloorStyle.Lava,        // Lava Sanctum
            9 => FloorStyle.Void,        // Boss
            11 => FloorStyle.DarkStone,  // The Depths
            _ => FloorStyle.DarkStone
        };
    }

    // Get floor tile source rects for a style (returns 2-4 tile variants for visual variety)
    private (Texture2D sheet, Rectangle[] tiles) GetFloorTiles(FloorStyle style)
    {
        // Dungeon sheet floor tiles (identified from visual inspection)
        // Each entry is a source rect in the 16×16 grid
        return style switch
        {
            FloorStyle.DarkStone => (_tsDungeon, new[] {
                new Rectangle(6 * 16, 8 * 16, 16, 16),  // dark stone 1
                new Rectangle(7 * 16, 8 * 16, 16, 16),  // dark stone 2
                new Rectangle(6 * 16, 9 * 16, 16, 16),  // dark stone 3
                new Rectangle(7 * 16, 9 * 16, 16, 16),  // dark stone 4
            }),
            FloorStyle.BrownStone => (_tsDungeon, new[] {
                new Rectangle(6 * 16, 0 * 16, 16, 16),  // brown stone 1
                new Rectangle(7 * 16, 0 * 16, 16, 16),  // brown stone 2
                new Rectangle(6 * 16, 1 * 16, 16, 16),  // brown stone 3
                new Rectangle(7 * 16, 1 * 16, 16, 16),  // brown stone 4
            }),
            FloorStyle.Cave => (_tsDungeon, new[] {
                new Rectangle(6 * 16, 4 * 16, 16, 16),  // cave 1
                new Rectangle(7 * 16, 4 * 16, 16, 16),  // cave 2
                new Rectangle(6 * 16, 5 * 16, 16, 16),  // cave 3
                new Rectangle(7 * 16, 5 * 16, 16, 16),  // cave 4
            }),
            FloorStyle.Ice => (_tsDungeon, new[] {
                new Rectangle(6 * 16, 6 * 16, 16, 16),  // ice 1
                new Rectangle(7 * 16, 6 * 16, 16, 16),  // ice 2
                new Rectangle(6 * 16, 7 * 16, 16, 16),  // ice 3
                new Rectangle(7 * 16, 7 * 16, 16, 16),  // ice 4
            }),
            FloorStyle.Lava => (_tsDungeon, new[] {
                new Rectangle(0 * 16, 8 * 16, 16, 16),  // lava stone 1
                new Rectangle(1 * 16, 8 * 16, 16, 16),  // lava stone 2
                new Rectangle(0 * 16, 9 * 16, 16, 16),  // lava stone 3
                new Rectangle(1 * 16, 9 * 16, 16, 16),  // lava stone 4
            }),
            FloorStyle.Grass => (_tsWorld, new[] {
                new Rectangle(6 * 16, 0 * 16, 16, 16),  // grass 1
                new Rectangle(7 * 16, 0 * 16, 16, 16),  // grass 2
                new Rectangle(6 * 16, 1 * 16, 16, 16),  // grass 3
                new Rectangle(7 * 16, 1 * 16, 16, 16),  // grass 4
            }),
            _ => (null, null) // Void — no floor tiles, keep black
        };
    }

    private void DrawTiledFloor(Rectangle area)
    {
        // Check for painted room data first
        bool hasPainted = _roomTileData.ContainsKey(_currentScreen) || _roomTileMid.ContainsKey(_currentScreen) || _roomTileOverlay.ContainsKey(_currentScreen);
        if (hasPainted)
        {
            var (roomCols, roomRows) = GetRoomTileSize(_currentScreen);
            var bg = _roomTileData.TryGetValue(_currentScreen, out var bgData) ? bgData : null;
            var fg = _roomTileOverlay.TryGetValue(_currentScreen, out var fgData) ? fgData : null;
            
            for (int r = 0; r < roomRows; r++)
            {
                for (int c = 0; c < roomCols; c++)
                {
                    int dx = c * TSDst;
                    int dy = r * TSDst;
                    if (r >= TSRoomRows || c >= TSRoomCols) continue;
                    
                    // Background layer
                    bool drewBg = false;
                    if (bg != null)
                    {
                        var (s, t) = bg[r, c];
                        if (s >= 0 && t >= 0 && _tsSheets[s] != null)
                        {
                            int sheetCols = _tsSheets[s].Width / TS16;
                            var src = new Rectangle((t % sheetCols) * TS16, (t / sheetCols) * TS16, TS16, TS16);
                            _spriteBatch.Draw(_tsSheets[s], new Rectangle(dx, dy, TSDst, TSDst), src, Color.White);
                            drewBg = true;
                        }
                    }
                    if (!drewBg) DrawRect(dx, dy, TSDst, TSDst, new Color(15, 15, 20));
                }
            }
            return;
        }
        
        // Fallback: auto-tiled floor from style
        var style = GetRoomFloor(_currentScreen);
        var (sheet, tiles) = GetFloorTiles(style);
        
        if (sheet == null || tiles == null)
        {
            // Void / fallback — dark rect
            DrawRect(area.X, area.Y, area.Width, area.Height, new Color(15, 15, 20));
            return;
        }
        
        int dst = TS16 * 3; // 48px display size (3× scale)
        int cols = (area.Width + dst - 1) / dst;
        int rows = (area.Height + dst - 1) / dst;
        
        for (int r = 0; r < rows; r++)
        {
            for (int c = 0; c < cols; c++)
            {
                int dx = area.X + c * dst;
                int dy = area.Y + r * dst;
                
                // Pick tile variant using deterministic hash (stable across frames)
                int hash = ((_currentScreen * 7919) + (r * 31) + c) & 0x7FFFFFFF;
                int tileIdx = hash % tiles.Length;
                
                // Clamp to arena bounds
                int drawW = Math.Min(dst, area.Right - dx);
                int drawH = Math.Min(dst, area.Bottom - dy);
                if (drawW <= 0 || drawH <= 0) continue;
                
                // Source rect (may need partial for edge tiles)
                var src = tiles[tileIdx];
                if (drawW < dst || drawH < dst)
                {
                    float srcFracW = (float)drawW / dst;
                    float srcFracH = (float)drawH / dst;
                    src = new Rectangle(src.X, src.Y, (int)(16 * srcFracW), (int)(16 * srcFracH));
                }
                
                _spriteBatch.Draw(sheet, new Rectangle(dx, dy, drawW, drawH), src, Color.White);
            }
        }
    }

    private void DrawTiledFloorMid()
    {
        if (!_roomTileMid.TryGetValue(_currentScreen, out var mid)) return;
        var (roomCols, roomRows) = GetRoomTileSize(_currentScreen);
        for (int r = 0; r < Math.Min(roomRows, mid.GetLength(0)); r++)
        {
            for (int c = 0; c < Math.Min(roomCols, mid.GetLength(1)); c++)
            {
                var (s, t) = mid[r, c];
                if (s < 0 || t < 0 || _tsSheets[s] == null) continue;
                int dx = c * TSDst;
                int dy = r * TSDst;
                int sheetCols = _tsSheets[s].Width / TS16;
                var src = new Rectangle((t % sheetCols) * TS16, (t / sheetCols) * TS16, TS16, TS16);
                _spriteBatch.Draw(_tsSheets[s], new Rectangle(dx, dy, TSDst, TSDst), src, Color.White);
            }
        }
    }
    
    private void DrawTiledFloorFG()
    {
        if (!_roomTileOverlay.TryGetValue(_currentScreen, out var fg)) return;
        var (roomCols, roomRows) = GetRoomTileSize(_currentScreen);
        for (int r = 0; r < Math.Min(roomRows, fg.GetLength(0)); r++)
        {
            for (int c = 0; c < Math.Min(roomCols, fg.GetLength(1)); c++)
            {
                var (s, t) = fg[r, c];
                if (s < 0 || t < 0 || _tsSheets[s] == null) continue;
                int dx = c * TSDst;
                int dy = r * TSDst;
                int sheetCols = _tsSheets[s].Width / TS16;
                var src = new Rectangle((t % sheetCols) * TS16, (t / sheetCols) * TS16, TS16, TS16);
                _spriteBatch.Draw(_tsSheets[s], new Rectangle(dx, dy, TSDst, TSDst), src, Color.White);
            }
        }
    }
    
    private void DrawRoomBorders()
    {
        if (_gameMode != GameMode.Awakening) return;
        if (_inPortal) return;
        
        int ax = _arena.Left, ay = _arena.Top, aw = _arena.Width, ah = _arena.Height;
        WallType wt = GetRoomWall(_currentScreen, "");
        float time = (float)_totalTime;
        
        int thick = 20;
        int doorW = 100;
        int doorH = 100;
        int doorCX = ax + aw / 2;
        int doorCY = ay + ah / 2;
        
        bool hasN = false, hasS = false, hasW = false, hasE = false;
        foreach (var d in _doors)
        {
            if (d.FromScreen != _currentScreen) continue;
            switch (d.Side)
            {
                case "N": hasN = true; break;
                case "S": hasS = true; break;
                case "W": hasW = true; break;
                case "E": hasE = true; break;
            }
        }
        
        if (hasN)
        {
            DrawWallSegment(wt, ax, ay - thick, doorCX - doorW/2 - ax, thick, true, time);
            DrawWallSegment(wt, doorCX + doorW/2, ay - thick, ax + aw - (doorCX + doorW/2), thick, true, time);
            DrawDoorArchway(doorCX - doorW/2, ay - thick, doorW, thick, "N");
        }
        else
        {
            DrawWallSegment(wt, ax, ay - thick, aw, thick, true, time);
        }
        
        if (hasS)
        {
            DrawWallSegment(wt, ax, ay + ah, doorCX - doorW/2 - ax, thick, true, time);
            DrawWallSegment(wt, doorCX + doorW/2, ay + ah, ax + aw - (doorCX + doorW/2), thick, true, time);
            DrawDoorArchway(doorCX - doorW/2, ay + ah, doorW, thick, "S");
        }
        else
        {
            DrawWallSegment(wt, ax, ay + ah, aw, thick, true, time);
        }
        
        if (hasW)
        {
            DrawWallSegment(wt, ax - thick, ay, thick, doorCY - doorH/2 - ay, false, time);
            DrawWallSegment(wt, ax - thick, doorCY + doorH/2, thick, ay + ah - (doorCY + doorH/2), false, time);
            DrawDoorArchway(ax - thick, doorCY - doorH/2, thick, doorH, "W");
        }
        else
        {
            DrawWallSegment(wt, ax - thick, ay, thick, ah, false, time);
        }
        
        if (hasE)
        {
            DrawWallSegment(wt, ax + aw, ay, thick, doorCY - doorH/2 - ay, false, time);
            DrawWallSegment(wt, ax + aw, doorCY + doorH/2, thick, ay + ah - (doorCY + doorH/2), false, time);
            DrawDoorArchway(ax + aw, doorCY - doorH/2, thick, doorH, "E");
        }
        else
        {
            DrawWallSegment(wt, ax + aw, ay, thick, ah, false, time);
        }
        
        DrawWallSegment(wt, ax - thick, ay - thick, thick, thick, true, time);
        DrawWallSegment(wt, ax + aw, ay - thick, thick, thick, true, time);
        DrawWallSegment(wt, ax - thick, ay + ah, thick, thick, true, time);
        DrawWallSegment(wt, ax + aw, ay + ah, thick, thick, true, time);
        
        Color bgColor = wt switch
        {
            WallType.Void => Color.Black,
            WallType.Lava => new Color(20, 8, 5),
            WallType.Water => new Color(10, 15, 25),
            _ => new Color(15, 12, 10)
        };
        DrawRect(0, 0, ScreenW, ay - thick, bgColor);
        DrawRect(0, ay + ah + thick, ScreenW, ScreenH - (ay + ah + thick), bgColor);
        DrawRect(0, ay - thick, ax - thick, ah + thick * 2, bgColor);
        DrawRect(ax + aw + thick, ay - thick, ScreenW - (ax + aw + thick), ah + thick * 2, bgColor);
    }
    
    private void DrawDoorArchway(int x, int y, int w, int h, string side)
    {
        Color frame = new Color(70, 60, 55);
        Color highlight = new Color(90, 80, 70);
        
        if (side == "N" || side == "S")
        {
            DrawRect(x, y, 4, h, frame);
            DrawRect(x + 1, y, 2, h, highlight);
            DrawRect(x + w - 4, y, 4, h, frame);
            DrawRect(x + w - 3, y, 2, h, highlight);
            DrawRect(x, y, w, 3, frame);
        }
        else
        {
            DrawRect(x, y, w, 4, frame);
            DrawRect(x, y + 1, w, 2, highlight);
            DrawRect(x, y + h - 4, w, 4, frame);
            DrawRect(x, y + h - 3, w, 2, highlight);
            DrawRect(x, y, 3, h, frame);
        }
    }
    
    private void DrawWallSegment(WallType type, int x, int y, int w, int h, bool horizontal, float time)
    {
        if (w <= 0 || h <= 0) return;
        
        switch (type)
        {
            case WallType.Tree: DrawTreeWall(x, y, w, h, horizontal, time); break;
            case WallType.Stone: DrawStoneWall(x, y, w, h, time); break;
            case WallType.Water: DrawWaterWall(x, y, w, h, time); break;
            case WallType.Lava: DrawLavaWall(x, y, w, h, time); break;
            case WallType.Cliff: DrawCliffWall(x, y, w, h); break;
            case WallType.Void: DrawRect(x, y, w, h, Color.Black); break;
        }
    }
    
    private void DrawTreeWall(int x, int y, int w, int h, bool horizontal, float time)
    {
        DrawRect(x, y, w, h, new Color(25, 45, 20));
        int treeSpacing = 24;
        int count = (horizontal ? w : h) / treeSpacing + 1;
        for (int i = 0; i < count; i++)
        {
            int tx, ty;
            if (horizontal) { tx = x + i * treeSpacing + 4; ty = y; }
            else { tx = x; ty = y + i * treeSpacing + 4; }
            if (tx > x + w || ty > y + h) break;
            DrawRect(tx + 6, ty + h - 6, 4, 6, new Color(90, 60, 35));
            DrawRect(tx + 7, ty + h - 5, 2, 4, new Color(110, 75, 45));
            int canH = Math.Min(h - 4, 16);
            DrawRect(tx + 2, ty + 2, 12, canH, new Color(35, 70, 30));
            DrawRect(tx + 3, ty + 1, 10, canH - 1, new Color(50, 95, 40));
            DrawRect(tx + 4, ty + 2, 6, canH / 2, new Color(70, 120, 50));
            DrawRect(tx + 5, ty + 3, 3, 3, new Color(90, 140, 65));
            float sway = MathF.Sin(time * 0.8f + i * 1.1f) * 1f;
            DrawRect(tx + 4 + (int)sway, ty, 8, 2, new Color(45, 85, 35));
            
            // Check if any burning tree is near this tree
            foreach (var bt in _burningTrees)
            {
                if (MathF.Abs(bt.Pos.X - (tx + 6)) < 16f && MathF.Abs(bt.Pos.Y - (ty + canH / 2)) < 20f)
                {
                    float fireAlpha = MathF.Min(bt.Timer / 5f, 1f) * 0.6f;
                    DrawRect(tx + 2, ty, 12, canH, new Color(255, 100, 20) * fireAlpha);
                    DrawRect(tx + 4, ty + 1, 8, canH / 2, new Color(255, 200, 40) * fireAlpha * 0.7f);
                    break;
                }
            }
        }
    }
    
    private void DrawStoneWall(int x, int y, int w, int h, float time)
    {
        DrawRect(x, y, w, h, new Color(45, 40, 38));
        int brickW = 16, brickH = 8;
        for (int row = 0; row * brickH < h; row++)
        {
            int offset = (row % 2 == 0) ? 0 : brickW / 2;
            for (int col = -1; col * brickW < w + brickW; col++)
            {
                int bx = x + col * brickW + offset;
                int by = y + row * brickH;
                if (bx + brickW < x || bx > x + w) continue;
                if (by + brickH < y || by > y + h) continue;
                int drawX = Math.Max(bx, x);
                int drawY = Math.Max(by, y);
                int drawW = Math.Min(bx + brickW, x + w) - drawX;
                int drawH = Math.Min(by + brickH, y + h) - drawY;
                if (drawW <= 0 || drawH <= 0) continue;
                int seed = (row * 37 + col * 13) & 0xFF;
                int r = 55 + (seed % 15);
                int g = 48 + (seed % 10);
                int b = 44 + (seed % 8);
                DrawRect(drawX, drawY, drawW, drawH, new Color(r, g, b));
                if (bx >= x && bx <= x + w)
                    DrawRect(bx, Math.Max(by, y), 1, Math.Min(brickH, y + h - Math.Max(by, y)), new Color(30, 26, 24));
                if (by >= y && by <= y + h)
                    DrawRect(Math.Max(bx, x), by, Math.Min(brickW, x + w - Math.Max(bx, x)), 1, new Color(30, 26, 24));
            }
        }
        DrawRect(x, y, w, 2, new Color(25, 22, 20));
        DrawRect(x, y + h - 2, w, 2, new Color(25, 22, 20));
        DrawRect(x, y, 2, h, new Color(25, 22, 20));
        DrawRect(x + w - 2, y, 2, h, new Color(25, 22, 20));
    }
    
    private void DrawWaterWall(int x, int y, int w, int h, float time)
    {
        DrawRect(x, y, w, h, new Color(15, 30, 55));
        for (int wy = 0; wy < h; wy += 4)
        {
            float wave = MathF.Sin(time * 2f + wy * 0.3f) * 2f;
            int rx = x + (int)wave + w / 2 - 3;
            int ry = y + wy;
            if (ry >= y && ry < y + h)
                DrawRect(Math.Max(rx, x), ry, Math.Min(6, x + w - Math.Max(rx, x)), 1, new Color(40, 80, 130) * 0.5f);
        }
        DrawRect(x, y, w, 1, new Color(80, 140, 180) * 0.3f);
        DrawRect(x, y + h - 1, w, 1, new Color(80, 140, 180) * 0.3f);
        DrawRect(x, y, 1, h, new Color(80, 140, 180) * 0.3f);
        DrawRect(x + w - 1, y, 1, h, new Color(80, 140, 180) * 0.3f);
        float sparkle = (MathF.Sin(time * 4f + x * 0.1f) + 1f) / 2f;
        if (w > 4 && h > 4)
            DrawRect(x + (int)(sparkle * (w - 2)), y + h / 2, 2, 2, new Color(120, 180, 220) * sparkle * 0.6f);
    }
    
    private void DrawLavaWall(int x, int y, int w, int h, float time)
    {
        DrawRect(x, y, w, h, new Color(30, 15, 10));
        for (int ly = 0; ly < h; ly += 6)
        {
            float flow = MathF.Sin(time * 1.5f + ly * 0.5f);
            int vx = x + w / 2 + (int)(flow * w * 0.3f);
            int vy = y + ly;
            if (vx >= x && vx < x + w && vy >= y && vy < y + h)
            {
                DrawRect(vx, vy, 2, 3, new Color(200, 80, 20) * 0.6f);
                DrawRect(vx, vy, 1, 2, new Color(255, 160, 40) * 0.4f);
            }
        }
        float glow = (MathF.Sin(time * 2f) + 1f) / 2f;
        DrawRect(x, y, w, h, new Color(200, 60, 10) * 0.04f * glow);
    }
    
    private void DrawCliffWall(int x, int y, int w, int h)
    {
        DrawRect(x, y, w, h, new Color(20, 18, 15));
        DrawRect(x, y, w, 2, new Color(50, 45, 40));
    }

    private void UpdateGameOver(KeyboardState kb, float dt)
    {
        _gameOverTimer += dt;
        
        // Don't accept input for first 1 second
        if (_gameOverTimer < 1f) return;
        
        if ((kb.IsKeyDown(Keys.Up) && !_prevKb.IsKeyDown(Keys.Up)) ||
            (kb.IsKeyDown(Keys.W) && !_prevKb.IsKeyDown(Keys.W)))
            _gameOverSelection = (_gameOverSelection - 1 + 3) % 3;
        if ((kb.IsKeyDown(Keys.Down) && !_prevKb.IsKeyDown(Keys.Down)) ||
            (kb.IsKeyDown(Keys.S) && !_prevKb.IsKeyDown(Keys.S)))
            _gameOverSelection = (_gameOverSelection + 1) % 3;
            
        if (kb.IsKeyDown(Keys.Enter) && !_prevKb.IsKeyDown(Keys.Enter))
        {
            switch (_gameOverSelection)
            {
                case 0: // Retry
                    if (_gameMode == GameMode.Gauntlet)
                    {
                        ResetGame();
                        _hasWand = true; _hasShield = true;
                        _hasCaliburn = true; _hasNimueTear = true; _hasWandOfMerlin = true; _hasTomeOfBinding = true; _ownsTomeOfBinding = true;
                        _hasHasteBand = true; _hasPhylactery = true; _hasGrimoire = true;
                        _ownsCaliburn = true; _ownsNimueTear = true; _ownsWandOfMerlin = true;
                        _ownsHasteBand = true; _ownsPhylactery = true; _ownsGrimoire = true;
                        foreach (Form f in Enum.GetValues<Form>()) _unlockedForms.Add(f);
                        foreach (Behavior b in Enum.GetValues<Behavior>()) _unlockedBehaviors.Add(b);
                        foreach (Essence e in Enum.GetValues<Essence>()) _unlockedEssences.Add(e);
                    }
                    else
                    {
                        // Soft restart — keep progress, return to Room 5
                        _playerHp = PlayerMaxHp;
                        _playerPos = new Vector2(_arena.Center.X, _arena.Center.Y);
                        _currentScreen = 5;
                        _enemies.Clear();
                        _enemyById.Clear();
                        _projectiles.Clear();
                        _pickups.Clear();
                        _particles.Clear();
                        _bossLavaPools.Clear();
                        _bossActive = false;
                        _bossDead = false; _victoryPlayed = false;
                        _bossDeathTimer = 0;
                        _inPortal = false;
                        _portalTransitioning = false;
                        _challengeActive = false;
                        _textBoxMessage = null;
                        _demoCompleteTimer = 0;
                        InitAwakeningRoom5Content();
                    }
                    _state = GameState.Playing;
                    break;
                case 1: // Mode select
                    _state = GameState.ModeSelect;
                    _menuSelection = 0;
                    break;
                case 2: // Title
                    _state = GameState.TitleScreen;
                    break;
            }
        }
    }
    
    private void ResetGame()
    {
        _playerHp = PlayerMaxHp;
        _enemies.Clear(); _enemyById.Clear();
        _projectiles.Clear();
        _enemyProjectiles.Clear();
        _lingerZones.Clear();
        _hedgeWalls.Clear();
        _revealedMazeCells.Clear();
        _screenHedges.Clear();
        _screenRevealedCells.Clear();
        _particles.Clear();
        _shards.Clear();
