        _gorgonSnakes.Clear();
        _boneHusks.Clear();
        _floatingTexts.Clear();
        _discoveredCombos.Clear();
        _shadowStitch.Active = false;
        _shadowStitch.ChainedIds = null;
        _wave = 1;
        _killCount = 0;
        _spawnInterval = 2f;
        _spawnTimer = 2f;
        _hasWand = false;
        _hasShield = false;
        _hasCaliburn = false;
        _hasNimueTear = false;
