        _chargeTimer = 0f;
        _iFrameTimer = 0;
        _damageFlashTimer = 0;
        _hitstopTimer = 0;
        _trauma = 0;
        _fireTimer = 0;
        _streakCount = 0;
        _bestStreak = 0;
        _hardEther = 0;
        _bossAlive = false;
        _bossId = -1;
        _currentFusion = null;
        // Reset ether AFTER relic flags so EffectiveMaxEther is correct
        _playerEther = EffectiveMaxEther;
        _etherDisplay = EffectiveMaxEther;
        _etherFlashTimer = 0f;
        _currentDualCombo = null;
        _loadout = new Loadout(Form.Bolt, Behavior.None, Essence.None);
        _sackItems.Clear();
        _sackOverflow.Clear(); _sackOverflowPos.Clear();
        _equippedArmor = ArmorType.None;
        _roomDroppedItems.Clear();
        _roomDropPos.Clear();
        _thiefStolenLoot.Clear();
        _roomsWithThief.Clear();
        // Starter gear: leather gambeson in sack (2×2, top-left corner)
        _sackItems.Add(new SackItem { Type = SackItemType.Armor, Armor = ArmorType.LeatherGambeson, Count = 1, MaxStack = 1, GridX = 0, GridY = 0, Width = 2, Height = 2 });
        SackAddClip(25); // starter clip for testing
