    // Light-emitting tile IDs — (sheet, tileId) pairs
    // Sheet 0 (dungeon): torches, lava, flames
    // Sheet 1 (exterior): torch, campfire
    // Sheet 2 (interior): campfire, torch, lava, candles, lantern
    // Sheet 4 (world): torch
    private static readonly HashSet<(int sheet, int tile)> TorchTilePairs = new()
    {
        // Dungeon (0): lava
        (0,243),(0,245),(0,273),(0,274),(0,275),(0,303),(0,304),(0,305),(0,333),(0,334),(0,335),
        // Dungeon (0): torches
        (0,263),(0,264),
        // Dungeon (0): flames
        (0,207),(0,208),(0,209),
        // Exterior (1): torch + campfire
        (1,318),(1,381),
        // Interior (2): campfire stack
        (2,124),(2,154),(2,184),(2,214),
        // Interior (2): torch
        (2,24),
        // Interior (2): lava
        (2,232),
        // Interior (2): candle + lantern
        (2,204),(2,206),
        // Interior (2): candles
        (2,381),(2,383),(2,441),(2,443),
        // World (4): torch
        (4,144),
    };
    
    private void AddTorchesFromTiles(int room)
    {
        // Scan both BG and FG layers for torch tiles
        void ScanLayer((int sheet, int tile)[,]? layer)
        {
            if (layer == null) return;
            int rows = layer.GetLength(0), cols = layer.GetLength(1);
            for (int r = 0; r < rows; r++)
            {
                for (int c = 0; c < cols; c++)
                {
                    var (s, t) = layer[r, c];
                    if (s >= 0 && TorchTilePairs.Contains((s, t)))
                    {
                        // Place torch at center of tile cell
                        float tx = c * TSDst + TSDst / 2f;
                        float ty = r * TSDst + TSDst / 2f;
                        // Avoid duplicates (same position from BG+FG)
                        bool dup = false;
                        foreach (var existing in _torches)
                            if (MathF.Abs(existing.X - tx) < 4 && MathF.Abs(existing.Y - ty) < 4) { dup = true; break; }
                        if (!dup) _torches.Add(new Vector2(tx, ty));
                    }
                }
            }
        }
        
        // Only add from tiles if the room has painted tile data
        bool hasTiles = _roomTileData.ContainsKey(room) || _roomTileMid.ContainsKey(room) || _roomTileOverlay.ContainsKey(room);
        if (!hasTiles) return;
        
        // Clear hardcoded torches — tile data takes over
        _torches.Clear();
        
        _roomTileData.TryGetValue(room, out var bg);
        _roomTileMid.TryGetValue(room, out var mid);
        _roomTileOverlay.TryGetValue(room, out var fg);
        ScanLayer(bg);
        ScanLayer(mid);
        ScanLayer(fg);
        System.Console.WriteLine($"AddTorchesFromTiles room={room}: hasBG={bg!=null} hasMID={mid!=null} hasFG={fg!=null} torchCount={_torches.Count}");
    }
    
