            new(ax + 80, ay + _arena.Height - 104, 24, 24),
            new(ax + _arena.Width - 104, ay + _arena.Height - 104, 24, 24),
        };
        
        // Override with editor-placed collision rects (room_tiles.json)
        foreach (var kvp in _roomCollision)
        {
            int room = kvp.Key;
            if (room == 50) continue;
            if (!_screenWalls.ContainsKey(room))
                _screenWalls[room] = new List<Rectangle>();
            else
                _screenWalls[room].Clear();
            _screenWallOneWay[room] = new List<int>();
            foreach (var cr in kvp.Value)
            {
                _screenWalls[room].Add(cr.Rect);
                _screenWallOneWay[room].Add(cr.OneWay);
            }
        }
    }

    private void FireWeapon(Vector2 mousePos, float chargePercent = 0f)
    {
        var parms = ProjectileParams.Resolve(_loadout);

        // Dragon Dance boost
        if (_dragonDanceStacks > 0)
        {
            parms.BaseDamage *= 1f + _dragonDanceStacks;
            parms.Speed *= 1f + _dragonDanceStacks * 0.5f;
        }

        // Charge shot: scale damage, size, and speed
        if (chargePercent > 0f)
        {
            float mult = 1f + (ChargeDamageMultiplier - 1f) * chargePercent;
            parms.BaseDamage *= mult;
            parms.Size *= 1f + chargePercent * 0.8f; // up to 1.8x size
            parms.Speed *= 1f + chargePercent * 0.3f; // slightly faster
        }

        // Caliburn relic: pierce one enemy
        if (_hasCaliburn)
            parms.PierceOne = true;

        // Pillars of Muspelheim: slow meteor-like bolts, bigger, more impactful
        if (_currentFusion == "Pillars of Muspelheim")
        {
            parms.Speed = 300f;    // slow, weighty fireballs (was 700)
            parms.Size = 8f;       // big (was 4)
            parms.FireRate = 0.45f; // slightly slower to let pillars breathe
            parms.Lifetime = 1.5f; // travel further despite lower speed
            parms.Piercing = true; // plows through enemies, leaving fire everywhere
        }

        // Fire-flaught Hasp: thunderstorm bolt
        if (_currentFusion == "Fire-flaught Hasp")
        {
            parms.Speed = 500f;
            parms.Size = 5f;
            parms.Piercing = false;
        }

        // Graveyard: bone altar bolt
        if (_currentFusion == "Graveyard")
        {
            parms.Speed = 550f;
            parms.Size = 5f;
        }

        // Ifrit's Fury: slow massive fireball
        if (_currentFusion == "Ifrit's Fury")
        {
            parms.Speed = 250f;
            parms.Size = 10f;
            parms.Lifetime = 1.5f;
        }

        // Raijin's Drum: fast bolt
        if (_currentFusion == "Raijin's Drum")
        {
            parms.Speed = 800f;
            parms.Size = 4f;
        }

        // Raiju: erratic thunder beast
        if (_currentFusion == "Raiju")
        {
            parms.BloomGrowRate = 2f;
            parms.BloomMaxScale = 2.5f;
            parms.Size = 5f;
        }

        // Fossil: rolling bone snowball
        if (_currentFusion == "Fossil")
        {
            parms.Size = 5f;
            parms.Lifetime = 3f;
            parms.Piercing = true;
        }

        Vector2 dir = mousePos - _playerPos;
        if (dir.LengthSquared() > 0) dir.Normalize();
        else dir = new Vector2(1, 0);

        // ═══════════════ DUAL COMBO EFFECTS ═══════════════
        // These modify parms/behavior before form-specific firing
        string dc = _currentDualCombo;
        if (dc != null && _currentFusion == null)
        {
            switch (dc)
            {
                // --- Form + Behavior ---
                case "Splinter Shot": parms.ShatterCount += 3; break; // extra shatter fragments
                case "Signal Flare":
                    parms.Lifetime *= 2.5f;
                    parms.Speed *= 0.6f;
                    parms.LingerDuration = 0;
                    parms.Size *= 1.3f;
                    break;
                case "Ricochet": parms.MaxBounces += 2; parms.Speed *= 1.15f; break;
                case "Comet":
                    parms.BaseDamage *= 2.0f;
                    parms.Size = 12f;
                    parms.Speed = 400f;
                    parms.Lifetime = 0.8f;
                    parms.BloomGrowRate = 0;
                    break;
                case "Freeze Ray": parms.StasisDuration *= 1.3f; parms.Speed *= 1.2f; break;
                case "Hex Bolt": parms.BaseDamage *= 1.2f; break;
                case "Firebomb": parms.LingerRadius *= 1.4f; parms.LingerDuration *= 1.3f; break;
                case "Buckshot": parms.MaxBounces += 1; parms.BurstCount += 2; break;
                case "Cluster Bomb": parms.ShatterCount += 4; parms.BurstCount += 1; break;
                case "Undertow": parms.LingerDuration *= 1.5f; parms.LingerRadius *= 1.3f; break;
                case "Echo": parms.MaxBounces += 3; parms.Lifetime *= 1.4f; break; // bouncing sine waves
                case "Tsunami": parms.Size *= 1.6f; parms.BloomGrowRate *= 1.4f; break;
                case "Supernova": parms.BloomGrowRate *= 1.5f; parms.Size *= 1.3f; break;
                case "Stasis Field": parms.StasisRadius *= 1.5f; parms.StasisDuration *= 1.3f; break;
                case "Ball Lightning": parms.MaxBounces += 2; parms.BloomGrowRate = 3f; parms.BloomMaxScale = 3f; parms.Size = 5f; break;
                case "Fork Lightning": parms.ShatterCount += 3; break;
                case "Landmine": parms.BloomGrowRate *= 1.5f; parms.LingerRadius *= 1.3f; break;
                case "Claymore": parms.ShatterCount += 5; parms.BaseDamage *= 1.15f; break;
                case "Pop Green": parms.MaxBounces += 2; parms.Size *= 1.3f; break; // bouncy combat plant
                case "Frost Bulb": parms.StasisRadius = MathF.Max(parms.StasisRadius, 35f); parms.StasisDuration = MathF.Max(parms.StasisDuration, 1.2f); break;
                case "Cordyceps": parms.BaseDamage *= 1.1f; break; // parasitic possession boost
                case "Creeping Moss": parms.LingerDuration = 12f; parms.LingerRadius = 20f; parms.BaseDamage *= 0.4f; break;
                case "Buzzsaw": parms.MaxBounces += 2; parms.BaseDamage *= 1.1f; break;
                case "Fragmentation": parms.ShatterCount += 6; parms.BurstCount += 4; break;
                case "Flash Freeze": parms.StasisRadius *= 2f; parms.StasisDuration *= 1.5f; break;
                case "Nyoibo":
                    parms.BaseDamage *= 1.5f;
                    parms.Lifetime = 2.5f;
                    break;
                case "Scorched Earth":
                    parms.LingerDuration = 0;
                    parms.BaseDamage *= 1.3f;
                    break;
                case "Trick Shot": parms.MaxBounces += 2; parms.BurstCount += 1; break;
                case "Barrage": parms.ShatterCount += 3; parms.BurstCount += 2; break;

                // --- Form + Essence ---
                case "Fire Bolt": 
                    parms.BaseDamage *= 1.15f; 
                    parms.Speed *= 0.7f; // slower, more visible fireball
                    parms.Size = 5f;
                    break;
                case "Shock Bolt":
                    parms.Speed *= 1.5f; // faster than fire bolt
                    parms.Size = 4f;
                    break;
                case "Shadow Bolt": parms.BloomGrowRate = 1.5f; parms.BloomMaxScale = 2.5f; parms.BaseDamage *= 1.2f; break; // Shadow Ball: growing dark orb
                case "Thorn Bolt": parms.Piercing = true; break; // thorns pierce through
                case "Dragon Spit": parms.BurstCount += 2; break; // more fire pellets
                case "Bat Burst": parms.BurstCount += 3; parms.Lifetime *= 0.8f; break; // lots of short bats
                case "Phantom Wave": parms.Piercing = true; parms.Size *= 1.3f; break; // passes through
                case "Muddy Water": parms.Size *= 1.5f; parms.Speed *= 0.8f; break; // wide slow wave, knockback applied in hit code
                case "Thunder Wave": parms.StasisDuration = 1.2f; parms.StasisRadius = 30f; parms.Speed *= 1.4f; break; // paralyzing electric wave
                case "Flame Wheel": parms.BaseDamage *= 1.2f; parms.LingerDuration = 3f; parms.LingerRadius = 12f; break; // orbit leaves fire trail
                case "Ice Shard": parms.Speed *= 1.8f; parms.BaseDamage *= 1.3f; break; // priority hit — fast ice bolt
                case "Razor Leaf": parms.BurstCount += 3; parms.Piercing = true; parms.BaseDamage *= 0.7f; break; // leaf barrage, pierce + sap heal
                case "Summon Spirit": parms.BaseDamage *= 0.9f; parms.Lifetime *= 1.3f; break; // ghost bullets, status on hit
                case "Bible": parms.MaxBounces += 5; parms.Speed *= 1.2f; parms.Lifetime *= 2f; break; // Castlevania bible — orbit that bounces off walls forever
                case "Dark Halo": parms.Size *= 1.2f; parms.Lifetime *= 1.3f; break;
                case "Arc Lightning": parms.Speed *= 1.2f; parms.BaseDamage *= 1.1f; break;
                case "Chain Fire": parms.BaseDamage *= 1.15f; break;
                case "Fire Trap": parms.LingerDuration *= 1.5f; break;
                case "Spore Mine": parms.LingerDuration = 6f; parms.LingerRadius = 25f; break; // Toxic Spikes: poison zone on death
                case "Nightshade": parms.BaseDamage *= 1.2f; parms.LingerDuration *= 1.3f; break;
                case "Shock Root": parms.StasisDuration = MathF.Max(parms.StasisDuration, 0.8f); parms.BaseDamage *= 1.1f; break;
                case "Void Sprout": parms.Size *= 1.4f; parms.Lifetime *= 1.3f; break;
                case "Bone Garden": parms.MaxBounces = 3; parms.ShatterCount += 4; parms.BaseDamage *= 1.15f; break; // Stealth Rock: bouncing bone shards
                case "Bone Saw": parms.BaseDamage *= 1.2f; parms.Size *= 1.15f; break;
                case "Flame Disc": parms.Speed *= 1.2f; parms.BaseDamage *= 1.1f; break;
                case "Hellfire": parms.BurstCount += 4; parms.BaseDamage *= 1.15f; break;
                case "Eclipse": parms.Size *= 1.3f; parms.BurstCount += 2; break;
                case "Sun Lance":
                    parms.BaseDamage *= 2.0f; // big damage
                    parms.BeamLength = 180f; // longer than normal lance
                    parms.Lifetime = 0.5f; // slightly longer hold
                    parms.Size = 12f; // thick beam
                    break;
                case "Void Beam": parms.Size *= 1.3f; parms.Lifetime *= 1.2f; break;
                case "Storm Volley": parms.BurstCount += 2; parms.Speed *= 1.15f; break;
                case "Bone Volley": parms.BaseDamage *= 1.15f; parms.BurstCount += 1; break;
                
                // --- NEW Awakening dual combos ---
                case "Spiral Lance": // Lance + Shatter: drill lance, multi-hit, hold to spin faster
                    parms.BaseDamage *= 0.4f; // per-tick damage (multi-hit compensates)
                    parms.Lifetime = 0.6f; // longer hold
                    parms.BeamLength = 120f;
                    break;
                case "Thunder Lance": // Lance + Pulse: charged lightning ball at lance tip
                    parms.BaseDamage *= 1.3f;
                    parms.Lifetime = 0.4f;
                    break;
                case "Bone Spear":
                    parms.BaseDamage *= 1.8f;
                    parms.BeamLength = 160f; // longer than normal lance (120)
                    parms.Lifetime = 0.35f;
                    parms.Size = 6f;
                    break;
                case "Binding Lance": // Lance + Silk: beam pins target, silk threads radiate
                    parms.Lifetime = 0.4f;
                    parms.StatusDuration = 2.5f; // extended slow
                    break;
                case "Crystal Spiderweb": // Shatter + Silk: shatters into radial tripwires
                    parms.ShatterCount = 0; // we handle custom shatter
                    parms.Lifetime = 1.2f;
                    parms.Size = 5f;
                    break;
                case "Web Trap": // Linger + Silk: sticky web zone
                    parms.Lifetime = 1.0f;
                    break;
                case "Silk Snare": // Bounce + Silk: trails silk threads between bounces
                    parms.Bounces = true;
                    parms.MaxBounces = 6;
                    parms.Speed *= 0.7f;
                    parms.Size = 4f;
                    parms.Lifetime = 4f;
                    break;
                case "Cocoon": // Bloom + Silk: defensive silk shield around player
                    break; // handled in FireWeapon
                case "Marrow Shot": // Bolt + Bone: spinning bone, breaks on hit
                    parms.Speed *= 0.7f;
                    parms.Size = 6f;
                    parms.BaseDamage *= 1.4f;
                    parms.Lifetime = 0.8f;
                    parms.Piercing = false;
                    break;
                case "Rainbow Thread": // Bolt + Silk: rainbow tripwire between player and wall
                    parms.Speed *= 0.9f;
                    parms.Lifetime = 1.5f;
                    break;

                // --- Behavior + Essence ---
                case "Bone Stakes": break; // plant type, handled in FireWeapon
                case "Fireworks": break; // handled in FireWeapon
                case "Bonfire": break; // plant type
                case "Chain Burst": parms.ShatterCount = 6; break; // fragments are homing
                case "Swamp": parms.LingerDuration *= 2f; parms.LingerRadius *= 1.5f; break;
                case "Tesla Ball": parms.MaxBounces += 2; parms.Speed *= 1.2f; break;
                case "Bone Bounce": parms.MaxBounces += 2; parms.BaseDamage *= 1.1f; break;
                case "Storm Giant's Ward": break; // plant type
                case "Bone Pit": break; // plant type
                case "Wildfire": parms.BloomGrowRate = 2f; parms.BloomMaxScale = 2.5f; break;
                case "Bone Blossom": break; // plant type
                case "Overgrowth": parms.BloomGrowRate *= 1.4f; parms.Size *= 1.2f; break;
                case "Shadow Bloom": parms.BloomGrowRate *= 1.3f; parms.BaseDamage *= 1.15f; break;
                case "Time Stop": parms.StasisRadius *= 1.5f; parms.StasisDuration *= 1.5f; break;
                case "Dark Pact": parms.BaseDamage *= 1.25f; break;
            }
        }
        // ═══════════════ END DUAL COMBO EFFECTS ═══════════════

        // ═══ BEHAVIOR+ESSENCE PLANT/SUMMON COMBOS ═══
        // These combos place entities at the player's position instead of firing projectiles
        if (_loadout.Form == Form.None && _currentDualCombo != null)
        {
            // --- Bone Stakes (Shatter + Bone) ---
            if (_currentDualCombo == "Bone Stakes")
            {
                Vector2 toMouse = _mouseWorld - _playerPos;
                if (toMouse.LengthSquared() > 0) toMouse.Normalize();
                Vector2 perpDir = new Vector2(-toMouse.Y, toMouse.X);
                Vector2[] offsets = { toMouse * 40f, perpDir * 40f, -perpDir * 40f };
                float[] angles = { MathF.Atan2(toMouse.Y, toMouse.X) - 0.3f, MathF.PI / 4f, -MathF.PI / 4f };
                for (int s = 0; s < 3; s++)
                {
                    _boneStakes.Add(new BoneStake
                    {
                        Position = _playerPos + offsets[s],
                        Angle = angles[s],
                        Life = 7f,
                        MaxLife = 7f,
                        Damage = parms.BaseDamage,
                        Alive = true,
                    });
                }
                SpawnExplosion(_playerPos, new Color(220, 210, 190), 10, 0.3f, 8f);
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
                return;
            }

            // --- Fireworks (Shatter + Cinder) ---
            if (_currentDualCombo == "Fireworks")
            {
                _fireworkEmbers.Add(new FireworkEmber
                {
                    Position = _playerPos,
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -300f),
                    Timer = 0.3f,
                    Damage = parms.BaseDamage,
                    Alive = true,
                });
                // Launch spark
                for (int p = 0; p < 4; p++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -50f - (float)_rng.NextDouble() * 50f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = new Color(255, 200, 100),
                        Size = 2f,
                    });
                }
                return;
            }

            // --- Bonfire (Linger + Cinder) ---
            if (_currentDualCombo == "Bonfire")
            {
                _lingerZones.Add(new LingerZone
                {
                    Position = _playerPos,
                    Radius = 25f,
                    Life = 10f,
                    MaxLife = 10f,
                    Damage = 1.5f,
                    TickTimer = 0f,
                    Color = new Color(255, 140, 30),
                    EssenceType = Essence.Cinder,
                    FusionTag = "Bonfire",
                    MaxRadius = 75f, // 3x original
                });
                SpawnExplosion(_playerPos, new Color(255, 160, 40), 12, 0.3f, 10f);
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
                return;
            }

            // --- Storm Giant's Ward (Linger + Pulse) ---
            if (_currentDualCombo == "Storm Giant's Ward")
            {
                _lingerZones.Add(new LingerZone
                {
                    Position = _playerPos,
                    Radius = 50f,
                    Life = 12f,
                    MaxLife = 12f,
                    Damage = 0.5f,
                    TickTimer = 0f,
                    Color = new Color(80, 140, 220),
                    EssenceType = Essence.Pulse,
                    FusionTag = "StormWard",
                    PillarTimer = 0.4f,
                });
                SpawnExplosion(_playerPos, new Color(100, 160, 255), 10, 0.3f, 12f);
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
                return;
            }

            // --- Bone Pit (Linger + Bone) ---
            if (_currentDualCombo == "Bone Pit")
            {
                _lingerZones.Add(new LingerZone
                {
                    Position = _playerPos,
                    Radius = 35f,
                    Life = 8f,
                    MaxLife = 8f,
                    Damage = 1f,
