                    Color = new Color(180, 160, 120),
                    EssenceType = Essence.Bone,
                    FusionTag = "BonePit",
                    SlowFactor = 0.6f,
                    PillarTimer = 0.6f, // spike spawn timer
                });
                SpawnExplosion(_playerPos, new Color(200, 190, 160), 8, 0.3f, 10f);
                _trauma = MathF.Min(_trauma + 0.05f, 1f);
                return;
            }

            // --- Bone Blossom (Bloom + Bone) ---
            if (_currentDualCombo == "Bone Blossom")
            {
                var blossomParms = parms;
                blossomParms.IsStationary = true;
                blossomParms.BloomGrowRate = 5f; // grows from size 6 to 25 over ~4s
                blossomParms.BloomMaxScale = 4.2f;
                blossomParms.Lifetime = 4f;
                blossomParms.Size = 6f;
                blossomParms.Color = new EssenceColor(220, 210, 180);
                var blossom = new Projectile(_playerPos, Vector2.Zero, blossomParms);
                blossom.FusionName = "BoneBlossom";
                blossom.LingerTrailTimer = 0f; // reuse as ejection timer
                _projectiles.Add(blossom);
                SpawnExplosion(_playerPos, new Color(220, 210, 180), 8, 0.3f, 8f);
                _trauma = MathF.Min(_trauma + 0.05f, 1f);
