                _cocoonBurstDamage = parms.BaseDamage * 1.5f;
                // Silk wrapping particles
                for (int sp = 0; sp < 20; sp++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float r = 20f + (float)_rng.NextDouble() * 15f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                        Velocity = new Vector2(-MathF.Sin(a) * 40f, MathF.Cos(a) * 40f), // spiral inward
                        Life = 0.5f, MaxLife = 0.5f,
