                    Position = _playerPos + new Vector2(-20, -25),
                    Text = "COCOON",
                    Color = new Color(200, 180, 220),
                    Life = 1f, MaxLife = 1f,
                });
                return;
            }
        }
        // (Wildfire, Ball Lightning, Chain Burst fire normally but need tags)        // ═══ COMET: spawn from sky at cursor position ═══
        if (dc == "Comet")
        {
            Vector2 target = _mouseWorld;
            target.X = MathHelper.Clamp(target.X, _arena.Left + 20, _arena.Right - 20);
            target.Y = MathHelper.Clamp(target.Y, _arena.Top + 20, _arena.Bottom - 20);
            // Comet angles from upper-left with slight variation
            float baseAngle = MathF.PI * 0.65f; // ~117° — incoming direction from upper-left
            float angleVariation = ((float)_rng.NextDouble() - 0.5f) * 0.3f; // ±~8.6°
            float cometAngle = baseAngle + angleVariation;
            float spawnDist = 220f + (float)_rng.NextDouble() * 40f;
            // Spawn offset: upper-left of target
            Vector2 spawnOffset = new Vector2(-MathF.Cos(cometAngle) * spawnDist, -MathF.Sin(cometAngle) * spawnDist);
            // In screen coords (Y down), we want spawn ABOVE and LEFT of target
            Vector2 spawnPos = new Vector2(target.X - spawnDist * 0.7f, target.Y - spawnDist * 0.7f);
            spawnPos.X += ((float)_rng.NextDouble() - 0.5f) * 40f;
            spawnPos.Y += ((float)_rng.NextDouble() - 0.5f) * 20f;
            Vector2 toTarget = Vector2.Normalize(target - spawnPos);
            float fallSpeed = parms.Speed > 0 ? parms.Speed : 400f;
            var comet = new Projectile(spawnPos, toTarget * fallSpeed, parms);
            comet.FusionName = "Comet";
            comet.Size = 12f;
            comet.GracePeriod = Vector2.Distance(spawnPos, target) / fallSpeed; // no collision until near target
            _projectiles.Add(comet);
            _trauma = MathF.Min(_trauma + 0.05f, 0.4f);
            return;
        }

        // Pillars of Muspelheim (Bolt+Linger+Cinder): slow meteoric fireballs that leave erupting pillars
        if (_currentFusion == "Pillars of Muspelheim")
        {
            parms.Speed = 350f;  // slow meteor (was 700 bolt default)
            parms.Size = 7f;     // big fireball
            parms.Piercing = true;
            parms.FireRate = 0.65f; // slower than bolt default
            parms.BaseDamage *= 1.4f;
        }

        // Sacred Fist (Nova+Shatter+Bone): massive bone fist punches forward, short range, huge damage
        if (_currentFusion == "Sacred Fist")
        {
            parms.FireRate = 0.9f;
            parms.BaseDamage *= 4f; // devastating single hit
            parms.Speed = 350f;
            parms.Lifetime = 0.25f; // very short range — melee punch
            parms.Size = 22f; // big fist
            parms.Piercing = true;
            parms.Color = new EssenceColor(220, 200, 170); // bone white
            parms.ShatterCount = 5; // bone fragments on death

            var proj = new Projectile(
                _playerPos + dir * 10f,
                dir * parms.Speed,
                parms
            );
            proj.FusionName = "SacredFist";
            _projectiles.Add(proj);

            // Punch wind burst
            for (int p = 0; p < 15; p++)
            {
                float a = MathF.Atan2(dir.Y, dir.X) + ((float)_rng.NextDouble() - 0.5f) * 0.8f;
                float spd = 100f + (float)_rng.NextDouble() * 200f;
                _particles.Add(new Particle
                {
                    Position = _playerPos + dir * 15f,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                    Life = 0.15f + (float)_rng.NextDouble() * 0.15f,
                    MaxLife = 0.3f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(240, 220, 190) : new Color(200, 180, 150),
                    Size = 3f + (float)_rng.NextDouble() * 4f,
                });
            }
            // Bone dust cloud at player
            for (int p = 0; p < 6; p++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (30f + (float)_rng.NextDouble() * 40f),
                    Life = 0.2f + (float)_rng.NextDouble() * 0.2f,
                    MaxLife = 0.4f,
                    Color = new Color(180, 160, 130),
                    Size = 4f + (float)_rng.NextDouble() * 3f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.15f, 1f);
            return;
        }

        // Mollificare: peaceful bolt — creates pacification zone on hit
        if (_currentFusion == "Mollificare")
        {
            parms.Speed = 200f;
            parms.BaseDamage = 2f; // minimal damage — it's about the effect
            parms.Lifetime = 1.5f;
            parms.Piercing = false;
            parms.Color = new EssenceColor(240, 235, 220);
            parms.Size = 8f;

            var proj = new Projectile(
                _playerPos + dir * 4f,
                dir * parms.Speed,
                parms
            );
            proj.FusionName = "Mollificare";
            _projectiles.Add(proj);
            
            // Soft milky particles at launch
            for (int p = 0; p < 8; p++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos + dir * 8f,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 20f,
                    Life = 0.3f, MaxLife = 0.3f,
                    Color = new Color(240, 235, 220),
                    Size = 2f,
                });
            }
            return;
        }
        
        // Shadow Stitch: channeled chain-possess — fire ONE shadow hand, hold to chain
        if (_currentFusion == "Shadow Stitch")
        {
            // Only fire if no active stitch
            if (_shadowStitch.Active) return;
            
            parms.FireRate = 0.3f; // cooldown after release, not between shots
            parms.Speed = 250f;
            parms.BaseDamage = 0; // no damage on hit — only on release
            parms.Lifetime = 1.2f; // range = speed × lifetime ≈ 300px
            parms.Piercing = false; // die on first hit to trigger chain
            parms.Color = new EssenceColor(40, 10, 60);
            parms.Size = 14f;

            var proj = new Projectile(
                _playerPos + dir * 4f,
                dir * parms.Speed,
                parms
            );
            proj.FusionName = "ShadowStitch";
            _projectiles.Add(proj);

            // Dark burst at feet
            for (int p = 0; p < 10; p++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (25f + (float)_rng.NextDouble() * 35f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                    MaxLife = 0.5f,
                    Color = new Color(30, 8, 45),
                    Size = 4f + (float)_rng.NextDouble() * 5f,
                });
            }
            return;
        }

        // Senbonzakura: scatter of cherry blossom petal blades (before form branching)
        if (_currentFusion == "Senbonzakura")
        {
            parms.FireRate = 0.12f;
            int petalCount = 7 + _rng.Next(4);
            for (int i = 0; i < petalCount; i++)
            {
                float spread = (float)(_rng.NextDouble() - 0.5) * 1.2f;
                float baseAngle = MathF.Atan2(dir.Y, dir.X) + spread;
                float speed = 140f + (float)_rng.NextDouble() * 80f;
                Vector2 petalDir = new Vector2(MathF.Cos(baseAngle), MathF.Sin(baseAngle));
                
                var petalParms = parms;
                petalParms.BaseDamage *= 0.18f;
                petalParms.Size = 1.5f + (float)_rng.NextDouble() * 1f;
                petalParms.Speed = speed;
                petalParms.Lifetime = 2.5f;
                petalParms.BloomGrowRate = 0.4f + (float)_rng.NextDouble() * 0.3f;
                petalParms.BloomMaxScale = 1.5f;
                petalParms.Piercing = true; // petals pass through — death by a thousand cuts
                petalParms.WaveAmplitude = 18f + (float)_rng.NextDouble() * 12f;
                petalParms.WaveFrequency = 4f + (float)_rng.NextDouble() * 3f;
                petalParms.Piercing = true;
                petalParms.Color = new EssenceColor(
                    (byte)(230 + _rng.Next(25)),
                    (byte)(140 + _rng.Next(60)),
                    (byte)(160 + _rng.Next(50))
                );
                
                var proj = new Projectile(
                    _playerPos + petalDir * 8f,
                    petalDir * speed,
                    petalParms
                );
                proj.FusionName = "Senbonzakura";
                _projectiles.Add(proj);
            }
            
            for (int i = 0; i < 3; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 20f,
                    Life = 0.6f, MaxLife = 0.6f,
                    Color = new Color(240, 180, 200),
                    Size = 3f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.02f, 1f);
            return;
        }

        // Earthquake: Geese Howard's Raging Storm — bone spikes from ground in a cage
        if (_currentFusion == "Earthquake")
        {
            parms.Piercing = true;
            parms.BaseDamage *= 3f;
            int spikeCount = 16;
            float radius = 100f;
            for (int i = 0; i < spikeCount; i++)
            {
                float angle = (MathF.PI * 2f / spikeCount) * i;
                Vector2 spikePos = _playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * radius;
                // Clamp to arena
                spikePos.X = MathHelper.Clamp(spikePos.X, _arena.Left + 5, _arena.Right - 5);
                spikePos.Y = MathHelper.Clamp(spikePos.Y, _arena.Top + 5, _arena.Bottom - 5);
                var spikeParms = parms;
                spikeParms.Speed = 0;
                spikeParms.IsStationary = true;
                spikeParms.Lifetime = 3f; // cage lasts 3 seconds
                spikeParms.Size = 4f;
                spikeParms.LingerDuration = 3f;
                spikeParms.LingerRadius = 15f;
                var spike = new Projectile(spikePos, Vector2.Zero, spikeParms);
                spike.FusionName = "Earthquake";
                _projectiles.Add(spike);
                // Ground crack particles rising upward (Geese-style eruption)
                for (int p = 0; p < 3; p++)
                {
                    _particles.Add(new Particle
                    {
                        Position = spikePos,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -40f - (float)_rng.NextDouble() * 60f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = new Color(200, 190, 150),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            // Center shockwave
            SpawnExplosion(_playerPos, new Color(180, 170, 130), 12, 0.4f, 20f);
            _trauma = MathF.Min(_trauma + 0.35f, 1f);
            _hitstopTimer = 0.1f;
            return;
        }
        
        // Unicorn Diana: expanding holy ring that grows
        if (_currentFusion == "Unicorn Diana")
        {
            int count = 24;
            float speed = 90f;
            parms.BaseDamage *= 2f;
            for (int i = 0; i < count; i++)
            {
                float angle = (MathF.PI * 2f / count) * i;
                var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed;
                var p = new Projectile(_playerPos, vel, parms);
                p.Lifetime = 1.2f;
                p.Params.BloomGrowRate = 3f;
                p.Params.BloomMaxScale = 4f;
                p.FusionName = "UnicornDiana";
                _projectiles.Add(p);
            }
            // Holy flash
            for (int i = 0; i < 20; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (50f + (float)_rng.NextDouble() * 80f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                    MaxLife = 0.6f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(255, 255, 200) : new Color(200, 180, 255),
                    Size = 3f + (float)_rng.NextDouble() * 2f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.2f, 1f);
            return;
        }
        
        // Thunderbird Mars: lightning sword — lance that shatters into chain lightning
        if (_currentFusion == "Thunderbird Mars")
        {
            parms.Piercing = true;
            parms.BaseDamage *= 2.5f;
            float beamLen = parms.BeamLength * 1.3f;
            var beam = new Projectile(_playerPos, Vector2.Zero, parms);
            beam.Params.IsStationary = true;
            beam.Params.Lifetime = 0.4f;
            beam.BeamDirection = dir;
            beam.BeamLen = beamLen;
            beam.FusionName = "ThunderbirdMars";
            beam.Size = 8f;
            
            // Truncate at walls
            if (_screenWalls.TryGetValue(_currentScreen, out var tbWalls))
            {
                foreach (var wall in tbWalls)
                {
                    float tMin = 0f, tMax = beamLen;
                    if (MathF.Abs(dir.X) > 0.001f)
                    {
                        float t1 = (wall.Left - _playerPos.X) / dir.X;
                        float t2 = (wall.Right - _playerPos.X) / dir.X;
                        if (t1 > t2) (t1, t2) = (t2, t1);
                        tMin = MathF.Max(tMin, t1); tMax = MathF.Min(tMax, t2);
                    }
                    else if (_playerPos.X < wall.Left || _playerPos.X > wall.Right) continue;
                    if (MathF.Abs(dir.Y) > 0.001f)
                    {
                        float t1 = (wall.Top - _playerPos.Y) / dir.Y;
                        float t2 = (wall.Bottom - _playerPos.Y) / dir.Y;
                        if (t1 > t2) (t1, t2) = (t2, t1);
                        tMin = MathF.Max(tMin, t1); tMax = MathF.Min(tMax, t2);
                    }
                    else if (_playerPos.Y < wall.Top || _playerPos.Y > wall.Bottom) continue;
                    if (tMin <= tMax && tMin > 0 && tMin < beam.BeamLen) beam.BeamLen = tMin;
                }
            }
            beamLen = beam.BeamLen;
            _projectiles.Add(beam);
            // Chain lightning bolts from impact point
            Vector2 tip = _playerPos + dir * beam.BeamLen;
            for (int i = 0; i < _enemies.Count && i < 5; i++)
            {
                if (!_enemies[i].Alive) continue;
                float d = Vector2.Distance(tip, _enemies[i].Position);
                if (d < 200f && HasLineOfSight(tip, _enemies[i].Position))
                {
                    _enemies[i].StasisTimer = MathF.Max(_enemies[i].StasisTimer, 0.8f);
                    _enemies[i].TakeDamage(ApplyElementCounter(_enemies[i], parms.BaseDamage * 0.4f, parms.EssenceType, showBark: false));
                    // Lightning arc particles
                    Vector2 arcDir = _enemies[i].Position - tip;
                    if (arcDir.LengthSquared() > 0) arcDir.Normalize();
                    for (int p = 0; p < 10; p++)
                    {
                        float t = (float)p / 10f;
                        _particles.Add(new Particle
                        {
                            Position = Vector2.Lerp(tip, _enemies[i].Position, t) + new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, ((float)_rng.NextDouble() - 0.5f) * 15f),
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(255, 255, 100),
                            Size = 3f,
                        });
                    }
                    // Bright flash at impact point
                    for (int fp = 0; fp < 10; fp++)
                    {
                        float fa = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = _enemies[i].Position,
                            Velocity = new Vector2(MathF.Cos(fa), MathF.Sin(fa)) * (20f + (float)_rng.NextDouble() * 40f),
                            Life = 0.2f, MaxLife = 0.2f,
                            Color = Color.White,
                            Size = 4f,
                        });
                    }
                }
            }
            // White flash at player position
            for (int wf = 0; wf < 8; wf++)
            {
                float wa = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos,
                    Velocity = new Vector2(MathF.Cos(wa), MathF.Sin(wa)) * (30f + (float)_rng.NextDouble() * 50f),
                    Life = 0.25f, MaxLife = 0.25f,
                    Color = new Color(200, 220, 255),
                    Size = 5f,
                });
            }
            // Crackling particles along main beam
            for (int cp = 0; cp < 12; cp++)
            {
                float ct = (float)_rng.NextDouble();
                _particles.Add(new Particle
                {
                    Position = _playerPos + dir * beamLen * ct + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                    Life = 0.2f, MaxLife = 0.2f,
                    Color = _rng.NextDouble() > 0.3 ? new Color(255, 255, 150) : Color.White,
                    Size = 2f + (float)_rng.NextDouble() * 2f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.15f, 1f);
            return;
        }
        
        // Dark Gate: dark portal that pulls enemies in
        if (_currentFusion == "Dark Gate")
        {
            Vector2 gatePos = _mouseWorld;
            float maxRange = 200f;
            if (Vector2.Distance(_playerPos, gatePos) > maxRange)
            {
                Vector2 toMouse = gatePos - _playerPos;
                toMouse.Normalize();
                gatePos = _playerPos + toMouse * maxRange;
            }
            var gateParms = parms;
            gateParms.Speed = 0;
            gateParms.IsStationary = true;
            gateParms.Lifetime = 4f;
            gateParms.Size = 8f;
            gateParms.BaseDamage *= 0.5f;
            gateParms.LingerDuration = 4f;
            gateParms.LingerRadius = 60f;
            var gate = new Projectile(gatePos, Vector2.Zero, gateParms);
            gate.FusionName = "DarkGate";
            _projectiles.Add(gate);
            // Dark swirl particles
            for (int i = 0; i < 15; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = gatePos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 30f,
                    Velocity = new Vector2(-MathF.Sin(a), MathF.Cos(a)) * 40f,
                    Life = 0.5f, MaxLife = 0.5f,
                    Color = new Color(80, 20, 120),
                    Size = 3f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.1f, 1f);
            return;
        }

        // Tiamat's Garden: reveal sections of the hidden maze
        if (_currentFusion == "Tiamat's Garden")
        {
            Vector2 center = _mouseWorld;
            center.X = MathHelper.Clamp(center.X, _arena.Left + 20, _arena.Right - 20);
            center.Y = MathHelper.Clamp(center.Y, _arena.Top + 20, _arena.Bottom - 20);
            
            // Base reveal radius, charge grows it
            float revealRadius = 60f + chargePercent * 100f; // 80-200px
            RevealMazeNear(center, revealRadius, charged: chargePercent > 0.3f);
            
            // Growth burst particles
            for (int i = 0; i < 15; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                float dist = (float)_rng.NextDouble() * revealRadius;
                _particles.Add(new Particle
                {
                    Position = center + new Vector2(MathF.Cos(a) * dist, MathF.Sin(a) * dist),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -25f - (float)_rng.NextDouble() * 20f),
                    Life = 0.5f, MaxLife = 0.5f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(40, 120, 30) : new Color(200, 40, 60),
                    Size = 3f + (float)_rng.NextDouble() * 2f,
                });
            }
            _trauma = MathF.Min(_trauma + 0.1f, 1f);
            return;
        }

        if (_loadout.Form == Form.Shotgun)
        {
            float baseAngle = MathF.Atan2(dir.Y, dir.X);
            bool isDragonbreath = _currentFusion == "Dragonbreath";
            bool isGebel = _currentFusion == "Gebel's Swarm";
            float spread = MathHelper.ToRadians(isDragonbreath ? 25f : (isGebel ? 30f : 15f));
            int count = (isDragonbreath || isGebel) ? 8 : parms.BurstCount;
            float lifetime = isDragonbreath ? 0.6f : (isGebel ? 0.5f : parms.Lifetime);
            for (int i = 0; i < count; i++)
            {
                float a = baseAngle + (i - count / 2f) * (spread * 2f / count);
                a += ((float)_rng.NextDouble() - 0.5f) * spread * 0.3f;
                var vel = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (parms.Speed + (float)_rng.NextDouble() * 50f);
                var p = new Projectile(_playerPos, vel, parms);
                if (isDragonbreath) p.Lifetime = lifetime;
                if (isGebel) { p.Lifetime = lifetime; p.FusionName = "Gebel's Swarm"; }
                _projectiles.Add(p);
            }
            // Gebel's Swarm: bat screech burst
            if (isGebel)
            {
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
                for (int i = 0; i < 10; i++)
                {
                    float a = baseAngle + ((float)_rng.NextDouble() - 0.5f) * spread * 2f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * 8f,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (60f + (float)_rng.NextDouble() * 100f),
                        Life = 0.2f + (float)_rng.NextDouble() * 0.2f,
                        MaxLife = 0.4f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(120, 40, 160) : new Color(60, 20, 80),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            // Dragonbreath: muzzle flame burst
            if (isDragonbreath)
            {
                _trauma = MathF.Min(_trauma + 0.08f, 1f);
                for (int i = 0; i < 15; i++)
                {
                    float a = baseAngle + ((float)_rng.NextDouble() - 0.5f) * spread * 2f;
                    float spd = 80f + (float)_rng.NextDouble() * 150f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * 10f,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.2f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.5f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 140, 30) : new Color(255, 80, 20),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
            }
        }
        else if (_loadout.Form == Form.Saw)
        {
            bool isDeathScythe = _currentFusion == "Death's Scythe";
            var vel = dir * parms.Speed;
            var p = new Projectile(_playerPos, vel, parms);
            if (isDeathScythe)
            {
                p.Size = 10f;           // moderately bigger (was 8 normal)
                p.Lifetime = 2.5f;
                p.Params.MaxBounces += 2;
                p.FusionName = "Death's Scythe";
            }
            _projectiles.Add(p);
        }
        else if (_loadout.Form == Form.Nova)
        {
            // Expanding shockwave ring — no aiming
            bool isFimbulwinter = _currentFusion == "Fimbulwinter";
            bool isVesuvius = _currentFusion == "Vesuvius";
            bool isSamael = _currentFusion == "Samael's Embrace";
            int count = isFimbulwinter ? 32 : (isVesuvius ? 20 : (isSamael ? 16 : parms.BurstCount));
            float speed = isFimbulwinter ? 80f : (isVesuvius ? 60f : (isSamael ? 100f : parms.Speed));
            for (int i = 0; i < count; i++)
            {
                float angle = (MathF.PI * 2f / count) * i;
                var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed;
                var p = new Projectile(_playerPos, vel, parms);
                if (isFimbulwinter) p.Lifetime = 0.8f; // wide reach
                if (isVesuvius) p.Lifetime = 0.5f; // slower, bigger
                if (isSamael) { p.Lifetime = 0.6f; p.FusionName = "Samael's Embrace"; p.Size = 6f; }
                _projectiles.Add(p);
            }
            _trauma = MathF.Min(_trauma + (isFimbulwinter ? 0.3f : isVesuvius ? 0.2f : isSamael ? 0.15f : 0.12f), 1f);
            
            if (isFimbulwinter)
            {
                // Blizzard: ice crystals + frost mist expanding
                for (int i = 0; i < 40; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 20f + (float)_rng.NextDouble() * 100f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.5f + (float)_rng.NextDouble() * 0.8f,
                        MaxLife = 1.3f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(180, 220, 255) : (_rng.NextDouble() > 0.5 ? new Color(120, 180, 240) : new Color(230, 240, 255)),
                        Size = 2f + (float)_rng.NextDouble() * 4f,
                    });
                }
            }
            else if (isVesuvius)
            {
                // Volcanic eruption: big rising column of fire + ash + lava chunks
                for (int i = 0; i < 40; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 30f + (float)_rng.NextDouble() * 100f;
                    bool isAsh = _rng.NextDouble() < 0.3;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                        Velocity = new Vector2(MathF.Cos(a) * spd, MathF.Sin(a) * spd - 120f - (float)_rng.NextDouble() * 80f), // strong upward
                        Life = 0.5f + (float)_rng.NextDouble() * 0.8f,
                        MaxLife = 1.3f,
                        Color = isAsh ? new Color(80, 60, 50) : (_rng.NextDouble() > 0.4 ? new Color(255, 100, 20) : new Color(255, 200, 50)),
                        Size = isAsh ? (3f + (float)_rng.NextDouble() * 4f) : (2f + (float)_rng.NextDouble() * 3f),
                    });
                }
            }
            else if (isSamael)
            {
                // Samael's Embrace: dark nova — screaming shadow burst (Aria's Flame Demon soul × CoTM darkness)
                for (int i = 0; i < 30; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 40f + (float)_rng.NextDouble() * 120f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, ((float)_rng.NextDouble() - 0.5f) * 20f),
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.4f + (float)_rng.NextDouble() * 0.6f,
                        MaxLife = 1.0f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(120, 40, 160) : (_rng.NextDouble() > 0.5 ? new Color(60, 20, 80) : new Color(180, 60, 200)),
                        Size = 3f + (float)_rng.NextDouble() * 4f,
                    });
                }
            }
            else
            {
                SpawnExplosion(_playerPos, new Color(parms.Color.R, parms.Color.G, parms.Color.B), 12, 0.3f, 20f);
            }
        }
        else if (_loadout.Form == Form.Lance)
        {
            // Hiten Mitsurugi: single wide katana slash — sweeping arc
            bool isHiten = _currentFusion == "Hiten Mitsurugi";
            if (isHiten)
            {
                // HITEN MITSURUGI — straight katana blade swung in an arc
                float baseAngle = MathF.Atan2(dir.Y, dir.X);
                float swingArc = 2.4f; // ~137° total swing
                parms.Piercing = true;
                parms.BaseDamage *= 5f;
                parms.Lifetime = 0.18f;
                parms.Size = 8f; // blade thickness
                parms.ShatterCount = 0;

                var slash = new Projectile(_playerPos, Vector2.Zero, parms);
                slash.Params.IsStationary = true;
                slash.Params.Speed = 0;
                slash.FusionName = "HitenSlash";
                slash.SwingStartAngle = baseAngle - swingArc / 2f;
                slash.SwingEndAngle = baseAngle + swingArc / 2f;
                slash.BladeLength = 110f;
                slash.Size = parms.Size;
                _projectiles.Add(slash);

                // Afterimage — trails behind the main blade
                var afterParms = parms;
                afterParms.BaseDamage = 0;
                afterParms.Lifetime = 0.30f;
                afterParms.Size = 5f;
                var after = new Projectile(_playerPos, Vector2.Zero, afterParms);
                after.Params.IsStationary = true;
                after.FusionName = "HitenAfterimage";
                after.SwingStartAngle = baseAngle - swingArc / 2f;
                after.SwingEndAngle = baseAngle + swingArc / 2f;
                after.BladeLength = 105f;
                after.Size = afterParms.Size;
                _projectiles.Add(after);

                _trauma = MathF.Min(_trauma + 0.35f, 1f);
                // Speed lines
                float slashAngle = MathF.Atan2(dir.Y, dir.X);
                for (int i = 0; i < 24; i++)
                {
                    float spread = ((float)_rng.NextDouble() - 0.5f) * 0.8f;
                    float angle = slashAngle + spread;
                    float dist = 20f + (float)_rng.NextDouble() * 100f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * dist,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * (200f + (float)_rng.NextDouble() * 150f),
                        Life = 0.15f + (float)_rng.NextDouble() * 0.1f,
                        MaxLife = 0.25f,
                        Color = Color.White,
                        Size = 1f + (float)_rng.NextDouble() * 1.5f,
                    });
                }
                Vector2 hPerp = new Vector2(-dir.Y, dir.X);
                for (int i = 0; i < 10; i++)
                {
                    float t = (float)_rng.NextDouble();
                    float side = _rng.NextDouble() > 0.5 ? 1f : -1f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * 100f * t,
                        Velocity = hPerp * side * (40f + (float)_rng.NextDouble() * 30f),
                        Life = 0.2f + (float)_rng.NextDouble() * 0.15f,
                        MaxLife = 0.35f,
                        Color = new Color(180, 140, 220),
                        Size = 1.5f + (float)_rng.NextDouble() * 1.5f,
                    });
                }
                return;
            }

            // Dragon Slayer (Lance+Shatter+Bone): colossal bone greatsword cleave
            if (_currentFusion == "Dragon Slayer")
            {
                float baseAngle = MathF.Atan2(dir.Y, dir.X);
                float swingArc = 3.0f; // ~172° — massive sweep
                parms.Piercing = true;
                parms.BaseDamage *= 6f; // even more than Hiten
                parms.Lifetime = 0.28f; // slower, heavier swing
                parms.Size = 16f; // WIDE blade — Berserk greatsword
                parms.ShatterCount = 8; // bone fragments spray on hit

                var slash = new Projectile(_playerPos, Vector2.Zero, parms);
                slash.Params.IsStationary = true;
                slash.Params.Speed = 0;
                slash.FusionName = "DragonSlayer";
                slash.SwingStartAngle = baseAngle - swingArc / 2f;
                slash.SwingEndAngle = baseAngle + swingArc / 2f;
                slash.BladeLength = 160f; // enormous reach
                slash.Size = parms.Size;
                _projectiles.Add(slash);

                // Heavy afterimage — bone-white trail
                var afterParms = parms;
                afterParms.BaseDamage = 0;
                afterParms.Lifetime = 0.40f; // lingers longer than Hiten
                afterParms.Size = 12f;
                afterParms.ShatterCount = 0;
                var after = new Projectile(_playerPos, Vector2.Zero, afterParms);
                after.Params.IsStationary = true;
                after.Params.Speed = 0;
                after.FusionName = "DragonSlayerAfter";
                after.SwingStartAngle = baseAngle - swingArc / 2f;
                after.SwingEndAngle = baseAngle + swingArc / 2f;
                after.BladeLength = 155f;
                after.Size = afterParms.Size;
                _projectiles.Add(after);

                _trauma = MathF.Min(_trauma + 0.45f, 1f); // bigger than Hiten
                _hitstopTimer = MathF.Max(_hitstopTimer, 0.04f);

                // Ground crack particles — bone shards spraying from impact
                for (int i = 0; i < 16; i++)
                {
                    float angle = baseAngle + ((float)_rng.NextDouble() - 0.5f) * swingArc;
                    float dist = 40f + (float)_rng.NextDouble() * 130f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * dist,
                        Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * (100f + (float)_rng.NextDouble() * 200f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                        MaxLife = 0.5f,
                        Color = _rng.NextDouble() < 0.5 ? new Color(230, 220, 200) : new Color(180, 170, 150),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                // Dust cloud at feet
                for (int i = 0; i < 8; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, 5f + (float)_rng.NextDouble() * 10f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, -10f - (float)_rng.NextDouble() * 20f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = new Color(120, 110, 100),
                        Size = 3f + (float)_rng.NextDouble() * 4f,
                    });
                }
                return;
            }

            // Marrow Bloom (Lance+Bloom+Bone): homing bone lance beam
            bool isMarrowBloom = _currentFusion == "Marrow Bloom";
            if (isMarrowBloom)
            {
                parms.BaseDamage *= 2.5f;
                parms.Piercing = false;
                parms.Color = new EssenceColor(220, 200, 170); // ivory bone
                parms.Size = 8f;
            }

            // Beam: spawn ONE projectile at player position — draws as full continuous beam
            float beamLen = parms.BeamLength;
            bool isGungnir = _currentFusion == "Gungnir";
            bool isSurya = _currentFusion == "Surya's Wrath";
            bool isLonginus = _currentFusion == "Longinus";
            bool isBifrost = _currentFusion == "Bifrost";
            bool isSpineOfWorld = _currentFusion == "Spine of the World";
            bool isFenrirsJaw = _currentFusion == "Fenrir's Jaw";
            bool isAmaterasu = _currentFusion == "Amaterasu";
            bool isHydra = _currentFusion == "Hydra";
            bool isHammerOfGod = _currentFusion == "Hammer of God";
            bool isZaHando = _currentFusion == "Za Hando";
            bool isAbhiseka = _currentFusion == "Abhiseka";
            if (chargePercent >= 0.3f) beamLen *= 1f + chargePercent * 0.6f;
            if (isGungnir)
            {
                beamLen *= 1.5f;
                parms.Lifetime = 0.6f;
                parms.BloomGrowRate = 0f;
                parms.Size = 10f; // beam thickness
            }
            if (isSurya)
            {
                beamLen *= 1.2f;
                parms.Lifetime = 0.5f;
                parms.Size = 7f;
            }
            if (isLonginus)
            {
                beamLen *= 1.8f;
                parms.Lifetime = 0.7f;
                parms.StasisDuration = 2f;
                parms.StasisRadius = 40f;
                parms.Size = 6f;
            }
            if (isBifrost)
            {
                parms.Size = 6f;
                parms.Lifetime = 0.4f;
            }
            if (isSpineOfWorld)
            {
                parms.Size = 7f;
                parms.Lifetime = 0.35f;
            }
            if (isFenrirsJaw)
            {
                parms.BaseDamage *= 2f;
                parms.Size = 6f;
            }
            if (isAmaterasu)
            {
                parms.Size = 8f;
                parms.Lifetime = 0.5f;
                parms.BaseDamage *= 2.5f;
            }
            if (isHydra)
            {
                parms.Size = 5f;
                parms.Lifetime = 0.5f;
            }
            if (isHammerOfGod)
            {
                parms.BaseDamage *= 3f; // devastating
                parms.Size = 10f; // thick bolt
                parms.Lifetime = 0.5f;
            }
            if (isZaHando)
            {
                parms.BaseDamage *= 2f;
                parms.Size = 10f;
                parms.Lifetime = 0.6f;
                parms.Color = new EssenceColor(0, 200, 120); // rift green instead of purple
            }
            if (isAbhiseka)
            {
                parms.BaseDamage *= 1.5f;
                parms.Size = 7f;
                parms.Lifetime = 0.5f;
                parms.BloomGrowRate = 80f; // bloom creates the hallowed ground
            }
            // Default lance thickness
            if (!isGungnir && !isSurya && !isLonginus && !isBifrost && !isSpineOfWorld && !isFenrirsJaw && !isAmaterasu && !isHydra && !isHammerOfGod && !isZaHando && !isAbhiseka) parms.Size = MathF.Max(parms.Size, 5f);
            
            parms.Piercing = true; // beams always pierce
            var beam = new Projectile(_playerPos, Vector2.Zero, parms);
            beam.Params.IsStationary = true;
            beam.BeamDirection = dir;
            beam.BeamLen = beamLen;
            if (isMarrowBloom) beam.FusionName = "MarrowBloom";
            else if (isGungnir) beam.FusionName = "Gungnir";
            else if (isSurya) beam.FusionName = "Surya";
            else if (isLonginus) beam.FusionName = "Longinus";
            else if (_currentDualCombo == "Spiral Lance") beam.FusionName = "Impaler";
            else if (_currentDualCombo == "Thunder Lance") beam.FusionName = "ThunderLance";
            else if (_currentDualCombo == "Scorched Earth") beam.FusionName = "ScorchedEarth";
            else if (_currentDualCombo == "Nyoibo") beam.FusionName = "Nyoibo";
            else if (_currentDualCombo == "Sun Lance") beam.FusionName = "SunLance";
            else if (_currentDualCombo == "Bone Spear") beam.FusionName = "BoneSpear";
            else if (_currentDualCombo == "Binding Lance") beam.FusionName = "BindingLance";
            else if (isBifrost) beam.FusionName = "Bifrost";
            else if (isSpineOfWorld) beam.FusionName = "SpineOfWorld";
            else if (isFenrirsJaw) beam.FusionName = "FenrirsJaw";
            else if (isAmaterasu) beam.FusionName = "Amaterasu";
            else if (isHydra) beam.FusionName = "Hydra";
            else if (isHammerOfGod) beam.FusionName = "HammerOfGod";
            else if (isZaHando) beam.FusionName = "ZaHando";
            else if (isAbhiseka) beam.FusionName = "Abhiseka";
            beam.Size = parms.Size;
            
            // Truncate beam at walls
            if (_screenWalls.TryGetValue(_currentScreen, out var beamWalls))
            {
                foreach (var wall in beamWalls)
                {
                    // Ray-AABB intersection: find where beam enters the wall
                    float tMin = 0f, tMax = beamLen;
                    Vector2 origin = _playerPos;
                    // Check X slab
                    if (MathF.Abs(dir.X) > 0.001f)
                    {
                        float t1 = (wall.Left - origin.X) / dir.X;
                        float t2 = (wall.Right - origin.X) / dir.X;
                        if (t1 > t2) (t1, t2) = (t2, t1);
                        tMin = MathF.Max(tMin, t1);
                        tMax = MathF.Min(tMax, t2);
                    }
                    else if (origin.X < wall.Left || origin.X > wall.Right) continue;
                    // Check Y slab
                    if (MathF.Abs(dir.Y) > 0.001f)
                    {
                        float t1 = (wall.Top - origin.Y) / dir.Y;
                        float t2 = (wall.Bottom - origin.Y) / dir.Y;
                        if (t1 > t2) (t1, t2) = (t2, t1);
                        tMin = MathF.Max(tMin, t1);
                        tMax = MathF.Min(tMax, t2);
                    }
                    else if (origin.Y < wall.Top || origin.Y > wall.Bottom) continue;
                    
                    if (tMin <= tMax && tMin > 0 && tMin < beam.BeamLen)
                        beam.BeamLen = tMin; // truncate at wall face
                }
            }
            beamLen = beam.BeamLen; // use truncated length for all effects below
            bool beamHitWall = beamLen < parms.BeamLength - 1f;
            
            _projectiles.Add(beam);

            _trauma = MathF.Min(_trauma + (isGungnir ? 0.18f : (isLonginus ? 0.15f : (isSurya ? 0.12f : 0.08f))), 1f);
            
            // Wall impact spray — sparks fly backward from wall contact point
            if (beamHitWall)
            {
                Vector2 wallHit = _playerPos + dir * beamLen;
                for (int i = 0; i < 12; i++)
                {
                    float spread = ((float)_rng.NextDouble() - 0.5f) * 80f;
                    float backSpeed = 80f + (float)_rng.NextDouble() * 120f;
                    _particles.Add(new Particle
                    {
                        Position = wallHit + new Vector2(((float)_rng.NextDouble() - 0.5f) * 4f, ((float)_rng.NextDouble() - 0.5f) * 4f),
                        Velocity = -dir * backSpeed + new Vector2(spread, spread),
                        Life = 0.25f + (float)_rng.NextDouble() * 0.15f,
                        MaxLife = 0.4f,
                        Color = _rng.Next(3) switch
                        {
                            0 => new Color(255, 230, 180), // bright spark
                            1 => new Color(200, 180, 140), // stone chip
                            _ => new Color(150, 140, 120), // dust
                        },
                        Size = 1.5f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            
            // Surya's Wrath: scorched earth — fire linger zones along beam (inspired by CoTM flame pillar DSS)
            if (isSurya)
            {
                int zoneCount = 5;
                for (int i = 0; i < zoneCount; i++)
                {
                    float t = (i + 0.5f) / zoneCount;
                    _lingerZones.Add(new LingerZone
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Radius = 18f,
                        Life = 2f,
                        MaxLife = 2f,
                        Damage = parms.BaseDamage * 0.3f,
                        TickTimer = 0f,
                        Color = new Color(255, 120, 30),
                        EssenceType = Essence.Cinder,
                        FusionTag = "SuryaScorch",
                    });
                }
                // Fire eruption along beam
                for (int i = 0; i < 20; i++)
                {
                    float t = (float)_rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t + new Vector2(((float)_rng.NextDouble() - 0.5f) * 10f, ((float)_rng.NextDouble() - 0.5f) * 10f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -60f - (float)_rng.NextDouble() * 80f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 100, 20) : new Color(255, 200, 50),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
            }
            
            // Bifrost: rainbow linger zones along beam
            if (isBifrost)
            {
                for (int i = 0; i < 5; i++)
                {
                    float t = (i + 0.5f) / 5f;
                    float hue = (_totalTime * 2f + i * 0.5f) % 1f;
                    int r2 = (int)(MathF.Sin(hue * MathF.PI * 2f) * 127 + 128);
                    int g2 = (int)(MathF.Sin((hue + 0.33f) * MathF.PI * 2f) * 127 + 128);
                    int b2 = (int)(MathF.Sin((hue + 0.66f) * MathF.PI * 2f) * 127 + 128);
                    _lingerZones.Add(new LingerZone
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Radius = 12f,
                        Life = 5f,
                        MaxLife = 5f,
                        Damage = parms.BaseDamage * 0.2f,
                        TickTimer = 0f,
                        Color = new Color(r2, g2, b2),
                        EssenceType = Essence.Pulse,
                        FusionTag = "Bifrost",
                        VineTimer = dir.X,  // store beam dir X
                        GrowRate = dir.Y,   // store beam dir Y
                    });
                }
            }

            // Spine of the World: bone stakes along beam
            if (isSpineOfWorld)
            {
                _trauma = MathF.Min(_trauma + 0.1f, 1f);
                for (int i = 0; i < 5; i++)
                {
                    float t = (i + 0.5f) / 5f;
                    _boneStakes.Add(new BoneStake
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Angle = ((float)_rng.NextDouble() - 0.5f) * 0.3f,
                        Life = 6f,
                        MaxLife = 6f,
                        Damage = parms.BaseDamage * 0.4f,
                        Alive = true,
                    });
                    // Bone dust on spawn
                    for (int p2 = 0; p2 < 4; p2++)
                    {
                        _particles.Add(new Particle
                        {
                            Position = _playerPos + dir * beamLen * t,
                            Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -30f - (float)_rng.NextDouble() * 30f),
                            Life = 0.3f, MaxLife = 0.3f,
                            Color = new Color(200, 190, 160),
                            Size = 2f + (float)_rng.NextDouble() * 2f,
                        });
                    }
                }
            }

            // Za Hando: dimensional rift at beam endpoint — erases space, sucks enemies in
            if (isZaHando)
            {
                _trauma = MathF.Min(_trauma + 0.25f, 1f);
            }

            // Abhiseka: hallowed ground at beam endpoint — white fire ascending, heals + damages
            if (isAbhiseka)
            {
                Vector2 holyPos = _playerPos + dir * beamLen;
                _trauma = MathF.Min(_trauma + 0.15f, 1f);
                // Small ritual circle at player's feet
                for (int rc = 0; rc < 16; rc++)
                {
                    float a = (MathF.PI * 2f / 16) * rc;
                    float circR = 25f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * circR,
                        Velocity = new Vector2(0, -15f),
                        Life = 0.8f, MaxLife = 0.8f,
                        Color = new Color(255, 240, 200),
                        Size = 1.5f,
                    });
                }
                _lingerZones.Add(new LingerZone
                {
                    Position = holyPos,
                    Radius = 90f,
                    Life = 6f,
                    MaxLife = 6f,
                    Damage = parms.BaseDamage * 0.4f,
                    TickTimer = 0f,
                    Color = new Color(255, 250, 230),
                    EssenceType = Essence.Hollow,
                    FusionTag = "Abhiseka",
                });
                // Consecration burst — white fire erupts upward
                for (int i = 0; i < 25; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float d2 = (float)_rng.NextDouble() * 60f;
                    _particles.Add(new Particle
                    {
                        Position = holyPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * d2,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -80f - (float)_rng.NextDouble() * 60f),
                        Life = 0.5f + (float)_rng.NextDouble() * 0.4f,
                        MaxLife = 0.9f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 255, 240) : new Color(255, 220, 150),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
            }

            // Fenrir's Jaw: spawn SECOND converging beam + explosion at convergence
            if (isFenrirsJaw)
            {
                // Two converging beams at ±8°
                float angle1 = MathF.Atan2(dir.Y, dir.X) + 0.14f;
                float angle2 = MathF.Atan2(dir.Y, dir.X) - 0.14f;
                Vector2 dir1 = new Vector2(MathF.Cos(angle1), MathF.Sin(angle1));
                Vector2 dir2 = new Vector2(MathF.Cos(angle2), MathF.Sin(angle2));
                // Modify first beam direction
                beam.BeamDirection = dir1;
                beam.BeamLen = beamLen * 0.85f;
                // Create second beam
                var beam2 = new Projectile(_playerPos, Vector2.Zero, parms);
                beam2.Params.IsStationary = true;
                beam2.BeamDirection = dir2;
                beam2.BeamLen = beamLen * 0.85f;
                beam2.Size = parms.Size;
                beam2.FusionName = "FenrirsJaw";
                _projectiles.Add(beam2);
                // Convergence explosion
                Vector2 convergence = _playerPos + dir * beamLen * 0.8f;
                SpawnExplosion(convergence, new Color(255, 120, 30), 20, 0.5f, 25f);
                SpawnExplosion(convergence, Color.White, 8, 0.2f, 10f);
                _trauma = MathF.Min(_trauma + 0.25f, 1f);
                // Damage enemies near convergence
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive) continue;
                    if (Vector2.Distance(convergence, _enemies[e].Position) < 25f + _enemies[e].Size / 2f)
                    {
                        _enemies[e].TakeDamage(ApplyElementCounter(_enemies[e], parms.BaseDamage * 3f, parms.EssenceType));
                        _enemies[e].Stagger += 20f;
                    }
                }
                // 8 fire fragments outward from convergence
                for (int f = 0; f < 8; f++)
                {
                    float a = (MathF.PI * 2f / 8f) * f;
                    Vector2 fv = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 250f;
                    var fragParms = parms;
                    fragParms.BaseDamage *= 0.3f;
                    fragParms.Lifetime = 0.4f;
                    fragParms.Size = 3f;
                    fragParms.IsStationary = false;
                    fragParms.Piercing = false;
                    var frag = new Projectile(convergence, fv, fragParms);
                    frag.Size = 3f;
                    frag.FusionName = "FenrirsJawFrag";
                    _projectiles.Add(frag);
                }
            }

            // Hammer of God: void bolt → implosion → reality fracture → AOE pulse
            if (isHammerOfGod)
            {
                Vector2 impactPos = _playerPos + dir * beamLen;
                
                // Screen trauma — heavy impact
                _trauma = MathF.Min(_trauma + 0.6f, 1f);
                _hitstopTimer = 0.35f; // long freeze frame — feel the impact
                
                // Phase 1: Implosion — particles suck inward toward impact
                for (int p = 0; p < 35; p++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float dist2 = 50f + (float)_rng.NextDouble() * 80f;
                    Vector2 startPos = impactPos + new Vector2(MathF.Cos(a) * dist2, MathF.Sin(a) * dist2);
                    Vector2 vel = (impactPos - startPos) * 2f; // rush inward (slower = more visible)
                    _particles.Add(new Particle
                    {
                        Position = startPos,
                        Velocity = vel,
                        Life = 0.5f, MaxLife = 0.5f,
                        Color = new Color(180, 140, 220),
                        Size = 3f + (float)_rng.NextDouble() * 4f,
                    });
                }
                
                // Phase 2: Lavender debris floating upward (reversed gravity)
                for (int d = 0; d < 20; d++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float r = (float)_rng.NextDouble() * 45f;
                    _particles.Add(new Particle
                    {
                        Position = impactPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -25f - (float)_rng.NextDouble() * 40f), // float UP slowly
                        Life = 1.2f + (float)_rng.NextDouble() * 0.8f,
                        MaxLife = 2f,
                        Color = new Color(180, 160, 220) * 0.7f,
                        Size = 3f + (float)_rng.NextDouble() * 5f,
                    });
                }
                
                // Phase 3: White core flash + expanding violet ring
                SpawnExplosion(impactPos, Color.White, 16, 0.25f, 20f);
                SpawnExplosion(impactPos, new Color(140, 100, 200), 30, 0.6f, 40f);
                
                // Phase 5: Screen crack overlay — fracture lines persist for 1.2s
                _screenCracks.Add(new ScreenCrack { Origin = impactPos, Timer = 2f, MaxTime = 2f });
                
                // Phase 5: AOE damage pulse at impact — damages everything in radius
                float aoeRadius = 80f;
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive) continue;
                    float eDist = Vector2.Distance(impactPos, _enemies[e].Position);
                    if (eDist < aoeRadius + _enemies[e].Size / 2f)
                    {
                        float falloff = 1f - (eDist / (aoeRadius + _enemies[e].Size / 2f)) * 0.5f; // 100% center, 50% edge
                        _enemies[e].TakeDamage(ApplyElementCounter(_enemies[e], parms.BaseDamage * 2f * falloff, parms.EssenceType));
                        _enemies[e].Stagger += 30f;
                        // Knockback away from impact
                        Vector2 kb = _enemies[e].Position - impactPos;
                        if (kb.LengthSquared() > 0.01f) kb = Vector2.Normalize(kb);
                        _enemies[e].KnockbackVel = kb * 200f;
                        _enemies[e].HitFlash = 0.15f;
                    }
                }
                
                // Vignette text — the name lingers
                _floatingTexts.Add(new FloatingText
                {
                    Position = impactPos + new Vector2(-40, -50),
                    Text = "HAMMER OF GOD",
                    Color = new Color(200, 180, 255) * 0.8f,
                    Life = 2f, MaxLife = 2f,
                });
            }

            // Hydra: two additional forking beams
            if (isHydra)
            {
                float baseAngle = MathF.Atan2(dir.Y, dir.X);
                // Beam 2: find nearest enemy in positive angular range
                Vector2 fork1Origin = _playerPos + dir * beamLen * 0.5f;
                float angle2 = baseAngle + 0.26f; // default +15°
                float bestDist2 = float.MaxValue;
                foreach (var en in _enemies)
                {
                    if (!en.Alive) continue;
                    float d = Vector2.Distance(fork1Origin, en.Position);
                    if (d < 300f && d < bestDist2)
                    {
                        float toEnemy = MathF.Atan2(en.Position.Y - fork1Origin.Y, en.Position.X - fork1Origin.X);
                        float diff = toEnemy - baseAngle;
                        while (diff > MathF.PI) diff -= MathF.PI * 2f;
                        while (diff < -MathF.PI) diff += MathF.PI * 2f;
                        if (diff > 0.05f && diff < MathF.PI * 0.25f) { angle2 = toEnemy; bestDist2 = d; }
                    }
                }
                Vector2 dir2 = new Vector2(MathF.Cos(angle2), MathF.Sin(angle2));
                var beam2 = new Projectile(_playerPos + dir * beamLen * 0.5f, Vector2.Zero, parms);
                beam2.Params.IsStationary = true;
                beam2.BeamDirection = dir2;
                beam2.BeamLen = beamLen;
                beam2.Size = parms.Size;
                beam2.Lifetime = 0.5f;
                beam2.FusionName = "Hydra";
                _projectiles.Add(beam2);

                // Second-level bifurcation from beam2
                if (_rng.NextDouble() < 0.7)
                {
                    Vector2 fork1Tip = fork1Origin + dir2 * beamLen;
                    float subAngle2a = angle2 + 0.2f + (float)_rng.NextDouble() * 0.15f;
                    Vector2 subDir2a = new Vector2(MathF.Cos(subAngle2a), MathF.Sin(subAngle2a));
                    var subBeam2a = new Projectile(fork1Tip, Vector2.Zero, parms);
                    subBeam2a.Params.IsStationary = true;
                    subBeam2a.BeamDirection = subDir2a;
                    subBeam2a.BeamLen = beamLen * 0.6f;
                    subBeam2a.Size = parms.Size * 0.7f;
                    subBeam2a.Lifetime = 0.45f;
                    subBeam2a.FusionName = "Hydra";
                    _projectiles.Add(subBeam2a);
                }

                // Beam 3: find nearest enemy in negative angular range
                Vector2 fork2Origin = _playerPos + dir * beamLen * 0.7f;
                float angle3 = baseAngle - 0.26f; // default -15°
                float bestDist3 = float.MaxValue;
                foreach (var en in _enemies)
                {
                    if (!en.Alive) continue;
                    float d = Vector2.Distance(fork2Origin, en.Position);
                    if (d < 300f && d < bestDist3)
                    {
                        float toEnemy = MathF.Atan2(en.Position.Y - fork2Origin.Y, en.Position.X - fork2Origin.X);
                        float diff = toEnemy - baseAngle;
                        while (diff > MathF.PI) diff -= MathF.PI * 2f;
                        while (diff < -MathF.PI) diff += MathF.PI * 2f;
                        if (diff < -0.05f && diff > -MathF.PI * 0.25f) { angle3 = toEnemy; bestDist3 = d; }
                    }
                }
                Vector2 dir3 = new Vector2(MathF.Cos(angle3), MathF.Sin(angle3));
                var beam3 = new Projectile(_playerPos + dir * beamLen * 0.7f, Vector2.Zero, parms);
                beam3.Params.IsStationary = true;
                beam3.BeamDirection = dir3;
                beam3.BeamLen = beamLen;
                beam3.Size = parms.Size;
                beam3.Lifetime = 0.5f;
                beam3.FusionName = "Hydra";
                _projectiles.Add(beam3);

                // Second-level bifurcation from beam3
                if (_rng.NextDouble() < 0.7)
                {
                    Vector2 fork2Tip = fork2Origin + dir3 * beamLen;
                    float subAngle3a = angle3 - 0.2f - (float)_rng.NextDouble() * 0.15f;
                    Vector2 subDir3a = new Vector2(MathF.Cos(subAngle3a), MathF.Sin(subAngle3a));
                    var subBeam3a = new Projectile(fork2Tip, Vector2.Zero, parms);
                    subBeam3a.Params.IsStationary = true;
                    subBeam3a.BeamDirection = subDir3a;
                    subBeam3a.BeamLen = beamLen * 0.6f;
                    subBeam3a.Size = parms.Size * 0.7f;
                    subBeam3a.Lifetime = 0.45f;
                    subBeam3a.FusionName = "Hydra";
                    _projectiles.Add(subBeam3a);
                }

                // Electric particles
                for (int ep = 0; ep < 15; ep++)
                {
                    float t = (float)_rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 80f, ((float)_rng.NextDouble() - 0.5f) * 80f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(120, 180, 255) : Color.White,
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }

            // Longinus: freeze everything along the beam + pale void particles (SotN Longinus Spear)
            if (isLonginus)
            {
                // Freeze all enemies near beam line
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive) continue;
                    // Point-to-line distance
                    Vector2 toEnemy = _enemies[e].Position - _playerPos;
                    float proj = Vector2.Dot(toEnemy, dir);
                    if (proj < 0 || proj > beamLen) continue;
                    Vector2 closest = _playerPos + dir * proj;
                    float perpDist = Vector2.Distance(_enemies[e].Position, closest);
                    if (perpDist < 40f)
                    {
                        _enemies[e].StasisTimer = MathF.Max(_enemies[e].StasisTimer, 2f);
                        
                        // Longinus Execution: enemies below 30% HP die instantly
                        if (_enemies[e].Hp < _enemies[e].MaxHp * 0.3f)
                        {
                            _enemies[e].Hp = 0;
                            _enemies[e].Alive = false;
                            _killCount++;
                            
                            // Dramatic execution effect — holy lance pierce
                            _trauma = MathF.Min(_trauma + 0.1f, 1f);
                            // Cross/holy burst at enemy position
                            Vector2 ePos = _enemies[e].Position;
                            // Vertical beam
                            for (int v = -3; v <= 3; v++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = ePos + new Vector2(0, v * 4f),
                                    Velocity = new Vector2(0, v * 30f),
                                    Life = 0.5f, MaxLife = 0.5f,
                                    Color = new Color(220, 230, 255),
                                    Size = 3f,
                                });
                            }
                            // Horizontal beam
                            for (int h = -3; h <= 3; h++)
                            {
                                _particles.Add(new Particle
                                {
                                    Position = ePos + new Vector2(h * 4f, 0),
                                    Velocity = new Vector2(h * 30f, 0),
                                    Life = 0.5f, MaxLife = 0.5f,
                                    Color = new Color(220, 230, 255),
                                    Size = 3f,
                                });
                            }
                            // Bright flash
                            SpawnExplosion(ePos, new Color(240, 245, 255), 12, 0.4f, 15f);
                            // Damage number (shows "EXECUTE")
                            _damageNumbers.Add(new DamageNumber
                            {
                                Position = ePos + new Vector2(0, -_enemies[e].Size),
                                Amount = _enemies[e].MaxHp,
                                Timer = 1f,
                                Color = new Color(220, 230, 255),
                            });
                        }
                    }
                }
                // Pale frost particles along beam
                for (int i = 0; i < 16; i++)
                {
                    float t = (float)_rng.NextDouble();
                    Vector2 perp = new Vector2(-dir.Y, dir.X);
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t + perp * ((float)_rng.NextDouble() - 0.5f) * 12f,
                        Velocity = perp * ((float)_rng.NextDouble() - 0.5f) * 40f + new Vector2(0, -20f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(180, 210, 240) : new Color(220, 230, 255),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            
            if (isGungnir)
            {
                // Shadow tendrils: dense purple particles along full beam + perpendicular wisps
                Vector2 perp = new Vector2(-dir.Y, dir.X);
                for (int i = 0; i < 24; i++)
                {
                    float t = (float)_rng.NextDouble();
                    float side = _rng.NextDouble() > 0.5 ? 1f : -1f;
                    // Perpendicular shadow wisps
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t + perp * side * ((float)_rng.NextDouble() * 6f),
                        Velocity = perp * side * (30f + (float)_rng.NextDouble() * 60f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(120, 40, 160) : new Color(80, 20, 120),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                // Dark core glow along beam center
                for (int i = 0; i < 12; i++)
                {
                    float t = (float)_rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Velocity = dir * 10f + new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, ((float)_rng.NextDouble() - 0.5f) * 15f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.4f,
                        MaxLife = 0.7f,
                        Color = new Color(160, 60, 200),
                        Size = 3f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            else
            {
                // Normal beam flash particles
                for (int i = 0; i < 6; i++)
                {
                    float t = (float)_rng.NextDouble();
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * beamLen * t,
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 60f, ((float)_rng.NextDouble() - 0.5f) * 60f),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = new Color(parms.Color.R, parms.Color.G, parms.Color.B),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
        }
        else if (_loadout.Form == Form.Volley)
        {
            // Three-round burst: fire 3 shots with slight delay via staggered lifetime offsets
            bool isKatyusha = _currentFusion == "Katyusha";
            bool isShango = _currentFusion == "Shango's Shale";
            bool isGorgon = _currentFusion == "Gorgon's Grasp";
            
            // Gorgon's Grasp: autonomous — no manual fire needed, just return
            if (isGorgon) return;
            
            // Katyusha: single big rocket — splits on hit (Clash Royale Firecracker)
            if (isKatyusha)
            {
                parms.Size = 8f;
                parms.Speed *= 0.85f; // slightly slower — big rocket
                parms.Lifetime = 1.5f;
                parms.ShatterCount = 0; // we handle splitting manually via FusionName
                var vel = dir * parms.Speed;
                var p = new Projectile(_playerPos + dir * 5f, vel, parms);
                p.FusionName = "Katyusha";
                _projectiles.Add(p);
            }
            else
            {
            float spread = MathHelper.ToRadians(isShango ? 12f : 3f);
            int burstCount = isShango ? 3 : parms.BurstCount;
                        if (isShango)
            {
                parms.MaxBounces += 2;
                parms.Speed *= 1.3f;
                parms.Lifetime = 3f;
                parms.BaseDamage *= 0.7f;
                parms.Size = 6f;
            }
            for (int i = 0; i < burstCount; i++)
            {
                float angleOffset = (i - (burstCount - 1) / 2f) * spread + ((float)_rng.NextDouble() - 0.5f) * spread * 0.3f;
                float baseAngle = MathF.Atan2(dir.Y, dir.X) + angleOffset;
                var vel = new Vector2(MathF.Cos(baseAngle), MathF.Sin(baseAngle)) * parms.Speed;
                Vector2 offset = dir * (i * 8f);
                var p = new Projectile(_playerPos + offset, vel, parms);
                if (isShango) p.FusionName = "Shango's Shale";
                if (_currentDualCombo == "Marrow Shot") p.FusionName = "MarrowShot";
                if (_currentDualCombo == "Rainbow Thread") p.FusionName = "SilkShot";
                if (_currentDualCombo == "Crystal Spiderweb") p.FusionName = "CrystalSpiderweb";
                if (_currentDualCombo == "Silk Snare") { p.FusionName = "SilkSnare"; p.ArcStart = _playerPos; }
                if (_currentDualCombo == "Web Trap") p.FusionName = "WebTrap";
                _projectiles.Add(p);
            }
            if (isShango)
            {
                _trauma = MathF.Min(_trauma + 0.08f, 1f);
                for (int i = 0; i < 6; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * ((float)_rng.NextDouble() * 20f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 80f, ((float)_rng.NextDouble() - 0.5f) * 80f),
                        Life = 0.15f, MaxLife = 0.15f,
                        Color = new Color(220, 230, 255),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            } // end non-Katyusha else
            if (isKatyusha)
            {
                _trauma = MathF.Min(_trauma + 0.15f, 1f);
                // Big rocket smoke trail from launch
                for (int i = 0; i < 12; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                        Velocity = -dir * (50f + (float)_rng.NextDouble() * 60f) + new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, ((float)_rng.NextDouble() - 0.5f) * 40f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.7f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(180, 170, 160) : new Color(120, 110, 100),
                        Size = 4f + (float)_rng.NextDouble() * 4f,
                    });
                }
            }
        }
        else if (_loadout.Form == Form.Orbit)
        {
            // Caoilfhionn: click sends angel to mouse position for manual swoop
            if (_currentFusion == "Caoilfhionn")
            {
                if (_angelActive && _angel.DepartTimer <= 0)
                {
                    var a = _angel;
                    // Clamp target to 200px from player
                    Vector2 toMouse = _mouseWorld - _playerPos;
                    if (toMouse.Length() > 200f)
                        toMouse = Vector2.Normalize(toMouse) * 200f;
                    Vector2 clampedTarget = _playerPos + toMouse;
                    
                    a.SwoopStart = a.ActualPos;
                    a.SwoopTarget = clampedTarget;
                    a.SwoopTimer = 0.3f;
                    a.SwoopCooldown = 0.8f;
                    a.Returning = false;
                    _angel = a;
                }
                return;
            }
            if (_currentFusion == "Scathach")
            {
                if (_knightActive && _knight.DepartTimer <= 0 && _knight.WindupTimer <= 0 && _knight.SwingTimer <= 0)
                {
                    var k = _knight;
                    Vector2 toMouse = _mouseWorld - _playerPos;
                    if (toMouse.Length() > 200f)
                        toMouse = Vector2.Normalize(toMouse) * 200f;
                    Vector2 clampedTarget = _playerPos + toMouse;
                    
                    k.SwingStart = k.ActualPos;
                    k.SwingTarget = clampedTarget;
                    k.SwingAngle = MathF.Atan2(toMouse.Y, toMouse.X);
                    k.WindupTimer = 0.25f; // wind-up before travel
                    k.SwingCooldown = 1.5f;
                    k.Returning = false;
                    _knight = k;
                }
                return;
            }
            
            // Sambhogakaya: transcendent self-buff — rings of light, AoE silence + invulnerability
            if (_currentFusion == "Sambhogakaya")
            {
                _trauma = MathF.Min(_trauma + 0.2f, 1f);
                _lingerZones.Add(new LingerZone
                {
                    Position = _playerPos,
                    Radius = 70f,
                    Life = 2.5f,
                    MaxLife = 2.5f,
                    Damage = parms.BaseDamage * 0.6f,
                    TickTimer = 0f,
                    Color = new Color(255, 250, 230),
                    EssenceType = Essence.Hollow,
                    FusionTag = "Sambhogakaya",
                });
                // Brief invulnerability
                _iFrameTimer = MathF.Max(_iFrameTimer, 2.5f);
                // Burst of light particles
                for (int sp = 0; sp < 30; sp++)
                {
                    float a = (MathF.PI * 2f / 30) * sp;
                    float speed2 = 50f + (float)_rng.NextDouble() * 40f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * speed2,
                        Life = 0.6f + (float)_rng.NextDouble() * 0.3f,
                        MaxLife = 0.9f,
                        Color = (sp % 3) switch { 0 => new Color(255, 240, 180), 1 => Color.White, _ => new Color(200, 180, 255) },
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                return;
            }

            // Cap active orbiters at 8
            int activeOrbiters = 0;
            for (int j = 0; j < _projectiles.Count; j++)
                if (_projectiles[j].Alive && _projectiles[j].Params.OrbitSpeed > 0) activeOrbiters++;
            if (activeOrbiters >= 8) return;

            bool isSurtr = _currentFusion == "Surtr's Crown";
            bool isEventHorizon = _currentFusion == "Event Horizon";
            bool isMorrigan = _currentFusion == "Morrigan's Court";
            int orbCount = chargePercent >= 0.8f ? 4 : chargePercent >= 0.3f ? 2 : 1;
            if (isSurtr) orbCount = MathHelper.Max(orbCount, 3);
            if (isEventHorizon) orbCount = MathHelper.Max(orbCount, 3);
            if (isMorrigan) orbCount = MathHelper.Max(orbCount, 3); // three phantom crows
            float startAngle = MathF.Atan2(dir.Y, dir.X);
            for (int i = 0; i < orbCount; i++)
            {
                float angle = startAngle + (MathF.PI * 2f / orbCount) * i;
                Vector2 offset = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * parms.OrbitRadius;
                var p = new Projectile(_playerPos + offset, Vector2.Zero, parms);
                p.OrbitAngle = angle;
                if (isSurtr) { p.Size = 8f; p.Lifetime = 6f; }
                if (isEventHorizon) { p.Lifetime = 5f; }
                if (isMorrigan) { p.Size = 7f; p.Lifetime = 5f; p.FusionName = "Morrigan's Court"; }
                _projectiles.Add(p);
            }
        }
        else if (_loadout.Form == Form.Chain)
        {
            bool isIndra = _currentFusion == "Indra's Arrow";
            bool isChronos = _currentFusion == "Chronos' Chain";
            bool isSerpent = _currentFusion == "Serpent Mercury";
            bool isZeus = _currentFusion == "Zeus in Chains";
            if (chargePercent >= 0.3f)
                parms.MaxChainTargets = (int)(parms.MaxChainTargets * (1f + chargePercent));
            if (isIndra)
            {
                parms.Bounces = true;
                parms.MaxBounces = 3;
                parms.MaxChainTargets += 4;
                parms.Speed *= 1.2f;
            }
            if (isChronos)
            {
                parms.MaxChainTargets += 4; // hits everything
                parms.StasisDuration = 2.5f; // long freeze (Chronomage from CoTM)
                parms.StasisRadius = 50f; // freeze nearby enemies at each jump point
                parms.Speed *= 0.8f; // slower, more deliberate — time crawl
            }
            if (isSerpent)
            {
                parms.MaxChainTargets += 3;
                parms.LingerDuration = 4f; // poison trail per enemy hit
                parms.LingerRadius = 20f;
                parms.BaseDamage *= 0.8f; // low direct damage, DoT is the point
            }
            if (isZeus)
            {
                parms.MaxChainTargets += 5; // chains to many targets
                parms.StasisDuration = 1.8f; // shorter than Chronos but still meaningful
                parms.StasisRadius = 35f;
                parms.Speed *= 1.3f; // lightning is fast
                parms.BaseDamage *= 0.6f; // low direct, tether damage is the payoff
            }
            var vel = dir * parms.Speed;
            var p = new Projectile(_playerPos, vel, parms);
            if (isSerpent) p.FusionName = "SerpentMercury";
            if (isZeus) p.FusionName = "ZeusChain";
            _projectiles.Add(p);
            if (isIndra)
            {
                // Initial lightning flash
                _trauma = MathF.Min(_trauma + 0.1f, 1f);
                for (int i = 0; i < 8; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * ((float)_rng.NextDouble() * 30f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 100f, ((float)_rng.NextDouble() - 0.5f) * 100f),
                        Life = 0.15f, MaxLife = 0.15f,
                        Color = new Color(255, 240, 60),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            if (isChronos)
            {
                // Chronos: clock-like void particles — expanding ring of time fragments
                _trauma = MathF.Min(_trauma + 0.08f, 1f);
                for (int i = 0; i < 12; i++)
                {
                    float a = (MathF.PI * 2f / 12) * i; // clock positions
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 60f,
                        Life = 0.3f + (float)_rng.NextDouble() * 0.2f,
                        MaxLife = 0.5f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(160, 200, 230) : new Color(100, 140, 180),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            if (isZeus)
            {
                // Zeus: thunderbolt flash + crackling launch
                _trauma = MathF.Min(_trauma + 0.15f, 1f);
                for (int i = 0; i < 10; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 60f + (float)_rng.NextDouble() * 80f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos + dir * ((float)_rng.NextDouble() * 20f),
                        Velocity = new Vector2(MathF.Cos(a) * spd, MathF.Sin(a) * spd),
                        Life = 0.2f, MaxLife = 0.2f,
                        Color = _rng.NextDouble() > 0.3 ? new Color(140, 180, 255) : new Color(255, 255, 220),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
        }
        else if (_loadout.Form == Form.Seed)
        {
            // Seed fires at cursor position, clamped to max range
            Vector2 toMouse = mousePos - _playerPos;
            float maxRange = chargePercent >= 0.3f ? 150f + 100f * chargePercent : 150f;
            if (toMouse.Length() > maxRange) { toMouse.Normalize(); toMouse *= maxRange; }
            Vector2 seedPos = _playerPos + toMouse;
            // Clamp seed out of walls
            if (_screenWalls.TryGetValue(_currentScreen, out var seedWalls))
            {
                foreach (var wall in seedWalls)
                {
                    if (seedPos.X > wall.Left && seedPos.X < wall.Right && seedPos.Y > wall.Top && seedPos.Y < wall.Bottom)
                    {
                        // Push to nearest edge
                        float dL = seedPos.X - wall.Left, dR = wall.Right - seedPos.X;
                        float dT = seedPos.Y - wall.Top, dB = wall.Bottom - seedPos.Y;
                        float min = MathF.Min(MathF.Min(dL, dR), MathF.Min(dT, dB));
                        if (min == dL) seedPos.X = wall.Left - 4f;
                        else if (min == dR) seedPos.X = wall.Right + 4f;
                        else if (min == dT) seedPos.Y = wall.Top - 4f;
                        else seedPos.Y = wall.Bottom + 4f;
                    }
                }
            }
            if (chargePercent >= 0.3f)
            {
                parms.LingerRadius *= 1f + chargePercent;
            }
            
            bool isYggdrasil = _currentFusion == "Yggdrasil's Root";
            if (isYggdrasil)
            {
                // Plant the World Tree — large stationary entity that whips vines + heals
                var zone = new LingerZone
                {
                    Position = seedPos,
                    Radius = 30f,
                    Damage = parms.BaseDamage * 0.5f,
                    Life = 5f,
                    MaxLife = 5f,
                    Color = new Color(60, 180, 60),
                    IsPillar = false,
                    FusionTag = "Yggdrasil",
                    VineTimer = 0f,
                };
                _lingerZones.Add(zone);
                // Sprouting particles
                for (int i = 0; i < 20; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = seedPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, 5f),
                        Velocity = new Vector2(MathF.Cos(a) * 20f, -40f - (float)_rng.NextDouble() * 60f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.4f,
                        MaxLife = 0.8f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(60, 180, 60) : new Color(30, 120, 30),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.08f, 1f);
            }
            else if (_currentFusion == "Portal to Hell")
            {
                // Fire portal — contact damage zone + spawns imp minions
                _lingerZones.Add(new LingerZone
                {
                    Position = seedPos, Radius = 25f, Damage = parms.BaseDamage * 0.4f,
                    Life = 4f, MaxLife = 4f, TickTimer = 0f,
                    Color = new Color(200, 40, 20), EssenceType = Essence.Cinder,
                    FusionTag = "HellPortal", VineTimer = 0.5f,
                });
                // Spawn 3 imp minions (small possessed enemies)
                for (int imp = 0; imp < 3; imp++)
                {
                    float a = (MathF.PI * 2f / 3) * imp;
                    Vector2 spawnPos = seedPos + new Vector2(MathF.Cos(a), MathF.Sin(a)) * 15f;
                    var enemy = new Enemy(spawnPos, 20f) { Size = 8f, Speed = 120f, BaseColor = new Color(200, 60, 30) };
                    enemy.Possessed = true;
                    enemy.PossessTimer = 4f;
                    _enemies.Add(enemy); _enemyById[enemy.Id] = enemy;
                }
                // Fire eruption particles
                for (int i = 0; i < 15; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    _particles.Add(new Particle
                    {
                        Position = seedPos, Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 60f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.7f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(255, 80, 20) : new Color(255, 200, 40),
                        Size = 3f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.15f, 1f);
            }
            else if (_currentFusion == "Portal to Heaven")
            {
                // Holy portal — spawns cherub familiars that fire homing bolts
                _lingerZones.Add(new LingerZone
                {
                    Position = seedPos, Radius = 25f, Damage = parms.BaseDamage * 0.2f,
                    Life = 4f, MaxLife = 4f, TickTimer = 0f,
                    Color = new Color(220, 230, 255), EssenceType = Essence.Hollow,
                    FusionTag = "HeavenPortal", VineTimer = 0.8f,
                });
                // Holy light particles
                for (int i = 0; i < 15; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = seedPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -50f - (float)_rng.NextDouble() * 40f),
                        Life = 0.5f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.8f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(240, 245, 255) : new Color(200, 220, 255),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
            }
            else if (_currentFusion == "Nikola's Coil")
            {
                // Tesla coil turret — periodic chain lightning to nearby enemies
                _lingerZones.Add(new LingerZone
                {
                    Position = seedPos, Radius = 15f, Damage = parms.BaseDamage * 0.3f,
                    Life = 5f, MaxLife = 5f, TickTimer = 0f,
                    Color = new Color(255, 240, 60), EssenceType = Essence.Pulse,
                    FusionTag = "Tesla", VineTimer = 0f,
                });
                // Electric spark burst on placement
                SpawnExplosion(seedPos, new Color(255, 240, 60), 10, 0.3f, 10f);
                _trauma = MathF.Min(_trauma + 0.08f, 1f);
            }
            else if (_currentFusion == "Bouncing Betty")
            {
                // Proximity mine — seed sits, explodes when enemy comes near
                var p = new Projectile(seedPos, Vector2.Zero, parms);
                p.FusionName = "BouncingBetty";
                p.Lifetime = 8f; // long-lived mine
                p.Size = 6f;
                _projectiles.Add(p);
                SpawnExplosion(seedPos, new Color(220, 220, 210), 6, 0.2f, 5f);
            }
            else if (_currentFusion == "Medusa's Garden")
            {
                // Petrification zone — long stasis + bone damage when it expires
                _lingerZones.Add(new LingerZone
                {
                    Position = seedPos, Radius = 35f, Damage = parms.BaseDamage * 0.3f,
                    Life = 4f, MaxLife = 4f, TickTimer = 0f,
                    Color = new Color(160, 170, 150), EssenceType = Essence.Bone,
                    FusionTag = "Medusa", VineTimer = 0f,
                });
                // Stone particles
                for (int i = 0; i < 10; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = seedPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -20f - (float)_rng.NextDouble() * 30f),
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(140, 150, 130) : new Color(180, 180, 170),
                        Size = 2f + (float)_rng.NextDouble() * 3f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.06f, 1f);
            }
            else if (_currentFusion == "Saibaman")
            {
                // Plant a shadow creature that runs at enemies and self-destructs
                var enemy = new Enemy(seedPos, 30f) { Size = 10f, Speed = 140f, BaseColor = new Color(80, 160, 40) };
                enemy.Possessed = true;
                enemy.PossessTimer = 5f;
                enemy.FusionTag = "Saibaman"; // will self-destruct on contact
                _enemies.Add(enemy); _enemyById[enemy.Id] = enemy;
                // Dark green sprout particles
                for (int i = 0; i < 12; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = seedPos, Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 40f, -30f - (float)_rng.NextDouble() * 40f),
                        Life = 0.3f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(60, 140, 30) : new Color(120, 40, 160),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
            else if (_currentFusion == "Grave Call")
            {
                // Plant a grave marker — linger zone that grabs enemies
                _lingerZones.Add(new LingerZone
                {
                    Position = seedPos, Radius = 30f, Damage = parms.BaseDamage * 0.6f,
                    Life = 8f, MaxLife = 8f, TickTimer = 0f,
                    Color = new Color(160, 140, 110), EssenceType = Essence.Bone,
                    FusionTag = "GraveCall", VineTimer = 0f,
                });
                // Grave eruption particles
                for (int i = 0; i < 15; i++)
                {
                    _particles.Add(new Particle
                    {
                        Position = seedPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, 0),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, -40f - (float)_rng.NextDouble() * 40f),
                        Life = 0.4f + (float)_rng.NextDouble() * 0.3f, MaxLife = 0.7f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(100, 80, 50) : new Color(140, 120, 80),
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
                _trauma = MathF.Min(_trauma + 0.1f, 1f);
            }
            else
            {
                var seed = new Projectile(seedPos, Vector2.Zero, parms);
                // Arc trajectory: seed flies from player to target
                float dist = Vector2.Distance(_playerPos, seedPos);
                seed.ArcStart = _playerPos;
                seed.ArcTarget = seedPos;
                seed.ArcDuration = 0.25f + dist / 600f; // faster for close, ~0.5s at max range
                seed.Position = _playerPos; // start at player
                _projectiles.Add(seed);
                // Launch particles
                for (int lp = 0; lp < 4; lp++)
                {
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = dir * 60f + new Vector2(((float)_rng.NextDouble() - 0.5f) * 30f, ((float)_rng.NextDouble() - 0.5f) * 30f),
                        Life = 0.15f, MaxLife = 0.15f,
                        Color = new Color(parms.Color.R, parms.Color.G, parms.Color.B) * 0.6f,
                        Size = 2f,
                    });
                }
            }
        }
        else
        {
            var vel = dir * parms.Speed;
            var p = new Projectile(_playerPos, vel, parms);
            if (_currentFusion == "Dragon's Teeth")
            {
                p.FusionName = "DragonTooth";
                p.Size = 8f; // big fang
                p.Params.BaseDamage *= 1.3f;
            }
            if (_currentFusion == "Gae Bolg")
            {
                p.FusionName = "GaeBolg";
                p.Params.Speed *= 1.5f; // fast spear throw
                p.Velocity = dir * p.Params.Speed;
                p.Params.BaseDamage *= 1.5f;
                p.Params.Size = 5f;
                p.Params.Piercing = false; // impales first target
            }
            if (_currentFusion == "Fire-flaught Hasp") p.FusionName = "FireflaughtHasp";
            if (_currentFusion == "Graveyard") p.FusionName = "Graveyard";
            if (_currentFusion == "Ifrit's Fury") p.FusionName = "IfritsFury";
            if (_currentFusion == "Raijin's Drum") p.FusionName = "RaijinsDrum";
            if (_currentFusion == "Raiju") p.FusionName = "Raiju";
            if (_currentFusion == "Fossil")
            {
                p.FusionName = "Fossil";
                p.Velocity = dir * 200f; // slow roll
            }
            // Prominence: cursor-anchored growing sun — stationary, skip normal bolt
            if (_currentFusion == "Prominence")
            {
                var sunParms = parms;
                sunParms.IsStationary = true;
                sunParms.BloomGrowRate = 2.5f;
                sunParms.BloomMaxScale = 3f;
                sunParms.Size = 6f;
                sunParms.Lifetime = 3f;
                var sun = new Projectile(_mouseWorld, Vector2.Zero, sunParms);
                sun.FusionName = "Prominence";
                sun.Size = 6f;
                sun.Params.IsStationary = true;
                _projectiles.Add(sun);
                return;
            }
            // BE combo FusionName tags for non-plant combos
            if (_currentDualCombo == "Wildfire") p.FusionName = "Wildfire";
            if (_currentDualCombo == "Ball Lightning") { p.FusionName = "BallLightning"; _ballLightningArcTimer = 0f; }
            if (_currentDualCombo == "Chain Burst") p.FusionName = "ChainBurst";
            _projectiles.Add(p);
        }
    }

    private void SpawnShatterDeferred(Projectile parent, List<Projectile> target)
    {
        // Dragon's Teeth: spawn skeleton soldiers instead of fragments
        // Chain Burst: homing shatter fragments
        if (parent.FusionName == "ChainBurst")
        {
            var cbParms = parent.Params;
            cbParms.ShatterCount = 0;
            cbParms.Piercing = false;
            cbParms.BaseDamage *= 0.4f;
            int cbCount = 6;
            for (int i = 0; i < cbCount; i++)
            {
                float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                float speed = 180f + (float)_rng.NextDouble() * 80f;
                var vel = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed;
                var frag = new Projectile(parent.Position, vel, cbParms);
                frag.Lifetime = 0.8f;
                frag.Size = parent.Size * 0.5f;
                frag.FusionName = "ChainBurstFrag";
                frag.Params.Color = new EssenceColor(80, 160, 255);
                // Find nearest enemy for homing
                float bestDist = float.MaxValue;
                int bestId = -1;
                for (int e = 0; e < _enemies.Count; e++)
                {
                    if (!_enemies[e].Alive) continue;
                    float d = Vector2.Distance(parent.Position, _enemies[e].Position);
                    if (d < bestDist) { bestDist = d; bestId = _enemies[e].Id; }
                }
                if (bestId >= 0)
                {
                    frag.HomingTargetId = bestId;
                    frag.HomingStrength = 8f;
                }
                target.Add(frag);
            }
            SpawnExplosion(parent.Position, new Color(80, 160, 255), 10, 0.3f, 10f);
            return;
        }

        if (parent.FusionName == "DragonTooth")
        {
            int skeletonCount = 3;
            for (int s = 0; s < skeletonCount; s++)
            {
                float angle = (MathF.PI * 2f / skeletonCount) * s + ((float)_rng.NextDouble() - 0.5f) * 0.5f;
                Vector2 spawnPos = parent.Position + new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * 12f;
                var skeleton = new Enemy(spawnPos, 25f) { Size = 12f, Speed = 100f, BaseColor = new Color(200, 200, 190) };
                skeleton.Possessed = true;
                skeleton.PossessTimer = 6f;
                skeleton.FusionTag = "Skeleton";
                _enemies.Add(skeleton); _enemyById[skeleton.Id] = skeleton;
            }
            // Bone burst particles
            for (int p = 0; p < 12; p++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = parent.Position,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (50f + (float)_rng.NextDouble() * 60f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.2f, MaxLife = 0.5f,
                    Color = _rng.NextDouble() > 0.5 ? new Color(220, 220, 210) : new Color(180, 180, 170),
                    Size = 2f + (float)_rng.NextDouble() * 3f,
                });
            }
            SpawnExplosion(parent.Position, new Color(220, 220, 210), 8, 0.3f, 12f);
            _trauma = MathF.Min(_trauma + 0.1f, 1f);
            return;
        }

        var parms = parent.Params;
        int count = parms.ShatterCount;
        bool isVesuvius = _currentFusion == "Vesuvius";
        if (isVesuvius) count = 8; // more fragments
        parms.ShatterCount = 0;
        parms.Piercing = false;
        parms.BaseDamage *= isVesuvius ? 0.5f : 0.4f;
        for (int i = 0; i < count; i++)
        {
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float speed = (isVesuvius ? 200f : 150f) + (float)_rng.NextDouble() * 100f;
            var vel = new Vector2(MathF.Cos(angle) * speed, MathF.Sin(angle) * speed);
            var frag = new Projectile(parent.Position, vel, parms);
            frag.Lifetime = isVesuvius ? 0.7f : 0.5f;
            frag.Size = parent.Size * (isVesuvius ? 0.6f : 0.5f);
            // Vesuvius: fragments get linger so they leave fire on death
            if (isVesuvius)
            {
                frag.Params.LingerDuration = 1.2f;
                frag.Params.LingerRadius = 15f;
            }
            target.Add(frag);
        }
        // Vesuvius: big fire explosion at shatter point
        if (isVesuvius)
        {
            for (int i = 0; i < 10; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = parent.Position,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (50f + (float)_rng.NextDouble() * 100f),
                    Life = 0.3f + (float)_rng.NextDouble() * 0.3f,
                    MaxLife = 0.6f,
                    Color = _rng.NextDouble() > 0.4 ? new Color(255, 100, 20) : new Color(255, 60, 10),
                    Size = 2f + (float)_rng.NextDouble() * 3f,
                });
            }
        }
    }

    private Vector2 GetEnemyPos(int id)
    {
        if (_enemyById.TryGetValue(id, out var e) && e.Alive) return e.Position;
        return _playerPos; // fallback
    }
    
    /// <summary>Returns true if a straight line from a to b is NOT blocked by any wall on the current screen.</summary>
    private bool HasLineOfSight(Vector2 a, Vector2 b)
    {
        if (!_screenWalls.TryGetValue(_currentScreen, out var losWalls) || losWalls.Count == 0)
            return true;
        Vector2 dir = b - a;
        float len = dir.Length();
        if (len < 1f) return true;
        dir /= len;
        foreach (var wall in losWalls)
        {
            float tMin = 0f, tMax = len;
            if (MathF.Abs(dir.X) > 0.001f)
            {
                float t1 = (wall.Left - a.X) / dir.X;
                float t2 = (wall.Right - a.X) / dir.X;
                if (t1 > t2) (t1, t2) = (t2, t1);
                tMin = MathF.Max(tMin, t1);
                tMax = MathF.Min(tMax, t2);
            }
            else if (a.X < wall.Left || a.X > wall.Right) continue;
            if (MathF.Abs(dir.Y) > 0.001f)
            {
                float t1 = (wall.Top - a.Y) / dir.Y;
                float t2 = (wall.Bottom - a.Y) / dir.Y;
                if (t1 > t2) (t1, t2) = (t2, t1);
                tMin = MathF.Max(tMin, t1);
                tMax = MathF.Min(tMax, t2);
            }
            else if (a.Y < wall.Top || a.Y > wall.Bottom) continue;
            if (tMin <= tMax && tMin < len && tMax > 0) return false;
        }
        return true;
    }

