    private void RefreshCombo()
    {
        var fkey = (_loadout.Form, _loadout.Behavior, _loadout.Essence);
        if (_hasGrimoire && SpellFusions.TryGetValue(fkey, out var fusionName))
        {
            _currentFusion = fusionName;
            _currentDualCombo = null;
            _fusionFlashTimer = 2f;
            // Clear companions when switching fusions
            _gorgonSnakes.Clear();
            _angelActive = false;
            _knightActive = false;
            if (_discoveredCombos.Add(fusionName))
            {
                _comboDiscoveryTimer = 1.5f;
                _comboDiscoveryName = fusionName;
                _hitstopTimer = MathF.Max(_hitstopTimer, 0.12f);
                _trauma = MathF.Min(_trauma + 0.15f, 0.4f);
            }
            // Init Gorgon snakes
            if (fusionName == "Gorgon's Grasp")
            {
                for (int gs = 0; gs < 5; gs++)
                {
                    _gorgonSnakes.Add(new GorgonSnake
                    {
                        AngleOffset = (gs - 2) * 0.22f,
                        Phase = gs * 1.3f,
                        AttackTimer = 0.3f + gs * 0.15f,
                        StrikeTimer = 0f,
                        TargetId = -1,
                    });
                }
            }
            // Init Caoilfhionn angel — prepared but NOT active until first click
            if (fusionName == "Caoilfhionn")
            {
                _angelActive = false;
                _angel = new AngelGuardian
                {
                    OrbitAngle = 0f,
                    OrbitSpeed = 1.5f,
                    SwoopTimer = 0f,
                    SwoopCooldown = 0.5f,
                    TargetId = -1,
                    IdleTime = 0f,
                    Returning = false,
                    ReturnTimer = 0f,
                    SwoopsLeft = 5,
                    DepartTimer = 0f,
                    ActualPos = _playerPos + new Vector2(60f, 0f),
                    Velocity = Vector2.Zero,
                };
                _angelTime = 0f;
            }
            // Init Scáthach knight — prepared but NOT active until first click
            if (fusionName == "Scathach")
            {
                _knightActive = false;
                _knight = new ShadowKnight
                {
                    OrbitAngle = MathF.PI,
                    OrbitSpeed = 1.0f,
                    SwingTimer = 0f,
                    SwingCooldown = 0.8f,
                    SwingAngle = 0f,
                    IdleTime = 0f,
                    Returning = false,
                    ReturnTimer = 0f,
                    SwingsLeft = 4,
                    DepartTimer = 0f,
                    ActualPos = _playerPos + new Vector2(-70f, 0f),
                    Velocity = Vector2.Zero,
                    WindupTimer = 0f,
                };
                _knightTime = 0f;
            }
        }
        else
        {
            _currentFusion = null;
            _gorgonSnakes.Clear();
            _angelActive = false;
            _knightActive = false;
            _shadowStitch.Active = false;
            _shadowStitch.ChainedIds = null;
            _currentDualCombo = null;
            int filled = _loadout.FilledSlots;
            if (filled == 2)
            {
                if (_loadout.Form != Form.None && _loadout.Behavior != Behavior.None && _loadout.Essence == Essence.None)
                    DualCombos_FB.TryGetValue((_loadout.Form, _loadout.Behavior), out _currentDualCombo);
                else if (_loadout.Form != Form.None && _loadout.Behavior == Behavior.None && _loadout.Essence != Essence.None)
                    DualCombos_FE.TryGetValue((_loadout.Form, _loadout.Essence), out _currentDualCombo);
                else if (_loadout.Form == Form.None && _loadout.Behavior != Behavior.None && _loadout.Essence != Essence.None)
                    DualCombos_BE.TryGetValue((_loadout.Behavior, _loadout.Essence), out _currentDualCombo);
            }
            if (_currentDualCombo != null && !ImplementedDualCombos.Contains(_currentDualCombo))
                _currentDualCombo = null;
            if (_currentDualCombo != null)
            {
                _fusionFlashTimer = 2f;
                if (_discoveredCombos.Add(_currentDualCombo))
                {
                    _comboDiscoveryTimer = 1.5f;
                    _comboDiscoveryName = _currentDualCombo;
                    _hitstopTimer = MathF.Max(_hitstopTimer, 0.12f);
                    _trauma = MathF.Min(_trauma + 0.15f, 0.4f);
                }
            }
        }
    }

    private void SpawnExplosion(Vector2 pos, Color color, int count, float life = 0.3f, float size = 3f)
    {
        for (int i = 0; i < count; i++)
        {
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float speed = 100f + (float)_rng.NextDouble() * 150f;
            _particles.Add(new Particle
            {
                Position = pos,
                Velocity = new Vector2(MathF.Cos(angle), MathF.Sin(angle)) * speed,
                Life = life,
                MaxLife = life,
                Color = color,
                Size = 2f + (float)_rng.NextDouble() * (size - 2f),
            });
        }
    }

    private void SpawnEtherDrops(Vector2 pos, bool isBoss)
    {
        // Liquid ether: 4-6 for normal, 10-12 for boss
        int liquidCount = isBoss ? 10 + _rng.Next(3) : 4 + _rng.Next(3);
        float liquidAmount = isBoss ? 12f : 6f;
        for (int i = 0; i < liquidCount; i++)
        {
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float speed = 40f + (float)_rng.NextDouble() * 80f;
            _etherDrops.Add(new EtherDrop
            {
                Position = pos,
                Velocity = new Vector2(MathF.Cos(angle) * speed, MathF.Sin(angle) * speed),
                Life = 8f, MaxLife = 8f,
                IsHard = false,
                Amount = liquidAmount,
                MagnetTimer = 0.3f + (float)_rng.NextDouble() * 0.2f, // slight scatter delay
            });
        }
        // Hard ether: 20% chance for normal, guaranteed for boss
        if (isBoss || _rng.NextDouble() < 0.2)
        {
            int hardCount = isBoss ? 2 + _rng.Next(2) : 1;
            for (int i = 0; i < hardCount; i++)
            {
                float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
                float speed = 30f + (float)_rng.NextDouble() * 50f;
                _etherDrops.Add(new EtherDrop
                {
                    Position = pos,
                    Velocity = new Vector2(MathF.Cos(angle) * speed, MathF.Sin(angle) * speed),
                    Life = 15f, MaxLife = 15f,
                    IsHard = true,
                    Amount = isBoss ? 5 : 1,
                    MagnetTimer = 0f,
                });
            }
        }
        
        // Clip drops: 8% chance from normals (small 25EP), bosses drop 1-2 medium (50EP)
        if (isBoss)
        {
            int clipCount = 1 + _rng.Next(2);
            for (int i = 0; i < clipCount; i++)
                SackAddClip(50);
            _floatingTexts.Add(new FloatingText
            {
                Position = pos + new Vector2(-15, -40),
                Text = $"+{clipCount} CLIP",
                Color = new Color(100, 200, 255),
                Life = 1.2f, MaxLife = 1.2f,
            });
        }
        else if (_rng.NextDouble() < 0.08)
        {
            SackAddClip(25);
            _floatingTexts.Add(new FloatingText
            {
                Position = pos + new Vector2(-10, -35),
                Text = "+CLIP",
                Color = new Color(100, 200, 255),
                Life = 1f, MaxLife = 1f,
            });
        }
    }
    
    private void DropOverflowToGround()
    {
        foreach (var item in _sackOverflow)
        {
            DropSackItemToGround(item);
            _floatingTexts.Add(new FloatingText
            {
                Position = _playerPos + new Vector2(-15, -25),
                Text = item.Type == SackItemType.Armor ? "DROPPED ARMOR" : "DROPPED",
                Color = new Color(200, 120, 80),
                Life = 1.5f, MaxLife = 1.5f,
            });
        }
        _sackOverflow.Clear(); _sackOverflowPos.Clear();
    }
    
    private void DropSackItemToGround(SackItem item)
    {
        if (item.Type == SackItemType.Armor)
        {
            float aAngle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float aSpeed = 30f + (float)_rng.NextDouble() * 60f;
            _etherDrops.Add(new EtherDrop
            {
                Position = _playerPos,
                Velocity = new Vector2(MathF.Cos(aAngle) * aSpeed, MathF.Sin(aAngle) * aSpeed),
                Life = 9999f, MaxLife = 9999f,
                IsHard = false, IsClip = false, IsArmor = true,
                ArmorDrop = item.Armor,
                Amount = 0,
                MagnetTimer = 0.8f, // pickup delay so it doesn't auto-collect
            });
            return;
        }
        int epVal = item.Type == SackItemType.LargeClip ? 100 :
                    item.Type == SackItemType.MediumClip ? 50 : 25;
        for (int c = 0; c < item.Count; c++)
        {
            float angle = (float)_rng.NextDouble() * MathF.PI * 2f;
            float speed = 30f + (float)_rng.NextDouble() * 60f;
            _etherDrops.Add(new EtherDrop
            {
                Position = _playerPos,
                Velocity = new Vector2(MathF.Cos(angle) * speed, MathF.Sin(angle) * speed),
                Life = 9999f, MaxLife = 9999f, // persist until room exit
                IsHard = false, IsClip = true,
                ClipEP = epVal,
                Amount = 0,
                MagnetTimer = 0.8f, // pickup delay
            });
        }
    }

    private void DamagePlayer(float amount, Vector2 sourcePos)
    {
        if (_iFrameTimer > 0) return; // invincible
        
        // Cocoon shield: absorb hits
        if (_cocoonHits > 0)
        {
            _cocoonHits--;
            _iFrameTimer = 0.3f;
            // Silk layer peeling particles
            for (int i = 0; i < 8; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                float r = 18f + (float)_rng.NextDouble() * 8f;
                _particles.Add(new Particle
                {
                    Position = _playerPos + new Vector2(MathF.Cos(a) * r, MathF.Sin(a) * r),
                    Velocity = new Vector2(MathF.Cos(a) * 50f, MathF.Sin(a) * 50f),
                    Life = 0.4f, MaxLife = 0.4f,
                    Color = new Color(200, 180, 220) * 0.7f,
                    Size = 2.5f,
                });
            }
            PlaySfx(_sfxHit, 0.2f);
            if (_cocoonHits <= 0)
            {
                // Burst: cocoon breaks, silk shrapnel in all directions
                for (int i = 0; i < 16; i++)
                {
                    float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                    float spd = 80f + (float)_rng.NextDouble() * 120f;
                    _particles.Add(new Particle
                    {
                        Position = _playerPos,
                        Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                        Life = 0.6f, MaxLife = 0.6f,
                        Color = _rng.NextDouble() > 0.5 ? new Color(220, 200, 240) : new Color(180, 160, 200),
                        Size = 3f + (float)_rng.NextDouble() * 2f,
                    });
                }
                // Damage nearby enemies on burst
                for (int ei = 0; ei < _enemies.Count; ei++)
                {
                    if (!_enemies[ei].Alive) continue;
                    if (Vector2.Distance(_playerPos, _enemies[ei].Position) < 80f)
                    {
                        _enemies[ei].Hp -= _cocoonBurstDamage;
                        _enemies[ei].SlowTimer = MathF.Max(_enemies[ei].SlowTimer, 2f);
                        _enemies[ei].HitFlash = 0.15f;
                        if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                        _damageNumbers.Add(new DamageNumber { Position = _enemies[ei].Position + new Vector2(0, -12), Amount = _cocoonBurstDamage, Timer = 0.8f, Color = new Color(200, 180, 220) });
                    }
                }
                _trauma = MathF.Min(_trauma + 0.2f, 0.5f);
                _floatingTexts.Add(new FloatingText
                {
                    Position = _playerPos + new Vector2(-20, -25),
                    Text = "BURST!",
                    Color = new Color(220, 200, 240),
                    Life = 1f, MaxLife = 1f,
                });
                _cocoonTimer = 0;
            }
            return;
        }
        
        // Elemental armor: Exoskeleton first-hit absorb
        if (_elementalArmor == ElementalArmorType.Bone && _exoskeletonShieldActive)
        {
            _exoskeletonShieldActive = false;
            // Bone crack particles
            for (int i = 0; i < 10; i++)
            {
                float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                _particles.Add(new Particle
                {
                    Position = _playerPos,
                    Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * (40f + (float)_rng.NextDouble() * 40f),
                    Life = 0.3f, MaxLife = 0.3f,
                    Color = new Color(200 + _rng.Next(40), 190 + _rng.Next(30), 170),
                    Size = 2f
                });
            }
            _iFrameTimer = 0.8f;
            return; // fully absorbed
        }
        
        // Elemental armor: damage reduction
        if (_elementalArmor == ElementalArmorType.Bone)
            amount *= 0.7f; // 30% reduction
        
        // Ward zone: 40% reduction while inside
        if (_wardZoneActive && Vector2.Distance(_playerPos, _wardZone.Position) < _wardZone.Radius)
            amount *= 0.6f;
        
        // Pulse static field: zap attacker
        if (_elementalArmor == ElementalArmorType.Pulse)
        {
            // Find nearest enemy to source and zap them
            for (int ei = 0; ei < _enemies.Count; ei++)
            {
                if (!_enemies[ei].Alive) continue;
                if (Vector2.Distance(sourcePos, _enemies[ei].Position) < 30f)
                {
                    _enemies[ei].Hp -= 8f;
                    _enemies[ei].Stagger += 15f;
                    if (_enemies[ei].Stagger >= _enemies[ei].MaxStagger)
                    {
                        _enemies[ei].Stagger = 0;
                        _enemies[ei].StaggerTimer = 0.5f;
                    }
                    if (_enemies[ei].Hp <= 0) _enemies[ei].Alive = false;
                    // Zap flash particles
                    for (int p = 0; p < 5; p++)
                    {
                        float a = (float)_rng.NextDouble() * MathF.PI * 2f;
                        _particles.Add(new Particle
                        {
                            Position = _enemies[ei].Position,
                            Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * 30f,
                            Life = 0.1f, MaxLife = 0.1f,
                            Color = new Color(150, 180, 255),
                            Size = 2f
                        });
                    }
                    break;
                }
            }
        }
        
        _playerHp -= amount;
        _iFrameTimer = 0.8f; // 0.8s invincibility
        _damageFlashTimer = 0.25f;
        _trauma = MathF.Min(_trauma + 0.25f, 1f);
        
        // Blood splatter from player
        Vector2 awayDir = _playerPos - sourcePos;
        if (awayDir.LengthSquared() > 0) awayDir.Normalize();
        else awayDir = Vector2.UnitY;
        for (int i = 0; i < 10; i++)
        {
            float spread = ((float)_rng.NextDouble() - 0.5f) * 1.4f;
            float a = MathF.Atan2(awayDir.Y, awayDir.X) + spread;
            float spd = 60f + (float)_rng.NextDouble() * 100f;
            _particles.Add(new Particle
            {
                Position = _playerPos,
                Velocity = new Vector2(MathF.Cos(a), MathF.Sin(a)) * spd,
                Life = 0.25f + (float)_rng.NextDouble() * 0.2f, MaxLife = 0.45f,
                Color = new Color(200 + _rng.Next(55), 0, 0),
                Size = 2f + (float)_rng.NextDouble() * 3f,
            });
        }
    }
    
    private void SpawnBoss()
    {
        // Don't kill existing enemies — they remain until they die naturally
        _enemyProjectiles.Clear(); // clear stale enemy shots for fairness
        
        // Determine drop type — cycles Form → Behavior → Essence
        int dropCycle = (_wave - 1) % 3;
        
        Vector2 pos = new Vector2(_arena.Center.X, _arena.Top + 60);
        float bossHp = (20f + _wave * 5f) * 2f;
        var boss = new Enemy(pos, bossHp);
        boss.Size = 28f; // 2× normal
        boss.Speed = 40f + _wave * 3f;
        
        // Boss type rotates: pick from the harder types
        EnemyType[] bossTypes = { EnemyType.GuardGargoyle, EnemyType.HollowPlate, EnemyType.TowerGuard };
        boss.Type = bossTypes[(_wave - 1) % bossTypes.Length];
        
        // Color indicates what it drops: Red=Form, Green=Behavior, Blue=Essence
        switch (dropCycle)
        {
            case 0: // Form
                boss.BaseColor = new Color(220, 60, 60); // red
                var forms = Enum.GetValues<Form>();
                boss.DropForm = forms[_rng.Next(1, forms.Length)];
                break;
            case 1: // Behavior
                boss.BaseColor = new Color(60, 220, 60); // green
                var behaviors = Enum.GetValues<Behavior>();
                boss.DropBehavior = behaviors[_rng.Next(1, behaviors.Length)];
                break;
            case 2: // Essence
                boss.BaseColor = new Color(60, 80, 220); // blue
                var essences = Enum.GetValues<Essence>();
                boss.DropEssence = essences[_rng.Next(1, essences.Length)];
                break;
        }
        
        // Boss-specific stat boosts on top of type defaults
        switch (boss.Type)
        {
            case EnemyType.GuardGargoyle:
                boss.AiStateTimer = 0.5f;
                break;
            case EnemyType.HollowPlate:
                boss.ShootTimer = 0.8f;
                break;
            case EnemyType.TowerGuard:
                boss.ShootTimer = 1f;
                break;
        }
        
        _enemies.Add(boss); _enemyById[boss.Id] = boss;
        _bossAlive = true;
        _bossId = boss.Id;
        _waveBannerTimer = 2.5f;
        _trauma = MathF.Min(_trauma + 0.3f, 1f); // dramatic entrance shake
    }
    
    // Tiamat's Garden: get maze walls for current screen
    // Uses recursive backtracker to generate a proper maze, seeded by screen index
    private List<(Rectangle rect, Color flower)> GetMazeWalls()
    {
        int cols = (_arena.Width - 20) / MazeCellSize; // ~28 columns
        int rows = (_arena.Height - 20) / MazeCellSize; // ~14 rows
        int ox = _arena.Left + 10; // offset from arena edge
        int oy = _arena.Top + 10;
        
        // Seeded maze generation (deterministic per screen)
        int seed = _currentScreen * 7919 + 42;
        var rng = new Random(seed);
        
        // Grid of cells, track which walls exist (right wall, bottom wall)
        bool[,] rightWall = new bool[cols, rows];
        bool[,] bottomWall = new bool[cols, rows];
        bool[,] visited = new bool[cols, rows];
        
        // Start with all walls
        for (int x = 0; x < cols; x++)
            for (int y = 0; y < rows; y++)
            { rightWall[x, y] = true; bottomWall[x, y] = true; }
        
        // Recursive backtracker
        var stack = new Stack<(int x, int y)>();
        stack.Push((0, 0));
        visited[0, 0] = true;
        
        while (stack.Count > 0)
        {
            var (cx, cy) = stack.Peek();
            var neighbors = new List<(int nx, int ny, int dx, int dy)>();
            if (cx > 0 && !visited[cx-1, cy]) neighbors.Add((cx-1, cy, -1, 0));
            if (cx < cols-1 && !visited[cx+1, cy]) neighbors.Add((cx+1, cy, 1, 0));
            if (cy > 0 && !visited[cx, cy-1]) neighbors.Add((cx, cy-1, 0, -1));
            if (cy < rows-1 && !visited[cx, cy+1]) neighbors.Add((cx, cy+1, 0, 1));
            
            if (neighbors.Count == 0) { stack.Pop(); continue; }
            
            var (nx, ny, dx, dy) = neighbors[rng.Next(neighbors.Count)];
            // Remove wall between current and neighbor
            if (dx == 1) rightWall[cx, cy] = false;
            else if (dx == -1) rightWall[nx, ny] = false;
            else if (dy == 1) bottomWall[cx, cy] = false;
            else if (dy == -1) bottomWall[cx, ny] = false;
            
            visited[nx, ny] = true;
            stack.Push((nx, ny));
        }
        
        // Remove ~30% of remaining walls for more open paths
        for (int x = 0; x < cols; x++)
            for (int y = 0; y < rows; y++)
            {
                if (rightWall[x, y] && rng.NextDouble() < 0.3) rightWall[x, y] = false;
                if (bottomWall[x, y] && rng.NextDouble() < 0.3) bottomWall[x, y] = false;
            }
        
        Color[] flowerColors = { new Color(200, 40, 60), new Color(220, 180, 40), new Color(140, 50, 180), new Color(40, 120, 200) };
        var walls = new List<(Rectangle, Color)>();
        
        // Get level geometry for this screen
        List<Rectangle> levelWalls = null;
        _screenWalls.TryGetValue(_currentScreen, out levelWalls);
        
        // Force maze walls adjacent to level geometry (hedges wrap around existing walls)
        if (levelWalls != null)
        {
            foreach (var lw in levelWalls)
            {
                // For each level wall edge, force the adjacent maze wall to exist
                // Left edge
                int cx = (lw.Left - ox) / MazeCellSize - 1;
                int cy1 = (lw.Top - oy) / MazeCellSize;
                int cy2 = (lw.Bottom - oy) / MazeCellSize;
                for (int y = Math.Max(0, cy1); y < Math.Min(rows, cy2 + 1); y++)
                    if (cx >= 0 && cx < cols) rightWall[cx, y] = true;
                // Right edge
                cx = (lw.Right - ox) / MazeCellSize;
                for (int y = Math.Max(0, cy1); y < Math.Min(rows, cy2 + 1); y++)
                    if (cx >= 0 && cx < cols - 1) rightWall[cx, y] = true;
                // Top edge
                int cy = (lw.Top - oy) / MazeCellSize - 1;
                int cx1 = (lw.Left - ox) / MazeCellSize;
                int cx2 = (lw.Right - ox) / MazeCellSize;
                for (int x = Math.Max(0, cx1); x < Math.Min(cols, cx2 + 1); x++)
                    if (cy >= 0 && cy < rows) bottomWall[x, cy] = true;
                // Bottom edge
                cy = (lw.Bottom - oy) / MazeCellSize;
                for (int x = Math.Max(0, cx1); x < Math.Min(cols, cx2 + 1); x++)
                    if (x >= 0 && x < cols && cy >= 0 && cy < rows - 1) bottomWall[x, cy] = true;
            }
        }
        
        for (int x = 0; x < cols; x++)
        {
            for (int y = 0; y < rows; y++)
            {
                int px = ox + x * MazeCellSize;
                int py = oy + y * MazeCellSize;
                
                if (x < cols - 1 && rightWall[x, y])
                {
                    var wallRect = new Rectangle(px + MazeCellSize - MazeWallThickness/2, py, MazeWallThickness, MazeCellSize);
                    // Skip if overlaps level geometry
                    bool overlaps = false;
                    if (levelWalls != null) foreach (var lw in levelWalls) if (lw.Intersects(wallRect)) { overlaps = true; break; }
                    if (!overlaps)
                        walls.Add((wallRect, flowerColors[(x + y * 3) % flowerColors.Length]));
                }
                if (y < rows - 1 && bottomWall[x, y])
                {
                    var wallRect = new Rectangle(px, py + MazeCellSize - MazeWallThickness/2, MazeCellSize, MazeWallThickness);
                    bool overlaps = false;
                    if (levelWalls != null) foreach (var lw in levelWalls) if (lw.Intersects(wallRect)) { overlaps = true; break; }
                    if (!overlaps)
                        walls.Add((wallRect, flowerColors[(x * 2 + y) % flowerColors.Length]));
                }
            }
        }
        // Post-process: extend hedge walls to close gaps with level geometry
        if (levelWalls != null)
        {
            for (int w = 0; w < walls.Count; w++)
            {
                var (rect, color) = walls[w];
                foreach (var lw in levelWalls)
                {
                    // If hedge is near a level wall (within MazeCellSize), extend to touch it
                    int gap;
                    // Hedge to the left of level wall
                    gap = lw.Left - rect.Right;
                    if (gap > 0 && gap <= MazeCellSize && rect.Top < lw.Bottom && rect.Bottom > lw.Top)
                    { rect.Width += gap; walls[w] = (rect, color); }
                    // Hedge to the right of level wall
                    gap = rect.Left - lw.Right;
                    if (gap > 0 && gap <= MazeCellSize && rect.Top < lw.Bottom && rect.Bottom > lw.Top)
                    { rect.X -= gap; rect.Width += gap; walls[w] = (rect, color); }
                    // Hedge above level wall
                    gap = lw.Top - rect.Bottom;
                    if (gap > 0 && gap <= MazeCellSize && rect.Left < lw.Right && rect.Right > lw.Left)
                    { rect.Height += gap; walls[w] = (rect, color); }
                    // Hedge below level wall
                    gap = rect.Top - lw.Bottom;
                    if (gap > 0 && gap <= MazeCellSize && rect.Left < lw.Right && rect.Right > lw.Left)
                    { rect.Y -= gap; rect.Height += gap; walls[w] = (rect, color); }
                }
            }
        }
        
        return walls;
    }
    
    // Reveal maze cells near a position
    private void RevealMazeNear(Vector2 center, float radius, bool charged = false)
    {
        var allWalls = GetMazeWalls();
        Color[] flowerColors = { new Color(200, 40, 60), new Color(220, 180, 40), new Color(140, 50, 180), new Color(40, 120, 200) };
        
        for (int i = 0; i < allWalls.Count; i++)
        {
            var (rect, flower) = allWalls[i];
            Vector2 wallCenter = new Vector2(rect.Center.X, rect.Center.Y);
            if (Vector2.Distance(center, wallCenter) > radius) continue;
            
            var cellKey = (rect.X, rect.Y);
            if (_revealedMazeCells.Contains(cellKey)) continue;
            
            if (Vector2.Distance(new Vector2(rect.Center.X, rect.Center.Y), _playerPos) < 30f) continue;
            
            _revealedMazeCells.Add(cellKey);
            float hp = charged ? HedgeHp * 1.5f : HedgeHp;
            float life = charged ? HedgeMaxLife * 1.3f : HedgeMaxLife;
            _hedgeWalls.Add(new HedgeWall
            {
                Rect = rect,
                Life = life, MaxLife = life,
                Hp = hp, MaxHp = hp,
                FlowerColor = flower,
                GrowTimer = 0.4f, GrowDuration = 0.4f,
                MazeCellX = rect.X, MazeCellY = rect.Y,
                Charged = charged,
            });
        }
    }
    
    private void SpawnEnemy()
    {
        Vector2 pos;
        int edge = _rng.Next(4);
        switch (edge)
        {
            case 0: pos = new Vector2(_rng.Next(_arena.Left, _arena.Right), _arena.Top); break;
            case 1: pos = new Vector2(_rng.Next(_arena.Left, _arena.Right), _arena.Bottom); break;
            case 2: pos = new Vector2(_arena.Left, _rng.Next(_arena.Top, _arena.Bottom)); break;
            default: pos = new Vector2(_arena.Right, _rng.Next(_arena.Top, _arena.Bottom)); break;
        }

        float hp = (20f + _wave * 5f) * 2.5f;
        var enemy = new Enemy(pos, hp);
        enemy.Speed = 60f + _wave * 5f;
        
        // Assign enemy type based on wave progression + randomness
        int typeRoll = _rng.Next(100);
        if (_wave <= 2)
        {
            enemy.Type = EnemyType.Squire; // early waves = all squires
        }
        else if (_wave <= 4)
        {
            enemy.Type = typeRoll < 50 ? EnemyType.Squire :
                         typeRoll < 75 ? EnemyType.GuardGargoyle :
                                         EnemyType.HollowPlate;
        }
        else
        {
            enemy.Type = typeRoll < 20 ? EnemyType.Squire :
                         typeRoll < 35 ? EnemyType.GuardGargoyle :
                         typeRoll < 50 ? EnemyType.HollowPlate :
                         typeRoll < 65 ? EnemyType.ShieldMaiden :
                         typeRoll < 80 ? EnemyType.HedgeSniper :
                                         EnemyType.TowerGuard;
        }
        
        // Type-specific stats & colors
        switch (enemy.Type)
        {
            case EnemyType.Squire:
                enemy.BaseColor = new Color(180, 160, 140); // dull armor
                enemy.ShootTimer = 1f + (float)_rng.NextDouble();
                // No element — generic foot soldier
                break;
            case EnemyType.GuardGargoyle:
                enemy.Hp *= 0.8f; enemy.MaxHp = enemy.Hp;
                enemy.Speed *= 0.5f; // slow base, fast hops
                enemy.BaseColor = new Color(120, 110, 130); // stone grey-purple
                enemy.Size = 16f;
                enemy.AiStateTimer = 0.5f;
                enemy.ElementType = Essence.Bone; // stone construct
                enemy.Weakness = Essence.Pulse; // shatter stone with force
                break;
            case EnemyType.HollowPlate:
                enemy.Hp *= 1.3f; enemy.MaxHp = enemy.Hp;
                enemy.Speed *= 0.9f;
                enemy.BaseColor = new Color(60, 60, 90); // dark steel
                enemy.Size = 16f;
                enemy.ShootTimer = 1f;
                enemy.ElementType = Essence.Dark; // ghostly haunted armor
                enemy.Weakness = Essence.Hollow; // void purges shadow
                break;
            case EnemyType.ShieldMaiden:
                enemy.Hp *= 1.5f; enemy.MaxHp = enemy.Hp;
                enemy.Speed *= 0.7f;
                enemy.TurnSpeed = 2.5f; // slow turn — easy to strafe
                enemy.BaseColor = new Color(180, 140, 100); // bronze
                enemy.Size = 15f;
                enemy.ElementType = Essence.Bone; // heavily armored
                enemy.Weakness = Essence.Cinder; // melt the armor
                break;
            case EnemyType.HedgeSniper:
                enemy.Hp *= 0.5f; enemy.MaxHp = enemy.Hp; // glass cannon
                enemy.Speed = 0; // stationary
                enemy.BaseColor = new Color(60, 100, 50); // hedge green
                enemy.Size = 12f;
                enemy.AiPhase = 0;
                enemy.AiStateTimer = 1f + (float)_rng.NextDouble() * 2f;
                enemy.ElementType = Essence.Sap; // living plant
                enemy.Weakness = Essence.Cinder; // burn the hedge
                break;
            case EnemyType.TowerGuard:
                enemy.Hp *= 2f; enemy.MaxHp = enemy.Hp; // tank
                enemy.Speed *= 0.4f;
                enemy.BaseColor = new Color(140, 140, 160); // heavy steel
                enemy.Size = 18f;
                enemy.ShootTimer = 1.5f;
                enemy.ElementType = Essence.Bone; // heavy armor
                enemy.Weakness = Essence.Pulse; // overload the plating
                break;
            case EnemyType.Maw:
                enemy.BaseColor = new Color(40, 10, 10);
                enemy.Size = 60f;
                enemy.ShootTimer = 3f;
                break;
            case EnemyType.Charger:
                enemy.ElementType = Essence.Bone; // bestial physical
                enemy.Weakness = Essence.Silk; // webs stop the charge
                break;
            case EnemyType.Gremlin:
                enemy.ElementType = Essence.Pulse; // chaotic energy
                enemy.Weakness = Essence.Dark; // fear calms the chaos
                break;
            case EnemyType.Wraith:
                enemy.ElementType = Essence.Dark; // shadow entity
                enemy.Weakness = Essence.Hollow; // void purges spectres
                break;
        }

        // Drop assignment — only boss drops components in wave mode
        // (regular enemies just drop shards)

        // Spawn animation per type
        switch (enemy.Type)
        {
            case EnemyType.Squire:
                enemy.SpawnDuration = 0.5f; // quick fade-in
                break;
            case EnemyType.GuardGargoyle:
                enemy.SpawnDuration = 0.8f; // drop from sky
                break;
            case EnemyType.HollowPlate:
                enemy.SpawnDuration = 0.7f; // assemble from ground
                break;
            case EnemyType.ShieldMaiden:
                enemy.SpawnDuration = 0.6f; // march in (fade)
                break;
            case EnemyType.HedgeSniper:
                enemy.SpawnDuration = 1.0f; // grow from ground (plant)
                break;
            case EnemyType.TowerGuard:
                enemy.SpawnDuration = 0.9f; // heavy drop from sky
                break;
            case EnemyType.Maw:
                enemy.SpawnDuration = 2.0f; // slow materialization from darkness
                break;
        }
        enemy.SpawnTimer = enemy.SpawnDuration;

        _enemies.Add(enemy); _enemyById[enemy.Id] = enemy;
    }

    /// <summary>
    /// Apply element counter multiplier to damage. Returns modified damage.
    /// Optionally spawns WEAKNESS!/RESIST floating text.
    /// </summary>
    private float ApplyElementCounter(Enemy enemy, float dmg, Essence attackEssence, bool showBark = true)
    {
        if (attackEssence == Essence.None) return dmg;
        bool isWeak = (enemy.Weakness != Essence.None && attackEssence == enemy.Weakness)
            || (enemy.Weakness2 != Essence.None && attackEssence == enemy.Weakness2);
        bool isResist = enemy.ElementType != Essence.None && attackEssence == enemy.ElementType;
        if (isWeak)
        {
            dmg *= 1.25f;
            if (showBark && _hasEtherSight)
                _floatingTexts.Add(new FloatingText {
                    Position = enemy.Position + new Vector2(0, -enemy.Size - 12),
                    Text = "WEAKNESS!", Color = new Color(255, 220, 60),
                    Life = 0.8f, MaxLife = 0.8f
                });
        }
        else if (isResist)
        {
            dmg *= 0.5f;
            if (showBark && _hasEtherSight)
                _floatingTexts.Add(new FloatingText {
                    Position = enemy.Position + new Vector2(0, -enemy.Size - 12),
                    Text = "RESIST", Color = new Color(140, 140, 140),
                    Life = 0.6f, MaxLife = 0.6f
                });
        }
        return dmg;
    }

    /// <summary>
    /// Apply element counter to stagger amount.
    /// </summary>
    private float ApplyElementCounterStagger(Enemy enemy, float stagger, Essence attackEssence)
    {
        if (attackEssence == Essence.None) return stagger;
        bool isWeak = (enemy.Weakness != Essence.None && attackEssence == enemy.Weakness)
            || (enemy.Weakness2 != Essence.None && attackEssence == enemy.Weakness2);
        bool isResist = enemy.ElementType != Essence.None && attackEssence == enemy.ElementType;
        if (isWeak) stagger *= 2f;
        else if (isResist) stagger *= 0.5f;
        return stagger;
    }

    private void TryDropComponent(Enemy enemy)
    {
        if (enemy.DropForm != Form.None && _unlockedForms.Add(enemy.DropForm))
        {
            _pickupNotifs.Add(new PickupNotif
            {
                Origin = enemy.Position,
                Text = enemy.DropForm.ToString(),
                TextColor = new Color(220, 80, 80), // red for form
                Timer = PickupNotif.TotalTime,
            });
        }
        if (enemy.DropBehavior != Behavior.None && _unlockedBehaviors.Add(enemy.DropBehavior))
        {
            _pickupNotifs.Add(new PickupNotif
            {
                Origin = enemy.Position + new Vector2(0, 14),
                Text = enemy.DropBehavior.ToString(),
                TextColor = new Color(80, 220, 80), // green for behavior
                Timer = PickupNotif.TotalTime,
            });
        }
        if (enemy.DropEssence != Essence.None && _unlockedEssences.Add(enemy.DropEssence))
        {
            _pickupNotifs.Add(new PickupNotif
            {
                Origin = enemy.Position + new Vector2(0, 28),
                Text = enemy.DropEssence.ToString(),
                TextColor = new Color(220, 220, 220), // white for essence
                Timer = PickupNotif.TotalTime,
            });
        }
    }

    private static T CycleEnum<T>(T current, HashSet<T> unlocked) where T : struct, Enum
    {
        var all = Enum.GetValues<T>();
        int idx = Array.IndexOf(all, current);
        for (int i = 1; i <= all.Length; i++)
        {
            var next = all[(idx + i) % all.Length];
            if (unlocked.Contains(next) || EqualityComparer<T>.Default.Equals(next, default))
                return next;
        }
        return current;
    }

    protected override void Draw(GameTime gameTime)
    {
        _currentGameTime = gameTime;

        // Begin render target capture for post-processing
        if (_postProcessEnabled)
            GraphicsDevice.SetRenderTarget(_sceneRT);

        GraphicsDevice.Clear(new Color(10, 10, 15));
        
        switch (_state)
        {
            case GameState.Intro:
                DrawIntro(gameTime);
                FinalizeFrame();
                return;
            case GameState.TitleScreen:
                DrawTitleScreen(gameTime);
                FinalizeFrame();
                return;
            case GameState.ModeSelect:
                DrawModeSelect(gameTime);
                FinalizeFrame();
                return;
            case GameState.GameOver:
                DrawGameOver(gameTime);
                FinalizeFrame();
                return;
            case GameState.DemoComplete:
                DrawDemoComplete(gameTime);
                FinalizeFrame();
                return;
        }
        
        // Tile Renderer mode — separate draw
        if (_gameMode == GameMode.TileRenderer)
        {
            DrawTileRenderer(gameTime);
            FinalizeFrame();
            return;
        }
        
        // Playing or Paused — draw game world
        var cameraMatrix = Matrix.CreateTranslation(_transitionOffset.X + _shakeX - _cameraOffset.X, _transitionOffset.Y + _shakeY - _cameraOffset.Y, 0);
        // BREAK Finisher zoom
        if (_finisherActive && _finisherZoom != 1f)
        {
            cameraMatrix = cameraMatrix *
                Matrix.CreateTranslation(-_finisherTarget.X, -_finisherTarget.Y, 0) *
                Matrix.CreateScale(_finisherZoom) *
                Matrix.CreateTranslation(_finisherTarget.X, _finisherTarget.Y, 0);
        }
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp, transformMatrix: cameraMatrix);

        // Cave transition animation
        if (_caveTransitionTimer > 0)
        {
            float t = _caveTransitionTimer / CaveTransitionDuration; // 1→0
            float progress = 1f - t; // 0→1
            
            if (_caveTransitionIn)
            {
                // Entering cave: player walks toward cave, shrinks, screen darkens
                Vector2 caveCenter = new Vector2(_caveEntrance.Center.X, _caveEntrance.Center.Y);
                _playerPos = Vector2.Lerp(caveCenter, _caveTransStartPos, t);
                _caveTransScale = MathHelper.Lerp(0.2f, 1f, t);
                DrawRect(0, 0, ScreenW, ScreenH, Color.Black * progress);
            }
            else
            {
                // Exiting cave: already on overworld, player grows from cave entrance to full size
                Vector2 cavePos = _caveTransStartPos; // cave entrance center
                _playerPos = Vector2.Lerp(_caveReturnPos, cavePos, t); // starts at cave, ends at return pos
                _caveTransScale = MathHelper.Lerp(1f, 0.2f, t); // starts small, grows
            }
        }
        else
        {
            _caveTransScale = 1f;
        }
        
        if (_inCave)
        {
            DrawCave();
        }
        else
        {
        // For scrolling rooms, fill extra area beyond arena bounds so camera scroll doesn't reveal clear color
        if (_arena.Height > ScreenH)
        {
            int pad = 200;
            DrawRect(_arena.Left - pad, _arena.Top - pad, _arena.Width + pad * 2, _arena.Height + pad * 2, new Color(10, 10, 15));
        }
        bool roomHasTiles = _roomTileData.ContainsKey(_currentScreen) || _roomTileMid.ContainsKey(_currentScreen) || _roomTileOverlay.ContainsKey(_currentScreen);
        if (!roomHasTiles)
            DrawRect(_arena.Left - 2, _arena.Top - 2, _arena.Width + 4, _arena.Height + 4, new Color(40, 40, 50));
        // Tiled floor (replaces flat color if tilesets loaded)
        if (_tsDungeon != null && !_inCave)
        {
            if (roomHasTiles)
                DrawTiledFloor(new Rectangle(0, 0, ScreenW, _arena.Bottom + 80)); // full screen for painted rooms
            else
                DrawTiledFloor(_arena); // just arena for auto-tiled
            // Mid layer — above floor, below player
            if (!_inCave) DrawTiledFloorMid();
        }
        else
            DrawRect(_arena.Left, _arena.Top, _arena.Width, _arena.Height, new Color(15, 15, 20));
        
        // Room 11: stone floor tiles to show the extended area
        if (_currentScreen == 11 && !roomHasTiles)
        {
            int ax = _arena.Left, ay = _arena.Top, aw = _arena.Width, ah = _arena.Height;
            for (int gy = 0; gy < ah; gy += 80)
                for (int gx = 0; gx < aw; gx += 80)
                {
                    bool checker = ((gx / 80) + (gy / 80)) % 2 == 0;
                    Color tileCol = checker ? new Color(18, 18, 24) : new Color(13, 13, 18);
                    DrawRect(ax + gx, ay + gy, 79, 79, tileCol);
                }
        }

        // Walls (skip flat rects when room has painted tile data)
        if (!roomHasTiles && _screenWalls.TryGetValue(_currentScreen, out var drawWalls))
        {
            foreach (var wall in drawWalls)
            {
                // Wall body
                DrawRect(wall.X, wall.Y, wall.Width, wall.Height, new Color(50, 48, 55));
                // Top edge highlight
                DrawRect(wall.X, wall.Y, wall.Width, 2, new Color(70, 68, 75));
                // Left edge highlight
                DrawRect(wall.X, wall.Y, 2, wall.Height, new Color(65, 63, 70));
                // Bottom shadow
                DrawRect(wall.X, wall.Y + wall.Height - 2, wall.Width, 2, new Color(30, 28, 35));
                // Right shadow
                DrawRect(wall.X + wall.Width - 2, wall.Y, 2, wall.Height, new Color(35, 33, 40));
            }
        }

        DrawCaveEntrance();
        if (!roomHasTiles) DrawRoomBorders();
        DrawAwakeningDoors();
        DrawRoom3Portal();
        DrawRoom7Shrine();
        DrawRoom8Lava();
        DrawRoom1Gauntlet();
        DrawRoom9Boss();
        DrawPellinore();
        if (_currentScreen == 8 || _currentScreen == 9) DrawImmolants();
        DrawUndine();
        
        // Merchant in Room 5
        if (_merchantActive && _currentScreen == 5 && !_inCave)
        {
            int mx = (int)_merchantPos.X;
            int my = (int)_merchantPos.Y;
            // Robe body
            DrawRect(mx - 8, my - 20, 16, 30, new Color(60, 40, 80));
            // Hood
            DrawRect(mx - 10, my - 28, 20, 12, new Color(50, 30, 70));
            // Face shadow
            DrawRect(mx - 5, my - 22, 10, 6, new Color(20, 15, 25));
            // Eyes
            DrawRect(mx - 3, my - 20, 2, 2, new Color(200, 180, 100));
            DrawRect(mx + 1, my - 20, 2, 2, new Color(200, 180, 100));
            // Interaction prompt
            if (Vector2.Distance(_playerPos, _merchantPos) < 50f)
            {
                DrawTextFallback(mx - 20, my - 40, "[E] Talk", new Color(200, 180, 100));
            }
            // Health bar (only show if damaged)
            if (_merchantHp < _merchantMaxHp)
            {
                int hbW = 30, hbH = 3;
                int hbX = (int)_merchantPos.X - hbW / 2;
                int hbY = (int)_merchantPos.Y - 30;
                DrawRect(hbX - 1, hbY - 1, hbW + 2, hbH + 2, Color.Black * 0.6f);
                float hpPct = _merchantHp / _merchantMaxHp;
                Color hpCol = hpPct > 0.5f ? new Color(60, 200, 60) : hpPct > 0.25f ? new Color(200, 200, 60) : new Color(200, 60, 60);
                DrawRect(hbX, hbY, (int)(hbW * hpPct), hbH, hpCol);
            }
        }
        DrawNPCs();
        DrawSigils();
        DrawEssenceCrystals();
        } // end else (!_inCave)

        // Player
        float ps = PlayerSize;
        int filledSlots = _loadout.FilledSlots;
        var resolvedParms = ProjectileParams.Resolve(_loadout);
        var essColor = new Color(resolvedParms.Color.R, resolvedParms.Color.G, resolvedParms.Color.B);
        Color playerColor;
        if (_currentFusion != null)
        {
            float pulse = (MathF.Sin((float)gameTime.TotalGameTime.TotalSeconds * 4f) + 1f) / 2f;
            playerColor = Color.Lerp(Color.White, new Color(255, 215, 0), pulse);
        }
        else if (filledSlots == 0) playerColor = new Color(100, 100, 100);
        else if (filledSlots == 1) playerColor = Color.White;
        else if (filledSlots == 2) playerColor = Color.White;
        else playerColor = essColor;

        if (_isDashing) playerColor = Color.Lerp(playerColor, Color.White, 0.7f);
        
        // iFrame flicker: player blinks rapidly during invincibility
        bool playerVisible = true;
        if (_iFrameTimer > 0)
        {
            playerVisible = ((int)(_iFrameTimer * 20f) % 2) == 0;
            if (playerVisible) playerColor = Color.Lerp(playerColor, new Color(255, 100, 100), 0.4f);
        }

        var mouse = Mouse.GetState();
        Vector2 aimDir = new Vector2(mouse.X, mouse.Y) - _playerPos;
        if (aimDir.LengthSquared() > 0) aimDir.Normalize();
        else aimDir = new Vector2(1, 0);

        if (playerVisible)
            DrawPlayer(_playerPos + new Vector2(0, -_jumpHeight), aimDir, playerColor, (float)gameTime.TotalGameTime.TotalSeconds, essColor, _jumpHeight);
        
        // Debug hitboxes (F1)
        if (_showHitboxes)
        {
            // Player collision box (green)
            int phbX = (int)(_playerPos.X - PlayerSize / 2);
            int phbY = (int)(_playerPos.Y - PlayerHitboxH / 2 + PlayerHitboxOffsetY);
            int phbS = (int)PlayerSize;
            int phbH = (int)PlayerHitboxH;
            DrawRect(phbX, phbY, phbS, 1, Color.Lime);
            DrawRect(phbX, phbY + phbH - 1, phbS, 1, Color.Lime);
            DrawRect(phbX, phbY, 1, phbH, Color.Lime);
            DrawRect(phbX + phbS - 1, phbY, 1, phbH, Color.Lime);
            // Center dot
            DrawRect((int)_playerPos.X - 1, (int)_playerPos.Y - 1, 3, 3, Color.Lime);
            
            // Wall collision rects
            if (_screenWalls.TryGetValue(_currentScreen, out var dbgWalls))
            {
                _screenWallOneWay.TryGetValue(_currentScreen, out var dbgOw);
                for (int di = 0; di < dbgWalls.Count; di++)
                {
                    var dw = dbgWalls[di];
                    int dow = (dbgOw != null && di < dbgOw.Count) ? dbgOw[di] : 0;
                    Color dc = (dow >= 1 && dow <= 4) ? Color.CornflowerBlue : (dow == 5 ? Color.Orange : Color.Red);
                    if (dow >= 1 && dow <= 4)
                    {
                        // Ledge: draw as a thick line on the edge
                        if (dow <= 2) // horizontal ledge
                        {
                            int ly = (dw.Height <= 24)
                                ? ((dow == 1) ? dw.Y : dw.Y + dw.Height - 1)
                                : dw.Y + dw.Height / 2;
                            DrawRect(dw.X, ly - 1, dw.Width, 3, dc);
                        }
                        else // vertical ledge
                        {
                            int lx = (dw.Width <= 24)
                                ? ((dow == 3) ? dw.X : dw.X + dw.Width - 1)
                                : dw.X + dw.Width / 2;
                            DrawRect(lx - 1, dw.Y, 3, dw.Height, dc);
                        }
                        string[] arrows = { "", "↑", "↓", "←", "→" };
                        DrawTextFallback(dw.X + 2, dw.Y + 2, arrows[dow], Color.CornflowerBlue, 0.5f);
                    }
                    else
                    {
                        DrawRect(dw.X, dw.Y, dw.Width, 1, dc);
                        DrawRect(dw.X, dw.Y + dw.Height - 1, dw.Width, 1, dc);
                        DrawRect(dw.X, dw.Y, 1, dw.Height, dc);
                        DrawRect(dw.X + dw.Width - 1, dw.Y, 1, dw.Height, dc);
                    }
                }
            }
            DrawTextFallback(4, ScreenH - 16, "F1: HITBOXES ON", Color.Lime * 0.6f, 0.5f);
        }
        
        // FG overlay tiles drawn AFTER player — tree canopies etc. obscure the player
        if (!_inCave) DrawTiledFloorFG();

        // Question mark when firing with empty loadout
        if (_questionMarkTimer > 0)
        {
            float qAlpha = MathHelper.Clamp(_questionMarkTimer / 0.3f, 0f, 1f);
            float qBob = MathF.Sin(_questionMarkTimer * 8f) * 2f;
            DrawTextFallback((int)_playerPos.X - 3, (int)(_playerPos.Y - _jumpHeight) - 50 + (int)qBob, "?", Color.Yellow * qAlpha);
        }

        // Wall push emotes
        if (_wallPushTime > 0)
        {
            int emoteX = (int)_playerPos.X;
            int emoteY = (int)(_playerPos.Y - _jumpHeight) - 55;
            
            if (_wallPushTime >= EmoteAngerTime)
            {
                // Anger symbol: ✕ shape that dilates and retracts
                float pulse = 1f + MathF.Sin(_angerPulse * 6f) * 0.3f; // 0.7-1.3 scale
                int sz = (int)(6 * pulse);
                Color angerCol = new Color(220, 50, 50);
                float alpha = MathHelper.Clamp((_wallPushTime - EmoteAngerTime) / 0.3f, 0f, 1f);
                // Draw cross/hash shape (manga anger vein)
                DrawRect(emoteX - sz, emoteY - 1, sz * 2, 2, angerCol * alpha);
                DrawRect(emoteX - 1, emoteY - sz, 2, sz * 2, angerCol * alpha);
                // Diagonal lines
                for (int d = -sz; d <= sz; d++)
                {
                    DrawRect(emoteX + d, emoteY + d, 2, 2, angerCol * alpha * 0.7f);
                    DrawRect(emoteX + d, emoteY - d, 2, 2, angerCol * alpha * 0.7f);
                }
            }
            else if (_wallPushTime >= EmoteScribbleTime)
            {
                // Scribble circle: animated wobbly ring
                float alpha = MathHelper.Clamp((_wallPushTime - EmoteScribbleTime) / 0.3f, 0f, 1f);
                Color scribCol = new Color(200, 200, 200) * alpha;
                float radius = 7f;
                float phase = _wallPushTime * 12f;
                int segments = 16;
                for (int s = 0; s < segments; s++)
                {
                    float a = (s / (float)segments) * MathF.PI * 2f;
                    float wobble = MathF.Sin(a * 3f + phase) * 2f;
                    float r = radius + wobble;
                    int px = emoteX + (int)(MathF.Cos(a) * r);
                    int py = emoteY + (int)(MathF.Sin(a) * r);
                    DrawRect(px, py, 2, 2, scribCol);
                }
            }
        }

        // Undine familiar
        DrawUndine();

        // Shield shape in front during bash
        if (_isDashing)
        {
            Vector2 shieldPos = _playerPos + _dashDir * (ps / 2 + 4);
            DrawRect((int)(shieldPos.X - 4), (int)(shieldPos.Y - 6), 8, 12, new Color(180, 200, 255));
        }

        // Pickup items
        if (!_hasWand && _gameMode != GameMode.Awakening)
        {
            float wandBob = MathF.Sin((float)gameTime.TotalGameTime.TotalSeconds * 3f) * 2f;
            int wx = (int)(_wandPickupPos.X - 2), wy = (int)(_wandPickupPos.Y - 7 + wandBob);
            DrawRect(wx - 1, wy - 1, 6, 16, new Color(80, 60, 20));
            DrawRect(wx, wy, 4, 14, new Color(255, 220, 80));
            DrawRect(wx - 1, wy, 6, 2, new Color(255, 255, 180));
        }
        if (!_hasShield && _gameMode != GameMode.Awakening)
        {
            float shieldBob = MathF.Sin((float)gameTime.TotalGameTime.TotalSeconds * 3f + 1f) * 2f;
            int sx = (int)(_shieldPickupPos.X - 6), sy = (int)(_shieldPickupPos.Y - 6 + shieldBob);
            DrawRect(sx, sy, 12, 14, new Color(40, 60, 120));
            DrawRect(sx + 1, sy + 1, 10, 12, new Color(80, 120, 200));
            DrawRect(sx + 4, sy + 3, 4, 4, new Color(200, 220, 255));
        }

        // Dash cooldown indicator
        if (_dashCooldown > 0)
        {
            int cdW = (int)(12 * (_dashCooldown / DashCooldownTime));
            DrawRect((int)(_playerPos.X - 6), (int)(_playerPos.Y + PlayerSize / 2 + 3), cdW, 2, new Color(100, 100, 255));
        }
        
        // Cocoon shield visual
        if (_cocoonHits > 0 && _cocoonTimer > 0)
        {
            float time = (float)gameTime.TotalGameTime.TotalSeconds;
            float breathe = 1f + 0.08f * MathF.Sin(time * 3f);
            float cocoonAlpha = MathHelper.Clamp(_cocoonTimer / 2f, 0f, 0.7f);
            Color silkCol = new Color(200, 180, 220);
            Color shimmer = new Color(230, 220, 245);
            int px = (int)_playerPos.X, py = (int)(_playerPos.Y - _jumpHeight);
            
            // Layered silk wrapping — one layer per remaining hit
            for (int layer = 0; layer < _cocoonHits; layer++)
            {
                float layerR = (14f + layer * 4f) * breathe;
                int segs = 12;
                for (int s = 0; s < segs; s++)
                {
                    float a = (MathF.PI * 2f / segs) * s + layer * 0.3f + time * (0.5f + layer * 0.2f);
                    float wobble = MathF.Sin(time * 4f + s * 1.5f + layer * 2f) * 2f;
                    int sx = px + (int)((layerR + wobble) * MathF.Cos(a));
                    int sy = py + (int)((layerR + wobble) * MathF.Sin(a));
                    // Thread strand connecting to next segment
                    float a2 = (MathF.PI * 2f / segs) * ((s + 1) % segs) + layer * 0.3f + time * (0.5f + layer * 0.2f);
                    float wobble2 = MathF.Sin(time * 4f + (s + 1) * 1.5f + layer * 2f) * 2f;
                    int sx2 = px + (int)((layerR + wobble2) * MathF.Cos(a2));
                    int sy2 = py + (int)((layerR + wobble2) * MathF.Sin(a2));
                    int midX = (sx + sx2) / 2, midY = (sy + sy2) / 2;
                    int w = Math.Max(Math.Abs(sx2 - sx), 1);
                    int h = Math.Max(Math.Abs(sy2 - sy), 1);
                    DrawRect(midX, midY, w, h, silkCol * (cocoonAlpha * (0.4f + layer * 0.1f)));
                }
            }
            
            // Glistening highlights
            for (int g = 0; g < 4; g++)
            {
                float ga = time * 5f + g * MathF.PI / 2f;
                float gr = 12f * breathe;
                int gx = px + (int)(MathF.Cos(ga) * gr);
                int gy = py + (int)(MathF.Sin(ga) * gr);
                float bright = MathF.Sin(time * 10f + g * 4f) > 0.5f ? 0.9f : 0.2f;
                DrawRect(gx, gy, 2, 2, shimmer * (cocoonAlpha * bright));
            }
            
            // Hit counter
            DrawTextFallback(px - 3, py - 22, _cocoonHits.ToString(), shimmer * cocoonAlpha);
        }

        // Gorgon's Grasp: draw procedural snakes behind player
        if (_currentFusion == "Gorgon's Grasp" && _gorgonSnakes.Count > 0)
        {
            Vector2 gAimDir = Vector2.Zero;
            var ms = Mouse.GetState();
            Vector2 mPos = new Vector2(ms.X, ms.Y);
            if (Vector2.DistanceSquared(mPos, _playerPos) > 1f)
            {
                gAimDir = mPos - _playerPos;
                gAimDir.Normalize();
            }
            
            for (int si = 0; si < _gorgonSnakes.Count; si++)
            {
                var snake = _gorgonSnakes[si];
                float behindAngle = MathF.Atan2(-gAimDir.Y, -gAimDir.X) + snake.AngleOffset;
                Vector2 snakeBase = _playerPos + new Vector2(MathF.Cos(behindAngle), MathF.Sin(behindAngle)) * 12f;
                
                int segments = 12;
                float segLen = 5f;
                // When striking, extend the last few segments forward (lunge)
                bool striking = snake.StrikeTimer > 0;
                float lungeExtend = striking ? 20f * (snake.StrikeTimer / 0.15f) : 0f; // 20px lunge, decays
                
                Vector2 prev = snakeBase;
                Vector2 lastSegDir = gAimDir;
                
                for (int seg = 0; seg < segments; seg++)
                {
                    float t = (float)(seg + 1) / segments;
                    Vector2 baseD = new Vector2(MathF.Cos(behindAngle), MathF.Sin(behindAngle));
                    Vector2 segDir = Vector2.Lerp(baseD, gAimDir, t * t);
                    if (segDir.LengthSquared() > 0) segDir.Normalize();
                    
                    Vector2 perp = new Vector2(-segDir.Y, segDir.X);
                    // Reduce slithering when striking
                    float slitherAmp = striking ? 1f : 4f;
                    float slither = MathF.Sin(_gorgonTime * 8f + snake.Phase + t * 6f) * slitherAmp * (1f - t * 0.5f);
                    
                    // Extra forward push on head segments during lunge
                    float extraLen = 0f;
                    if (striking && seg >= segments - 3)
                        extraLen = lungeExtend * ((float)(seg - (segments - 4)) / 3f);
                    
                    Vector2 pos = prev + segDir * (segLen + extraLen) + perp * slither;
                    
                    // Body width: thicker in middle, thinner at tail and head tip
                    float width = 2.5f + (1f - MathF.Abs(t - 0.55f)) * 3.5f;
                    // Color: dark green body, brighter toward head
                    Color segColor = Color.Lerp(new Color(35, 100, 35), new Color(50, 180, 50), t);
                    if (seg % 2 == 0) segColor = Color.Lerp(segColor, new Color(25, 70, 25), 0.3f);
                    // Flash red on strike
                    if (striking && seg >= segments - 2)
                        segColor = Color.Lerp(segColor, new Color(200, 60, 60), snake.StrikeTimer / 0.15f);
                    
                    int sw = (int)MathF.Max(Vector2.Distance(prev, pos), 1);
                    float segRot = MathF.Atan2(pos.Y - prev.Y, pos.X - prev.X);
                    int sh = (int)MathF.Max(width, 2);
                    _spriteBatch.Draw(_pixel, new Rectangle((int)prev.X, (int)prev.Y, sw, sh),
                        null, segColor, segRot, new Vector2(0, sh / 2f), SpriteEffects.None, 0);
                    
                    prev = pos;
                    lastSegDir = segDir;
                    
                    // Head on last segment
                    if (seg == segments - 1)
                    {
                        // Head diamond shape (slightly bigger)
                        int headSize = striking ? 8 : 6;
                        _spriteBatch.Draw(_pixel, new Rectangle((int)pos.X - headSize / 2, (int)pos.Y - headSize / 2, headSize, headSize),
                            null, striking ? new Color(200, 80, 80) : new Color(40, 160, 40),
                            segRot, new Vector2(headSize / 2f, headSize / 2f), SpriteEffects.None, 0);
                        // Eyes
                        Vector2 eyePerp = new Vector2(-lastSegDir.Y, lastSegDir.X);
                        Vector2 eye1 = pos + eyePerp * 2.5f + lastSegDir * 2f;
                        Vector2 eye2 = pos - eyePerp * 2.5f + lastSegDir * 2f;
                        _spriteBatch.Draw(_pixel, new Rectangle((int)eye1.X, (int)eye1.Y, 2, 2), new Color(255, 200, 0));
                        _spriteBatch.Draw(_pixel, new Rectangle((int)eye2.X, (int)eye2.Y, 2, 2), new Color(255, 200, 0));
                        // Open mouth when striking
                        if (striking)
                        {
                            Vector2 mouthPos = pos + lastSegDir * 4f;
                            _spriteBatch.Draw(_pixel, new Rectangle((int)mouthPos.X - 2, (int)mouthPos.Y - 2, 4, 3),
                                new Color(180, 30, 30));
                        }
                    }
                }
            }
        }

        // Draw Shadow Stitch chain (before projectiles so arm is behind)
        if (_shadowStitch.Active && _shadowStitch.ChainedIds != null)
        {
            Vector2 prev = _shadowStitch.AnchorPos;
            for (int c = 0; c < _shadowStitch.ChainedIds.Count; c++)
            {
                Vector2 epos = GetEnemyPos(_shadowStitch.ChainedIds[c]);
                Vector2 segDir = epos - prev;
                float segLen = segDir.Length();
                if (segLen < 1f) { prev = epos; continue; }
                segDir /= segLen;
                float segAngle = MathF.Atan2(segDir.Y, segDir.X);
                
                // Thick dark tendril between nodes
                int segs = Math.Max(1, (int)(segLen / 5f));
                for (int s = 0; s <= segs; s++)
                {
                    float t = (float)s / segs;
                    Vector2 pos = Vector2.Lerp(prev, epos, t);
                    float w = 6f + MathF.Sin(t * MathF.PI) * 4f; // thicker in middle
                    float wobble = MathF.Sin(_gorgonTime * 6f + t * 8f + c * 3f) * 3f;
                    Vector2 perp = new Vector2(-segDir.Y, segDir.X);
                    pos += perp * wobble;
                    
                    _spriteBatch.Draw(_pixel, pos, null, new Color(20, 6, 35) * 0.85f,
                        segAngle, new Vector2(0.5f, 0.5f), new Vector2(6f, w + 4f), SpriteEffects.None, 0);
                    _spriteBatch.Draw(_pixel, pos, null, new Color(40, 12, 60) * 0.9f,
                        segAngle, new Vector2(0.5f, 0.5f), new Vector2(5f, w), SpriteEffects.None, 0);
                }
                
                // Glow at each chained enemy
                _spriteBatch.Draw(_pixel, epos, null, new Color(70, 20, 100) * (0.3f + 0.1f * MathF.Sin(_gorgonTime * 4f)),
                    0f, new Vector2(0.5f, 0.5f), new Vector2(24f, 24f), SpriteEffects.None, 0);
                
                prev = epos;
            }
            
            // Draw seeking tendril if active
            if (_shadowStitch.Seeking)
            {
                Vector2 seekFrom = _shadowStitch.ChainedIds.Count > 0 ? GetEnemyPos(_shadowStitch.ChainedIds[^1]) : _shadowStitch.AnchorPos;
                Vector2 seekDir = _shadowStitch.SeekingTip - seekFrom;
                float seekLen = seekDir.Length();
                if (seekLen > 1f)
                {
                    seekDir /= seekLen;
                    float seekAngle = MathF.Atan2(seekDir.Y, seekDir.X);
                    int seekSegs = Math.Max(1, (int)(seekLen / 5f));
                    for (int s = 0; s <= seekSegs; s++)
                    {
                        float t = (float)s / seekSegs;
                        Vector2 pos = Vector2.Lerp(seekFrom, _shadowStitch.SeekingTip, t);
                        float w = 4f + MathF.Sin(t * MathF.PI) * 3f;
                        float wobble = MathF.Sin(_gorgonTime * 8f + t * 10f) * 2f;
                        Vector2 perp = new Vector2(-seekDir.Y, seekDir.X);
                        pos += perp * wobble;
                        
                        _spriteBatch.Draw(_pixel, pos, null, new Color(50, 15, 70) * (0.5f + t * 0.4f),
                            seekAngle, new Vector2(0.5f, 0.5f), new Vector2(5f, w + 2f), SpriteEffects.None, 0);
                    }
                    // Seeking tip glow
                    _spriteBatch.Draw(_pixel, _shadowStitch.SeekingTip, null, new Color(90, 30, 130) * 0.6f,
                        0f, new Vector2(0.5f, 0.5f), new Vector2(10f, 10f), SpriteEffects.None, 0);
                }
            }
        }

        // Caoilfhionn: draw guardian angel
        if (_angelActive && _currentFusion == "Caoilfhionn")
        {
            var a = _angel;
            float time = _angelTime;
            Vector2 angelPos;
            float facingAngle = 0f; // angle the angel faces (toward swoop target or orbit tangent)
            bool facingLeft;
            float departAlpha = 1f; // for fading during departure
            
            if (a.DepartTimer > 0)
            {
                // Departing — ascend upward and fade
                float departTotal = 1.5f;
                float dt2 = 1f - (a.DepartTimer / departTotal);
                departAlpha = 1f - dt2;
                float bob = MathF.Sin(time * 2.5f) * 3f;
                Vector2 orbitBase = _playerPos + new Vector2(MathF.Cos(a.OrbitAngle), MathF.Sin(a.OrbitAngle)) * 60f;
                angelPos = orbitBase + new Vector2(0, bob - dt2 * 80f); // rise upward
                facingLeft = false;
                facingAngle = -MathF.PI / 2f; // facing up
            }
            else if (a.SwoopTimer > 0)
            {
                // Swooping — lerp from start to target with ease-in
                float swoopTotal = 0.25f;
                float t = 1f - (a.SwoopTimer / swoopTotal);
                t = t * t; // ease-in (accelerate toward target)
                angelPos = Vector2.Lerp(a.SwoopStart, a.SwoopTarget, t);
                Vector2 toTarget = a.SwoopTarget - a.SwoopStart;
                facingAngle = MathF.Atan2(toTarget.Y, toTarget.X);
                facingLeft = toTarget.X < 0;
            }
            else if (a.Returning)
            {
                // Returning to orbit — lerp back
                float returnTotal = 0.3f;
                float t = 1f - (a.ReturnTimer / returnTotal);
                t = 1f - (1f - t) * (1f - t); // ease-out
                angelPos = Vector2.Lerp(a.SwoopTarget, a.ActualPos, t);
                facingLeft = (a.ActualPos.X - a.SwoopTarget.X) < 0;
                facingAngle = a.OrbitAngle;
            }
            else
            {
                // Orbiting — use smoothed actual position
                angelPos = a.ActualPos;
                // Face movement direction
                facingLeft = a.Velocity.X < 0;
                facingAngle = a.OrbitAngle;
            }
            
            int ax = (int)angelPos.X;
            int ay = (int)angelPos.Y;
            int flip = facingLeft ? -1 : 1;
            
            // Halo — golden ring above head
            float haloPulse = 0.7f + 0.3f * MathF.Sin(time * 4f);
            Color haloCol = new Color(255, 220, 100) * haloPulse * departAlpha;
            DrawRect(ax - 4, ay - 18, 8, 2, haloCol);
            DrawRect(ax - 5, ay - 17, 1, 2, haloCol * 0.6f);
            DrawRect(ax + 4, ay - 17, 1, 2, haloCol * 0.6f);
            
            // Wings — red, diagonal layout (upper-left + lower-right like ref image)
            float wingSpread = a.SwoopTimer > 0 ? 1.4f : 1f;
            float wingFlap = MathF.Sin(time * 5f) * 3f;
            Color wingBase = new Color(160, 35, 35) * departAlpha;
            Color wingMid = new Color(190, 50, 45) * departAlpha;
            Color wingTip = new Color(220, 80, 60) * departAlpha;
            Color wingEdge = new Color(120, 25, 25) * departAlpha;
            
            // Upper wing — goes up-left from shoulder
            {
                float wAngle = -2.2f + wingFlap * 0.05f; // mostly up-left
                int uwX = ax - 3;
                int uwY = ay - 10;
                // 4 feather segments radiating up-left
                for (int f = 0; f < 4; f++)
                {
                    float segAngle = wAngle + f * 0.15f;
                    float segLen = (8f + f * 5f) * wingSpread;
                    int sx = uwX + (int)(MathF.Cos(segAngle) * segLen);
                    int sy = uwY + (int)(MathF.Sin(segAngle) * segLen);
                    int w = 4 - f / 2; // taper
                    Color fc = f < 1 ? wingEdge : f < 3 ? wingBase : wingTip;
                    // Draw feather as filled rect from shoulder to tip
                    int rx = Math.Min(uwX, sx); int ry = Math.Min(uwY, sy);
                    int rw = Math.Max(Math.Abs(sx - uwX), w); int rh = Math.Max(Math.Abs(sy - uwY), w);
                    DrawRect(rx, ry, rw, rh, fc * 0.85f);
                }
                // Wing membrane fill
                DrawRect(uwX - (int)(14 * wingSpread), uwY - (int)(12 * wingSpread), (int)(16 * wingSpread), (int)(14 * wingSpread), wingMid * 0.5f);
            }
            
            // Lower wing — goes down-right from hip
            {
                float wAngle = 0.8f - wingFlap * 0.05f; // mostly down-right
                int lwX = ax + 3;
                int lwY = ay - 2;
                for (int f = 0; f < 4; f++)
                {
                    float segAngle = wAngle - f * 0.15f;
                    float segLen = (8f + f * 5f) * wingSpread;
                    int sx = lwX + (int)(MathF.Cos(segAngle) * segLen);
                    int sy = lwY + (int)(MathF.Sin(segAngle) * segLen);
                    int w = 4 - f / 2;
                    Color fc = f < 1 ? wingEdge : f < 3 ? wingBase : wingTip;
                    int rx = Math.Min(lwX, sx); int ry = Math.Min(lwY, sy);
                    int rw = Math.Max(Math.Abs(sx - lwX), w); int rh = Math.Max(Math.Abs(sy - lwY), w);
                    DrawRect(rx, ry, rw, rh, fc * 0.85f);
                }
                // Wing membrane fill
                DrawRect(lwX, lwY, (int)(16 * wingSpread), (int)(14 * wingSpread), wingMid * 0.5f);
            }
            
            // Body — teal/dark armor
            Color armorCol = new Color(40, 80, 90) * departAlpha;
            Color armorLight = new Color(60, 120, 130) * departAlpha;
            // Torso
            DrawRect(ax - 4, ay - 12, 8, 10, armorCol);
            DrawRect(ax - 3, ay - 11, 6, 8, armorLight);
            // Shoulder pauldrons
            DrawRect(ax - 6, ay - 12, 3, 4, armorCol);
            DrawRect(ax + 3, ay - 12, 3, 4, armorCol);
            // Head
            DrawRect(ax - 2, ay - 16, 4, 4, new Color(200, 180, 160)); // face
            DrawRect(ax - 3, ay - 16, 6, 2, armorCol); // helmet
            // Legs
            DrawRect(ax - 3, ay - 2, 2, 4, armorCol);
            DrawRect(ax + 1, ay - 2, 2, 4, armorCol);
            
            // Shield (left hand) — small round buckler
            Color shieldCol = new Color(180, 160, 120) * departAlpha;
            int shX = ax - flip * 7;
            DrawRect(shX - 3, ay - 9, 6, 8, shieldCol);
            DrawRect(shX - 2, ay - 8, 4, 6, new Color(220, 200, 160));
            DrawRect(shX - 1, ay - 6, 2, 2, new Color(255, 220, 100)); // shield boss
            
            // Sword (right hand) — held out during swoop, otherwise at side
            Color swordCol = new Color(220, 220, 240) * departAlpha;
            Color swordEdge = Color.White * departAlpha;
            if (a.SwoopTimer > 0)
            {
                // Sword thrust forward — extended toward target
                Vector2 sDir = a.SwoopTarget - angelPos;
                if (sDir.LengthSquared() > 0) sDir = Vector2.Normalize(sDir);
                int swordLen = 14;
                for (int s = 0; s < swordLen; s++)
                {
                    Vector2 sp = angelPos + new Vector2(flip * 5, -4) + sDir * (s + 2);
                    float sAlpha = 1f - (float)s / swordLen * 0.3f;
                    int sw = s < 3 ? 3 : s < 8 ? 2 : 1; // taper
                    DrawRect((int)(sp.X - sw / 2), (int)(sp.Y - 1), sw, 2, swordEdge * sAlpha);
                }
                // Sword glow during swoop
                for (int s = 0; s < swordLen; s++)
                {
                    Vector2 sp = angelPos + new Vector2(flip * 5, -4) + sDir * (s + 2);
                    DrawRect((int)(sp.X - 2), (int)(sp.Y - 2), 5, 5, new Color(180, 160, 220) * 0.2f);
                }
            }
            else
            {
                // Sword at side — vertical
                int sX = ax + flip * 6;
                DrawRect(sX, ay - 14, 2, 12, swordCol);
                DrawRect(sX - 1, ay - 4, 4, 2, new Color(160, 140, 80)); // crossguard
                DrawRect(sX, ay - 2, 2, 3, new Color(120, 80, 40)); // grip
            }
            
            // Faint divine glow around angel
            float glowPulse = 0.3f + 0.15f * MathF.Sin(time * 3f);
            DrawRect(ax - 12, ay - 20, 24, 28, new Color(200, 180, 255) * (glowPulse * 0.1f));
            
            // Trail particles while swooping
            if (a.SwoopTimer > 0)
            {
                for (int p = 0; p < 2; p++)
                {
                    _particles.Add(new Particle
                    {
                        Position = angelPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 8f, ((float)_rng.NextDouble() - 0.5f) * 8f),
                        Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 20f, -15f - (float)_rng.NextDouble() * 20f),
                        Life = 0.4f, MaxLife = 0.4f,
                        Color = new Color(220, 200, 255) * 0.5f,
                        Size = 2f + (float)_rng.NextDouble() * 2f,
                    });
                }
            }
        }

        // Scáthach: draw shadow knight
        if (_knightActive && _currentFusion == "Scathach")
        {
            var k = _knight;
            float time = _knightTime;
            Vector2 knightPos;
            bool facingKLeft;
            
            float dAlpha = 1f; // departure fade
            if (k.DepartTimer > 0)
            {
                float dt2 = 1f - (k.DepartTimer / 2.0f);
                dAlpha = 1f - dt2;
                knightPos = k.ActualPos + new Vector2(0, dt2 * -40f); // sink slightly then dissolve
                facingKLeft = false;
            }
            else if (k.WindupTimer > 0)
            {
                float wt = 1f - (k.WindupTimer / 0.25f);
                wt = wt * wt;
                knightPos = Vector2.Lerp(k.SwingStart, k.SwingTarget, wt);
                facingKLeft = (k.SwingTarget.X - k.SwingStart.X) < 0;
            }
            else if (k.SwingTimer > 0)
            {
                knightPos = k.ActualPos;
                facingKLeft = MathF.Cos(k.SwingAngle) < 0;
            }
            else if (k.Returning)
            {
                float rt = 1f - (k.ReturnTimer / 0.4f);
                rt = 1f - (1f - rt) * (1f - rt);
                knightPos = Vector2.Lerp(k.SwingTarget, k.ActualPos, rt);
                facingKLeft = (k.ActualPos.X - k.SwingTarget.X) < 0;
            }
            else
            {
                knightPos = k.ActualPos;
                facingKLeft = k.Velocity.X < 0;
            }
            
            int kx = (int)knightPos.X;
            int ky = (int)knightPos.Y;
            int kf = facingKLeft ? -1 : 1;
            
            // Shadow aura — dark purple glow
            float auraPulse = 0.25f + 0.1f * MathF.Sin(time * 2f);
            DrawRect(kx - 20, ky - 28, 40, 44, new Color(40, 10, 60) * (auraPulse * dAlpha));
            
            // Cape — dark, flowing behind (opposite to facing)
            Color capeCol = new Color(30, 10, 50) * dAlpha;
            float capeWave = MathF.Sin(time * 3f) * 4f;
            DrawRect(kx - kf * 4 - 6, ky - 10, 12, 18 + (int)capeWave, capeCol);
            DrawRect(kx - kf * 4 - 5, ky + 6, 10, 8 + (int)(capeWave * 0.5f), new Color(20, 5, 35) * dAlpha);
            
            // Body — heavy armored side-profile (like ref: thick, bulky)
            Color dkArmor = new Color(35, 30, 45) * dAlpha;
            Color dkArmorLight = new Color(55, 45, 65) * dAlpha;
            Color dkArmorHighlight = new Color(80, 60, 100) * dAlpha;
            // Torso — wide barrel chest
            DrawRect(kx - 8, ky - 18, 16, 18, dkArmor);
            DrawRect(kx - 7, ky - 17, 14, 16, dkArmorLight);
            // Chest detail — horizontal armor bands (like ref)
            DrawRect(kx - 7, ky - 14, 14, 2, dkArmorHighlight);
            DrawRect(kx - 7, ky - 8, 14, 2, dkArmorHighlight);
            DrawRect(kx - 6, ky - 4, 12, 2, dkArmorHighlight);
            // Belt
            DrawRect(kx - 7, ky - 1, 14, 3, new Color(70, 50, 30) * dAlpha);
            // Skull chest emblem
            DrawRect(kx - 3, ky - 13, 6, 5, new Color(200, 180, 160) * dAlpha);
            DrawRect(kx - 2, ky - 12, 1, 2, new Color(40, 10, 10) * dAlpha); // left eye
            DrawRect(kx + 1, ky - 12, 1, 2, new Color(40, 10, 10) * dAlpha); // right eye
            DrawRect(kx - 1, ky - 9, 3, 1, new Color(150, 130, 120) * dAlpha); // jaw
            // Shoulder pauldrons — large, layered
            DrawRect(kx - 12, ky - 20, 6, 8, dkArmor);
            DrawRect(kx + 6, ky - 20, 6, 8, dkArmor);
            DrawRect(kx - 11, ky - 19, 4, 6, dkArmorHighlight);
            DrawRect(kx + 7, ky - 19, 4, 6, dkArmorHighlight);
            // Arm (shield side)
            DrawRect(kx - kf * 10, ky - 12, 4, 14, dkArmor);
            // Arm (sword side)
            DrawRect(kx + kf * 8, ky - 12, 4, 14, dkArmor);
            // Helm — full great helm
            DrawRect(kx - 4, ky - 26, 8, 8, dkArmor);
            DrawRect(kx - 3, ky - 25, 6, 6, dkArmorLight);
            DrawRect(kx - 3, ky - 23, 6, 2, new Color(140, 40, 40) * dAlpha); // visor slit — red glow
            // Crown spikes — red energy (3 prongs)
            Color crownCol = new Color(180, 40, 50) * dAlpha;
            float crownPulse = 0.8f + 0.2f * MathF.Sin(time * 5f);
            DrawRect(kx - 5, ky - 30, 2, 5, crownCol * crownPulse);
            DrawRect(kx + 3, ky - 30, 2, 5, crownCol * crownPulse);
            DrawRect(kx - 1, ky - 33, 2, 8, crownCol * crownPulse); // center spike taller
            // Legs — armored greaves, wide stance
            DrawRect(kx - 6, ky + 2, 5, 8, dkArmor);
            DrawRect(kx + 1, ky + 2, 5, 8, dkArmor);
            DrawRect(kx - 5, ky + 8, 3, 3, dkArmorLight); // boot left
            DrawRect(kx + 2, ky + 8, 3, 3, dkArmorLight); // boot right
            
            // Shield — large kite shield, held in front (shield-side arm)
            int sKx = kx - kf * 12;
            Color shieldDk = new Color(50, 40, 60) * dAlpha;
            DrawRect(sKx - 5, ky - 18, 10, 20, shieldDk);
            DrawRect(sKx - 4, ky - 17, 8, 18, new Color(70, 55, 80) * dAlpha);
            DrawRect(sKx - 3, ky - 14, 6, 4, dkArmorHighlight); // shield band
            DrawRect(sKx - 1, ky - 10, 2, 3, new Color(180, 40, 50) * dAlpha); // red gem
            
            // Sword — massive claymore (bigger than before)
            Color swordBlade = new Color(180, 175, 195) * dAlpha;
            Color swordEdgeK = Color.White * dAlpha;
            int swX = kx + kf * 10;
            if (k.SwingTimer > 0)
            {
                // Swing arc — massive sword sweeps 120 degrees
                float swingProgress = 1f - (k.SwingTimer / 0.3f);
                float halfArc = MathF.PI / 3f;
                float currentAngle = k.SwingAngle - halfArc + (halfArc * 2f * swingProgress);
                Vector2 sDir = new Vector2(MathF.Cos(currentAngle), MathF.Sin(currentAngle));
                int swordLen = 32; // much longer blade
                for (int s = 0; s < swordLen; s++)
                {
                    Vector2 sp = knightPos + sDir * (10f + s);
                    int sw = s < 6 ? 6 : s < 16 ? 5 : s < 24 ? 4 : 3; // wider blade
                    float sAlpha = 1f - (float)s / swordLen * 0.15f;
                    DrawRect((int)(sp.X - sw / 2), (int)(sp.Y - sw / 2), sw, sw, swordBlade * sAlpha);
                    // White edge highlight
                    if (s % 3 == 0)
                        DrawRect((int)(sp.X - sw / 2), (int)(sp.Y - sw / 2), sw, 1, swordEdgeK * (sAlpha * 0.5f));
                }
                // Dark energy arc trail (wider)
                for (int s = 0; s < swordLen; s++)
                {
                    Vector2 sp = knightPos + sDir * (10f + s);
                    DrawRect((int)(sp.X - 5), (int)(sp.Y - 5), 10, 10, new Color(100, 40, 140) * (0.2f * dAlpha));
                }
                // Trailing afterimage at previous angle
                float trailAngle = currentAngle - halfArc * 0.3f * (swingProgress > 0.1f ? 1f : 0f);
                Vector2 tDir = new Vector2(MathF.Cos(trailAngle), MathF.Sin(trailAngle));
                for (int s = 0; s < swordLen; s++)
                {
                    Vector2 sp = knightPos + tDir * (10f + s);
                    int sw = s < 6 ? 4 : s < 16 ? 3 : 2;
                    DrawRect((int)(sp.X - sw / 2), (int)(sp.Y - sw / 2), sw, sw, new Color(80, 30, 120) * (0.15f * dAlpha));
                }
            }
            else if (k.WindupTimer > 0)
            {
                // Wind-up — sword pulled back overhead
                float wDir = k.SwingAngle + MathF.PI * 0.7f;
                Vector2 sDir = new Vector2(MathF.Cos(wDir), MathF.Sin(wDir));
                for (int s = 0; s < 28; s++)
                {
                    Vector2 sp = knightPos + sDir * (8f + s);
                    int sw = s < 6 ? 6 : s < 14 ? 5 : s < 22 ? 4 : 3;
                    DrawRect((int)(sp.X - sw / 2), (int)(sp.Y - sw / 2), sw, sw, swordBlade * 0.7f);
                }
                // Gathering dark energy glow
                float gatherPulse = 0.5f + 0.5f * MathF.Sin(time * 12f);
                Vector2 tipPos = knightPos + sDir * 36f;
                DrawRect((int)(tipPos.X - 6), (int)(tipPos.Y - 6), 12, 12, new Color(120, 50, 160) * (gatherPulse * 0.3f * dAlpha));
            }
            else
            {
                // Resting — sword held diagonally behind shoulder (like ref)
                DrawRect(swX - 1, ky - 30, 5, 36, swordBlade);
                DrawRect(swX, ky - 28, 3, 32, swordEdgeK * 0.3f); // highlight
                DrawRect(swX - 3, ky - 8, 9, 4, new Color(120, 80, 40) * dAlpha); // crossguard
                DrawRect(swX, ky + 6, 3, 5, new Color(80, 50, 30) * dAlpha); // grip
                // Dark energy shimmer on blade
                float shimmer = MathF.Sin(time * 4f + 1.5f) * 0.3f;
                DrawRect(swX - 1, ky - 28, 5, 16, new Color(100, 40, 140) * (shimmer * dAlpha));
            }
            
            // Shadow wisps while orbiting
            if (k.DepartTimer <= 0 && k.SwingTimer <= 0 && _rng.NextDouble() < 0.15)
            {
                _particles.Add(new Particle
                {
                    Position = knightPos + new Vector2(((float)_rng.NextDouble() - 0.5f) * 14f, ((float)_rng.NextDouble() - 0.5f) * 14f),
                    Velocity = new Vector2(((float)_rng.NextDouble() - 0.5f) * 15f, -10f - (float)_rng.NextDouble() * 15f),
                    Life = 0.5f, MaxLife = 0.5f,
                    Color = new Color(60, 20, 80) * 0.4f,
                    Size = 2f + (float)_rng.NextDouble() * 2f,
                });
            }
        }

        foreach (var proj in _projectiles)
        {
            // Marrow Shot: spinning bone cross
            if (proj.Alive && proj.FusionName == "MarrowShot")
            {
                float spin = proj.Age * 15f;
                float sz = proj.Params.Size;
                Color boneColor = new Color(200, 185, 150);
                // Rotating cross shape (two perpendicular rects)
                float c1 = MathF.Cos(spin);
                float s1 = MathF.Sin(spin);
                float c2 = MathF.Cos(spin + MathF.PI / 2f);
                float s2 = MathF.Sin(spin + MathF.PI / 2f);
                // Bar 1
                DrawRect((int)(proj.Position.X + c1 * sz - 1), (int)(proj.Position.Y + s1 * sz - 1), 3, 3, boneColor);
                DrawRect((int)(proj.Position.X - c1 * sz - 1), (int)(proj.Position.Y - s1 * sz - 1), 3, 3, boneColor);
                // Bar 2
                DrawRect((int)(proj.Position.X + c2 * sz - 1), (int)(proj.Position.Y + s2 * sz - 1), 3, 3, boneColor);
                DrawRect((int)(proj.Position.X - c2 * sz - 1), (int)(proj.Position.Y - s2 * sz - 1), 3, 3, boneColor);
                // Center
                DrawRect((int)(proj.Position.X - 2), (int)(proj.Position.Y - 2), 4, 4, new Color(220, 200, 170));
                continue;
            }
            
            // Silk Shot: rainbow thread projectile
            if (proj.Alive && proj.FusionName == "SilkShot")
            {
                float hue = (proj.Age * 200f) % 360f;
                Color rc = HueToColor(hue);
                DrawRect((int)(proj.Position.X - 2), (int)(proj.Position.Y - 2), 4, 4, rc);
                // Small rainbow trail
                Vector2 trail = proj.Position - (proj.Velocity.LengthSquared() > 0 ? Vector2.Normalize(proj.Velocity) * 6f : Vector2.Zero);
                DrawRect((int)(trail.X - 1), (int)(trail.Y - 1), 2, 2, rc * 0.5f);
                continue;
            }
            // Sacred Fist: big bone fist shape
            if (proj.Alive && proj.FusionName == "SacredFist")
            {
                Vector2 velDir = proj.Velocity;
                if (velDir.LengthSquared() > 1f) velDir.Normalize();
                float angle = MathF.Atan2(velDir.Y, velDir.X);
                float sz = proj.Params.Size;
                
                // Fist body (knuckles = front, wrist = back)
                // Outer glow
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(255, 240, 200) * 0.3f,
                    angle, new Vector2(0.5f, 0.5f), new Vector2(sz * 1.6f, sz * 1.4f), SpriteEffects.None, 0);
                // Main fist block
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(220, 200, 170),
                    angle, new Vector2(0.5f, 0.5f), new Vector2(sz * 1.2f, sz), SpriteEffects.None, 0);
                // Knuckle ridge (front edge)
                Vector2 knucklePos = proj.Position + velDir * sz * 0.5f;
                _spriteBatch.Draw(_pixel, knucklePos, null, new Color(240, 225, 195),
                    angle, new Vector2(0.5f, 0.5f), new Vector2(sz * 0.3f, sz * 1.1f), SpriteEffects.None, 0);
                // Dark joint lines
                for (int f = -1; f <= 1; f++)
                {
                    Vector2 perp = new Vector2(-velDir.Y, velDir.X);
                    Vector2 jointPos = proj.Position + perp * (f * sz * 0.28f);
                    _spriteBatch.Draw(_pixel, jointPos, null, new Color(160, 140, 110) * 0.6f,
                        angle, new Vector2(0.5f, 0.5f), new Vector2(sz * 0.8f, 1.5f), SpriteEffects.None, 0);
                }
                // Wrist bone extension behind
                Vector2 wristPos = proj.Position - velDir * sz * 0.7f;
                _spriteBatch.Draw(_pixel, wristPos, null, new Color(200, 180, 150),
                    angle, new Vector2(0.5f, 0.5f), new Vector2(sz * 0.6f, sz * 0.6f), SpriteEffects.None, 0);
                
                continue;
            }
            
            // Earthquake: bone spikes rising from ground
            if (proj.Alive && proj.FusionName == "Earthquake")
            {
                float life = proj.Age / proj.Lifetime;
                // Spike rises up over first 0.3s, stays, sinks in last 0.3s
                float rise = life < 0.1f ? life / 0.1f : (life > 0.9f ? (1f - life) / 0.1f : 1f);
                float spikeH = 20f * rise;
                float spikeW = 4f;
                // Bone spike triangle (3 rects to approximate)
                DrawRect((int)(proj.Position.X - spikeW/2), (int)(proj.Position.Y - spikeH), (int)spikeW, (int)spikeH, new Color(200, 190, 150));
                DrawRect((int)(proj.Position.X - spikeW/4), (int)(proj.Position.Y - spikeH - 4), (int)(spikeW/2), 4, new Color(230, 220, 180)); // tip
                DrawRect((int)(proj.Position.X - spikeW), (int)(proj.Position.Y - 2), (int)(spikeW*2), 2, new Color(120, 110, 80) * 0.5f); // base crack
                continue;
            }
            
            // Dark Gate: swirling dark portal
            if (proj.Alive && proj.FusionName == "DarkGate")
            {
                float t = proj.Age * 3f;
                float baseR = 25f + MathF.Sin(t) * 5f;
                // Rotating dark energy rings
                for (int ring = 0; ring < 3; ring++)
                {
                    float a = t + ring * MathF.PI * 2f / 3f;
                    float rx = baseR * 0.8f;
                    float ry = baseR * 0.4f; // elliptical for perspective
                    Vector2 rp = proj.Position + new Vector2(MathF.Cos(a) * rx, MathF.Sin(a) * ry);
                    DrawRect((int)(rp.X - 3), (int)(rp.Y - 3), 6, 6, new Color(100, 30, 150) * 0.6f);
                }
                // Core
                DrawRect((int)(proj.Position.X - 8), (int)(proj.Position.Y - 8), 16, 16, new Color(40, 10, 60) * 0.8f);
                DrawRect((int)(proj.Position.X - 5), (int)(proj.Position.Y - 5), 10, 10, new Color(80, 20, 120));
                continue;
            }
            
            // Unicorn Diana: holy expanding orbs (white-gold glow)
            if (proj.Alive && proj.FusionName == "UnicornDiana")
            {
                float s = proj.Size * (1f + proj.Age * proj.Params.BloomGrowRate);
                float pulse = (MathF.Sin(proj.Age * 8f) + 1f) / 2f;
                DrawRect((int)(proj.Position.X - s), (int)(proj.Position.Y - s), (int)(s*2), (int)(s*2), new Color(255, 255, 200) * (0.15f + pulse * 0.1f));
                DrawRect((int)(proj.Position.X - s/2), (int)(proj.Position.Y - s/2), (int)s, (int)s, new Color(255, 240, 150));
                continue;
            }

            if (proj.Alive && proj.FusionName == "ShadowStitch")
            {
                // Draw shadow hand extending from player
                Vector2 armDir = proj.Position - _playerPos;
                float armLen = armDir.Length();
                if (armLen < 1f) { continue; }
                armDir /= armLen;
                float angle = MathF.Atan2(armDir.Y, armDir.X);
                float handSize = proj.Params.Size;
                
                // Tapered arm
                int segments = Math.Max(1, (int)(armLen / 5f));
                for (int s = 0; s <= segments; s++)
                {
                    float t = (float)s / segments;
                    Vector2 pos = Vector2.Lerp(_playerPos, proj.Position, t);
                    float width = MathHelper.Lerp(4f, handSize * 0.8f, t);
                    float wobble = MathF.Sin(_gorgonTime * 6f + t * 10f) * 2f;
                    Vector2 perp = new Vector2(-armDir.Y, armDir.X);
                    pos += perp * wobble;
                    
                    _spriteBatch.Draw(_pixel, pos, null, new Color(20, 6, 35) * (0.7f + t * 0.2f),
                        angle, new Vector2(0.5f, 0.5f), new Vector2(6f, width + 4f), SpriteEffects.None, 0);
                    _spriteBatch.Draw(_pixel, pos, null, new Color(40, 12, 60) * (0.8f + t * 0.15f),
                        angle, new Vector2(0.5f, 0.5f), new Vector2(5f, width), SpriteEffects.None, 0);
                }
                
                // Hand — 5 fingers with thumb offset
                float fingerLen = handSize * 1.4f;
                float[] fingerAngles = { -0.4f, -0.18f, 0f, 0.18f, 0.35f }; // thumb wider
                float[] fingerWidths = { 3.5f, 2.5f, 2.5f, 2.5f, 3f }; // thumb thicker
                for (int f = 0; f < 5; f++)
                {
                    float fAngle = angle + fingerAngles[f];
                    float fLen = f == 0 ? fingerLen * 0.75f : fingerLen; // thumb shorter
                    Vector2 fingerMid = proj.Position + new Vector2(MathF.Cos(fAngle), MathF.Sin(fAngle)) * fLen * 0.5f;
                    
                    _spriteBatch.Draw(_pixel, fingerMid, null, new Color(35, 10, 55) * 0.9f,
                        fAngle, new Vector2(0.5f, 0.5f), new Vector2(fLen, fingerWidths[f]), SpriteEffects.None, 0);
                }
                
                // Palm
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(55, 18, 80) * 0.7f,
                    angle, new Vector2(0.5f, 0.5f), new Vector2(handSize * 0.9f, handSize * 0.9f), SpriteEffects.None, 0);
                
                continue;
            }
            
            // Fire Bolt / Muspelheim: layered teardrop fireball (SotN style)
            if (proj.Alive && (_currentDualCombo == "Fire Bolt" || _currentFusion == "Pillars of Muspelheim") && proj.Velocity.LengthSquared() > 1f)
            {
                float s = proj.Size * proj.CurrentScale;
                float moveAngle = MathF.Atan2(proj.Velocity.Y, proj.Velocity.X);
                Vector2 origin = new Vector2(0.5f, 0.5f);
                float flicker = 0.85f + 0.15f * MathF.Sin(proj.Age * 35f + proj.Position.X * 0.3f);
                float jitter = MathF.Sin(proj.Age * 50f) * 0.08f;
                float angle = moveAngle + jitter;
                
                // Outer glow: dark red/orange, elongated backward (tail)
                float tailLen = s * 3.5f;
                float tailWidth = s * 2f * flicker;
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(180, 40, 5) * 0.5f, angle,
                    origin, new Vector2(tailLen, tailWidth), SpriteEffects.None, 0);
                // Mid layer: orange, slightly smaller
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(255, 130, 20) * 0.7f, angle,
                    origin, new Vector2(s * 2.5f, s * 1.5f * flicker), SpriteEffects.None, 0);
                // Hot layer: bright yellow
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(255, 220, 60) * 0.85f, angle,
                    origin, new Vector2(s * 1.8f, s * 1.0f * flicker), SpriteEffects.None, 0);
                // Core: white-hot
                _spriteBatch.Draw(_pixel, proj.Position, null, new Color(255, 255, 220) * 0.95f, angle,
                    origin, new Vector2(s * 1.0f, s * 0.6f), SpriteEffects.None, 0);
                continue;
            }
            // Hammer of God: thick void bolt with indigo core + white-violet corona + afterimages
            if (proj.Alive && proj.FusionName == "HammerOfGod" && proj.BeamLen > 0)
            {
                float time = (float)_totalTime;
                Vector2 bd = proj.BeamDirection;
                float bAngle = MathF.Atan2(bd.Y, bd.X);
                Vector2 bPerp = new Vector2(-bd.Y, bd.X);
                float bLen = proj.BeamLen;
                float lifeRatio = proj.Lifetime > 0 ? MathHelper.Clamp(1f - proj.Age / proj.Lifetime, 0, 1) : 1f;
                
                // Layer 1: Outer corona — wide, faint violet glow (pulses)
                float coronaPulse = 0.5f + 0.3f * MathF.Sin(time * 20f);
                for (int seg = 0; seg < (int)(bLen / 4); seg++)
                {
                    float t = seg * 4f;
                    Vector2 pos = proj.Position + bd * t;
                    float wobble = MathF.Sin(time * 15f + t * 0.1f) * 2f;
                    DrawRect((int)(pos.X + bPerp.X * wobble - 8), (int)(pos.Y + bPerp.Y * wobble - 8), 16, 16,
                        new Color(100, 60, 160) * (0.15f * coronaPulse * lifeRatio));
                }
                
                // Layer 2: White-violet corona — medium width
                for (int seg = 0; seg < (int)(bLen / 3); seg++)
                {
                    float t = seg * 3f;
                    Vector2 pos = proj.Position + bd * t;
                    float flicker = 0.7f + 0.3f * MathF.Sin(time * 25f + t * 0.2f);
                    DrawRect((int)(pos.X - 5), (int)(pos.Y - 5), 10, 10,
                        new Color(180, 150, 230) * (0.4f * flicker * lifeRatio));
                }
                
                // Layer 3: Indigo core — narrow, bright
                for (int seg = 0; seg < (int)(bLen / 2); seg++)
                {
                    float t = seg * 2f;
                    Vector2 pos = proj.Position + bd * t;
                    DrawRect((int)(pos.X - 3), (int)(pos.Y - 3), 6, 6,
                        new Color(60, 30, 120) * (0.9f * lifeRatio));
                }
                
                // Layer 4: White-hot center line
                for (int seg = 0; seg < (int)(bLen / 2); seg++)
                {
                    float t = seg * 2f;
                    Vector2 pos = proj.Position + bd * t;
                    DrawRect((int)(pos.X - 1), (int)(pos.Y - 1), 3, 3,
                        Color.White * (0.95f * lifeRatio));
                }
                
                // Trailing afterimages (3 fading copies offset behind)
                for (int trail = 1; trail <= 3; trail++)
                {
                    float trailAlpha = (1f - trail * 0.3f) * lifeRatio * 0.3f;
                    Vector2 trailOff = -bd * trail * 6f;
                    for (int seg = 0; seg < (int)(bLen / 6); seg++)
                    {
                        float t = seg * 6f;
                        Vector2 pos = proj.Position + bd * t + trailOff;
                        DrawRect((int)(pos.X - 2), (int)(pos.Y - 2), 5, 5,
                            new Color(140, 100, 200) * trailAlpha);
                    }
                }
                
                // Subtle screen vibration while beam exists (micro-trauma)
                _trauma = MathF.Max(_trauma, 0.05f * lifeRatio);
                
                continue; // skip default draw
            }
            proj.Draw(_spriteBatch, _pixel);
        }
        
        // Enemy projectiles
        foreach (var ep in _enemyProjectiles)
        {
            float alpha = MathHelper.Clamp(ep.Life * 3f, 0f, 1f);
            int sz = (int)ep.Size;
            // Outer glow
            _spriteBatch.Draw(_pixel, new Rectangle((int)(ep.Position.X - sz), (int)(ep.Position.Y - sz), sz * 2, sz * 2),
                ep.Color * alpha * 0.3f);
            // Core
            _spriteBatch.Draw(_pixel, new Rectangle((int)(ep.Position.X - sz / 2), (int)(ep.Position.Y - sz / 2), sz, sz),
                ep.Color * alpha);
            // Bright center
            _spriteBatch.Draw(_pixel, new Rectangle((int)ep.Position.X, (int)ep.Position.Y, MathHelper.Max(sz / 2, 1), MathHelper.Max(sz / 2, 1)),
                Color.White * alpha * 0.7f);
        }

        // Bone Husks
        foreach (var husk in _boneHusks)
        {
            int ix = (int)husk.Position.X;
            int iy = (int)husk.Position.Y;
            float phase = husk.GrowTimer > 0 ? 1f - (husk.GrowTimer / 1.5f) : 1f; // 0→1
            
            if (phase < 1f)
            {
                // === TRANSFORMATION SEQUENCE ===
                float es = husk.EnemySize; // original enemy size
                
                // Phase 1 (0-0.2): Seizure — enemy visible, color draining, shaking
                if (phase < 0.2f)
                {
                    float t = phase / 0.2f; // 0→1 within phase
                    // Enemy body — color drains to pale, with shake
                    Color bodyCol = Color.Lerp(husk.EnemyColor, new Color(180, 170, 150), t * 0.6f);
                    int shakeX = (int)(MathF.Sin(phase * 200f) * 2f);
                    int shakeY = (int)(MathF.Cos(phase * 173f) * 2f);
                    DrawRect(ix - (int)(es/2) + shakeX, iy - (int)(es/2) + shakeY, (int)es, (int)es, bodyCol);
                    // Cracks appearing
                    for (int c = 0; c < (int)(t * 4); c++)
                    {
                        float ca = c * 1.7f;
                        int cx = ix + (int)(MathF.Cos(ca) * es * 0.2f);
                        int cy = iy + (int)(MathF.Sin(ca) * es * 0.2f);
                        DrawRect(cx, cy, 2, 2, new Color(220, 200, 170) * t);
                    }
                }
                // Phase 2 (0.2-0.47): Eruption — spikes bursting, body deforming
                else if (phase < 0.47f)
                {
                    float t = (phase - 0.2f) / 0.27f;
                    // Deformed body — expanding unevenly
                    float swell = 1f + t * 0.3f;
                    Color bodyCol = Color.Lerp(new Color(180, 170, 150), new Color(200, 180, 150), t);
                    DrawRect(ix - (int)(es*swell/2), iy - (int)(es*swell/2), (int)(es*swell), (int)(es*swell), bodyCol);
                    // Bone interior showing through
                    DrawRect(ix - (int)(es*0.3f), iy - (int)(es*0.3f), (int)(es*0.6f), (int)(es*0.6f), new Color(220, 200, 170) * t);
                    
                    // Spikes that have erupted
                    for (int sp = 0; sp < husk.SpikeCount; sp++)
                    {
                        float angle = sp * MathF.PI * 2f / 8f;
                        float spikeLen = es * 0.4f * t;
                        int sx = ix + (int)(MathF.Cos(angle) * (es * swell * 0.5f + spikeLen * 0.5f));
                        int sy = iy + (int)(MathF.Sin(angle) * (es * swell * 0.5f + spikeLen * 0.5f));
                        int ss = (int)MathF.Max(2, spikeLen * 0.4f);
                        DrawRect(sx - ss/2, sy - ss/2, ss, ss, new Color(230, 210, 180));
                        // Blood at spike base
                        DrawRect(sx - 1, sy - 1, 3, 3, new Color(160, 40, 30) * (0.8f - t * 0.3f));
                    }
                }
                // Phase 3 (0.47-0.8): Bloom — mass hardens and swells to final size
                else if (phase < 0.8f)
                {
                    float t = (phase - 0.47f) / 0.33f;
                    float s = MathHelper.Lerp(husk.EnemySize * 0.6f, husk.Size, t);
                    
                    // Hardening body
                    DrawRect(ix - (int)s, iy - (int)s, (int)(s*2), (int)(s*2), new Color(60, 50, 40));
                    DrawRect(ix - (int)(s*0.85f), iy - (int)(s*0.85f), (int)(s*1.7f), (int)(s*1.7f), Color.Lerp(new Color(200, 180, 150), new Color(200, 180, 150), t));
                    DrawRect(ix - (int)(s*0.5f), iy - (int)(s*0.5f), (int)s, (int)s, new Color(220, 200, 170));
                    
                    // All 8 spikes growing to full
                    for (int sp = 0; sp < 8; sp++)
                    {
                        float angle = sp * MathF.PI * 2f / 8f;
                        float spikeLen = s * (0.3f + 0.3f * t);
                        int sx = ix + (int)(MathF.Cos(angle) * (s + spikeLen * 0.5f));
                        int sy = iy + (int)(MathF.Sin(angle) * (s + spikeLen * 0.5f));
                        int ss = (int)MathF.Max(2, spikeLen * 0.3f);
                        DrawRect(sx - ss/2, sy - ss/2, ss, ss, new Color(230, 210, 180));
                    }
                    
                    // Residual blood dripping down
                    for (int b = 0; b < 3; b++)
                    {
                        int bx = ix - (int)s + (int)(s * 0.5f * b);
                        int by = iy + (int)(s * 0.7f) + (int)(t * 8f * (b + 1));
                        DrawRect(bx, by, 2, 3 + (int)(t * 4), new Color(120, 30, 20) * (1f - t * 0.5f));
                    }
                }
                // Phase 4 (0.8-1.0): Solidify — flash, lock in
                else
                {
                    float t = (phase - 0.8f) / 0.2f;
                    float s = husk.Size;
                    float flash = (1f - t) * 0.4f; // bright flash fading out
                    
                    // Final form
                    DrawRect(ix - (int)s, iy - (int)s, (int)(s*2), (int)(s*2), new Color(60, 50, 40));
                    DrawRect(ix - (int)(s*0.8f), iy - (int)(s*0.8f), (int)(s*1.6f), (int)(s*1.6f), new Color(200, 180, 150));
                    DrawRect(ix - (int)(s*0.5f), iy - (int)(s*0.5f), (int)s, (int)s, new Color(220, 200, 170));
                    
                    for (int sp = 0; sp < 8; sp++)
                    {
                        float angle = sp * MathF.PI * 2f / 8f;
                        float spikeLen = s * 0.6f;
                        int sx = ix + (int)(MathF.Cos(angle) * (s + spikeLen * 0.5f));
                        int sy = iy + (int)(MathF.Sin(angle) * (s + spikeLen * 0.5f));
                        int ss = (int)MathF.Max(2, spikeLen * 0.3f);
                        DrawRect(sx - ss/2, sy - ss/2, ss, ss, new Color(230, 210, 180));
                    }
                    
                    // Solidify flash
                    DrawRect(ix - (int)(s*1.3f), iy - (int)(s*1.3f), (int)(s*2.6f), (int)(s*2.6f), new Color(255, 240, 200) * flash);
                }
            }
            else
            {
                // === FULLY FORMED HUSK ===
                float s = husk.Size;
                float pulse = (MathF.Sin(husk.PulseTimer * 3f) + 1f) / 2f;
                
                DrawRect(ix - (int)s, iy - (int)s, (int)(s * 2), (int)(s * 2), new Color(60, 50, 40));
                DrawRect(ix - (int)(s * 0.8f), iy - (int)(s * 0.8f), (int)(s * 1.6f), (int)(s * 1.6f), new Color(200, 180, 150));
                DrawRect(ix - (int)(s * 0.5f), iy - (int)(s * 0.5f), (int)(s), (int)(s), new Color(220, 200, 170));
                
                for (int sp = 0; sp < 8; sp++)
                {
                    float angle = sp * MathF.PI * 2f / 8f;
                    float spikeLen = s * (0.6f + 0.15f * MathF.Sin(husk.PulseTimer * 2f + sp));
                    int sx = ix + (int)(MathF.Cos(angle) * (s + spikeLen * 0.5f));
                    int sy = iy + (int)(MathF.Sin(angle) * (s + spikeLen * 0.5f));
                    int spikeSize = (int)MathF.Max(2, spikeLen * 0.3f);
                    DrawRect(sx - spikeSize / 2, sy - spikeSize / 2, spikeSize, spikeSize, new Color(230, 210, 180));
                }
                
                DrawRect(ix - (int)(s * 1.2f), iy - (int)(s * 1.2f), (int)(s * 2.4f), (int)(s * 2.4f), new Color(255, 240, 200) * (0.03f + 0.02f * pulse));
            }
        }

        for (int _ei = 0; _ei < _enemies.Count; _ei++)
        {
            var enemy = _enemies[_ei];
            // Boss aura: pulsing glow behind boss
            if (enemy.Id == _bossId && enemy.Alive)
            {
                float pulse = (MathF.Sin(_gorgonTime * 4f) + 1f) / 2f;
                int auraSize = (int)(enemy.Size * (1.8f + pulse * 0.4f));
                _spriteBatch.Draw(_pixel, new Rectangle(
                    (int)(enemy.Position.X - auraSize / 2f), (int)(enemy.Position.Y - auraSize / 2f),
                    auraSize, auraSize), enemy.BaseColor * (0.15f + 0.1f * pulse));
            }
            
            // Spawn animation visual transforms
            if (enemy.Spawning && enemy.Alive)
            {
                float t = 1f - enemy.SpawnTimer / enemy.SpawnDuration;
                switch (enemy.Type)
                {
                    case EnemyType.GuardGargoyle:
                    case EnemyType.TowerGuard:
                        // Shadow on ground, enemy drops in at end
                        if (t < 0.8f)
                        {
                            // Just the shadow (growing ellipse)
                            float shadowScale = t / 0.8f;
                            int sw = (int)(enemy.Size * 1.5f * shadowScale);
                            int sh = (int)(enemy.Size * 0.5f * shadowScale);
                            _spriteBatch.Draw(_pixel, new Rectangle(
                                (int)(enemy.Position.X - sw / 2f), (int)(enemy.Position.Y - sh / 2f + enemy.Size * 0.3f),
                                sw, sh), new Color(20, 20, 30) * (0.3f + 0.3f * shadowScale));
                        }
                        else
                        {
                            // Enemy visible, slamming down — scale from 2x to 1x
                            float landT = (t - 0.8f) / 0.2f;
                            float scale = 2f - landT; // 2→1
                            float yOff = -40f * (1f - landT); // drop from above
                            int s = (int)(enemy.Size * scale);
                            Color c = Color.Lerp(Color.White, enemy.BaseColor, landT);
                            _spriteBatch.Draw(_pixel, new Rectangle(
                                (int)(enemy.Position.X - s / 2f), (int)(enemy.Position.Y + yOff - s / 2f),
                                s, s), c);
                        }
                        break;
                        
                    case EnemyType.HollowPlate:
                        // Assemble from ground — grow upward
                        {
                            float scaleY = t;
                            float scaleX = 0.5f + t * 0.5f;
                            int w = (int)(enemy.Size * scaleX);
                            int h = (int)(enemy.Size * scaleY);
                            float alpha = 0.3f + t * 0.7f;
                            _spriteBatch.Draw(_pixel, new Rectangle(
                                (int)(enemy.Position.X - w / 2f), (int)(enemy.Position.Y + enemy.Size / 2f - h),
                                w, h), enemy.BaseColor * alpha);
                        }
                        break;
                        
                    case EnemyType.HedgeSniper:
                        // Grow from ground like a plant
                        {
                            float growT = t * t; // ease-in for organic feel
                            int w = (int)(enemy.Size * (0.3f + 0.7f * growT));
                            int h = (int)(enemy.Size * growT);
                            _spriteBatch.Draw(_pixel, new Rectangle(
                                (int)(enemy.Position.X - w / 2f), (int)(enemy.Position.Y + enemy.Size / 2f - h),
                                w, h), enemy.BaseColor * (0.2f + 0.8f * growT));
                        }
                        break;
                        
                    case EnemyType.Maw:
                        // Slow materialization — dark haze expanding with flickering eyes
                        {
                            float alpha = t * t; // slow start
                            int mSize = (int)(enemy.Size * (0.3f + 0.7f * t));
                            int mx = (int)(enemy.Position.X - mSize / 2);
                            int my = (int)(enemy.Position.Y - mSize / 2);
                            // Dark haze
                            DrawRect(mx, my, mSize, mSize, new Color(40, 10, 10) * (alpha * 0.3f));
                            DrawRect(mx + 4, my + 4, mSize - 8, mSize - 8, new Color(60, 10, 15) * (alpha * 0.2f));
                            // Eyes flicker on at 60%
                            if (t > 0.6f)
                            {
                                float eyeAlpha = (t - 0.6f) / 0.4f;
                                int ey = (int)enemy.Position.Y - 8;
                                DrawRect((int)enemy.Position.X - 8, ey, 3, 3, Color.White * (eyeAlpha * 0.7f));
                                DrawRect((int)enemy.Position.X + 5, ey, 3, 3, Color.White * (eyeAlpha * 0.7f));
                            }
                            // Teeth appear at 80%
                            if (t > 0.8f)
                            {
                                float teethAlpha = (t - 0.8f) / 0.2f;
                                int ty = (int)enemy.Position.Y + 4;
                                for (int tt = 0; tt < 7; tt++)
                                {
                                    int tx = (int)(enemy.Position.X - 15 + tt * 5);
                                    DrawRect(tx, ty, 2, 3, Color.White * (teethAlpha * 0.8f));
                                }
                            }
                        }
                        break;
                    default: // Squire, ShieldMaiden — fade in with scale
                        {
                            float alpha = t;
                            float scale = 0.3f + 0.7f * t;
                            int s = (int)(enemy.Size * scale);
                            _spriteBatch.Draw(_pixel, new Rectangle(
                                (int)(enemy.Position.X - s / 2f), (int)(enemy.Position.Y - s / 2f),
                                s, s), enemy.BaseColor * alpha);
                        }
                        break;
                }
                continue; // skip normal Draw during spawn
            }
            
            // Gae Bolg Shrieker: grotesque pulsing totem (DOS2 inspired)
            if (enemy.ShriekerTimer > 0)
            {
                float pulse = (MathF.Sin(enemy.ShriekerTimer * 8f) + 1f) / 2f;
                float sz = enemy.Size;
                // Sickly green-blue base body (decaying)
                Color shriekColor = Color.Lerp(new Color(60, 140, 100), new Color(100, 180, 255), pulse);
                DrawRect((int)(enemy.Position.X - sz/2), (int)(enemy.Position.Y - sz), (int)sz, (int)(sz * 2), shriekColor);
                // Barbs/spines sprouting outward
                for (int b = 0; b < 6; b++)
                {
                    float a = (MathF.PI * 2f / 6f) * b + enemy.ShriekerTimer * 0.5f;
                    float barbLen = 6f + pulse * 4f;
                    Vector2 barbEnd = enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * (sz/2 + barbLen);
                    DrawRect((int)(barbEnd.X - 1), (int)(barbEnd.Y - 1), 3, 3, new Color(100, 180, 255));
                }
                // Electric glow ring
                float ringR = 80f * (0.3f + pulse * 0.7f);
                int ringSegs = 16;
                for (int s = 0; s < ringSegs; s++)
                {
                    float a = (MathF.PI * 2f / ringSegs) * s;
                    Vector2 rp = enemy.Position + new Vector2(MathF.Cos(a), MathF.Sin(a)) * ringR;
                    DrawRect((int)(rp.X), (int)(rp.Y), 2, 2, new Color(100, 180, 255) * (0.2f + pulse * 0.3f));
                }
                continue; // skip normal draw
            }
            
            // Attack proximity glow — intensifies as enemy gets closer to player
            if (enemy.Alive && !enemy.Spawning)
            {
                float distToPlayer = Vector2.Distance(enemy.Position, _playerPos);
                if (distToPlayer < enemy.Size * 3f && distToPlayer > 0)
                {
                    float intensity = 1f - (distToPlayer / (enemy.Size * 3f));
                    Color glowCol = Color.Lerp(enemy.BaseColor, Color.White, intensity * 0.5f);
                    int gs = (int)(enemy.Size * (1f + intensity * 0.3f));
                    DrawRect((int)(enemy.Position.X - gs / 2f), (int)(enemy.Position.Y - gs / 2f), gs, gs, glowCol * (intensity * 0.2f));
                }
            }
            
            // Element type visual tell — subtle colored aura/particles showing enemy's nature
            if (enemy.Alive && !enemy.Spawning && enemy.ElementType != Essence.None)
            {
                Color elemCol = enemy.ElementType switch
                {
                    Essence.Cinder => new Color(255, 120, 40),
                    Essence.Dark => new Color(100, 40, 140),
                    Essence.Bone => new Color(200, 190, 160),
                    Essence.Silk => new Color(180, 200, 160),
                    Essence.Pulse => new Color(80, 160, 255),
                    Essence.Hollow => new Color(140, 80, 200),
                    Essence.Sap => new Color(80, 180, 60),
                    _ => Color.White
                };
                // Pulsing element glow underneath enemy
                float elemPulse = (MathF.Sin(_totalTime * 2.5f + enemy.Id * 1.7f) + 1f) / 2f;
                int eg = (int)(enemy.Size * 1.4f + elemPulse * 4f);
                DrawRect((int)(enemy.Position.X - eg / 2f), (int)(enemy.Position.Y - eg / 2f), eg, eg, elemCol * (0.08f + elemPulse * 0.06f));
                // 2 orbiting element motes
                for (int m = 0; m < 2; m++)
                {
                    float mAngle = _totalTime * 1.8f + enemy.Id + m * MathF.PI;
                    float mR = enemy.Size * 0.8f + elemPulse * 3f;
                    Vector2 mp = enemy.Position + new Vector2(MathF.Cos(mAngle) * mR, MathF.Sin(mAngle) * mR * 0.6f);
                    DrawRect((int)mp.X - 1, (int)mp.Y - 1, 2, 2, elemCol * (0.4f + elemPulse * 0.3f));
                }
            }
            
            // BREAK Finisher jitter effect
            if (_finisherActive && _ei == _finisherEnemyIndex && _finisherTimer > 0.3f)
            {
                int jitter = ((int)(_finisherTimer * 30f) % 2 == 0) ? -3 : 3;
                enemy.Position.X += jitter;
                enemy.HitFlash = 1f; // force white color
                enemy.Draw(_spriteBatch, _pixel, _totalTime);
                enemy.Position.X -= jitter;
                enemy.HitFlash = 0f;
            }
            else
            {
                enemy.Draw(_spriteBatch, _pixel, _totalTime);
            }
            
            // Just-staggered visual bark
            if (enemy.Alive && enemy.StaggerTimer > 0 && enemy.StaggerTimer > enemy.MaxStagger * 0.8f)
            {
                DrawTextFallback((int)(enemy.Position.X - 2), (int)(enemy.Position.Y - enemy.Size / 2 - 18), "!", new Color(255, 100, 100));
            }
            
            // Enemy bark system (set by AI, decays here)
            if (enemy.Alive && enemy.BarkTimer > 0)
            {
                float barkAlpha = MathHelper.Clamp(enemy.BarkTimer / 0.3f, 0f, 1f); // fade out last 0.3s
                float barkRise = (1f - enemy.BarkTimer / 1.5f) * 8f; // drift upward
                Color barkCol = enemy.Type == EnemyType.Thief ? new Color(255, 220, 80) :
                                enemy.Type == EnemyType.HollowPlate ? new Color(160, 140, 200) :
                                enemy.Type == EnemyType.Webspinner ? new Color(180, 180, 160) :
                                enemy.Type == EnemyType.GuardGargoyle ? new Color(200, 160, 120) :
                                enemy.Type == EnemyType.HedgeSniper ? new Color(120, 200, 120) :
                                new Color(200, 200, 200);
                DrawTextFallback((int)(enemy.Position.X - enemy.Bark.Length * 3), (int)(enemy.Position.Y - enemy.Size / 2 - 26 - barkRise), enemy.Bark, barkCol * barkAlpha, 0.9f);
                enemy.BarkTimer -= 1f / 60f;
                if (enemy.BarkTimer <= 0) enemy.Bark = null;
            }
            // TowerGuard shield glow when armor is active
            if (enemy.Alive && !enemy.Spawning && enemy.Type == EnemyType.TowerGuard && enemy.StaggerTimer <= 0 && !enemy.IsBroken)
            {
                float shieldPulse = (MathF.Sin(_totalTime * 2f + enemy.Id) + 1f) / 2f;
                int sx = (int)enemy.Position.X;
                int sy = (int)enemy.Position.Y;
                DrawRect(sx - (int)(enemy.Size * 0.6f), sy - (int)(enemy.Size * 0.4f),
                    (int)(enemy.Size * 1.2f), (int)(enemy.Size * 0.8f),
                    new Color(180, 180, 200) * (0.1f + 0.08f * shieldPulse));
            }
            
            // BREAK! indicator above broken enemies (requires Ether Sight)
            if (enemy.IsBroken && enemy.Alive && _hasEtherSight)
            {
                int bx = (int)(enemy.Position.X - 20);
                int by = (int)(enemy.Position.Y - enemy.Size / 2) - 22;
                
                Color breakCol = ((int)(enemy.BreakTimer * 10) % 2 == 0) ? new Color(255, 255, 80) : Color.White;
                // Glow background
                float pulse = 0.5f + 0.5f * MathF.Sin(enemy.BreakTimer * 20f);
                DrawRect(bx - 2, by - 1, 44, 10, breakCol * (0.15f + 0.1f * pulse));
                DrawTextFallback(bx, by, "BREAK!", breakCol, 0.8f);
                
                // FINISH prompt when close enough and low HP
                if (enemy.Hp <= enemy.MaxHp * 0.25f && Vector2.Distance(_playerPos, enemy.Position) < 60f && !_finisherActive)
                {
                    float finishPulse = (MathF.Sin(_totalTime * 6f) + 1f) / 2f;
                    Color finishCol = Color.Lerp(new Color(255, 80, 60), Color.White, finishPulse * 0.4f);
                    int fx = (int)(enemy.Position.X - 22);
                    int fy = by - 14;
                    DrawRect(fx - 2, fy - 1, 52, 10, Color.Black * 0.5f);
                    DrawTextFallback(fx, fy, "FINISH [E]", finishCol, 0.7f);
                    // Pulsing red ring around enemy
                    int ringSize = (int)(enemy.Size + 8f + finishPulse * 4f);
                    int rx2 = (int)(enemy.Position.X - ringSize / 2);
                    int ry2 = (int)(enemy.Position.Y - ringSize / 2);
                    DrawRect(rx2, ry2, ringSize, 2, finishCol * 0.5f);
                    DrawRect(rx2, ry2 + ringSize - 2, ringSize, 2, finishCol * 0.5f);
                    DrawRect(rx2, ry2, 2, ringSize, finishCol * 0.5f);
                    DrawRect(rx2 + ringSize - 2, ry2, 2, ringSize, finishCol * 0.5f);
                }
            }
            if (enemy.SlowTimer > 0 && enemy.Alive)
            {
                float bob = MathF.Sin(enemy.SlowTimer * 6f) * 2f;
                int ax = (int)(enemy.Position.X - 3);
                int ay = (int)(enemy.Position.Y - enemy.Size / 2 - 12 + bob);
                Color slowColor = new Color(80, 180, 50);
                DrawRect(ax, ay, 7, 2, slowColor);
                DrawRect(ax + 1, ay + 2, 5, 2, slowColor);
                DrawRect(ax + 2, ay + 4, 3, 2, slowColor);
                DrawRect(ax + 3, ay + 6, 1, 1, slowColor);
            }
            
        }

        // Chronos' Chain: clock hands on frozen enemies
        if (_currentFusion == "Chronos' Chain")
        {
            foreach (var enemy in _enemies)
            {
                if (!enemy.Alive || enemy.StasisTimer <= 0) continue;
                float cx = enemy.Position.X;
                float cy = enemy.Position.Y;
                float clockRadius = enemy.Size * 0.6f;
                
                // Clock circle outline (8 small dots)
                for (int c = 0; c < 8; c++)
                {
                    float a = (MathF.PI * 2f / 8) * c;
                    float dx = MathF.Cos(a) * clockRadius;
                    float dy = MathF.Sin(a) * clockRadius;
                    DrawRect((int)(cx + dx - 1), (int)(cy + dy - 1), 2, 2, new Color(160, 200, 230) * 0.8f);
                }
                
                // Hour hand (slow, based on stasis remaining)
                float hourAngle = enemy.StasisTimer * 2f; // ticks slowly
                float hx = MathF.Sin(hourAngle) * clockRadius * 0.5f;
                float hy = -MathF.Cos(hourAngle) * clockRadius * 0.5f;
                // Draw as 3-pixel line approximation
                for (float t = 0; t < 1f; t += 0.15f)
                {
                    DrawRect((int)(cx + hx * t - 1), (int)(cy + hy * t - 1), 2, 3, new Color(180, 220, 255));
                }
                
                // Minute hand (fast spin, based on time)
                float minAngle = _noiseTime * 5f;
                float mx = MathF.Sin(minAngle) * clockRadius * 0.7f;
                float my = -MathF.Cos(minAngle) * clockRadius * 0.7f;
                for (float t = 0; t < 1f; t += 0.15f)
                {
                    DrawRect((int)(cx + mx * t), (int)(cy + my * t), 2, 2, new Color(200, 230, 255));
                }
                
                // Time distortion ring — expanding pale circle
                float ringPhase = (enemy.StasisTimer * 3f) % 1f;
                float ringR = clockRadius * (1f + ringPhase * 1.5f);
                float ringAlpha = (1f - ringPhase) * 0.4f;
                int ringPts = 16;
                for (int r = 0; r < ringPts; r++)
                {
                    float a = (MathF.PI * 2f / ringPts) * r;
                    DrawRect((int)(cx + MathF.Cos(a) * ringR - 1), (int)(cy + MathF.Sin(a) * ringR - 1), 2, 2, new Color(160, 200, 230) * ringAlpha);
                }
            }
        }

        // Spider webs
        DrawSpiderWebs();
        
        // Linger zones
        // ═══ Bone Stakes drawing ═══
        foreach (var stake in _boneStakes)
        {
            if (!stake.Alive) continue;
            float alpha = MathHelper.Clamp(stake.Life / stake.MaxLife, 0f, 1f);
            int sx = (int)stake.Position.X;
            int sy = (int)stake.Position.Y;
            // Tall bone stake with visual tilt
            Color boneColor = new Color(230, 220, 200) * alpha;
            Color boneTip = new Color(255, 250, 240) * alpha;
            // Main stake body (6x28 rect)
            DrawRect(sx - 3, sy - 24, 6, 28, boneColor);
            // Pointed tip
            DrawRect(sx - 2, sy - 28, 4, 4, boneTip);
            DrawRect(sx - 1, sy - 30, 2, 2, boneTip);
            // Dark base
            DrawRect(sx - 4, sy + 2, 8, 3, new Color(140, 120, 90) * alpha);
        }

        foreach (var z in _lingerZones)
        {
            float alpha = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f) * 0.35f;
            int r = (int)z.Radius;
            
            if (z.FusionTag == "CreepingMoss")
            {
                // Organic mossy spread: multiple overlapping rectangles for irregular shape
                float growProg = z.MaxRadius > 0 ? z.Radius / z.MaxRadius : 1f;
                float mossAlpha = alpha * 1.5f; // more visible
                int patches = 5 + (int)(growProg * 8);
                // Deterministic patches based on zone position (so they don't jitter)
                int seed = (int)(z.Position.X * 73 + z.Position.Y * 137);
                for (int p = 0; p < patches; p++)
                {
                    // Pseudo-random but stable per-zone
                    int h = seed + p * 7919;
                    float ax = ((h * 13 % 200) - 100) / 100f * r;
                    float ay = ((h * 17 % 200) - 100) / 100f * r;
                    float sz = 4f + (h * 11 % 12) * growProg;
                    Color mc = (h % 3) == 0 ? new Color(30, 100, 25) : (h % 3) == 1 ? new Color(45, 130, 35) : new Color(55, 110, 40);
                    DrawRect((int)(z.Position.X + ax - sz/2), (int)(z.Position.Y + ay - sz/2), (int)sz, (int)sz, mc * mossAlpha);
                }
                // Outer edge glow
                float edgePulse = (MathF.Sin(z.Life * 3f) + 1f) / 2f * 0.2f;
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y - r), r * 2, r * 2, new Color(60, 160, 50) * (edgePulse * alpha));
            }
            else if (z.FusionTag == "ThunderStorm")
            {
                // Dark storm cloud zone
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y - r), r * 2, r * 2, new Color(50, 55, 70) * (alpha * 0.4f));
                // Crackling edge
                float crackle2 = MathF.Abs(MathF.Sin(z.Life * 15f)) * 0.3f;
                DrawRect((int)(z.Position.X - r - 2), (int)(z.Position.Y - r - 2), r * 2 + 4, 2, new Color(200, 200, 255) * (alpha * crackle2));
            }
            else if (z.FusionTag == "Graveyard")
            {
                // Dark altar zone
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y - r), r * 2, r * 2, new Color(60, 50, 40) * (alpha * 0.3f));
                // 3 bone pillars at 120° intervals
                for (int bp = 0; bp < 3; bp++)
                {
                    float ba = (MathF.PI * 2f / 3f) * bp;
                    int bpx = (int)(z.Position.X + MathF.Cos(ba) * r * 0.6f);
                    int bpy = (int)(z.Position.Y + MathF.Sin(ba) * r * 0.6f);
                    DrawRect(bpx - 2, bpy - 10, 4, 20, new Color(220, 210, 180) * alpha);
                }
            }
            else if (z.FusionTag == "Bifrost")
            {
                float hue2 = (_totalTime * 3f + z.Position.X * 0.01f) % 1f;
                int cr2 = (int)(MathF.Sin(hue2 * MathF.PI * 2f) * 127 + 128);
                int cg2 = (int)(MathF.Sin((hue2 + 0.33f) * MathF.PI * 2f) * 127 + 128);
                int cb2 = (int)(MathF.Sin((hue2 + 0.66f) * MathF.PI * 2f) * 127 + 128);
                float pulse2 = 0.3f + 0.15f * MathF.Sin(z.Life * 8f);
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y - r), r * 2, r * 2, new Color(cr2, cg2, cb2) * (alpha * pulse2));
            }
            else if (z.FusionTag == "GraveCall")
            {
                // Grave marker: cross/tombstone shape
                float fadeIn = MathHelper.Clamp(1f - z.Life / z.MaxLife, 0, 0.3f) / 0.3f;
                Color graveColor = new Color(160, 140, 110) * (alpha * 1.5f);
                // Tombstone body
                DrawRect((int)(z.Position.X - 6), (int)(z.Position.Y - 12), 12, 16, graveColor);
                // Top arch
                DrawRect((int)(z.Position.X - 5), (int)(z.Position.Y - 15), 10, 4, graveColor);
                // Cross
                DrawRect((int)(z.Position.X - 1), (int)(z.Position.Y - 10), 2, 8, new Color(200, 190, 160) * alpha);
                DrawRect((int)(z.Position.X - 4), (int)(z.Position.Y - 8), 8, 2, new Color(200, 190, 160) * alpha);
                // Ground dirt
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y + 2), r * 2, 3, new Color(80, 60, 40) * alpha);
                // Skeletal hand hints reaching up from dirt
                float handPulse = (MathF.Sin(z.Life * 4f) + 1f) / 2f;
                if (handPulse > 0.6f)
                {
                    DrawRect((int)(z.Position.X - r + 5), (int)(z.Position.Y - 2), 3, 5, new Color(200, 190, 160) * alpha);
                    DrawRect((int)(z.Position.X + r - 8), (int)(z.Position.Y - 1), 3, 4, new Color(200, 190, 160) * alpha);
                }
            }
            else if (z.IsPillar)
            {
                // Muspelheim fire pillar: animated layered flame column
                float lifeRatio = z.Life / z.MaxLife;
                float baseAlpha = MathHelper.Clamp(lifeRatio * 2f, 0, 1f);
                float flicker = 0.8f + 0.2f * MathF.Sin(z.Life * 25f + z.Position.X * 0.5f);
                float flicker2 = 0.85f + 0.15f * MathF.Sin(z.Life * 18f + z.Position.Y * 0.3f);
                int bx = (int)z.Position.X;
                int by = (int)z.Position.Y;
                
                float heightScale = MathHelper.Clamp(lifeRatio * 1.5f, 0.3f, 1f);
                int flameH = (int)(40 * heightScale * flicker);
                int flameW = (int)(r * 1.8f * flicker2);
                
                // Outer glow: dark red
                DrawRect(bx - flameW, by - flameH, flameW * 2, flameH + 4, new Color(180, 30, 5) * (baseAlpha * 0.25f));
                // Mid flame: orange
                int midW = (int)(flameW * 0.7f);
                int midH = (int)(flameH * 0.85f);
                DrawRect(bx - midW, by - midH, midW * 2, midH + 2, new Color(255, 130, 20) * (baseAlpha * 0.45f));
                // Hot core: yellow
                int coreW = (int)(flameW * 0.35f * flicker);
                int coreH = (int)(flameH * 0.7f);
                DrawRect(bx - coreW, by - coreH, coreW * 2, coreH, new Color(255, 220, 60) * (baseAlpha * 0.6f));
                // White-hot center
                int hotW = (int)(flameW * 0.15f);
                int hotH = (int)(flameH * 0.4f * flicker2);
                DrawRect(bx - hotW, by - hotH / 2, hotW * 2, hotH, new Color(255, 255, 220) * (baseAlpha * 0.5f));
                
                // Ground glow
                float groundPulse = 0.7f + 0.3f * MathF.Sin(z.Life * 12f);
                int gw = (int)(r * 2.2f * groundPulse);
                DrawRect(bx - gw / 2, by, gw, 4, new Color(255, 100, 20) * (baseAlpha * 0.35f));
                DrawRect(bx - gw / 3, by + 1, gw * 2 / 3, 2, new Color(255, 200, 60) * (baseAlpha * 0.25f));
            }
            else if (z.FusionTag == "Bonfire")
            {
                // Bonfire: hot glowing ground circle
                float pulse = (MathF.Sin(z.Life * 8f) + 1f) / 2f;
                int bfR = (int)z.Radius;
                DrawRect((int)(z.Position.X - bfR), (int)(z.Position.Y - bfR), bfR * 2, bfR * 2, new Color(200, 60, 10) * (alpha * 1.5f));
                int innerR = (int)(bfR * 0.6f);
                DrawRect((int)(z.Position.X - innerR), (int)(z.Position.Y - innerR), innerR * 2, innerR * 2, new Color(255, 160, 30) * (alpha * 1.2f + pulse * 0.1f));
                int hotR = (int)(bfR * 0.25f);
                DrawRect((int)(z.Position.X - hotR), (int)(z.Position.Y - hotR), hotR * 2, hotR * 2, new Color(255, 240, 100) * (alpha + pulse * 0.15f));
            }
            else if (z.FusionTag == "StormWard")
            {
                // Storm Giant's Ward: glowing blue pillar
                float pulse = (MathF.Sin(z.Life * 6f) + 1f) / 2f;
                int px = (int)z.Position.X;
                int py = (int)z.Position.Y;
                // Ground glow
                int gR = (int)z.Radius;
                DrawRect(px - gR, py - gR, gR * 2, gR * 2, new Color(60, 100, 180) * (alpha * 0.3f));
                // Pillar body
                DrawRect(px - 4, py - 24, 8, 28, new Color(100, 120, 160) * (alpha * 2f));
                // Rune dots
                DrawRect(px - 1, py - 18, 2, 2, new Color(100, 220, 255) * (alpha * 2f + pulse * 0.3f));
                DrawRect(px + 1, py - 12, 2, 2, new Color(100, 220, 255) * (alpha * 2f + pulse * 0.3f));
                DrawRect(px - 2, py - 6, 2, 2, new Color(100, 220, 255) * (alpha * 2f + pulse * 0.3f));
                // Top glow
                DrawRect(px - 3, py - 26, 6, 3, new Color(150, 200, 255) * (alpha * 1.5f + pulse * 0.2f));
            }
            else if (z.FusionTag == "BonePit")
            {
                // Bone pit: dark ground zone
                int bpR = (int)z.Radius;
                DrawRect((int)(z.Position.X - bpR), (int)(z.Position.Y - bpR), bpR * 2, bpR * 2, new Color(80, 60, 40) * (alpha * 1.5f));
                // Lighter edge
                DrawRect((int)(z.Position.X - bpR + 2), (int)(z.Position.Y - bpR + 2), bpR * 2 - 4, bpR * 2 - 4, new Color(100, 80, 55) * alpha);
            }
            else if (z.FusionTag == "SignalFlare")
            {
                float pulse = (MathF.Sin(z.Life * 8f) + 1f) / 2f;
                int outerR = (int)(z.Radius * 2f);
                float outerAlpha = 0.15f + pulse * 0.15f;
                DrawRect((int)(z.Position.X - outerR), (int)(z.Position.Y - outerR), outerR * 2, outerR * 2, new Color(255, 220, 100) * outerAlpha);
                int innerR = (int)(z.Radius * 0.5f);
                DrawRect((int)(z.Position.X - innerR), (int)(z.Position.Y - innerR), innerR * 2, innerR * 2, new Color(255, 250, 200) * 0.7f);
                int coreR = (int)(z.Radius * 0.2f);
                DrawRect((int)(z.Position.X - coreR), (int)(z.Position.Y - coreR), MathHelper.Max(coreR * 2, 2), MathHelper.Max(coreR * 2, 2), Color.White * 0.8f);
            }
            else if (z.FusionTag == "CometCrater")
            {
                float fadeAlpha = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f);
                int seed = (int)(z.Position.X * 31 + z.Position.Y * 97);
                for (int c = 0; c < 3; c++)
                {
                    int h2 = seed + c * 3571;
                    int ox = (h2 * 13 % 10) - 5;
                    int oy = (h2 * 17 % 10) - 5;
                    int sz = r + (h2 * 7 % 8) - 4;
                    Color cc = c == 0 ? new Color(100, 50, 20) : c == 1 ? new Color(140, 70, 30) : new Color(80, 40, 15);
                    DrawRect((int)(z.Position.X - sz + ox), (int)(z.Position.Y - sz + oy), sz * 2, sz * 2, cc * (fadeAlpha * 0.4f));
                }
                float smolder = (MathF.Sin(z.Life * 5f) + 1f) / 2f;
                int glowR = (int)(r * 0.4f);
                DrawRect((int)(z.Position.X - glowR), (int)(z.Position.Y - glowR), glowR * 2, glowR * 2, new Color(255, 120, 40) * (fadeAlpha * 0.3f * smolder));
            }
            else if (z.FusionTag == "ScorchedEarth")
            {
                float fadeAlpha = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f);
                int seed = (int)(z.Position.X * 53 + z.Position.Y * 113);
                for (int c = 0; c < 3; c++)
                {
                    int h2 = seed + c * 2713;
                    int ox = (h2 * 11 % 8) - 4;
                    int oy = (h2 * 19 % 8) - 4;
                    int sz = r / 2 + (h2 * 7 % 6);
                    Color ec = c == 0 ? new Color(90, 70, 50) : c == 1 ? new Color(70, 55, 40) : new Color(110, 85, 60);
                    DrawRect((int)(z.Position.X - sz + ox), (int)(z.Position.Y - sz + oy), sz * 2, sz * 2, ec * (fadeAlpha * 0.45f));
                }
            }
            else if (z.FusionTag == "ZeusCage")
            {
                // Zeus in Chains: crackling electric cage around the target
                float life01 = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f);
                float baseAlpha = life01 * 0.7f;
                int zx = (int)z.Position.X, zy = (int)z.Position.Y;
                float time = _totalTime;
                
                // Outer ring — 8 points forming an octagon cage
                for (int cp = 0; cp < 8; cp++)
                {
                    float a1 = (MathF.PI * 2f / 8) * cp;
                    float a2 = (MathF.PI * 2f / 8) * ((cp + 1) % 8);
                    float wobble1 = r + MathF.Sin(time * 8f + cp * 1.5f) * 3f;
                    float wobble2 = r + MathF.Sin(time * 8f + (cp + 1) * 1.5f) * 3f;
                    int x1 = zx + (int)(MathF.Cos(a1) * wobble1);
                    int y1 = zy + (int)(MathF.Sin(a1) * wobble1);
                    int x2 = zx + (int)(MathF.Cos(a2) * wobble2);
                    int y2 = zy + (int)(MathF.Sin(a2) * wobble2);
                    // Draw line segment as series of pixels
                    int steps = Math.Max(Math.Abs(x2 - x1), Math.Abs(y2 - y1));
                    if (steps < 1) steps = 1;
                    for (int s = 0; s <= steps; s++)
                    {
                        float t2 = (float)s / steps;
                        int px = x1 + (int)((x2 - x1) * t2);
                        int py = y1 + (int)((y2 - y1) * t2);
                        // Crackling: randomly brighten/dim segments
                        float crackle = MathF.Sin(time * 20f + s * 3f + cp * 7f) > 0.3f ? 1f : 0.3f;
                        DrawRect(px, py, 1, 1, new Color(140, 180, 255) * (baseAlpha * crackle));
                    }
                }
                
                // Central electric arcs — random jagged lines through the cage
                int arcSeed = (int)(z.Position.X * 43 + z.Position.Y * 89);
                for (int arc = 0; arc < 3; arc++)
                {
                    float arcAngle = time * 4f + arc * 2.09f + arcSeed;
                    float arcR = r * 0.8f;
                    int ax1 = zx + (int)(MathF.Cos(arcAngle) * arcR);
                    int ay1 = zy + (int)(MathF.Sin(arcAngle) * arcR);
                    int ax2 = zx + (int)(MathF.Cos(arcAngle + MathF.PI) * arcR);
                    int ay2 = zy + (int)(MathF.Sin(arcAngle + MathF.PI) * arcR);
                    // Jagged arc through center
                    int segs = 6;
                    int prevX = ax1, prevY = ay1;
                    for (int s = 1; s <= segs; s++)
                    {
                        float t2 = (float)s / segs;
                        int tx = ax1 + (int)((ax2 - ax1) * t2);
                        int ty = ay1 + (int)((ay2 - ay1) * t2);
                        if (s < segs)
                        {
                            // Jitter perpendicular to the line
                            float jx = MathF.Sin(time * 15f + s * 5f + arc * 3f) * 6f;
                            float jy = MathF.Cos(time * 13f + s * 4f + arc * 2f) * 6f;
                            tx += (int)jx; ty += (int)jy;
                        }
                        int lSteps = Math.Max(Math.Abs(tx - prevX), Math.Abs(ty - prevY));
                        if (lSteps < 1) lSteps = 1;
                        for (int ls = 0; ls <= lSteps; ls++)
                        {
                            float lt = (float)ls / lSteps;
                            DrawRect(prevX + (int)((tx - prevX) * lt), prevY + (int)((ty - prevY) * lt), 1, 1,
                                new Color(200, 220, 255) * (baseAlpha * 0.8f));
                        }
                        prevX = tx; prevY = ty;
                    }
                }
                
                // Ground glow
                float pulse = 0.3f + 0.2f * MathF.Sin(time * 6f);
                DrawRect(zx - r, zy - r, r * 2, r * 2, new Color(80, 120, 200) * (baseAlpha * pulse));
            }
            else if (z.FusionTag == "SuryaScorch")
            {
                // Surya's Wrath scorched earth: burning ground fissures with flame tongues
                float life01 = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f);
                float baseAlpha = life01 * 0.8f;
                int zx = (int)z.Position.X, zy = (int)z.Position.Y;
                int seed = (int)(z.Position.X * 67 + z.Position.Y * 131);
                float time = _totalTime;
                
                // Ground scorch mark — dark charred circle
                DrawRect(zx - r, zy - r, r * 2, r * 2, new Color(40, 20, 10) * (baseAlpha * 0.5f));
                DrawRect(zx - r + 2, zy - r + 2, r * 2 - 4, r * 2 - 4, new Color(60, 30, 15) * (baseAlpha * 0.4f));
                
                // Glowing fissure cracks radiating from center
                for (int cr = 0; cr < 4; cr++)
                {
                    int h = seed + cr * 4729;
                    float angle = (h % 628) / 100f; // pseudo-random angle
                    float crackLen = r * 0.8f + (h % 5) * 2f;
                    float crackPulse = 0.6f + 0.4f * MathF.Sin(time * 6f + cr * 1.7f);
                    Color crackCol = new Color(255, (int)(100 + 60 * crackPulse), 20) * (baseAlpha * crackPulse);
                    // Draw crack as a series of small segments
                    for (int seg = 0; seg < 4; seg++)
                    {
                        float t2 = (seg + 0.5f) / 4f;
                        int cx = zx + (int)(MathF.Cos(angle) * crackLen * t2);
                        int cy = zy + (int)(MathF.Sin(angle) * crackLen * t2);
                        DrawRect(cx, cy, 2, 1, crackCol);
                        DrawRect(cx, cy, 1, 2, crackCol);
                    }
                }
                
                // Flame tongues rising from fissures
                int tongueCount = 3 + (seed % 2);
                for (int ft = 0; ft < tongueCount; ft++)
                {
                    int h = seed + ft * 3571;
                    float ox = ((h * 13 % 20) - 10);
                    float flamePhase = time * (8f + ft * 2f) + ft * 2.3f;
                    float tongueH = (6f + (h % 8)) * life01;
                    float flicker = 0.7f + 0.3f * MathF.Sin(flamePhase);
                    float tongueW = 2f + MathF.Sin(flamePhase * 1.3f) * 1f;
                    int tx = zx + (int)ox;
                    int tBase = zy - 1;
                    
                    // Flame body: orange → yellow → white tip
                    int tH = (int)(tongueH * flicker);
