                    float baseAngle = time * (1.5f + ring * 0.3f);
                    float tiltProgress = 1f - life01;
                    float tiltAngle = MathHelper.Lerp(-0.7f, 0.7f, tiltProgress) + ring * 0.4f;
                    float ySquish = MathF.Abs(MathF.Cos(tiltAngle));
                    ySquish = MathF.Max(ySquish, 0.15f);
                    
                    int segments = 32;
                    for (int s = 0; s < segments; s++)
                    {
                        float a = baseAngle + (MathF.PI * 2f / segments) * s;
                        int rx = zx + (int)(MathF.Cos(a) * ringR);
                        int ry = zy + (int)(MathF.Sin(a) * ringR * ySquish);
                        
                        float segAlpha = 0.4f + 0.3f * MathF.Sin(a * 2f + time * 3f);
                        Color ringCol = ring switch
                        {
                            0 => new Color(255, 240, 180),
                            1 => Color.White,
                            _ => new Color(200, 180, 255),
                        };
                        DrawRect(rx, ry, 2, 2, ringCol * (baseAlpha * segAlpha));
                    }
                }
                
                float formPulse = 0.5f + 0.3f * MathF.Sin(time * 4f);
                DrawRect(zx - 8, zy - 8, 16, 16, new Color(255, 250, 230) * (baseAlpha * formPulse * 0.3f));
                DrawRect(zx - 4, zy - 4, 8, 8, Color.White * (baseAlpha * formPulse * 0.2f));
            }
            else if (z.FusionTag == "Mollificare")
            {
                // Pacification ripples — concentric expanding white circles
                float life01 = MathHelper.Clamp(z.Life / z.MaxLife, 0f, 1f);
                float baseAlpha = life01 * 0.6f;
                int zx = (int)z.Position.X, zy = (int)z.Position.Y;
                float time = _totalTime;
                int zr = (int)z.Radius;
                
                for (int ripple = 0; ripple < 4; ripple++)
                {
                    float phase = (time * 1.5f + ripple * 0.25f) % 1f;
                    float rippleR = zr * phase;
                    float rippleAlpha = baseAlpha * (1f - phase) * 0.5f;
                    
                    int segs = 24;
                    for (int s = 0; s < segs; s++)
                    {
                        float a = (MathF.PI * 2f / segs) * s;
                        int rx = zx + (int)(MathF.Cos(a) * rippleR);
                        int ry = zy + (int)(MathF.Sin(a) * rippleR);
                        DrawRect(rx, ry, 2, 2, new Color(240, 235, 220) * rippleAlpha);
                    }
                }
                
                float centerPulse = 0.4f + 0.2f * MathF.Sin(time * 3f);
                int glowR = zr / 3;
                DrawRect(zx - glowR, zy - glowR, glowR * 2, glowR * 2, new Color(255, 250, 240) * (baseAlpha * centerPulse * 0.3f));
                DrawRect(zx - glowR / 2, zy - glowR / 2, glowR, glowR, Color.White * (baseAlpha * centerPulse * 0.15f));
            }
            else
            {
                DrawRect((int)(z.Position.X - r), (int)(z.Position.Y - r), r * 2, r * 2, z.Color * alpha);
                float pulse = (MathF.Sin(z.Life * 6f) + 1f) / 2f;
                int ir = (int)(r * 0.6f * pulse);
                DrawRect((int)(z.Position.X - ir), (int)(z.Position.Y - ir), ir * 2, ir * 2, z.Color * (alpha * 0.5f));
            }
        }

        // Zeus in Chains: draw lightning tethers between linked enemies
        foreach (var tether in _zeusTethers)
        {
            // Find the two enemies
            Vector2 posA = Vector2.Zero, posB = Vector2.Zero;
            bool foundA = false, foundB = false;
            for (int ei = 0; ei < _enemies.Count; ei++)
            {
                if (_enemies[ei].Id == tether.EnemyIdA) { posA = _enemies[ei].Position; foundA = true; }
                if (_enemies[ei].Id == tether.EnemyIdB) { posB = _enemies[ei].Position; foundB = true; }
                if (foundA && foundB) break;
            }
            if (!foundA || !foundB) continue;

            float life01 = MathHelper.Clamp(tether.Life / tether.MaxLife, 0f, 1f);
            float alpha = life01 * 0.8f;
            float time = _totalTime + tether.ArcPhase;

            // Main lightning bolt: jagged line with 8-10 segments
            int segCount = 8;
            Vector2 dir = posB - posA;
            float len = dir.Length();
            if (len < 1) continue;
            Vector2 dirN = dir / len;
            float perpX = -dirN.Y, perpY = dirN.X;

            // Draw 2 overlapping bolts for thickness
            for (int bolt = 0; bolt < 2; bolt++)
            {
                float boltPhase = time * 18f + bolt * 50f;
                int prevX = (int)posA.X, prevY = (int)posA.Y;
                for (int s = 1; s <= segCount; s++)
                {
                    float t = (float)s / segCount;
                    int baseX = (int)(posA.X + dir.X * t);
                    int baseY = (int)(posA.Y + dir.Y * t);
                    if (s < segCount)
                    {
                        // Jagged offset perpendicular to the line
                        float jitter = MathF.Sin(boltPhase + s * 4.7f) * (8f + len * 0.03f);
                        float jitter2 = MathF.Cos(boltPhase * 0.7f + s * 3.1f) * 4f;
                        baseX += (int)(perpX * jitter + dirN.X * jitter2);
                        baseY += (int)(perpY * jitter + dirN.Y * jitter2);
                    }
                    // Draw line from prev to current
                    int lSteps = Math.Max(Math.Abs(baseX - prevX), Math.Abs(baseY - prevY));
                    if (lSteps < 1) lSteps = 1;
                    Color boltCol = bolt == 0 ? new Color(160, 200, 255) : new Color(220, 240, 255);
                    float boltAlpha = bolt == 0 ? alpha * 0.6f : alpha * 0.9f;
                    for (int ls = 0; ls <= lSteps; ls++)
                    {
                        float lt = (float)ls / lSteps;
                        int px = prevX + (int)((baseX - prevX) * lt);
                        int py = prevY + (int)((baseY - prevY) * lt);
                        DrawRect(px, py, bolt == 0 ? 2 : 1, bolt == 0 ? 2 : 1, boltCol * boltAlpha);
                    }
                    prevX = baseX; prevY = baseY;
                }
            }

            // Glow at connection points
            float pulse = 0.5f + 0.5f * MathF.Sin(time * 10f);
            int gr = (int)(6 * pulse);
            DrawRect((int)posA.X - gr, (int)posA.Y - gr, gr * 2, gr * 2, new Color(100, 150, 255) * (alpha * 0.3f));
            DrawRect((int)posB.X - gr, (int)posB.Y - gr, gr * 2, gr * 2, new Color(100, 150, 255) * (alpha * 0.3f));
        }

        // Hedge walls (Tiamat's Garden)
        foreach (var h in _hedgeWalls)
        {
            float lifePct = MathHelper.Clamp(h.Life / h.MaxLife, 0f, 1f);
            float hpPct = h.Hp / h.MaxHp;
            
            // Autumn transition: last 30% of life shifts green → tan → brown (no alpha fade)
            float autumnProg = lifePct < 0.3f ? 1f - (lifePct / 0.3f) : 0f; // 0 = green, 1 = dead brown
            // Also factor in HP damage
            float decayProg = MathF.Max(autumnProg, 1f - hpPct);
            
            // Grow animation: scale up from ground
            float growProg = h.GrowTimer > 0 ? 1f - (h.GrowTimer / h.GrowDuration) : 1f;
            growProg = growProg * growProg; // ease-in
            
            int drawW = (int)(h.Rect.Width * growProg);
            int drawH = (int)(h.Rect.Height * growProg);
            int drawX = h.Rect.X + (h.Rect.Width - drawW) / 2;
            int drawY = h.Rect.Y + (h.Rect.Height - drawH); // grow upward from base
            
            if (drawW < 2 || drawH < 2) continue;
            
            // Color: green → autumn gold → dead brown
            Color liveBase = new Color(45, 110, 30);
            Color autumnBase = new Color(160, 130, 50);
            Color deadBase = new Color(100, 70, 35);
            Color liveTop = new Color(60, 140, 40);
            Color autumnTop = new Color(180, 150, 60);
            Color deadTop = new Color(120, 85, 45);
            
            Color hedgeBase, hedgeTop, highlightColor;
            if (decayProg < 0.5f)
            {
                float t = decayProg * 2f;
                hedgeBase = Color.Lerp(liveBase, autumnBase, t);
                hedgeTop = Color.Lerp(liveTop, autumnTop, t);
                highlightColor = Color.Lerp(new Color(70, 160, 50), new Color(200, 170, 60), t);
            }
            else
            {
                float t = (decayProg - 0.5f) * 2f;
                hedgeBase = Color.Lerp(autumnBase, deadBase, t);
                hedgeTop = Color.Lerp(autumnTop, deadTop, t);
                highlightColor = Color.Lerp(new Color(200, 170, 60), new Color(130, 90, 50), t);
            }
            
            DrawRect(drawX, drawY, drawW, drawH, hedgeBase);
            DrawRect(drawX + 1, drawY + 1, drawW - 2, drawH - 2, hedgeTop);
            DrawRect(drawX + 2, drawY, drawW - 4, 2, highlightColor * 0.6f);
            
            // Flowers — bigger, visible; charged = double flowers; autumn: shrink/disappear
            if (growProg >= 0.8f && decayProg < 0.7f)
            {
                int seed = (int)(h.Rect.X * 31 + h.Rect.Y * 17);
                int flowerCount = (int)(MathF.Max(h.Rect.Width, h.Rect.Height) / 8f);
                flowerCount = Math.Max(flowerCount, 2);
                if (h.Charged) flowerCount = (int)(flowerCount * 2.5f); // lush charged hedges
                Color[] extraColors = { new Color(200, 40, 60), new Color(220, 180, 40), new Color(140, 50, 180), new Color(40, 120, 200), new Color(240, 120, 60) };
                float flowerFade = 1f - (decayProg / 0.7f);
                for (int f = 0; f < flowerCount; f++)
                {
                    int fx = drawX + 2 + ((seed + f * 7919) % Math.Max(drawW - 6, 1));
                    int fy = drawY + 2 + ((seed + f * 6271) % Math.Max(drawH - 6, 1));
                    Color fc = extraColors[(seed + f) % extraColors.Length];
                    DrawRect(fx - 1, fy, 5, 3, fc * flowerFade);
                    DrawRect(fx, fy - 1, 3, 5, fc * flowerFade);
                    DrawRect(fx, fy, 3, 3, Color.White * (flowerFade * 0.8f));
                    DrawRect(fx + 1, fy + 1, 1, 1, new Color(255, 200, 50) * flowerFade);
                }
            }
            // Dead leaves when autumn is progressing
            if (decayProg > 0.3f && growProg >= 0.5f)
            {
                int leafSeed = (int)(h.Rect.X * 17 + h.Rect.Y * 31);
                int leafCount = (int)(decayProg * 4);
                for (int l = 0; l < leafCount; l++)
                {
                    int lx = drawX + ((leafSeed + l * 4001) % Math.Max(drawW, 1));
                    int ly = drawY + ((leafSeed + l * 2999) % Math.Max(drawH, 1));
                    Color leafColor = (leafSeed + l) % 3 == 0 ? new Color(180, 140, 50) : 
                                      (leafSeed + l) % 3 == 1 ? new Color(140, 95, 40) : new Color(110, 70, 30);
                    DrawRect(lx, ly, 3, 2, leafColor);
                }
            }
            
            // Thorns along edges — charged = more + larger thorns
            if (growProg >= 0.5f)
            {
                int thornSeed = (int)(h.Rect.X * 13 + h.Rect.Y * 7);
                Color thornColor = Color.Lerp(new Color(60, 100, 20), new Color(80, 60, 25), decayProg);
                int thornCount = h.Charged ? 6 : 3;
                int thornH = h.Charged ? 5 : 3;
                for (int t = 0; t < thornCount; t++)
                {
                    int tx = drawX + ((thornSeed + t * 3571) % Math.Max(drawW, 1));
                    DrawRect(tx, drawY - thornH + 1, 2, thornH, thornColor); // top thorns
                    DrawRect(tx + 5, drawY + drawH - 1, 2, thornH, thornColor); // bottom thorns
                    if (h.Charged) // side thorns too
                    {
                        int ty = drawY + ((thornSeed + t * 2741) % Math.Max(drawH, 1));
                        DrawRect(drawX - thornH + 1, ty, thornH, 2, thornColor);
                        DrawRect(drawX + drawW - 1, ty + 3, thornH, 2, thornColor);
                    }
                }
            }
        }
        
        // Particles
        foreach (var pt in _particles)
        {
            float alpha = MathHelper.Clamp(pt.Life / pt.MaxLife, 0f, 1f);
            DrawRect((int)(pt.Position.X - pt.Size / 2), (int)(pt.Position.Y - pt.Size / 2),
                (int)pt.Size, (int)pt.Size, pt.Color * alpha);
        }
        
        // Ether shards
        foreach (var shard in _shards)
        {
            // Colors: 1=cyan, 5=blue, 25=gold
            Color shardColor = shard.Value >= 25 ? new Color(255, 215, 0) :
                               shard.Value >= 5  ? new Color(60, 140, 255) :
                                                    new Color(140, 230, 255);
            Color glowColor = shard.Value >= 25 ? new Color(255, 240, 150) :
                              shard.Value >= 5  ? new Color(120, 180, 255) :
                                                   new Color(200, 245, 255);
            
            // Pulsing glow
            float pulse = (MathF.Sin(_gorgonTime * 6f + shard.Position.X * 0.1f) + 1f) / 2f;
            float fadeAlpha = shard.Life < 2f ? shard.Life / 2f : 1f; // blink before despawn
            
            int sz = shard.Value >= 25 ? 6 : shard.Value >= 5 ? 5 : 4;
            int glowSz = sz + 2;
            
            // Outer glow
            _spriteBatch.Draw(_pixel, new Rectangle(
                (int)(shard.Position.X - glowSz / 2f), (int)(shard.Position.Y - glowSz / 2f), glowSz, glowSz),
                glowColor * (0.2f + 0.15f * pulse) * fadeAlpha);
            // Core diamond (rotated square via 2 overlapping rects)
            _spriteBatch.Draw(_pixel, new Rectangle(
                (int)(shard.Position.X - sz / 2f), (int)(shard.Position.Y - sz / 2f), sz, sz),
                shardColor * (0.8f + 0.2f * pulse) * fadeAlpha);
            // Bright center pixel
            _spriteBatch.Draw(_pixel, new Rectangle(
                (int)(shard.Position.X), (int)(shard.Position.Y), 2, 2),
                Color.White * (0.6f + 0.4f * pulse) * fadeAlpha);
        }

        // Damage numbers (requires Ether Sight relic)
        if (_hasDamageNumbers)
        {
            foreach (var dn in _damageNumbers)
            {
                float alpha = MathHelper.Clamp(dn.Timer / 0.8f, 0f, 1f);
                DrawTextFallback((int)dn.Position.X, (int)dn.Position.Y, $"{dn.Amount:F0}", dn.Color * alpha);
            }
        }

        // Floating combat text (WEAKNESS/RESIST etc.)
        foreach (var ft in _floatingTexts)
        {
            float alpha = MathHelper.Clamp(ft.Life / ft.MaxLife, 0, 1);
            DrawTextFallback((int)ft.Position.X, (int)ft.Position.Y, ft.Text, ft.Color * alpha);
        }

        // Pickup notifications: golden box hover → fly to player
        foreach (var pn in _pickupNotifs)
        {
            float elapsed = PickupNotif.TotalTime - pn.Timer;
            Vector2 drawPos;
            float alpha;
            float scale;

            if (elapsed < PickupNotif.HoverTime)
            {
                // Phase 1: hover above enemy origin, slight float up
                float t = elapsed / PickupNotif.HoverTime;
                drawPos = pn.Origin + new Vector2(0, -20 - t * 15f);
                alpha = MathF.Min(elapsed * 5f, 1f); // quick fade in
                scale = 1f;
            }
            else
            {
                // Phase 2: fly to player with flash
                float t = (elapsed - PickupNotif.HoverTime) / PickupNotif.FlyTime;
                t = t * t; // ease-in (accelerate)
                drawPos = Vector2.Lerp(pn.Origin + new Vector2(0, -35), _playerPos, t);
                alpha = 1f - t * 0.5f;
                scale = 1f + t * 0.5f; // grow slightly as it flies
            }

            int textW = pn.Text.Length * 7;
            int boxW = textW + 12;
            int boxH = 16;
            int bx = (int)(drawPos.X - boxW / 2);
            int by = (int)(drawPos.Y - boxH / 2);

            // Golden box background
            Color boxColor = new Color(40, 35, 15) * alpha;
            Color borderColor = new Color(200, 180, 60) * alpha;
            DrawRect(bx - 1, by - 1, boxW + 2, boxH + 2, borderColor);
            DrawRect(bx, by, boxW, boxH, boxColor);
            // Gold accent line top
            DrawRect(bx, by, boxW, 1, new Color(255, 220, 80) * alpha);
            DrawTextFallback(bx + 6, by + 3, pn.Text, pn.TextColor * alpha);
        }

        // Room number inside arena (only in non-Awakening modes)
        if (_gameMode != GameMode.Awakening)
            DrawTextFallback(_arena.Right - 30, _arena.Bottom - 20, $"{_currentScreen}", new Color(220, 180, 50));

        // Custom reticle at cursor position (gameplay only, not inventory)
        if (_state == GameState.Playing && !_inventoryOpen)
        {
            int mx = (int)_mouseWorld.X, my = (int)_mouseWorld.Y;
            Color essenceColor = _loadout.Essence switch
            {
                Essence.Cinder => new Color(255, 120, 30),
                Essence.Dark => new Color(140, 50, 180),
                Essence.Bone => new Color(220, 210, 190),
                Essence.Silk => new Color(200, 180, 220),
                Essence.Pulse => new Color(80, 180, 255),
                Essence.Hollow => new Color(160, 220, 240),
                Essence.Sap => new Color(80, 180, 60),
                _ => new Color(180, 170, 150), // iron grey when no essence
            };
            Color reticleColor = essenceColor;
            int armLen = 7, gap = 2, thick = 2;
            float rot = 0f;

            if (_currentFusion == "Gungnir")
            { armLen = 7; thick = 1; gap = 3; }
            else if (_currentFusion == "Sacred Fist")
            { armLen = 6; thick = 2; float p = (MathF.Sin(_totalTime * 10f) + 1f) / 2f; reticleColor = Color.Lerp(essenceColor, Color.White, p * 0.4f); }
            else if (_currentFusion == "Shadow Stitch")
            { rot = _totalTime * 1.5f; reticleColor = new Color(100, 40, 140); }

            if (rot != 0f)
            {
                for (int arm = 0; arm < 4; arm++)
                {
                    float baseAngle = arm * MathF.PI / 2f;
                    float ax = MathF.Cos(baseAngle + rot), ay = MathF.Sin(baseAngle + rot);
                    for (int d = gap; d <= gap + armLen; d++)
                        DrawRect(mx + (int)(ax * d), my + (int)(ay * d), thick, thick, reticleColor * 0.9f);
                }
            }
            else
            {
                // Outline for visibility
                Color outlineCol = Color.Black * 0.9f;
                DrawRect(mx - 1, my - gap - armLen - 1, thick + 2, armLen + 2, outlineCol);
                DrawRect(mx - 1, my + gap, thick + 2, armLen + 2, outlineCol);
                DrawRect(mx - gap - armLen - 1, my - 1, armLen + 2, thick + 2, outlineCol);
                DrawRect(mx + gap, my - 1, armLen + 2, thick + 2, outlineCol);
                DrawRect(mx, my - gap - armLen, thick, armLen, reticleColor);
                DrawRect(mx, my + gap + 1, thick, armLen, reticleColor);
                DrawRect(mx - gap - armLen, my, armLen, thick, reticleColor);
                DrawRect(mx + gap + 1, my, armLen, thick, reticleColor);
            }
            DrawRect(mx, my, 1, 1, Color.White * 0.4f);
            
            // Soft glow around cursor (blooms nicely with post-processing)
            DrawRect(mx - 6, my - 6, 13, 13, reticleColor * 0.04f);
            DrawRect(mx - 4, my - 4, 9, 9, reticleColor * 0.06f);
            DrawRect(mx - 2, my - 2, 5, 5, reticleColor * 0.08f);
        }

        // End camera-transformed batch
        _spriteBatch.End();

        // ═══ LIGHTING PASS — Draw light mask, then composite with scene ═══
        if (_lightGradient != null && (_state == GameState.Playing || _state == GameState.Paused))
        {
            // 1. Draw light mask to _lightRT
            GraphicsDevice.SetRenderTarget(_lightRT);
            GraphicsDevice.Clear(Color.Black); // start fully dark
            
            // Use same camera transform as scene
            var lightCamMatrix = Matrix.CreateTranslation(_transitionOffset.X + _shakeX - _cameraOffset.X, _transitionOffset.Y + _shakeY - _cameraOffset.Y, 0);
            if (_finisherActive)
            {
                lightCamMatrix = lightCamMatrix *
                    Matrix.CreateTranslation(-_finisherTarget.X, -_finisherTarget.Y, 0) *
                    Matrix.CreateScale(_finisherZoom) *
                    Matrix.CreateTranslation(_finisherTarget.X, _finisherTarget.Y, 0);
            }
            
            _spriteBatch.Begin(blendState: BlendState.Additive, samplerState: SamplerState.LinearClamp,
                transformMatrix: lightCamMatrix);
            
            // Per-room ambient base — faint fullscreen fill so nothing is pure black
            // Ambient fill — must cover entire world area visible through camera (not just screen coords)
            int ambPad = 500;
            _spriteBatch.Draw(_pixel, new Rectangle(-ambPad, (int)_cameraOffset.Y - ambPad, ScreenW + ambPad * 2, ScreenH + ambPad * 2), Color.White * _ambientLight);
            
            // Player glow — gated behind Lambent Aura relic
            if (_hasLambentAura)
            {
                int playerRadius = 250 - (int)(_jumpHeight * 1.5f); // shrinks when jumping
                if (playerRadius < 120) playerRadius = 120;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(_playerPos.X - playerRadius), (int)(_playerPos.Y - playerRadius),
                    playerRadius * 2, playerRadius * 2), Color.White * 0.9f);
            }
            
            // Cursor glow — small light so you can see where you're aiming
            {
                int cursorRad = 60;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(_mouseWorld.X - cursorRad), (int)(_mouseWorld.Y - cursorRad),
                    cursorRad * 2, cursorRad * 2), Color.White * 0.4f);
            }
            
            // Torch lights — draw multiple stacked layers for bright, smooth glow
            for (int i = 0; i < _torches.Count; i++)
            {
                int tRadius = 350 + (int)(MathF.Sin(_totalTime * 3f + i) * 25f);
                Color torchCol = Color.Lerp(new Color(255, 180, 80), new Color(255, 140, 50), 
                    0.5f + 0.5f * MathF.Sin(_totalTime * 5f + i * 2f));
                // Core bright glow — large
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(_torches[i].X - tRadius), (int)(_torches[i].Y - tRadius),
                    tRadius * 2, tRadius * 2), torchCol * 1f);
                // Inner hot glow — smaller, stacked for brightness
                int innerRad = tRadius * 2 / 3;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(_torches[i].X - innerRad), (int)(_torches[i].Y - innerRad),
                    innerRad * 2, innerRad * 2), Color.White * 0.5f);
                // Second stack for extra brightness near center
                int coreRad = tRadius / 3;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(_torches[i].X - coreRad), (int)(_torches[i].Y - coreRad),
                    coreRad * 2, coreRad * 2), Color.White * 0.4f);
            }
            
            // Lava glow (Room 8) — large overlapping glows for full moat coverage
            if (_currentScreen == 8)
            {
                Color lavaGlow = new Color(255, 100, 20);
                // One big glow covering the entire moat area
                int moatCX = _arena.Left + 180 + 330; // center of moat
                int moatCY = _arena.Top + 120 + 170;
                int bigRad = 500;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    moatCX - bigRad, moatCY - bigRad,
                    bigRad * 2, bigRad * 2), lavaGlow * 0.9f);
                // Extra glows at moat corners to ensure full coverage
                foreach (var lr in _lavaRects)
                {
                    int lRad = (int)(MathF.Max(lr.Width, lr.Height) * 1.2f);
                    _spriteBatch.Draw(_lightGradient, new Rectangle(
                        lr.Center.X - lRad, lr.Center.Y - lRad,
                        lRad * 2, lRad * 2), lavaGlow * 0.5f);
                }
                // Boss lava pools
                for (int i = 0; i < _bossLavaPools.Count; i++)
                {
                    var bp = _bossLavaPools[i];
                    if (bp.FadeTimer > 0) continue;
                    int bpRad = (int)(MathF.Max(bp.Rect.Width, bp.Rect.Height) * 0.8f);
                    _spriteBatch.Draw(_lightGradient, new Rectangle(
                        bp.Rect.Center.X - bpRad, bp.Rect.Center.Y - bpRad,
                        bpRad * 2, bpRad * 2), lavaGlow * 0.6f);
                }
            }
            
            // Projectile lights — each active projectile emits a small glow
            for (int i = 0; i < _projectiles.Count; i++)
            {
                var proj = _projectiles[i];
                if (!proj.Alive) continue;
                Color projCol = proj.Params.EssenceType switch
                {
                    Essence.Cinder => new Color(255, 160, 40),
                    Essence.Pulse => new Color(80, 180, 255),
                    Essence.Bone => new Color(220, 200, 170),
                    Essence.Silk => new Color(140, 200, 140),
                    Essence.Dark => new Color(120, 60, 180),
                    Essence.Hollow => new Color(200, 220, 255),
                    Essence.Sap => new Color(100, 180, 60),
                    _ => new Color(200, 200, 210),
                };
                
                if (proj.BeamLen > 0 && proj.BeamDirection.LengthSquared() > 0)
                {
                    // Beam/lance — emit glows along the beam length
                    Vector2 dir = Vector2.Normalize(proj.BeamDirection);
                    float len = proj.BeamLen;
                    int steps = Math.Max(4, (int)(len / 40f));
                    for (int s = 0; s <= steps; s++)
                    {
                        float t = (float)s / steps;
                        Vector2 pt = proj.Position + dir * len * t;
                        int bRad = 150;
                        _spriteBatch.Draw(_lightGradient, new Rectangle(
                            (int)(pt.X - bRad), (int)(pt.Y - bRad),
                            bRad * 2, bRad * 2), projCol * 1f);
                    }
                }
                else
                {
                    // Normal projectile — single point glow
                    int pRad = 90 + (int)(proj.Params.Size * 4);
                    _spriteBatch.Draw(_lightGradient, new Rectangle(
                        (int)(proj.Position.X - pRad), (int)(proj.Position.Y - pRad),
                        pRad * 2, pRad * 2), projCol * 0.8f);
                }
            }
            
            // Enemy glow — faint, element-colored
            for (int i = 0; i < _enemies.Count; i++)
            {
                var en = _enemies[i];
                if (!en.Alive) continue;
                int eRad = (int)(en.Size * 1.5f);
                Color eCol = en.ElementType switch
                {
                    Essence.Cinder => new Color(255, 140, 40),
                    Essence.Pulse => new Color(80, 160, 255),
                    Essence.Bone => new Color(200, 180, 150),
                    Essence.Silk => new Color(120, 180, 120),
                    Essence.Dark => new Color(100, 50, 160),
                    Essence.Hollow => new Color(160, 180, 220),
                    Essence.Sap => new Color(80, 150, 50),
                    _ => new Color(150, 150, 160),
                };
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(en.Position.X - eRad), (int)(en.Position.Y - eRad),
                    eRad * 2, eRad * 2), eCol * 0.4f);
            }
            
            // Linger zone glow
            for (int i = 0; i < _lingerZones.Count; i++)
            {
                var lz = _lingerZones[i];
                if (lz.Life <= 0) continue;
                int lRad = (int)(lz.Radius * 1.8f);
                float lAlpha = MathF.Min(lz.Life / lz.MaxLife, 1f) * 0.6f;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(lz.Position.X - lRad), (int)(lz.Position.Y - lRad),
                    lRad * 2, lRad * 2), lz.Color * lAlpha);
            }
            
            // Particle glow (only bright/large particles — skip tiny ones for perf)
            for (int i = 0; i < _particles.Count; i++)
            {
                var part = _particles[i];
                if (part.Size < 3f || part.Life <= 0) continue;
                int partRad = (int)(part.Size * 4);
                float partAlpha = (part.Life / part.MaxLife) * 0.2f;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(part.Position.X - partRad), (int)(part.Position.Y - partRad),
                    partRad * 2, partRad * 2), part.Color * partAlpha);
            }
            
            // Essence crystal glow (Room 6)
            for (int i = 0; i < _essenceCrystals.Count; i++)
            {
                var crys = _essenceCrystals[i];
                if (crys.Collected || crys.Hidden) continue;
                int cRad = 120;
                _spriteBatch.Draw(_lightGradient, new Rectangle(
                    (int)(crys.Position.X - cRad), (int)(crys.Position.Y - cRad),
                    cRad * 2, cRad * 2), crys.CrystalColor * 0.7f);
            }
            
            _spriteBatch.End();
            
            // 2. Composite: scene × light mask
            GraphicsDevice.SetRenderTarget(_sceneRT); // draw BACK onto scene RT
            // We need to read _sceneRT but also write to it — use a temp copy
            // Actually: read _sceneRT into shader, output to backbuffer... 
            // But we need post-processing after. Let's write to a temp approach:
            // Just apply the light mask as a multiply blend on top of scene RT.
            _spriteBatch.Begin(blendState: new BlendState
            {
                ColorSourceBlend = Blend.Zero,
                ColorDestinationBlend = Blend.SourceColor,
                ColorBlendFunction = BlendFunction.Add,
                AlphaSourceBlend = Blend.Zero,
                AlphaDestinationBlend = Blend.One,
            }, samplerState: SamplerState.LinearClamp);
            _spriteBatch.Draw(_lightRT, Vector2.Zero, Color.White);
            _spriteBatch.End();
        }

        // Apply post-processing to the game world BEFORE HUD
        if (_postProcessEnabled)
        {
            GraphicsDevice.SetRenderTarget(null);
            ApplyPostProcessing();
        }

        // ═══ Biome Color Tint — per-room atmosphere ═══
        if (_gameMode == GameMode.Awakening && !_inTransition)
        {
            _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
            Color biomeTint = _currentScreen switch
            {
                1 => new Color(140, 160, 200),  // Gauntlet — cold steel blue
                2 => new Color(180, 170, 150),  // Armory — warm stone
                3 => new Color(120, 180, 110),  // Proving Grounds — overgrown green
                4 => new Color(160, 150, 180),  // Crypt — faded purple
                5 => new Color(150, 170, 160),  // Caverns — mossy grey-green
                6 => new Color(100, 180, 190),  // Wellspring — deep aqua
                7 => new Color(200, 170, 100),  // Shrine — warm amber
                8 => new Color(200, 120, 80),   // Forge — lava orange
                9 => new Color(150, 100, 180),  // Boss — ominous purple
                _ => new Color(160, 160, 160),  // neutral
            };
            // Tint: overlay the inverse color at low opacity
            // Darkens channels that are LOW in the tint, preserving the dominant hue
            float tintStrength = 0.12f;
            Color overlay = new Color(255 - biomeTint.R, 255 - biomeTint.G, 255 - biomeTint.B);
            _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), overlay * tintStrength);
            _spriteBatch.End();
        }

        // HUD: untransformed, drawn AFTER post-processing (no vignette/bloom on HUD)
        // World-space elements that need camera transform (drawn after post-process so no bloom/vignette)
        {
            var hudCam = Matrix.CreateTranslation(-_cameraOffset.X, -_cameraOffset.Y, 0);
            _spriteBatch.Begin(samplerState: SamplerState.PointClamp, transformMatrix: hudCam);
            if (_gameMode == GameMode.Awakening)
            {
                if (!_inventoryOpen && _screenTransitionTimer <= 0) DrawPickups();
                DrawEtherDrops();
                DrawTripwires();
            }
            _spriteBatch.End();
        }
        // Screen-space HUD (no camera transform)
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        DrawHUD();
        if (_gameMode == GameMode.Awakening)
        {
            DrawRoomName();
        }
        DrawRoom3Overlay();
        DrawRoom8Reveal();
        DrawTextBox(); // always on top

        // Screen transition: subtle vignette during scroll
        if (_inTransition)
        {
            float t = _screenTransitionTimer / ScreenTransitionDuration;
            float flash = MathF.Sin(t * MathF.PI) * 0.3f;
            _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), Color.Black * flash);
        }
        
        // Damage red flash overlay
        if (_damageFlashTimer > 0)
        {
            float flashAlpha = _damageFlashTimer / 0.25f * 0.35f;
            _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), new Color(255, 0, 0) * flashAlpha);
        }
        
        // Portal fade transition
        if (_portalTransitioning && _portalTransitionTimer > 0)
        {
            float progress = 1f - (_portalTransitionTimer / 0.6f);
            float alpha = progress < 0.5f ? progress * 2f : (1f - progress) * 2f;
            _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), Color.Black * alpha);
        }
        
        // Pause overlay
        if (_state == GameState.Paused)
        {
            _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), Color.Black * 0.6f);
            var tf = _titleFont ?? _font;
            
            DrawTextCenteredOutlined(ScreenH / 2 - 80, "PAUSED", Color.White, Color.Black, 2.5f, tf, 2);
            
            string[] pauseOpts = { "Resume", "Mode Select", "Quit" };
            for (int i = 0; i < pauseOpts.Length; i++)
            {
                int y = ScreenH / 2 - 10 + i * 35;
                bool sel = i == _pauseSelection;
                Color c = sel ? Color.Lerp(new Color(255, 215, 0), Color.White, (MathF.Sin(_titleTimer * 4f) + 1f) / 2f * 0.3f) : new Color(100, 100, 110);
                int ow = MeasureText(pauseOpts[i], 1f, tf);
                if (sel) DrawTextOutlined(ScreenW / 2 - ow / 2 - 15, y, ">", c, Color.Black, 1f, tf);
                DrawTextOutlined(ScreenW / 2 - ow / 2, y, pauseOpts[i], c, Color.Black, 1f, tf);
            }
        }

        _spriteBatch.End();
        DrawPixelCursor();
        base.Draw(_currentGameTime);
    }

    private void FinalizeFrame()
    {
        if (_postProcessEnabled)
        {
            GraphicsDevice.SetRenderTarget(null);
            ApplyPostProcessing();
        }
        base.Draw(_currentGameTime);
    }

    private void ApplyPostProcessing()
    {
        if (_shadersAvailable)
            ApplyShaderPostProcessing();
        else
            ApplyCpuPostProcessing();
    }

    private void ApplyShaderPostProcessing()
    {
        // Step 1: Extract bright pixels (half-res)
        GraphicsDevice.SetRenderTarget(_bloomExtractRT);
        GraphicsDevice.Clear(Color.Black);
        _postProcessEffect.CurrentTechnique = _postProcessEffect.Techniques["BrightnessExtract"];
        _postProcessEffect.Parameters["BloomThreshold"].SetValue(_bloomThreshold);
        _spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.Opaque, SamplerState.LinearClamp, null, null, _postProcessEffect);
        _spriteBatch.Draw(_sceneRT, new Rectangle(0, 0, 640, 360), Color.White);
        _spriteBatch.End();

        // Step 2: Horizontal blur
        GraphicsDevice.SetRenderTarget(_bloomRT1);
        GraphicsDevice.Clear(Color.Black);
        _postProcessEffect.CurrentTechnique = _postProcessEffect.Techniques["GaussianBlur"];
        _postProcessEffect.Parameters["BlurDirection"].SetValue(new Vector2(1f / 640f, 0));
        _spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.Opaque, SamplerState.LinearClamp, null, null, _postProcessEffect);
        _spriteBatch.Draw(_bloomExtractRT, new Rectangle(0, 0, 320, 180), Color.White);
        _spriteBatch.End();

        // Step 3: Vertical blur
        GraphicsDevice.SetRenderTarget(_bloomRT2);
        GraphicsDevice.Clear(Color.Black);
        _postProcessEffect.Parameters["BlurDirection"].SetValue(new Vector2(0, 1f / 180f));
        _spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.Opaque, SamplerState.LinearClamp, null, null, _postProcessEffect);
        _spriteBatch.Draw(_bloomRT1, new Rectangle(0, 0, 160, 90), Color.White);
        _spriteBatch.End();

        // Step 4: Composite — scene + bloom + vignette + IGN
        GraphicsDevice.SetRenderTarget(null);
        GraphicsDevice.Clear(Color.Black);
        _postProcessEffect.CurrentTechnique = _postProcessEffect.Techniques["Composite"];
        _postProcessEffect.Parameters["BloomIntensity"].SetValue(_bloomIntensity);
        _postProcessEffect.Parameters["VignetteRadius"].SetValue(1.1f);
        _postProcessEffect.Parameters["VignetteSmooth"].SetValue(0.55f);
        float vx = (_state == GameState.Playing || _state == GameState.Paused) ? (_playerPos.X - _cameraOffset.X) / 1280f : 0.5f;
        float vy = (_state == GameState.Playing || _state == GameState.Paused) ? (_playerPos.Y - _cameraOffset.Y) / 720f : 0.5f;
        _postProcessEffect.Parameters["VignetteCenter"].SetValue(new Vector2(vx, vy));
        _postProcessEffect.Parameters["Time"].SetValue(_totalTime);

        // Set bloom texture on sampler 1
        GraphicsDevice.Textures[1] = _bloomRT2;
        GraphicsDevice.SamplerStates[1] = SamplerState.LinearClamp;

        _spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.Opaque, SamplerState.PointClamp, null, null, _postProcessEffect);
        _spriteBatch.Draw(_sceneRT, new Rectangle(0, 0, 1280, 720), Color.White);
        _spriteBatch.End();
    }

    private void ApplyCpuPostProcessing()
    {
        // Step 1: Downscale scene to quarter-res (natural box-filter blur)
        GraphicsDevice.SetRenderTarget(_bloomRT1);
        GraphicsDevice.Clear(Color.Black);
        _spriteBatch.Begin(samplerState: SamplerState.LinearClamp);
        _spriteBatch.Draw(_sceneRT, new Rectangle(0, 0, 320, 180), Color.White);
        _spriteBatch.End();
        
        // Step 2: Downscale again to eighth-res (more blur)
        GraphicsDevice.SetRenderTarget(_bloomRT2);
        GraphicsDevice.Clear(Color.Black);
        _spriteBatch.Begin(samplerState: SamplerState.LinearClamp);
        _spriteBatch.Draw(_bloomRT1, new Rectangle(0, 0, 160, 90), Color.White);
        _spriteBatch.End();
        
        // Step 3: Upscale back to quarter-res (smooths further)
        GraphicsDevice.SetRenderTarget(_bloomRT1);
        GraphicsDevice.Clear(Color.Black);
        _spriteBatch.Begin(samplerState: SamplerState.LinearClamp);
        _spriteBatch.Draw(_bloomRT2, new Rectangle(0, 0, 320, 180), Color.White);
        _spriteBatch.End();
        
        // Step 4: Draw scene + bloom + vignette to backbuffer
        GraphicsDevice.SetRenderTarget(null);
        GraphicsDevice.Clear(Color.Black);
        
        // Base scene
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        _spriteBatch.Draw(_sceneRT, new Rectangle(0, 0, 1280, 720), Color.White);
        _spriteBatch.End();
        
        // Bloom overlay (additive blend, upscaled = soft glow)
        byte bloomAlpha = (byte)MathHelper.Clamp(_bloomIntensity * 255, 0, 255);
        _spriteBatch.Begin(blendState: BlendState.Additive, samplerState: SamplerState.LinearClamp);
        _spriteBatch.Draw(_bloomRT1, new Rectangle(0, 0, 1280, 720), new Color(bloomAlpha, bloomAlpha, bloomAlpha, bloomAlpha));
        _spriteBatch.End();
        
        // Screen cracks — radial fracture lines from impact point
        if (_screenCracks.Count > 0)
        {
            _spriteBatch.Begin(blendState: BlendState.Additive, samplerState: SamplerState.PointClamp);
            foreach (var sc in _screenCracks)
        {
            float alpha = MathHelper.Clamp(sc.Timer / sc.MaxTime, 0, 1);
            // Outer glow cracks (wide, faint violet)
            for (int r = 0; r < 16; r++)
            {
                float angle = (MathF.PI * 2f / 16f) * r + sc.Origin.X * 0.01f; // slight seed offset
                float len = 60f + (r % 3) * 35f + (r % 5) * 20f; // varied lengths — longer
                Vector2 crackDir = new Vector2(MathF.Cos(angle), MathF.Sin(angle));
                // Draw crack as series of small rects
                for (int seg = 0; seg < (int)(len / 3); seg++)
                {
                    float t = seg * 3f;
                    Vector2 pos = sc.Origin + crackDir * t;
                    // Jitter the crack slightly
                    float jitter = MathF.Sin(t * 0.5f + angle * 3f) * 2f;
                    Vector2 perp = new Vector2(-crackDir.Y, crackDir.X) * jitter;
                    pos += perp;
                    float segAlpha = alpha * (1f - t / len); // fade toward tips
                    Color col = Color.Lerp(Color.White, new Color(160, 120, 220), t / len) * segAlpha;
                    DrawRect((int)(pos.X - 2), (int)(pos.Y - 2), 4, 4, col);
                    // Wider glow behind
                    DrawRect((int)(pos.X - 4), (int)(pos.Y - 4), 8, 8, new Color(140, 100, 200) * (segAlpha * 0.35f));
                }
            }
            // Bright white center flash (fades faster)
            float centerAlpha = MathHelper.Clamp(sc.Timer / (sc.MaxTime * 0.3f), 0, 1) * alpha;
            DrawRect((int)(sc.Origin.X - 10), (int)(sc.Origin.Y - 10), 20, 20, Color.White * centerAlpha);
            DrawRect((int)(sc.Origin.X - 16), (int)(sc.Origin.Y - 16), 32, 32, new Color(200, 180, 255) * (centerAlpha * 0.5f));
            }
            _spriteBatch.End();
        }
        
        // Vignette overlay
        float vigOffsetX = 0, vigOffsetY = 0;
        if (_state == GameState.Playing)
        {
            vigOffsetX = ((_playerPos.X - _cameraOffset.X) - 640f) * 0.3f; // 30% follow
            vigOffsetY = ((_playerPos.Y - _cameraOffset.Y) - 360f) * 0.3f;
        }
        // Vignette fades out at high ambient light (daytime) — full strength only at night
        float vigScale = 1f - _ambientLight * 0.6f; // at ambient=1.0 (full day), vignette is 40% strength
        byte vigAlpha = (byte)MathHelper.Clamp(_vignetteStrength * vigScale * 255, 0, 255);
        _spriteBatch.Begin(blendState: BlendState.AlphaBlend, samplerState: SamplerState.LinearClamp);
        _spriteBatch.Draw(_vignetteTexture, 
            new Rectangle((int)vigOffsetX - 100, (int)vigOffsetY - 100, 1280 + 200, 720 + 200), 
            new Color((int)255, (int)255, (int)255, (int)vigAlpha));
        _spriteBatch.End();
    }

    private Texture2D GenerateVignetteTexture(int w, int h)
    {
        var tex = new Texture2D(GraphicsDevice, w, h);
        var data = new Color[w * h];
        float cx = w / 2f, cy = h / 2f;
        float maxDist = MathF.Sqrt(cx * cx + cy * cy);
        for (int y = 0; y < h; y++)
        {
            for (int x = 0; x < w; x++)
            {
                float dx = (x - cx) / cx; // normalized -1 to 1
                float dy = (y - cy) / cy;
                float dist = MathF.Sqrt(dx * dx + dy * dy);
                // Smooth falloff from center
                float v = MathHelper.Clamp((dist - 0.3f) / 1.0f, 0f, 1f);
                v = v * v; // quadratic falloff for smoother look
                byte alpha = (byte)(v * 255);
                data[y * w + x] = new Color((int)0, (int)0, (int)0, (int)alpha);
            }
        }
        tex.SetData(data);
        return tex;
    }
    
    private Texture2D GenerateNoiseTexture(int width, int height, int seed = 42)
    {
        var tex = new Texture2D(GraphicsDevice, width, height);
        var data = new Color[width * height];
        var noiseRng = new Random(seed);
        
        // Multi-octave tileable value noise
        // Wide texture (256×128) bakes horizontal stretch — no runtime distortion needed
        int[] gridW = { 4, 8, 16 };   // grid cells in X per octave
        int[] gridH = { 4, 8, 16 };   // grid cells in Y per octave
        float[] amplitudes = { 0.6f, 0.3f, 0.1f };
        
        float[,] values = new float[height, width];
        
        for (int oct = 0; oct < gridW.Length; oct++)
        {
            int gw = gridW[oct];
            int gh = gridH[oct];
            float amp = amplitudes[oct];
            
            float[,] grid = new float[gh, gw];
            for (int gy = 0; gy < gh; gy++)
                for (int gx = 0; gx < gw; gx++)
                    grid[gy, gx] = (float)noiseRng.NextDouble();
            
            for (int y = 0; y < height; y++)
            {
                for (int x = 0; x < width; x++)
                {
                    float fx = (float)x / width * gw;
                    float fy = (float)y / height * gh;
                    int gx0 = (int)fx;
                    int gy0 = (int)fy;
                    int gx1 = (gx0 + 1) % gw;
                    int gy1 = (gy0 + 1) % gh;
                    float tx = fx - gx0;
                    float ty = fy - gy0;
                    // Quintic smoothstep
                    tx = tx * tx * tx * (tx * (tx * 6f - 15f) + 10f);
                    ty = ty * ty * ty * (ty * (ty * 6f - 15f) + 10f);
                    float v = grid[gy0, gx0] * (1 - tx) * (1 - ty)
                            + grid[gy0, gx1] * tx * (1 - ty)
                            + grid[gy1, gx0] * (1 - tx) * ty
                            + grid[gy1, gx1] * tx * ty;
                    values[y, x] += v * amp;
                }
            }
        }
        
        // Normalize and contrast
        float min = float.MaxValue, max = float.MinValue;
        for (int y = 0; y < height; y++)
            for (int x = 0; x < width; x++)
            {
                if (values[y, x] < min) min = values[y, x];
                if (values[y, x] > max) max = values[y, x];
            }
        float range = max - min;
        if (range < 0.001f) range = 1f;
        
        for (int y = 0; y < height; y++)
        {
            for (int x = 0; x < width; x++)
            {
                float v = (values[y, x] - min) / range;
                v = v * v * (3f - 2f * v); // S-curve
                v = v * v * (3f - 2f * v); // double for strong contrast
                
                // Cull extremes: very dark and very bright become transparent
                // Keeps the mid-range "interesting" water caustic look
                float alpha = 1f;
                if (v < 0.15f)
                    alpha = v / 0.15f;           // fade out darks
                else if (v > 0.85f)
                    alpha = (1f - v) / 0.15f;    // fade out brights
                alpha = MathHelper.Clamp(alpha, 0f, 1f);
                
                byte b = (byte)(v * 255);
                byte a = (byte)(alpha * 255);
                data[y * width + x] = new Color(b, b, b, (int)a);
            }
        }
        tex.SetData(data);
        return tex;
    }
    
    private void DrawScrollingNoiseWater(int x, int y, int w, int h, float time)
    {
        if (_noiseTexture == null) return;
        
        // Draw base dark water color
        DrawRect(x, y, w, h, new Color(15, 35, 70));
        
        // Pool floor — stone tile pattern
        int tileSize = 32;
        for (int ty2 = y; ty2 < y + h; ty2 += tileSize)
        {
            for (int tx2 = x; tx2 < x + w; tx2 += tileSize)
            {
                int tw = Math.Min(tileSize, x + w - tx2);
                int th = Math.Min(tileSize, y + h - ty2);
                bool light = ((tx2 / tileSize) + (ty2 / tileSize)) % 2 == 0;
                Color floorCol = light ? new Color(25, 45, 65) : new Color(18, 35, 55);
                DrawRect(tx2, ty2, tw, th, floorCol);
                DrawRect(tx2, ty2, tw, 1, new Color(12, 25, 40));
                DrawRect(tx2, ty2, 1, th, new Color(12, 25, 40));
            }
        }
        
        // === Noise layers on top (flat, scissor clipped) ===
        _spriteBatch.End();
        
        var prevScissor = GraphicsDevice.ScissorRectangle;
        var scissorRaster = new RasterizerState { ScissorTestEnable = true };
        GraphicsDevice.ScissorRectangle = new Rectangle(x, y, w, h);
        _spriteBatch.Begin(samplerState: SamplerState.LinearWrap, rasterizerState: scissorRaster);
        
        float noiseScale = 4f;
        int texW = (int)(_noiseTexture.Width * noiseScale);
        int texH = (int)(_noiseTexture.Height * noiseScale);
        
        // Layer 1: scrolls left and upward
        float off1X = (time * -14f) % texW;
        float off1Y = (time * -9f) % texH;
        if (off1X > 0) off1X -= texW;
        if (off1Y > 0) off1Y -= texH;
        
        for (float ny = y + off1Y; ny < y + h; ny += texH)
            for (float nx = x + off1X; nx < x + w; nx += texW)
                _spriteBatch.Draw(_noiseTexture, new Vector2(nx, ny), null, new Color(50, 130, 180) * 0.6f, 0f, Vector2.Zero, noiseScale, SpriteEffects.None, 0f);
        
        // Layer 2: scrolls left and downward
        float off2X = (time * -11f) % texW;
        float off2Y = (time * 12f) % texH;
        if (off2X > 0) off2X -= texW;
        if (off2Y > 0) off2Y -= texH;
        
        for (float ny = y + off2Y; ny < y + h; ny += texH)
            for (float nx = x + off2X; nx < x + w; nx += texW)
                _spriteBatch.Draw(_noiseTexture2, new Vector2(nx, ny), null, new Color(40, 110, 170) * 0.5f, 0f, Vector2.Zero, noiseScale, SpriteEffects.None, 0f);
        
        _spriteBatch.End();
        GraphicsDevice.ScissorRectangle = prevScissor;
        
        // Restart caller's batch
        float shake = _trauma * _trauma;
        float sx = MathF.Sin(100f + _noiseTime * 25f) * shake * 8f;
        float sy = MathF.Sin(200f + _noiseTime * 30f) * shake * 8f;
        var cameraMatrix = Matrix.CreateTranslation(sx + _transitionOffset.X - _cameraOffset.X, sy + _transitionOffset.Y - _cameraOffset.Y, 0);
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp, transformMatrix: cameraMatrix);
    }
    
    private void DrawScrollingNoiseLava(int x, int y, int w, int h, float time)
    {
        if (_noiseTexture == null) return;
        
        // Solid opaque lava base — hot orange
        DrawRect(x, y, w, h, new Color(180, 60, 15));
        
        // 3 noise layers at different scales to hide tiling seams
        _spriteBatch.End();
        
        var prevScissor = GraphicsDevice.ScissorRectangle;
        var scissorRaster = new RasterizerState { ScissorTestEnable = true };
        GraphicsDevice.ScissorRectangle = new Rectangle(x, y, w, h);
        _spriteBatch.Begin(samplerState: SamplerState.LinearWrap, rasterizerState: scissorRaster);
        
        // Layer 1: large scale, slow drift — broad molten flow
        float scale1 = 5f;
        int texW1 = (int)(_noiseTexture.Width * scale1);
        int texH1 = (int)(_noiseTexture.Height * scale1);
        float off1X = (time * -3f) % texW1;
        float off1Y = (time * -2f) % texH1;
        if (off1X > 0) off1X -= texW1;
        if (off1Y > 0) off1Y -= texH1;
        for (float ny = y + off1Y; ny < y + h; ny += texH1)
            for (float nx = x + off1X; nx < x + w; nx += texW1)
                _spriteBatch.Draw(_noiseTexture, new Vector2(nx, ny), null, new Color(200, 70, 15) * 0.9f, 0f, Vector2.Zero, scale1, SpriteEffects.None, 0f);
        
        // Layer 2: medium scale, counter-drift — magma veins
        float scale2 = 3f;
        int texW2 = (int)(_noiseTexture2.Width * scale2);
        int texH2 = (int)(_noiseTexture2.Height * scale2);
        float off2X = (time * 2f) % texW2;
        float off2Y = (time * -1.5f) % texH2;
        if (off2X > 0) off2X -= texW2;
        if (off2Y > 0) off2Y -= texH2;
        for (float ny = y + off2Y; ny < y + h; ny += texH2)
            for (float nx = x + off2X; nx < x + w; nx += texW2)
                _spriteBatch.Draw(_noiseTexture2, new Vector2(nx, ny), null, new Color(255, 140, 30) * 0.6f, 0f, Vector2.Zero, scale2, SpriteEffects.None, 0f);
        
        // Layer 3: small scale, diagonal drift — surface shimmer (breaks tiling)
        float scale3 = 2f;
        int texW3 = (int)(_noiseTexture.Width * scale3);
        int texH3 = (int)(_noiseTexture.Height * scale3);
        float off3X = (time * 1.5f) % texW3;
        float off3Y = (time * 2.5f) % texH3;
        if (off3X > 0) off3X -= texW3;
        if (off3Y > 0) off3Y -= texH3;
        for (float ny = y + off3Y; ny < y + h; ny += texH3)
            for (float nx = x + off3X; nx < x + w; nx += texW3)
                _spriteBatch.Draw(_noiseTexture, new Vector2(nx, ny), null, new Color(255, 200, 60) * 0.35f, 0f, Vector2.Zero, scale3, SpriteEffects.None, 0f);
        
        _spriteBatch.End();
        GraphicsDevice.ScissorRectangle = prevScissor;
        
        // Restart caller's batch
        float lshake = _trauma * _trauma;
        float lsx = MathF.Sin(100f + _noiseTime * 25f) * lshake * 8f;
        float lsy = MathF.Sin(200f + _noiseTime * 30f) * lshake * 8f;
        var lavaCamMatrix = Matrix.CreateTranslation(lsx + _transitionOffset.X - _cameraOffset.X, lsy + _transitionOffset.Y - _cameraOffset.Y, 0);
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp, transformMatrix: lavaCamMatrix);
    }
    
    // Line-segment to circle intersection test (for beam collision)
    private static bool LineCircleIntersects(Vector2 a, Vector2 b, Vector2 center, float radius)
    {
        Vector2 d = b - a;
        Vector2 f = a - center;
        float dLen2 = d.LengthSquared();
        if (dLen2 < 0.001f) return Vector2.Distance(a, center) < radius;
        float t = MathHelper.Clamp(-Vector2.Dot(f, d) / dLen2, 0f, 1f);
        Vector2 closest = a + d * t;
        return Vector2.Distance(closest, center) < radius;
    }

    private int MeasureText(string text, float scale = 1f, SpriteFont font = null)
    {
        var f = font ?? _font;
        if (f != null)
            return (int)(f.MeasureString(text).X * scale);
        return (int)(text.Length * 7 * scale);
    }
    
    private void DrawTextCentered(int y, string text, Color color, float scale = 1f, SpriteFont font = null)
    {
        int w = MeasureText(text, scale, font);
        DrawTextFallback(ScreenW / 2 - w / 2, y, text, color, scale, font);
    }
    
    private void DrawTextOutlined(int x, int y, string text, Color fillColor, Color outlineColor, float scale = 1f, SpriteFont font = null, int thickness = 1)
    {
        for (int dx = -thickness; dx <= thickness; dx++)
            for (int dy = -thickness; dy <= thickness; dy++)
                if (dx != 0 || dy != 0)
                    DrawTextFallback(x + dx, y + dy, text, outlineColor, scale, font);
        DrawTextFallback(x, y, text, fillColor, scale, font);
    }
    
    private void DrawTextCenteredOutlined(int y, string text, Color fillColor, Color outlineColor, float scale = 1f, SpriteFont font = null, int thickness = 1)
    {
        int w = MeasureText(text, scale, font);
        DrawTextOutlined(ScreenW / 2 - w / 2, y, text, fillColor, outlineColor, scale, font, thickness);
    }
    
    private void DrawDemoComplete(GameTime gameTime)
    {
        GraphicsDevice.Clear(Color.Black);
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        
        string[] lines = {
            "THE AWAKENING",
            "",
            "Demo Complete",
            "",
            "",
            "Thank you for playing",
            "Iron & Ether",
            "",
            "",
            "This is an early prototype.",
            "The full game will feature:",
            "",
            "- A vast world to explore",
            "- Hundreds of spell combinations",
            "- A story of knights, fae, and forbidden magic",
            "",
            "",
            "Press ENTER to return",
        };
        
        float baseY = ScreenH - _demoCompleteScroll + 100;
        int spacing = 28;
        
        for (int i = 0; i < lines.Length; i++)
        {
            float y = baseY + i * spacing;
            if (y < -30 || y > ScreenH + 30) continue;
            
            float edgeFade = 1f;
            if (y < 80) edgeFade = MathF.Max(0, y / 80f);
            if (y > ScreenH - 80) edgeFade = MathF.Max(0, (ScreenH - y) / 80f);
            
            string line = lines[i];
            if (line.Length == 0) continue;
            
            Color col = i == 0 ? new Color(255, 215, 0) * edgeFade :
                         i == 2 ? new Color(200, 180, 255) * edgeFade :
                         new Color(180, 190, 210) * edgeFade;
            
            float scale = i == 0 ? 1.8f : i == 2 ? 1.4f : 1f;
            var font = (i == 0 || i == 2) ? (_titleFont ?? _font) : _font;
            
            int tw = MeasureText(line, scale);
            DrawTextFallback(ScreenW / 2 - tw / 2, (int)y, line, col, scale, font);
        }
        
        _spriteBatch.End();
    }

    private void DrawIntro(GameTime gameTime)
    {
        GraphicsDevice.Clear(Color.Black);
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        
        // Starfield background — subtle twinkling dots
        int starSeed = 42;
        for (int i = 0; i < 60; i++)
        {
            int sx = (starSeed + i * 7919) % ScreenW;
            int sy = (starSeed + i * 6271) % ScreenH;
            float twinkle = (MathF.Sin(_introTimer * (1.5f + (i % 5) * 0.3f) + i * 0.7f) + 1f) / 2f;
            byte b = (byte)(30 + (int)(twinkle * 50));
            DrawRect(sx, sy, 1, 1, new Color(b, b, (byte)(b + 20)));
        }
        
        // ALttP-style blue gradient text scrolling upward
        float baseY = ScreenH - _introScroll;
        int lineSpacing = 26;
        
        for (int i = 0; i < IntroCrawl.Length; i++)
        {
            float y = baseY + i * lineSpacing;
            if (y < -30 || y > ScreenH + 30) continue; // off-screen
            
            string line = IntroCrawl[i];
            if (line.Length == 0) continue;
            
            // Fade in/out at edges
            float edgeFade = 1f;
            if (y < 80) edgeFade = MathHelper.Clamp(y / 80f, 0f, 1f);
            if (y > ScreenH - 80) edgeFade = MathHelper.Clamp((ScreenH - y) / 80f, 0f, 1f);
            
            // Blue gradient: lighter at top lines, deeper blue at bottom
            float prog = (float)i / IntroCrawl.Length;
            Color textColor;
            bool isLastLine = (i == IntroCrawl.Length - 1);
            if (isLastLine)
            {
                // "A weapon of iron and ether." — gold, larger
                float gold = MathHelper.Clamp((_introTimer - (IntroCrawl.Length * lineSpacing - ScreenH / 2f) / 28f) * 2f, 0f, 1f);
                textColor = new Color(220, 190, 80) * (edgeFade * gold);
                int tw = MeasureText(line, 1.2f, _titleFont);
                DrawTextOutlined((ScreenW - tw) / 2, (int)y, line, textColor, Color.Black * edgeFade, 1.2f, _titleFont, 2);
            }
            else
            {
                byte r = (byte)(100 + (int)(prog * 60));
                byte g = (byte)(140 + (int)(prog * 50));
                byte bl = (byte)(220 + (int)(prog * 35));
                textColor = new Color(r, g, bl) * edgeFade;
                Color outlineColor = new Color(20, 40, 120) * edgeFade;
                int tw = MeasureText(line, 1f, _titleFont);
                DrawTextOutlined((ScreenW - tw) / 2, (int)y, line, textColor, outlineColor, 1f, _titleFont, 2);
            }
        }
        
        // "Press any key" after initial delay
        if (_introTimer > 3f)
        {
            float blink = (MathF.Sin(_introTimer * 3f) + 1f) / 2f;
            DrawTextCenteredOutlined(ScreenH - 30, "Press any key", new Color(80, 80, 100) * (0.3f + blink * 0.3f), Color.Black * 0.3f, 0.8f);
        }
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
    private void DrawTitleScreen(GameTime gameTime)
    {
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        
        // ═══ WEATHER EFFECTS ═══
        float wt = _titleTimer;
        if (_titleWeather == 0 || _titleWeather == 2)
        {
            // Heavy Rain (weather 0) or Storm Rain (weather 2)
            int streakCount = _titleWeather == 0 ? 180 : 120;
            for (int r = 0; r < streakCount; r++)
            {
                // Each drop falls, hits bottom, respawns at a new random X
                int h1 = (r * 7919 + 1013) % 15731;
                float period = 1.2f + (h1 % 1000) / 1000f * 1.0f; // 1.2-2.2s per fall
                float startOffset = (h1 % 10000) / 10000f * period; // stagger initial phase
                float adjustedTime = wt + startOffset;
                int lifeIndex = (int)(adjustedTime / period);
                float lifeFrac = (adjustedTime % period) / period;
                
                // Proper RNG seeded per (drop, life) — uniform X distribution
                var dropRng = new Random(r * 10007 + lifeIndex * 7919);
                float rx = dropRng.Next(ScreenW) + MathF.Sin(wt * 0.9f + r * 1.372f) * 6f;
                rx = ((rx % ScreenW) + ScreenW) % ScreenW;
                
                float ry = lifeFrac * (ScreenH + 20) - 10;
                float ra = 0.2f + (dropRng.Next(100)) / 100f * 0.2f;
                int streakLen = 5 + dropRng.Next(6);
                _spriteBatch.Draw(_pixel, new Rectangle((int)rx, (int)ry, 2, streakLen), new Color(100, 140, 180) * ra);
            }
            // Splash particles at bottom
            for (int s = 0; s < 15; s++)
            {
                float sx = (s * 89.7f + wt * (60f + s % 3 * 20f)) % ScreenW;
                float splashPhase = (s * 7.3f + wt * 4f) % 1f;
                if (splashPhase < 0.15f)
                {
                    float sa = (1f - splashPhase / 0.15f) * 0.3f;
                    int sy = ScreenH - 5 - s % 10;
                    _spriteBatch.Draw(_pixel, new Rectangle((int)sx - 2, sy, 5, 1), new Color(120, 160, 200) * sa);
                }
            }
            if (_titleWeather == 0)
            {
                // Slightly darker tint for heavy rain
                _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), Color.Black * 0.08f);
            }
        }
        if (_titleWeather == 1)
        {
            // Grey Ash floating upward
            for (int a = 0; a < 70; a++)
            {
                float hashA = ((a * 6563 + 2039) % 11317) / 11317f;
                float hashB = ((a * 4391 + 5471) % 9601) / 9601f;
                float riseSpeed = 0.3f + hashA * 0.4f;
                float phase = (wt * riseSpeed * 0.15f + hashA) % 1f;
                float ax2 = (hashB * ScreenW + MathF.Sin(wt * (0.5f + hashA * 0.6f) + a * 2.236f) * 20f
                    + wt * (3f + hashB * 8f)) % ScreenW;
                if (ax2 < 0) ax2 += ScreenW;
                float ay2 = ScreenH - phase * (ScreenH + 40);
                float aa = 0.15f + hashB * 0.1f;
                Color ashCol = new Color(140 + (int)(hashA * 30), 135 + (int)(hashA * 30), 130 + (int)(hashA * 30));
                bool wide = MathF.Sin(wt * 2f + a * 1.618f) > 0;
                if (wide)
                    _spriteBatch.Draw(_pixel, new Rectangle((int)ax2, (int)ay2, 3, 2), ashCol * aa);
                else
                    _spriteBatch.Draw(_pixel, new Rectangle((int)ax2, (int)ay2, 2, 3), ashCol * aa);
            }
        }
        if (_titleWeather == 2)
        {
            // Lightning storm flashes
            _titleLightningTimer -= (float)gameTime.ElapsedGameTime.TotalSeconds;
            if (_titleLightningFlash > 0)
                _titleLightningFlash -= (float)gameTime.ElapsedGameTime.TotalSeconds;
            if (_titleLightningTimer <= 0)
            {
                _titleLightningFlash = 0.3f;
                _titleLightningTimer = 2f + (float)_rng.NextDouble() * 3f;
            }
            if (_titleLightningFlash > 0)
            {
                // Screen flash
                float flashAlpha = _titleLightningFlash > 0.2f ? 0.3f : _titleLightningFlash / 0.2f * 0.15f;
                _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), new Color(180, 200, 255) * flashAlpha);
                // Lightning bolt
                if (_titleLightningFlash > 0.15f)
                {
                    int boltX = (int)((_titleLightningTimer * 137f) % ScreenW);
                    int by = 0;
                    for (int seg = 0; seg < 12; seg++)
                    {
                        int nextX = boltX + ((seg * 31 + (int)(_titleLightningTimer * 100)) % 31) - 15;
                        int nextY = by + ScreenH / 12;
                        // Draw bolt segment as rect
                        int minX2 = Math.Min(boltX, nextX);
                        int minY2 = Math.Min(by, nextY);
                        _spriteBatch.Draw(_pixel, new Rectangle(minX2, minY2, Math.Max(Math.Abs(nextX - boltX), 2), nextY - by), Color.White * 0.9f);
                        boltX = nextX;
                        by = nextY;
                    }
                }
            }
            else
            {
                // Subtle distant rumble flash
                float rumble = MathF.Sin(wt * 1.3f);
                if (rumble > 0.95f)
                    _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), new Color(150, 170, 200) * 0.05f);
            }
        }
        
        // Morien portrait — left side, fading in from darkness
        if (_titlePortrait != null)
        {
            float fadeIn = MathHelper.Clamp(_titleTimer * 0.5f, 0f, 0.85f);
            // Scale to fit left portion of screen
            float imgScale = (float)ScreenH / _titlePortrait.Height;
            int imgW = (int)(_titlePortrait.Width * imgScale);
            _spriteBatch.Draw(_titlePortrait, new Rectangle(-imgW / 4, 12, imgW, ScreenH), Color.White * fadeIn);
        }
        
        // Wand/gun — right side
        if (_titleWand != null)
        {
            float fadeIn = MathHelper.Clamp((_titleTimer - 0.5f) * 0.8f, 0f, 0.7f);
            float bob = MathF.Sin(_titleTimer * 1.5f) * 5f;
            int wSize = 200;
            _spriteBatch.Draw(_titleWand, new Rectangle(ScreenW - wSize - 80, (int)(ScreenH / 2 - wSize / 2 + bob), wSize, wSize), Color.White * fadeIn);
        }
        
        // Dark gradient over center for text readability
        _spriteBatch.Draw(_pixel, new Rectangle(ScreenW / 3, 0, ScreenW * 2 / 3, ScreenH), Color.Black * 0.4f);
        
        // Dark box behind title for readability over portrait
        _spriteBatch.Draw(_pixel, new Rectangle(0, 160, ScreenW, 100), Color.Black * 0.45f);
        // Soft edges (gradient fade)
        _spriteBatch.Draw(_pixel, new Rectangle(0, 140, ScreenW, 20), Color.Black * 0.2f);
        _spriteBatch.Draw(_pixel, new Rectangle(0, 260, ScreenW, 20), Color.Black * 0.2f);
        
        // Title: IRON & ETHER (Jacquard font)
        var jf = _jacquardFont ?? _titleFont ?? _font;
        string title = "IRON  &  ETHER";
        float pulse = (MathF.Sin(_titleTimer * 2f) + 1f) / 2f;
        Color titleColor = Color.Lerp(new Color(200, 170, 100), new Color(255, 215, 0), pulse);
        DrawTextCenteredOutlined(200, title, titleColor, new Color(30, 20, 10), 2.5f, jf);
        
        // Prompt
        float blink = (MathF.Sin(_titleTimer * 3f) + 1f) / 2f;
        var tf = _titleFont ?? _font;
        DrawTextCenteredOutlined(420, "Press ENTER to begin", Color.White * (0.4f + 0.6f * blink), Color.Black * 0.5f, 1f, tf);
        
        // Version
        DrawTextFallback(ScreenW - 260, ScreenH - 25, "alpha build v0.2", new Color(60, 60, 60));
        
        // Decorative particles — gold dust
        float t = (float)gameTime.TotalGameTime.TotalSeconds;
        for (int i = 0; i < 8; i++)
        {
            float x = (t * (10f + i * 3f) + i * 163f) % ScreenW;
            float y = (MathF.Sin(t * 0.3f + i * 1.7f) + 1f) / 2f * ScreenH;
            int sz = 1 + (i % 3);
            float alpha = 0.08f + 0.12f * ((MathF.Sin(t * 0.7f + i) + 1f) / 2f);
            DrawRect((int)x, (int)y, sz, sz, new Color(200, 170, 100) * alpha);
        }
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
