    private Rectangle GetPaintArena(int room)
    {
        if (room == 50) // Cave: 9×7 tiles centered on screen
        {
            int w = 9 * TSDst, h = 7 * TSDst;
            return new Rectangle((ScreenW - w) / 2, (ScreenH - h) / 2, w, h);
        }
        return new Rectangle(60, 80, 1160, room == 11 ? 1300 : 580);
    }
    
    private (int cols, int rows) GetRoomTileSize(int room)
    {
        if (room == 50) return (9, 7); // Room 5b (cave interior): 400×300 → 9×7 tiles
        // Full screen width always 1280. Height depends on room
        int totalW = 1280; // ScreenW
        int totalH = room == 11 ? (80 + 1300 + 80) : 720; // Room 11: top margin + tall arena + bottom
        return ((totalW + TSDst - 1) / TSDst, (totalH + TSDst - 1) / TSDst);
    }
    
    private (int sheet, int tile)[,] GetOrCreateRoomTiles(int room)
    {
        if (!_roomTileData.ContainsKey(room))
        {
            var data = new (int sheet, int tile)[TSRoomRows, TSRoomCols];
            for (int r = 0; r < TSRoomRows; r++)
                for (int c = 0; c < TSRoomCols; c++)
                    data[r, c] = (-1, -1); // empty
            _roomTileData[room] = data;
        }
        return _roomTileData[room];
    }
    
    private (int sheet, int tile)[,] GetOrCreateRoomOverlay(int room)
    {
        if (!_roomTileOverlay.ContainsKey(room))
        {
            var data = new (int sheet, int tile)[TSRoomRows, TSRoomCols];
            for (int r = 0; r < TSRoomRows; r++)
                for (int c = 0; c < TSRoomCols; c++)
                    data[r, c] = (-1, -1);
            _roomTileOverlay[room] = data;
        }
        return _roomTileOverlay[room];
    }
    
    private (int sheet, int tile)[,] GetOrCreateRoomMid(int room)
    {
        if (!_roomTileMid.ContainsKey(room))
        {
            var data = new (int sheet, int tile)[TSRoomRows, TSRoomCols];
            for (int r = 0; r < TSRoomRows; r++)
                for (int c = 0; c < TSRoomCols; c++)
                    data[r, c] = (-1, -1);
            _roomTileMid[room] = data;
        }
        return _roomTileMid[room];
    }
    
    private int?[][] TileLayerToArray((int sheet, int tile)[,] data)
    {
        int rows = data.GetLength(0);
        int cols = data.GetLength(1);
        var arr = new int?[rows][];
        for (int r = 0; r < rows; r++)
        {
            var row = new int?[cols * 2];
            for (int c = 0; c < cols; c++)
            {
                var (s, t) = data[r, c];
                if (s >= 0) { row[c * 2] = s; row[c * 2 + 1] = t; }
                else { row[c * 2] = null; row[c * 2 + 1] = null; }
            }
            arr[r] = row;
        }
        return arr;
    }
    
    private (int sheet, int tile)[,] ArrayToTileLayer(JsonElement rowsArr)
    {
        int rowCount = rowsArr.GetArrayLength();
        var data = new (int sheet, int tile)[TSRoomRows, TSRoomCols];
        for (int r = 0; r < TSRoomRows; r++)
            for (int c = 0; c < TSRoomCols; c++)
                data[r, c] = (-1, -1);
        for (int r = 0; r < Math.Min(rowCount, TSRoomRows); r++)
        {
            var row = rowsArr[r];
            int pairs = row.GetArrayLength() / 2;
            for (int c = 0; c < Math.Min(pairs, TSRoomCols); c++)
            {
                var sElem = row[c * 2];
                var tElem = row[c * 2 + 1];
                if (sElem.ValueKind == JsonValueKind.Number && tElem.ValueKind == JsonValueKind.Number)
                    data[r, c] = (sElem.GetInt32(), tElem.GetInt32());
            }
        }
        return data;
    }
    
    private void SaveRoomTiles()
    {
        // Save as {"rooms":{"5":{"bg":[...],"fg":[...],"collision":[[x,y,w,h],...]}, ...}}
        var rooms = new Dictionary<string, Dictionary<string, object>>();
        var allRooms = new HashSet<int>(_roomTileData.Keys);
        foreach (var k in _roomTileMid.Keys) allRooms.Add(k);
        foreach (var k in _roomTileOverlay.Keys) allRooms.Add(k);
        foreach (var k in _roomCollision.Keys) allRooms.Add(k);
        
        foreach (int room in allRooms)
        {
            var entry = new Dictionary<string, object>();
            if (_roomTileData.TryGetValue(room, out var bg))
                entry["bg"] = TileLayerToArray(bg);
            if (_roomTileMid.TryGetValue(room, out var mid))
                entry["mid"] = TileLayerToArray(mid);
            if (_roomTileOverlay.TryGetValue(room, out var fg))
                entry["fg"] = TileLayerToArray(fg);
            if (_roomCollision.TryGetValue(room, out var coll) && coll.Count > 0)
                entry["collision"] = coll.Select(cr => new int[] { cr.Rect.X, cr.Rect.Y, cr.Rect.Width, cr.Rect.Height, cr.OneWay }).ToArray();
            rooms[room.ToString()] = entry;
        }
        var wrapper = new Dictionary<string, object> { ["rooms"] = rooms };
        string json = JsonSerializer.Serialize(wrapper, new JsonSerializerOptions { WriteIndented = false });
        string path = Path.Combine(Content.RootDirectory, "room_tiles.json");
        File.WriteAllText(path, json);
        System.Console.WriteLine($"Saved room tiles to {path} ({allRooms.Count} rooms)");
    }
    
    private void LoadRoomTiles()
    {
        string path = Path.Combine(Content.RootDirectory, "room_tiles.json");
        if (!File.Exists(path)) return;
        try
        {
            string json = File.ReadAllText(path);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;
            _roomTileData.Clear();
            _roomTileMid.Clear();
            _roomTileOverlay.Clear();
            _roomCollision.Clear();
            
            // New format: {"rooms":{"5":{"bg":[...],"fg":[...],"collision":[[x,y,w,h],...]}}}
            if (root.TryGetProperty("rooms", out var roomsElem))
            {
                foreach (var prop in roomsElem.EnumerateObject())
                {
                    int roomNum = int.Parse(prop.Name);
                    if (prop.Value.TryGetProperty("bg", out var bgElem))
                        _roomTileData[roomNum] = ArrayToTileLayer(bgElem);
                    if (prop.Value.TryGetProperty("mid", out var midElem))
                        _roomTileMid[roomNum] = ArrayToTileLayer(midElem);
                    if (prop.Value.TryGetProperty("fg", out var fgElem))
                        _roomTileOverlay[roomNum] = ArrayToTileLayer(fgElem);
                    if (prop.Value.TryGetProperty("collision", out var collElem))
                    {
                        var rects = new List<CollRect>();
                        foreach (var arr in collElem.EnumerateArray())
                        {
                            var vals = arr.EnumerateArray().Select(v => v.GetInt32()).ToArray();
                            if (vals.Length >= 4)
                            {
                                int ow = vals.Length >= 5 ? vals[4] : 0;
                                rects.Add(new CollRect(new Rectangle(vals[0], vals[1], vals[2], vals[3]), ow));
                            }
                        }
                        if (rects.Count > 0)
                            _roomCollision[roomNum] = rects;
                    }
                }
            }
            else
            {
                // Legacy format: {"5":[[...],...]}
                foreach (var prop in root.EnumerateObject())
                {
                    int roomNum = int.Parse(prop.Name);
                    _roomTileData[roomNum] = ArrayToTileLayer(prop.Value);
                }
            }
            System.Console.WriteLine($"Loaded room tiles ({_roomTileData.Count} bg, {_roomTileMid.Count} mid, {_roomTileOverlay.Count} fg rooms)");
        }
        catch (Exception ex)
        {
            System.Console.WriteLine($"Failed to load room tiles: {ex.Message}");
        }
    }
    
    private void UpdateTileRenderer(KeyboardState kb, MouseState mouse, float dt)
    {
        // P toggles paint/browse mode
        if (kb.IsKeyDown(Keys.P) && !_prevKb.IsKeyDown(Keys.P))
        {
            _trPaintMode = !_trPaintMode;
            if (_trPaintMode)
            {
                _trCameraPos = Vector2.Zero;
                // Initialize walls/cave/torches for overlay
                _arena = GetPaintArena(_trPaintRoom);
                InitScreenWalls();
                InitAwakeningDoors();
                // Set up cave data for room 5
                int ax = _arena.Left, ay = _arena.Top;
                _caveEntrance = new Rectangle(ax + 274, ay + 160, 48, 48);
                int caveW = 400, caveH = 300;
                int caveCX = ScreenW / 2, caveCY = ScreenH / 2;
                _caveArea = new Rectangle(caveCX - caveW / 2, caveCY - caveH / 2, caveW, caveH);
            }
        }
        
        if (_trPaintMode)
            UpdateTilePainter(kb, mouse, dt);
        else
            UpdateTileBrowser(kb, mouse, dt);
    }
    
    private void UpdateTileBrowser(KeyboardState kb, MouseState mouse, float dt)
    {
        float speed = 300f * dt;
        if (kb.IsKeyDown(Keys.LeftShift)) speed *= 3f;
        if (kb.IsKeyDown(Keys.W) || kb.IsKeyDown(Keys.Up)) _trCameraPos.Y -= speed;
        if (kb.IsKeyDown(Keys.S) || kb.IsKeyDown(Keys.Down)) _trCameraPos.Y += speed;
        if (kb.IsKeyDown(Keys.A) || kb.IsKeyDown(Keys.Left)) _trCameraPos.X -= speed;
        if (kb.IsKeyDown(Keys.D) || kb.IsKeyDown(Keys.Right)) _trCameraPos.X += speed;
        
        // Tab cycles through sheets
        if (kb.IsKeyDown(Keys.Tab) && !_prevKb.IsKeyDown(Keys.Tab))
            _trSheetIdx = (_trSheetIdx + 1) % _tsSheets.Length;
        
        // +/- to adjust scale
        if (kb.IsKeyDown(Keys.OemPlus) && !_prevKb.IsKeyDown(Keys.OemPlus) && _trScale < 8)
            _trScale++;
        if (kb.IsKeyDown(Keys.OemMinus) && !_prevKb.IsKeyDown(Keys.OemMinus) && _trScale > 1)
            _trScale--;
        
        // Left-click to pick a tile for painting
        if (mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released)
        {
            var sheet = _tsSheets != null && _trSheetIdx < _tsSheets.Length ? _tsSheets[_trSheetIdx] : null;
            if (sheet != null)
            {
                int dst = TS16 * _trScale;
                int gap = 1;
                int cols = sheet.Width / TS16;
                int rows = sheet.Height / TS16;
                int mx = mouse.X + (int)_trCameraPos.X - 20;
                int my = mouse.Y + (int)_trCameraPos.Y - 60;
                int hc = mx / (dst + gap);
                int hr = my / (dst + gap);
                if (hc >= 0 && hc < cols && hr >= 0 && hr < rows && mx >= 0 && my >= 0)
                {
                    _trSelectedTile = hr * cols + hc;
                    _trSelectedSheet = _trSheetIdx;
                }
            }
        }
        
        // Escape to return to menu
        if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
        {
            _state = GameState.ModeSelect;
            _menuSelection = 0;
        }
        
        // Clamp camera
        if (_trCameraPos.X < 0) _trCameraPos.X = 0;
        if (_trCameraPos.Y < 0) _trCameraPos.Y = 0;
        var sh = _tsSheets != null && _trSheetIdx < _tsSheets.Length ? _tsSheets[_trSheetIdx] : null;
        if (sh != null)
        {
            int sheetDispW = sh.Width / TS16 * (TS16 * _trScale);
            int sheetDispH = sh.Height / TS16 * (TS16 * _trScale);
            if (_trCameraPos.X > MathF.Max(0, sheetDispW - ScreenW + 40)) _trCameraPos.X = MathF.Max(0, sheetDispW - ScreenW + 40);
            if (_trCameraPos.Y > MathF.Max(0, sheetDispH - ScreenH + 100)) _trCameraPos.Y = MathF.Max(0, sheetDispH - ScreenH + 100);
        }
    }
    
    private void UpdateTilePainter(KeyboardState kb, MouseState mouse, float dt)
    {
        // WASD to pan camera
        float speed = 400f * dt;
        if (kb.IsKeyDown(Keys.LeftShift)) speed *= 3f;
        if (kb.IsKeyDown(Keys.W)) _trCameraPos.Y -= speed;
        if (kb.IsKeyDown(Keys.S)) _trCameraPos.Y += speed;
        if (kb.IsKeyDown(Keys.A)) _trCameraPos.X -= speed;
        if (kb.IsKeyDown(Keys.D)) _trCameraPos.X += speed;
        
        // Clamp camera
        var (roomCols, roomRows) = GetRoomTileSize(_trPaintRoom);
        int palW = 200;
        int gridX = palW + 10;
        int gridY = 60;
        int totalGridW = roomCols * TSDst;
        int totalGridH = roomRows * TSDst;
        float maxCX = MathF.Max(0, totalGridW - (ScreenW - gridX) + 20);
        float maxCY = MathF.Max(0, totalGridH - (ScreenH - gridY) + 20);
        _trCameraPos.X = MathHelper.Clamp(_trCameraPos.X, 0, maxCX);
        _trCameraPos.Y = MathHelper.Clamp(_trCameraPos.Y, 0, maxCY);
        
        // Left/Right to switch rooms (disabled in collision mode — arrows set ledge direction)
        int[] paintRooms = { 1, 2, 3, 4, 5, 50, 6, 7, 8, 9, 11 };
        if (!_trCollisionMode && kb.IsKeyDown(Keys.Left) && !_prevKb.IsKeyDown(Keys.Left))
        {
            int idx = Array.IndexOf(paintRooms, _trPaintRoom);
            if (idx > 0) _trPaintRoom = paintRooms[idx - 1];
            _trCameraPos = Vector2.Zero;
            _arena = GetPaintArena(_trPaintRoom);
            InitScreenWalls(); InitAwakeningDoors();
        }
        if (!_trCollisionMode && kb.IsKeyDown(Keys.Right) && !_prevKb.IsKeyDown(Keys.Right))
        {
            int idx = Array.IndexOf(paintRooms, _trPaintRoom);
            if (idx < paintRooms.Length - 1) _trPaintRoom = paintRooms[idx + 1];
            _trCameraPos = Vector2.Zero;
            _arena = GetPaintArena(_trPaintRoom);
            InitScreenWalls(); InitAwakeningDoors();
        }
        
        // Tab cycles palette sheet
        if (kb.IsKeyDown(Keys.Tab) && !_prevKb.IsKeyDown(Keys.Tab))
            _trSheetIdx = (_trSheetIdx + 1) % _tsSheets.Length;
        
        // Scroll palette with mouse wheel
        int scrollDelta = mouse.ScrollWheelValue - _prevMouse.ScrollWheelValue;
        if (scrollDelta != 0) _trPalScroll -= scrollDelta / 40;
        
        // X = eraser
        if (kb.IsKeyDown(Keys.X) && !_prevKb.IsKeyDown(Keys.X))
            _trSelectedTile = -1;
        
        // G = toggle collision overlay
        if (kb.IsKeyDown(Keys.G) && !_prevKb.IsKeyDown(Keys.G))
            _trShowOverlay = !_trShowOverlay;
        
        // C = toggle collision editing mode
        if (kb.IsKeyDown(Keys.C) && !_prevKb.IsKeyDown(Keys.C))
        {
            _trCollisionMode = !_trCollisionMode;
            _trDraggingCollision = false;
        }
        
        // V = cycle layer visibility: Both → BG only → FG only → Both
        if (kb.IsKeyDown(Keys.V) && !_prevKb.IsKeyDown(Keys.V))
            _trLayerView = (_trLayerView + 1) % 4;
        
        // L = toggle layer (0=bg, 1=mid, 2=fg overlay)
        if (kb.IsKeyDown(Keys.L) && !_prevKb.IsKeyDown(Keys.L))
            _trActiveLayer = (_trActiveLayer + 1) % 3;
        
        // Ctrl+S to save
        if (kb.IsKeyDown(Keys.LeftControl) && kb.IsKeyDown(Keys.S) && !_prevKb.IsKeyDown(Keys.S))
            SaveRoomTiles();
        
        // F to fill entire room with selected tile
        if (kb.IsKeyDown(Keys.F) && !_prevKb.IsKeyDown(Keys.F) && _trSelectedTile >= 0)
        {
            var data = _trActiveLayer == 0 ? GetOrCreateRoomTiles(_trPaintRoom) : _trActiveLayer == 1 ? GetOrCreateRoomMid(_trPaintRoom) : GetOrCreateRoomOverlay(_trPaintRoom);
            for (int r = 0; r < roomRows; r++)
                for (int c = 0; c < roomCols; c++)
                    data[r, c] = (_trSelectedSheet, _trSelectedTile);
        }
        
        // Escape: back to browse (not menu)
        if (kb.IsKeyDown(Keys.Escape) && !_prevKb.IsKeyDown(Keys.Escape))
        {
            _trPaintMode = false;
        }
        
        // Calculate grid position with camera offset
        int camGX = gridX - (int)_trCameraPos.X;
        int camGY = gridY - (int)_trCameraPos.Y;
        
        // Left-click on palette to select tile
        if (mouse.LeftButton == ButtonState.Pressed && !_trCollisionMode)
        {
            if (mouse.X < palW && mouse.Y > 50)
            {
                if (_prevMouse.LeftButton == ButtonState.Released)
                {
                    var sheet = _tsSheets != null && _trSheetIdx < _tsSheets.Length ? _tsSheets[_trSheetIdx] : null;
                    if (sheet != null)
                    {
                        int palTileSize = 24;
                        int palCols = (palW - 8) / (palTileSize + 1);
                        int mx = (mouse.X - 4) / (palTileSize + 1);
                        int my = (mouse.Y - 54 + _trPalScroll) / (palTileSize + 1);
                        int sheetCols = sheet.Width / TS16;
                        int sheetRows = sheet.Height / TS16;
                        if (mx >= 0 && mx < palCols && my >= 0)
                        {
                            int tileId = my * palCols + mx;
                            if (tileId < sheetCols * sheetRows)
                            {
                                _trSelectedTile = tileId;
                                _trSelectedSheet = _trSheetIdx;
                            }
                        }
                    }
                }
            }
            else if (mouse.X >= palW)
            {
                // Painting on room grid with camera offset
                int gc = (mouse.X - camGX) / TSDst;
                int gr = (mouse.Y - camGY) / TSDst;
                if (gc >= 0 && gc < roomCols && gr >= 0 && gr < roomRows && mouse.Y > 50)
                {
                    var data = _trActiveLayer == 0 ? GetOrCreateRoomTiles(_trPaintRoom) : _trActiveLayer == 1 ? GetOrCreateRoomMid(_trPaintRoom) : GetOrCreateRoomOverlay(_trPaintRoom);
                    if (_trSelectedTile >= 0)
                        data[gr, gc] = (_trSelectedSheet, _trSelectedTile);
                    else
                        data[gr, gc] = (-1, -1);
                }
            }
        }
        
        // Right-click = erase
        if (mouse.RightButton == ButtonState.Pressed && mouse.X >= palW && !_trCollisionMode)
        {
            int gc = (mouse.X - camGX) / TSDst;
            int gr = (mouse.Y - camGY) / TSDst;
            if (gc >= 0 && gc < roomCols && gr >= 0 && gr < roomRows)
            {
                // When viewing a specific layer, erase from that layer; otherwise use active layer
                int eraseLayer = _trLayerView == 1 ? 0 : _trLayerView == 2 ? 1 : _trLayerView == 3 ? 2 : _trActiveLayer;
                var data = eraseLayer == 0 ? GetOrCreateRoomTiles(_trPaintRoom) : eraseLayer == 1 ? GetOrCreateRoomMid(_trPaintRoom) : GetOrCreateRoomOverlay(_trPaintRoom);
                data[gr, gc] = (-1, -1);
            }
        }
        
        // ═══ Collision Editing Mode ═══
        if (_trCollisionMode && mouse.X >= palW)
        {
            if (!_roomCollision.ContainsKey(_trPaintRoom))
                _roomCollision[_trPaintRoom] = new List<CollRect>();
            var collRects = _roomCollision[_trPaintRoom];
            
            // Mouse position in room-space (account for camera pan)
            int cmx = mouse.X - camGX;
            int cmy = mouse.Y - camGY;
            
            // Left-click drag to create rect
            if (mouse.LeftButton == ButtonState.Pressed && _prevMouse.LeftButton == ButtonState.Released && mouse.Y > 50)
            {
                _trDraggingCollision = true;
                _trCollDragStart = new Point(cmx, cmy);
            }
            
            if (_trDraggingCollision && mouse.LeftButton == ButtonState.Released)
            {
                _trDraggingCollision = false;
                int x1 = Math.Min(_trCollDragStart.X, cmx);
                int y1 = Math.Min(_trCollDragStart.Y, cmy);
                int x2 = Math.Max(_trCollDragStart.X, cmx);
                int y2 = Math.Max(_trCollDragStart.Y, cmy);
                // Snap to grid — hold Shift for half-tile (24px), otherwise full tile (48px)
                int snap = kb.IsKeyDown(Keys.LeftShift) || kb.IsKeyDown(Keys.RightShift) ? TSDst / 2 : TSDst;
                x1 = (x1 / snap) * snap;
                y1 = (y1 / snap) * snap;
                x2 = ((x2 + snap - 1) / snap) * snap;
                y2 = ((y2 + snap - 1) / snap) * snap;
                int w = x2 - x1;
                int h = y2 - y1;
                if (w >= snap && h >= snap)
                {
                    // Hold arrow key while releasing to set ledge direction
                    // Arrow = direction player CAN HOP THROUGH (↓ = can jump down off ledge)
                    int oneWay = 0;
                    if (kb.IsKeyDown(Keys.Up)) oneWay = 1;
                    else if (kb.IsKeyDown(Keys.Down)) oneWay = 2;
                    else if (kb.IsKeyDown(Keys.Left)) oneWay = 3;
                    else if (kb.IsKeyDown(Keys.Right)) oneWay = 4;
                    else if (kb.IsKeyDown(Keys.Space)) oneWay = 5; // player-only wall (bullets pass)
                    collRects.Add(new CollRect(new Rectangle(x1, y1, w, h), oneWay));
                    SaveRoomTiles();
                }
            }
            
            // Right-click to delete hovered rect
            _trCollHoverIdx = -1;
            for (int i = collRects.Count - 1; i >= 0; i--)
            {
                if (collRects[i].Rect.Contains(cmx, cmy))
                {
                    _trCollHoverIdx = i;
                    break;
                }
            }
            
            if (mouse.RightButton == ButtonState.Pressed && _prevMouse.RightButton == ButtonState.Released && _trCollHoverIdx >= 0)
            {
                collRects.RemoveAt(_trCollHoverIdx);
                _trCollHoverIdx = -1;
                SaveRoomTiles();
            }
        }
    }
    
    private void DrawTileRenderer(GameTime gameTime)
    {
        if (_trPaintMode)
            DrawTilePainter(gameTime);
        else
            DrawTileBrowser(gameTime);
    }
    
    private void DrawTileBrowser(GameTime gameTime)
    {
        GraphicsDevice.Clear(new Color(20, 20, 25));
        
        var sheet = _tsSheets != null && _trSheetIdx < _tsSheets.Length ? _tsSheets[_trSheetIdx] : null;
        
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        
        if (sheet == null)
        {
            DrawTextCenteredOutlined(ScreenH / 2, "No tileset loaded.", Color.Red, Color.Black);
            _spriteBatch.End();
            return;
        }
        
        int dst = TS16 * _trScale;
        int cols = sheet.Width / TS16;
        int rows = sheet.Height / TS16;
        int ox = 20 - (int)_trCameraPos.X;
        int oy = 60 - (int)_trCameraPos.Y;
        
        int gap = 1;
        for (int r = 0; r < rows; r++)
        {
            for (int c = 0; c < cols; c++)
            {
                int dx = ox + c * (dst + gap);
                int dy = oy + r * (dst + gap);
                if (dx + dst < 0 || dx > ScreenW || dy + dst < 0 || dy > ScreenH) continue;
                
                DrawRect(dx, dy, dst, dst, new Color(40, 40, 50));
                var src = new Rectangle(c * TS16, r * TS16, TS16, TS16);
                _spriteBatch.Draw(sheet, new Rectangle(dx, dy, dst, dst), src, Color.White);
            }
        }
        
        // Mouse hover
        var mouse = Mouse.GetState();
        int mx = mouse.X + (int)_trCameraPos.X - 20;
        int my = mouse.Y + (int)_trCameraPos.Y - 60;
        int hc = mx / (dst + gap);
        int hr = my / (dst + gap);
        
        if (hc >= 0 && hc < cols && hr >= 0 && hr < rows && mx >= 0 && my >= 0)
        {
            int hx = ox + hc * (dst + gap);
            int hy = oy + hr * (dst + gap);
            DrawRect(hx - 2, hy - 2, dst + 4, 2, Color.Yellow);
            DrawRect(hx - 2, hy + dst, dst + 4, 2, Color.Yellow);
            DrawRect(hx - 2, hy, 2, dst, Color.Yellow);
            DrawRect(hx + dst, hy, 2, dst, Color.Yellow);
            
            int tileId = hr * cols + hc;
            string info = $"ID:{tileId}  Row:{hr} Col:{hc}  Src:({hc * TS16},{hr * TS16})";
            int tw = MeasureText(info, 0.8f);
            int tx = mouse.X + 16;
            int ty = mouse.Y - 24;
            if (tx + tw > ScreenW - 10) tx = mouse.X - tw - 16;
            if (ty < 4) ty = mouse.Y + 20;
            DrawRect(tx - 4, ty - 2, tw + 8, 20, new Color(0, 0, 0, 200));
            DrawTextOutlined(tx, ty, info, Color.Yellow, Color.Black, 0.8f);
        }
        
        // Selected tile indicator
        if (_trSelectedTile >= 0)
        {
            string selInfo = $"Selected: {_tsNames[_trSelectedSheet]} #{_trSelectedTile}";
            DrawRect(ScreenW - 220, ScreenH - 70, 210, 60, new Color(0, 0, 0, 180));
            DrawTextOutlined(ScreenW - 210, ScreenH - 64, selInfo, Color.Lime, Color.Black, 0.8f);
            // Draw selected tile preview
            var selSheet = _tsSheets[_trSelectedSheet];
            int selCols = selSheet.Width / TS16;
            int sr = _trSelectedTile / selCols;
            int sc = _trSelectedTile % selCols;
            var selSrc = new Rectangle(sc * TS16, sr * TS16, TS16, TS16);
            _spriteBatch.Draw(selSheet, new Rectangle(ScreenW - 210, ScreenH - 44, 40, 40), selSrc, Color.White);
        }
        
        // Header
        DrawRect(0, 0, ScreenW, 50, new Color(15, 15, 20, 230));
        string header = $"BROWSE — {_tsNames[_trSheetIdx].ToUpper()} ({cols}×{rows})  Scale:{_trScale}×";
        DrawTextOutlined(20, 8, header, new Color(200, 170, 100), Color.Black, 1f);
        string controls = "TAB:sheet  +/-:scale  WASD:pan  Click:pick tile  P:paint mode  ESC:back";
        DrawTextOutlined(20, 28, controls, new Color(100, 100, 120), Color.Black, 0.7f);
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
    private void DrawTilePainter(GameTime gameTime)
    {
        GraphicsDevice.Clear(new Color(20, 20, 25));
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        
        int palW = 200;
        int gridX = palW + 10 - (int)_trCameraPos.X; // grid starts at screen origin (0,0)
        int gridY = 60 - (int)_trCameraPos.Y;
        var (roomCols, roomRows) = GetRoomTileSize(_trPaintRoom);
        
        // ── Room Grid (both layers) ──
        var bgData = GetOrCreateRoomTiles(_trPaintRoom);
        var midData = GetOrCreateRoomMid(_trPaintRoom);
        var fgData = GetOrCreateRoomOverlay(_trPaintRoom);
        var mouse = Mouse.GetState();
        int maxR = Math.Min(roomRows, Math.Min(bgData.GetLength(0), fgData.GetLength(0)));
        int maxC = Math.Min(roomCols, Math.Min(bgData.GetLength(1), fgData.GetLength(1)));
        
        for (int r = 0; r < maxR; r++)
        {
            for (int c = 0; c < maxC; c++)
            {
                int dx = gridX + c * TSDst;
                int dy = gridY + r * TSDst;
                
                // Cull off-screen
                if (dx + TSDst < palW || dx > ScreenW || dy + TSDst < 50 || dy > ScreenH) continue;
                
                // Background layer (visible when view=0 all or view=1 BG only)
                if (_trLayerView == 0 || _trLayerView == 1)
                {
                var (s, t) = bgData[r, c];
                if (s >= 0 && t >= 0 && _tsSheets[s] != null)
                {
                    int sheetCols = _tsSheets[s].Width / TS16;
                    int tr2 = t / sheetCols;
                    int tc2 = t % sheetCols;
                    var src = new Rectangle(tc2 * TS16, tr2 * TS16, TS16, TS16);
                    _spriteBatch.Draw(_tsSheets[s], new Rectangle(dx, dy, TSDst, TSDst), src, Color.White);
                }
                else
                {
                    DrawRect(dx, dy, TSDst, TSDst, new Color(15, 15, 20));
                }
                }
                
                // Mid layer (visible when view=0 all or view=2 MID only)
                if (_trLayerView == 0 || _trLayerView == 2)
                {
                var (sm, tm) = midData[r, c];
                if (sm >= 0 && tm >= 0 && _tsSheets[sm] != null)
                {
                    int sheetColsM = _tsSheets[sm].Width / TS16;
                    int trM = tm / sheetColsM;
                    int tcM = tm % sheetColsM;
                    var srcM = new Rectangle(tcM * TS16, trM * TS16, TS16, TS16);
                    _spriteBatch.Draw(_tsSheets[sm], new Rectangle(dx, dy, TSDst, TSDst), srcM, Color.White);
                }
                }
                
                // Foreground/overlay layer (visible when view=0 all or view=3 FG only)
                if (_trLayerView == 0 || _trLayerView == 3)
                {
                var (s2, t2) = fgData[r, c];
                if (s2 >= 0 && t2 >= 0 && _tsSheets[s2] != null)
                {
                    int sheetCols2 = _tsSheets[s2].Width / TS16;
                    int tr3 = t2 / sheetCols2;
                    int tc3 = t2 % sheetCols2;
                    var src2 = new Rectangle(tc3 * TS16, tr3 * TS16, TS16, TS16);
                    _spriteBatch.Draw(_tsSheets[s2], new Rectangle(dx, dy, TSDst, TSDst), src2, Color.White);
                }
                }
                
                // Grid lines (dimmer on inactive layer)
                DrawRect(dx, dy, TSDst, 1, new Color(40, 40, 50, 80));
                DrawRect(dx, dy, 1, TSDst, new Color(40, 40, 50, 80));
            }
        }
        
        // Room border outline
        DrawRect(gridX - 1, gridY - 1, roomCols * TSDst + 2, 1, new Color(100, 100, 120));
        DrawRect(gridX - 1, gridY + roomRows * TSDst, roomCols * TSDst + 2, 1, new Color(100, 100, 120));
        DrawRect(gridX - 1, gridY, 1, roomRows * TSDst, new Color(100, 100, 120));
        DrawRect(gridX + roomCols * TSDst, gridY, 1, roomRows * TSDst, new Color(100, 100, 120));
        
        // Hover highlight on grid
        if (mouse.X >= palW && mouse.Y > 50)
        {
            int gc = (mouse.X - gridX) / TSDst;
            int gr = (mouse.Y - gridY) / TSDst;
            if (gc >= 0 && gc < roomCols && gr >= 0 && gr < roomRows)
            {
                int hx = gridX + gc * TSDst;
                int hy = gridY + gr * TSDst;
                DrawRect(hx, hy, TSDst, 2, Color.Yellow);
                DrawRect(hx, hy + TSDst - 2, TSDst, 2, Color.Yellow);
                DrawRect(hx, hy, 2, TSDst, Color.Yellow);
                DrawRect(hx + TSDst - 2, hy, 2, TSDst, Color.Yellow);
                
                // Preview selected tile at cursor (semi-transparent)
                if (_trSelectedTile >= 0 && _tsSheets[_trSelectedSheet] != null)
                {
                    int sheetCols = _tsSheets[_trSelectedSheet].Width / TS16;
                    int pr = _trSelectedTile / sheetCols;
                    int pc = _trSelectedTile % sheetCols;
                    var src = new Rectangle(pc * TS16, pr * TS16, TS16, TS16);
                    _spriteBatch.Draw(_tsSheets[_trSelectedSheet], new Rectangle(hx, hy, TSDst, TSDst), src, Color.White * 0.5f);
                }
            }
        }
        
        // ── Collision/Object Overlay ──
        if (_trShowOverlay)
        {
            // Arena boundary — green outline
            int oax = gridX + 60; // arena.Left=60
            int oay = gridY + 80; // arena.Top=80
            int oaw = 1160, oah = (_trPaintRoom == 11) ? 1300 : 580;
            DrawRect(oax, oay, oaw, 2, Color.Lime * 0.6f);
            DrawRect(oax, oay + oah, oaw, 2, Color.Lime * 0.6f);
            DrawRect(oax, oay, 2, oah, Color.Lime * 0.6f);
            DrawRect(oax + oaw, oay, 2, oah, Color.Lime * 0.6f);
            // Label
            DrawTextOutlined(oax + 4, oay + 4, "ARENA", Color.Lime * 0.8f, Color.Black, 0.6f);
            
            // Wall rects — red semi-transparent fill
            if (_screenWalls.TryGetValue(_trPaintRoom, out var walls))
            {
                foreach (var w in walls)
                {
                    int wx = gridX + w.X;
                    int wy = gridY + w.Y;
                    DrawRect(wx, wy, w.Width, w.Height, Color.Red * 0.3f);
                    DrawRect(wx, wy, w.Width, 1, Color.Red * 0.7f);
                    DrawRect(wx, wy + w.Height, w.Width, 1, Color.Red * 0.7f);
                    DrawRect(wx, wy, 1, w.Height, Color.Red * 0.7f);
                    DrawRect(wx + w.Width, wy, 1, w.Height, Color.Red * 0.7f);
                }
                DrawTextOutlined(oax + 4, oay + 16, $"WALLS: {walls.Count}", Color.Red * 0.8f, Color.Black, 0.6f);
            }
            
            // Cave area — blue (room 5 only, but show for any that has it)
            if (_trPaintRoom == 5)
            {
                // Cave entrance
                var ce = _caveEntrance;
                DrawRect(gridX + ce.X, gridY + ce.Y, ce.Width, ce.Height, Color.Cyan * 0.3f);
                DrawTextOutlined(gridX + ce.X, gridY + ce.Y - 12, "CAVE ENTRANCE", Color.Cyan * 0.8f, Color.Black, 0.5f);
                
                // Cave area
                var ca = _caveArea;
                DrawRect(gridX + ca.X, gridY + ca.Y, ca.Width, ca.Height, Color.Blue * 0.2f);
                DrawRect(gridX + ca.X, gridY + ca.Y, ca.Width, 1, Color.Blue * 0.6f);
                DrawRect(gridX + ca.X, gridY + ca.Y + ca.Height, ca.Width, 1, Color.Blue * 0.6f);
                DrawRect(gridX + ca.X, gridY + ca.Y, 1, ca.Height, Color.Blue * 0.6f);
                DrawRect(gridX + ca.X + ca.Width, gridY + ca.Y, 1, ca.Height, Color.Blue * 0.6f);
                DrawTextOutlined(gridX + ca.X + 4, gridY + ca.Y + 4, "CAVE INTERIOR", Color.Blue * 0.8f, Color.Black, 0.6f);
            }
            
            // Torches — yellow dots
            foreach (var torch in _torches)
            {
                int tx = gridX + (int)torch.X;
                int ty = gridY + (int)torch.Y;
                DrawRect(tx - 4, ty - 4, 8, 8, Color.Yellow * 0.7f);
                DrawRect(tx - 5, ty - 5, 10, 1, Color.Yellow);
                DrawRect(tx - 5, ty + 4, 10, 1, Color.Yellow);
                DrawRect(tx - 5, ty - 5, 1, 10, Color.Yellow);
                DrawRect(tx + 4, ty - 5, 1, 10, Color.Yellow);
            }
            
            // Doors — magenta indicators at edges
            string[] sides = { "N", "S", "E", "W" };
            foreach (var side in sides)
            {
                if (HasDoorOnSide(_trPaintRoom, side))
                {
                    int dx = 0, dy = 0, dw = 0, dh = 0;
                    int doorSize = 100;
                    // Doors at screen edges (transitions use screen bounds now)
                    switch (side)
                    {
                        case "N": dx = gridX + ScreenW / 2 - doorSize / 2; dy = gridY - 6; dw = doorSize; dh = 6; break;
                        case "S": dx = gridX + ScreenW / 2 - doorSize / 2; dy = gridY + ScreenH; dw = doorSize; dh = 6; break;
                        case "W": dx = gridX - 6; dy = gridY + ScreenH / 2 - doorSize / 2; dw = 6; dh = doorSize; break;
                        case "E": dx = gridX + ScreenW; dy = gridY + ScreenH / 2 - doorSize / 2; dw = 6; dh = doorSize; break;
                    }
                    DrawRect(dx, dy, dw, dh, Color.Magenta * 0.7f);
                    DrawTextOutlined(dx, dy - 10, $"DOOR {side}", Color.Magenta * 0.8f, Color.Black, 0.5f);
                }
            }
        }
        
        // ═══ Collision rects (always visible when in collision mode or overlay) ═══
        if (_trCollisionMode || _trShowOverlay)
        {
            if (_roomCollision.TryGetValue(_trPaintRoom, out var drawColl))
            {
                for (int i = 0; i < drawColl.Count; i++)
                {
                    var cr = drawColl[i];
                    var r = cr.Rect;
                    int rx = gridX + r.X, ry = gridY + r.Y;
                    bool isOneWay = cr.OneWay >= 1 && cr.OneWay <= 4;
                    bool isPlayerOnly = cr.OneWay == 5;
                    Color c = (i == _trCollHoverIdx && _trCollisionMode) ? Color.Red 
                        : isPlayerOnly ? new Color(255, 165, 0) : isOneWay ? new Color(80, 180, 255) : new Color(255, 80, 80);
                    float alpha = _trCollisionMode ? 0.4f : 0.2f;
                    DrawRect(rx, ry, r.Width, r.Height, c * alpha);
                    DrawRect(rx, ry, r.Width, 2, c * 0.8f);
                    DrawRect(rx, ry + r.Height - 2, r.Width, 2, c * 0.8f);
                    DrawRect(rx, ry, 2, r.Height, c * 0.8f);
                    DrawRect(rx + r.Width - 2, ry, 2, r.Height, c * 0.8f);
                    if (_trCollisionMode)
                    {
                        string[] owLabels = { "", "↑HOP UP", "↓HOP DOWN", "←HOP LEFT", "→HOP RIGHT", "PLAYER ONLY" };
                        string label = (cr.OneWay > 0 && cr.OneWay <= 5) ? owLabels[cr.OneWay] : $"{r.Width/TSDst}×{r.Height/TSDst}";
                        DrawTextFallback(rx + 4, ry + 4, label, Color.White * 0.6f, 0.5f);
                    }
                }
            }
            
            // Draw drag preview
            if (_trCollisionMode && _trDraggingCollision)
            {
                var ms = Mouse.GetState();
                var kbs = Keyboard.GetState();
                int cmx = ms.X - gridX, cmy = ms.Y - gridY;
                int x1 = Math.Min(_trCollDragStart.X, cmx);
                int y1 = Math.Min(_trCollDragStart.Y, cmy);
                int x2 = Math.Max(_trCollDragStart.X, cmx);
                int y2 = Math.Max(_trCollDragStart.Y, cmy);
                int snap = kbs.IsKeyDown(Keys.LeftShift) || kbs.IsKeyDown(Keys.RightShift) ? TSDst / 2 : TSDst;
                x1 = (x1 / snap) * snap;
                y1 = (y1 / snap) * snap;
                x2 = ((x2 + snap - 1) / snap) * snap;
                y2 = ((y2 + snap - 1) / snap) * snap;
                DrawRect(gridX + x1, gridY + y1, x2 - x1, y2 - y1, Color.Yellow * 0.3f);
                DrawRect(gridX + x1, gridY + y1, x2 - x1, 2, Color.Yellow);
                DrawRect(gridX + x1, gridY + y1 + (y2 - y1) - 2, x2 - x1, 2, Color.Yellow);
                DrawRect(gridX + x1, gridY + y1, 2, y2 - y1, Color.Yellow);
                DrawRect(gridX + x1 + (x2 - x1) - 2, gridY + y1, 2, y2 - y1, Color.Yellow);
            }
            
            // Collision cursor — crosshair + snapped cell highlight
            if (_trCollisionMode && !_trDraggingCollision)
            {
                var ms = Mouse.GetState();
                var kbs = Keyboard.GetState();
                int cmx = ms.X - gridX, cmy = ms.Y - gridY;
                int snap = kbs.IsKeyDown(Keys.LeftShift) || kbs.IsKeyDown(Keys.RightShift) ? TSDst / 2 : TSDst;
                int cellX = (cmx / snap) * snap;
                int cellY = (cmy / snap) * snap;
                int sx = gridX + cellX, sy = gridY + cellY;
                // Highlight snapped cell
                DrawRect(sx, sy, snap, snap, Color.White * 0.15f);
                DrawRect(sx, sy, snap, 1, Color.White * 0.5f);
                DrawRect(sx, sy + snap - 1, snap, 1, Color.White * 0.5f);
                DrawRect(sx, sy, 1, snap, Color.White * 0.5f);
                DrawRect(sx + snap - 1, sy, 1, snap, Color.White * 0.5f);
                // Crosshair
                DrawRect(ms.X - 8, ms.Y, 17, 1, Color.White * 0.6f);
                DrawRect(ms.X, ms.Y - 8, 1, 17, Color.White * 0.6f);
                // Snap size indicator
                string snapLabel = snap == TSDst / 2 ? "½" : "1×1";
                DrawTextFallback(ms.X + 10, ms.Y - 14, snapLabel, Color.White * 0.5f, 0.6f);
            }
        }
        
        // ── Palette (left side, fixed) ──
        DrawRect(0, 50, palW, ScreenH - 50, new Color(25, 25, 30));
        
        var palSheet = _tsSheets != null && _trSheetIdx < _tsSheets.Length ? _tsSheets[_trSheetIdx] : null;
        if (palSheet != null)
        {
            int palTileSize = 24;
            int palGap = 1;
            int palCols = (palW - 8) / (palTileSize + palGap);
            int sheetCols2 = palSheet.Width / TS16;
            int sheetRows2 = palSheet.Height / TS16;
            int totalTiles = sheetCols2 * sheetRows2;
            
            int palRows = (totalTiles + palCols - 1) / palCols;
            int maxScroll = Math.Max(0, palRows * (palTileSize + palGap) - (ScreenH - 60));
            if (_trPalScroll < 0) _trPalScroll = 0;
            if (_trPalScroll > maxScroll) _trPalScroll = maxScroll;
            
            for (int i = 0; i < totalTiles; i++)
            {
                int pc = i % palCols;
                int pr = i / palCols;
                int px = 4 + pc * (palTileSize + palGap);
                int py = 54 + pr * (palTileSize + palGap) - _trPalScroll;
                
                if (py + palTileSize < 50 || py > ScreenH) continue;
                
                int sr = i / sheetCols2;
                int sc = i % sheetCols2;
                var src = new Rectangle(sc * TS16, sr * TS16, TS16, TS16);
                
                DrawRect(px, py, palTileSize, palTileSize, new Color(35, 35, 40));
                _spriteBatch.Draw(palSheet, new Rectangle(px, py, palTileSize, palTileSize), src, Color.White);
                
                if (i == _trSelectedTile && _trSelectedSheet == _trSheetIdx)
                {
                    DrawRect(px - 1, py - 1, palTileSize + 2, 1, Color.Lime);
                    DrawRect(px - 1, py + palTileSize, palTileSize + 2, 1, Color.Lime);
                    DrawRect(px - 1, py, 1, palTileSize, Color.Lime);
                    DrawRect(px + palTileSize, py, 1, palTileSize, Color.Lime);
                }
            }
        }
        
        // ── Header (fixed) ──
        DrawRect(0, 0, ScreenW, 50, new Color(15, 15, 20, 230));
        string layerStr = _trCollisionMode ? "COLLISION" : (_trActiveLayer == 0 ? "BG" : _trActiveLayer == 1 ? "MID" : "FG");
        string viewStr = _trLayerView == 0 ? "" : _trLayerView == 1 ? " [BG ONLY]" : _trLayerView == 2 ? " [MID ONLY]" : " [FG ONLY]";
        string selStr = _trCollisionMode ? "Drag=add, RClick=del, Shift=half, Arrows=ledge, Space=player-only" : (_trSelectedTile >= 0 ? $"{_tsNames[_trSelectedSheet]}#{_trSelectedTile}" : "ERASER");
        string roomLabel = _trPaintRoom == 50 ? "5b (Cave)" : _trPaintRoom.ToString();
        string header = $"PAINT — Room {roomLabel} ({roomCols}×{roomRows})  |  Mode: {layerStr}{viewStr}  |  {selStr}";
        Color headerColor = _trCollisionMode ? new Color(255, 100, 100) : new Color(200, 170, 100);
        DrawTextOutlined(10, 6, header, headerColor, Color.Black, 0.9f);
        string controls = _trCollisionMode 
            ? "WASD:pan  L/R:room  C:tiles  Click+drag:add wall  RClick:delete  Ctrl+S:save  ESC:back"
            : "WASD:pan  L/R:room  TAB:sheet  L:layer  V:view  C:collision  Click:paint  RClick:erase  X:eraser  F:fill  G:overlay  Ctrl+S:save  ESC:back";
        DrawTextOutlined(10, 28, controls, new Color(100, 100, 120), Color.Black, 0.65f);
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
    private void DrawModeSelect(GameTime gameTime)
    {
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        var tf = _titleFont ?? _font;
        
        DrawTextCenteredOutlined(160, "SELECT MODE", new Color(200, 170, 100), Color.Black, 2f, tf, 2);
        
        string[] options = { "The Awakening", "Campaign", "Gauntlet", "Tile Renderer", "Quit" };
        string[] descs = {
            "A guided journey. Discover your power.",
            "Explore the world. Uncover the myth.",
            "Endless waves. How long can you last?",
            "Browse and inspect tilesets.",
            "Return to the void."
        };
        
        bool flashVisible = ((int)(_menuFlashTimer * 8f)) % 2 == 0;
        float fadeAlpha = _menuFadeTimer > 0 ? _menuFadeTimer / 0.8f : 1f;
        
        for (int i = 0; i < options.Length; i++)
        {
            int y = 280 + i * 70;
            bool selected = i == _menuSelection;
            
            if (i == _menuFlashSelection && _menuTransitioning)
            {
                if (flashVisible)
                {
                    float pulse = (MathF.Sin(_titleTimer * 4f) + 1f) / 2f;
                    Color selColor = Color.Lerp(new Color(255, 215, 0), Color.White, pulse * 0.3f) * fadeAlpha;
                    int optW = MeasureText(options[i], 1.5f, tf);
                    DrawTextOutlined(ScreenW / 2 - optW / 2 - 25, y, ">", selColor, Color.Black, 1.5f, tf);
                    DrawTextOutlined(ScreenW / 2 - optW / 2 + 5, y, options[i], selColor, Color.Black, 1.5f, tf);
                    DrawTextCenteredOutlined(y + 42, descs[i], new Color(120, 120, 130) * fadeAlpha, Color.Black * 0.5f, 0.8f, tf);
                }
            }
            else if (selected)
            {
                float pulse = (MathF.Sin(_titleTimer * 4f) + 1f) / 2f;
                Color selColor = Color.Lerp(new Color(255, 215, 0), Color.White, pulse * 0.3f);
                int optW = MeasureText(options[i], 1.5f, tf);
                DrawTextOutlined(ScreenW / 2 - optW / 2 - 25, y, ">", selColor, Color.Black, 1.5f, tf);
                DrawTextOutlined(ScreenW / 2 - optW / 2 + 5, y, options[i], selColor, Color.Black, 1.5f, tf);
                DrawTextCenteredOutlined(y + 42, descs[i], new Color(120, 120, 130), Color.Black * 0.5f, 0.8f, tf);
            }
            else
            {
                int optW = MeasureText(options[i], 1.5f, tf);
                DrawTextOutlined(ScreenW / 2 - optW / 2 + 5, y, options[i], new Color(100, 100, 110), Color.Black * 0.5f, 1.5f, tf);
            }
        }
        
        // Controls hint
        int chW = MeasureText("W/S or Up/Down  |  ENTER");
        DrawTextOutlined(ScreenW / 2 - chW / 2, 560, "W/S or Up/Down  |  ENTER", new Color(80, 80, 90), Color.Black * 0.5f);
        
        // Full-screen fade to black during menu transition
        if (_menuFadeTimer > 0)
            DrawRect(0, 0, ScreenW, ScreenH, Color.Black * (1f - _menuFadeTimer / 0.8f));
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
    private void DrawGameOver(GameTime gameTime)
    {
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        var tf = _titleFont ?? _font;
        
        // Dark background with red tint
        _spriteBatch.Draw(_pixel, new Rectangle(0, 0, ScreenW, ScreenH), new Color(30, 5, 5));
        
        // Death title
        float shake = _gameOverTimer < 0.5f ? (0.5f - _gameOverTimer) * 10f * MathF.Sin(_gameOverTimer * 40f) : 0f;
        string deathText = "YOU HAVE FALLEN";
        int dtW = MeasureText(deathText, 2.5f, tf);
        DrawTextOutlined((int)(ScreenW / 2 - dtW / 2 + shake), 160, deathText, new Color(200, 40, 40), Color.Black, 2.5f, tf, 2);
        
        // Stats — centered
        int statY = 270;
        DrawTextCenteredOutlined(statY, $"Wave Reached:  {_wave}", new Color(180, 180, 180), Color.Black * 0.5f, 1f, tf);
        DrawTextCenteredOutlined(statY + 30, $"Best Streak:   {_bestStreak}", new Color(180, 180, 180), Color.Black * 0.5f, 1f, tf);
        DrawTextCenteredOutlined(statY + 60, $"Ether Shards: {_hardEther}", new Color(100, 200, 220), Color.Black * 0.5f, 1f, tf);
        
        // Options (after delay)
        if (_gameOverTimer >= 1f)
        {
            string[] opts = { "Retry", "Mode Select", "Title Screen" };
            for (int i = 0; i < opts.Length; i++)
            {
                int y = 410 + i * 40;
                bool selected = i == _gameOverSelection;
                Color c = selected ? Color.Lerp(new Color(255, 215, 0), Color.White, (MathF.Sin(_titleTimer * 4f) + 1f) / 2f * 0.3f) : new Color(100, 100, 110);
                int ow = MeasureText(opts[i], 1f, tf);
                if (selected) DrawTextOutlined(ScreenW / 2 - ow / 2 - 15, y, ">", c, Color.Black, 1f, tf);
                DrawTextOutlined(ScreenW / 2 - ow / 2, y, opts[i], c, Color.Black, 1f, tf);
            }
        }
        else
        {
            // "Processing..." text before options appear
            float dots = (_gameOverTimer * 3f) % 3f;
            string wait = "..." .Substring(0, (int)dots + 1);
            DrawTextFallback(ScreenW / 2 - 20, 420, wait, new Color(80, 80, 80));
        }
        
        _spriteBatch.End();
        DrawPixelCursor();
    }
    
    private void DrawPlayer(Vector2 pos, Vector2 aimDir, Color tint, float gameTime, Color essenceColor, float jumpHeight = 0f)
    {
        // During cave transition, draw scaled silhouette instead of full player
        if (_caveTransScale < 0.95f)
        {
            float s = _caveTransScale;
            int sz = (int)(PlayerSize * s);
            DrawRect((int)(pos.X - sz / 2), (int)(pos.Y - sz / 2), sz, sz, tint * s);
            return;
        }
        
        int bx = (int)(pos.X - 8);
        int by = (int)(pos.Y - 8);
        
        // Drop shadow — scales with jump height (smaller when higher)
        int groundY = by + 18 + (int)jumpHeight; // shadow stays on ground
        float shadowScale = jumpHeight > 0.5f ? (1f - MathHelper.Clamp(jumpHeight / 60f, 0f, 0.55f)) : 1f;
        int shadowW = (int)(20f * shadowScale);
        int shadowH = (int)(4f * shadowScale + 1f);
        int shadowX = (int)(pos.X - shadowW / 2);
        DrawRect(shadowX, groundY, shadowW, shadowH, new Color(0, 0, 0, (int)(80 * shadowScale)));
        DrawRect(shadowX + 2, groundY + 1, shadowW - 4, MathHelper.Max(shadowH - 1, 1), new Color(0, 0, 0, (int)(50 * shadowScale)));
        
        Color blk = Color.Black;
        
        // Sprite-based player
        if (_playerTex != null)
        {
            int srcX = (KF_COL + _walkFrame) * KF_W;
            int srcY = _facingDir * KF_H;
            var srcRect = new Rectangle(srcX, srcY, KF_W, KF_H);
            float scale = 2.5f; // 26×36 → 65×90 display
            var origin = new Vector2(KF_W / 2f, KF_H - 4f); // anchor at feet
            var drawPos = new Vector2(pos.X, pos.Y + PlayerSize / 2f + 14f); // +14 to lower sprite
            
            // Hit flash
            Color spriteTint = tint;
            
            _spriteBatch.Draw(_playerTex, drawPos, srcRect, spriteTint,
                0f, origin, scale, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
        }
        else
        {
            // Fallback rect player
            int pw = (int)PlayerSize;
            int ph = (int)PlayerSize;
            int px = (int)(pos.X - pw / 2);
            int py = (int)(pos.Y - ph / 2);
            DrawRect(px, py, pw, ph, tint);
            DrawRect(px, py, pw, 1, blk);
            DrawRect(px, py + ph - 1, pw, 1, blk);
            DrawRect(px, py, 1, ph, blk);
            DrawRect(px + pw - 1, py, 1, ph, blk);
            // Eyes (show facing direction)
            int eyeX = aimDir.X >= 0 ? px + pw - 6 : px + 3;
            int eyeY = py + 4;
            DrawRect(eyeX, eyeY, 3, 3, Color.White);
            DrawRect(eyeX + (aimDir.X >= 0 ? 1 : 0), eyeY + 1, 1, 1, blk);
        }
        
        // Sword swing arc (sprite-based)
        if (_hasSword && _swordTimer > 0 && _swordTex != null)
        {
            float swingProgress = 1f - (_swordTimer / SwordSwingTime);
            float baseAngle = MathF.Atan2(_swordDir.Y, _swordDir.X);
            float sweepAngle = baseAngle + MathHelper.Lerp(-SwordArc / 2f, SwordArc / 2f, swingProgress);
            var srcRect = new Rectangle(0, 0, 16, 16);
            int drawSize = 48;
            var origin = new Vector2(8, 15); // pivot at base/hilt of sword
            float dist = 8f; // close to player body
            float sx = pos.X + MathF.Cos(sweepAngle) * dist;
            float sy = pos.Y + MathF.Sin(sweepAngle) * dist - jumpHeight;
            float rot = sweepAngle + MathF.PI / 2f;
            _spriteBatch.Draw(_swordTex, new Vector2(sx, sy), srcRect, Color.White,
                rot, origin, drawSize / 16f, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
            for (int t = 1; t <= 3; t++)
            {
                float trailAngle = sweepAngle - (SwordArc / 8f) * t;
                float trailAlpha = (1f - t / 4f) * 0.3f;
                float tsx = pos.X + MathF.Cos(trailAngle) * 8f;
                float tsy = pos.Y + MathF.Sin(trailAngle) * 8f - jumpHeight;
                float trot = trailAngle + MathF.PI / 2f;
                _spriteBatch.Draw(_swordTex, new Vector2(tsx, tsy), srcRect, Color.White * trailAlpha,
                    trot, origin, drawSize / 16f, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
            }
        }
        return;
        
        /* ORIGINAL KNIGHT DESIGN — preserved for later
        Color ltGrey = Color.Lerp(new Color(190, 195, 200), tint, 0.3f);
        Color dkGrey = Color.Lerp(new Color(120, 125, 130), tint, 0.2f);
        Color visor = new Color(30, 30, 40);
        Color belt = new Color(50, 50, 55);
        
        // Row 0: helm top
        DrawRect(bx + 2, by, 12, 1, blk);
        // Row 1-3: helm
        for (int r = 1; r <= 3; r++)
        {
            DrawRect(bx + 1, by + r, 1, 1, blk);
            DrawRect(bx + 2, by + r, 12, 1, ltGrey);
            DrawRect(bx + 14, by + r, 1, 1, blk);
            // dark accent lines
            if (r == 2) { DrawRect(bx + 4, by + r, 1, 1, dkGrey); DrawRect(bx + 11, by + r, 1, 1, dkGrey); }
        }
        // Row 4-5: visor (T-shape)
        for (int r = 4; r <= 5; r++)
        {
            DrawRect(bx + 1, by + r, 1, 1, blk);
            DrawRect(bx + 2, by + r, 2, 1, ltGrey);
            DrawRect(bx + 4, by + r, 8, 1, visor); // horizontal bar of T
            DrawRect(bx + 12, by + r, 2, 1, ltGrey);
            DrawRect(bx + 14, by + r, 1, 1, blk);
        }
        // T vertical slit
        DrawRect(bx + 7, by + 4, 2, 2, new Color(15, 15, 20));
        // Row 6: chin
        DrawRect(bx + 2, by + 6, 12, 1, dkGrey);
        DrawRect(bx + 1, by + 6, 1, 1, blk);
        DrawRect(bx + 14, by + 6, 1, 1, blk);
        // Row 7-8: shoulders (wider)
        for (int r = 7; r <= 8; r++)
        {
            DrawRect(bx, by + r, 1, 1, blk);
            DrawRect(bx + 1, by + r, 14, 1, ltGrey);
            DrawRect(bx + 15, by + r, 1, 1, blk);
        }
        // Row 9-10: body
        for (int r = 9; r <= 10; r++)
        {
            DrawRect(bx + 2, by + r, 1, 1, blk);
            DrawRect(bx + 3, by + r, 10, 1, ltGrey);
            DrawRect(bx + 13, by + r, 1, 1, blk);
        }
        // Row 11-12: belt
        for (int r = 11; r <= 12; r++)
        {
            DrawRect(bx + 2, by + r, 1, 1, blk);
            DrawRect(bx + 3, by + r, 10, 1, belt);
            DrawRect(bx + 13, by + r, 1, 1, blk);
        }
        // Belt buckle
        DrawRect(bx + 7, by + 11, 2, 2, dkGrey);
        // Row 13-15: legs
        for (int r = 13; r <= 15; r++)
        {
            // Left leg
            DrawRect(bx + 3, by + r, 1, 1, blk);
            DrawRect(bx + 4, by + r, 3, 1, dkGrey);
            DrawRect(bx + 7, by + r, 1, 1, blk);
            // Right leg
            DrawRect(bx + 8, by + r, 1, 1, blk);
            DrawRect(bx + 9, by + r, 3, 1, dkGrey);
            DrawRect(bx + 12, by + r, 1, 1, blk);
        }
        // Cape hint on back side (opposite aim)
        float capeX = -aimDir.X;
        if (MathF.Abs(capeX) > 0.3f)
        {
            int cx = capeX > 0 ? bx + 13 : bx + 1;
            DrawRect(cx, by + 8, 2, 6, new Color(80, 30, 30));
        }
        
        // Wand extending toward cursor
        if (_hasWand)
        {
            Color wandColor = _loadout.Essence != Essence.None ? essenceColor : new Color(160, 160, 170);
            for (int i = 0; i < 6; i++)
            {
                int wx = (int)(pos.X + aimDir.X * (8 + i));
                int wy = (int)(pos.Y + aimDir.Y * (8 + i));
                DrawRect(wx, wy, 1, 1, wandColor);
            }
            // Wand tip glow
            int tx = (int)(pos.X + aimDir.X * 14);
            int ty = (int)(pos.Y + aimDir.Y * 14);
            DrawRect(tx - 1, ty - 1, 3, 3, wandColor * 0.5f);
            
            // Overheat glow when ether is low (visual only)
            float etherPct = _playerEther / EffectiveMaxEther;
            if (etherPct < 0.4f)
            {
                float heat = 1f - (etherPct / 0.4f); // 0 at 40%, 1 at 0%
                float flicker = 0.7f + 0.3f * MathF.Sin(gameTime * 12f + MathF.Sin(gameTime * 5f) * 2f);
                float glowAlpha = heat * flicker * 0.6f;
                Color heatColor = Color.Lerp(new Color(255, 140, 40), new Color(255, 60, 20), heat);
                
                // Glow along wand barrel
                for (int i = 0; i < 6; i++)
                {
                    int gx = (int)(pos.X + aimDir.X * (8 + i));
                    int gy = (int)(pos.Y + aimDir.Y * (8 + i));
                    DrawRect(gx - 1, gy - 1, 3, 3, heatColor * (glowAlpha * (0.3f + 0.7f * i / 6f)));
                }
                // Hot tip pulse
                DrawRect(tx - 2, ty - 2, 5, 5, heatColor * (glowAlpha * 0.8f));
                DrawRect(tx - 1, ty - 1, 3, 3, new Color(255, 220, 160) * (glowAlpha * 0.5f));
            }
        }
        
        // Sword swing arc
        if (_hasSword && _swordTimer > 0)
        {
            float swingProgress = 1f - (_swordTimer / SwordSwingTime); // 0→1
            float baseAngle = MathF.Atan2(_swordDir.Y, _swordDir.X);
            // Sweep from -45° to +45° over the swing duration
            float sweepAngle = baseAngle + MathHelper.Lerp(-SwordArc / 2f, SwordArc / 2f, swingProgress);
            
            if (_swordTex != null)
            {
                // Draw sprite sword — top-left 16×16 from sheet, scaled up, rotated along sweep
                var srcRect = new Rectangle(0, 0, 16, 16);
                int drawSize = 48; // 3x scale
                var origin = new Vector2(8, 14); // pivot near hilt (bottom-center of 16×16)
                float dist = 20f; // distance from player center to sword pivot
                float sx = pos.X + MathF.Cos(sweepAngle) * dist;
                float sy = pos.Y + MathF.Sin(sweepAngle) * dist;
                // Rotate sword to point outward (+90° because sprite points up)
                float rot = sweepAngle + MathF.PI / 2f;
                _spriteBatch.Draw(_swordTex, new Vector2(sx, sy), srcRect, Color.White,
                    rot, origin, drawSize / 16f, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
                
                // Trail afterimages
                for (int t = 1; t <= 3; t++)
                {
                    float trailAngle = sweepAngle - (SwordArc / 8f) * t;
                    float trailAlpha = (1f - t / 4f) * 0.3f;
                    float tsx = pos.X + MathF.Cos(trailAngle) * dist;
                    float tsy = pos.Y + MathF.Sin(trailAngle) * dist;
                    float trot = trailAngle + MathF.PI / 2f;
                    _spriteBatch.Draw(_swordTex, new Vector2(tsx, tsy), srcRect, Color.White * trailAlpha,
                        trot, origin, drawSize / 16f, Microsoft.Xna.Framework.Graphics.SpriteEffects.None, 0f);
                }
            }
            else
            {
            Color bladeColor = new Color(200, 210, 220);
            Color trailColor = new Color(180, 190, 200) * (0.6f - swingProgress * 0.4f);
            
            // Draw blade (line of pixels from player outward)
            for (int i = 8; i < (int)SwordRange; i += 2)
            {
                float px2 = pos.X + MathF.Cos(sweepAngle) * i;
                float py2 = pos.Y + MathF.Sin(sweepAngle) * i;
                float alpha = 1f - (float)i / SwordRange;
                DrawRect((int)px2, (int)py2, 2, 2, bladeColor * alpha);
            }
            
            // Draw trailing arc (3 trailing lines for sweep effect)
            for (int t = 1; t <= 3; t++)
            {
                float trailAngle = sweepAngle - (SwordArc / 8f) * t;
                float trailAlpha = (1f - t / 4f) * 0.4f;
                for (int i = 12; i < (int)SwordRange - 5; i += 3)
                {
                    float px2 = pos.X + MathF.Cos(trailAngle) * i;
                    float py2 = pos.Y + MathF.Sin(trailAngle) * i;
                    DrawRect((int)px2, (int)py2, 1, 1, trailColor * trailAlpha);
                }
            }
            
            // Blade tip spark
            float tipX = pos.X + MathF.Cos(sweepAngle) * (SwordRange - 4);
            float tipY = pos.Y + MathF.Sin(sweepAngle) * (SwordRange - 4);
                        DrawRect((int)tipX - 1, (int)tipY - 1, 3, 3, Color.White * (0.8f - swingProgress * 0.6f));
            } // end else (fallback rect sword)
        }
        END OF ORIGINAL KNIGHT DESIGN */
    }

    private static Color GetEssenceColor(Essence e) => e switch
    {
        Essence.Cinder => new Color(255, 100, 30),
        Essence.Dark => new Color(120, 40, 160),
        Essence.Bone => new Color(220, 220, 210),
        Essence.Silk => new Color(180, 100, 220),
        Essence.Pulse => new Color(255, 240, 60),
        Essence.Hollow => new Color(60, 200, 255),
        Essence.Sap => new Color(60, 180, 60),
        _ => new Color(200, 200, 200),
    };

    private void DrawHUD()
    {
        int hudY = 14;
        
        // ═══ LOADOUT CARDS — combo title cards that flip on Q swap ═══
        float swapT = _loadoutSwapTimer > 0 ? 1f - (_loadoutSwapTimer / LoadoutSwapDuration) : 1f;
        float smoothSwap = swapT * swapT * (3f - 2f * swapT); // smoothstep
        
        int cardX = 20, cardW = 360, cardH = 36;
        int peekX = 6, peekY = 10;
        
        float activeY = hudY;
        float inactiveY = hudY + peekY;
        
        if (_loadoutSwapTimer > 0)
        {
            activeY = MathHelper.Lerp(hudY + peekY, hudY, smoothSwap);
            inactiveY = MathHelper.Lerp(hudY, hudY + peekY, smoothSwap);
        }
        
        // Resolve both loadout names
        var activeLo = _loadout;
        var inactiveLo = _loadoutSecondary;
        var activeParms = ProjectileParams.Resolve(activeLo);
        var activeEssCol = new Color(activeParms.Color.R, activeParms.Color.G, activeParms.Color.B);
        
        // Get combo names (fusion > dual > default)
        string activeComboName = _currentFusion ?? _currentDualCombo ?? activeLo.ComboName;
        string inactiveComboName = inactiveLo.ComboName; // no fusion tracking for inactive
        
        Color activeAccent = _loadoutIsPrimary ? new Color(255, 200, 100) : new Color(100, 200, 255);
        Color inactiveAccent = _loadoutIsPrimary ? new Color(100, 200, 255) : new Color(255, 200, 100);
        
        // INACTIVE card (behind) — peeking out (only if it has content)
        float dimA = 0.45f;
        if (inactiveLo.FilledSlots > 0)
        {
            DrawRect(cardX + peekX, (int)inactiveY, cardW, cardH, new Color(18, 18, 25));
            DrawRect(cardX + peekX, (int)inactiveY, cardW, 2, inactiveAccent * dimA);
            DrawTextFallback(cardX + peekX + 8, (int)inactiveY + 12, inactiveComboName, Color.Gray * dimA);
        }
        
        // ACTIVE card (top)
        DrawRect(cardX, (int)activeY, cardW, cardH, new Color(25, 25, 35));
        DrawRect(cardX, (int)activeY, cardW, 2, activeAccent);
        DrawTextFallback(cardX + 8, (int)activeY + 4, "Q", activeAccent * 0.5f, 0.7f);
        DrawTextFallback(cardX + 22, (int)activeY + 4, activeComboName, Color.White, 1.1f);
        // Essence color dot — outside card to the right
        DrawRect(cardX + cardW + 10, (int)activeY + 10, 14, 14, activeEssCol);
        DrawRect(cardX + cardW + 11, (int)activeY + 11, 12, 12, activeEssCol * 0.6f);
        
        var parms = activeParms;
        var essenceColor = activeEssCol;
        
        // Utility essence — right of combo card + dot
        string utilName = _utilityEssence == Essence.None ? "---" : _utilityEssence.ToString();
        Color utilColor = _utilityEssence == Essence.None ? Color.Gray : GetEssenceColor(_utilityEssence);
        int utilX = cardX + cardW + 34;
        DrawRect(utilX, hudY, 100, cardH, new Color(20, 25, 20));
        DrawRect(utilX, hudY, 100, 2, new Color(60, 220, 160) * 0.6f);
        DrawTextFallback(utilX + 4, hudY + 4, "E", new Color(60, 220, 160) * 0.5f, 0.7f);
        DrawTextFallback(utilX + 16, hudY + 4, utilName, utilColor);
        // Utility flash on use
        if (_utilityFlashTimer > 0)
            DrawRect(utilX, hudY, 100, cardH, utilColor * (_utilityFlashTimer / 0.4f * 0.3f));
        
        // Stats line below active card
        string statsLine = $"DMG:{parms.BaseDamage:F0}  SPD:{parms.Speed:F0}  FR:{parms.FireRate:F2}s";
        DrawTextFallback(cardX + 8, (int)activeY + cardH + 8, statsLine, Color.Gray * 0.6f, 0.7f);
        
        if (_gameMode != GameMode.Awakening)
            DrawTextFallback(cardX + 8, (int)activeY + cardH + 20, $"Wave {_wave}  Kills {_killCount}/{_waveKillTarget}", Color.Gray * 0.5f, 0.7f);

        // Fusion/combo name above arena
        if (_currentFusion != null && _fusionFlashTimer > 0)
        {
            float pulse = (MathF.Sin(_fusionFlashTimer * 8f) + 1f) / 2f;
            var goldColor = new Color(255, 215, 0) * (0.6f + 0.4f * pulse);
            DrawTextFallback(_arena.Center.X - _currentFusion.Length * 4, _arena.Top - 20, $"[ {_currentFusion} ]", goldColor);
        }
        else if (_currentDualCombo != null && _fusionFlashTimer > 0)
        {
            float pulse = (MathF.Sin(_fusionFlashTimer * 8f) + 1f) / 2f;
            var comboFlash = new Color(135, 206, 235) * (0.6f + 0.4f * pulse);
            DrawTextFallback(_arena.Center.X - _currentDualCombo.Length * 4, _arena.Top - 20, $"[ {_currentDualCombo} ]", comboFlash);
        }
        
        // ═══ COMBO DISCOVERY BANNER ═══
        if (_comboDiscoveryTimer > 0 && _comboDiscoveryName != null)
        {
            float t = _comboDiscoveryTimer / 1.5f; // 1→0
            float fadeIn = MathF.Min((1.5f - _comboDiscoveryTimer) / 0.2f, 1f); // quick fade in
            float fadeOut = MathF.Min(_comboDiscoveryTimer / 0.3f, 1f); // fade out at end
            float alpha = fadeIn * fadeOut;
            float scale = 1.2f + 0.3f * (1f - fadeIn); // starts big, settles to 1.2x
            float pulse = MathF.Sin(_totalTime * 12f) * 0.1f;
            
            string label = "NEW COMBO DISCOVERED";
            int cx = _arena.Center.X;
            int cy = _arena.Center.Y - 40;
            
            // Dark backdrop
            DrawRect(cx - 140, cy - 5, 280, 45, new Color(0, 0, 0) * (alpha * 0.7f));
            
            // "NEW COMBO DISCOVERED" header
            Color headerCol = new Color(255, 230, 100) * (alpha + pulse);
            DrawTextFallback(cx - label.Length * 4, cy, label, headerCol);
            
            // Combo name — big and bright
            Color nameCol = new Color(255, 255, 255) * alpha;
            DrawTextFallback(cx - _comboDiscoveryName.Length * 5, cy + 18, _comboDiscoveryName, nameCol, scale);
        }
        
        // Kill streak
        if (_streakCount >= 3)
        {
            string streakLabel = _streakCount >= 25 ? "MASSACRE" :
                                 _streakCount >= 15 ? "RAMPAGE" :
                                 _streakCount >= 10 ? "UNSTOPPABLE" :
                                 _streakCount >= 5  ? "KILLING SPREE" : "STREAK";
            string streakText = $"{_streakCount}x {streakLabel}";
            float streakPulse = (MathF.Sin(_gorgonTime * 10f) + 1f) / 2f; // reuse gorgonTime as general time
            float streakScale = 1f + _streakCount * 0.02f; // text conceptually bigger at higher streaks
            Color streakColor = _streakCount >= 25 ? new Color(255, 50, 50) :
                                _streakCount >= 15 ? new Color(255, 140, 0) :
                                _streakCount >= 10 ? new Color(255, 215, 0) :
                                _streakCount >= 5  ? new Color(200, 200, 255) :
                                                     Color.White;
            streakColor *= (0.7f + 0.3f * streakPulse);
            int streakX = _arena.Center.X - streakText.Length * 4;
            int streakY = _arena.Top + 15;
            DrawTextFallback(streakX, streakY, streakText, streakColor);
        }
        
        // Wave banner
        if (_waveBannerTimer > 0)
        {
            float bannerAlpha = MathHelper.Clamp(_waveBannerTimer / 0.5f, 0f, 1f); // fade out last 0.5s
            string bannerText = _bossAlive ? "BOSS" : $"WAVE {_wave}";
            Color bannerColor = _bossAlive ? new Color(255, 80, 80) : new Color(255, 255, 255);
            int bw = bannerText.Length * 8;
            DrawTextFallback(_arena.Center.X - bw / 2, _arena.Center.Y - 20, bannerText, bannerColor * bannerAlpha);
        }
        
        // HP bar — top right of HUD
        int hpBarX = 1010;
        int hpBarY = 8;
        int hpBarW = 200;
        DrawRect(hpBarX, hpBarY, hpBarW, 10, new Color(60, 20, 20));
        DrawRect(hpBarX, hpBarY, (int)(hpBarW * (_playerHp / PlayerMaxHp)), 10, new Color(200, 50, 50));
        DrawTextFallback(hpBarX - 83, hpBarY - 1, $"HP {_playerHp:F0}", Color.White);
        
        // Mana bar — below HP bar (juiced)
        int etherBarY = hpBarY + 14;
        float etherFrac = _etherDisplay / EffectiveMaxEther;
        float etherActual = _playerEther / EffectiveMaxEther;
        bool etherLow = etherFrac < 0.2f;
        float etherPulse = etherLow ? 0.15f * MathF.Sin(_totalTime * 8f) : 0f;
        
        // Background
        DrawRect(hpBarX - 1, etherBarY - 1, hpBarW + 2, 10, new Color(10, 10, 35));
        
        // Trailing ghost (shows where mana WAS — smooth drain visual)
        if (_etherDisplay > _playerEther)
        {
            int ghostW = (int)(hpBarW * (_etherDisplay / EffectiveMaxEther));
            DrawRect(hpBarX, etherBarY, ghostW, 8, new Color(100, 130, 200, 80));
        }
        
        // Main fill
        int etherW = (int)(hpBarW * etherActual);
        Color etherCol = etherLow 
            ? Color.Lerp(new Color(60, 100, 220), new Color(180, 60, 60), 0.5f + etherPulse) 
            : new Color(60, 100, 220);
        DrawRect(hpBarX, etherBarY, etherW, 8, etherCol);
        
        // Bright core line (top 2px for glossy look)
        if (etherW > 2)
            DrawRect(hpBarX, etherBarY, etherW, 2, new Color(120, 170, 255, 140));
        
        // Lambent glow when ether is full
        bool etherFull = _playerEther >= EffectiveMaxEther - 0.1f;
        if (etherFull)
        {
            float glow = (MathF.Sin(_totalTime * 3f) + 1f) / 2f; // slow breathing 0→1
            float glow2 = (MathF.Sin(_totalTime * 7f) + 1f) / 2f; // faster shimmer
            // Outer glow halo
            DrawRect(hpBarX - 2, etherBarY - 2, hpBarW + 4, 12, new Color(100, 160, 255) * (glow * 0.25f));
            // Bright overlay on the bar itself
            DrawRect(hpBarX, etherBarY, etherW, 8, new Color(150, 200, 255) * (glow * 0.3f + glow2 * 0.1f));
            // Core shimmer line
            DrawRect(hpBarX, etherBarY + 3, etherW, 2, new Color(200, 230, 255) * (glow2 * 0.4f));
        }
        
        // Flash on spend
        if (_etherFlashTimer > 0)
        {
            float flashA = _etherFlashTimer / 0.15f;
            DrawRect(hpBarX, etherBarY - 1, hpBarW, 10, Color.White * (flashA * 0.4f));
        }
        
        // Label
        Color epLabelCol = etherLow ? Color.Lerp(new Color(100, 150, 255), new Color(255, 80, 80), 0.5f + etherPulse) : new Color(100, 150, 255);
        DrawTextFallback(hpBarX - 83, etherBarY - 1, $"EP {_playerEther:F0}", epLabelCol);
        
        // Ether shard counter — below mana bar
        DrawTextFallback(hpBarX, etherBarY + 14, $"Ether Crystals: {_hardEther}", new Color(200, 180, 255));
        
        // Ether clips — compact count display
        int clipX = hpBarX + hpBarW + 8;
        int clipY = etherBarY;
        int clipCount2 = SackClipCount();
        if (clipCount2 > 0)
        {
            float clipPulse = 0.6f + 0.3f * MathF.Sin(_totalTime * 4f);
            DrawRect(clipX, clipY, 10, 10, new Color(80, 160, 255) * (clipPulse * 0.7f));
            DrawRect(clipX + 2, clipY + 2, 6, 6, new Color(140, 200, 255) * (clipPulse * 0.9f));
            DrawTextFallback(clipX + 14, clipY, $"x{clipCount2}", new Color(140, 200, 255));
        }
        // Reload prompt
        if (SackClipCount() > 0 && _playerEther < 50f && !_reloadActive && _reloadTimer <= 0)
        {
            float promptPulse = 0.5f + 0.5f * MathF.Sin(_totalTime * 6f);
            DrawTextFallback(clipX + 40, clipY, "[R] Reload", new Color(100, 180, 255) * promptPulse);
        }
        
        // Active reload bar — sweeping cursor with sweet spot
        if (_reloadActive)
        {
            int barW = 80, barH = 8;
            int barX = (int)_playerPos.X - barW / 2;
            int barY = (int)_playerPos.Y - 35;
            // Background
            DrawRect(barX - 1, barY - 1, barW + 2, barH + 2, Color.Black * 0.8f);
            DrawRect(barX, barY, barW, barH, new Color(30, 30, 40));
            // Sweet spot zone (green)
            int ssX = barX + (int)(ReloadSweetSpotStart * barW);
            int ssW = (int)((ReloadSweetSpotEnd - ReloadSweetSpotStart) * barW);
            DrawRect(ssX, barY, ssW, barH, new Color(60, 200, 100) * 0.5f);
            // Cursor
            float visualPos = _reloadCursor <= 1f ? _reloadCursor : 2f - _reloadCursor;
            int cursorX = barX + (int)(visualPos * barW);
            DrawRect(cursorX - 1, barY - 2, 3, barH + 4, Color.White);
        }

        // Relic slots — below shards
        int relicX = hpBarX;
        int relicY = etherBarY + 32;
        for (int i = 0; i < 8; i++)
        {
            DrawRect(relicX + i * 28, relicY, 24, 24, new Color(40, 40, 50));
            DrawRect(relicX + i * 28 + 1, relicY + 1, 22, 22, new Color(25, 25, 35));
        }
        if (_hasCaliburn)
        {
            DrawRect(relicX + 2, relicY + 2, 20, 20, new Color(60, 60, 80));
            DrawTextFallback(relicX + 4, relicY + 6, "C", new Color(200, 200, 255));
        }
        if (_hasNimueTear)
        {
            DrawRect(relicX + 30, relicY + 2, 20, 20, new Color(60, 60, 80));
            DrawTextFallback(relicX + 32, relicY + 6, "N", new Color(100, 200, 255));
        }
        if (_hasWandOfMerlin)
        {
            DrawRect(relicX + 58, relicY + 2, 20, 20, new Color(80, 60, 60));
            DrawTextFallback(relicX + 60, relicY + 6, "W", new Color(255, 200, 100));
        }
        if (_hasHasteBand)
        {
            DrawRect(relicX + 86, relicY + 2, 20, 20, new Color(60, 80, 60));
            DrawTextFallback(relicX + 88, relicY + 6, "H", new Color(100, 255, 150));
        }
        if (_hasPhylactery)
        {
            DrawRect(relicX + 114, relicY + 2, 20, 20, new Color(60, 50, 80));
            DrawTextFallback(relicX + 116, relicY + 6, "P", new Color(180, 140, 255));
        }
        if (_hasDragonDance)
        {
            float ddAlpha = MathHelper.Clamp(_dragonDanceStacks * 2f, 0.3f, 1f);
            DrawRect(relicX + 142, relicY + 2, 20, 20, new Color(80, 50, 50));
            DrawTextFallback(relicX + 144, relicY + 6, "D", new Color(255, 100, 80) * ddAlpha);
            if (_dragonDanceStacks > 0.05f)
            {
                string stk = $"{(int)(_dragonDanceStacks * 100f)}%";
                DrawTextFallback(relicX + 142, relicY - 8, stk, new Color(255, 150, 100));
            }
        }
        if (_hasGrimoire)
        {
            DrawRect(relicX + 170, relicY + 2, 20, 20, new Color(50, 50, 80));
            DrawTextFallback(relicX + 172, relicY + 6, "G", new Color(150, 180, 255));
        }
        if (_hasTomeOfBinding)
        {
            DrawRect(relicX + 198, relicY + 2, 20, 20, new Color(70, 50, 60));
            DrawTextFallback(relicX + 200, relicY + 6, "T", new Color(220, 160, 200));
        }
        
        // Relic tooltip on hover — drawn at fixed position below relics with background
        {
            var ms = Mouse.GetState();
            string[] relicTooltips = { "Caliburn Shard: Pierce", "Nimue's Tear: Drain", "Wand of Merlin: Charge", "Haste Band: Speed", "Phylactery: +25% EP", "Dragon Dance: Kill buff", "Grimoire: Fusions", "Tome of Binding: Dual Combos" };
            bool[] hudRelicActive = { _hasCaliburn, _hasNimueTear, _hasWandOfMerlin, _hasHasteBand, _hasPhylactery, _hasDragonDance, _hasGrimoire, _hasTomeOfBinding };
            bool[] hudRelicOwned = { _ownsCaliburn, _ownsNimueTear, _ownsWandOfMerlin, _ownsHasteBand, _ownsPhylactery, _ownsDragonDance, _ownsGrimoire, _ownsTomeOfBinding };
            for (int i = 0; i < 7; i++)
            {
                if (hudRelicOwned[i] && ms.X >= relicX + i * 28 && ms.X <= relicX + i * 28 + 24 && ms.Y >= relicY && ms.Y <= relicY + 24)
                {
                    string tip = relicTooltips[i] + (hudRelicActive[i] ? "" : " (OFF)");
                    int tipW = MeasureText(tip, 0.8f);
                    int tipX = MathHelper.Clamp(relicX + i * 28, 4, ScreenW - tipW - 8);
                    int tipY = relicY + 30;
                    // Background box
                    DrawRect(tipX - 3, tipY - 2, tipW + 6, 16, Color.Black * 0.85f);
                    DrawTextOutlined(tipX, tipY, tip, Color.White, Color.Black, 0.8f);
                    break;
                }
            }
        }
        
        // Boss HP bar — just above arena
        if (_bossAlive)
        {
            Enemy boss = null;
            if (_enemyById.TryGetValue(_bossId, out var bossRef) && bossRef.Alive) boss = bossRef;
            if (boss != null)
            {
                int bossBarX = _arena.Left + 100;
                int bossBarY = _arena.Top - 14;
                int bossBarW = _arena.Width - 200;
                DrawRect(bossBarX, bossBarY, bossBarW, 6, new Color(40, 40, 40));
                float hpPct = boss.Hp / boss.MaxHp;
                DrawRect(bossBarX, bossBarY, (int)(bossBarW * hpPct), 6, boss.BaseColor);
                DrawTextFallback(bossBarX + bossBarW + 8, bossBarY - 2, "BOSS", boss.BaseColor);
            }
        }

        // Controls hint — bottom
        DrawTextOutlined(_arena.Left, _arena.Bottom + 24, "WASD:Move  LMB:Shoot  RMB:Charge  1/2/3:Cycle  SPACE:Bash  TAB:Inventory", new Color(80, 80, 90), Color.Black * 0.4f);

        // Charge indicator (while charging)
        if (_isCharging)
        {
            float pct = _chargeTimer / ChargeTime;
            int barW = 30;
            DrawRect((int)(_playerPos.X - barW / 2), (int)(_playerPos.Y - PlayerSize - 8), barW, 4, new Color(30, 30, 30));
            DrawRect((int)(_playerPos.X - barW / 2), (int)(_playerPos.Y - PlayerSize - 8), (int)(barW * pct), 4,
                pct >= 1f ? new Color(255, 220, 60) : new Color(200, 200, 200));
        }

        // Relic tooltips on hover
        var mouseState = Mouse.GetState();
        string[] relicNames = { "Caliburn Shard", "Nimue's Tear", "Wand of Merlin", "Haste Band", "" };
        string[] relicDescs = { "Pierce 1 enemy", "Heal 8% damage", "RMB charge (3x dmg)", "35% faster fire rate", "" };
        bool[] relicActive = { _hasCaliburn, _hasNimueTear, _hasWandOfMerlin, _hasHasteBand, false };
        for (int i = 0; i < 5; i++)
        {
            var box = new Rectangle(relicX + i * 28, relicY, 24, 24);
            if (box.Contains(mouseState.X, mouseState.Y) && relicNames[i].Length > 0)
            {
                string line1 = relicNames[i];
                string line2 = relicActive[i] ? relicDescs[i] : "(inactive)";
                int ttW = MathHelper.Max(line1.Length, line2.Length) * 7 + 12;
                int ttH = 28;
                // Position tooltip above the relic box, clamped to screen
                int ttX = MathHelper.Clamp(box.Center.X - ttW / 2, 4, ScreenW - ttW - 4);
                int ttY = box.Y - ttH - 4;
                DrawRect(ttX, ttY, ttW, ttH, new Color(15, 15, 25));
                DrawRect(ttX, ttY, ttW, 1, relicActive[i] ? new Color(200, 180, 80) : new Color(80, 80, 80));
                DrawTextFallback(ttX + 6, ttY + 4, line1, relicActive[i] ? new Color(255, 220, 100) : new Color(150, 150, 150));
                DrawTextFallback(ttX + 6, ttY + 16, line2, relicActive[i] ? new Color(180, 180, 160) : new Color(100, 100, 100));
            }
        }

        // Test mode panel
        if (_testMode)
        {
            int px = _arena.Right - 280;
            int py = _arena.Top + 5;
            DrawRect(px - 5, py - 5, 275, 360, new Color(20, 20, 30));

            DrawTextFallback(px, py, "=== TEST MODE (T to exit) ===", Color.Yellow);
            py += 18;
            DrawTextFallback(px, py, $"Combo: {_loadout.ComboName}", Color.White);
            py += 16;
            DrawTextFallback(px, py, $"Form: {_loadout.Form} (spd:{parms.Speed:F0} sz:{parms.Size:F0})", Color.White);
            py += 16;
            DrawTextFallback(px, py, $"Behavior: {_loadout.Behavior}", Color.White);
            if (parms.ShatterCount > 0) { py += 14; DrawTextFallback(px + 10, py, $"Shatters into {parms.ShatterCount}", Color.Gray); }
            if (parms.Bounces) { py += 14; DrawTextFallback(px + 10, py, $"Bounces {parms.MaxBounces}x", Color.Gray); }
            if (parms.BloomGrowRate > 0) { py += 14; DrawTextFallback(px + 10, py, $"Grows x{parms.BloomMaxScale:F0}", Color.Gray); }
            if (parms.Possesses) { py += 14; DrawTextFallback(px + 10, py, "Possesses on kill", Color.Gray); }
            if (parms.StasisRadius > 0) { py += 14; DrawTextFallback(px + 10, py, $"Stasis r:{parms.StasisRadius:F0} d:{parms.StasisDuration:F1}s", Color.Gray); }
            if (parms.WaveAmplitude > 0) { py += 14; DrawTextFallback(px + 10, py, $"Wave amp:{parms.WaveAmplitude:F0} freq:{parms.WaveFrequency:F0}", Color.Gray); }
            py += 16;
            string essenceDesc = _loadout.Essence switch
            {
                Essence.Cinder => "Cinder (+10% dmg, Ignite)",
                Essence.Dark => "Dark (+5% dmg, Fear)",
                Essence.Bone => "Bone (+15% dmg, burst)",
                Essence.Silk => "Silk (Slow)",
                Essence.Pulse => "Pulse (Stagger)",
                Essence.Hollow => "Hollow (-10% dmg, Silence)",
                Essence.Sap => "Sap (Leech HP)",
                _ => "None (kinetic)"
            };
            DrawTextFallback(px, py, $"Essence: {essenceDesc}", essenceColor);
            py += 16;
            DrawTextFallback(px, py, $"Fire Rate: {parms.FireRate:F2}s", Color.White);
            py += 16;
            DrawTextFallback(px, py, $"Base Damage: {parms.BaseDamage:F1}", Color.White);
            py += 16;
            if (parms.StatusChance > 0)
                DrawTextFallback(px, py, $"Status: {parms.StatusChance * 100:F0}% ({parms.StatusDuration:F1}s)", Color.White);
            else
                DrawTextFallback(px, py, "Status: none", Color.Gray);
            py += 16;
            DrawTextFallback(px, py, $"Relics: {(_hasCaliburn ? "Caliburn " : "")}{(_hasNimueTear ? "Nimue's Tear" : "")}", new Color(180, 180, 255));
            py += 20;
            if (_currentFusion != null)
            {
                DrawTextFallback(px, py, $"[SPELL FUSION: {_currentFusion}]", new Color(255, 215, 0));
                py += 16;
            }
            DrawTextOutlined(px, py, "1/2/3: Cycle  SPACE: Shield Bash", new Color(100, 100, 100), Color.Black * 0.4f);
            py += 14;
            DrawTextOutlined(px, py, "LMB: Shoot  T: Exit test  H: Hitboxes" + (_showHitboxes ? " [ON]" : ""), new Color(100, 100, 100), Color.Black * 0.4f);
            py += 18;
            DrawTextFallback(px, py, $"Bloom: {_bloomIntensity:F2} [Y/U]  Vignette: {_vignetteStrength:F2} [I/O]", Color.Yellow, 0.6f);
            py += 14;
            DrawTextFallback(px, py, $"PP: {(_postProcessEnabled ? "ON" : "OFF")} [P]  Shader: {(_shadersAvailable ? "YES" : "CPU")}", Color.Yellow, 0.6f);
            py += 18;
            
            // ═══ Ambient Light Slider ═══
            DrawTextFallback(px, py, $"Ambient: {_ambientLight * 100:F0}%", Color.White);
            py += 16;
            int sliderX = px, sliderW = 250, sliderH = 12;
            DrawRect(sliderX, py, sliderW, sliderH, new Color(40, 40, 50));
            // Gradient preview: dark left → bright right
            for (int sx = 0; sx < sliderW; sx++)
            {
                float pct = (float)sx / sliderW;
                byte v = (byte)(pct * 255);
                DrawRect(sliderX + sx, py + 1, 1, sliderH - 2, new Color(v, v, v) * 0.3f);
            }
            int handleX = sliderX + (int)(_ambientLight * sliderW);
            DrawRect(handleX - 3, py - 2, 6, sliderH + 4, Color.White);
            DrawRect(handleX - 2, py - 1, 4, sliderH + 2, new Color(255, 230, 140));
            // Drag interaction
            var sliderMouse = Mouse.GetState();
            if (sliderMouse.LeftButton == ButtonState.Pressed)
            {
                int mx2 = sliderMouse.X, my2 = sliderMouse.Y;
                if (my2 >= py - 4 && my2 <= py + sliderH + 4 && mx2 >= sliderX - 10 && mx2 <= sliderX + sliderW + 10)
                {
                    _ambientLight = MathHelper.Clamp((float)(mx2 - sliderX) / sliderW, 0f, 1f);
                }
            }
            py += sliderH + 8;
            // Day/night cycle info
            DrawTextFallback(px, py, $"Day Cycle: {(_dayNightEnabled ? "ON" : "OFF")} [N]  Time: {_dayTimeMinutes:F1}min", new Color(180, 180, 220));
        }
        
        // ═══════════════ TAB INVENTORY PANEL ═══════════════
        if (_inventorySlide > 0.01f)
        {
            int panelMaxH = 620;
            int panelH = (int)(panelMaxH * _inventorySlide);
            int panelY = _arena.Top - 2;
            
            // Dark panel sliding down over arena
            // Full-screen dark overlay
            DrawRect(0, 0, ScreenW, panelY + panelH, new Color(8, 8, 12) * (_inventorySlide * 0.85f));
            DrawRect(0, panelY + panelH, ScreenW, 2, new Color(200, 170, 100, 120)); // gold border bottom
            
            if (_inventorySlide > 0.3f) // only draw contents when mostly open
            {
                float alpha = MathF.Min((_inventorySlide - 0.3f) / 0.7f, 1f);
                Color textCol = Color.White * alpha;
                Color dimCol = new Color(120, 120, 130) * alpha;
                Color goldCol = new Color(200, 170, 100) * alpha;
                
                int cx = InvPanelX;
                int cy = panelY + 20;
                
                // Section: WAND CONFIGURATION
                DrawTextFallback(cx, cy, "WAND CONFIGURATION", goldCol, 1.3f);
                
                // Form slot
                DrawTextFallback(cx, InvFormLabelY, "FORM", new Color(200, 80, 80) * alpha);
                string formVal = _loadout.Form == Form.None ? "---" : _loadout.FormName;
                DrawTextFallback(cx + 120, InvFormLabelY, formVal, textCol);
                
                // Form options (clickable, skip None)
                int fx = cx + InvItemIndent;
                foreach (var f in _unlockedForms)
                {
                    if (f == Form.None) continue;
                    string fn = f.ToString();
                    int tw = MeasureText(fn);
                    bool active = f == _loadout.Form;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvFormItemsY - 2 && _mouseWorld.Y <= InvFormItemsY + 18;
                    Color fc = active ? new Color(255, 215, 0) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvFormItemsY, fn, fc);
                    fx += tw + InvItemGap;
                }
                
                // Behavior slot
                DrawTextFallback(cx, InvBehLabelY, "BEHAVIOR", new Color(80, 200, 80) * alpha);
                string behVal = _loadout.Behavior == Behavior.None ? "---" : _loadout.BehaviorName;
                DrawTextFallback(cx + 120, InvBehLabelY, behVal, textCol);
                
                // Behavior options (clickable, skip None)
                fx = cx + InvItemIndent;
                foreach (var b in _unlockedBehaviors)
                {
                    if (b == Behavior.None) continue;
                    string bn = b.ToString();
                    int tw = MeasureText(bn);
                    bool active = b == _loadout.Behavior;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvBehItemsY - 2 && _mouseWorld.Y <= InvBehItemsY + 18;
                    Color bc = active ? new Color(255, 215, 0) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvBehItemsY, bn, bc);
                    fx += tw + InvItemGap;
                }
                
                // Essence slot
                var eparms = ProjectileParams.Resolve(_loadout);
                Color essCol = new Color(eparms.Color.R, eparms.Color.G, eparms.Color.B) * alpha;
                DrawTextFallback(cx, InvEssLabelY, "ESSENCE", essCol);
                string essVal = _loadout.Essence == Essence.None ? "---" : _loadout.EssenceName;
                DrawTextFallback(cx + 120, InvEssLabelY, essVal, textCol);
                
                // Essence options (clickable, skip None)
                fx = cx + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int tw = MeasureText(en);
                    bool active = e == _loadout.Essence;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvEssItemsY - 2 && _mouseWorld.Y <= InvEssItemsY + 18;
                    Color ec = active ? new Color(255, 215, 0) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvEssItemsY, en, ec);
                    fx += tw + InvItemGap;
                }
                cy = InvEssItemsY + 36;
                
                // ═══ SECONDARY LOADOUT (Q-swap) ═══
                DrawTextFallback(cx, InvSecHeaderY, "SECONDARY LOADOUT [Q]", new Color(100, 200, 255) * alpha, 1.1f);
                
                // Secondary Form
                DrawTextFallback(cx, InvSecFormLabelY, "FORM", new Color(200, 80, 80) * alpha);
                string secFormVal = _loadoutSecondary.Form == Form.None ? "---" : _loadoutSecondary.FormName;
                DrawTextFallback(cx + 120, InvSecFormLabelY, secFormVal, textCol);
                fx = cx + InvItemIndent;
                foreach (var f in _unlockedForms)
                {
                    if (f == Form.None) continue;
                    string fn = f.ToString();
                    int tw = MeasureText(fn);
                    bool active = f == _loadoutSecondary.Form;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvSecFormY - 2 && _mouseWorld.Y <= InvSecFormY + 18;
                    Color fc = active ? new Color(100, 200, 255) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvSecFormY, fn, fc);
                    fx += tw + InvItemGap;
                }
                
                // Secondary Behavior
                DrawTextFallback(cx, InvSecBehLabelY, "BEHAVIOR", new Color(80, 200, 80) * alpha);
                string secBehVal = _loadoutSecondary.Behavior == Behavior.None ? "---" : _loadoutSecondary.BehaviorName;
                DrawTextFallback(cx + 120, InvSecBehLabelY, secBehVal, textCol);
                fx = cx + InvItemIndent;
                foreach (var b in _unlockedBehaviors)
                {
                    if (b == Behavior.None) continue;
                    string bn = b.ToString();
                    int tw = MeasureText(bn);
                    bool active = b == _loadoutSecondary.Behavior;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvSecBehY - 2 && _mouseWorld.Y <= InvSecBehY + 18;
                    Color bc = active ? new Color(100, 200, 255) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvSecBehY, bn, bc);
                    fx += tw + InvItemGap;
                }
                
                // Secondary Essence
                DrawTextFallback(cx, InvSecEssLabelY, "ESSENCE", essCol);
                string secEssVal = _loadoutSecondary.Essence == Essence.None ? "---" : _loadoutSecondary.EssenceName;
                DrawTextFallback(cx + 120, InvSecEssLabelY, secEssVal, textCol);
                fx = cx + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int tw = MeasureText(en);
                    bool active = e == _loadoutSecondary.Essence;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvSecEssY - 2 && _mouseWorld.Y <= InvSecEssY + 18;
                    Color ec = active ? new Color(100, 200, 255) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvSecEssY, en, ec);
                    fx += tw + InvItemGap;
                }
                
                // Secondary combo name (only if at least one slot filled)
                if (_loadoutSecondary.FilledSlots > 0)
                {
                    string secComboName = _loadoutSecondary.ComboName;
                    DrawTextFallback(cx + InvItemIndent, InvSecComboY, secComboName, textCol);
                }
                
                // ═══ UTILITY ESSENCE [E] ═══
                DrawTextFallback(cx, InvUtilLabelY, "UTILITY ESSENCE [E]", new Color(60, 220, 160) * alpha, 1.1f);
                fx = cx + InvItemIndent;
                foreach (var e in _unlockedEssences)
                {
                    if (e == Essence.None) continue;
                    string en = e.ToString();
                    int tw = MeasureText(en);
                    bool active = e == _utilityEssence;
                    bool hover = _mouseWorld.X >= fx && _mouseWorld.X <= fx + tw && _mouseWorld.Y >= InvUtilItemsY - 2 && _mouseWorld.Y <= InvUtilItemsY + 18;
                    Color ec = active ? new Color(60, 220, 160) * alpha : (hover ? Color.White * alpha : dimCol);
                    DrawTextFallback(fx, InvUtilItemsY, en, ec);
                    fx += tw + InvItemGap;
                }
                
                // Current combo
                if (_currentFusion != null)
                {
                    DrawTextFallback(cx, cy, "SPELL FUSION:", goldCol);
                    DrawTextFallback(cx + 170, cy, _currentFusion, new Color(255, 215, 0) * alpha, 1.1f);
                }
                else if (_currentDualCombo != null)
                {
                    DrawTextFallback(cx, cy, "DUAL COMBO:", new Color(135, 206, 235) * alpha);
                    DrawTextFallback(cx + 160, cy, _currentDualCombo, new Color(135, 206, 235) * alpha, 1.1f);
                }
                
                // ═══ Right column: Relics + Stats (accordion dropdowns) ═══
                int rx = ScreenW - 295;
                int ry = panelY + 20;
                
                // Relic symbol lookup
                string[] relicSymbols = { "◆", "◇", "☆", "⊕", "»", "◈", "✦", "⚔", "◉", "▣", "☀", "∞", "⟲" };
                string[] invRelicNames = { "Caliburn Shard", "Nimue's Tear", "Wand of Merlin", "Tome of Binding", "Haste Band", "Merlin's Phylactery", "Grimoire", "Dragon Dance", "Ether Sight", "Arcane Numbers", "Lambent Aura", "Wellspring Heart", "Quickswap Charm" };
                bool[] invRelicOwned = { _ownsCaliburn, _ownsNimueTear, _ownsWandOfMerlin, _ownsTomeOfBinding, _ownsHasteBand, _ownsPhylactery, _ownsGrimoire, _ownsDragonDance, _ownsEtherSight, _ownsDamageNumbers, _ownsLambentAura, _ownsEtherRegen, _ownsQuickswap };
                bool[] invRelicActive = { _hasCaliburn, _hasNimueTear, _hasWandOfMerlin, _hasTomeOfBinding, _hasHasteBand, _hasPhylactery, _hasGrimoire, _hasDragonDance, _hasEtherSight, _hasDamageNumbers, _hasLambentAura, _hasEtherRegenRelic, _hasQuickswap };
                string[] invRelicDescs = { "Projectiles pierce one enemy", "Drain HP on hit", "Hold RMB to charge shots", "Unlocks Dual Combos", "Increased movement speed", "Max ether increased 25%", "Unlocks Spell Fusions", "+10% dmg/speed per kill", "Reveals WEAKNESS, RESIST, and BREAK", "Shows damage numbers on hit", "Emit a lambent glow that illuminates the dark", "Ether regenerates passively over time", "Enables secondary loadout (Q to swap)" };
                Color[] relicColors = { new Color(200, 180, 120), new Color(100, 180, 220), new Color(160, 120, 200), new Color(180, 140, 100), new Color(120, 200, 120), new Color(140, 100, 200), new Color(200, 160, 60), new Color(220, 80, 60), new Color(160, 200, 255), new Color(200, 180, 255), new Color(255, 230, 140), new Color(80, 200, 180), new Color(100, 200, 255) };
                
                // RELICS header button
                {
                    var ms = Mouse.GetState();
                    bool hoverHeader = ms.X >= rx && ms.X <= rx + 120 && ms.Y >= ry && ms.Y <= ry + 24;
                    string arrow = _relicsSlide > 0.5f ? "▼" : "▶";
                    Color headerCol = hoverHeader ? new Color(255, 230, 140) * alpha : goldCol;
                    DrawTextFallback(rx, ry, $"{arrow} RELICS", headerCol, 1.1f);
                    // Subtle underline
                    DrawRect(rx, ry + 20, 100, 1, goldCol * (alpha * 0.3f));
                }
                ry += 28;
                
                if (_relicsSlide > 0.001f)
                {
                    float rEase = MathHelper.SmoothStep(0f, 1f, _relicsSlide);
                    float rAlpha = alpha * rEase;
                    int relicsContentH = invRelicNames.Length * 24 + 8;
                    int clippedH = (int)(relicsContentH * rEase);
                    int relicsStartY = ry;
                    
                    // Vertical slide offset: content slides up as it collapses
                    int slideOffset = (int)((1f - rEase) * -relicsContentH * 0.3f);
                    
                    var ms = Mouse.GetState();
                    int hoveredRelic = -1;
                    int hoveredRelicY = 0;
                    int drawY = ry + slideOffset;
                    for (int i = 0; i < invRelicNames.Length; i++)
                    {
                        if (drawY >= relicsStartY && drawY - relicsStartY < clippedH) // clip above header AND below content
                        {
                            if (invRelicOwned[i])
                            {
                                bool hover = rEase > 0.8f && ms.X >= rx && ms.X <= rx + 300 && ms.Y >= drawY - 2 && ms.Y <= drawY + 18;
                                if (hover) { hoveredRelic = i; hoveredRelicY = drawY; }
                                bool active = invRelicActive[i];
                                Color symCol = active ? relicColors[i] * rAlpha : new Color(50, 50, 60) * rAlpha;
                                Color nameCol = hover ? new Color(255, 215, 0) * rAlpha : (active ? textCol * rEase : new Color(80, 80, 90) * rAlpha);
                                string label = active ? invRelicNames[i] : invRelicNames[i] + " (OFF)";
                                DrawTextFallback(rx, drawY, relicSymbols[i], symCol, 0.9f);
                                DrawTextFallback(rx + 18, drawY, label, nameCol);
                            }
                            else
                            {
                                DrawRect(rx, drawY + 2, 150, 14, new Color(25, 25, 30) * rAlpha);
                                DrawTextFallback(rx + 4, drawY, "- - -", new Color(40, 40, 50) * rAlpha);
                            }
                        }
                        drawY += 24;
                    }
                    ry += clippedH;
                    
                    // Relic tooltip — drawn last so it's on top
                    if (hoveredRelic >= 0)
                    {
                        string desc = invRelicDescs[hoveredRelic];
                        string relicName = invRelicNames[hoveredRelic];
                        Color relicCol = relicColors[hoveredRelic];
                        
                        // Word wrap at ~28 chars per line
                        int wrapWidth = 28;
                        var lines = new System.Collections.Generic.List<string>();
                        string[] words = desc.Split(' ');
                        string currentLine = "";
                        foreach (var word in words)
                        {
                            if (currentLine.Length > 0 && currentLine.Length + word.Length + 1 > wrapWidth)
                            {
                                lines.Add(currentLine);
                                currentLine = word;
                            }
                            else
                            {
                                currentLine = currentLine.Length > 0 ? currentLine + " " + word : word;
                            }
                        }
                        if (currentLine.Length > 0) lines.Add(currentLine);
                        
                        int tooltipW = 210;
                        int lineH = 16;
                        int tooltipH = 24 + lines.Count * lineH + 10;
                        int ttx = rx - tooltipW - 12;
                        int tty = hoveredRelicY - 4;
                        
                        if (tty + tooltipH > ScreenH - 10) tty = ScreenH - 10 - tooltipH;
                        if (tty < 10) tty = 10;
                        
                        DrawRect(ttx - 2, tty - 2, tooltipW + 4, tooltipH + 4, new Color(40, 35, 50) * (alpha * 0.95f));
                        DrawRect(ttx, tty, tooltipW, tooltipH, new Color(12, 10, 18) * (alpha * 0.95f));
                        DrawRect(ttx, tty, tooltipW, 2, relicCol * (alpha * 0.6f));
                        DrawRect(ttx, tty, 2, tooltipH, relicCol * (alpha * 0.3f));
                        
                        DrawTextFallback(ttx + 8, tty + 6, relicName, relicCol * alpha, 0.9f);
                        for (int li = 0; li < lines.Count; li++)
                        {
                            DrawTextFallback(ttx + 8, tty + 24 + li * lineH, lines[li], new Color(190, 185, 200) * alpha, 0.8f);
                        }
                    }
                }
                
                // STATS header button
                {
                    var ms = Mouse.GetState();
                    bool hoverHeader = ms.X >= rx && ms.X <= rx + 120 && ms.Y >= ry && ms.Y <= ry + 24;
                    string arrow = _statsSlide > 0.5f ? "▼" : "▶";
                    Color headerCol = hoverHeader ? new Color(255, 230, 140) * alpha : goldCol;
                    DrawTextFallback(rx, ry, $"{arrow} STATS", headerCol, 1.1f);
                    DrawRect(rx, ry + 20, 100, 1, goldCol * (alpha * 0.3f));
                }
                ry += 28;
                
                if (_statsSlide > 0.001f)
                {
                    float sEase = MathHelper.SmoothStep(0f, 1f, _statsSlide);
                    float sAlpha = alpha * sEase;
                    int statsContentH = 88; // 4 lines × 22
                    int clippedSH = (int)(statsContentH * sEase);
                    int slideOff = (int)((1f - sEase) * -statsContentH * 0.3f);
                    int statsStartY = ry;
                    int sy = ry + slideOff;
                    
                    if (sy >= statsStartY && sy - statsStartY < clippedSH)
                    {
                        DrawTextFallback(rx, sy, $"Ether Shards: {_hardEther}", new Color(100, 200, 220) * sAlpha);
                        sy += 22;
                    }
                    else sy += 22;
                    if (sy >= statsStartY && sy - statsStartY < clippedSH)
                    {
                        DrawTextFallback(rx, sy, $"Wave: {_wave}", textCol * sEase);
                        sy += 22;
                    }
                    else sy += 22;
                    if (sy >= statsStartY && sy - statsStartY < clippedSH)
                    {
                        DrawTextFallback(rx, sy, $"Best Streak: {_bestStreak}", textCol * sEase);
                        sy += 22;
                    }
                    else sy += 22;
                    if (sy >= statsStartY && sy - statsStartY < clippedSH)
                    {
                        string fallenLabel = _timesFallen == 1 ? "Time Fallen" : "Times Fallen";
                        DrawTextFallback(rx, sy, $"{fallenLabel}: {_timesFallen}", new Color(180, 100, 100) * sAlpha);
                    }
                    ry += clippedSH;
                }
                
                // ═══ SACK INVENTORY (3×3 grid) ═══
                int gridW = SackGridSize * SackCellSize;
                int gridH = SackGridSize * SackCellSize;
                int gridOriginX = ScreenW / 2 - gridW / 2;
                int gridOriginY = panelY + panelH - gridH - 50;
                
                // ── ARMOR SLOT (left of sack) ──
                {
                    int armorSlotW = 60, armorSlotH = 60;
                    int armorX = gridOriginX - armorSlotW - 50;
                    int armorY = gridOriginY + (gridH - armorSlotH) / 2;
                    
                    // Label — centered above slot
                    int armorLabelW = MeasureText("ARMOR");
                    DrawTextFallback(armorX + armorSlotW / 2 - armorLabelW / 2, armorY - 20, "ARMOR", goldCol, 0.9f);
                    
                    // Slot background
                    DrawRect(armorX - 2, armorY - 2, armorSlotW + 4, armorSlotH + 4, new Color(50, 45, 40) * (alpha * 0.6f));
                    DrawRect(armorX, armorY, armorSlotW, armorSlotH, new Color(18, 16, 20) * alpha);
                    // Border
                    DrawRect(armorX, armorY, armorSlotW, 1, new Color(80, 70, 60) * (alpha * 0.5f));
                    DrawRect(armorX, armorY, 1, armorSlotH, new Color(80, 70, 60) * (alpha * 0.5f));
                    DrawRect(armorX, armorY + armorSlotH - 1, armorSlotW, 1, new Color(40, 35, 30) * (alpha * 0.5f));
                    DrawRect(armorX + armorSlotW - 1, armorY, 1, armorSlotH, new Color(40, 35, 30) * (alpha * 0.5f));
                    
                    // Chestplate silhouette (darkened pixel art — reference: purple/grey armor)
                    Color sil = _equippedArmor == ArmorType.None 
                        ? new Color(40, 35, 50) * (alpha * 0.4f) // empty = very dark silhouette
                        : new Color(120, 100, 160) * (alpha * 0.8f); // equipped = lit up
                    Color silDark = _equippedArmor == ArmorType.None 
                        ? new Color(25, 22, 35) * (alpha * 0.4f) 
                        : new Color(80, 65, 120) * (alpha * 0.7f);
                    Color silLight = _equippedArmor == ArmorType.None 
                        ? new Color(50, 45, 60) * (alpha * 0.3f) 
                        : new Color(150, 135, 190) * (alpha * 0.8f);
                    Color silAccent = _equippedArmor == ArmorType.None 
                        ? new Color(35, 40, 55) * (alpha * 0.3f) 
                        : new Color(100, 140, 200) * (alpha * 0.8f);
                    
                    int acx = armorX + armorSlotW / 2;
                    int acy = armorY + armorSlotH / 2 - 2;
                    
                    // Shoulder guards (left and right)
                    DrawRect(acx - 22, acy - 14, 10, 8, sil);   // left shoulder
                    DrawRect(acx + 12, acy - 14, 10, 8, sil);   // right shoulder
                    DrawRect(acx - 20, acy - 12, 8, 4, silDark); // left shoulder shade
                    DrawRect(acx + 12, acy - 12, 8, 4, silDark); // right shoulder shade
                    
                    // Shoulder to body connectors
                    DrawRect(acx - 14, acy - 8, 4, 6, sil);     // left strap
                    DrawRect(acx + 10, acy - 8, 4, 6, sil);     // right strap
                    
                    // Main torso
                    DrawRect(acx - 12, acy - 6, 24, 20, sil);   // body
                    DrawRect(acx - 10, acy - 4, 20, 16, silDark); // inner shade
                    
                    // Chest plate highlight (center)
                    DrawRect(acx - 6, acy - 4, 12, 10, silLight);
                    DrawRect(acx - 4, acy - 2, 8, 6, sil);
                    
                    // Belt/waist
                    DrawRect(acx - 10, acy + 12, 20, 3, silDark);
                    
                    // Blue accent gem (center chest)
                    DrawRect(acx - 2, acy - 1, 4, 4, silAccent);
                    
                    // Neck opening
                    DrawRect(acx - 4, acy - 10, 8, 4, new Color(18, 16, 20) * alpha); // dark hole
                    
                    // Arm holes (cut-outs)
                    DrawRect(acx - 16, acy - 2, 4, 10, new Color(18, 16, 20) * alpha); // left
                    DrawRect(acx + 12, acy - 2, 4, 10, new Color(18, 16, 20) * alpha); // right
                    
                    // Equipped armor name
                    if (_equippedArmor != ArmorType.None)
                    {
                        string armorName = _equippedArmor switch
                        {
                            ArmorType.LeatherGambeson => "Leather Gambeson",
                            ArmorType.IronPlate => "Iron Plate",
                            ArmorType.EtherWeave => "Ether Weave",
                            ArmorType.BoneMail => "Bone Mail",
                            ArmorType.CinderGuard => "Cinder Guard",
                            ArmorType.HollowShroud => "Hollow Shroud",
                            ArmorType.SapCarapace => "Sap Carapace",
                            _ => "Unknown"
                        };
                        // Draw name below slot, split into lines if needed to avoid overlap with grid
                        int nameW = MeasureText(armorName);
                        int maxNameW = armorSlotW + 20; // allow slight overflow
                        if (nameW > maxNameW && armorName.Contains(' '))
                        {
                            // Split at space
                            int sp = armorName.IndexOf(' ');
                            string line1 = armorName[..sp];
                            string line2 = armorName[(sp + 1)..];
                            int l1w = MeasureText(line1);
                            int l2w = MeasureText(line2);
                            DrawTextFallback(armorX + armorSlotW / 2 - l1w / 2, armorY + armorSlotH + 6, line1, textCol * alpha, 0.7f);
                            DrawTextFallback(armorX + armorSlotW / 2 - l2w / 2, armorY + armorSlotH + 18, line2, textCol * alpha, 0.7f);
                        }
                        else
                        {
                            int cx2 = armorX + armorSlotW / 2 - nameW / 2;
                            DrawTextFallback(cx2, armorY + armorSlotH + 6, armorName, textCol * alpha, 0.7f);
                        }
                    }
                }
                
                // ── Pixel art burlap sack behind grid ──
                {
                    int sackPad = 14; // extra width around grid
                    int sackW = gridW + sackPad * 2;
                    int sackBodyH = gridH + sackPad + 10;
                    int sackX = gridOriginX - sackPad;
                    int sackBottomY = gridOriginY + gridH + sackPad;
                    int sackTopY = sackBottomY - sackBodyH;
                    
                    // Burlap colors
                    Color burlap = new Color(160, 130, 80) * (alpha * 0.7f);
                    Color burlapDark = new Color(120, 95, 55) * (alpha * 0.6f);
                    Color burlapLight = new Color(190, 160, 110) * (alpha * 0.5f);
                    Color rope = new Color(140, 110, 60) * (alpha * 0.8f);
                    
                    // Body — wider at bottom, narrower at top (trapezoid via stacked rects)
                    for (int row = 0; row < sackBodyH; row++)
                    {
                        float t = (float)row / sackBodyH; // 0=top, 1=bottom
                        float widthFrac = 0.7f + 0.3f * t; // narrower top, wider bottom
                        // Slight bulge in middle
                        float bulge = MathF.Sin(t * MathF.PI) * 6f;
                        int rowW = (int)(sackW * widthFrac + bulge);
                        int rowX = sackX + (sackW - rowW) / 2;
                        int rowY = sackTopY + row;
                        
                        // Alternate dark/light rows for weave texture
                        Color rowCol = (row % 3 == 0) ? burlapDark : (row % 3 == 1) ? burlap : burlapLight;
                        DrawRect(rowX, rowY, rowW, 1, rowCol);
                        
                        // Vertical weave lines
                        if (row % 2 == 0)
                        {
                            for (int wx = rowX + 4; wx < rowX + rowW - 4; wx += 6)
                            {
                                Color weaveCol = ((wx + row) % 4 == 0) ? burlapDark : burlapLight;
                                DrawRect(wx, rowY, 1, 1, weaveCol * 0.3f);
                            }
                        }
                    }
                    
                    // Rounded bottom corners
                    DrawRect(sackX + 2, sackBottomY - 1, 2, 1, new Color(0, 0, 0, 0)); // cut corners
                    DrawRect(sackX + sackW - 4, sackBottomY - 1, 2, 1, new Color(0, 0, 0, 0));
                    
                    // Gathered top / cinch
                    int cinchY = sackTopY - 4;
                    int cinchW = (int)(sackW * 0.5f);
                    int cinchX = sackX + (sackW - cinchW) / 2;
                    // Gathered folds
                    for (int fold = 0; fold < 5; fold++)
                    {
                        int foldH = 6 + (fold % 2) * 3;
                        int foldX = cinchX + fold * (cinchW / 5) - 2;
                        int foldW = cinchW / 5 + 4;
                        Color foldCol = (fold % 2 == 0) ? burlap : burlapDark;
                        for (int fy = 0; fy < foldH; fy++)
                        {
                            float ft = (float)fy / foldH;
                            int fw = (int)(foldW * (1f - ft * 0.4f));
                            DrawRect(foldX + (foldW - fw) / 2, cinchY - fy, fw, 1, foldCol);
                        }
                    }
                    
                    // Rope tie
                    int ropeY = cinchY + 1;
                    DrawRect(cinchX - 4, ropeY, cinchW + 8, 2, rope);
                    DrawRect(cinchX - 6, ropeY - 1, 3, 4, rope); // knot left
                    DrawRect(cinchX + cinchW + 3, ropeY - 1, 3, 4, rope); // knot right
                    // Rope dangling ends
                    for (int rd = 0; rd < 8; rd++)
                    {
                        float sway = MathF.Sin(_totalTime * 2f + rd * 0.5f) * 2f;
                        DrawRect(cinchX - 8 + (int)sway, ropeY + 4 + rd * 2, 1, 2, rope * (1f - rd * 0.1f));
                        DrawRect(cinchX + cinchW + 6 + (int)(-sway), ropeY + 4 + rd * 2, 1, 2, rope * (1f - rd * 0.1f));
                    }
                    
                    // Shadow underneath
                    DrawRect(sackX + 4, sackBottomY, sackW - 8, 3, new Color(0, 0, 0) * (alpha * 0.2f));
                }
                
                DrawTextFallback(gridOriginX, gridOriginY - 22, "SACK", goldCol, 1.3f);
                
                // Build occupied lookup (multi-cell items fill all their cells)
                var cellContents = new Dictionary<(int, int), SackItem>();
                foreach (var s in _sackItems)
                {
                    int w = Math.Max(1, s.Width), h = Math.Max(1, s.Height);
                    for (int dy = 0; dy < h; dy++)
                        for (int dx = 0; dx < w; dx++)
                            cellContents[(s.GridX + dx, s.GridY + dy)] = s;
                }
                
                // Update hover
                int mxGrid = ((int)_mouseWorld.X - gridOriginX) / SackCellSize;
                int myGrid = ((int)_mouseWorld.Y - gridOriginY) / SackCellSize;
                _sackHoverX = (mxGrid >= 0 && mxGrid < SackGridSize && myGrid >= 0 && myGrid < SackGridSize) ? mxGrid : -1;
                _sackHoverY = (mxGrid >= 0 && mxGrid < SackGridSize && myGrid >= 0 && myGrid < SackGridSize) ? myGrid : -1;
                
                // Draw grid
                for (int gy = 0; gy < SackGridSize; gy++)
                {
                    for (int gx = 0; gx < SackGridSize; gx++)
                    {
                        int cellX = gridOriginX + gx * SackCellSize;
                        int cellY = gridOriginY + gy * SackCellSize;
                        
                        // Cell background — skip for non-origin cells of multi-cell items (they're covered by the item draw)
                        bool isSubCell = cellContents.TryGetValue((gx, gy), out var cellItem) && cellItem.Width > 1 && !(gx == cellItem.GridX && gy == cellItem.GridY);
                        if (!isSubCell)
                        {
                            bool hovered = gx == _sackHoverX && gy == _sackHoverY;
                            Color cellBg = hovered ? new Color(40, 40, 55) : new Color(20, 20, 28);
                            DrawRect(cellX, cellY, SackCellSize - 1, SackCellSize - 1, cellBg * alpha);
                            // Border
                            DrawRect(cellX, cellY, SackCellSize - 1, 1, new Color(60, 60, 70) * (alpha * 0.5f));
                            DrawRect(cellX, cellY, 1, SackCellSize - 1, new Color(60, 60, 70) * (alpha * 0.5f));
                        }
                        
                        // Item in cell
                        if (cellContents.TryGetValue((gx, gy), out var item))
                        {
                            if (item.Type == SackItemType.Armor)
                            {
                                // Only draw at the origin cell (top-left)
                                if (gx == item.GridX && gy == item.GridY)
                                {
                                    int aw = SackCellSize * 2 - 1, ah = SackCellSize * 2 - 1;
                                    float pulse = 0.7f + 0.3f * MathF.Sin(_totalTime * 2.5f);
                                    // Background
                                    DrawRect(cellX, cellY, aw, ah, new Color(30, 25, 40) * alpha);
                                    // Chestplate silhouette (scaled to fill 2×2)
                                    int cx3 = cellX + aw / 2, cy3 = cellY + ah / 2;
                                    Color sil2 = new Color(120, 100, 160) * (pulse * 0.8f) * alpha;
                                    Color silD = new Color(80, 65, 120) * (pulse * 0.7f) * alpha;
                                    Color silL = new Color(150, 130, 190) * (pulse * 0.9f) * alpha;
                                    // Shoulders
                                    DrawRect(cx3 - 28, cy3 - 18, 14, 10, sil2);
                                    DrawRect(cx3 + 14, cy3 - 18, 14, 10, sil2);
                                    // Straps
                                    DrawRect(cx3 - 16, cy3 - 10, 6, 8, silD);
                                    DrawRect(cx3 + 10, cy3 - 10, 6, 8, silD);
                                    // Torso
                                    DrawRect(cx3 - 16, cy3 - 6, 32, 26, sil2);
                                    DrawRect(cx3 - 12, cy3 - 2, 24, 18, silD);
                                    // Chest highlight
                                    DrawRect(cx3 - 8, cy3 - 4, 16, 12, silL);
                                    DrawRect(cx3 - 6, cy3 - 2, 12, 8, sil2);
                                    // Belt
                                    DrawRect(cx3 - 12, cy3 + 16, 24, 4, silD);
                                    // Gem
                                    DrawRect(cx3 - 3, cy3 - 1, 6, 6, new Color(100, 140, 200) * (pulse * 0.9f) * alpha);
                                }
                            }
                            else
                            {
                                Color itemCol = item.Type == SackItemType.LargeClip ? new Color(160, 120, 255) :
                                                item.Type == SackItemType.MediumClip ? new Color(80, 160, 255) :
                                                new Color(80, 200, 230);
                                float pulse = 0.7f + 0.3f * MathF.Sin(_totalTime * 3f + gx * 1.1f + gy * 0.7f);
                                
                                int pad = 4;
                                DrawRect(cellX + pad, cellY + pad, SackCellSize - pad * 2 - 1, SackCellSize - pad * 2 - 1, itemCol * (pulse * 0.5f) * alpha);
                                int core = 6;
                                DrawRect(cellX + core, cellY + core, SackCellSize - core * 2 - 1, SackCellSize - core * 2 - 1, itemCol * (pulse * 0.8f) * alpha);
                                
                                if (item.Count > 1)
                                    DrawTextFallback(cellX + SackCellSize - 14, cellY + SackCellSize - 14, $"{item.Count}", Color.White * alpha, 0.7f);
                            }
                        }
                    }
                }
                
                // Tooltip on hover (not while dragging)
                if (_sackDragIdx < 0 && _sackHoverX >= 0 && cellContents.TryGetValue((_sackHoverX, _sackHoverY), out var hoverItem))
                {
                    string name = hoverItem.Type == SackItemType.Armor ? (hoverItem.Armor switch
                    {
                        ArmorType.LeatherGambeson => "Leather Gambeson",
                        ArmorType.IronPlate => "Iron Plate",
                        ArmorType.EtherWeave => "Ether Weave",
                        ArmorType.BoneMail => "Bone Mail",
                        ArmorType.CinderGuard => "Cinder Guard",
                        ArmorType.HollowShroud => "Hollow Shroud",
                        ArmorType.SapCarapace => "Sap Carapace",
                        _ => "Armor"
                    }) :
                                  hoverItem.Type == SackItemType.LargeClip ? "Large Ether Clip (100 EP)" :
                                  hoverItem.Type == SackItemType.MediumClip ? "Medium Ether Clip (50 EP)" :
                                  "Small Ether Clip (25 EP)";
                    int tipX = gridOriginX + _sackHoverX * SackCellSize + SackCellSize + 4;
                    int tipY = gridOriginY + _sackHoverY * SackCellSize;
                    int tipW = MeasureText(name) + 12;
                    DrawRect(tipX - 2, tipY - 2, tipW, 20, new Color(10, 10, 15) * 0.9f * alpha);
                    DrawTextFallback(tipX + 4, tipY + 2, name, Color.White * alpha, 0.8f);
                    if (hoverItem.Type != SackItemType.Armor)
                        DrawTextFallback(tipX + 4, tipY + 14, $"x{hoverItem.Count}/{hoverItem.MaxStack}", dimCol * alpha, 0.7f);
                }
                
                // Dragged item follows mouse
                if (_sackDragIdx >= 0)
                {
                    int dx = (int)(_mouseWorld.X - _sackDragOffset.X);
                    int dy = (int)(_mouseWorld.Y - _sackDragOffset.Y);
                    
                    if (_sackDragFromArmor)
                    {
                        // Dragging armor — draw 2×2 purple block
                        int asz = SackCellSize * 2;
                        DrawRect(dx, dy, asz - 1, asz - 1, new Color(120, 100, 160) * 0.5f * alpha);
                        DrawRect(dx + 8, dy + 8, asz - 17, asz - 17, new Color(120, 100, 160) * 0.8f * alpha);
                    }
                    else
                    {
                        var dragList = _sackDragFromOverflow ? _sackOverflow : _sackItems;
                        if (_sackDragIdx < dragList.Count)
                        {
                            var dragItem = dragList[_sackDragIdx];
                            if (dragItem.Type == SackItemType.Armor)
                            {
                                int asz = SackCellSize * 2;
                                DrawRect(dx, dy, asz - 1, asz - 1, new Color(120, 100, 160) * 0.5f * alpha);
                                DrawRect(dx + 8, dy + 8, asz - 17, asz - 17, new Color(120, 100, 160) * 0.8f * alpha);
                            }
                            else
                            {
                                Color dragCol = dragItem.Type == SackItemType.LargeClip ? new Color(160, 120, 255) :
                                                dragItem.Type == SackItemType.MediumClip ? new Color(80, 160, 255) :
                                                new Color(80, 200, 230);
                                DrawRect(dx, dy, SackCellSize - 1, SackCellSize - 1, dragCol * 0.6f * alpha);
                                int dCore = 6;
                                DrawRect(dx + dCore, dy + dCore, SackCellSize - dCore * 2 - 1, SackCellSize - dCore * 2 - 1, dragCol * 0.9f * alpha);
                                if (dragItem.Count > 1)
                                    DrawTextFallback(dx + SackCellSize - 14, dy + SackCellSize - 14, $"{dragItem.Count}", Color.White * alpha, 0.7f);
                            }
                        }
                    }
                }
                
                // Rotate arrow animation
                if (_sackRotateAnim > 0)
                {
                    float ra = MathHelper.Clamp(_sackRotateAnim, 0f, 1f);
                    int arrowCX = gridOriginX + SackGridSize * SackCellSize + 12;
                    int arrowCY = gridOriginY + (SackGridSize * SackCellSize) / 2;
                    Color arrowCol = new Color(200, 180, 100) * (ra * alpha);
                    // Curved arrow: draw arc segments
                    for (int seg = 0; seg < 8; seg++)
                    {
                        float t = seg / 8f * MathF.PI * 1.5f * ra;
                        float r2 = 14f;
                        int ax = arrowCX + (int)(MathF.Cos(t) * r2);
                        int ay = arrowCY + (int)(MathF.Sin(t) * r2);
                        DrawRect(ax, ay, 2, 2, arrowCol);
                    }
                    // Arrowhead
                    float endT = MathF.PI * 1.5f * ra;
                    int ahx = arrowCX + (int)(MathF.Cos(endT) * 14f);
                    int ahy = arrowCY + (int)(MathF.Sin(endT) * 14f);
                    DrawRect(ahx - 1, ahy - 3, 3, 3, arrowCol);
                    DrawRect(ahx + 1, ahy - 1, 3, 3, arrowCol);
                }
                
                // ── Floating items (dragged out of grid — will drop to ground on TAB close) ──
                for (int oi = 0; oi < _sackOverflow.Count && oi < _sackOverflowPos.Count; oi++)
                {
                    var ov = _sackOverflow[oi];
                    int ocx = (int)_sackOverflowPos[oi].X;
                    int ocy = (int)_sackOverflowPos[oi].Y;
                    int iw = Math.Max(1, ov.Width) * SackCellSize;
                    int ih = Math.Max(1, ov.Height) * SackCellSize;
                    float pulse = 0.5f + 0.5f * MathF.Sin(_totalTime * 4f + oi * 1.3f);
                    
                    if (ov.Type == SackItemType.Armor)
                    {
                        // Draw chestplate silhouette at floating position
                        Color ac = new Color(120, 100, 160) * (alpha * pulse);
                        Color ad = new Color(80, 65, 120) * (alpha * pulse);
                        int fcx = ocx + iw / 2, fcy = ocy + ih / 2;
                        DrawRect(fcx - 20, fcy - 16, 8, 8, ac); // left shoulder
                        DrawRect(fcx + 12, fcy - 16, 8, 8, ac); // right shoulder
                        DrawRect(fcx - 16, fcy - 8, 32, 22, ac); // torso
                        DrawRect(fcx - 12, fcy - 4, 24, 14, ad); // inner
                        DrawRect(fcx - 2, fcy - 2, 4, 4, new Color(100, 140, 200) * (alpha * pulse)); // gem
                    }
                    else
                    {
                        Color ovCol = ov.Type == SackItemType.LargeClip ? new Color(160, 120, 255) :
                                      ov.Type == SackItemType.MediumClip ? new Color(80, 160, 255) :
                                      new Color(80, 200, 230);
                        int pad = 5;
                        DrawRect(ocx + pad, ocy + pad, iw - pad * 2 - 1, ih - pad * 2 - 1, ovCol * (pulse * 0.4f) * alpha);
                        if (ov.Count > 1)
                            DrawTextFallback(ocx + iw - 14, ocy + ih - 14, $"{ov.Count}", Color.White * alpha, 0.7f);
                    }
                }
                
                // TAB hint inside panel at bottom
                DrawTextCentered(panelY + panelH - 24, "TAB to close", dimCol);
            }
        }
    }

    private void DrawSlotBox(int x, int y, string label, string value, Color color)
    {
        int w = 190, h = 50;
        DrawRect(x, y, w, h, new Color(25, 25, 35));
        DrawRect(x, y, w, 2, color);

        DrawTextFallback(x + 6, y + 6, label, new Color(120, 120, 120));
        DrawTextFallback(x + 6, y + 24, value, color);
    }

    private void DrawTextFallback(int x, int y, string text, Color color, float scale = 1f, SpriteFont font = null)
    {
        var f = font ?? _font;
        if (f != null)
        {
            _spriteBatch.DrawString(f, text, new Vector2(x, y), color, 0f, Vector2.Zero, scale, SpriteEffects.None, 0);
            return;
        }
        int cx = x;
        int cw = (int)(5 * scale);
        int ch = (int)(8 * scale);
        int spacing = (int)(7 * scale);
        foreach (char c in text)
        {
            if (c != ' ')
                _spriteBatch.Draw(_pixel, new Rectangle(cx, y, cw, ch), color);
            cx += spacing;
        }
    }

    private void PlayMusic(Song song, string name, bool oneShot = false)
    {
        if (song == null || name == _currentMusicName) return;
        if (_currentMusicName == "")
        {
            // Nothing playing — start immediately with fade-in
            _currentMusicName = name;
            MediaPlayer.IsRepeating = !oneShot;
            _musicVolume = 0f;
            _musicTargetVolume = MusicMaxVolume;
            MediaPlayer.Volume = 0f;
            MediaPlayer.Play(song);
        }
        else
        {
            // Something playing — fade out, then swap
            _pendingMusicSong = song;
            _pendingMusicName = name;
            _pendingMusicOneShot = oneShot;
            _musicTargetVolume = 0f; // fade out current
        }
    }
    
    private void StopMusic()
    {
        _musicTargetVolume = 0f;
        _pendingMusicSong = null;
        _pendingMusicName = "";
        // Will fade to 0 then stop in UpdateMusicFade
    }
    
    private static SoundEffect GenerateSfx(float[] freqs, float noteLen, float volume)
    {
        int sampleRate = 44100;
        int totalSamples = (int)(freqs.Length * noteLen * sampleRate);
        byte[] buffer = new byte[totalSamples * 2]; // 16-bit mono
        int samplesPerNote = (int)(noteLen * sampleRate);
        
        for (int i = 0; i < totalSamples; i++)
        {
            int noteIndex = Math.Min(i / samplesPerNote, freqs.Length - 1);
            float t = (float)i / sampleRate;
            float noteT = (float)(i % samplesPerNote) / samplesPerNote;
            float envelope = MathF.Min(noteT * 20f, 1f) * MathF.Max(0, 1f - noteT * 1.2f); // attack + decay
            float sample = MathF.Sin(t * freqs[noteIndex] * MathF.PI * 2f) * envelope * volume;
            short pcm = (short)(sample * 32767f);
            buffer[i * 2] = (byte)(pcm & 0xFF);
            buffer[i * 2 + 1] = (byte)((pcm >> 8) & 0xFF);
        }
        
        return new SoundEffect(buffer, sampleRate, AudioChannels.Mono);
    }
    
    private void PlaySfx(SoundEffect sfx, float volume = 1f)
    {
        sfx?.Play(volume, 0f, 0f);
    }
    
    private void UpdateMusicFade(float dt)
    {
        if (_musicVolume < _musicTargetVolume)
        {
            _musicVolume = MathF.Min(_musicVolume + MusicFadeSpeed * dt, _musicTargetVolume);
        }
        else if (_musicVolume > _musicTargetVolume)
        {
            _musicVolume = MathF.Max(_musicVolume - MusicFadeSpeed * dt, _musicTargetVolume);
        }
        
        MediaPlayer.Volume = _musicVolume;
        
        // When fade-out completes, swap to pending track or stop
        if (_musicVolume <= 0.001f && _musicTargetVolume <= 0.001f)
        {
            if (_pendingMusicSong != null)
            {
                _currentMusicName = _pendingMusicName;
                MediaPlayer.IsRepeating = !_pendingMusicOneShot;
                MediaPlayer.Play(_pendingMusicSong);
                _musicTargetVolume = MusicMaxVolume; // fade in
                _pendingMusicSong = null;
                _pendingMusicName = "";
            }
            else if (_currentMusicName != "")
            {
                MediaPlayer.Stop();
                _currentMusicName = "";
            }
        }
    }
    
    private void UpdateMusic()
    {
        if (_state == GameState.TitleScreen || _state == GameState.ModeSelect || _state == GameState.Intro)
        {
            PlayMusic(LoadSong("Music/LightAmbient1"), "light1");
            return;
        }
        
        if (_state == GameState.GameOver)
        {
            PlayMusic(LoadSong("Music/Death"), "death", oneShot: true);
            return;
        }
        
        if (_state != GameState.Playing) return;
        
        if (_gameMode == GameMode.Awakening)
        {
            // Grimoire reveal = dramatic silence already handled
            if (_grimoireRevealActive) return;
            
            switch (_currentScreen)
            {
                case 5: // The Awakening — cave start
                    PlayMusic(LoadSong("Music/NightAmbient2"), "night2");
                    break;
                case 2: // Training Grounds
                case 4: // Knight's Hall
                    PlayMusic(LoadSong("Music/LightAmbient3"), "light3");
                    break;
                case 1: // The Gauntlet — combat
                    PlayMusic(_gauntletStarted && _gauntletWave >= 1 && _gauntletWave <= 3 ? LoadSong("Music/Action1") : LoadSong("Music/LightAmbient3"), 
                              _gauntletStarted && _gauntletWave >= 1 && _gauntletWave <= 3 ? "action1" : "light3");
                    break;
                case 3: // Proving Grounds
                    PlayMusic(_inPortal ? LoadSong("Music/Action3") : LoadSong("Music/Strange"), _inPortal ? "action3" : "strange");
                    break;
                case 6: // Wellspring
                    PlayMusic(LoadSong("Music/Ambient1"), "ambient1");
                    break;
                case 7: // Lady's Shrine
                    PlayMusic(LoadSong("Music/LightAmbient1"), "light1");
                    break;
                case 8: // Lava Sanctum
                    PlayMusic(LoadSong("Music/Strange"), "strange");
                    break;
                case 9: // Boss
                    if (_bossDead || _clearedScreens.Contains(9))
                    { if (!_victoryPlayed) { PlayMusic(LoadSong("Music/Victory"), "victory"); _victoryPlayed = true; } }
                    else if (_bossActive)
                        PlayMusic(LoadSong("Music/BossDreadRequiem"), "boss");
                    else
                        PlayMusic(LoadSong("Music/Strange"), "strange");
                    break;
            }
        }
        else if (_gameMode == GameMode.Gauntlet || _gameMode == GameMode.Campaign)
        {
            PlayMusic(LoadSong("Music/Action1"), "action1");
        }
    }
    
    private static Color HueToColor(float hue)
    {
        float h = hue / 60f;
        int sector = (int)h % 6;
        float f = h - (int)h;
        byte v = 255, p = 80, q = (byte)(255 * (1 - f) + 80 * f), t2 = (byte)(80 + 175 * f);
        return sector switch
        {
            0 => new Color(v, t2, p),
            1 => new Color(q, v, p),
            2 => new Color(p, v, t2),
            3 => new Color(p, q, v),
            4 => new Color(t2, p, v),
            _ => new Color(v, p, q),
        };
    }
    
    private void DrawSpiderWebs()
    {
        foreach (var w in _spiderWebs)
        {
            float alpha = MathHelper.Clamp(w.Life / w.MaxLife, 0, 1) * 0.6f;
            Color webCol = new Color(180, 180, 190) * alpha;
            int x = (int)w.Position.X, y = (int)w.Position.Y, r = (int)w.Radius;
            for (int s = 0; s < 6; s++)
            {
                float angle = s * MathF.PI / 3f;
                int ex = x + (int)(MathF.Cos(angle) * r);
                int ey = y + (int)(MathF.Sin(angle) * r);
                for (int d = 0; d < 5; d++)
                {
                    float t2 = d / 4f;
                    int dx = (int)MathHelper.Lerp(x, ex, t2);
                    int dy = (int)MathHelper.Lerp(y, ey, t2);
                    DrawRect(dx, dy, 1, 1, webCol);
                }
            }
            for (int ring = 1; ring <= 3; ring++)
            {
                float ringR = r * ring / 3f;
                int segs = 12;
                for (int s2 = 0; s2 < segs; s2++)
                {
                    float a2 = s2 * MathF.PI * 2f / segs;
                    int rx2 = x + (int)(MathF.Cos(a2) * ringR);
                    int ry2 = y + (int)(MathF.Sin(a2) * ringR);
                    DrawRect(rx2, ry2, 1, 1, webCol * 0.7f);
                }
            }
            DrawRect(x - 1, y - 1, 3, 3, webCol * 1.2f);
            if (w.HitsLeft < 2)
            {
                DrawRect(x + r / 3, y - 1, 3, 3, Color.Black * alpha * 0.5f);
                DrawRect(x - r / 2, y + r / 4, 2, 2, Color.Black * alpha * 0.5f);
            }
        }
    }
    
    private void DrawRect(int x, int y, int w, int h, Color color)
    {
        _spriteBatch.Draw(_pixel, new Rectangle(x, y, w, h), color);
    }

    private void DrawPixelCursor()
    {
        // Skip during gameplay (reticle drawn in world space instead)
        if (_state == GameState.Playing && !_inventoryOpen) return;
        _spriteBatch.Begin(samplerState: SamplerState.PointClamp);
        var mouse = Mouse.GetState();
        int cx = mouse.X, cy = mouse.Y;
        // Stylized pixel gauntlet cursor (pointing up-left)
        Color iron = new Color(180, 175, 165);
        Color highlight = new Color(220, 215, 200);
        Color shadow = new Color(100, 95, 85);
        // Arrow body — 10px tall
        DrawRect(cx, cy, 1, 1, highlight);         // tip
        DrawRect(cx, cy + 1, 1, 1, highlight);
        DrawRect(cx, cy + 2, 2, 1, iron);
        DrawRect(cx, cy + 3, 2, 1, iron);
        DrawRect(cx, cy + 4, 3, 1, iron);
        DrawRect(cx, cy + 5, 3, 1, iron);
        DrawRect(cx, cy + 6, 4, 1, iron);
        DrawRect(cx + 1, cy + 7, 3, 1, iron);
        DrawRect(cx + 1, cy + 8, 2, 1, shadow);
        DrawRect(cx + 2, cy + 9, 1, 1, shadow);
        // Right edge shadow
        DrawRect(cx + 1, cy + 2, 1, 1, shadow);
        DrawRect(cx + 2, cy + 4, 1, 1, shadow);
        DrawRect(cx + 3, cy + 6, 1, 1, shadow);
        // 1px black outline for readability
        DrawRect(cx + 1, cy, 1, 2, Color.Black * 0.6f);
        DrawRect(cx + 2, cy + 2, 1, 2, Color.Black * 0.6f);
        DrawRect(cx + 3, cy + 4, 1, 2, Color.Black * 0.6f);
        DrawRect(cx + 4, cy + 6, 1, 1, Color.Black * 0.6f);
        DrawRect(cx + 3, cy + 7, 1, 1, Color.Black * 0.6f);
        DrawRect(cx + 2, cy + 8, 1, 1, Color.Black * 0.6f);
        DrawRect(cx + 2, cy + 9, 1, 1, Color.Black * 0.6f);
        _spriteBatch.End();
    }
}
